/* AUTO-GENERATED by content-engine/import.cjs — subject:airbrakes — do not edit by hand.
   Replaces 237 upgraded questions in place, appends 0 new ones, fills en/ru/tr/es/hi.
   Idempotent: re-run import.cjs to regenerate. Safe to remove (just delete this file + its <script> tag). */
(function(){
  if(!window.CDL_DATA||!window.I18N){ return; }
  var SUBJ="airbrakes";
  var D=window.CDL_DATA, I=window.I18N;
  var cat=D.categories.filter(function(c){return c.id===SUBJ;})[0]; if(!cat) return;
  I.q=I.q||{}; ["ru","tr","es","hi"].forEach(function(L){ I.q[L]=I.q[L]||{}; I.q[L][SUBJ]=I.q[L][SUBJ]||{}; });
  var REPL={"0":{"q":"During my pre-trip inspection, an examiner asks me to explain the air brake setup on my tractor. I tell him the air brakes are really several braking systems combined into one. Which answer correctly states how many separate braking systems an air brake system actually combines, and names them?","options":["Three systems: the service brakes, the parking brakes, and the emergency brakes.","Two systems: the primary air system and the secondary air system with one set of controls.","Four systems: the service brakes, the parking brakes, the emergency brakes, and the ABS.","One system: a single circuit that handles normal stops, parking, and emergencies together."],"answer":0,"explanation":"An air brake system is actually three separate systems combined: the service brakes, the parking brakes, and the emergency brakes.","handbook":"Air brakes are three systems: service, parking and emergency.","hbref":"§5.1 Parts","qid":"AB-001"},"1":{"q":"I'm doing my pre-trip inspection and I rev the engine to build air pressure while watching the dash gauge. I want to confirm the governor is working correctly by noting the pressure at which the air compressor stops pumping air into the tanks. At approximately what reading should the needle stop climbing because the governor has cut OUT?","options":["About 100 psi, which is the pressure where the compressor stops adding air to the tanks","About 125 psi, at which point the governor cuts out and the compressor stops pumping","About 150 psi, where the system reaches its maximum and the compressor shuts off","About 60 psi, the point at which the governor halts the compressor on a charged system"],"answer":1,"explanation":"The governor cuts out at about 125 psi, stopping the compressor from pumping more air into the tanks.","handbook":"The governor stops the compressor at cut-out, around 125 psi; cut-in is around 100 psi.","hbref":"§5.1 Governor","qid":"AB-002"},"2":{"q":"I'm parked doing my pre-trip and watching the air gauge. The compressor had cut out earlier and stopped pumping, so the pressure has been slowly dropping as I test the system. At what gauge reading should I expect the governor to kick the compressor back in and start pumping air again?","options":["About 60 psi, the same point where the low air pressure warning light and buzzer come on","About 125 psi, the level at which the governor stops the compressor from pumping","About 100 psi, the point where the governor signals the compressor to resume pumping","About 150 psi, the level at which the safety relief valve opens to release pressure"],"answer":2,"explanation":"The governor cut-in point is about 100 psi, where it signals the compressor to resume pumping air.","handbook":"Cut-in (about 100 psi) is where the compressor resumes pumping.","hbref":"§5.1 Governor","qid":"AB-003"},"3":{"q":"During my pre-trip, I notice the air compressor governor isn't cutting out — the gauge keeps climbing past the normal 125 psi point where pumping should stop. If the governor never cuts out, at roughly what pressure should the safety relief valve open to protect the system from over-pressurizing?","options":["At about 100 psi, the same point where the governor would normally cut in and resume pumping","At about 60 psi, the same threshold that triggers the low air pressure warning light and buzzer","At about 125 psi, matching the governor cut-out so the two devices act together","At about 150 psi, venting excess air to keep the system from building dangerous pressure"],"answer":3,"explanation":"The safety relief valve opens at about 150 psi to vent excess air and protect the system from dangerous pressure.","handbook":"The safety valve is usually set to open at 150 psi.","hbref":"§5.1 Reservoirs","qid":"AB-004"},"4":{"q":"I'm doing a pre-trip inspection on a single tractor with a fully charged air system. With the engine off, I fan the brakes down step by step and watch the dash. At what point should the low-air warning light and buzzer be active by — that is, the warning must already be ON before pressure falls below which level?","options":["Before air pressure drops below 60 psi","Before air pressure drops below 80 psi","Once pressure has already fallen into the 20 to 45 psi range","Before air pressure drops below 100 psi"],"answer":0,"explanation":"The low air pressure warning must come on before system pressure drops below 60 psi.","handbook":"The low air warning must come on before pressure falls below 60 psi.","hbref":"§5.1 Warning","qid":"AB-005"},"5":{"q":"I'm driving a loaded single tractor-trailer when a line ruptures and my air pressure starts bleeding off fast. The low-air warning light and buzzer are already on, and the needle keeps falling. At roughly what pressure should I expect the spring (emergency) brakes to come on by themselves and bring me to a stop?","options":["Around 60 psi, the same point where the low-air warning first activates","Somewhere in the 20 to 45 psi range, after the warning has already been on","Around 100 psi, the governor cut-in point where the compressor restarts","Around 5 to 10 psi, only once the tanks are almost completely empty"],"answer":1,"explanation":"The spring (emergency/parking) brakes apply automatically when system air pressure falls into the 20 to 45 psi range.","handbook":"Spring brakes come on automatically at about 20 to 45 psi.","hbref":"§5.1 Spring Brakes","qid":"AB-006"},"6":{"q":"During my pre-trip, my instructor points at the pedal I press with my foot to apply the service brakes and asks me its other proper name. To answer correctly, which component is he pointing to?","options":["The governor, since it controls how much braking air the pedal releases to the wheels","The slack adjuster, because it transfers my foot pressure into mechanical braking force","The foot (treadle) valve, which sends air to the service brakes when I press it","The glad hand, since it is the connection that carries my braking air to the brakes"],"answer":2,"explanation":"The brake pedal is properly called the foot or treadle valve, which meters air to the service brakes when pressed.","handbook":"The brake pedal is also called the foot valve or treadle valve.","hbref":"§5.1 Parts","qid":"AB-007"},"7":{"q":"It is a freezing winter morning and during my pre-trip I open the drain valve on the bottom of the air tank. A milky, oily liquid sputters out along with the air. A coworker tells me I must have a serious mechanical problem because that fluid should never be in the tank. Which statement correctly explains what I am seeing and why I drain the tanks daily?","options":["Nothing should drain but air; the liquid means a cracked tank is leaking brake fluid into the air supply","Coolant has seeped past a failed seal into the tank, so I must drain it before it reaches the brake chambers","Leaking brake fluid has mixed with the air, and daily draining flushes that fluid out of the system","Compressed air normally collects water and some compressor oil, and daily draining removes it to prevent freeze-up and damage"],"answer":3,"explanation":"Compressed air naturally collects water and some compressor oil, so the tanks must be drained daily to prevent freeze-up and damage.","handbook":"Air tanks must be drained to remove water and compressor oil.","hbref":"§5.1 Tanks","qid":"AB-008"},"8":{"q":"It is below freezing on a winter morning, and I notice my truck is equipped with an air dryer mounted on the supply (wet) tank. During my pre-trip, I am trying to recall the main job this component performs. Which statement BEST describes what the air dryer is doing for my air brake system?","options":["It removes water and contaminants from the compressed air before that air reaches the storage tanks","It boosts the compressed air above the governor cut-out so the tanks reach a higher working pressure","It triggers the low air pressure warning light and buzzer before tank pressure falls below 60 psi","It cools the heated brake drums and linings after a long, steep downgrade to prevent brake fade"],"answer":0,"explanation":"The air dryer removes water and contaminants from the compressed air before it reaches the storage tanks.","handbook":"The air dryer removes moisture and some oil from the air.","hbref":"§5.1 Parts","qid":"AB-009"},"9":{"q":"I'm doing my pre-trip on a tractor-trailer and the engine just reached governor cut-out. Scanning the dash, I see two air gauges side by side. To confirm I have enough stored air before I release the brakes and pull out, which reading on the supply pressure gauge tells me what I need to know?","options":["The amount of pressure I'm currently sending to the brake chambers when I press the pedal","The amount of air pressure currently stored in the air tanks (about 125 psi at cut-out)","The pressure at which the spring brakes will pop on automatically if air gets low","The pressure the safety relief valve is set to open at to protect the system"],"answer":1,"explanation":"The supply pressure gauge shows how much air pressure is currently stored in the air tanks, about 125 psi at cut-out.","handbook":"The supply pressure gauge shows the pressure in the air tanks.","hbref":"§5.1 Gauges","qid":"AB-010"},"10":{"q":"I'm descending a long grade in my loaded truck and pressing the brake pedal harder to hold my speed. As I push the treadle down farther, one gauge on my dash climbs higher the more I press, and drops back toward zero when I let off. Which gauge am I watching respond to my foot on the pedal?","options":["The air tank (supply) pressure gauge, since it tracks how much air is left in the reservoirs","The governor cut-out gauge, since it shows the compressor stopping at about 125 psi","The application pressure gauge, since it shows how much air pressure I am applying to the brakes","The low air pressure warning gauge, since it lights up before pressure drops below 60 psi"],"answer":2,"explanation":"The application pressure gauge shows how much air pressure you are sending to the brakes through the foot pedal.","handbook":"The application gauge shows how much pressure you apply to the brakes.","hbref":"§5.1 Gauges","qid":"AB-011"},"11":{"q":"During my pre-trip inspection, my instructor points at the S-cam on a brake assembly and asks me to explain what physically happens at that component the instant I press the brake pedal and air is delivered to the brake chamber. Which answer correctly describes the S-cam's job?","options":["It bleeds water and compressor oil out of the air tanks so the lines do not freeze up","It signals the governor to stop the compressor once the tanks reach about 125 psi","It pulls the slack adjuster back to take up free play in the pushrod travel","It rotates and forces the brake shoes apart against the inside of the drum"],"answer":3,"explanation":"The S-cam rotates and wedges between the brake shoes, forcing them apart against the inside of the drum.","handbook":"The S-cam twists and forces the brake shoes against the drum.","hbref":"§5.1 Parts","qid":"AB-012"},"12":{"q":"During my pre-trip inspection, I park on level ground, chock the wheels, release the parking brakes, and pry against a manual slack adjuster with a pry bar to check for excessive pushrod travel. The brakes are out of adjustment if the slack adjuster moves MORE than about:","options":["1 inch, since greater free play means the brakes are out of adjustment and lose braking power","3 inches, which is the maximum travel allowed before the brakes are out of adjustment","5 inches, since anything less than that still keeps the brakes within proper adjustment","It can move freely, because slack adjusters are designed to swing without any travel limit"],"answer":0,"explanation":"A manual slack adjuster should move no more than about 1 inch when pried, or the brakes are out of adjustment.","handbook":"A slack adjuster should not move more than about one inch.","hbref":"§5.3 Inspection","qid":"AB-013"},"13":{"q":"I'm driving a tractor-trailer with air brakes and I press the brake pedal hard to slow for traffic ahead. Compared to the hydraulic brakes on my car, there is a noticeable delay before the air brakes actually grab. About how long is this air brake lag — the time it takes for the air to travel through the lines and act after I push the pedal down?","options":["About 1/10 of a second, the same near-instant response I feel in a hydraulic car braking system","About 1/2 of a second for the air to travel through the lines and the brakes to take hold","About 2 seconds, roughly matching the reaction-distance delay before a driver hits the pedal","About 5 seconds, since the air must fully charge every chamber before any braking begins"],"answer":1,"explanation":"Air brakes have about a half-second lag while compressed air travels through the lines before the brakes take hold.","handbook":"Air brakes have about a half-second of brake lag.","hbref":"§5.4 Using","qid":"AB-014"},"14":{"q":"I'm calculating the total stopping distance for my air-brake rig. For a car with hydraulic brakes, total stopping distance is just perception distance plus reaction distance plus braking distance. Because my truck uses air brakes, which ADDITIONAL piece must I add to that calculation that the car driver does not have?","options":["An extra reaction distance, because air-brake controls take longer for the brain to operate","A longer perception distance, because the larger truck makes hazards harder to spot in time","A brake-lag distance, for the roughly half-second the air takes to travel through the lines and apply","Nothing extra, since the four basic distances are identical for every type of brake system"],"answer":2,"explanation":"Air-brake stopping distance adds a brake-lag distance for the half-second the air takes to travel through the lines and apply.","handbook":"With air brakes, add brake lag distance to the stopping distance.","hbref":"§5.4 Using","qid":"AB-015"},"15":{"q":"During my pre-trip, I shut off the engine with the system fully charged to about 125 psi, chock the wheels, and leave the parking brakes released on my straight (single) truck. I watch the dash gauge for one minute to time the leakage. The air loss is acceptable only as long as it stays at or below which rate?","options":["4 psi per minute, since that is the limit once the engine is off and the tanks are full","1 psi per minute, on the assumption that almost no air should escape from a sealed system","3 psi per minute, the same figure that applies to a combination vehicle in this test","2 psi per minute, the maximum allowed for a single vehicle with the brakes released"],"answer":3,"explanation":"For a single vehicle with the brakes released, air loss must not exceed 2 psi per minute.","handbook":"With brakes released, single vehicles lose under 2 psi/min.","hbref":"§5.3 Inspection","qid":"AB-016"},"16":{"q":"During my pre-trip on a tractor-trailer, I fully charge the system to about 125 psi, shut the engine off, and leave the brakes released to time the air leakage. Watching the dash gauge for one minute, what is the MAXIMUM pressure drop I can have and still pass this part of the inspection?","options":["3 psi in one minute","2 psi in one minute","4 psi in one minute","6 psi in one minute"],"answer":0,"explanation":"For a combination vehicle with the brakes released, air loss must not exceed 3 psi per minute.","handbook":"With brakes released, combinations lose under 3 psi/min.","hbref":"§5.3 Inspection","qid":"AB-017"},"17":{"q":"During my pre-trip, I charge the air system to about 125 psi, shut off the engine, chock the wheels, and fully apply the foot brake on my single straight truck (no trailer). I watch the dash gauge for one minute to check the air leakage rate. Which reading means my truck is within the legal limit and safe to drive?","options":["The pressure drops by 4 psi in that minute","The pressure drops by 2 psi in that minute","The pressure drops by 5 psi in that minute","The pressure drops by 6 psi in that minute"],"answer":1,"explanation":"For a single vehicle with the brakes applied, air loss must stay under 3 psi per minute.","handbook":"With brakes applied, single vehicles lose under 3 psi/min.","hbref":"§5.3 Inspection","qid":"AB-018"},"18":{"q":"During my pre-trip inspection on a dual air brake system, I start the engine, run it at operating rpm, and watch the dash gauges climb from 85 psi. To pass the air build-up portion of the check, by what time must the gauges reach 100 psi?","options":["Within 10 seconds of running at operating rpm","Within 3 minutes of running at operating rpm","Within 45 seconds of running at operating rpm","Within 5 minutes of running at operating rpm"],"answer":2,"explanation":"In a dual air brake system, pressure should build from 85 to 100 psi within 45 seconds at operating rpm.","handbook":"In dual systems pressure builds 85 to 100 psi within 45 seconds.","hbref":"§5.3 Inspection","qid":"AB-019"},"19":{"q":"During my pre-trip inspection, the engine is off and my air tanks are charged to about 125 psi. I want to confirm the low-air-pressure warning device is working correctly before I drive. Which action actually performs this check?","options":["Run the engine at high rpm with the system charged and watch for the warning to light up as pressure climbs past 60 psi","Open the tank drain valves wide so all the air escapes quickly out of the tanks, then listen for the buzzer to sound","Pump the brake pedal one time and confirm that the warning device stays off while pressure is above 100 psi","With the engine off, repeatedly step on and release the brake pedal to bleed pressure down until the warning comes on above 60 psi"],"answer":3,"explanation":"With the engine off, fan the brakes to bleed pressure down and confirm the low-air warning comes on before pressure drops below 60 psi.","handbook":"Fan off air with the engine off; the warning must light before 60 psi.","hbref":"§5.3 Inspection","qid":"AB-020"},"20":{"q":"During my pre-trip air-brake inspection, I have built the system to full pressure, released the parking brake, and I'm ready to check that the service brakes will actually hold and stop the rig straight. Which of these is the correct way to perform the service-brake stop test?","options":["Let the vehicle move forward at about 5 mph, then push the brake pedal down firmly and confirm it stops without pulling to one side","Accelerate to normal highway speed and brake hard once to confirm the brakes can handle a full stop","Hold the vehicle still, pull the parking brake knob out, and feel whether the tractor stays locked in place","While rolling at about 5 mph, pump the brake pedal ten times quickly to confirm pressure builds back each time"],"answer":0,"explanation":"A correct service-brake check: roll forward at about 5 mph, push the pedal down firmly, and the vehicle should stop straight without pulling to one side.","handbook":"Test service brakes at about 5 mph with a firm brake.","hbref":"§5.3 Inspection","qid":"AB-021"},"21":{"q":"During my pre-trip, I find a crack running across the face of one brake drum. I need to decide whether to take the rig out of service. According to the Texas CDL Handbook, a cracked brake drum is out of service when the crack is longer than which of the following?","options":["Any visible hairline crack on the drum face","One-half the width of the drum's friction surface","One-quarter the width of the drum's friction surface","The full width of the drum's friction surface"],"answer":1,"explanation":"A brake drum must be taken out of service when a crack runs longer than one-half the width of the drum's friction surface.","handbook":"Drums must not have cracks longer than half the friction width.","hbref":"§5.3 Inspection","qid":"AB-022"},"22":{"q":"During my pre-trip inspection, I pull a wheel and crawl under the trailer to look at the drum brakes. I find a problem and decide the linings must be replaced before I drive. Which of the following conditions on the brake linings would CORRECTLY justify taking this vehicle out of service?","options":["The linings are thick, dry, and firmly seated against the backing plate","The linings sit flush against the drum and show even, light surface wear","The linings are soaked with oil or grease, or are worn dangerously thin","The linings were just installed and have light glaze from initial seating"],"answer":2,"explanation":"Brake linings are defective and the vehicle must be put out of service when they are soaked with oil or grease or worn dangerously thin.","handbook":"Linings must not be loose, oil-soaked, or dangerously thin.","hbref":"§5.3 Inspection","qid":"AB-023"},"23":{"q":"I'm hauling a loaded combination down a long, steep grade. I've shifted into a low gear before starting down, and now I'm thinking about how to use my air brakes for the rest of the descent. Which statement correctly describes the role my brakes should play on this downgrade?","options":["They are my main speed control, so I should keep steady pressure on the pedal the entire way down","They work best when pumped on and off repeatedly, letting the air recharge between each application","They should be held down firmly and continuously to keep the wheels from gaining any speed at all","They are a supplement to engine braking, used in light, steady applications to back up the low gear"],"answer":3,"explanation":"On a long downgrade the engine in a low gear is the primary speed control, and the brakes only supplement it with light, steady applications.","handbook":"On a downgrade, brakes only supplement the engine braking effect.","hbref":"§5.4 Downgrades","qid":"AB-024"},"24":{"q":"I'm descending a long, steep grade in my loaded combination vehicle, already in a low gear, and I want to use the proper snub-braking technique to keep my speed under control. Which action correctly describes what I should do with the brakes?","options":["Apply the brakes firmly until my speed drops to about 5 mph below my safe speed, then fully release them, and repeat the cycle as needed","Hold steady, light pressure on the brake pedal continuously the whole way down to avoid ever building heat","Pump the brakes rapidly on and off the entire descent to keep the wheels from locking up","Shift into neutral and coast, applying the brakes only if the speedometer climbs above my safe speed"],"answer":0,"explanation":"Use snub braking on a long downgrade: apply the brakes firmly until speed drops about 5 mph below your safe speed, fully release to let them cool, then repeat.","handbook":"Snub braking: brake firmly to slow, then release, and repeat.","hbref":"§5.4 Downgrades","qid":"AB-025"},"25":{"q":"I'm descending a long, steep mountain grade in a loaded truck with air brakes. The grade keeps going and I'm worried about my brakes, so I start rapidly pressing and releasing the brake pedal over and over to keep my speed in check. Why is this exactly the wrong thing to do?","options":["Repeated on-off braking overheats the slack adjusters and locks the front wheels, causing the truck to skid out of control on the grade","Each release lets air escape faster than the compressor can replace it, so pressure can fall until the brakes no longer have enough air to work","Rapid pedal cycling triggers the ABS to release the brakes entirely, leaving the spring brakes as the only way to slow down","Pumping the pedal forces the safety relief valve open at 150 psi, dumping the tank air you need for the rest of the descent"],"answer":1,"explanation":"Fanning the brakes releases air faster than the compressor can replace it, so air pressure can drop until the brakes no longer have enough air to work.","handbook":"Fanning uses air faster than the compressor can replace it.","hbref":"§5.4 Using","qid":"AB-026"},"26":{"q":"I've just finished a long descent down a steep mountain grade, riding my air brakes the whole way, and I pull into a rest area to take my mandatory break. In which of these situations should I NOT set the parking (spring) brakes, and instead chock the wheels?","options":["I'm parking on a slight downhill slope where the rig could roll if left in gear","I'll be leaving the truck unattended overnight in a marked truck lot","The brake drums and shoes are still extremely hot from the descent I just made","The low air pressure warning buzzer came on briefly as I rolled to a stop"],"answer":2,"explanation":"Do not set the parking (spring) brakes when the drums and shoes are still extremely hot from a long descent, because it can damage them and cause seizing.","handbook":"Do not use the parking brakes when the brakes are very hot.","hbref":"§5.4 Parking","qid":"AB-027"},"28":{"q":"I'm driving a 2020 tractor-trailer (equipped with working ABS) when a car suddenly stops dead in my lane. I must stop as fast as possible while keeping the rig in my lane to avoid the shoulder. Which braking method gives me the best control in this emergency?","options":["Pump the brake pedal rapidly so the ABS can cycle and grip between each release","Apply only the trailer hand valve first to keep the tractor wheels from sliding","Lighten pressure the instant I feel a wheel start to skid, then squeeze again","Press the brake pedal hard, hold it down, and keep steering toward the open lane"],"answer":3,"explanation":"With ABS, brake hard and hold firm pedal pressure while steering, because ABS keeps the wheels from locking so you can steer toward the open lane.","handbook":"With ABS, brake as hard as you can and keep steering.","hbref":"§5.4 ABS","qid":"AB-028"},"29":{"q":"I'm driving an older tractor-trailer that is NOT equipped with ABS, and a car suddenly cuts in front of me. I need to make a hard emergency stop while keeping the rig under control. Which braking method should I use?","options":["Use controlled or stab braking so the wheels keep turning and I can still steer","Press the brake pedal all the way to the floor and hold it down hard until I stop","Brake hard enough to lock the wheels, since locked wheels give the shortest stop","Pump the brake pedal rapidly the whole way down to keep the air pressure up"],"answer":0,"explanation":"Without ABS, use controlled or stab braking so the wheels keep turning, which preserves both stopping power and steering control.","handbook":"Without ABS, use controlled braking or stab braking.","hbref":"§5.4 Using","qid":"AB-029"},"30":{"q":"I'm driving a loaded truck without ABS when something darts into the road, and I have to brake hard. I push the brake pedal down all the way, the wheels lock up, and I release to start a stab-braking sequence. To do stab braking correctly, when should I push the pedal down hard again?","options":["As soon as I let off the pedal, without waiting for anything","Only after the wheels have started to roll again","After holding off the brakes for a full count of about 10 seconds","Not at all — once released, I should steer and ride it out"],"answer":1,"explanation":"In stab braking you reapply the brakes only after the wheels have started to roll again, since locked wheels cannot steer or brake effectively.","handbook":"Stab braking: release when locked, reapply once wheels roll.","hbref":"§5.4 Using","qid":"AB-030"},"31":{"q":"You are 30 miles into a run when the amber ABS malfunction lamp on your dash comes on and stays lit. Your low air pressure warning has NOT activated and the pedal still feels firm. Which of the following correctly describes your situation and the right course of action?","options":["Your service brakes have failed; bring the rig to a controlled stop on the shoulder immediately and call for a tow before driving any farther.","Your stopping distance is now longer than normal, so increase your following distance and pump the brake pedal to keep air flowing to the wheels.","You still have your normal service brakes and can keep driving carefully; only the anti-lock function is lost, so have the ABS serviced as soon as you can.","Your spring brakes are about to apply automatically, so reduce speed and exit at the next ramp before the wheels lock up on you."],"answer":2,"explanation":"An ABS warning lamp means only the anti-lock function is lost; you keep full normal service brakes, so drive carefully and get the ABS repaired soon.","handbook":"If the ABS lamp stays on you still have normal brakes.","hbref":"§5.1 ABS","qid":"AB-031"},"32":{"q":"I'm buying a used truck tractor and want to confirm it came with anti-lock brakes (ABS) from the factory, since federal rules made ABS mandatory on certain air-brake vehicles. The dealer hands me four tractors built in different years. Which is the EARLIEST build date that would REQUIRE the tractor to have factory-installed ABS?","options":["Any tractor built on or after March 1, 1998","Any tractor built on or after March 1, 1995","Any tractor built on or after March 1, 2000","Any tractor built on or after March 1, 1997"],"answer":3,"explanation":"Federal rules require factory ABS on truck tractors built on or after March 1, 1997.","handbook":"ABS is required on tractors made on or after March 1, 1997.","hbref":"§5.1 ABS","qid":"AB-032"},"34":{"q":"It's a sub-freezing December morning in Amarillo and I'm doing my pre-trip. My rig has manual drain valves on the air tanks but I'm running late, so I'm tempted to skip draining them today. Which is the BEST reason I should still open the tank drains before I pull out?","options":["Water that collects in the tanks can freeze in cold weather and keep the brakes from working","Draining the tanks lets the governor cut out at a higher pressure so the system charges faster","Opening the drains bleeds off old air so the safety relief valve reseats at the correct 150 psi setting","Releasing the air resets the low-air warning so the buzzer won't sound below 60 psi"],"answer":0,"explanation":"Drain the air tanks daily because collected water can freeze in cold weather and keep the brakes from working.","handbook":"Drain tanks to remove water that can freeze in cold weather.","hbref":"§5.1 Tanks","qid":"AB-033"},"35":{"q":"I'm finishing my pre-trip on a tractor-trailer. The engine has been idling and the air pressure gauge needle is climbing. Before I release the parking brakes and pull out of the yard, to what pressure level should I let the air system build?","options":["Up to about 100 psi, because that is the point where the compressor cuts in and I know it is working","Up to the normal operating range, about 125 psi, where the governor cuts out and stops pumping","Up to about 150 psi, the level where the safety relief valve opens to protect the system","Up to about 60 psi is enough, since that is where the low air pressure warning shuts off"],"answer":1,"explanation":"Charge the air system to its normal operating range, about 125 psi, where the governor cuts out, before driving.","handbook":"Wait for pressure to build to the normal range before driving.","hbref":"§5.3 Inspection","qid":"AB-034"},"36":{"q":"During my pre-trip, I notice the belt that drives my air compressor is glazed and can be pushed down a couple of inches with my thumb. The engine starts fine and the cab radio works. Why does this loose drive belt matter for safe operation?","options":["A loose belt is only a concern because it can squeal and make it harder to hear the low-air warning buzzer","It matters because the belt also turns the alternator that keeps the trailer's emergency battery charged","A slipping belt can keep the compressor from pumping fast enough, so the system may never build or hold enough air pressure","It matters because the drive belt routes cooling air over the front brake drums to prevent brake fade"],"answer":2,"explanation":"A slipping compressor drive belt keeps the compressor from pumping fast enough, so the system may never build or hold proper air pressure.","handbook":"If belt-driven, check the compressor belt's condition and tightness.","hbref":"§5.3 Inspection","qid":"AB-035"},"37":{"q":"I'm doing my pre-trip on a single combination vehicle and want to be sure I've completed every part of the air-brake portion before I roll. A fellow driver tells me a few of the checks I listed don't really count as part of the air-brake test. Which of these is actually a required part of a full pre-trip air-brake check?","options":["Only the low-air warning device test, since the buzzer and light are the part the examiner watches for","Only the air pressure build-up timing, since that proves the compressor is doing its job","Only the static air leakage rate, since a leak is the most serious defect you can find","All of them — the low-air warning, the build-up timing, and the air leakage rate are each required parts of the check"],"answer":3,"explanation":"A full pre-trip air-brake check requires all of these: the low-air warning, the build-up timing, and the air leakage rate.","handbook":"Check the low-air warning, build-up time, and leakage rate.","hbref":"§5.3 Inspection","qid":"AB-036"},"38":{"q":"I'm running my pre-trip on a tractor with air brakes and I want to skip any step that does NOT actually check the air-brake system itself. Which item on my list belongs to a different system and tells me nothing about my brakes?","options":["Draining water and oil from the radiator to keep the engine cooling system clear","Timing how long it takes pressure to climb from 85 to 100 psi to confirm a healthy build-up rate","Charging the system, shutting the engine off, and watching the gauge for the leak-down rate","Fanning the pedal until the low-air warning light and buzzer come on near 60 psi"],"answer":0,"explanation":"Draining water and oil from the radiator is engine cooling-system maintenance and tests nothing in the air-brake system.","handbook":"Air-brake tests include leakage, build-up, and the warning signal.","hbref":"§5.3 Inspection","qid":"AB-037"},"39":{"q":"I'm driving a tractor-trailer equipped with ABS and I have to make a hard, panic stop on dry pavement. As the ABS activates and I feel the pedal pulsing, which statement about what ABS is actually doing for me in this stop is TRUE?","options":["It is shortening my stopping distance compared to the same rig without ABS","It is keeping my wheels from locking up so I can still steer while braking hard","It is automatically reducing my brake-lag time below the usual half second","It is applying the spring (parking) brakes to add extra stopping force"],"answer":1,"explanation":"ABS keeps the wheels from locking up so they keep rolling, letting you steer while braking hard.","handbook":"ABS does not necessarily shorten stopping distance.","hbref":"§5.1 ABS","qid":"AB-038"},"40":{"q":"I'm doing my morning pre-trip and notice the air tanks on my tractor have collected a mix of water and a film of compressor oil at the bottom. It's a cold winter morning in the Panhandle. To keep the air brake system working safely and prevent freeze-up, what should I do about this buildup?","options":["Leave it alone, since the air dryer and brake heat will burn off the water and oil during the trip","Top off the tanks with extra compressor oil so the moisture stays suspended and cannot freeze","Drain the air tanks daily using the drain valves so water and oil don't damage the system or freeze up","Drain the tanks only once a week, since modern automatic valves handle the rest on their own"],"answer":2,"explanation":"Drain the air tanks daily using the drain valves so collected water and oil don't damage the system or freeze up.","handbook":"Drain air tanks regularly to remove water and compressor oil that collect in them.","hbref":"§5.1","qid":"AB-039"},"41":{"q":"During my pre-trip, I shut the engine off to run the air leakage test and notice my air gauge stops climbing entirely while the engine is off. A rookie next to me insists the compressor should keep building pressure on its own. Which statement correctly explains why pressure stopped rising once I killed the engine?","options":["The governor mechanically pumps the air tanks and only works while the truck is rolling forward","The parking-brake spring is what charges the air system, so it stops once brakes are set","The trailer's wheel rotation turns the compressor, so pressure only builds while moving","The compressor is driven by the engine (by belt or directly), so no air is pumped once the engine is off"],"answer":3,"explanation":"The air compressor is driven by the engine, so it pumps no air once the engine is off.","handbook":"The air compressor is connected to the engine and pumps air into the storage tanks.","hbref":"§5.1","qid":"AB-040"},"42":{"q":"It is well below freezing on a winter morning and I'm doing my pre-trip on a tractor equipped with an air dryer. I want to understand what this device is protecting me from as the compressor packs air into the system. What is the air dryer's main job in this situation?","options":["It pulls water vapor (and a little oil) out of the compressed air before it reaches the tanks, so less moisture can collect and freeze up the system","It signals the compressor to stop pumping once tank pressure climbs to the cut-out point near 125 psi","It vents the air tanks automatically if pressure ever spikes above the safety relief setting of about 150 psi","It injects a measured amount of alcohol into the lines to keep the brake valves from icing in cold weather"],"answer":0,"explanation":"The air dryer removes water vapor and some oil from the compressed air before it reaches the tanks, reducing moisture that could freeze and disable the brakes.","handbook":"An air dryer removes moisture and oil from the air before it enters the tanks.","hbref":"§5.1","qid":"AB-041"},"43":{"q":"During my pre-trip inspection, I climb under the trailer to examine the foundation brakes. At each wheel I find a brake drum, brake shoes with linings, and a slack adjuster connected to a pushrod that rotates a part shaped like the letter 'S' to force the shoes apart. Based on what I'm looking at, which type of foundation brake is this vehicle equipped with — the type found on most heavy air-braked vehicles?","options":["Air disc brakes, where a caliper squeezes a rotor — the most common design on heavy trucks","S-cam drum brakes, the most common foundation brake on heavy air-braked vehicles","Wedge drum brakes, where a wedge pushes the shoes apart through a single chamber","Hydraulic disc brakes, like those on a passenger car but scaled up for the trailer"],"answer":1,"explanation":"S-cam drum brakes are the most common foundation brake on heavy air-braked vehicles, identified by the S-shaped cam the pushrod rotates to spread the shoes.","handbook":"The most common type of foundation brake is the S-cam drum brake.","hbref":"§5.1","qid":"AB-042"},"45":{"q":"I'm driving a loaded tractor-trailer with air brakes when a car suddenly stops ahead of me. The moment my foot fully presses the brake pedal, there's a brief delay before the truck actually begins to slow. My instructor calls this 'brake lag.' What is physically happening during that delay?","options":["My brain and body are still processing the hazard before my foot reaches the pedal","The air compressor is building extra pressure in the tanks to meet the demand","Compressed air is traveling through the brake lines before it can apply the brakes","The vehicle is covering perception distance before any braking input begins"],"answer":2,"explanation":"After the pedal is pressed it takes about a half-second for the compressed air to travel through the brake lines and actually apply the brakes at each wheel.","handbook":"Air brakes take about one-half second to work because air must flow through the lines.","hbref":"§5.2","qid":"AB-043"},"46":{"q":"I'm studying total stopping distance for my CDL air-brake endorsement. I know that with a car's hydraulic brakes, total stopping distance is perception distance plus reaction distance plus braking distance. My instructor says air brakes add one more component to that total. Which component does an air-brake system add that hydraulic brakes do NOT have?","options":["Extra reaction distance, because air-brake pedals are heavier and slower to push down than hydraulic pedals","Extra perception distance, because larger air-brake vehicles sit higher and take longer to judge hazards","Longer effective braking distance, because air-brake vehicles are heavier and need more room to stop","Brake-lag distance, the distance traveled while air travels through the lines before the brakes grip"],"answer":3,"explanation":"Air brakes add a fourth stopping component, brake-lag distance, covering the roughly half-second the air takes to travel the lines before the brakes grip.","handbook":"With air brakes, add brake lag distance to the perception, reaction, and braking distances.","hbref":"§5.2","qid":"AB-044"},"47":{"q":"You have finished your pre-trip and the air system is fully charged. You now want to verify that the service brakes actually stop the truck and that nothing is dragging or pulling. Which of the following is the correct way to perform the service-brake stop check?","options":["Release the parking brake, let the truck creep forward to about 5 mph, then firmly apply the brake pedal and feel whether it stops promptly and straight","Hold the truck still, press the brake pedal hard, and watch the air gauge to confirm pressure does not drop more than 3 psi in one minute","While stopped, pull and release the yellow parking-brake knob several times to confirm the spring brakes set and release","Drive up to about 20 mph, then make a hard stop and check that the wheels lock up evenly on both sides"],"answer":0,"explanation":"The service-brake stop test is done in motion: let the vehicle creep to about 5 mph, then firmly apply the brakes and feel that it stops promptly without pulling to one side.","handbook":"Test the service brakes by moving about 5 mph and pressing the brake pedal firmly.","hbref":"§5.3","qid":"AB-045"},"48":{"q":"During my pre-trip inspection, my CDL instructor tells me to grab one of the brake adjusters and pull on it by hand to check how far the pushrod moves before the brakes engage. He says if there is too much free play here, my braking power is reduced. What component am I actually checking when I do this?","options":["The air compressor governor, which decides when the system stops and resumes pumping air","The slack adjuster, which sets how far the brake pushrod travels before the brakes apply","The safety relief valve, which opens to release pressure if the tanks are overcharged","The modulating control valve, which lets me apply the spring brakes gradually in an emergency"],"answer":1,"explanation":"The slack adjuster sets how far the brake pushrod travels before the brakes apply, and excessive free play—out-of-adjustment brakes—is the most common air-brake defect.","handbook":"Check slack adjusters; too much brake pushrod travel reduces braking power.","hbref":"§5.3","qid":"AB-046"},"49":{"q":"During a pre-trip inspection in freezing weather, I notice my truck's air tanks are expelling collected water and oil on their own, without me having to open anything by hand. The shop says this tank is equipped so that draining happens by itself to help prevent freeze-up. Which device is doing this job?","options":["A relay valve, which speeds the air signal to the rear brakes but also bleeds moisture from the tank on its own","A manual drain valve, which lets accumulated water and oil escape automatically once tank pressure is high enough","An automatic drain valve, which expels water and compressor oil from the tank without anyone draining it by hand","A safety relief valve, which opens near 150 psi and clears built-up water and oil from the supply tank as it vents"],"answer":2,"explanation":"An automatic drain valve expels accumulated water and compressor oil from the tank by itself, with no manual draining, which helps prevent freeze-up in cold weather.","handbook":"Some air tanks have automatic drain valves that expel water and oil by themselves.","hbref":"§5.1","qid":"AB-047"},"50":{"q":"During my pre-trip on a newer combination vehicle, I notice the air pressure gauge has two needles instead of one, and the truck won't let me build pressure normally until both readings come up. My instructor says this rig has a dual air brake system. Which statement correctly describes how this dual system is actually built?","options":["It is one large air system fed by a single tank, with the second gauge needle only showing trailer pressure as a courtesy reading.","It combines the service, parking, and emergency brakes into a single shared air line so all three work off one pressure source.","It is a single air system with a backup compressor that switches on only after the primary compressor fails completely.","It is two completely separate air systems, a primary and a secondary, controlled by one set of brake controls for added safety."],"answer":3,"explanation":"A dual air brake system is two completely separate air systems, a primary and a secondary, each with its own tanks and lines but operated by one set of controls for backup safety.","handbook":"Most heavy vehicles use a dual air brake system with separate primary and secondary systems.","hbref":"§5.1","qid":"AB-048"},"51":{"q":"I'm driving a tractor-trailer equipped with a dual air brake system when the low air pressure warning suddenly activates for only the primary circuit, and that side's gauge needle drops toward zero. The secondary system's gauge still reads in the normal range. Which statement best describes what I should expect and do?","options":["The secondary system will still operate the brakes, so I should brake to a stop safely while allowing for a longer stopping distance, then get the truck repaired.","Because both circuits share one set of controls, the secondary system fails along with the primary, so I have no braking left and must coast to a stop.","I should pump the brake pedal rapidly to force the working circuit to send air to all wheels and restore full pressure to the failed side.","The spring brakes will instantly lock all wheels the moment one circuit fails, so I should brace for an immediate hard stop."],"answer":0,"explanation":"If one circuit of a dual air brake system fails, the other still operates the brakes, so brake to a controlled stop allowing for a longer stopping distance, then get it repaired.","handbook":"In a dual air system, if one part fails, the other can still be used to stop.","hbref":"§5.1","qid":"AB-049"},"52":{"q":"I'm pre-tripping my tractor-trailer and the engine is off. As the system slowly bleeds down, I watch the gauge fall past 60 psi, then keep dropping toward 30 psi. Suddenly the spring (parking) brakes snap on by themselves, even though I never touched the parking control. Which statement BEST explains why the spring brakes had stayed released up to that point?","options":["They were being held back mechanically by the slack adjusters until the pushrod travel ran out","Air pressure was holding the powerful springs compressed, and losing that pressure let the springs apply the brakes","They were locked open by the yellow diamond-shaped parking control until the low-air buzzer released it","The service brake pedal was keeping them released and they applied only when the pedal pressure faded"],"answer":1,"explanation":"Air pressure holds the powerful spring brakes in the released position, so when pressure drops below the 20-45 psi range the springs automatically apply the brakes.","handbook":"Spring brakes are held back by air pressure; when air is lost, the springs apply the brakes.","hbref":"§5.1","qid":"AB-050"},"53":{"q":"On my pre-trip, the spring brakes won't release and I suspect a mechanical fault in the spring-brake chamber. A coworker hands me a tool and says the powerful springs can be manually 'caged' (compressed) so I can move the truck to the shop. I have never been trained on this procedure. What is the correct action?","options":["Cage the springs myself this once, since the truck only needs to roll a short distance to the shop","Repeatedly release and reapply the spring brakes by hand to gradually work the stuck chamber loose","Leave the springs alone and do not attempt to cage them, because caging these powerful springs should only be done by trained personnel","Paint the spring-brake chambers a bright color first so the strong springs are easy to see while you cage them"],"answer":2,"explanation":"Caging spring brakes is dangerous because the springs store enormous force, so it must be left to trained personnel.","handbook":"Spring brake springs are very powerful; only release or cage them if you are trained.","hbref":"§5.1","qid":"AB-051"},"54":{"q":"I've finished my pre-trip and I'm running through my air-brake checks before pulling out of the yard. With the engine running and air pressure fully built up, I set the parking brake by pulling out the yellow diamond-shaped knob. Now I want to confirm the spring brakes will actually hold the vehicle in place. Which action correctly tests this?","options":["Release the parking brake and apply the foot brake firmly to feel for a firm pedal","Fan the brake pedal several times and watch the air gauge for any pressure drop","Rev the engine and listen for the spring brakes to release at about 20-45 psi","Leave the parking brake set, release the clutch, and gently pull forward against it"],"answer":3,"explanation":"To check the parking (spring) brakes, keep them set and gently pull forward in low gear to confirm they hold the vehicle.","handbook":"Test the parking brake by gently pulling forward against it to be sure it holds.","hbref":"§5.3","qid":"AB-052"},"55":{"q":"I'm hauling a loaded combination down a long, steep mountain grade and I'm worried about keeping control of my air brakes. Which technique should I use to safely manage my speed all the way to the bottom?","options":["Select a low gear before the descent and use light, steady brake pressure, easing off once I drop about 5 mph below my safe speed","Apply firm, continuous brake pressure the whole way down to keep my speed pinned low and under control","Pump the brake pedal on and off in repeated bursts so the brakes get a chance to cool between applications","Shift into neutral to save the engine and let the brakes do all the slowing as needed on the way down"],"answer":0,"explanation":"On a downgrade, pick a low gear and use light, steady brake pressure, releasing once you slow about 5 mph below your safe speed.","handbook":"On a long grade, use a low gear and steady braking to keep a safe speed.","hbref":"§5.3","qid":"AB-053"},"56":{"q":"I'm rolling down a Texas highway in my air-brake truck at normal speed and press down firmly on the foot pedal (treadle valve) to slow for traffic. Which braking system am I applying with that pedal?","options":["The parking brakes, which are held off by air and set by the yellow knob","The service brakes, which I use for all normal slowing and stopping","The emergency brakes, which apply automatically when air pressure gets low","The trailer brakes only, controlled separately by the trailer hand valve"],"answer":1,"explanation":"The foot pedal (treadle valve) operates the service brakes, which are used for all normal slowing and stopping.","handbook":"The brake pedal controls the service brakes used for normal stopping.","hbref":"§5.1","qid":"AB-054"},"57":{"q":"During my pre-trip inspection I'm checking the brake drums and discs on my tractor. Which condition means a drum or disc is dangerous and the vehicle should NOT be driven until it's repaired?","options":["The drum is cool to the touch and free of any oil film","There is a light coating of road dust on the outer surface","The drum has a visible crack or the surface is badly worn down","The drum shows fresh paint from a recent shop service"],"answer":2,"explanation":"A brake drum that is cracked or badly worn can fail under heat and load, so the vehicle must be taken out of service until repaired.","handbook":"Cracked drums and worn brake linings can cause brake failure and must be checked.","hbref":"§5.3","qid":"AB-055"},"58":{"q":"During a pre-trip inspection, you charge your air system to about 125 psi, shut off the engine, and watch the dash gauge. With the brakes released, the needle keeps falling well past the allowed leakage rate and shows no sign of stopping. The low air warning hasn't lit up yet. What is the correct action?","options":["Start the engine and drive normally, since the warning light and buzzer haven't come on yet","Pump the brake pedal a few times to reseat the valves, then continue your route as planned","Drive directly to the nearest repair shop while pressure stays above 60 psi","Take the vehicle out of service and have the leak repaired before driving anywhere"],"answer":3,"explanation":"A continuing air leak past the allowed rate can drain the tanks and disable the brakes, so the vehicle must be taken out of service until repaired.","handbook":"If you have an air leak you cannot control, stop and have it repaired.","hbref":"§5.3","qid":"AB-056"},"59":{"q":"I'm rolling down the highway in my tractor-trailer when the yellow ABS malfunction lamp on my dash comes on and stays lit. The truck is still braking and steering normally. Based on what this lamp is telling me, which statement is the MOST accurate?","options":["My antilock system may not be working, but my normal service brakes still function and I should get the ABS checked.","My service brakes have already failed, so I must pull over and set the parking brake immediately.","My ABS is fully engaged and actively shortening my stopping distance on this stretch of road.","My air pressure has dropped below 60 psi and the spring brakes are about to lock the wheels."],"answer":0,"explanation":"A lit yellow ABS lamp means only the antilock function may be out; the normal service brakes still work and the ABS should be checked.","handbook":"If the ABS malfunction lamp stays on, the antilock system may not be working.","hbref":"§5.3","qid":"AB-057"},"60":{"q":"I'm hauling a loaded combination vehicle on a long route, and I keep an eye on my dashboard gauges. To make sure my air brakes will actually apply and release every time I step on the pedal, which ONE condition must I keep maintained throughout the trip?","options":["A full fuel tank, since the brakes draw their power directly from the engine's fuel supply","Enough air pressure in the system, since the air is what applies and releases the brakes","A low-beam headlight setting, so the brake warning sensors can read the gauges in daylight","At least one passenger aboard to confirm the brake lights are working at each stop"],"answer":1,"explanation":"An air brake system needs enough air pressure because compressed air is what applies and releases the brakes.","handbook":"Air brakes need enough air pressure in the system to work properly.","hbref":"§5.1","qid":"AB-058"},"61":{"q":"During my pre-trip inspection, I let the air system charge to governor cut-out, then run the engine at operating RPM and watch the gauge climb from 85 to 100 psi. Which of the following observations would tell me the air compressor is healthy and the build-up rate is acceptable?","options":["The gauge takes several long minutes to crawl from 85 to 100 psi, but eventually reaches it","The pressure does not move at all because the governor has already cut out the compressor","The gauge climbs from 85 to 100 psi within about 45 seconds, a matter of seconds, not minutes","The pressure jumps from 85 to 100 psi instantly the moment I press the accelerator"],"answer":2,"explanation":"In a dual air brake system, pressure should build from 85 to 100 psi within about 45 seconds, showing a healthy compressor restores air fast.","handbook":"The air compressor should build pressure quickly; slow build signals a problem.","hbref":"§5.3","qid":"AB-059"},"62":{"q":"During my pre-trip inspection, I crawl under the trailer and notice that the brake linings on one wheel have worn down so thin they are nearly flush with the rivets. Everything else on the brake system checks out fine. Which of the following is the correct action before I take this vehicle on the road?","options":["Leave the linings as they are, since the pushrod travel and slack adjusters still test within the legal limit","Apply a light coat of brake fluid to the thin linings to reduce squealing until I reach the next shop","Note it on my inspection report but keep driving, as long as the low-air warning stays above 60 psi","Take the vehicle out of service and have the worn linings replaced with new ones before driving"],"answer":3,"explanation":"Brake linings worn too thin can no longer create adequate friction, so they must be replaced before the vehicle is driven.","handbook":"Replace brake linings before they become too thin to brake safely.","hbref":"§5.3","qid":"AB-060"},"63":{"q":"I'm hauling a loaded trailer down a long mountain grade. To keep my speed in check, I keep pressing and releasing the brake pedal over and over ('fanning' the brakes). My instructor warns me to stop doing this. Which of the following is the MAIN reason fanning is dangerous on a long downgrade?","options":["It can use up air faster than the compressor can rebuild it, draining the supply","It cools the brake drums too quickly and can crack the linings from thermal shock","It pushes extra air into the trailer supply tank and overloads the relief valve","It makes the slack adjusters tighten up so the pushrod travel becomes too short"],"answer":0,"explanation":"Repeatedly fanning the brakes releases air with each application faster than the compressor can rebuild it, draining the air supply.","handbook":"Fanning the brakes on a downgrade can let air pressure drop too low.","hbref":"§5.3","qid":"AB-061"},"64":{"q":"I just moved from driving a car to a tractor-trailer equipped with an air brake system. When I press the brake pedal, I'm trying to picture what actually travels through the lines to push the brake shoes against the drums and slow the rig down. In this air brake system, the force I create at the pedal is transmitted to the wheels by which medium?","options":["Pressurized hydraulic brake fluid pushed from a master cylinder, the same as in my car","Compressed air stored in the tanks and released through the brake lines to the chambers","A heavy steel cable and mechanical linkage pulled tight from the pedal to each wheel","Electric current sent down a wire that energizes a brake magnet at each wheel"],"answer":1,"explanation":"Air brakes transmit force using compressed air stored in the tanks and released through the brake lines into the chambers.","handbook":"Air brakes use compressed air to make the brakes work.","hbref":"§5.1","qid":"AB-062"},"65":{"q":"I'm driving a loaded truck with air brakes when a line ruptures and my air pressure bleeds all the way down to zero. A trainee riding with me asks why this setup is considered safer than the hydraulic brakes on his pickup. Which statement BEST explains the real safety advantage of my air brake system in this exact situation?","options":["Because air is the fluid, my service brakes will keep working normally even after all the air has leaked out of the system.","The low air pressure warning buzzer is what physically stops the truck once the pressure has dropped below 60 psi.","As the air pressure falls into the 20 to 45 psi range, the spring (emergency) brakes apply automatically and bring the truck to a stop.","Air brakes are designed to always stop a loaded truck in a shorter distance than hydraulic brakes regardless of any leak."],"answer":2,"explanation":"When air pressure drops into the 20 to 45 psi range, the spring (emergency) brakes apply automatically and stop the vehicle.","handbook":"If air pressure is lost, the spring brakes apply automatically.","hbref":"§5.1","qid":"AB-063"},"66":{"q":"I'm rolling down the highway in a loaded tractor-trailer when a line ruptures and my air pressure bleeds out completely. As the system empties, what will happen with my spring brakes?","options":["Nothing happens to them, because spring brakes only function as my service brakes when I press the pedal","They stay released, because the powerful springs need stored air pressure to hold them clamped on","They release fully, because losing air is exactly what frees the springs to let the rig roll","They apply automatically, because the springs clamp the brakes once the air that held them off is gone"],"answer":3,"explanation":"Spring brakes are held off by air pressure, so when that air is lost the springs clamp the brakes on automatically as a fail-safe.","handbook":"Spring brakes come on automatically when air pressure is lost.","hbref":"§5.1","qid":"AB-064"},"67":{"q":"I'm doing a brake check with the engine off and a fully charged system. I keep stepping on and releasing the brake pedal to bleed air out of the tanks, watching the air gauge fall. As the needle keeps dropping, at roughly what pressure should I expect the tractor protection valve to close automatically and the trailer air supply to cut off?","options":["Between about 20 and 45 psi, as the pressure falls into the low range","Between about 60 and 80 psi, right as the low air warning is active","Between about 100 and 125 psi, near the governor's normal operating band","Between about 5 and 10 psi, only after the gauge nearly reads empty"],"answer":0,"explanation":"The tractor protection valve and trailer air supply close automatically when system air pressure falls into the 20 to 45 psi range.","handbook":"The tractor protection valve closes at about 20 to 45 psi.","hbref":"§6.2","qid":"AB-065"},"68":{"q":"I'm hooked up to a loaded trailer and finishing my pre-trip inside the cab. To charge the trailer's air system and release its brakes before I roll, I need to push in one specific dash control. Which knob's color and shape identifies the one I must push in to supply air to the trailer?","options":["The yellow, diamond-shaped knob, because that control feeds air to the trailer brakes","The red, eight-sided (octagon) knob, because that is the trailer air supply control","The blue, round knob, because the service line to the trailer is color-coded blue","The yellow, eight-sided (octagon) knob, because the trailer supply matches the parking control shape"],"answer":1,"explanation":"The trailer air supply control is the red, eight-sided (octagon) knob that charges the trailer's air system and releases its brakes.","handbook":"The trailer air supply valve is a red, eight-sided knob.","hbref":"§6.2","qid":"AB-066"},"69":{"q":"I've finished parking my tractor-trailer at a rest stop and I'm about to shut down. To set the parking (spring) brakes so the rig stays put, which dash control do I need to pull out?","options":["The blue round button that releases the service-brake pressure","The red, eight-sided (octagon) knob next to the dash gauges","The yellow, diamond-shaped knob on the control panel","The green square lever beside the trailer hand valve"],"answer":2,"explanation":"The parking (spring) brake control is the yellow, diamond-shaped knob, pulled out to apply and pushed in to release the spring brakes.","handbook":"The parking brake control is a yellow, diamond-shaped knob.","hbref":"§5.3","qid":"AB-067"},"70":{"q":"During my pre-trip, the engine quits and the compressor stops turning, yet I notice my supply tank holds its pressure instead of bleeding back toward the dead compressor. Which component is responsible for this behavior?","options":["The safety relief valve, which traps tank air whenever it senses the compressor has stopped","The governor, which seals off the supply tank once it reaches the cut-out pressure setting","The automatic drain valve, which closes tight to lock the stored air inside the tank","The one-way check valve, which blocks air from flowing back out toward the stopped compressor"],"answer":3,"explanation":"The one-way check valve allows air to flow only into the tank, so it blocks stored air from leaking back out when the compressor stops.","handbook":"A check valve keeps air from flowing back out if the compressor loses pressure.","hbref":"§5.1","qid":"AB-068"},"71":{"q":"It is a freezing January morning in Amarillo, and my dispatcher tells me my tractor is equipped with an alcohol evaporator in the air brake system. As I do my pre-trip, I am asked what this device actually does for me in these conditions. Which statement BEST explains its purpose?","options":["It puts alcohol into the air system to reduce the chance of ice forming in the lines and valves during cold weather","It burns alcohol to warm the brake drums so the parking brakes will not freeze in cold weather","It adds alcohol to the air to absorb moisture so I no longer need to drain the air tanks daily","It releases alcohol vapor that boosts air compressor output so pressure builds faster when it is cold"],"answer":0,"explanation":"The alcohol evaporator puts alcohol into the air system to reduce the chance of ice forming in the lines and valves during cold weather.","handbook":"An alcohol evaporator reduces the risk of ice in cold weather.","hbref":"§5.1","qid":"AB-069"},"72":{"q":"During my pre-trip, I'm tracing the foundation brake assembly at one of the wheels on my air-brake tractor. As the brake is applied, I watch the slack adjuster rotate a shaft that turns an S-shaped cam, which forces the brake shoes and linings outward against the inside of the drum. While I'm confirming each part is present and working, which of the following should I NOT expect to find anywhere in this S-cam foundation brake?","options":["The slack adjuster that converts pushrod travel into rotation of the brake cam","A hydraulic master cylinder that pressurizes fluid to push the shoes outward","The brake drum that the shoes press against to create stopping friction","The brake shoes and linings that are forced against the drum when braking"],"answer":1,"explanation":"An S-cam air foundation brake is purely mechanical-pneumatic with no fluid, so it contains no hydraulic master cylinder.","handbook":"S-cam foundation brakes use shoes, a drum, an S-cam, and a slack adjuster.","hbref":"§5.1","qid":"AB-070"},"73":{"q":"I'm hauling a loaded trailer down a long, steep grade when my service brakes fade and the pedal goes soft. My rig is equipped with a modulating control valve. In this situation, what does that valve actually let me do?","options":["Pump the service brakes repeatedly to rebuild air pressure in the lines before they fully fail","Override the governor so the compressor cuts out higher than 125 psi and restores my braking power","Apply the spring (emergency) brakes gradually with the control handle instead of having them grab all at once","Switch off the ABS so the wheels can lock up and scrub off speed faster on the downgrade"],"answer":2,"explanation":"A modulating control valve lets you apply the spring (emergency) brakes gradually with the control handle for controlled stopping if the service brakes fail.","handbook":"A modulating valve applies the spring brakes gradually if the service brakes fail.","hbref":"§5.3","qid":"AB-071"},"74":{"q":"I'm driving a loaded straight truck when I notice my low-air warning light flick on and the buzzer sound. A pre-trip inspection earlier showed a small air leak I figured was minor. Compared with how a hydraulic-brake system would behave with a similar small leak, what should I expect from my air brakes right now?","options":["The brakes will fail completely the instant the leak starts, exactly like a hydraulic system, so I have no usable braking left","Air pressure loss gives no warning at all, so the light and buzzer must be signaling some other unrelated fault","The leak cannot really be confirmed while driving, so I should keep going at speed until I can park and inspect the lines","The brakes keep working as long as air pressure remains, and the warning is alerting me to stop safely before it drops too low"],"answer":3,"explanation":"Air brakes keep working as long as usable air pressure remains, and the low-pressure warning must come on before pressure drops below 60 psi so you can stop safely.","handbook":"Air brakes keep working as long as air pressure remains.","hbref":"§5.1","qid":"AB-072"},"75":{"q":"I'm doing the air-brake portion of my pre-trip on a single tractor. I've already drained the tanks and built pressure to governor cut-out. Before I roll out of the yard, which set of brake functions must I still confirm actually work to complete the air-brake walkaround?","options":["The low-air pressure warning, the spring (parking) brakes, and the service brakes","Only the spring (parking) brakes and the service brakes, since the warning self-tests on start-up","Only the low-air pressure warning and the service brakes, since spring brakes set automatically","Only the service brakes, because a firm pedal at 5 mph proves the whole system is sound"],"answer":0,"explanation":"A complete air-brake check must confirm three things: the low-air pressure warning, the spring (parking) brakes, and the service brakes.","handbook":"Test the low-air warning, the parking brakes, and the service brakes.","hbref":"§5.3","qid":"AB-073"},"76":{"q":"I just bought a straight truck equipped with air brakes and I already hold a valid CDL that I earned in a vehicle with hydraulic brakes. Before I legally drive this air-brake truck, which additional step does Texas require of me that did NOT apply to my old hydraulic-brake vehicle?","options":["Nothing extra — my existing CDL already covers any braking system, so I can drive it as-is","I must pass the air-brake (no-restriction) test, or my license will carry an air-brake restriction","I only need to add a Class C designation to match the smaller truck size","I must obtain a separate motorcycle endorsement before operating any air-brake unit"],"answer":1,"explanation":"You must pass the air-brake knowledge and skills test, or the state places an air-brake restriction on your license barring you from air-brake vehicles.","handbook":"You must pass the air-brake test or get an air-brake restriction.","hbref":"§5.1","qid":"AB-074"},"77":{"q":"I'm hauling a loaded trailer on a wet interstate when a car cuts in front of me and stops short. I stomp the brake pedal hard, and my ABS-equipped tractor-trailer kicks in. In that hard-braking moment, what should I realistically expect ABS to do for me?","options":["Cut my total stopping distance dramatically so I stop well short of the car ahead","Apply my brakes for me automatically even before I press the pedal down","Keep my wheels from locking up so I can still steer around the hazard while braking hard","Take over as my main service brakes once the pedal is pushed all the way down"],"answer":2,"explanation":"ABS keeps the wheels from locking up during hard braking so you retain steering control and can steer around a hazard.","handbook":"ABS keeps your wheels from locking so you can steer while braking hard.","hbref":"§5.3","qid":"AB-075"},"78":{"q":"I'm driving a straight truck with a single air brake system and the engine quits on a quiet stretch of highway. As I coast to the shoulder, I keep my eyes on the air pressure gauge, knowing the air will slowly bleed down with the compressor no longer running. At approximately what pressure should I FIRST expect the low air pressure warning (the light and buzzer) to activate, signaling that I'm losing my air reserve?","options":["About 100 psi, the point where the governor would normally cut the compressor back in","About 125 psi, the point where the governor would normally cut the compressor out","About 30 psi, once the spring brakes are about to set automatically","About 60 psi, well before the pressure gets dangerously low"],"answer":3,"explanation":"The low air pressure warning must come on at about 60 psi, well before pressure gets dangerously low.","handbook":"The low-air warning must come on before pressure drops below about 60 psi.","hbref":"§5.1","qid":"AB-076"},"79":{"q":"I'm doing my pre-trip and trying to picture what actually makes my air brakes apply when I press the pedal. As long as my engine, gauges, and lines are healthy, my air brakes will keep stopping the truck for as long as which of the following remains adequate?","options":["The air pressure built up and stored in the tanks","The hydraulic brake fluid in the master cylinder","The engine oil pressure feeding the brake circuit","The 12-volt battery charge powering the brake valves"],"answer":0,"explanation":"Air brakes apply and hold using the compressed air pressure built up and stored in the tanks, not fluid.","handbook":"Air brakes keep working as long as there is air pressure.","hbref":"§5.1","qid":"AB-077"},"80":{"q":"During my pre-trip inspection, I trace the air-brake foundation system on a drum-braked axle. I follow the path from the brake chamber, through the pushrod, to the slack adjuster, which rotates a shaft at the wheel. At the end of that shaft I find an S-shaped part sitting between the two brake shoes. When I make a brake application, what is the LAST mechanical action that actually forces the shoes outward against the drum to slow the wheel?","options":["The pushrod extends out of the brake chamber and presses directly on the brake shoes against the drum","The S-cam rotates and spreads the brake shoes apart, pressing their linings against the inside of the drum","Hydraulic fluid from a master cylinder pushes a wheel piston that clamps the shoes onto the drum","The slack adjuster squeezes a pair of pads against a rotor mounted on the wheel hub"],"answer":1,"explanation":"Air pressure moves the pushrod and slack adjuster to rotate the S-cam, which spreads the brake shoes so their linings press against the inside of the drum.","handbook":"Pressing the brakes turns the S-cam, which pushes the shoes against the drum.","hbref":"§5.1","qid":"AB-078"},"81":{"q":"During my pre-trip inspection I notice my rig has several metal tanks mounted along the frame, separate from the engine and fuel system. A newer driver asks me what these supply (storage) tanks actually do for the air brake system. Which answer correctly explains their job?","options":["They build and pressurize the air, taking over the pumping work whenever the compressor reaches governor cut-out at about 125 psi","They remove the water and oil from the air so the lines never need to be drained at the end of the day","They hold the reserve of compressed air so there is enough pressure available to operate the brakes","They sense low pressure and trigger the warning light and buzzer before air drops below about 60 psi"],"answer":2,"explanation":"The supply tanks hold a reserve of compressed air so there is always enough pressure available to operate the service, parking, and emergency brakes.","handbook":"Air storage tanks hold compressed air to operate the brakes.","hbref":"§5.1","qid":"AB-079"},"82":{"q":"I'm driving a loaded straight truck when a major air line ruptures. The air gauge needle is steadily falling, the low-air warning light and buzzer have already triggered, and I do not touch the brake pedal. As the pressure keeps dropping, what causes my truck to come to a stop on its own?","options":["The service brakes self-apply through the foot valve once the gauge passes the governor cut-out point","The safety relief valve vents the system, which mechanically forces the service brakes against the drums","The low-air warning circuit energizes the brakes the instant the light and buzzer come on","The spring brakes apply automatically once the falling air pressure reaches the low range where the springs take over"],"answer":3,"explanation":"Spring brakes are held off by air, so when leaking pressure falls into the low range (about 20-45 psi) the springs apply the brakes automatically.","handbook":"Spring brakes apply automatically when air pressure gets too low.","hbref":"§5.1","qid":"AB-080"},"84":{"q":"On a delivery run, my low-air warning light suddenly comes on and I notice one of my two air pressure gauges is dropping fast while the other holds steady. My rig has a dual air brake system. Which statement BEST explains why I still have some braking ability right now?","options":["The system is split into two separate circuits, so the failing circuit's loss does not disable the circuit that is still holding pressure","Both circuits draw from one large shared tank, so the steady gauge is feeding air back into the failing side","A hydraulic backup brake automatically takes over whenever one air circuit loses pressure","The dual system removes the parking brake, so all remaining air is routed to the service brakes"],"answer":0,"explanation":"A dual air brake system has two independent circuits, so a leak or failure in one circuit does not drain the other, which keeps holding pressure and braking its part of the vehicle.","handbook":"A dual air brake system has two separate brake circuits.","hbref":"§5.1","qid":"AB-081"},"85":{"q":"I just started the engine on my tractor-trailer in a cold yard. The low air warning light is off, but my gauge still reads only 65 psi as I get ready to pull out of the lot. According to Texas DPS procedure, what is the LOWEST pressure I should let build before I begin driving?","options":["65 psi, because the low air pressure warning light has already turned off","About 100 psi, so there is enough air to operate the brakes safely","About 60 psi, the point at which the low air warning shuts off","About 125 psi, the governor cut-out, before releasing the parking brake"],"answer":1,"explanation":"Let air pressure build to at least about 100 psi before driving so there is enough air to operate the service and emergency brakes safely.","handbook":"Let the air system build to at least about 100 psi before driving.","hbref":"§5.3","qid":"AB-082"},"86":{"q":"During my pre-trip inspection on a single straight truck, I build the air system up to about 125 psi, shut the engine off, and chock the wheels. I leave the parking brake knob pushed in so the brakes stay released, then I watch the dash gauge. In the first minute the needle falls more than 4 psi. What is this telling me about the vehicle?","options":["Nothing is wrong; with the engine off the air in the tanks is just cooling and contracting, so a drop this size in the first minute is expected.","The reading proves the spring brakes have applied themselves correctly, since pressure always bleeds off fast once the parking system engages.","The system is leaking air faster than allowed; with brakes released a single vehicle should lose no more than 2 psi per minute, and more than 4 psi means a leak to find and fix.","This confirms the governor has reached cut-out and stopped the compressor, which is the normal way pressure behaves after you shut the engine down."],"answer":2,"explanation":"With brakes released a single vehicle should lose no more than 2 psi per minute, so a loss greater than 4 psi signals an air leak that must be found and fixed.","handbook":"A fast pressure drop with the engine off indicates an air leak.","hbref":"§5.3","qid":"AB-083"},"87":{"q":"I'm parked at a loading dock when a slow air leak drains my supply tanks and the system pressure keeps falling toward zero. As the pressure bleeds off, what does my air brake system do to keep the rig from rolling, and why? Choose the statement that is TRUE.","options":["The service brakes use stored hydraulic fluid to clamp the wheels, so the truck stays put even with no air left in the tanks.","Nothing holds the truck once pressure is gone; that single small leak instantly releases every brake and the rig is free to roll.","The compressor automatically pumps the leak back up to 125 psi, so the foot-valve service brakes keep the vehicle stopped on their own.","The spring (parking) brakes apply automatically as pressure drops into the 20-45 psi range, mechanically holding the wheels without any air."],"answer":3,"explanation":"Spring parking brakes are held off by air, so as pressure drops into the 20-45 psi range powerful springs apply the brakes automatically and hold the wheels without any air.","handbook":"Spring brakes apply automatically if air pressure is lost.","hbref":"§5.1","qid":"AB-084"},"88":{"q":"I just started the engine on my air-brake tractor and the air pressure gauge reads only 50 psi, with the low-air warning buzzer still sounding. I am parked, loaded, and running late for my delivery. What should I do before I release the parking brake and pull out of the yard?","options":["Wait, keeping the engine running, until pressure builds up to about 100 psi and the low-air warning shuts off","Pull out slowly at 50 psi, since the brakes will keep building pressure as I drive to the delivery","Open the tank drain valves to bleed off the trapped air so the compressor can refill the tanks faster","Disconnect the low-air warning buzzer so it stops sounding, then drive once the noise has stopped"],"answer":0,"explanation":"Keep the engine running and wait until pressure builds to about 100 psi and the low-air warning shuts off before driving.","handbook":"Let the air pressure build to about 100 psi before driving.","hbref":"§5.3","qid":"AB-085"},"89":{"q":"I'm hauling a loaded combination down a long mountain grade and I've been holding steady pressure on the brake pedal the whole way. Near the bottom, the pedal still feels firm but the rig barely slows when I press it. Which explanation BEST accounts for why my brakes have lost their stopping power?","options":["The continuous braking pushed system air pressure above governor cut-out, so the brakes can no longer build enough force","Continuous braking overheated the brake drums and linings, and that heat reduces how much friction the brakes can produce","Steady braking gradually bled the air tanks down, and the spring brakes partially released to compensate","The slack adjusters tightened from the heat, pulling the linings away from the drums"],"answer":1,"explanation":"Sustained continuous braking on a long downgrade overheats the drums and linings, and that heat reduces the friction the brakes can produce, causing brake fade.","handbook":"Brakes can fade on a long downgrade when heat makes them less effective.","hbref":"§5.3","qid":"AB-086"},"90":{"q":"I'm coming up on a stop sign in my air-brake truck and I press the brake pedal firmly. There's a noticeable delay before I actually feel the truck start to slow down, even though my foot moved instantly. My instructor calls this 'brake lag.' What is actually happening during that delay?","options":["My slack adjusters are out of alignment, so the pushrods are too slow to seat the shoes","My reaction time as a driver is what creates the lag between deciding and braking","Air takes a fraction of a second to travel through the lines and reach the brakes","The air pressure has dropped below cut-in, so the governor must repressurize first"],"answer":2,"explanation":"Brake lag is the roughly half-second it takes for compressed air to travel through the lines from the pedal to the brake chambers, a normal feature of every air-brake system.","handbook":"Air brakes have a short lag before they apply after you press the pedal.","hbref":"§5.2","qid":"AB-087"},"91":{"q":"During my pre-trip inspection on an older air-brake tractor, I let the air build up, shut off the engine, and start fanning the brakes to bleed pressure down. As the gauge falls toward 60 psi, a small mechanical arm suddenly swings down into my view above the windshield. The instructor calls it a 'wig-wag.' What is the purpose of this device?","options":["It is the governor signaling that the compressor has reached cut-out and stopped pumping air into the tanks","It is the modulating control valve dropping down to let me apply the spring brakes gradually in an emergency","It is the automatic drain valve releasing the water and oil that collect in the supply tank","It is a mechanical low-air warning that physically drops into view to alert me that pressure is getting dangerously low"],"answer":3,"explanation":"A wig-wag is a mechanical low-air warning whose spring-loaded arm drops into the driver's view to signal that air pressure is getting dangerously low.","handbook":"A wig-wag is a low-air warning device.","hbref":"§5.1","qid":"AB-088"},"92":{"q":"During my pre-trip, I press the brake pedal and watch the foundation brakes on a wheel. As air fills the brake chamber, the push rod extends outward. In a properly working S-cam drum brake, what is the NEXT thing this push rod motion is supposed to do?","options":["Rotate the slack adjuster, which twists the S-cam and forces the brake shoes against the drum","Push the brake shoes directly against the drum without any cam or lever involved","Open the spring brake chamber so the parking springs help apply the service brakes","Feed extra compressed air into the supply tank to keep system pressure up"],"answer":0,"explanation":"Air in the brake chamber pushes the push rod, which rotates the slack adjuster and twists the S-cam, forcing the brake shoes apart against the drum.","handbook":"The brake chamber and push rod turn the slack adjuster and S-cam.","hbref":"§5.1","qid":"AB-089"},"93":{"q":"I just bought a 2020 truck tractor with air brakes, and I'm tracing the ABS wiring to confirm the anti-lock system meets the federal requirement for a vehicle this new. As I check each axle, which wheels am I required to find ABS on?","options":["Only the steer (front) wheels, since that is where locking would cause loss of steering","All of the wheels on the tractor, since newer tractors must have ABS on every wheel","Only the rear drive wheels, since that is where the heaviest braking load occurs","None of the wheels, because ABS is optional equipment that the buyer adds later"],"answer":1,"explanation":"ABS is required on every wheel of truck tractors built on or after March 1, 1997, so a newer tractor must have ABS on all wheels.","handbook":"Newer truck tractors must have ABS on all wheels.","hbref":"§5.3","qid":"AB-090"},"94":{"q":"During a pre-trip inspection of my combination vehicle, the dash tells me the tractor's own ABS is fine, but I still need to confirm the trailer's ABS is working. The trailer was built in 1999, so it has its own ABS and a separate malfunction lamp I must check. Walking around the rig, where should I look to find that trailer ABS malfunction lamp?","options":["Mounted on the front of the trailer near the kingpin, so it faces the tractor cab","On the dash inside the cab, right next to the tractor's own ABS warning light","On the left side or left rear of the trailer, where it is visible during the walk-around","Inside the trailer's air supply tank, behind the manual drain valve"],"answer":2,"explanation":"On a 1999 trailer, the ABS malfunction lamp is mounted on the trailer's left side or left rear so it is visible during the walk-around inspection.","handbook":"The trailer ABS malfunction lamp is usually on the left rear of the trailer.","hbref":"§5.3","qid":"AB-091"},"95":{"q":"I'm driving a medium-duty truck equipped with an air-over-hydraulic brake system. During my pre-trip, I want to understand what the air portion of this system actually does so I know what I'll lose if the air supply fails. Which statement correctly describes the role of the air pressure in this setup?","options":["The air pressure circulates through the calipers to cool the hydraulic fluid and stop it from overheating on long downgrades","The air pressure keeps the hydraulic fluid topped off, automatically replacing fluid that is lost through worn seals","The air pressure runs the compressor that recharges the battery so the hydraulic pump always has power","The air pressure acts on the hydraulic system to boost the braking force the driver applies at the pedal"],"answer":3,"explanation":"In an air-over-hydraulic system, the air pressure boosts the force the driver applies at the pedal, which the hydraulic fluid then sends to the wheel brakes.","handbook":"Air-over-hydraulic brakes use air pressure to boost hydraulic braking.","hbref":"§5.1","qid":"AB-092"},"96":{"q":"During a pre-trip inspection, you discover that your slack adjusters show excessive pushrod travel, meaning the brakes are out of adjustment. If you drive anyway and head down a long, steep grade, what is the MOST likely consequence of this defect?","options":["The braking power will be reduced, and the brakes may fail completely as they heat up on the grade","The brakes will grip harder than normal, raising the risk of locking the wheels and skidding","The system will simply use less air, so you can safely fan the brake pedal longer on the grade","The low air pressure warning will trigger early, but braking strength itself stays unaffected"],"answer":0,"explanation":"Out-of-adjustment brakes reduce braking power and can fade and fail completely under heat load, such as on a long, steep downgrade.","handbook":"Brakes out of adjustment are weaker and may fail.","hbref":"§5.3","qid":"AB-093"},"97":{"q":"I'm rolling down a slight grade in my air-brake truck and I press the brake pedal a little harder to slow down. As I push the pedal, one of my two pressure gauges climbs higher the harder I press. Which gauge am I watching, and what is it telling me?","options":["The supply pressure gauge, telling me how much air is still stored in my tanks","The application pressure gauge, telling me how much air pressure I am applying with the brake pedal","The governor cut-out gauge, telling me when the compressor will stop pumping at 125 psi","The low-air warning gauge, telling me pressure is about to drop below 60 psi"],"answer":1,"explanation":"The application pressure gauge shows the air pressure being sent to the brakes, so its reading rises as you press the pedal harder and drops as you ease off.","handbook":"The application pressure gauge shows how much air pressure you are applying.","hbref":"§5.1","qid":"AB-094"},"98":{"q":"I'm driving an air-brake tractor-trailer at 55 mph on a dry highway when I spot a stalled car ahead and slam the brake pedal hard. A classmate insists the half-second it takes for the air to actually travel through the lines and apply the brakes barely matters at highway speed. Roughly how much EXTRA stopping distance does that brake lag add at 55 mph, on top of my perception, reaction, and effective braking distances?","options":["None worth counting — the half-second lag is too short to add any measurable distance at 55 mph","About 12 feet — roughly the length of the tractor before the brakes grab","About 32 feet — nearly the length of the trailer travels before the brakes take hold","About 60 feet — since lag distance keeps doubling as speed climbs"],"answer":2,"explanation":"Air brakes have about a half-second lag, so at 55 mph the vehicle rolls roughly 32 extra feet before the brakes take hold.","handbook":"Brake lag adds about 32 feet of stopping distance at 55 mph.","hbref":"§5.2","qid":"AB-095"},"99":{"q":"During my pre-trip inspection, I shut off the engine with the system fully charged and watch the gauge. The needle keeps creeping downward and won't settle, even though all my doors are closed and I'm not pressing the brake pedal. Before I decide whether this truck is safe to drive, which condition tells me I have a leak serious enough that I should NOT take it on the road?","options":["The gauge climbed to exactly 125 psi during build-up, so the slow drop afterward is just the normal cooling of the tanks","I can hear a faint hiss from the compressor area, but as long as the low-air warning buzzer has not sounded yet, the system is fine to drive","The pressure drops only until the governor cuts in again, which proves the compressor is keeping up with the demand","With the engine off and brakes released, the air pressure will not hold steady and keeps falling beyond the allowed leakage rate"],"answer":3,"explanation":"With the engine off and brakes released, pressure must hold steady; if it keeps falling past the allowed leakage rate, the leak is too large to drive on safely.","handbook":"Do not drive if the air system cannot hold pressure.","hbref":"§5.3","qid":"AB-096"},"100":{"q":"During my pre-trip, the low-air warning buzzer keeps sounding because my air pressure won't build up past 70 psi, even with the engine running at fast idle. A mechanic tells me the component responsible for generating and pumping air into the tanks has failed and must be replaced. Which component is he referring to?","options":["The air compressor, which pumps air into the storage tanks to power the system","The governor, which controls when air is pumped into the storage tanks","The slack adjuster, which regulates air flow to the brake chambers","The safety relief valve, which releases air to maintain tank pressure"],"answer":0,"explanation":"The air compressor generates and pumps air into the storage tanks, so when pressure cannot build, the compressor is the failing component.","handbook":"The air compressor pumps air into the air storage tanks.","hbref":"§5.1","qid":"AB-097"},"101":{"q":"During my pre-trip inspection, I let the engine run and watch the air gauge climb. At about 125 psi the compressor stops loading the system, and after I make several brake applications and the pressure falls to about 100 psi, the compressor begins pumping again. Which component is responsible for starting and stopping the compressor at these pressures?","options":["The safety relief valve, which dumps air once the tanks reach roughly 150 psi","The governor, which cuts the compressor out near 125 psi and cuts it back in near 100 psi","The low air pressure warning device, which signals the compressor before pressure drops below 60 psi","The compressor's own unloader pistons, which set the system's working pressure on their own"],"answer":1,"explanation":"The governor controls the compressor, cutting it out at about 125 psi and cutting it back in at about 100 psi.","handbook":"The governor controls when the compressor pumps air.","hbref":"§5.1","qid":"AB-098"},"102":{"q":"During my pre-trip inspection, I start the engine and watch the air pressure gauge climb as the compressor pumps. I'm waiting for the governor to reach cut-out, the point where the compressor stops adding air to the tanks. At about what gauge reading should I expect that to happen?","options":["Around 100 psi, since that is where the governor controls the system","Around 150 psi, right as the system reaches its highest safe pressure","Around 125 psi, when the governor signals the compressor to stop pumping","Around 60 psi, just as the warning device shuts off and pumping ends"],"answer":2,"explanation":"Compressor cut-out, the point where the governor stops the compressor from pumping, occurs at about 125 psi.","handbook":"The governor stops the compressor around 125 psi.","hbref":"§5.1","qid":"AB-099"},"103":{"q":"I'm doing a pre-trip inspection on a single vehicle with air brakes. With the engine off, I pump the brake pedal to bleed down the system and watch the air gauge fall. At what point should the low-air warning light and buzzer activate to tell me the pressure is getting dangerously low?","options":["As soon as the gauge drops below 100 psi, since that's where the governor cuts in to rebuild air","Once pressure falls into the 20 to 45 psi range, at the same moment the spring brakes apply","The instant pressure climbs past 125 psi, where the governor cuts out and stops pumping","Before the gauge drops below 60 psi, while there is still enough air to stop safely"],"answer":3,"explanation":"The low air pressure warning must come on before pressure drops below 60 psi, leaving enough air to bring the vehicle to a safe stop.","handbook":"The low air pressure warning must activate by 60 psi.","hbref":"§5.1","qid":"AB-100"},"104":{"q":"During my pre-trip inspection, I start the engine and watch one of the dash gauges climb steadily until the governor cuts out the compressor around 125 psi. Glancing back and forth between that gauge and the others, which reading is this particular gauge actually telling me?","options":["How much air pressure is currently stored in the air tanks","How hard I am pressing the brake pedal, shown as application pressure","The point at which the low air pressure warning light will switch on","How many seconds the air took to build from 85 to 100 psi"],"answer":0,"explanation":"The air pressure gauge shows how much air pressure is currently stored in the air tanks.","handbook":"The air pressure gauge shows the pressure in the air tanks.","hbref":"§5.1","qid":"AB-101"},"105":{"q":"It is winter, and my tractor-trailer has manual drain valves on its air tanks. I have just finished a long shift and I notice water and compressor oil have collected in the system. Knowing this can freeze and damage components overnight, when should I be opening these manual drain valves to bleed off the moisture?","options":["Only once a week, since the air dryer removes most moisture between drainings","At the end of every day, draining the tanks completely before I park the vehicle","Only when the low air pressure warning light comes on below 60 psi","About once a month, or any time I notice the tanks are visibly leaking air"],"answer":1,"explanation":"Drain air tanks with manual valves completely at the end of every day to remove water and oil that collect during operation.","handbook":"Drain manual air tanks at the end of each day.","hbref":"§5.1","qid":"AB-102"},"106":{"q":"During my pre-trip walkaround, my examiner asks me to name the three separate braking systems that are combined into one air brake setup. I correctly say the service brakes and the parking brakes. Which one must I name as the third system to complete the answer?","options":["The retarder system, which slows the truck without using the brake pedal","The dual-circuit system, which splits the air into a primary and secondary supply","The emergency brake system, which stops the truck if the main air supply fails","The modulating system, which lets me ease the spring brakes on gradually"],"answer":2,"explanation":"An air brake system combines three systems: the service brakes, the parking brakes, and the emergency brakes that stop the vehicle if the air supply fails.","handbook":"Air brakes use service, parking, and emergency systems.","hbref":"§5.1","qid":"AB-103"},"107":{"q":"I'm driving a loaded straight truck when a hose ruptures and my air pressure keeps bleeding off. The low air warning light and buzzer have already been going for a while, and now I feel the truck slowing hard on its own as the spring (parking/emergency) brakes apply by themselves. EXCEPT for an exact reading, into roughly what pressure range had the air dropped at the moment those spring brakes came on automatically?","options":["About 100 psi, the point where the governor would normally cut in","About 60 psi, the same point the low air pressure warning first triggers","About 125 psi, the point where the governor cuts out and stops pumping","About 20 to 45 psi, where the spring brakes apply automatically"],"answer":3,"explanation":"Spring brakes are held off by air pressure and apply automatically when pressure falls into the 20 to 45 psi range.","handbook":"Spring brakes come on when pressure drops to about 20–45 psi.","hbref":"§5.2","qid":"AB-104"},"108":{"q":"I just brought my loaded rig down a long, steep grade, riding the air brakes hard the whole way. At the bottom I pull into a rest area and feel the wheels giving off serious heat. EXCEPT for one of these, the others are sound moves before I leave the cab. Which action should I AVOID right now?","options":["Setting the parking (spring) brakes while the brake drums are still very hot from the descent","Chocking the wheels and letting the brakes cool before relying on the spring brakes to hold","Letting air pressure build back to governor cut-out before I count on the system to hold","Checking pushrod travel later, since out-of-adjustment brakes are the most common air-brake defect"],"answer":0,"explanation":"Never set the parking (spring) brakes when the brake drums are very hot, such as right after a steep downgrade, because it can damage them.","handbook":"Do not use the parking brake if the brakes are very hot.","hbref":"§5.2","qid":"AB-105"},"109":{"q":"I'm descending a long, steep grade in a loaded combination vehicle. To keep my speed in check, I keep pressing and releasing the brake pedal over and over (\"fanning\"). Which of the following is the MOST likely result of doing this all the way down the hill?","options":["My brakes will stay cooler because they get a chance to release and breathe between each application","My air pressure will drop because each release lets air escape faster than the compressor can replace it, eventually using up my air","The compressor will pump faster with every release, so my tanks will actually build more air the longer I fan","Nothing changes as long as I stay above the 60 psi low-air warning level the whole way down"],"answer":1,"explanation":"Do not fan or pump the brakes on a long downgrade because each release lets air escape faster than the compressor can replace it, eventually using up your air.","handbook":"Fanning the brakes wastes air pressure.","hbref":"§5.2","qid":"AB-106"},"110":{"q":"I'm driving a tractor-trailer with air brakes and I press the brake pedal hard, but I notice the vehicle does not begin to slow the instant my foot moves the pedal — there's a short delay of about half a second before braking actually starts. This particular delay, caused by air having to travel through the brake lines to the chambers, is known as:","options":["Brake fade, the loss of braking power from overheated drums on a long downgrade","Brake pull, the tendency of the vehicle to veer to one side when I apply the brakes","Brake lag, the time the air needs to travel through the lines before the brakes work","Brake imbalance, the uneven braking force between the tractor and the trailer axles"],"answer":2,"explanation":"Brake lag is the roughly half-second delay caused by air needing time to travel through the brake lines before the brakes take hold.","handbook":"Air brakes have a brake lag before they take effect.","hbref":"§5.2","qid":"AB-107"},"111":{"q":"I'm comparing my air-brake tractor to a friend's car with hydraulic brakes. Assuming identical speed, road, and reaction time, how does the air brakes' roughly half-second brake lag affect my TOTAL stopping distance compared to the hydraulic-brake vehicle?","options":["It has no effect, because total stopping distance is set only by perception and reaction distance.","It cuts the total stopping distance roughly in half once the air reaches the brake chambers.","It slightly shortens the total stopping distance because the air pressure builds braking force faster.","It slightly lengthens the total stopping distance because brake-lag distance is added to the total."],"answer":3,"explanation":"The roughly half-second brake lag adds a brake-lag distance segment to total stopping distance, about 32 feet at 55 mph.","handbook":"Brake lag adds to total stopping distance.","hbref":"§5.2","qid":"AB-108"},"112":{"q":"During my pre-trip, I keep building air and watch the gauge climb past the governor cut-out. Something has failed and the compressor never stops pumping, so pressure keeps rising. At roughly what pressure should the safety relief valve in the supply (wet) tank pop off to protect the system from over-pressurization?","options":["About 150 psi","About 125 psi","About 100 psi","About 60 psi"],"answer":0,"explanation":"The safety relief valve in the supply tank opens at about 150 psi to vent excess pressure if the governor fails.","handbook":"The safety valve is usually set to open at about 150 psi.","hbref":"§5.1","qid":"AB-109"},"113":{"q":"During my pre-trip air-brake inspection, the examiner tells me to \"apply firm pressure to the foot valve and hold it\" while we watch the air-leakage rate. I look down at the controls and pedals in the cab. Which one is the examiner telling me to press?","options":["The yellow, diamond-shaped knob on the dash, since that is what controls the braking air supply","The brake pedal on the cab floor, because in an air brake system it is also called the foot or treadle valve","The accelerator pedal, because air pressure has to be raised before the leakage test can begin","The clutch pedal, since pressing it down is what releases the spring brakes to apply pressure"],"answer":1,"explanation":"The brake pedal on the cab floor is the service brake control, also called the foot valve or treadle valve.","handbook":"The brake pedal is also called the foot valve or treadle valve.","hbref":"§5.1","qid":"AB-110"},"114":{"q":"I'm driving a tractor-trailer with a dual air brake system when the low air pressure warning light and buzzer suddenly come on, telling me the primary air system has lost pressure. Which of the following is TRUE about what I can expect from my brakes at this moment?","options":["Both the primary and secondary systems shut down together, so I have no braking power left at all","The spring brakes immediately lock all wheels solid, and I should steer hard to keep control","The secondary system is still charged and will continue to provide braking, so I can brake to a safe stop","My stopping power doubles because the secondary system dumps its full air pressure into the wheels"],"answer":2,"explanation":"In a dual air brake system the separate secondary circuit stays charged when the primary fails, so it can still brake the vehicle to a safe stop.","handbook":"In a dual system, the remaining system can still stop the vehicle.","hbref":"§5.1","qid":"AB-111"},"115":{"q":"During my pre-trip inspection, the air system is fully charged and the engine is off. I want to confirm the low-air-pressure warning device is working properly before I drive. Which action correctly tests it?","options":["Start the engine and let the governor pump until the safety relief valve opens, then listen for the buzzer","Apply and hold the brake pedal firmly for one minute and watch the gauge for a sudden pressure spike","Pull out the yellow parking-brake knob and confirm the spring brakes set before the warning sounds","With the engine off, step on and release the brake pedal to bleed air down and watch for the warning by 60 psi"],"answer":3,"explanation":"With the engine off, pump the brake pedal to bleed air from the tanks and confirm the low-air warning comes on before pressure drops below 60 psi.","handbook":"Test the low-air warning by pumping pressure down.","hbref":"§5.3","qid":"AB-112"},"116":{"q":"I'm driving a single straight truck with a standard air brake system when my air compressor starts failing and pressure keeps falling. My low-air warning light and buzzer have already been on for a while, and I'm slowing to pull off the road. At what approximate pressure should I expect the spring (parking) brakes to come on by themselves and bring the truck to a stop, EXCEPT if I have already parked?","options":["Somewhere in the 20 to 45 psi range","Just below 60 psi, the same point the warning light comes on","Around 100 psi, when the governor would normally cut in","About 125 psi, when the governor normally cuts out"],"answer":0,"explanation":"Spring (parking/emergency) brakes are held off by air and apply automatically when pressure falls into the 20 to 45 psi range.","handbook":"Spring brakes should activate by about 20–45 psi.","hbref":"§5.3","qid":"AB-113"},"117":{"q":"During my pre-trip, I'm about to perform the air leakage rate test on my single vehicle. I've started the engine and the air gauge currently reads about 90 psi and is still climbing. Before I begin timing the pressure drop, what must I do FIRST so the test is valid?","options":["Pump the brake pedal several times to bleed the lines down to the cut-in pressure, then start timing","Let the system keep building until the governor cuts out near 125 psi, then turn off the engine","Drain all of the air tanks completely so I'm measuring loss from a fresh, empty system","Apply the parking brake and rev the engine until the safety relief valve opens near 150 psi"],"answer":1,"explanation":"The air leakage test must be done with the system fully charged to governor cut-out near 125 psi and the engine off so the compressor cannot mask a leak.","handbook":"Build pressure to governor cut-out, then turn off the engine to check leakage.","hbref":"§5.3","qid":"AB-114"},"118":{"q":"During my pre-trip on a straight (single) truck, I shut off the engine, chock the wheels, and fully charge the air system to governor cut-out. I leave the parking brake released and watch the dash gauge for one minute to check for leaks. Which reading tells me the leakage is still within the legal limit and I can move on?","options":["A drop of up to 3 psi in that minute is acceptable, since that is the released limit for a single vehicle","Any drop is a failure; with the engine off and brakes released the gauge must hold perfectly steady","A drop of no more than 2 psi in that minute is within limits for this released single-vehicle check","A drop of up to 4 psi in that minute is fine because the brakes are released, not applied"],"answer":2,"explanation":"For a released single vehicle, an air loss of no more than 2 psi per minute is within the allowable limit.","handbook":"With brakes released, single-vehicle leakage should be under 2 psi per minute.","hbref":"§5.3","qid":"AB-115"},"119":{"q":"During my pre-trip inspection on a straight (single) box truck, I've fully charged the system to about 125 psi, shut off the engine, and pressed and held the brake pedal down. I'm now watching the air gauge for one full minute to check the leakage rate. To pass this test, the pressure drop I observe should be no more than:","options":["2 psi in that minute, since holding the pedal down is the same standard as a released-brake check","4 psi in that minute, which is the limit a single straight truck is allowed to lose","10 psi in that minute, as long as the low-air warning never comes on during the test","3 psi in that minute, the maximum allowable loss for a single vehicle with the brakes applied"],"answer":3,"explanation":"With the brakes applied, a single vehicle may lose no more than 3 psi per minute and still be within limits.","handbook":"With brakes applied, single-vehicle leakage should be under 3 psi per minute.","hbref":"§5.3","qid":"AB-116"},"120":{"q":"During a pre-trip inspection, I pull on a slack adjuster and notice it moves more than an inch of free play, telling me the brakes are out of adjustment. If I drive without fixing this, what is the MOST direct safety consequence I should expect?","options":["The brakes will work poorly because the excessive pushrod travel reduces braking power","The low air pressure warning buzzer will sound before pressure drops below 60 psi","The air compressor governor will fail to cut out at about 125 psi","The spring brakes will apply automatically once pressure falls into the 20 to 45 psi range"],"answer":0,"explanation":"Slack adjusters that are too loose cause excessive pushrod travel, which reduces the braking force reaching the wheels and makes the brakes work poorly.","handbook":"Slack adjusters that are too loose reduce braking.","hbref":"§5.1","qid":"AB-117"},"121":{"q":"During my pre-trip, I crawl under the trailer and have my helper hold the brakes down hard while I watch a brake chamber pushrod. I want to know whether the slack adjuster is still in spec. About how far can that pushrod travel before I should consider the brakes out of adjustment and have them serviced?","options":["About a half a foot of travel before it is out of spec","About 1 inch of travel before it is out of spec","About 6 inches of travel before it is out of spec","Roughly 2 feet of travel before it is out of spec"],"answer":1,"explanation":"Pushrod travel should not exceed about 1 inch when the brakes are applied hard; within that, the slack adjuster is still in spec.","handbook":"Excessive pushrod travel (more than about 1 inch) means adjustment is needed.","hbref":"§5.1","qid":"AB-118"},"122":{"q":"During my pre-trip inspection, I find a hairline crack running across one of my brake drums and notice the brake shoe on that wheel is worn down nearly to the rivets. I still have full air pressure and the brakes seem to apply fine when I press the pedal. What does this condition mean for my vehicle?","options":["The vehicle is fine to drive as long as air pressure builds to governor cut-out and the low-air warning works","It is acceptable for now because the brakes still apply firmly during the 5 mph stop test","The vehicle is out of service and must not be driven until the cracked drum and worn shoe are repaired","It is safe in dry conditions but should be avoided only when driving in rain or on wet roads"],"answer":2,"explanation":"A cracked drum or shoes worn to the rivets is an automatic out-of-service condition, and the vehicle must not be driven until those parts are repaired.","handbook":"Cracked or badly worn brake drums or shoes are out of service.","hbref":"§5.1","qid":"AB-119"},"124":{"q":"I'm hauling a loaded trailer on a rain-slick interstate when traffic suddenly stops ahead. I jam the brake pedal to the floor and my rig is equipped with ABS. Based on what ABS is actually designed to do, what is the realistic benefit I should expect from it in this hard stop?","options":["It will cut my total stopping distance well short of what the same rig would need without ABS","It will pump the brakes for me so I never have to use stab braking on this slick surface","It will automatically downshift and hold my air pressure so the spring brakes never set","It will keep my wheels from locking up so I can still steer around the stopped traffic"],"answer":3,"explanation":"ABS does not shorten stopping distance; it prevents wheel lockup during hard braking so you keep steering control to maneuver around hazards.","handbook":"ABS helps you keep steering control during hard braking.","hbref":"§5.4","qid":"AB-120"},"125":{"q":"During a pre-trip inspection I trace the path of compressed air from the tanks toward one wheel. I want to find the single component where the stored air pressure is finally converted into the mechanical pushing force that physically moves the brake linkage. Which component am I looking for?","options":["The brake chamber, because it converts air pressure into the mechanical force that works the brakes","The slack adjuster, because it is the part that pushes out to press the linings against the drum","The air compressor, because it is the source of the pressure that ultimately powers the brakes","The governor, because it controls the air pressure being delivered down to the wheel"],"answer":0,"explanation":"The brake chamber converts compressed air pressure into the mechanical force that pushes the pushrod out to apply the brakes.","handbook":"The brake chamber converts air pressure to mechanical force.","hbref":"§5.1","qid":"AB-121"},"126":{"q":"During my pre-trip inspection, I crawl under the trailer to check pushrod travel because brakes out of adjustment are the most common air-brake defect. I follow the pushrod out of the brake chamber and find it bolted to one end of the slack adjuster. To understand how my braking force actually turns the wheel-brake on, I need to know what the OTHER end of that slack adjuster turns. What component does the slack adjuster connect the pushrod to?","options":["The brake pedal linkage, so pressing the pedal pulls the pushrod back","The S-cam, which it rotates to spread the brake shoes against the drum","The air dryer, which it opens to release moisture from the chamber","The governor, which it signals to cut the compressor out at 125 psi"],"answer":1,"explanation":"The slack adjuster rotates the S-cam, which spreads the brake shoes apart against the drum to stop the wheel.","handbook":"The slack adjuster connects the pushrod to the brake S-cam.","hbref":"§5.1","qid":"AB-122"},"127":{"q":"During my pre-trip, I'm checking the brakes at each wheel of my tractor-trailer and notice an S-shaped cam that rotates to push the brake shoes outward against a rotating drum. My examiner asks why I should be familiar with this design before anything else. Which answer is correct?","options":["It is the only foundation brake design that the FMCSA still permits on vehicles equipped with air brakes","It is a wedge-type foundation brake, which is what most heavy combination vehicles are built with today","It is the S-cam drum brake, the foundation brake design found most often on commercial air-brake vehicles","It is an air disc foundation brake, the type used on the large majority of trucks now on the road"],"answer":2,"explanation":"An S-shaped cam that turns to force the brake shoes against a drum identifies the S-cam drum brake, the most common foundation brake on air-brake vehicles.","handbook":"The S-cam drum brake is the most common type.","hbref":"§5.1","qid":"AB-123"},"128":{"q":"During a pre-trip inspection, my instructor tells me that when I press the brake pedal, air pressure forces a wedge that pushes the brake shoes outward against a rotating part attached to the wheel, and the friction between them slows the vehicle. Which part do the brake shoes press against to create that stopping friction?","options":["The slack adjuster, which the shoes squeeze to transfer braking force","The brake chamber, which the shoes clamp to hold the wheel","The air storage tank, which the shoes press to release pressure","The brake drum, which the shoes press against to create friction"],"answer":3,"explanation":"The brake shoes press outward against the rotating brake drum, and the friction between them slows and stops the vehicle.","handbook":"Brake shoes press against the inside of the brake drum.","hbref":"§5.1","qid":"AB-124"},"129":{"q":"During my pre-trip on a single tractor, I finish charging the air system and want to set the vehicle so it won't roll while I walk around it. Reaching for the dash, which control should I operate, and how?","options":["Pull out the yellow, diamond-shaped knob to apply the parking (spring) brakes","Pull out the red, eight-sided knob to apply the parking (spring) brakes","Push in the yellow, diamond-shaped knob to apply the parking (spring) brakes","Press and hold the brake pedal, which locks the spring brakes mechanically"],"answer":0,"explanation":"The parking (spring) brake is the yellow, diamond-shaped knob that you pull out to apply and push in to release.","handbook":"The yellow diamond-shaped knob controls the parking brakes.","hbref":"§5.2","qid":"AB-125"},"130":{"q":"I climb into my tractor first thing in the morning, start the engine, and I'm ready to roll. The yellow diamond-shaped parking brake knob is still pulled out. Before I push that knob in to release the parking brakes, which condition must I make sure is met?","options":["The engine has reached normal operating temperature and the coolant gauge has risen out of the cold range","The air pressure has built up high enough that the system is fully charged and the low-air warning is off","The fuel pressure has stabilized and the diesel has fully primed through the injection lines","The engine oil pressure has climbed into the normal band so the bearings are properly lubricated"],"answer":1,"explanation":"Spring brakes are released by air pressure, so the system must be fully charged with the low-air warning off before releasing the parking brake.","handbook":"Do not release the parking brakes until there is enough air pressure.","hbref":"§5.2","qid":"AB-126"},"133":{"q":"I'm doing a pre-trip air-brake check and I'm watching the dash gauge to test the governor. I fan the brakes to bleed air down, and the compressor kicks back on to start rebuilding air. At roughly what gauge reading should I expect the governor to CUT IN and the compressor to resume pumping?","options":["About 60 psi, right as the low-air warning would be coming on","About 125 psi, the same point where it stopped pumping earlier","About 100 psi, somewhat below the point where it cut out","About 20 psi, just as the spring brakes start to set"],"answer":2,"explanation":"The governor cuts in to resume pumping at about 100 psi, somewhat below the roughly 125 psi cut-out pressure.","handbook":"The compressor cuts in around 100 psi.","hbref":"§5.1","qid":"AB-127"},"134":{"q":"During my pre-trip inspection on a tractor-trailer with a dual air brake system, I rev the engine to a fast idle and watch the dash gauge climb. I want to confirm the air build-up rate is within spec. Watching the needle pass 85 psi, by what point should it have reached 100 psi for the build-up to be considered acceptable?","options":["Within about 3 seconds of passing 85 psi","Within about 30 seconds of passing 85 psi","Within about 60 seconds of passing 85 psi","Within about 45 seconds of passing 85 psi"],"answer":3,"explanation":"In a dual air brake system, pressure should build from 85 to 100 psi within about 45 seconds, or the system has a problem.","handbook":"In a dual system, pressure should build 85–100 psi within about 45 seconds.","hbref":"§5.3","qid":"AB-128"},"135":{"q":"During my pre-trip, the air compressor has charged my supply (wet) tank, but I notice a slow leak developing on a line downstream of my service tank. There's a one-way check valve installed between the tanks. As that leak bleeds air, what is the main job this check valve is doing for me?","options":["It blocks the already-stored air in the upstream tank from draining backward out through the leaking section","It stops air pressure from ever building up past the leak point so the system never over-pressurizes","It keeps the leaking air from ever reaching the brake chambers so the brakes still apply","It prevents the trapped air from getting cold and freezing inside the lines during the leak"],"answer":0,"explanation":"A one-way check valve allows airflow in only one direction, sealing off a downstream leak so stored air in the upstream tank cannot drain backward out.","handbook":"A one-way check valve keeps air from escaping back if a tank leaks.","hbref":"§5.1","qid":"AB-129"},"136":{"q":"During my pre-trip, I open the drain valves on my air tanks and notice one tank in particular is consistently full of water and oil sludge, far more than the others. Knowing how the system routes air from the compressor, which tank is this MOST likely to be?","options":["The dry tank, because it sits downstream and is where moisture finally condenses after cooling","The wet (supply) tank, because it receives air straight from the compressor and is where most water collects first","The fuel tank, because condensation from the air lines drains back into it overnight","Whichever tank is mounted lowest, since gravity pulls all the accumulated water down to it"],"answer":1,"explanation":"The wet (supply) tank receives hot, moisture-laden air straight from the compressor, so most water and oil condense and collect there first.","handbook":"The wet tank (supply tank) collects water and oil.","hbref":"§5.1","qid":"AB-130"},"137":{"q":"During my pre-trip inspection, I park on level ground, chock the wheels, set the parking brake by pulling the yellow diamond-shaped knob out, then release the chocks and gently pull forward against the brake in a low gear. If the parking brake is working correctly, what should happen?","options":["The vehicle should creep forward slowly, proving the spring brakes are holding partial pressure","The low air warning buzzer should sound, confirming the spring brakes engaged because pressure dropped on schedule","The vehicle should stay put and not move, showing the parking brake holds the vehicle in place","The vehicle should hold only after I also press and keep the service brake pedal pushed down firmly"],"answer":2,"explanation":"A properly working spring parking brake clamps with full force and must hold the vehicle stationary when you gently pull against it in low gear.","handbook":"Test the parking brake by gently pulling against it; it should hold.","hbref":"§5.3","qid":"AB-131"},"138":{"q":"During my pre-trip, I release the parking brake, let the bus creep forward to about 5 mph on a level lot, and I want to confirm my service brakes are working correctly before I head out. What should I do at this point?","options":["Pump the brake pedal rapidly several times and listen for the air to release each time","Hold the pedal lightly and coast to a slow stop, watching that the air gauge stays above 60 psi","Speed up to about 20 mph first so I get a more realistic, highway-like reading from the brakes","Push the brake pedal down firmly and check that the vehicle stops straight without pulling to one side and that the pedal feels firm"],"answer":3,"explanation":"A properly working service brake system stops the vehicle straight without pulling to one side, and the pedal feels firm rather than spongy.","handbook":"Test service brakes at about 5 mph by pushing the brake pedal.","hbref":"§5.3","qid":"AB-132"},"139":{"q":"During my pre-trip air-brake check, I roll forward at about 5 mph and press the brake pedal. The truck stops straight, but the pedal sinks low and feels soft and spongy under my foot instead of firm. What should I conclude from this pedal feel?","options":["It likely signals a problem in the brake system that needs to be checked before driving","It is normal because air brakes always feel softer than hydraulic brakes","It just means the air pressure is above the 125 psi governor cut-out","It shows the slack adjusters have automatically taken up the extra travel"],"answer":0,"explanation":"A soft or spongy pedal that sinks low signals a brake problem such as air in the lines, low pressure, or a leak that must be fixed before driving.","handbook":"A spongy brake pedal may indicate a problem.","hbref":"§5.3","qid":"AB-133"},"140":{"q":"I'm finishing my pre-trip and start the engine. The ABS malfunction lamp on my dash lights up at first, but it never goes out — it stays lit while I idle and after I've built full pressure. Based on this, what should I conclude about my anti-lock braking system?","options":["The lamp is simply confirming the ABS self-check ran and the system is fully functional","The ABS may not be working right and should be inspected before I drive","The lamp only signals low air pressure, so I just need to let the governor build more air","The lamp means the spring brakes are applied, so it will clear once I release the parking knob"],"answer":1,"explanation":"The ABS malfunction lamp should come on briefly at start-up then go out; if it stays on, the ABS may be faulty and must be inspected before driving.","handbook":"An ABS lamp that stays on means the ABS is not working.","hbref":"§5.4","qid":"AB-134"},"141":{"q":"I'm driving a loaded tractor-trailer when the malfunction lamp for the ABS lights up on my dash. The brakes still feel normal, but I'm worried about what just happened. Which of the following is the MOST accurate description of my braking situation right now?","options":["I have lost all braking ability and must coast to a stop using the engine and gears only","My stopping distance is now automatically shorter, so I can brake later than before","I still have my normal service brakes and can stop the vehicle, but I must brake carefully to avoid locking the wheels","Only my parking brakes will work, so I must pull the yellow knob to stop"],"answer":2,"explanation":"An ABS malfunction only disables the anti-lock feature, so you keep full normal service brakes but must brake carefully to avoid locking the wheels.","handbook":"If ABS fails, you still have normal braking.","hbref":"§5.4","qid":"AB-135"},"142":{"q":"During my pre-trip inspection, I notice excessive pushrod travel at one of the brake chambers. My tractor is equipped with automatic slack adjusters, which a coworker says are 'maintenance-free,' so he tells me I don't need to worry about them anymore. Which statement reflects the correct way to treat automatic slack adjusters?","options":["Because they self-adjust, they remove the need for any inspection during a pre-trip check","I should manually back them off while driving until the excessive free play disappears","They eliminate out-of-adjustment brakes, so my coworker is right that they can be ignored","They still must be checked regularly, because out-of-adjustment brakes are a common defect even with them"],"answer":3,"explanation":"Brakes out of adjustment are the most common air-brake defect, so even automatic slack adjusters must be checked regularly since they are not foolproof.","handbook":"Automatic slack adjusters still need to be checked.","hbref":"§5.1","qid":"AB-136"},"143":{"q":"During my pre-trip, I notice excessive pushrod travel on a slack adjuster, which tells me the brakes are out of adjustment. I'm running late and the yard tools are right there. Who should actually perform the brake adjustment before this rig goes on the road?","options":["Only a person who is trained and qualified to adjust brakes","Any current CDL holder, since holding the license proves brake competence","Me, right now, because pushrod travel is simple to reset with the yard tools","Whoever is closest and available so the rig is not delayed any further"],"answer":0,"explanation":"Because out-of-adjustment brakes directly reduce braking power, brake adjustment must be done only by a person trained and qualified to do that work.","handbook":"Brakes should be adjusted by a qualified person.","hbref":"§5.1","qid":"AB-137"},"144":{"q":"I'm driving my tractor-trailer when the low air pressure warning light flicks on, and I quickly realize my air compressor has quit pumping entirely. There's an exit with a safe shoulder coming up in about a mile. Assuming my system was fully charged, what does the reserve air in my tanks let me count on doing?","options":["Continuing to drive normally for a full day's worth of trips, since the tanks store a day's supply","Making several more brake applications to slow down and pull off safely before the air runs low","Driving indefinitely, because the spring brakes will keep recharging the service tanks for me","Getting essentially no usable braking, so I must immediately bail off the road right where I am"],"answer":1,"explanation":"The air tanks hold a reserve of compressed air so that, even after the compressor stops, you can make several more brake applications to pull off safely.","handbook":"Air tanks must hold enough air for several stops if the compressor fails.","hbref":"§5.1","qid":"AB-138"},"145":{"q":"It's a freezing winter morning and my pre-trip checklist reminds me to drain the air tanks daily so water and compressor oil don't collect and freeze up the system. I'm standing under the tractor looking for the right components to open. Which device do I actually operate to drain the accumulated water out of the air tanks?","options":["The safety relief valve, which I crack open by hand to vent the moisture out of the supply tank","The yellow diamond-shaped knob in the cab, which I pull out to release the water from the tanks","The drain valves, also called petcocks, located at the bottom of each air tank","The air compressor governor, which I reset so it pushes the trapped water back out"],"answer":2,"explanation":"Air tanks are drained using the drain valves, also called petcocks, located at the bottom of each tank to remove collected water and oil.","handbook":"Air tanks are drained using drain valves (petcocks).","hbref":"§5.1","qid":"AB-139"},"146":{"q":"You are driving a loaded straight truck with air brakes on a rural Texas highway when the low-air warning light flicks on and the buzzer sounds. The gauge is dropping through the low-pressure range. Which action is correct?","options":["Keep driving at a reduced speed to the next exit, since the spring brakes have not applied yet and you still have some air left","Continue driving but pump the brake pedal a few times to help the compressor rebuild the lost air pressure faster","Maintain your speed and ignore the alarm for now, because the warning often comes on briefly and clears itself once the governor cuts in","Stop as soon as it is safe and get off the road, because a continuing pressure drop can lead to a sudden, dangerous loss of braking"],"answer":3,"explanation":"When the low-air warning comes on with falling pressure, stop and get off the road as soon as it is safe, because continued loss can cause sudden brake failure.","handbook":"Do not drive with the low air pressure warning on.","hbref":"§5.3","qid":"AB-140"},"147":{"q":"I'm doing a pre-trip on my tractor-trailer and a mechanic mentions that my brake (stop) lights only come on when I actually press the brake pedal hard enough. On an air brake vehicle, what physically triggers that electric stop-light switch to turn the brake lights on?","options":["Air pressure building in the brake lines when the pedal is applied closes the stop-light switch","Mechanical movement of the brake pedal directly pushes the switch closed, the same as on a car","The drop in air pressure that occurs as the spring brakes begin to release closes the switch","Heat generated at the brake drums signals the switch to power the stop lights"],"answer":0,"explanation":"On air brakes the stop-light switch is electric and operated by air; rising line pressure when you press the pedal closes it and lights the brake lamps.","handbook":"The stop light switch is operated by air pressure.","hbref":"§5.1","qid":"AB-141"},"148":{"q":"I climb into my tractor-trailer first thing on a cold morning, start the engine, and get ready to release the spring brakes and pull out. Before I push in the yellow parking-brake knob to release the spring brakes and drive away, what must be true about the air pressure in my system?","options":["The low-air warning light and buzzer have just shut off, so any pressure above that point is enough to release and drive","Pressure must be built up high enough first, to normal operating range near governor cut-out, before the spring brakes are released","Pressure only needs to climb back above the 20-to-45 psi range where the spring brakes set, then I can release and go","Pressure should be bled down as low as possible so the spring brakes pop free easily, then I release the knob"],"answer":1,"explanation":"Spring brakes are held off by air, so pressure must first build to the normal operating range near governor cut-out before they will release.","handbook":"Air pressure must be high enough before releasing the spring brakes.","hbref":"§5.2","qid":"AB-142"},"149":{"q":"I'm hauling a loaded trailer down a long, steep grade and I've been riding the brakes heavily the whole way. Near the bottom I notice the brake drums have gotten extremely hot. What is the MOST likely effect this overheating will have on my air brakes?","options":["The expanding drums press tighter against the shoes, giving me noticeably stronger braking","The heat dries any moisture in the lines, so the brakes respond more quickly and firmly","The brakes will fade, meaning I have to push harder and harder to get less stopping power","Nothing changes while moving, but the hot drums will crack the moment I stop and park"],"answer":2,"explanation":"Overheated brake drums lose their ability to turn motion into heat, so the brakes fade and you must push harder for less stopping power.","handbook":"Overheated brake drums cause brake fade.","hbref":"§5.2","qid":"AB-143"},"150":{"q":"I'm driving a tractor-trailer down the highway when the trailer suddenly breaks away and its air lines rip apart, dumping all the air on the trailer side. Which device is designed to seal off and protect the air supply in my tractor so I still keep enough air to control and stop the tractor itself?","options":["The relay valve, which speeds up brake application by sending air to the rear brakes the instant I press the pedal","The quick-release valve, which dumps trapped air out fast so the brakes release the moment I let off the pedal","The foot valve (treadle), which controls how much braking air pressure I send when I press down on the brake pedal","The tractor protection valve, which closes off the tractor air supply to keep enough air to brake and steer the tractor"],"answer":3,"explanation":"If the trailer breaks away or leaks badly, the tractor protection valve automatically closes to seal off the tractor's air supply so you keep enough to brake and steer.","handbook":"The tractor protection valve protects tractor air if the trailer breaks away.","hbref":"§5.3","qid":"AB-144"},"151":{"q":"You've just finished coupling your tractor to a loaded trailer, connected the air lines, and built system pressure to governor cut-out. Before you can move the trailer, you reach for the red, eight-sided knob on your dash. What does pushing this knob IN accomplish?","options":["It charges the trailer brake system by sending air from the tractor to the trailer","It sets the trailer's spring brakes so the trailer stays parked","It releases only the tractor's parking brakes while leaving the trailer locked","It vents the trailer air lines to test the low-air warning buzzer"],"answer":0,"explanation":"Pushing in the red octagon trailer air supply knob opens the supply line and sends air from the tractor to charge the trailer's brake system.","handbook":"The trailer air supply knob supplies air to the trailer when pushed in.","hbref":"§5.3","qid":"AB-145"},"152":{"q":"I'm hauling a loaded trailer when a supply line leak starts bleeding off my air. As the gauge keeps falling, I want to know the point where the tractor protection valve will close on its own to seal off the tractor's air and protect what's left in the system. At roughly what pressure does that automatic closing happen?","options":["At about 60 psi, the same point the low air pressure warning light and buzzer first come on","In the 20 to 45 psi range, after the warning has already been going for a while","At about 100 psi, the level where the governor tells the compressor to cut in and resume pumping","At about 150 psi, the level where the safety relief valve in the supply tank would open"],"answer":1,"explanation":"The tractor protection valve closes automatically when air pressure drops into the 20 to 45 psi range, after the low-air warning has already been on for a while.","handbook":"The tractor protection valve closes at about 20–45 psi.","hbref":"§5.3","qid":"AB-146"},"153":{"q":"On my pre-trip, I notice the rear brake chambers on my trailer are mounted far to the back, a long run of air line away from the foot brake valve up in the cab. A trainee asks why pressing the brake pedal doesn't take noticeably longer to apply those far rear brakes than the front ones, given all that extra distance the air has to travel. What is the correct explanation?","options":["The rear brakes really do apply slower because of the distance, which is why air brakes use a built-in 5-second brake lag to compensate for the long air-line run","Front and rear chambers are linked by a balance valve that deliberately delays the front brakes so that both axles release at exactly the same moment","A relay valve mounted near the rear chambers uses a local air signal to apply those brakes quickly, instead of waiting for air from the pedal","A spring brake valve holds extra pressure at the rear so those brakes can apply well before the air from the pedal ever arrives back there"],"answer":2,"explanation":"A relay valve mounted near the rear chambers applies those brakes from a local air signal, speeding up rear braking instead of waiting for air from the pedal.","handbook":"Relay valves speed up rear brake application.","hbref":"§5.1","qid":"AB-147"},"154":{"q":"I'm doing a pre-trip inspection and notice my air-brake system includes a quick-release valve mounted on the front axle, near the brake chambers. A mechanic asks me to explain what this component actually does for the brakes during normal operation. Which statement correctly describes its purpose?","options":["It slows the rate at which air reaches the brake chambers so the brakes apply more gently and smoothly","It holds residual air pressure in the chambers so the spring brakes stay locked after I park","It bleeds off compressor oil and water from the lines to keep the front brakes from freezing up","It lets air escape from the brake chambers quickly so the brakes release faster when I let off the pedal"],"answer":3,"explanation":"A quick-release valve lets air escape from the brake chambers near them the instant you let off the pedal, so the brakes release faster and don't drag.","handbook":"A quick-release valve speeds up brake release.","hbref":"§5.1","qid":"AB-148"},"155":{"q":"A spring-brake chamber on my parked rig has failed and the truck won't move, but a wrecker needs to tow it a short distance off the highway. With no air available to release the brakes the normal way, which action will free the wheels so the unit can be towed?","options":["Manually cage (mechanically wind back) the spring brakes on the affected chamber","Pump up the system until the gauge reaches about 125 psi to release them","Push in the yellow diamond-shaped parking knob to let the springs off","Disconnect and cut the air lines so the chambers can't hold pressure"],"answer":0,"explanation":"Spring brakes apply by springs and are held off by air, so when a chamber fails the only way to release them for towing is to manually cage them with the caging bolt.","handbook":"Spring brakes can be released for towing by manually caging them.","hbref":"§5.2","qid":"AB-149"},"156":{"q":"On a wet, slick highway in my air-brake tractor, another driver tells me I should disconnect or back off my front-wheel brakes because they cause the steering tires to skid and make the truck harder to control in the rain. According to the Texas CDL Handbook, how should I treat my front-wheel brakes?","options":["Front-wheel brakes should be disconnected on wet roads because braking the steer tires causes a front-end skid and loss of steering","Front-wheel brakes are important and needed for normal stopping, and there is no danger of skidding because of them","Front-wheel brakes are only useful for show and add little real stopping power, so leaving them weak is acceptable","Front-wheel brakes are best left out of adjustment so the rear brakes do most of the work and the front tires last longer"],"answer":1,"explanation":"Front-wheel brakes provide real, necessary stopping power and the belief they cause skids is a myth, so they should always work properly.","handbook":"Front-wheel brakes are important for safe stopping.","hbref":"§5.2","qid":"AB-150"},"157":{"q":"I'm hauling a load on a wet two-lane highway and notice my front brakes are working hard during a stop. A veteran driver once told me to disconnect or avoid using the front brakes because they cause the rig to skid on slippery surfaces. Before I act on that advice, which statement reflects what the Texas CDL Handbook actually says about front-wheel braking?","options":["He is correct — front brakes are the leading cause of skids, so you should keep them disconnected whenever the road is wet.","He is correct, but only above 55 mph — below that speed front brakes are safe to use normally.","He is mistaken — the idea that front brakes cause skids is false, and you get the best braking when all the brakes work together.","He is partly right — front brakes are fine on dry roads but should never be relied on for stopping power in any condition."],"answer":2,"explanation":"The belief that front brakes cause skids is false; you get the best, most balanced stopping power when all the brakes work together.","handbook":"Front brakes do not cause skids; that belief is false.","hbref":"§5.2","qid":"AB-151"},"158":{"q":"I'm hauling a load at 55 mph on a dry Texas highway when I spot a stopped vehicle ahead and hit the brake pedal hard. My instructor reminds me that my air brakes have a built-in delay before they actually grip, so the truck keeps rolling for an extra distance during that half-second of lag BEFORE the wheels even begin to slow. Roughly how much EXTRA stopping distance does this brake-lag delay add at 55 mph?","options":["About 2 feet, because the half-second lag is too brief to matter much at highway speed","About 300 feet, since this delay is what makes air brakes stop so much slower than hydraulics","About 1 mile, because the air must travel all the way through the lines before any braking begins","About 32 feet, the distance the truck travels during the half-second of brake lag at 55 mph"],"answer":3,"explanation":"Air brakes have about a half-second lag, so at 55 mph the truck travels roughly 32 feet before the brakes begin to take hold.","handbook":"Brake lag adds about 32 feet at 55 mph.","hbref":"§5.2","qid":"AB-152"},"159":{"q":"I'm reviewing my CDL notes and I've already accounted for three of the four parts that make up total air-brake stopping distance: the perception distance, the reaction distance, and the brake-lag distance. Which part am I still MISSING from the total?","options":["The effective braking distance, the distance traveled once the brakes actually grab and slow the vehicle","The effective steering distance, the extra room ABS needs to keep the wheels from locking up","The compressor build-up distance, traveled while the governor pumps pressure back up to cut-out","The slack-adjuster distance, traveled while excessive pushrod free play is taken up before braking"],"answer":0,"explanation":"Total air-brake stopping distance is perception plus reaction plus brake-lag plus effective braking distance, the distance traveled after the brakes engage.","handbook":"Air-brake stopping distance adds brake lag to the effective braking distance.","hbref":"§5.2","qid":"AB-153"},"160":{"q":"I'm hauling a loaded combination rig down a long, steep mountain grade and I can feel gravity pushing the truck faster. Air-brake temperatures are climbing the longer I'm on the descent. To keep this vehicle under control all the way to the bottom, what is the correct braking technique?","options":["Stay in a higher gear so the engine runs smoother, and press the brake pedal hard and continuously to hold my speed down","Select a low gear before the descent and use light, steady brake pressure, releasing when I drop about 5 mph below my safe speed and then reapplying","Rapidly pump or 'fan' the brake pedal on and off so the brakes get a chance to cool between applications","Shift into neutral to save the engine and feather the brakes only when the rig starts to feel like it's getting away from me"],"answer":1,"explanation":"Select a low gear before the descent and use light, steady braking, releasing about 5 mph below your safe speed and reapplying as speed builds back up.","handbook":"On long downgrades, use a low gear and light, steady braking.","hbref":"§5.2","qid":"AB-154"},"161":{"q":"I'm taking my loaded rig down a long mountain grade. I've already selected a low gear, and the instructor tells me to use proper 'snub' braking to keep my speed under control. Which of the following correctly describes what I should do?","options":["Apply firm, continuous brake pressure and hold it on the whole way down to keep a steady speed","Lightly fan the brakes on and off in quick taps so the air pressure has time to recover between presses","Apply the brakes hard enough to slow about 5 mph below my safe speed, release them, then reapply as the speed builds back up","Shift into neutral and ride the brakes lightly so the engine doesn't fight my braking effort"],"answer":2,"explanation":"Snub braking means applying the brakes firmly to slow about 5 mph below your safe speed, fully releasing them, then reapplying as the speed builds back up.","handbook":"Snub braking means braking to slow, releasing, then braking again.","hbref":"§5.2","qid":"AB-155"},"162":{"q":"I'm hauling a loaded combination rig and I see a sign warning of a long, steep mountain downgrade ahead. To safely control my speed with my air brakes on the way down, when should I choose my gear?","options":["About halfway down, once I can feel how steep the grade really is and how fast I'm picking up speed","Only if the engine starts to over-rev or my brakes begin to fade and I actually need a lower gear","Near the bottom, where the road levels out and I can shift down without straining the transmission","Before I start down, while I'm still on level ground and can shift without forcing the gearbox"],"answer":3,"explanation":"Choose a low gear before you start down, while still on level ground, because transmissions are hard or impossible to downshift once rolling fast on a steep grade.","handbook":"Select your gear before starting down a grade.","hbref":"§5.2","qid":"AB-156"},"163":{"q":"During my pre-trip inspection, I'm checking the brakes on a tractor-trailer and notice that the brake linings (shoe pads) on one of the wheels have worn down dangerously thin. Everything else on the vehicle checks out fine. Under DPS rules, what should I do before this vehicle is allowed to operate?","options":["Keep the vehicle out of service until the worn linings are replaced, because dangerously thin linings make the vehicle unsafe to drive.","Drive normally but allow extra following distance, since thin linings only slightly reduce braking power.","Pump the brake pedal a few times to seat the thin linings, then continue if the pedal feels firm.","Proceed as long as the air leakage rate stays under 3 psi per minute, since lining thickness is not part of the brake check."],"answer":0,"explanation":"Brake linings worn too thin are an automatic out-of-service condition, so the vehicle must not be driven until the linings are replaced.","handbook":"Brake linings that are too thin are out of service.","hbref":"§5.1","qid":"AB-157"},"164":{"q":"During a pre-trip inspection, I park on level ground, chock my wheels, release the parking brakes, and grab a manual slack adjuster to check for excessive pushrod travel. I pull on it hard by hand. How far should it move before I conclude the brakes are properly adjusted?","options":["About one full inch of free play is the maximum allowed before adjustment","It should move less than about one inch when pulled by hand","About six inches of movement still indicates a safely adjusted brake","It should not move at all, since any movement means it is out of adjustment"],"answer":1,"explanation":"When pulled hard by hand, a manual slack adjuster rod should move less than about one inch; more free play means the brakes are out of adjustment.","handbook":"A manual slack adjuster should move less than about 1 inch.","hbref":"§5.1","qid":"AB-158"},"165":{"q":"I'm driving a loaded tractor-trailer with air brakes and approaching a stop sign at the bottom of a slight grade. I notice that when I press the brake pedal, there is a short delay before the brakes actually grab, compared to the hydraulic brakes on my pickup. To safely account for this difference, when should I begin applying the brakes?","options":["At the same point I would in a hydraulic-brake vehicle, since the half-second lag is too small to matter","A little later than usual, because the air pressure builds extra stopping force once it reaches the brakes","A little sooner than usual, to allow for the roughly half-second air-brake lag before the brakes take hold","Only after the trailer brakes engage on their own, then add pedal pressure to finish the stop"],"answer":2,"explanation":"Because of the roughly half-second air-brake lag, start braking a little sooner than usual so the delay does not add to your stopping distance.","handbook":"Allow for brake lag by braking a little sooner.","hbref":"§5.2","qid":"AB-159"},"166":{"q":"I'm taking a loaded combination down a long, steep mountain grade and I keep light, steady pressure on the brake pedal the whole way down instead of using a low gear. Holding the brakes applied continuously like this for the entire descent will most likely cause my brakes to:","options":["Stay cooler, because steady pressure spreads the workload evenly across all the drums","Hold the truck back better the longer I keep them applied on the grade","Wear down more slowly since the linings never fully release from the drums","Overheat and fade, losing the stopping power I need before the bottom"],"answer":3,"explanation":"Continuously dragging the brakes the whole way down a long grade overheats them and causes brake fade, losing stopping power before the bottom.","handbook":"Riding the brakes downhill overheats them.","hbref":"§5.2","qid":"AB-160"},"167":{"q":"I just forded a flooded low-water crossing in my air-brake straight truck, and on the dry road ahead I notice my brakes feel weak and grab unevenly on the first stop. What is the correct way to handle the wet brakes?","options":["Keep moving at a slow speed while gently applying light brake pressure so friction heat dries them out","Pull the yellow parking-brake knob and hold the spring brakes set for a minute to squeeze the water out","Accelerate hard to redline so engine and wheel speed spin the water off the linings quickly","Pump the brake pedal rapidly several times to push the trapped water out of the chambers"],"answer":0,"explanation":"Dry wet brake linings by driving slowly while applying light, steady brake pressure so the friction heat evaporates the water and restores even braking.","handbook":"Dry the brakes after driving through deep water.","hbref":"§5.2","qid":"AB-161"},"168":{"q":"I've pulled my rig onto a steep shoulder to wait out a road closure. I've set the parking brake, but I'm worried it might not hold on this grade for an extended stop. According to safe air-brake practice, what additional step should I take to keep the vehicle from rolling?","options":["Leave the engine running in low gear so the transmission helps hold the load","Place chocks against the tires to physically block the wheels from rolling","Pump the brake pedal a few times to build extra pressure in the spring brakes","Pull out the red trailer air supply knob to lock the trailer wheels harder"],"answer":1,"explanation":"On a grade the parking brakes may slowly leak down, so chock the wheels to physically block the tires as a mechanical backstop.","handbook":"On a grade, set the parking brake and chock the wheels.","hbref":"§5.2","qid":"AB-162"},"170":{"q":"During my pre-trip inspection, I'm crouched at the wheels checking the air-brake components on my tractor. As I look over the brake drums and shoes, which condition should make me put the vehicle out of service rather than drive it?","options":["The drum surface shows a smooth, bright metallic shine all the way around","The brake shoe linings still have plenty of thickness remaining on them","The brake drum has cracks running across its surface","There is a light coating of road dust and dirt on the drum face"],"answer":2,"explanation":"A brake drum with cracks across its surface is a defect that can fail under braking heat and force, making the vehicle unsafe to drive.","handbook":"Inspect brake drums for cracks.","hbref":"§5.1","qid":"AB-163"},"171":{"q":"I'm doing a pre-trip on a tractor built in 2015. While tracing the brake lines, I find a valve that automatically pulses and releases air pressure to an individual wheel hundreds of times per second to keep that wheel from locking up during hard braking. A coworker insists this component belongs to a completely different system on the truck. Which system does this modulator valve actually belong to?","options":["The dual air supply system, since it cycles air pressure between the primary and secondary tanks","The parking brake system, since it controls how the spring brakes engage and release on each wheel","The service brake system, since it directly meters the air the driver sends with the brake pedal","The ABS (anti-lock braking) system, since the modulator valve pulses pressure to keep wheels from locking so you can steer"],"answer":3,"explanation":"A valve that pulses air to a wheel many times per second to prevent lockup during hard braking is the ABS modulator valve, which preserves steering.","handbook":"The modulator valve is part of the ABS system.","hbref":"§5.4","qid":"AB-164"},"172":{"q":"I'm hooking up my tractor to a trailer and I have two air lines (gladhands) to connect: the service line and the supply/emergency line. To make sure I grab the correct supply line and don't cross my connections, which color should I be looking for on the supply (emergency) line?","options":["Red","Blue","Yellow","Green"],"answer":0,"explanation":"The trailer's emergency (supply) air line is red, matching the red eight-sided trailer air-supply knob in the cab.","handbook":"The trailer supply (emergency) line is red.","hbref":"§5.3","qid":"AB-165"},"173":{"q":"I'm hooking up my tractor to a trailer and reach for the two air lines running between the units. One carries the signal that applies and releases the trailer's brakes when I press the brake pedal (the service/control line), and the other constantly supplies air to charge the trailer's reservoirs and control the emergency line. I need to grab the correct one to connect to the service glad hand. Which color identifies the service (control) line I should be looking for?","options":["The red line, because red marks the circuit that carries the braking signal from my pedal to the trailer","The blue line, because blue marks the service (control) line that applies and releases the trailer brakes","The black line, since the neutral-colored hose is the one tied to the foot brake on most combinations","The orange line, since the brighter color flags the hose that responds to the brake pedal"],"answer":1,"explanation":"The service (control) line, which carries the brake-pedal signal to apply and release the trailer's service brakes, is blue.","handbook":"The trailer service (control) line is blue.","hbref":"§5.3","qid":"AB-166"},"174":{"q":"I'm hauling a loaded trailer on the interstate when the trailer suddenly separates from my tractor and the air supply line is torn apart. As the trailer rolls free on its own, what should happen to the trailer's brakes?","options":["They stay fully released, so the trailer keeps coasting until friction slows it down","They release only after I pull the red trailer air supply knob from the cab","They apply automatically because losing air supply triggers the trailer's emergency brakes","They pulse on and off rapidly the same way an ABS system would react"],"answer":2,"explanation":"If a trailer breaks away, the lost air supply makes the spring-loaded emergency brakes apply automatically, stopping the runaway trailer.","handbook":"If a trailer breaks away, its emergency brakes come on.","hbref":"§5.3","qid":"AB-167"},"175":{"q":"You're driving a tractor-trailer equipped with working ABS when a car cuts in front of you and stops short. You stomp the brake pedal as hard as you can to avoid a rear-end collision. With your ABS doing its job during this hard stop, what can you realistically expect to be able to do?","options":["Press the pedal to the floor and trust that ABS will noticeably shorten your overall stopping distance","Pump the brake pedal rapidly so the ABS cycles faster and grips the road harder","Hold the pedal down but keep the wheel dead straight, since steering during a hard stop will defeat the ABS","Keep the pedal pressed down firmly while still steering around the hazard, because the wheels won't lock up"],"answer":3,"explanation":"With ABS you can press the brake pedal firmly and still steer around a hazard, because the system keeps the wheels from locking up.","handbook":"With ABS you can brake hard and still steer.","hbref":"§5.4","qid":"AB-168"},"176":{"q":"I'm driving an older tractor-trailer with no ABS when a car suddenly stops dead in front of me. I've already started a hard stab-braking effort, but I need a second technique to bring the rig down fast without losing control. Other than stab braking, which method should I use to stop as quickly as possible?","options":["Controlled braking, applying the brakes firmly without letting the wheels lock up","Locked-wheel braking, pressing the pedal to the floor so the tires skid to a halt","Pumping the brakes rapidly the whole way down to keep maximum pressure at the wheels","Engine braking only, downshifting and releasing the pedal so the drivetrain slows you"],"answer":0,"explanation":"Controlled braking means applying the brakes as hard as possible without locking the wheels, since locked wheels cause skidding and loss of steering.","handbook":"Without ABS, use controlled or stab braking.","hbref":"§5.4","qid":"AB-169"},"177":{"q":"I'm doing a walk-around on my combination rig and I want to confirm the trailer has working ABS before I pull onto the highway. I climb up to check, but a coworker tells me I'm looking in the wrong spot for the ABS malfunction indicator. Where on the trailer should I actually look to find that ABS warning lamp?","options":["Up front near the kingpin, where a green lamp glows whenever the trailer ABS is armed and ready","On the left rear of the trailer, where a yellow malfunction lamp signals an ABS problem","On the rear door, where a red lamp lights to show the trailer ABS has fully failed","Up on the trailer roof, where a blue lamp is visible to the driver in the mirrors"],"answer":1,"explanation":"A trailer's ABS malfunction is shown by a yellow lamp mounted on the left rear of the trailer.","handbook":"The trailer ABS lamp is yellow, on the left rear.","hbref":"§5.4","qid":"AB-170"},"178":{"q":"You are hauling a loaded trailer on I-35 when the ABS malfunction lamp on the trailer suddenly lights up. The tractor you are driving is newer and its own ABS is still working normally. The malfunction lamp tells you only the trailer's ABS has dropped out. Which statement BEST describes what you can rely on for the rest of this trip?","options":["Because the trailer ABS failed, you have lost the service brakes on the trailer and must stop immediately to avoid a jackknife.","Because the trailer ABS failed, your stopping distance is now shorter than it was before the warning lamp came on.","Because only the ABS has failed, you still have normal service brakes on the whole rig, but the trailer wheels can now lock up during hard braking.","Because only the trailer ABS failed, the tractor's working ABS will automatically take over braking control for the trailer wheels."],"answer":2,"explanation":"An ABS failure disables only the anti-lock function, so your normal service brakes still work, but the affected wheels can lock up under hard braking.","handbook":"If trailer ABS fails, you still have normal brakes.","hbref":"§5.4","qid":"AB-171"},"180":{"q":"During my pre-trip, I notice my air-brake dash has two separate pressure needles instead of one. As I let the engine run, both needles climb until the governor cuts out, and each holds steady at its own reading. What does the presence of these two needles tell me about how this vehicle is built?","options":["It has two air compressors, one feeding each needle independently","One needle reads the service brakes and the other reads the parking brakes","It has two governors, so each system cuts out at a different psi","It is a dual air brake system: a primary and a secondary air system"],"answer":3,"explanation":"Two needles on the dash mean a dual air brake system with two separate air systems, a primary and a secondary, sharing one set of controls.","handbook":"Dual gauges show the two separate air systems.","hbref":"§5.1","qid":"AB-172"},"181":{"q":"I'm hauling a loaded trailer through stop-and-go city traffic, and out of habit I keep my left foot lightly resting on the brake pedal between stops to react faster. My instructor tells me to take my foot completely off the pedal whenever I'm not actually braking. What is the MAIN reason he gives for this?","options":["Even light, constant pressure keeps the brakes partially applied, which heats and wears them prematurely","Keeping a foot on the pedal locks out the automatic spring brakes if air pressure drops too low","Resting on the pedal slowly bleeds air from the supply tank and triggers the low-air warning early","Light pedal pressure overrides the governor and prevents the compressor from cutting back in at 100 psi"],"answer":0,"explanation":"Resting your foot on the pedal keeps the brakes lightly applied, generating constant friction that overheats and wears the linings prematurely.","handbook":"Do not ride the brake pedal; it heats and wears the brakes.","hbref":"§5.2","qid":"AB-173"},"182":{"q":"A mechanic just finished replacing a leaking brake chamber on my tractor, and I'm parked in the shop yard with a full load hooked up and a delivery running late. The air gauge reads about 125 psi and the low-air warning is off. Before I pull out onto the highway, what should I do FIRST?","options":["Trust the mechanic's work and merge straight onto the highway, since the gauge already reads about 125 psi","Test the brakes at low speed before driving, including a slow-roll stop at about 5 mph to confirm they hold and pull straight","Pull out and ride the brakes lightly for the first mile to let the new chamber seat itself in","Pump the brake pedal several times in the yard to bleed any air out of the freshly repaired line"],"answer":1,"explanation":"After any brake repair you must verify the brakes yourself, including a slow-roll stop at about 5 mph to confirm they hold and pull straight.","handbook":"Test the brakes after any repair before driving.","hbref":"§5.3","qid":"AB-174"},"183":{"q":"During a pre-trip inspection, I crawl under my tractor and notice that one slack adjuster on the rear axle has noticeably more free play (pushrod travel) than the slack adjuster on the opposite wheel of the SAME axle. Which of the following is true about how the two slack adjusters on that axle should be set?","options":["The slack adjuster on the heavier-loaded side should be left looser to balance the trailer weight","A difference in free play between the two is normal and is not something I need to correct","Both slack adjusters on the same axle should be adjusted the same, so the uneven free play must be corrected","One should be removed so the remaining brake on that axle does all the work evenly"],"answer":2,"explanation":"Both slack adjusters on the same axle must have equal free play, so uneven travel is a defect that must be corrected before driving.","handbook":"Slack adjusters on the same axle should be adjusted alike.","hbref":"§5.1","qid":"AB-175"},"184":{"q":"During my pre-trip inspection on a cold Texas morning, I notice my air brake system has an air dryer mounted between the compressor and the air tanks. A mechanic warns me that if this component ever fails, I'll be much more likely to get freeze-ups in my brake lines and tanks during winter. Based on what the air dryer's main job is, why would its failure cause this freezing problem?","options":["The air dryer adds a small amount of oil to lubricate the lines, and without that oil the lines would seize up and freeze in cold weather","The air dryer warms the compressed air before it reaches the tanks, so if it fails the cold air freezes the system","The air dryer pressurizes the air to governor cut-out, and without enough pressure the remaining air freezes solid in the lines","The air dryer removes moisture from the air, so if it fails, water collects in the tanks and lines and can freeze in cold temperatures"],"answer":3,"explanation":"The air dryer removes moisture from the compressed air, so if it fails, water collects in the tanks and lines and can freeze in cold weather.","handbook":"The air dryer removes moisture from the air.","hbref":"§5.1","qid":"AB-176"},"185":{"q":"I just dropped my loaded trailer at the yard and I'm driving my tractor back across town with no trailer attached (bobtailing). Compared to when I had the loaded trailer hooked up, what should I expect about how this rig handles when I have to make a hard stop?","options":["It can be surprisingly harder to stop, so I need to allow extra care and distance because a bobtail tractor handles differently under braking","It will stop noticeably faster and in a shorter distance, so I can safely follow other vehicles more closely than before","It needs no special attention while stopping, since dropping the trailer removed weight and the brakes now have an easy job","It will require less steering effort and correction during the stop because the tractor is now much lighter overall"],"answer":0,"explanation":"A bobtail tractor can be harder to stop because its drive axles have less weight and traction without a trailer, so allow extra care and stopping distance.","handbook":"A bobtail tractor may need extra care when stopping.","hbref":"§5.2","qid":"AB-177"},"186":{"q":"During a pre-trip inspection I'm crawling under my tractor and I find one of the air reservoirs (tanks) shifting slightly on its bracket because a mounting strap has worked loose. Before I take this rig on the road, what is the correct way for that air tank to be mounted, and why does it matter?","options":["Loosely on flexible straps, so road vibration and chassis flex can't crack the tank welds","Securely to the frame, so it stays fixed in place and the lines and fittings don't get stressed or fail","With the drain valve facing upward, so collected water and oil stay clear of the mounting hardware","High on the frame rail or behind the cab, so the tank drains forward and away from the brake lines"],"answer":1,"explanation":"Air reservoirs must be mounted securely to the frame so they stay fixed against vibration and the connected lines and fittings are not stressed or damaged.","handbook":"Air reservoirs must be mounted securely.","hbref":"§5.1","qid":"AB-178"},"187":{"q":"During my pre-trip inspection I'm looking at a drum brake on the trailer and I notice it has a mechanical brake wear indicator. When this device gives its reading, what is it actually telling me about the condition of the brake linings?","options":["That the linings have absorbed moisture and need to be dried before the brakes will hold","That the slack adjusters have reached the maximum allowable pushrod travel and need adjusting","That the linings have worn down to the point where they need to be replaced","That the linings are correctly seated and the brakes are safe to operate for this trip"],"answer":2,"explanation":"A brake wear indicator shows when the brake linings have worn down to the point that they need to be replaced.","handbook":"Wear indicators show when brake linings are worn.","hbref":"§5.1","qid":"AB-179"},"188":{"q":"I just finished a long, steep mountain downgrade with my loaded combination vehicle, and I want to pull into a rest area to take a break. My brakes are smoking hot from the descent. Which of the following is the BEST reason I should NOT set the parking (spring) brakes right now?","options":["Setting the spring brakes while they are hot can cause the trailer air supply pressure to drop below 60 psi and trigger the low-air warning","Hot brakes increase pushrod travel, so the slack adjusters will be out of adjustment until they cool down","The spring brakes only hold properly once air pressure has dropped into the 20 to 45 psi range, which hot brakes prevent","Clamping very hot brake components with the spring brakes can damage them, so I should let the brakes cool first before parking"],"answer":3,"explanation":"Applying the spring (parking) brakes on very hot brakes can damage the components, so let the brakes cool before parking after a long downgrade.","handbook":"Do not park on spring brakes if the brakes are very hot or wet.","hbref":"§5.2","qid":"AB-180"},"189":{"q":"During a pre-trip inspection I've coupled my tractor to a loaded trailer, charged the system to about 125 psi, shut the engine off, and pressed and held the brake pedal down to check for leaks while watching the dash gauge. Over one full minute, what is the MAXIMUM air-pressure drop I can see and still pass this leakage check?","options":["4 psi","3 psi","2 psi","0 psi"],"answer":0,"explanation":"With brakes applied, a combination vehicle's air loss must stay under 4 psi per minute to pass the leakage check.","handbook":"With a trailer, applied leakage should be under 4 psi per minute.","hbref":"§5.3","qid":"AB-181"},"190":{"q":"During my pre-trip, I'm checking air leakage on my tractor-trailer combination. The engine is off, the system is fully charged to about 125 psi, and I've left the brakes RELEASED (parking valves out, foot off the pedal). Watching my gauge for one minute, what is the maximum air loss I should allow before the leak is out of spec?","options":["2 psi per minute, because that is the leakage limit when the brakes are released","3 psi per minute, because a combination vehicle with brakes released may leak slightly more","4 psi per minute, because that is the leakage limit for a combination vehicle","Any loss is acceptable as long as the low-air warning has not come on yet"],"answer":1,"explanation":"With brakes released, a combination vehicle may leak up to 3 psi per minute, slightly more than a single vehicle.","handbook":"With a trailer, static leakage should be under 3 psi per minute.","hbref":"§5.3","qid":"AB-182"},"191":{"q":"During my pre-trip on a tractor-trailer, I shut off the engine, release the brakes, and start fanning the brake pedal to bleed down the air. I'm watching the dash gauge, waiting for the low air pressure warning light and buzzer to activate so I can confirm they work. According to the Texas CDL Handbook, the warning is required to come on before the air pressure in my combination vehicle falls below which level?","options":["Before pressure drops below 45 psi, the point where the spring brakes begin to apply","Before pressure drops below 100 psi, the point where the governor cuts the compressor back in","Before pressure drops below 60 psi, well before the brakes lose effective stopping power","Before pressure drops below 20 psi, the point where the emergency brakes are fully set"],"answer":2,"explanation":"The low air pressure warning must come on before pressure drops below 60 psi to give an early alert with enough air left to stop safely.","handbook":"The low air warning must come on by 60 psi.","hbref":"§5.3","qid":"AB-183"},"192":{"q":"I'm running my pre-trip inspection and watching the air gauge climb as the compressor pumps. At about 125 psi the compressor stops adding air to the system and holds it there. The instructor asks me to name the governor setting that just stopped the compressor from pumping. Which term correctly names that setting?","options":["Cut-in — the setting near 100 psi where the compressor resumes pumping air back into the system","Shut-off — the setting that fully disables the compressor until the engine is restarted","Stand-by — the setting that idles the compressor whenever the parking brakes are applied","Cut-out — the setting near 125 psi where the governor stops the compressor from pumping air"],"answer":3,"explanation":"The cut-out setting, around 125 psi, is where the governor stops the compressor from pumping more air into the system.","handbook":"The governor has cut-in and cut-out settings.","hbref":"§5.1","qid":"AB-184"},"193":{"q":"I'm hauling a loaded combination down a long mountain grade. To control my speed, I select a low gear so the engine and transmission do most of the work of holding me back, and I only tap the service brakes lightly now and then. Compared with riding the brakes the whole way down, what is the main advantage of letting the engine and a low gear hold my speed?","options":["The service brakes stay cool, so they keep their full stopping power if I need a hard stop at the bottom","The service brakes warm up just enough to grip the drums better and shorten my stopping distance","The air compressor builds extra pressure faster because the brakes are barely being used on the grade","The spring (parking) brakes share the load with the service brakes and slow the vehicle automatically"],"answer":0,"explanation":"A low gear lets the engine absorb the vehicle's energy, keeping the service brakes cool so they retain full stopping power for a hard stop.","handbook":"Using the engine and low gear keeps the brakes cooler.","hbref":"§5.2","qid":"AB-185"},"194":{"q":"I'm descending a long, steep grade in a loaded truck with air brakes, and the rig is starting to creep above my safe speed. A buddy on the CB tells me to repeatedly pump and release the brake pedal to hold my speed. Why is following that advice dangerous on this kind of downgrade?","options":["Repeatedly pumping the pedal overheats the compressor and trips the safety relief valve at 150 psi","Repeatedly pumping the pedal bleeds off air faster than the compressor can replace it, so pressure can drop until you lose braking","Repeatedly pumping the pedal forces water and oil out of the tanks and contaminates the brake lines","Repeatedly pumping the pedal builds excess air that locks the spring brakes on while you are still rolling"],"answer":1,"explanation":"Fanning the brakes on a long downgrade releases air faster than the compressor can replace it, so pressure can drop until you lose braking.","handbook":"Fanning the brakes wastes air.","hbref":"§5.2","qid":"AB-186"},"195":{"q":"I've pulled my combination rig into a rest area for a 30-minute break. To hold the unit in place while I'm away from the cab, I reach for the trailer hand valve and apply it. Why is this the WRONG way to secure the rig?","options":["The hand valve activates the trailer's spring brakes, which can overheat and lock up while the rig sits parked","The hand valve releases the red trailer air supply knob, so the tractor will drift forward on its own","The hand valve only applies service air to the trailer brakes, and that air can leak off over time and let the rig roll","The hand valve sends air to the steering axle only, so the drive and trailer wheels are left completely unbraked"],"answer":2,"explanation":"The trailer hand valve applies only service air, which leaks off over time and lets the rig roll, so always park with the spring brakes.","handbook":"Do not use the trailer hand valve for parking.","hbref":"§5.3","qid":"AB-187"},"196":{"q":"During my pre-trip on a single tractor, I run the air system up to about 125 psi, then shut the engine off and release the brakes. I've already chocked the wheels and the low-air warning is off. What is the whole POINT of shutting the engine down at this step?","options":["To let me pump the brake pedal several times and confirm the air pressure builds back up quickly","To force the spring brakes to apply automatically so I can confirm they seat in the 20–45 psi range","To drain the wet tank without the compressor cycling and pushing more oil and water in","To stop the compressor from adding air so I can time the pressure drop and check the leak rate"],"answer":3,"explanation":"Shutting off the engine stops the compressor from adding air so you can time the pressure drop and accurately measure the leak rate.","handbook":"After building pressure and shutting off, watch the leakage rate.","hbref":"§5.3","qid":"AB-188"},"197":{"q":"During my pre-trip, my instructor asks me to explain what actually pushes the brake shoes against the drums when I press the brake pedal. The engine is running and the system is fully charged. Which answer correctly describes the form of stored energy my brakes rely on to do that work?","options":["Compressed air held in the tanks, which is released to apply the brakes","Hydraulic fluid pressurized by a master cylinder, like a car's brakes","Electrical current from the battery sent to magnets at each wheel","Engine oil pressure routed from the lubrication system to the brakes"],"answer":0,"explanation":"An air brake system stores energy as compressed air in the tanks, which is released to apply the brakes.","handbook":"The air system stores energy as compressed air.","hbref":"§5.1","qid":"AB-189"},"198":{"q":"During my pre-trip inspection, I start the engine and watch the dash gauge. My dual air system is taking far longer than the required 85-to-100 psi in 45 seconds to come up to pressure, and it keeps creeping up sluggishly. Of the following, what is the MOST likely cause of this slow build-up?","options":["The low air pressure warning buzzer is sounding too early, below 60 psi","A failing air compressor or an air leak somewhere in the system","The governor cut-out is set too high, near the 150 psi relief setting","The slack adjusters have too much pushrod travel and free play"],"answer":1,"explanation":"Air pressure that builds too slowly to reach 85-100 psi within 45 seconds points to a failing compressor or a leak in the system.","handbook":"Slow pressure build-up may mean a weak compressor or a leak.","hbref":"§5.1","qid":"AB-190"},"199":{"q":"During my pre-trip, I hear a loud hiss of air escaping from the safety relief valve on the supply (wet) tank while the engine is running and the compressor is building air. Of the following, what condition is this valve specifically designed to protect the tanks against?","options":["The low air pressure warning failing to come on before pressure drops below 60 psi","The governor failing to cut the compressor back in once pressure falls to about 100 psi","Air pressure climbing too high in the system, with the valve set to open at about 150 psi","The compressor failing to build pressure from 85 to 100 psi within 45 seconds"],"answer":2,"explanation":"The safety relief (pop-off) valve in the supply tank opens at about 150 psi to protect the system from excessive air pressure.","handbook":"The safety valve protects the tank from too much pressure.","hbref":"§5.1","qid":"AB-191"},"200":{"q":"I'm transitioning from driving my personal pickup, which has hydraulic brakes, into a Class B truck equipped with an air brake system. During pre-trip, I'm trying to understand the fundamental difference in how the actual stopping force reaches the brakes at each wheel. Which statement correctly identifies what physically transmits the force that applies the brakes in my air brake vehicle?","options":["The hydraulic fluid in the master cylinder is pressurized further, then routed to the brake chambers to clamp the shoes","Engine oil pressure builds up and is diverted through the brake lines to push the slack adjusters against the drums","An electric signal from the brake pedal energizes magnets at each wheel that pull the brake shoes outward","Compressed air, stored in the tanks and released by the pedal, travels through the lines to apply force at the brake chambers"],"answer":3,"explanation":"Air brakes use compressed air stored in the tanks, released by the pedal through the lines to the brake chambers to apply braking force.","handbook":"Air brakes apply using compressed air.","hbref":"§5.1","qid":"AB-192"},"201":{"q":"I just upgraded from a pickup with hydraulic brakes to a tractor-trailer with air brakes. The first time I press the brake pedal hard, I notice the truck does NOT begin slowing the instant my foot moves, the way my old pickup did. Which statement BEST explains this difference between air brakes and hydraulic brakes?","options":["Air brakes have a built-in lag of about half a second because the air must travel through the lines before the brakes apply.","Air brakes deliver no stopping power at all until the system reaches full governor cut-out pressure of 125 psi.","Air brakes respond instantly like hydraulics, so the delay I felt was only worn slack adjusters out of adjustment.","Air brakes have no brake pedal feedback, so the slowing actually began immediately even though I could not feel it."],"answer":0,"explanation":"Air brakes have about a half-second lag because the air must travel through the lines before the brakes apply.","handbook":"Air brakes have a brake lag that hydraulic brakes do not.","hbref":"§5.2","qid":"AB-193"},"203":{"q":"You are hauling a load down a rural Texas highway when the low air pressure warning light flicks on and the buzzer starts sounding. There is a truck stop about 12 miles ahead where you know a mechanic is on duty. EXCEPT for one of the following, the actions below are unsafe responses to this warning. Which is the correct thing to do?","options":["Maintain highway speed and push on to the truck stop 12 miles ahead so a mechanic can inspect the system","Brake gently to reduce speed and get the vehicle off the road and stopped safely as soon as you can","Pump the brake pedal repeatedly to rebuild pressure in the tanks and continue driving normally","Keep rolling but apply the parking brake knob now so the spring brakes can help you stop later"],"answer":1,"explanation":"When the low air warning comes on, brake gently and get the vehicle off the road and stopped safely before the spring brakes apply automatically.","handbook":"If the low-air warning sounds, stop safely while you still can.","hbref":"§5.3","qid":"AB-194"},"204":{"q":"You stop at a red light in your air-brake straight truck. The low-air warning light and buzzer are on, and the dash gauge shows pressure has fallen well below the normal operating range. The light turns green and traffic behind you starts honking. What is the correct action?","options":["Pull forward slowly through the intersection, since the spring brakes only lock up at 20 psi and you are still above that","Make a quick lane change to the shoulder while you still have enough air to roll the wheels","Stay stopped and do not move the truck until the air pressure has built back up into the normal range","Lightly fan the brake pedal a few times to help the compressor refill the tanks faster before pulling away"],"answer":2,"explanation":"A lit low-air warning means braking is no longer reliable, so stay stopped until air pressure builds back into the normal range.","handbook":"Do not drive until air pressure is back to a safe level.","hbref":"§5.3","qid":"AB-195"},"205":{"q":"I'm hauling a loaded combination down a long, steep grade and partway down I notice the brake pedal getting soft and the truck barely slowing when I press it. My brakes are clearly fading. Which of the following is the BEST action for me to take?","options":["Press the brake pedal harder and hold steady pressure all the way to the bottom to make up for the lost braking power","Pump the brake pedal rapidly to rebuild pedal feel and restore the stopping power I have lost","Shift into a higher gear so the engine spins freely and the truck can coast smoothly to the bottom","Shift to a lower gear for engine braking and find the nearest safe place to pull off and stop the truck"],"answer":3,"explanation":"If air brakes begin to fade on a long downgrade, shift to a lower gear for engine braking and pull off at the nearest safe place to stop.","handbook":"If brakes fade on a grade, use a lower gear and stop safely.","hbref":"§5.2","qid":"AB-196"},"206":{"q":"I've parked my loaded tractor-trailer on a slight grade and set the parking brake with the yellow knob. While I'm doing my paperwork, the engine is off and air pressure in the tanks is slowly bleeding down past 45 psi toward zero. What is actually keeping my rig from rolling away, and why does it hold even as the air leaks out?","options":["Powerful springs in the brake chambers clamp the brakes mechanically, so the holding force stays on as air bleeds off","Trapped air pressure locked inside the brake chambers keeps the shoes pressed against the drums","The engine and transmission hold the wheels through compression once it is shut down","The yellow knob mechanically latches the foot-valve linkage down to maintain pedal force"],"answer":0,"explanation":"Parking and emergency brakes are held on by powerful springs in the spring brake chambers, so they keep holding even as air bleeds off.","handbook":"Spring brakes hold by mechanical spring force.","hbref":"§5.2","qid":"AB-197"},"207":{"q":"I'm rolling down the highway with my air system fully charged at normal operating pressure, and I feel the spring brakes are NOT dragging or applying. Which statement correctly explains the role of hold-off pressure in this situation?","options":["Hold-off pressure is keeping the spring brakes partially clamped so they respond faster when I press the pedal.","Hold-off pressure is holding the spring brakes released while I drive, so they stay off until air drops too low.","Hold-off pressure is keeping the spring brakes fully applied at all times to back up my service brakes.","Hold-off pressure has been completely removed from the chambers, which is why the spring brakes feel off."],"answer":1,"explanation":"Hold-off air pressure compresses the springs to keep the spring brakes released while driving, and they apply only if air drops too low.","handbook":"Air pressure holds the spring brakes off while driving.","hbref":"§5.2","qid":"AB-198"},"208":{"q":"I park my rig at the end of my shift, shut off the engine, and feel the spring brakes lock the wheels as the air bleeds down. A trainee asks me which braking function of the air system I just relied on to hold the truck. Which answer is correct?","options":["The service braking function, since the foot pedal is what holds a parked vehicle once the engine is off","The modulating function, since the spring brakes apply gradually as air pressure falls below 60 psi","The parking/emergency function, since the spring brakes set automatically to hold the vehicle once air pressure is lost","The low-air-warning function, since the buzzer and light are what physically clamp the wheels"],"answer":2,"explanation":"The spring brakes set automatically to hold the vehicle when air pressure is lost, which is the parking/emergency function.","handbook":"Spring brakes provide the parking and emergency function.","hbref":"§5.2","qid":"AB-199"},"210":{"q":"During my pre-trip inspection, I open the hood and notice that my air compressor is driven by a belt rather than connected directly to the engine. Because it is belt-driven, what additional item must I specifically inspect that I would NOT need to check on a gear-driven compressor?","options":["That the governor cut-out pressure reads about 125 psi on the gauge","That the air tanks have been drained of water and compressor oil","That the low air pressure warning light comes on before 60 psi","That the drive belt is properly tensioned and not showing wear"],"answer":3,"explanation":"On a belt-driven compressor, check that the drive belt is properly tensioned and not worn, since a gear-driven one has no belt.","handbook":"Check a belt-driven compressor for tension and wear.","hbref":"§5.1","qid":"AB-200"},"211":{"q":"During my pre-trip inspection, I notice that one of the air storage tanks under the trailer is no longer held tightly against its mounting bracket and shifts when I push on it. Why is this loose tank a defect I must fix before I drive?","options":["The tank can rub against parts of the vehicle or work loose and fall off the truck","The tank will draw extra air from the compressor and force the governor to cut out early","The tank will hold less compressed air, so my low air pressure warning will sound sooner","The tank will let water and oil drain out on its own, leaving nothing to remove daily"],"answer":0,"explanation":"A loose air tank can vibrate and rub against vehicle parts or work free and fall off the truck.","handbook":"Air tanks must be secure so they cannot rub or fall off.","hbref":"§5.1","qid":"AB-201"},"212":{"q":"You've pulled your air-brake straight truck onto level, paved ground at a fuel island and shut the engine off. Gauges read full system pressure and you're about to step out of the cab to start fueling. Which action must you complete before you leave the cab?","options":["Leave the truck in its lowest forward gear and rely on engine compression to hold it","Pull out the yellow diamond-shaped knob to set the parking (spring) brakes","Hold the truck by keeping firm, steady foot pressure on the service brake pedal","Pull out the red octagon-shaped knob to lock the trailer air supply line"],"answer":1,"explanation":"Always set the parking (spring) brakes by pulling out the yellow diamond-shaped knob before leaving the cab.","handbook":"Always set the parking brake before leaving the cab.","hbref":"§5.2","qid":"AB-202"},"213":{"q":"I'm a new driver deciding between two used trucks: a heavy tractor-trailer rated to haul near its maximum gross weight, and a light delivery van. A mechanic tells me the big rig uses air brakes while the van uses hydraulic brakes. I want to understand why heavy commercial vehicles are built with air brakes in the first place. Which statement BEST explains why air brakes are the standard choice for big, heavily loaded trucks?","options":["Air brakes shorten the truck's total stopping distance, so a fully loaded rig can stop in less space than it could with hydraulic brakes","Air brakes are chosen mainly because they are the cheapest braking system to install and never need the tanks drained or maintained","Air brakes use compressed air rather than a fixed amount of fluid, so they keep working effectively even on large vehicles carrying heavy loads","Air brakes eliminate brake lag entirely, letting a loaded truck respond the instant the pedal is pressed with no delay in the lines"],"answer":2,"explanation":"Air brakes use continuously replenished compressed air instead of a fixed amount of fluid, so they keep braking effectively on heavy, fully loaded vehicles.","handbook":"Air brakes are effective for heavy vehicles.","hbref":"§5.1","qid":"AB-203"},"214":{"q":"I'm parked on a grade and decide to set my yellow parking-brake knob (engaging the spring brakes) while I'm STILL holding the service-brake pedal down hard. A driver next to me warns me to ease off the pedal first. Why is applying the service brakes and the spring brakes hard at the same time a problem?","options":["It does no harm at all and actually gives me extra holding power, so there is no reason to ease off the service pedal first","It causes the low air pressure warning to come on early, below the 60 psi point, and drains the supply tank faster","It saves a large amount of air because both systems share the same stored pressure when applied together","The braking forces combine and add together, and that compounding force can put too much strain on and damage the brake components"],"answer":3,"explanation":"Applying the service brakes hard while the spring brakes are set lets the two forces combine, putting excess strain that can damage brake components.","handbook":"Compounding the brakes can damage them.","hbref":"§5.2","qid":"AB-204"},"215":{"q":"I'm parking my rig and I pull out the yellow knob to set the spring (parking) brakes. Out of habit, my foot is still pressing hard on the brake pedal, so air pressure is also being sent to the same brake chambers at the same time. The mechanic warned me that without a certain valve, applying both forces together could combine and damage the brakes. Which valve protects against this combined, 'double-apply' force?","options":["The anti-compounding valve, which prevents the spring-brake force and the air-application force from adding together on the same brakes","The modulating control valve, which lets you apply the spring brakes gradually so the two forces never overlap","The safety relief valve, which opens at about 150 psi to bleed off the extra pressure created by the double application","The trailer air supply valve, the red octagon knob that cuts air to the rear brakes when both are applied"],"answer":0,"explanation":"The anti-compounding valve releases the air-application pressure when the spring brakes are set so the two braking forces do not add together.","handbook":"An anti-compounding valve prevents brake damage from double application.","hbref":"§5.2","qid":"AB-205"},"216":{"q":"During my pre-trip inspection, I'm running the air-brake checks on a tractor-trailer. I want to confirm the device that is REQUIRED to alert me the moment system air drops too low (before it falls under 60 psi) so I know to stop while I still have braking ability. Which feature is the system required to use to give me that warning?","options":["The air pressure gauge slowly creeping downward, which I'm expected to watch closely the whole trip","A warning light and/or a buzzer that activates before pressure falls below 60 psi","The spring (parking) brakes snapping on automatically to physically force me to stop","The safety relief valve venting air with a loud hiss once pressure gets too low"],"answer":1,"explanation":"An air-brake vehicle must have a low-air-pressure warning light, and usually a buzzer, that activates before pressure falls below 60 psi.","handbook":"A low air warning must use a light and/or buzzer.","hbref":"§5.1","qid":"AB-206"},"217":{"q":"I'm idling at a truck stop watching my air pressure gauge after a full charge. The needle keeps cycling: it climbs, the governor cuts out, the needle slowly settles a bit, then the governor cuts back in and pumps it up again. I want to confirm my air compressor is keeping up with demand. Which gauge behavior tells me the compressor is doing its job?","options":["The gauge keeps climbing past 150 psi and the safety relief valve vents, proving the compressor has plenty of capacity to spare","The gauge slowly bleeds all the way down toward zero, then the compressor refills it in one quick burst","The needle stays within the normal operating range, cycling between governor cut-in and cut-out as pressure is used and replaced","The gauge holds dead steady at one fixed psi and never moves, showing the governor has locked the system pressure in place"],"answer":2,"explanation":"A working compressor keeps pressure in the normal range, cycling between the governor cut-out (about 125 psi) and cut-in (about 100 psi) as air is used and replaced.","handbook":"The compressor keeps up if pressure stays in the normal range.","hbref":"§5.1","qid":"AB-207"},"219":{"q":"I'm doing my pre-trip on a single tractor and let the engine idle to build air. I want the system fully charged before I roll out, so I watch the dash gauge climb and wait for the compressor governor to cut out and stop pumping. At about what pressure should I expect that to happen?","options":["About 100 psi, the point where the governor cuts in and starts pumping again","About 60 psi, where the low air pressure warning light and buzzer shut off","About 150 psi, where the safety relief valve opens to bleed off extra air","About 125 psi, where the governor cuts out and the compressor stops pumping"],"answer":3,"explanation":"A fully charged system sits at governor cut-out pressure, about 125 psi, where the compressor stops pumping air.","handbook":"Fully charge the system to governor cut-out (about 125 psi).","hbref":"§5.3","qid":"AB-208"},"220":{"q":"You are driving a combination vehicle when your trailer suddenly breaks away from the tractor and its air supply line is torn loose, dumping all the air out of the trailer's brake system. What will happen to the runaway trailer?","options":["Its spring (emergency) brakes will apply automatically as the air pressure drops, slowing and stopping the trailer","Its service brakes will hold only as long as you keep your foot on the brake pedal in the tractor","It will roll free with no braking, since losing air also releases the trailer's parking brakes","Nothing will happen to it until you pull the red trailer air supply knob to set the brakes"],"answer":0,"explanation":"Spring brakes are held off by air pressure, so when a breakaway trailer loses air they apply automatically and bring the trailer to a stop.","handbook":"A trailer that breaks away brakes automatically.","hbref":"§5.3","qid":"AB-209"},"221":{"q":"You're driving a single straight truck with an air brake system when a major line failure dumps all the air out of the system and the pressure gauges fall to zero. You did not touch the brake pedal or the parking control. What does the truck do?","options":["It coasts freely with no braking, because losing air also releases the spring brakes and leaves you rolling.","It comes to a stop on its own, because the spring brakes apply automatically once air pressure drops low enough.","It keeps moving normally and you simply lose your service brakes, but steering and the parking brake still work.","It loses only the power-assist, so the brakes still work but the pedal becomes much harder to push down."],"answer":1,"explanation":"Spring brakes are held off by air pressure, so a total loss of air applies them automatically and stops the vehicle.","handbook":"If all air is lost, the spring brakes stop the truck.","hbref":"§5.2","qid":"AB-210"},"222":{"q":"During my pre-trip on a tractor-trailer, I notice one front brake's slack adjuster has more pushrod travel than the others, so that brake does less of the work while the rest do more. A buddy says this won't matter much. What is the MOST important thing I lose when my brakes are out of adjustment and no longer share the braking work evenly?","options":["Better fuel economy, because evenly worked brakes reduce engine drag","Faster air pressure build-up from 85 to 100 psi during the test","Good brake balance, so the vehicle stops straight without pulling to one side","Stronger engine braking power when I shift down on a long grade"],"answer":2,"explanation":"When all brakes are properly adjusted and share the work equally, brake balance keeps the vehicle stopping straight without pulling to one side.","handbook":"Properly adjusted brakes give good brake balance.","hbref":"§5.1","qid":"AB-211"},"223":{"q":"I'm doing a pre-trip on my tractor-trailer. The engine has been running and air is building in the tanks. Before I release the parking brakes and pull out of the yard, what is the MINIMUM air pressure I should have in the system to drive safely?","options":["At least about 60 psi, since that is the point where the low air pressure warning shuts off","At least about 20 psi, since that is where the spring brakes release and let the rig roll","At least about 125 psi, since the rig is not safe to drive until the governor reaches cut-out","At least about 100 psi, since that is the minimum pressure needed to brake and drive safely"],"answer":3,"explanation":"You must build at least about 100 psi before driving, since that is the minimum air pressure needed to brake and drive safely.","handbook":"Have at least about 100 psi before driving.","hbref":"§5.3","qid":"AB-212"},"224":{"q":"I drive the same dependable tractor-trailer on a short 40-mile delivery loop that I run several times a day. The unit passed its full air-brake inspection clean this morning, and I have not touched it since lunch. As I climb back in to start my afternoon run, which approach to checking the air brakes is correct?","options":["Run the air-brake checks again before this afternoon trip, just as before any trip","Skip the checks this time, since a full inspection already passed earlier today on this same vehicle","Only repeat the checks if the low-air warning light or buzzer came on during the morning run","Wait and re-check the brakes once a week or after about every 1,000 miles of driving"],"answer":0,"explanation":"Air-brake checks must be performed before every trip, since brake condition, air leakage, and slack adjustment can change between trips.","handbook":"Test the air brakes before every trip.","hbref":"§5.3","qid":"AB-213"},"225":{"q":"During my pre-trip, I notice the slack adjusters on my tractor have more free play than they should, meaning the brakes are out of adjustment. If I drive anyway without fixing this, what should I most expect to happen on the road?","options":["The brakes will actually grip harder and stop the truck in a shorter distance","The brakes will have reduced power and the truck will not stop as well","The system will conserve air, so the compressor cycles on far less often","The brake linings and drums will wear out much more slowly over time"],"answer":1,"explanation":"Excessive pushrod travel from out-of-adjustment slack adjusters reduces braking power, so the truck will not stop as well.","handbook":"Brakes out of adjustment will not stop the vehicle properly.","hbref":"§5.1","qid":"AB-214"},"226":{"q":"During my pre-trip inspection, I notice a brake hose has been routed so it presses against a sharp bracket on the frame, and the outer surface is scuffed where it contacts the metal. Why does this finding matter for my air brake system?","options":["The contact tightens the fitting over time, so it actually reduces the chance of a connection coming loose","The friction work-hardens the rubber, letting the hose hold higher pressure than the rest of the system","The constant rubbing can wear through the hose until it fails and leaks air","Nothing changes for the brakes, but the rubbing may speed up cooling at that one spot"],"answer":2,"explanation":"A brake hose that rubs against a part is worn down by constant abrasion until it wears through and leaks air.","handbook":"Brake hoses that rub can wear through and leak.","hbref":"§5.1","qid":"AB-215"},"227":{"q":"During my pre-trip inspection, my single tractor is fully charged to about 125 psi. I turn the engine off, leave the brakes released, and watch the gauge. The pressure falls more than 2 psi in one minute, and I trace a faint hissing sound to a brake chamber where the rubber diaphragm has a small tear in it. What is this torn diaphragm doing to my air system?","options":["It is boosting the force pushing the pushrod, giving that wheel extra braking power","It only matters with the brakes applied, so with brakes released it has no real effect","It is helping the shoes grip the drum tighter at that wheel during the stop","It is letting compressed air escape, which is why my leakage rate is too high"],"answer":3,"explanation":"A torn brake-chamber diaphragm lets compressed air escape through the hole instead of applying the brakes, raising the leakage rate.","handbook":"A torn brake chamber diaphragm causes an air leak.","hbref":"§5.1","qid":"AB-216"},"228":{"q":"During my pre-trip, the air leakage rate on my tractor-trailer is failing—pressure drops far faster than the limit even with the engine off and brakes released. I notice a faint hissing right where the tractor and trailer air lines couple together. Which condition is the MOST likely cause of what I'm hearing and the failing leak test?","options":["Worn glad-hand seals are letting air escape at the coupled connection between the tractor and trailer","A slack adjuster is out of adjustment, allowing excessive pushrod travel at one of the brake chambers","The safety relief valve has opened because tank pressure climbed past 150 psi during charging","The governor failed to reach cut-out, so the compressor never stopped pumping air into the system"],"answer":0,"explanation":"Worn glad-hand seals let air escape where the tractor and trailer air lines couple, causing the hiss and excessive leakage.","handbook":"Worn glad-hand seals leak air.","hbref":"§5.3","qid":"AB-217"},"229":{"q":"I've just coupled my tractor to a loaded trailer and connected the air lines. The trailer's air tanks are still empty, and I need to send air back to the trailer to charge its brake system before I can do my brake checks. Sitting in the cab, which control do I operate to send air to the trailer?","options":["I pull out the yellow, diamond-shaped knob to release pressure to the trailer","I push in the red, eight-sided knob to send air back to the trailer","I press and hold the service brake pedal to pump air through the lines","I pull out the red, eight-sided knob to open the supply line to the trailer"],"answer":1,"explanation":"Pushing in the red, eight-sided trailer air supply knob sends air from the tractor back to charge the trailer's brake system.","handbook":"Push in the trailer air supply knob to charge the trailer.","hbref":"§5.3","qid":"AB-218"},"230":{"q":"I'm driving a tractor-trailer when a leak in the system causes my air pressure to fall well below the level needed to hold the trailer's air supply valve open. Without me touching anything on the dash, what should I expect the red, eight-sided trailer air supply knob to do?","options":["Stay seated and pushed in, since the trailer brakes only respond to the foot pedal","Light up and sound a buzzer but remain pushed in until I pull it by hand","Pop out on its own and close, automatically applying the trailer emergency brakes","Push itself in further to seal off the trailer and keep the remaining air pressure"],"answer":2,"explanation":"If air pressure drops too low, the red eight-sided knob pops out on its own and closes, automatically applying the trailer emergency brakes.","handbook":"The trailer air supply knob pops out at low pressure.","hbref":"§5.3","qid":"AB-219"},"231":{"q":"During my pre-trip inspection, my mechanic mentions that one axle on my rig has been fitted with larger brake chambers than the others, and a newer student riding along asks me what difference that makes when I press the brake pedal. Compared to the smaller chambers, what does the larger brake chamber on that axle actually produce?","options":["It softens the pedal feel because the larger chamber holds more air before the pushrod moves","It reduces braking output because the bigger chamber bleeds air pressure away from the slack adjuster","It produces no braking change at all, since chamber size only affects how fast the air refills","It produces more braking force because the larger chamber pushes the slack adjuster with greater effort"],"answer":3,"explanation":"A larger brake chamber has more surface area for the air to act on, driving the slack adjuster with greater force for more braking power.","handbook":"A larger brake chamber produces more braking force.","hbref":"§5.1","qid":"AB-220"},"232":{"q":"During my pre-trip, I press the brake pedal and watch the S-cam foundation brake on a drive axle turn. As the S-cam rotates, what is it actually doing inside that brake assembly to slow the wheel?","options":["Forcing the brake shoes outward so their linings press against the inside of the brake drum","Pulling the brake shoes inward, away from the drum, so the return springs can release them","Rotating the slack adjuster to take up free play in the pushrod before braking begins","Bleeding air out of the brake chamber so the spring brakes can apply against the drum"],"answer":0,"explanation":"The rotating S-cam wedges between the brake shoes, forcing them outward so their linings press against the inside of the spinning brake drum to slow the wheel.","handbook":"The S-cam forces the brake shoes against the drum.","hbref":"§5.1","qid":"AB-221"},"233":{"q":"During my pre-trip, I'm inspecting the foundation brakes on a tractor equipped with air disc brakes instead of the more common drum type. As I look at the wheel assembly, I see the caliper straddling a flat, spinning metal component that the caliper squeezes to slow the wheel. To correctly describe this air disc brake system on my inspection, the part the caliper clamps against is the:","options":["Brake drum that the shoes press outward against","Rotor that the caliper squeezes to create friction","Spring brake chamber that applies the pressure","Slack adjuster that the pushrod moves against"],"answer":1,"explanation":"Air disc brakes use a caliper that clamps friction pads against a spinning rotor (disc) mounted to the wheel hub to create the friction that slows the wheel.","handbook":"Air disc brakes use a caliper and rotor.","hbref":"§5.1","qid":"AB-222"},"234":{"q":"During my pre-trip, a mechanic points to a large brake chamber on my rig and calls it the 'maxi' chamber, telling me it does NOT use air pressure to push the rod out and stop the wheel the way the smaller chamber does. Based on how this component actually works, what is the 'maxi' chamber?","options":["It is the service brake, since the maxi chamber is the part that applies braking force every time I press the foot pedal during normal driving","It is the modulating control valve, since the maxi chamber is what lets me apply pressure gradually to the rear axle in an emergency","It is the spring brake, since the maxi chamber holds a powerful spring that applies the brakes when air pressure is released or lost","It is the trailer air supply unit, since the maxi chamber is what feeds and charges air back to the trailer's tanks while driving"],"answer":2,"explanation":"A maxi (spring brake) chamber holds a powerful compressed spring that applies the brakes whenever air pressure is released or lost, rather than pushing the rod with applied air.","handbook":"The 'maxi' chamber is the spring brake.","hbref":"§5.2","qid":"AB-223"},"235":{"q":"I'm parked at a loading dock and my truck is fully aired up at about 125 psi with no leaks. Other than the air pressure dropping into the 20-45 psi range, what is the OTHER way my spring brakes can be made to apply?","options":["By pressing and holding the service brake pedal all the way to the floor","By flipping on the antilock braking system (ABS) warning switch","By revving the engine so the governor reaches cut-out at 125 psi","By pulling out the yellow diamond-shaped parking brake control knob"],"answer":3,"explanation":"Spring brakes are applied manually by pulling out the yellow diamond-shaped parking brake control knob.","handbook":"Spring brakes apply from low air or manually with the parking control.","hbref":"§5.2","qid":"AB-224"},"236":{"q":"It is a freezing winter morning in the Panhandle, and my tractor-trailer is equipped with an alcohol evaporator on the air brake system. As I run my pre-trip and start driving, what is the MAIN job this device is doing for me in this cold weather?","options":["Adding alcohol into the air system to keep ice from forming and clogging the air brake lines and valves","Keeping the brake drums and linings warm so the service brakes do not lose their stopping power","Removing the water and compressor oil from the tanks so I no longer have to drain them daily","Raising the governor cut-out pressure so the compressor builds air faster in the cold"],"answer":0,"explanation":"An alcohol evaporator adds alcohol into the air system to lower moisture's freezing point and keep ice from forming and clogging the brake lines and valves in cold weather.","handbook":"An alcohol evaporator helps prevent ice in the air system.","hbref":"§5.1","qid":"AB-225"},"238":{"q":"During my pre-trip, I let the engine run and watch the air gauge climb. It reaches about 125 psi and the needle stops rising even though the engine keeps running. The governor has just reached its cut-out setting. What is the compressor itself doing at this exact moment?","options":["It has shut off completely with the engine, and will only restart once pressure falls to roughly 60 psi","It keeps running but stops pumping air into the tanks (it has unloaded) until pressure drops to about 100 psi","It pumps even harder to push pressure up toward the 150 psi safety relief valve setting","It locks up and bleeds the excess air out through the safety relief valve to protect the tanks"],"answer":1,"explanation":"At the governor cut-out point (about 125 psi) the compressor keeps turning but unloads, stopping air delivery to the tanks until pressure drops to the cut-in point of about 100 psi.","handbook":"At cut-out the compressor stops pumping (unloads).","hbref":"§5.1","qid":"AB-226"},"239":{"q":"I just dropped my trailer at the yard and I'm driving the tractor back to the terminal bobtail (no trailer attached). The road home has a long flat stretch, an open gravel lot I cut through, a couple of highway on-ramps, and a sweeping curve near the exit. Where should I be MOST careful to slow down, because a bobtail tractor handles poorly there?","options":["On the long flat stretch, since the lighter rig lets me cruise faster than normal","In the open gravel lot, since loose surfaces are the only place a bobtail loses grip","On the curves and the on-ramps, where a bobtail tractor can handle poorly","Nowhere in particular, since a bobtail with no trailer brakes and corners better"],"answer":2,"explanation":"A bobtail tractor lacks trailer weight over the drive axles and handles poorly, so slow down extra on curves and on-ramps where forces are greatest.","handbook":"A bobtail tractor needs care on curves and ramps.","hbref":"§5.2","qid":"AB-227"},"240":{"q":"I'm finishing my pre-trip inspection on a tractor-trailer in the yard. I've already drained the air tanks, confirmed the governor cuts out near 125 psi, and verified the low-air warning comes on before 60 psi. Before I pull out onto the road, which of the following must I still do regarding the lights at the rear of my vehicle?","options":["Confirm the rear reflectors are freshly painted so other drivers can see them at night","Confirm the rear lamp housings are covered to protect the bulbs from road debris","Confirm the rear marker lights have been removed to reduce electrical load","Confirm the brake lights actually come on when I press the brake pedal"],"answer":3,"explanation":"A pre-trip inspection requires confirming the brake lights actually come on when the brake pedal is pressed, so following traffic gets a signal that you are slowing or stopping.","handbook":"Confirm the brake lights work before driving.","hbref":"§5.3","qid":"AB-228"},"241":{"q":"During my pre-trip 5 mph stop test, I press the brake pedal and the truck jerks hard to the right and the pedal grabs unevenly before stopping. Which conclusion is correct?","options":["The brakes are defective and the vehicle needs service before it can be driven","This is normal brake-lag behavior and I can release and continue the trip","The air pressure is simply too high, so I should bleed the tanks and retest","The ABS is doing its job by gripping one wheel, so no action is needed"],"answer":0,"explanation":"In the 5 mph brake test, brakes that pull to one side or grab unevenly are defective and the vehicle must not be driven until it is serviced and repaired.","handbook":"Brakes that grab or pull need service.","hbref":"§5.1","qid":"AB-229"},"242":{"q":"During my pre-trip inspection, I crawl under the trailer to check the foundation brakes at each wheel. I've already confirmed the brake drums and brake shoes are in good shape. To finish inspecting the foundation brake components themselves, which part should I check next?","options":["The yellow diamond-shaped parking brake knob in the cab","The slack adjusters connected to each brake chamber pushrod","The governor that controls compressor cut-in and cut-out","The safety relief valve mounted on the supply (wet) tank"],"answer":1,"explanation":"Slack adjusters connect each brake chamber pushrod to the brake mechanism, converting pushrod travel into braking force at the wheel.","handbook":"Foundation brakes include drums, shoes, and slack adjusters.","hbref":"§5.1","qid":"AB-230"},"243":{"q":"During my pre-trip inspection, I connect the tractor and trailer glad hands, charge the air system to about 125 psi, and shut off the engine. As I lean near the coupling, I clearly hear a steady hissing sound coming from one of the glad hand connections. What does this hissing MOST likely tell me about that connection?","options":["The seal is fully airtight and the connection passed the test","Extra air pressure is being routed to boost the trailer brakes","Air is escaping from the connection because of a leak","The supply line has just finished bleeding out trapped water"],"answer":2,"explanation":"A steady hiss at a glad hand coupling means pressurized air is escaping through a leak in the seal.","handbook":"A hissing glad hand means an air leak.","hbref":"§5.3","qid":"AB-231"},"244":{"q":"I'm driving a tractor-trailer equipped with a working ABS system when a car suddenly stops dead in my lane. I need to stop as hard as possible while keeping the rig under control. What is the correct way to use my brakes in this emergency?","options":["Rapidly pump the brake pedal up and down so the ABS has time to react between applications","Press hard, then ease off the instant I feel the pedal pulse, repeating in short bursts","Tap the pedal once to trigger the ABS, then steer around the hazard without further braking","Press down firmly on the pedal and hold steady pressure, letting the ABS prevent wheel lockup so I can steer"],"answer":3,"explanation":"With ABS, press the brake pedal firmly and hold steady pressure so the system prevents wheel lockup and you keep steering control.","handbook":"With ABS, apply firm steady pressure and hold.","hbref":"§5.4","qid":"AB-232"},"245":{"q":"It is a freezing winter morning and I'm doing my pre-trip on a tractor-trailer with air brakes. I realize I forgot to drain the air tanks for the last several days, and I notice moisture around the drain valves. Why does this matter for the brake system?","options":["Water and compressor oil that collect in the tanks can damage the brake system and may freeze up in cold weather, so the tanks must be drained daily","A small amount of water and oil in the tanks actually helps lubricate and seal the brake valves, so skipping the drain occasionally is harmless","Water and oil have no effect on braking because the safety relief valve will simply vent them off automatically at about 150 psi","Moisture only matters for the parking brakes, so as long as the service brakes hold I can safely delay draining the tanks until spring"],"answer":0,"explanation":"Air tanks must be drained daily because water and compressor oil collect in them and can damage the brake system or freeze in cold weather.","handbook":"Water and oil in the tanks can damage the system.","hbref":"§5.1","qid":"AB-233"},"246":{"q":"It's a freezing morning and during your pre-trip you notice water and a little oily sludge have collected in the supply (wet) tank overnight. To get this contamination out before it freezes and damages the system, which device do you operate on that tank?","options":["The safety relief valve, by pushing it open to vent the tank","The drain valve (petcock) at the bottom of the tank","The governor, by cutting it out to release the buildup","The low-air warning buzzer reset, to clear the line"],"answer":1,"explanation":"Water and oil are removed by opening the drain valve, or petcock, located at the bottom of the air tank.","handbook":"Drain the wet tank with its drain valve.","hbref":"§5.1","qid":"AB-234"},"247":{"q":"During a pre-trip inspection, I let the air system build to full pressure. I suddenly hear a loud burst of air escaping from the safety relief valve on the supply (wet) tank. Before driving, what does this most likely tell me about my system?","options":["The low air pressure warning failed, so tank pressure quietly dropped below 60 psi.","The governor cut in early and the compressor stopped sending air to the tanks.","The governor failed to cut out, so pressure climbed past about 150 psi and the valve dumped it.","A slow leak let pressure fall into the 20 to 45 psi range and tripped the spring brakes."],"answer":2,"explanation":"If the governor fails to cut out the compressor, pressure climbs past about 150 psi and the safety relief valve opens to dump the excess air.","handbook":"The safety valve opens when pressure is too high.","hbref":"§5.1","qid":"AB-235"},"248":{"q":"During my pre-trip inspection, the shop mechanic tells me to go check that the \"maxi-brakes\" are holding properly while the trailer is parked. I'm not familiar with that slang term. Which component on my air-brake vehicle is he actually referring to?","options":["The service brakes I apply with the foot pedal during a normal stop","The modulating valve I use to apply the brakes gradually in an emergency","The slack adjusters that control how far the pushrod travels","The spring brakes that hold the vehicle and apply when air pressure is lost"],"answer":3,"explanation":"Maxi-brakes are another name for the spring brakes, which hold a parked vehicle and apply automatically when air pressure is lost.","handbook":"Spring brakes are also called maxi-brakes.","hbref":"§5.2","qid":"AB-236"},"249":{"q":"I'm switching from a car to a loaded tractor-trailer equipped with air brakes, and my instructor asks why mastering the air brake system matters most for a CDL driver. Which answer best captures the primary purpose of learning air brakes?","options":["To bring a heavy, loaded vehicle to a safe, controlled stop","To let the rig coast and accelerate to higher cruising speeds","To reduce fuel use by keeping the engine compressor idle","To shorten the total stopping distance compared with hydraulic brakes"],"answer":0,"explanation":"The main purpose of an air brake system is to bring a heavy, loaded vehicle to a safe, controlled stop.","handbook":"Knowing air brakes helps you stop a heavy vehicle safely.","hbref":"§5.1","qid":"AB-237"}};
  var APPEND=[];
  var TR={"ru":{"0":{"q":"Во время предрейсового осмотра экзаменатор просит меня объяснить устройство пневматических тормозов на моем тягаче. Я говорю, что пневматическая тормозная система на самом деле объединяет несколько отдельных тормозных систем в одну. Какой ответ правильно указывает, сколько отдельных тормозных систем фактически объединяет пневматическая тормозная система, и называет их?","options":["Три системы: рабочие тормоза, стояночные тормоза и аварийные тормоза.","Две системы: первичный и вторичный воздушные контуры с одним набором органов управления.","Четыре системы: рабочие тормоза, стояночные тормоза, аварийные тормоза и ABS.","Одна система: единый контур, который обеспечивает обычные остановки, стоянку и аварийное торможение вместе."],"explanation":"Пневматическая тормозная система фактически состоит из трёх систем: рабочих тормозов, стояночных тормозов и аварийных тормозов."},"1":{"q":"Я выполняю предрейсовый осмотр и поднимаю обороты двигателя, чтобы нагнетать давление воздуха, наблюдая за манометром на приборной панели. Я хочу убедиться, что регулятор работает правильно, отметив давление, при котором воздушный компрессор перестаёт нагнетать воздух в ресиверы. При каком приблизительно показании стрелка должна перестать подниматься, потому что регулятор отключился (cut-out)?","options":["Около 100 psi — это давление, при котором компрессор перестаёт добавлять воздух в ресиверы","Около 125 psi — в этот момент регулятор отключается (cut-out) и компрессор перестаёт нагнетать воздух","Около 150 psi — здесь система достигает максимума и компрессор выключается","Около 60 psi — точка, в которой регулятор останавливает компрессор в заряженной системе"],"explanation":"Регулятор отключается примерно при 125 psi, останавливая подачу воздуха компрессором в баллоны."},"2":{"q":"Я стою на стоянке и провожу предрейсовую проверку, наблюдая за манометром давления воздуха. Компрессор ранее отключился и перестал нагнетать воздух, поэтому давление медленно падает, пока я тестирую систему. При каком показании манометра регулятор должен снова включить компрессор и возобновить нагнетание воздуха?","options":["Около 60 psi, в той же точке, где загорается контрольная лампа и звучит зуммер низкого давления воздуха","Около 125 psi, на уровне, при котором регулятор останавливает нагнетание воздуха компрессором","Около 100 psi, в точке, где регулятор подаёт компрессору сигнал возобновить нагнетание","Около 150 psi, на уровне, при котором предохранительный клапан открывается для сброса давления"],"explanation":"Точка включения регулятора составляет около 100 psi, при которой компрессор снова начинает нагнетать воздух."},"3":{"q":"Во время предрейсового осмотра я замечаю, что регулятор (губернатор) воздушного компрессора не отключается — манометр продолжает расти выше обычной отметки 125 psi, где накачка должна прекратиться. Если регулятор так и не отключится, при каком примерно давлении должен открыться предохранительный клапан, чтобы защитить систему от избыточного давления?","options":["Примерно при 100 psi — в той же точке, где регулятор обычно включается и возобновляет накачку","Примерно при 60 psi — на том же пороге, который включает сигнальную лампу и зуммер низкого давления воздуха","Примерно при 125 psi — совпадая с отключением регулятора, чтобы оба устройства срабатывали вместе","Примерно при 150 psi — стравливая избыток воздуха, чтобы система не достигла опасного давления"],"explanation":"Предохранительный клапан открывается примерно при 150 psi, стравливая лишний воздух и защищая систему от опасного давления."},"4":{"q":"Я провожу предрейсовый осмотр одиночного тягача с полностью заряженной пневмосистемой. При выключенном двигателе я ступенчато стравливаю воздух нажатиями на тормоз и слежу за приборной панелью. К какому моменту контрольная лампа и зуммер низкого давления воздуха уже должны сработать — то есть предупреждение должно ВКЛЮЧИТЬСЯ до того, как давление упадёт ниже какого уровня?","options":["До того, как давление воздуха упадёт ниже 60 psi","До того, как давление воздуха упадёт ниже 80 psi","Только после того, как давление уже опустится в диапазон 20–45 psi","До того, как давление воздуха упадёт ниже 100 psi"],"explanation":"Предупреждение о низком давлении воздуха должно сработать до того, как давление в системе упадёт ниже 60 psi."},"5":{"q":"Я веду гружёный одиночный тягач с прицепом, когда лопается магистраль и давление воздуха начинает быстро падать. Световой сигнал и зуммер низкого давления уже сработали, а стрелка продолжает падать. Примерно при каком давлении пружинные (аварийные) тормоза должны сработать сами и остановить меня?","options":["Около 60 psi — в той же точке, где впервые срабатывает предупреждение о низком давлении","Где-то в диапазоне от 20 до 45 psi, уже после того как сработало предупреждение","Около 100 psi — точка включения регулятора, где компрессор снова запускается","Около 5–10 psi — только когда баллоны почти полностью опустели"],"explanation":"Пружинные (аварийные/стояночные) тормоза срабатывают автоматически, когда давление воздуха падает до 20–45 psi."},"6":{"q":"Во время предрейсового осмотра инструктор показывает на педаль, которую я нажимаю ногой, чтобы привести в действие рабочие тормоза, и спрашивает её второе правильное название. Чтобы ответить верно, на какой компонент он указывает?","options":["На регулятор давления (губернатор), так как он определяет, сколько тормозного воздуха педаль подаёт на колёса","На регулировочный рычаг (slack adjuster), потому что он преобразует усилие моей ноги в механическую тормозную силу","На ножной (педальный) клапан, который при нажатии подаёт воздух к рабочим тормозам","На соединительную головку (glad hand), так как это соединение, по которому тормозной воздух идёт к тормозам"],"explanation":"Педаль тормоза правильно называется ножным (педальным) клапаном, который подаёт воздух к рабочим тормозам при нажатии."},"7":{"q":"Морозное зимнее утро, и во время предрейсового осмотра я открываю сливной клапан внизу воздушного ресивера. Вместе с воздухом выбрызгивается молочная маслянистая жидкость. Коллега говорит, что у меня серьёзная поломка, потому что этой жидкости в ресивере быть не должно. Какое утверждение верно объясняет, что я вижу и почему я сливаю ресиверы ежедневно?","options":["Сливаться должен только воздух; жидкость означает, что треснувший ресивер пропускает тормозную жидкость в систему воздуха","Охлаждающая жидкость просочилась через неисправный сальник в ресивер, поэтому я должен слить её до попадания в тормозные камеры","Протекающая тормозная жидкость смешалась с воздухом, и ежедневный слив вымывает эту жидкость из системы","Сжатый воздух обычно накапливает воду и немного компрессорного масла, и ежедневный слив удаляет их, чтобы предотвратить замерзание и повреждения"],"explanation":"В сжатом воздухе естественно скапливаются вода и немного компрессорного масла, поэтому баллоны нужно сливать ежедневно, чтобы избежать замерзания и повреждений."},"8":{"q":"Зимним утром стоит мороз, и я замечаю, что мой грузовик оснащён осушителем воздуха, установленным на питающем (влажном) баке. Во время предрейсового осмотра я пытаюсь вспомнить основную функцию этого узла. Какое утверждение ЛУЧШЕ ВСЕГО описывает, что осушитель воздуха делает для моей пневматической тормозной системы?","options":["Он удаляет воду и загрязнения из сжатого воздуха до того, как этот воздух попадёт в накопительные баки","Он повышает давление сжатого воздуха выше точки отключения регулятора, чтобы баки достигли более высокого рабочего давления","Он включает сигнальную лампу и зуммер низкого давления воздуха до того, как давление в баке упадёт ниже 60 psi","Он охлаждает нагретые тормозные барабаны и накладки после долгого крутого спуска, чтобы предотвратить потерю эффективности торможения"],"explanation":"Осушитель воздуха удаляет воду и загрязнения из сжатого воздуха до того, как тот попадёт в накопительные баллоны."},"9":{"q":"Я провожу предрейсовый осмотр тягача с прицепом, и двигатель только что достиг отсечки регулятора (cut-out). Осматривая приборную панель, я вижу два манометра воздуха рядом. Чтобы убедиться, что запасённого воздуха достаточно, прежде чем отпустить тормоза и тронуться, какой показатель манометра давления подачи (supply pressure gauge) даёт мне нужную информацию?","options":["Величину давления, которое я сейчас подаю в тормозные камеры, когда нажимаю на педаль","Количество воздушного давления, накопленного в воздушных баллонах в данный момент (около 125 psi при отсечке)","Давление, при котором пружинные тормоза сработают автоматически, если воздуха станет мало","Давление, на которое настроен предохранительный клапан, открывающийся для защиты системы"],"explanation":"Манометр давления показывает, сколько воздуха в данный момент хранится в баллонах — около 125 psi при отключении регулятора."},"10":{"q":"Я спускаюсь по длинному уклону на груженом грузовике и сильнее нажимаю на педаль тормоза, чтобы удерживать скорость. Чем дальше я выжимаю педаль (тормозной кран), тем выше поднимается стрелка одного из приборов на панели, а когда я отпускаю педаль, она падает обратно к нулю. За каким прибором я наблюдаю, реагирующим на нажатие педали?","options":["Манометр давления в воздушных баллонах (ресиверах), так как он показывает, сколько воздуха осталось в баллонах","Манометр отключения регулятора, так как он показывает остановку компрессора примерно при 125 psi","Манометр давления торможения (применяемого давления), так как он показывает, какое давление воздуха я подаю на тормоза","Прибор предупреждения о низком давлении, так как он загорается до падения давления ниже 60 psi"],"explanation":"Манометр давления подачи показывает, какое давление воздуха вы подаёте на тормоза через педаль."},"11":{"q":"Во время предрейсового осмотра инструктор показывает на S-образный кулачок (S-cam) тормозного механизма и просит объяснить, что физически происходит в этом узле в момент, когда я нажимаю на педаль тормоза и воздух поступает в тормозную камеру. Какой ответ правильно описывает работу S-образного кулачка?","options":["Он сливает воду и компрессорное масло из воздушных баков, чтобы магистрали не замёрзли","Он подаёт сигнал регулятору остановить компрессор, когда в баках достигается около 125 psi","Он отводит назад регулировочный рычаг (slack adjuster), выбирая свободный ход штока","Он проворачивается и разводит тормозные колодки в стороны, прижимая их к внутренней поверхности барабана"],"explanation":"S-образный кулачок поворачивается и раздвигает тормозные колодки, прижимая их к внутренней стороне барабана."},"12":{"q":"Во время предрейсового осмотра я паркуюсь на ровной площадке, подкладываю упоры под колёса, отпускаю стояночные тормоза и поддеваю монтировкой ручной регулятор зазора, чтобы проверить чрезмерный ход штока. Тормоза разрегулированы, если регулятор зазора смещается БОЛЬШЕ чем примерно на:","options":["1 дюйм, поскольку больший свободный ход означает, что тормоза разрегулированы и теряют тормозную силу","3 дюйма, что является максимально допустимым ходом до разрегулировки тормозов","5 дюймов, поскольку всё, что меньше этого, всё ещё держит тормоза в правильной регулировке","Он может двигаться свободно, потому что регуляторы зазора рассчитаны на качание без ограничения хода"],"explanation":"Ручной регулировочный рычаг при подёргивании должен смещаться не более чем на 1 дюйм, иначе тормоза разрегулированы."},"13":{"q":"Я веду тягач с прицепом на пневматических (воздушных) тормозах и сильно нажимаю на педаль тормоза, чтобы сбросить скорость перед заторами впереди. По сравнению с гидравлическими тормозами на моей легковой машине есть заметная задержка, прежде чем воздушные тормоза действительно срабатывают. Какова примерно эта задержка пневмотормозов — время, за которое воздух проходит по магистралям и срабатывает после того, как я нажал на педаль?","options":["Около 1/10 секунды — та же почти мгновенная реакция, какую я чувствую в гидравлической тормозной системе автомобиля","Около 1/2 секунды — за это время воздух проходит по магистралям и тормоза срабатывают","Около 2 секунд, что примерно соответствует задержке дистанции реакции, прежде чем водитель нажмёт на педаль","Около 5 секунд, поскольку воздух должен полностью заполнить каждую камеру, прежде чем начнётся торможение"],"explanation":"У пневматических тормозов задержка около полусекунды, пока сжатый воздух проходит по магистралям и тормоза срабатывают."},"14":{"q":"Я рассчитываю общий тормозной путь для моего грузовика с пневматическими (воздушными) тормозами. Для легкового автомобиля с гидравлическими тормозами общий тормозной путь равен сумме расстояния восприятия, расстояния реакции и расстояния торможения. Поскольку мой грузовик использует пневматические тормоза, какую ДОПОЛНИТЕЛЬНУЮ составляющую я должен добавить к этому расчёту, которой нет у водителя легкового автомобиля?","options":["Дополнительное расстояние реакции, потому что мозгу требуется больше времени, чтобы управлять пневматическими тормозами","Увеличенное расстояние восприятия, потому что из-за большего размера грузовика опасность труднее вовремя заметить","Расстояние задержки торможения — примерно полсекунды, за которые воздух проходит по магистралям и срабатывают тормоза","Ничего дополнительного, ведь четыре базовые составляющие одинаковы для любого типа тормозной системы"],"explanation":"Тормозной путь пневматики включает дистанцию задержки на полсекунды, пока воздух проходит по магистралям и тормоза срабатывают."},"15":{"q":"Во время предрейсового осмотра я глушу двигатель при полностью заряженной системе (около 125 psi), подкладываю упоры под колёса и оставляю стояночные тормоза ОТПУЩЕННЫМИ на моём одиночном (без прицепа) грузовике. Я смотрю на приборную панель ровно одну минуту, замеряя утечку. Потеря воздуха допустима только при условии, что она не превышает какую величину?","options":["4 psi в минуту, так как это предел, когда двигатель заглушён, а баки заполнены","1 psi в минуту, исходя из предположения, что из герметичной системы почти не должно выходить воздуха","3 psi в минуту — та же величина, что применяется к автопоезду (составу) в этом тесте","2 psi в минуту — максимум, допустимый для одиночного транспортного средства с отпущенными тормозами"],"explanation":"Для одиночного транспортного средства с отпущенными тормозами потеря воздуха не должна превышать 2 psi в минуту."},"16":{"q":"Во время предрейсового осмотра тягача с прицепом я полностью заряжаю систему примерно до 125 psi, глушу двигатель и оставляю тормоза отпущенными, чтобы засечь утечку воздуха. Наблюдая за манометром на панели в течение одной минуты, какое МАКСИМАЛЬНОЕ падение давления допустимо, чтобы пройти эту часть осмотра?","options":["3 psi за одну минуту","2 psi за одну минуту","4 psi за одну минуту","6 psi за одну минуту"],"explanation":"Для составного транспортного средства с отпущенными тормозами потеря воздуха не должна превышать 3 psi в минуту."},"17":{"q":"Во время предрейсового осмотра я накачиваю пневмосистему примерно до 125 psi, глушу двигатель, подкладываю упоры под колёса и до отказа нажимаю на ножную тормозную педаль на своём одиночном грузовике без прицепа. Я смотрю на приборную панель в течение одной минуты, чтобы проверить скорость утечки воздуха. Какое показание означает, что мой грузовик в пределах допустимой нормы и безопасен для движения?","options":["Давление падает на 4 psi за эту минуту","Давление падает на 2 psi за эту минуту","Давление падает на 5 psi за эту минуту","Давление падает на 6 psi за эту минуту"],"explanation":"Для одиночного транспортного средства с нажатыми тормозами потеря воздуха должна оставаться менее 3 psi в минуту."},"18":{"q":"Во время предрейсового осмотра двухконтурной пневматической тормозной системы я запускаю двигатель, держу рабочие обороты и слежу за приборами на панели, которые поднимаются с 85 psi. Чтобы пройти проверку нарастания давления, за какое время стрелки должны достичь 100 psi?","options":["В течение 10 секунд работы на рабочих оборотах","В течение 3 минут работы на рабочих оборотах","В течение 45 секунд работы на рабочих оборотах","В течение 5 минут работы на рабочих оборотах"],"explanation":"В двухконтурной пневмосистеме давление должно подняться с 85 до 100 psi за 45 секунд на рабочих оборотах."},"19":{"q":"Во время предрейсового осмотра двигатель выключен, а воздушные ресиверы заряжены примерно до 125 psi. Я хочу убедиться, что устройство предупреждения о низком давлении воздуха работает правильно, прежде чем тронуться. Какое действие действительно выполняет эту проверку?","options":["Запустить двигатель на высоких оборотах при заряженной системе и следить, не загорится ли предупреждение, когда давление поднимется выше 60 psi","Широко открыть сливные краны ресиверов, чтобы весь воздух быстро вышел из баков, и слушать зуммер","Один раз нажать на педаль тормоза и убедиться, что устройство предупреждения не срабатывает при давлении выше 100 psi","При выключенном двигателе многократно нажимать и отпускать педаль тормоза, стравливая давление, пока предупреждение не сработает выше 60 psi"],"explanation":"При выключенном двигателе многократно нажимайте тормоз, стравливая давление, и убедитесь, что предупреждение о низком давлении срабатывает до падения ниже 60 psi."},"20":{"q":"Во время предрейсового осмотра пневматических тормозов я накачал систему до полного давления, отпустил стояночный тормоз и готов проверить, что рабочие тормоза действительно держат и останавливают тягач прямо. Какой из вариантов является правильным способом выполнить тест на остановку рабочими тормозами?","options":["Дать автомобилю проехать вперёд на скорости около 5 миль/ч, затем твёрдо нажать на педаль тормоза и убедиться, что он останавливается без увода в сторону","Разогнаться до обычной скорости на трассе и резко затормозить один раз, чтобы убедиться, что тормоза справятся с полной остановкой","Удерживая автомобиль на месте, вытянуть рукоятку стояночного тормоза и проверить, остаётся ли тягач надёжно зафиксированным","Двигаясь со скоростью около 5 миль/ч, быстро нажать на педаль тормоза десять раз, чтобы убедиться, что давление каждый раз восстанавливается"],"explanation":"Правильная проверка рабочих тормозов: двигаясь вперёд со скоростью около 5 миль/ч, твёрдо нажмите на педаль — машина должна остановиться прямо, не уводя в сторону."},"21":{"q":"Во время предрейсового осмотра я обнаруживаю трещину, идущую по поверхности одного из тормозных барабанов. Мне нужно решить, выводить ли тягач из эксплуатации. Согласно руководству CDL штата Техас, тормозной барабан с трещиной выводится из эксплуатации, когда длина трещины превышает что из перечисленного?","options":["Любую видимую тонкую (волосяную) трещину на поверхности барабана","Половину ширины рабочей (фрикционной) поверхности барабана","Четверть ширины рабочей (фрикционной) поверхности барабана","Полную ширину рабочей (фрикционной) поверхности барабана"],"explanation":"Тормозной барабан подлежит снятию с эксплуатации, если трещина длиннее половины ширины фрикционной поверхности барабана."},"22":{"q":"Во время предрейсового осмотра я снимаю колесо и залезаю под прицеп, чтобы осмотреть барабанные тормоза. Я обнаруживаю проблему и решаю, что тормозные накладки нужно заменить до начала движения. Какое из перечисленных состояний тормозных накладок ПРАВИЛЬНО оправдывает снятие этого транспортного средства с эксплуатации?","options":["Накладки толстые, сухие и плотно прилегают к опорному диску","Накладки плотно прилегают к барабану и имеют равномерный, лёгкий поверхностный износ","Накладки пропитаны маслом или смазкой либо изношены до опасно тонкого состояния","Накладки были только что установлены и имеют лёгкий глянец от первоначальной приработки"],"explanation":"Тормозные накладки неисправны, и машину нужно снять с эксплуатации, если они пропитаны маслом или смазкой либо изношены до опасно малой толщины."},"23":{"q":"Я везу гружёный автопоезд вниз по длинному крутому спуску. Перед началом спуска я включил пониженную передачу, и теперь думаю, как использовать пневматические тормоза на оставшейся части спуска. Какое утверждение правильно описывает роль, которую должны играть мои тормоза на этом спуске?","options":["Они являются моим главным средством контроля скорости, поэтому я должен держать педаль нажатой с постоянным усилием всю дорогу вниз","Они работают лучше всего, если их прерывисто нажимать и отпускать, давая воздуху восстановиться между нажатиями","Их следует удерживать нажатыми сильно и непрерывно, чтобы колёса вообще не набирали скорость","Они являются дополнением к торможению двигателем, применяются лёгкими, ровными нажатиями в поддержку пониженной передачи"],"explanation":"На длинном спуске основное средство контроля скорости — двигатель на пониженной передаче, а тормоза лишь дополняют его лёгкими, ровными нажатиями."},"24":{"q":"Я спускаюсь по длинному крутому склону на гружёном составном автопоезде, уже включил пониженную передачу и хочу применить правильную технику прерывистого (snub) торможения, чтобы контролировать скорость. Какое действие верно описывает, как мне следует работать с тормозами?","options":["Нажать на тормоз достаточно сильно, чтобы скорость упала примерно на 5 миль/ч ниже моей безопасной скорости, затем полностью отпустить тормоз и повторять этот цикл по мере необходимости","Постоянно удерживать ровное лёгкое давление на педаль тормоза всю дорогу вниз, чтобы вообще не допустить нагрева","Быстро прокачивать тормоза нажатием и отпусканием на протяжении всего спуска, чтобы колёса не заблокировались","Перейти в нейтраль и катиться накатом, нажимая на тормоз только если спидометр поднимается выше безопасной скорости"],"explanation":"На длинном спуске применяйте прерывистое торможение: тормозите твёрдо, пока скорость не упадёт примерно на 5 миль/ч ниже безопасной, полностью отпускайте для остывания и повторяйте."},"25":{"q":"Я спускаюсь по длинному крутому горному склону на груженом грузовике с пневматическими (воздушными) тормозами. Спуск всё не кончается, и я переживаю за тормоза, поэтому начинаю быстро снова и снова нажимать и отпускать педаль тормоза, чтобы держать скорость под контролем. Почему делать так категорически неправильно?","options":["Повторяющееся прерывистое торможение перегревает регулировочные рычаги (трещотки) и блокирует передние колёса, из-за чего грузовик заносит на спуске","При каждом отпускании педали воздух уходит быстрее, чем компрессор успевает его восполнить, поэтому давление может упасть настолько, что тормозам не хватит воздуха для работы","Быстрое нажатие педали заставляет систему ABS полностью отпустить тормоза, оставляя пружинные (стояночные) тормоза единственным способом замедлиться","Накачивание педалью открывает предохранительный клапан при 150 psi, стравливая воздух из ресивера, который нужен вам на остаток спуска"],"explanation":"Подкачивание тормозов выпускает воздух быстрее, чем компрессор успевает его восполнять, поэтому давление может упасть до уровня, при котором тормозам не хватит воздуха для работы."},"26":{"q":"Я только что завершил долгий спуск с крутого горного склона, всю дорогу удерживая педаль пневмотормозов, и заезжаю на стоянку для обязательного отдыха. В какой из этих ситуаций мне НЕ следует ставить стояночный (пружинный) тормоз, а вместо этого подложить упоры под колёса?","options":["Я паркуюсь на небольшом уклоне под гору, где машина может покатиться, если оставить её на передаче","Я оставлю грузовик без присмотра на ночь на размеченной стоянке для фур","Тормозные барабаны и колодки всё ещё крайне горячие после только что пройденного спуска","Зуммер предупреждения о низком давлении воздуха кратко сработал, когда я останавливался"],"explanation":"Не ставьте стояночный (пружинный) тормоз, когда барабаны и колодки ещё очень горячие после длинного спуска, так как это может их повредить и привести к заклиниванию."},"28":{"q":"Я веду тягач с полуприцепом 2020 года (с исправной системой ABS), когда автомобиль внезапно останавливается прямо в моей полосе. Мне нужно остановиться как можно быстрее, удерживая машину в своей полосе, чтобы не съехать на обочину. Какой способ торможения обеспечит лучший контроль в этой аварийной ситуации?","options":["Быстро накачивать педаль тормоза, чтобы ABS могла срабатывать и схватывать между каждым отпусканием","Сначала задействовать только ручной кран тормозов прицепа, чтобы колёса тягача не скользили","Ослаблять давление в тот момент, когда я чувствую начало юза колеса, а затем снова нажимать","Сильно нажать на педаль тормоза, удерживать её и продолжать руль направлять в свободную полосу"],"explanation":"С ABS тормозите сильно и удерживайте твёрдое давление на педаль, продолжая управлять, так как ABS не даёт колёсам заблокироваться, позволяя направить машину в свободную полосу."},"29":{"q":"Я веду старый тягач с полуприцепом, который НЕ оборудован системой ABS, и вдруг передо мной подрезает легковой автомобиль. Мне нужно резко и экстренно затормозить, сохраняя контроль над автопоездом. Какой способ торможения мне следует применить?","options":["Применить контролируемое или прерывистое (рывковое) торможение, чтобы колёса продолжали вращаться и я мог управлять рулём","Выжать педаль тормоза до самого пола и удерживать её с силой до полной остановки","Затормозить так сильно, чтобы колёса заблокировались, ведь заблокированные колёса дают самый короткий тормозной путь","Быстро нажимать и отпускать педаль тормоза до самого пола, чтобы поддерживать давление воздуха"],"explanation":"Без ABS применяйте контролируемое или прерывистое торможение, чтобы колёса продолжали вращаться, что сохраняет и тормозное усилие, и управляемость."},"30":{"q":"Я веду гружёный грузовик без системы ABS, когда на дорогу что-то выскакивает, и мне приходится резко тормозить. Я выжимаю педаль тормоза до упора, колёса блокируются, и я отпускаю педаль, чтобы начать прерывистое (stab) торможение. Чтобы выполнить прерывистое торможение правильно, когда я должен снова сильно нажать на педаль?","options":["Сразу после того, как отпустил педаль, ничего не дожидаясь","Только после того, как колёса снова начнут вращаться","После того, как отпустил тормоза примерно на 10 секунд","Вообще не нажимать — после отпускания нужно рулить и ждать"],"explanation":"При прерывистом торможении тормоза снова нажимают только после того, как колёса снова начали вращаться, поскольку заблокированные колёса не позволяют управлять и эффективно тормозить."},"31":{"q":"Вы проехали 30 миль рейса, когда на приборной панели загорается и остаётся гореть жёлтая контрольная лампа неисправности ABS (антиблокировочной системы). Предупреждение о низком давлении воздуха НЕ сработало, и педаль по-прежнему ощущается твёрдой. Какое из утверждений правильно описывает вашу ситуацию и верные действия?","options":["Ваши рабочие тормоза отказали; немедленно остановите автопоезд на обочине контролируемым торможением и вызовите эвакуатор, прежде чем ехать дальше.","Ваш тормозной путь теперь длиннее обычного, поэтому увеличьте дистанцию и прокачивайте педаль тормоза, чтобы воздух продолжал поступать к колёсам.","У вас по-прежнему работают обычные рабочие тормоза, и можно продолжать движение осторожно; утрачена только функция антиблокировки, поэтому обслужите ABS как можно скорее.","Ваши пружинные (стояночные) тормоза вот-вот сработают автоматически, поэтому снизьте скорость и съезжайте на ближайшем съезде, пока колёса не заблокировались."],"explanation":"Загорание лампы ABS означает потерю только антиблокировочной функции; обычные рабочие тормоза работают полностью, поэтому ведите машину осторожно и отремонтируйте ABS как можно скорее."},"32":{"q":"Я покупаю подержанный седельный тягач и хочу убедиться, что он с завода оснащён антиблокировочной системой тормозов (ABS), так как федеральные правила сделали ABS обязательной для определённых транспортных средств с пневматическими тормозами. Дилер показывает мне четыре тягача, выпущенные в разные годы. Какая САМАЯ РАННЯЯ дата выпуска ОБЯЗЫВАЕТ, чтобы тягач имел заводскую систему ABS?","options":["Любой тягач, выпущенный 1 марта 1998 года или позже","Любой тягач, выпущенный 1 марта 1995 года или позже","Любой тягач, выпущенный 1 марта 2000 года или позже","Любой тягач, выпущенный 1 марта 1997 года или позже"],"explanation":"Федеральные правила требуют заводской системы ABS на тягачах, выпущенных 1 марта 1997 года или позже."},"34":{"q":"Морозное декабрьское утро в Амарилло, я провожу предрейсовый осмотр. На воздушных ресиверах моего тягача стоят ручные сливные краны, но я опаздываю, поэтому хочется пропустить слив сегодня. Какая причина ЛУЧШЕ всего объясняет, почему я всё же должен открыть сливные краны ресиверов перед выездом?","options":["Вода, скапливающаяся в ресиверах, может замёрзнуть в холодную погоду и вывести тормоза из строя","Слив ресиверов позволяет регулятору отключаться при более высоком давлении, и система заряжается быстрее","Открытие кранов стравливает старый воздух, чтобы предохранительный клапан снова сел на правильную настройку 150 psi","Выпуск воздуха сбрасывает предупреждение о низком давлении, и зуммер не сработает ниже 60 psi"],"explanation":"Сливайте воздушные баллоны ежедневно, так как скопившаяся вода может замёрзнуть в холодную погоду и вывести тормоза из строя."},"35":{"q":"Я заканчиваю предрейсовый осмотр тягача с прицепом. Двигатель работает на холостом ходу, и стрелка манометра воздушного давления поднимается. Прежде чем отпустить стояночный тормоз и выехать со стоянки, до какого уровня давления нужно дать воздушной системе накачаться?","options":["Примерно до 100 psi, потому что это точка, где компрессор включается, и я понимаю, что он работает","До нормального рабочего диапазона, примерно 125 psi, где регулятор отключается и прекращает накачку","Примерно до 150 psi — уровня, на котором открывается предохранительный клапан для защиты системы","Примерно до 60 psi достаточно, ведь именно на этом уровне отключается предупреждение о низком давлении воздуха"],"explanation":"Перед началом движения зарядите воздушную систему до нормального рабочего диапазона, около 125 psi, при котором регулятор отключается."},"36":{"q":"Во время предрейсового осмотра я замечаю, что ремень привода воздушного компрессора залоснился и продавливается большим пальцем на пару сантиметров. Двигатель заводится нормально, и радио в кабине работает. Почему этот ослабленный приводной ремень важен для безопасной эксплуатации?","options":["Ослабленный ремень важен только потому, что он может свистеть и мешать расслышать зуммер предупреждения о низком давлении воздуха","Это важно, потому что тот же ремень вращает генератор, который заряжает аварийный аккумулятор прицепа","Проскальзывающий ремень не даёт компрессору качать воздух с нужной скоростью, поэтому система может так и не набрать или не удержать достаточное давление воздуха","Это важно, потому что приводной ремень направляет охлаждающий поток воздуха на передние тормозные барабаны, предотвращая перегрев тормозов"],"explanation":"Проскальзывающий приводной ремень компрессора не даёт ему вращаться достаточно быстро, поэтому система может не набирать или не удерживать нужное давление воздуха."},"37":{"q":"Я провожу предрейсовый осмотр одиночного автопоезда и хочу убедиться, что выполнил каждый этап проверки пневматических (воздушных) тормозов, прежде чем тронуться. Другой водитель говорит мне, что несколько перечисленных мной проверок на самом деле не входят в проверку воздушных тормозов. Что из перечисленного действительно является обязательной частью полной предрейсовой проверки воздушных тормозов?","options":["Только проверка устройства предупреждения о низком давлении воздуха, ведь именно за зуммером и лампочкой следит экзаменатор","Только проверка времени нарастания давления воздуха, ведь это доказывает, что компрессор работает","Только проверка скорости утечки воздуха в статике, ведь утечка — самый серьёзный дефект, который можно обнаружить","Все они — проверка предупреждения о низком давлении, проверка времени нарастания давления и проверка скорости утечки воздуха являются обязательными частями проверки"],"explanation":"Полная предрейсовая проверка пневмотормозов требует всех этих пунктов: предупреждения о низком давлении, времени набора давления и скорости утечки воздуха."},"38":{"q":"Я провожу предрейсовый осмотр тягача с пневматическими (воздушными) тормозами и хочу пропустить любой шаг, который НЕ проверяет саму систему воздушных тормозов. Какой пункт из моего списка относится к другой системе и ничего не говорит о тормозах?","options":["Слив воды и масла из радиатора, чтобы система охлаждения двигателя оставалась чистой","Замер времени роста давления с 85 до 100 psi для проверки исправной скорости набора давления","Накачать систему, заглушить двигатель и следить по манометру за скоростью падения давления (утечкой)","Прокачивать педаль, пока около 60 psi не сработают сигнальная лампа и зуммер низкого давления"],"explanation":"Слив воды и масла из радиатора относится к обслуживанию системы охлаждения двигателя и не проверяет пневмотормозную систему."},"39":{"q":"Я веду тягач с прицепом, оборудованный системой ABS, и мне нужно совершить резкое экстренное торможение на сухом покрытии. Когда ABS срабатывает и я чувствую пульсацию педали, какое утверждение о том, что ABS на самом деле для меня делает при этом торможении, ВЕРНО?","options":["Она сокращает мой тормозной путь по сравнению с той же машиной без ABS","Она не даёт колёсам заблокироваться, чтобы я мог управлять рулём при сильном торможении","Она автоматически сокращает запаздывание тормозов ниже обычной половины секунды","Она включает пружинные (стояночные) тормоза, добавляя дополнительную тормозную силу"],"explanation":"ABS предотвращает блокировку колёс, поэтому они продолжают вращаться, позволяя управлять рулём при резком торможении."},"40":{"q":"Я провожу утренний предрейсовый осмотр и замечаю, что в воздушных ресиверах моего тягача на дне скопилась смесь воды и пленка компрессорного масла. Холодное зимнее утро в районе Пэнхэндл. Чтобы воздушная тормозная система работала безопасно и не замерзла, что мне следует сделать с этим скоплением?","options":["Оставить как есть, ведь осушитель воздуха и нагрев тормозов выпарят воду и масло в пути","Долить в ресиверы дополнительное компрессорное масло, чтобы влага оставалась во взвешенном состоянии и не замерзла","Ежедневно сливать конденсат из воздушных ресиверов через сливные клапаны, чтобы вода и масло не повредили систему и не вызвали замерзание","Сливать конденсат только раз в неделю, так как современные автоматические клапаны справляются с остальным сами"],"explanation":"Сливайте воздушные баллоны ежедневно через сливные клапаны, чтобы скопившиеся вода и масло не повредили систему и не замёрзли."},"41":{"q":"Во время предрейсового осмотра я заглушил двигатель, чтобы провести тест на утечку воздуха, и замечаю, что стрелка манометра полностью перестала подниматься, пока двигатель выключен. Новичок рядом со мной настаивает, что компрессор должен сам продолжать нагнетать давление. Какое утверждение правильно объясняет, почему давление перестало расти после того, как я заглушил двигатель?","options":["Регулятор (губернатор) механически накачивает воздушные баллоны и работает только когда грузовик катится вперёд","Пружина стояночного тормоза заряжает воздушную систему, поэтому она останавливается при включении тормозов","Вращение колёс прицепа крутит компрессор, поэтому давление растёт только при движении","Компрессор приводится в действие двигателем (ремнём или напрямую), поэтому при выключенном двигателе воздух не нагнетается"],"explanation":"Воздушный компрессор приводится в действие двигателем, поэтому при выключенном двигателе он не нагнетает воздух."},"42":{"q":"Зимним утром стоит сильный мороз, и я провожу предрейсовый осмотр тягача, оснащённого осушителем воздуха. Я хочу понять, от чего это устройство защищает меня, пока компрессор нагнетает воздух в систему. Какова главная задача осушителя воздуха в этой ситуации?","options":["Он удаляет водяной пар (и немного масла) из сжатого воздуха до того, как тот попадёт в ресиверы, чтобы меньше влаги скапливалось и замерзало в системе","Он подаёт сигнал компрессору прекратить нагнетание, когда давление в ресивере достигает точки отключения около 125 psi","Он автоматически стравливает воздух из ресиверов, если давление превысит уставку предохранительного клапана около 150 psi","Он впрыскивает дозированное количество спирта в магистрали, чтобы тормозные клапаны не обмерзали в холодную погоду"],"explanation":"Осушитель воздуха удаляет водяной пар и часть масла из сжатого воздуха до его поступления в ресиверы, снижая влагу, которая могла бы замёрзнуть и отказать тормоза."},"43":{"q":"Во время предрейсового осмотра я залезаю под прицеп, чтобы осмотреть колесные тормозные механизмы. На каждом колесе я нахожу тормозной барабан, тормозные колодки с накладками и регулировочный рычаг, соединенный со штоком, который поворачивает деталь в форме буквы 'S', раздвигающую колодки. Исходя из того, что я вижу, каким типом колесного тормоза оборудовано это транспортное средство — типом, который встречается на большинстве тяжелых машин с пневматическими тормозами?","options":["Дисковые пневматические тормоза, где суппорт сжимает диск — самая распространенная конструкция на тяжелых грузовиках","Барабанные тормоза с S-образным кулачком — самый распространенный колесный тормоз на тяжелых машинах с пневмоприводом","Клиновые барабанные тормоза, где клин раздвигает колодки через одну камеру","Гидравлические дисковые тормоза, как на легковом автомобиле, но увеличенные для прицепа"],"explanation":"Барабанные тормоза с S-образным кулаком — самый распространённый рабочий тормоз на тяжёлых машинах с пневмоприводом, узнаваемый по S-образному кулаку, который шток поворачивает, разводя колодки."},"45":{"q":"Я веду гружёный тягач с прицепом на пневматических (воздушных) тормозах, и впереди резко останавливается легковой автомобиль. В тот момент, когда я полностью выжимаю педаль тормоза, проходит короткая задержка, прежде чем грузовик действительно начинает замедляться. Мой инструктор называет это «запаздыванием тормозов» (brake lag). Что физически происходит во время этой задержки?","options":["Мой мозг и тело ещё обрабатывают опасность, пока нога не дошла до педали","Компрессор нагнетает дополнительное давление в ресиверы, чтобы обеспечить запрос","Сжатый воздух проходит по тормозным магистралям, прежде чем сможет привести в действие тормоза","Машина проезжает расстояние восприятия, пока ещё не начато торможение"],"explanation":"После нажатия педали сжатому воздуху требуется около полусекунды, чтобы пройти по тормозным магистралям и фактически привести в действие тормоза на каждом колесе."},"46":{"q":"Я готовлюсь к экзамену CDL по пневматическим тормозам и изучаю общий тормозной путь. С гидравлическими тормозами легкового автомобиля общий тормозной путь — это путь восприятия плюс путь реакции плюс путь торможения. Мой инструктор говорит, что пневматические тормоза добавляют к этому ещё один компонент. Какой компонент добавляет пневматическая система, которого НЕТ у гидравлических тормозов?","options":["Дополнительный путь реакции, потому что педаль пневматических тормозов тяжелее и нажимается медленнее, чем гидравлическая","Дополнительный путь восприятия, потому что крупные пневматические транспортные средства выше и опасность дольше оценивать","Больший эффективный путь торможения, потому что пневматические транспортные средства тяжелее и им нужно больше места для остановки","Путь запаздывания тормозов — расстояние, пройденное, пока воздух проходит по магистралям, прежде чем тормоза сработают"],"explanation":"Пневмотормоза добавляют четвёртую составляющую остановочного пути — путь запаздывания тормозов — за те примерно полсекунды, пока воздух проходит по магистралям до срабатывания тормозов."},"47":{"q":"Вы завершили предрейсовый осмотр, и воздушная система полностью заряжена. Теперь вы хотите убедиться, что рабочие (служебные) тормоза действительно останавливают грузовик и что ничего не заедает и не уводит в сторону. Какой из следующих способов является правильным для проверки остановки рабочими тормозами?","options":["Отпустите стояночный тормоз, дайте грузовику медленно тронуться примерно до 5 миль/ч, затем уверенно нажмите на педаль тормоза и почувствуйте, останавливается ли он быстро и прямо","Удерживая грузовик на месте, сильно нажмите на педаль тормоза и следите за манометром, чтобы убедиться, что давление не падает более чем на 3 psi за одну минуту","Стоя на месте, несколько раз вытяните и отпустите жёлтую кнопку стояночного тормоза, чтобы убедиться, что пружинные тормоза срабатывают и отпускаются","Разгонитесь примерно до 20 миль/ч, затем резко затормозите и проверьте, что колёса блокируются равномерно с обеих сторон"],"explanation":"Проверка рабочих тормозов выполняется в движении: дайте машине разогнаться примерно до 5 миль/ч, затем твёрдо нажмите на тормоз и убедитесь, что она останавливается быстро и без увода в сторону."},"48":{"q":"Во время предрейсового осмотра инструктор по CDL велит мне взяться рукой за один из регуляторов тормозов и потянуть его, чтобы проверить, насколько далеко перемещается шток до срабатывания тормозов. Он говорит, что если здесь слишком большой свободный ход, моя тормозная сила снижается. Какой компонент я на самом деле проверяю, делая это?","options":["Регулятор (губернатор) воздушного компрессора, который определяет, когда система прекращает и возобновляет нагнетание воздуха","Регулировочный рычаг (slack adjuster), который задает, насколько далеко перемещается шток тормоза до срабатывания тормозов","Предохранительный клапан, который открывается для сброса давления при перекачке воздуха в баках","Модулирующий управляющий клапан, который позволяет мне постепенно задействовать пружинные тормоза в экстренной ситуации"],"explanation":"Регулировочный рычаг задаёт, насколько далеко проходит шток тормоза до его срабатывания, а чрезмерный свободный ход — нерегулированные тормоза — самый частый дефект пневмотормозов."},"49":{"q":"Во время предрейсового осмотра в морозную погоду я замечаю, что воздушные ресиверы моего грузовика сами выпускают скопившуюся воду и масло, и мне не нужно ничего открывать вручную. В мастерской говорят, что этот ресивер оборудован так, чтобы слив происходил самостоятельно и предотвращал замерзание. Какое устройство выполняет эту работу?","options":["Ускорительный (релейный) клапан, который ускоряет подачу воздуха к задним тормозам, но при этом сам удаляет влагу из ресивера","Ручной сливной клапан, который автоматически выпускает скопившуюся воду и масло, как только давление в ресивере становится достаточно высоким","Автоматический сливной клапан, который выпускает воду и компрессорное масло из ресивера без ручного слива кем-либо","Предохранительный клапан, который открывается около 150 psi и удаляет скопившуюся воду и масло из питающего ресивера при стравливании"],"explanation":"Автоматический сливной клапан сам удаляет скопившуюся воду и масло компрессора из ресивера без ручного слива, что помогает предотвратить замерзание в холодную погоду."},"50":{"q":"Во время предрейсового осмотра нового сцепленного транспортного средства я замечаю, что на манометре давления воздуха две стрелки вместо одной, и грузовик не дает мне нормально набрать давление, пока оба показания не поднимутся. Мой инструктор говорит, что у этой машины двойная пневматическая тормозная система. Какое утверждение верно описывает, как на самом деле устроена эта двойная система?","options":["Это одна большая пневматическая система, питаемая от одного резервуара, а вторая стрелка манометра лишь показывает давление прицепа в качестве справочной информации.","Она объединяет рабочие, стояночные и аварийные тормоза в одну общую воздушную магистраль, так что все три работают от одного источника давления.","Это одна пневматическая система с резервным компрессором, который включается только после полного отказа основного компрессора.","Это две полностью раздельные пневматические системы, основная и вторичная, управляемые одним комплектом тормозных органов управления для повышенной безопасности."],"explanation":"Двухконтурная пневмотормозная система состоит из двух полностью раздельных контуров — основного и вспомогательного — каждый со своими ресиверами и магистралями, но управляемых одним набором органов для резервной безопасности."},"51":{"q":"Я веду тягач с прицепом, оснащённый двойной пневматической тормозной системой, когда внезапно срабатывает предупреждение о низком давлении воздуха только для первичного контура, и стрелка манометра этой стороны падает к нулю. Манометр вторичной системы по-прежнему показывает значение в нормальном диапазоне. Какое утверждение лучше всего описывает, чего мне ожидать и что делать?","options":["Вторичная система продолжит управлять тормозами, поэтому мне следует безопасно затормозить до остановки, учитывая увеличенный тормозной путь, а затем отремонтировать грузовик.","Поскольку оба контура используют один набор органов управления, вторичная система откажет вместе с первичной, поэтому у меня не останется тормозов и придётся катиться до остановки.","Мне следует быстро нажимать на педаль тормоза, чтобы заставить рабочий контур подать воздух ко всем колёсам и восстановить полное давление на отказавшей стороне.","Пружинные тормоза мгновенно заблокируют все колёса в момент отказа одного контура, поэтому мне следует приготовиться к немедленной резкой остановке."],"explanation":"Если один контур двухконтурной пневмосистемы отказывает, второй всё ещё управляет тормозами, поэтому тормозите до контролируемой остановки с учётом увеличенного тормозного пути, а затем отремонтируйте машину."},"52":{"q":"Я провожу предрейсовый осмотр своего тягача с прицепом, двигатель заглушен. Пока давление в системе медленно падает, я смотрю на манометр: стрелка проходит отметку 60 psi и продолжает опускаться к 30 psi. Внезапно пружинные (стояночные) тормоза срабатывают сами, хотя я не трогал орган управления стояночным тормозом. Какое утверждение ЛУЧШЕ всего объясняет, почему пружинные тормоза до этого момента оставались отпущенными?","options":["Их механически удерживали разжатыми регулировочные рычаги (трещотки), пока не исчерпался ход штока","Сжатые мощные пружины удерживались сжатым воздухом, и потеря давления позволила пружинам привести тормоза в действие","Они удерживались отпущенными жёлтой ромбовидной кнопкой стояночного тормоза, пока их не освободил зуммер низкого давления","Их удерживала отпущенными нажатая педаль рабочего тормоза, и они сработали только когда давление на педаль ослабло"],"explanation":"Давление воздуха удерживает мощные пружинные тормоза в отпущенном положении, поэтому при падении давления ниже диапазона 20-45 psi пружины автоматически приводят тормоза в действие."},"53":{"q":"При предрейсовом осмотре пружинные (стояночные) тормоза не отпускаются, и я подозреваю механическую неисправность в камере пружинного тормоза. Напарник даёт мне инструмент и говорит, что мощные пружины можно вручную 'зажать' (сжать), чтобы я мог перегнать грузовик в мастерскую. Я никогда не проходил обучение этой процедуре. Каково правильное действие?","options":["Зажать пружины самому всего один раз, ведь грузовику нужно проехать совсем короткое расстояние до мастерской","Многократно отпускать и снова применять пружинные тормоза вручную, чтобы постепенно расходить заклинившую камеру","Не трогать пружины и не пытаться их зажимать, потому что зажатие этих мощных пружин должно выполняться только обученным персоналом","Сначала покрасить камеры пружинного тормоза в яркий цвет, чтобы сильные пружины было хорошо видно во время зажатия"],"explanation":"Зажим (caging) пружинных тормозов опасен, так как пружины накапливают огромную силу, поэтому это должны выполнять только обученные специалисты."},"54":{"q":"Я закончил предрейсовый осмотр и проверяю пневматические тормоза перед выездом с площадки. Двигатель работает, давление воздуха набрано полностью. Я ставлю стояночный тормоз, вытягивая желтую ромбовидную кнопку. Теперь я хочу убедиться, что пружинные тормоза действительно удержат машину на месте. Какое действие правильно это проверяет?","options":["Отпустить стояночный тормоз и сильно нажать на педаль рабочего тормоза, чтобы почувствовать упругость педали","Несколько раз прокачать педаль тормоза и следить за манометром на предмет падения давления","Прибавить обороты двигателя и слушать, как пружинные тормоза отпускают примерно при 20-45 psi","Оставить стояночный тормоз включенным, отпустить сцепление и осторожно двинуться вперед, упираясь в него"],"explanation":"Чтобы проверить стояночные (пружинные) тормоза, держите их включёнными и осторожно тронитесь вперёд на низкой передаче, убедившись, что они удерживают машину."},"55":{"q":"Я везу гружёный автопоезд вниз по длинному крутому горному спуску и беспокоюсь о том, чтобы сохранить контроль над пневматическими тормозами. Какой приём мне следует использовать, чтобы безопасно управлять скоростью до самого подножия?","options":["Включить пониженную передачу перед спуском и применять лёгкое, ровное торможение, отпуская педаль, когда скорость упадёт примерно на 5 миль/ч ниже безопасной","Применять сильное, непрерывное нажатие на тормоз всю дорогу вниз, чтобы удерживать скорость стабильно низкой и под контролем","Нажимать и отпускать педаль тормоза повторяющимися рывками, чтобы тормоза успевали остывать между нажатиями","Переключиться на нейтраль, чтобы сберечь двигатель, и позволить тормозам выполнять всё замедление по мере необходимости на спуске"],"explanation":"На спуске выберите низкую передачу и применяйте лёгкое равномерное торможение, отпуская тормоз, когда скорость упадёт примерно на 5 миль/ч ниже безопасной."},"56":{"q":"Я еду по техасскому шоссе на грузовике с пневматическими тормозами на обычной скорости и сильно нажимаю ногой на педаль (тормозной кран), чтобы притормозить в потоке. Какую тормозную систему я задействую этой педалью?","options":["Стояночные тормоза, которые удерживаются отпущенными воздухом и включаются жёлтой кнопкой","Рабочие тормоза, которые я использую для обычного замедления и остановки","Аварийные тормоза, которые срабатывают автоматически при низком давлении воздуха","Только тормоза прицепа, управляемые отдельно ручным краном прицепа"],"explanation":"Педаль тормоза (тормозной кран) управляет рабочими тормозами, которые используются для всех обычных замедлений и остановок."},"57":{"q":"Во время предрейсового осмотра я проверяю тормозные барабаны и диски на своём тягаче. Какое состояние означает, что барабан или диск опасен и на этом транспортном средстве НЕЛЬЗЯ ехать, пока его не отремонтируют?","options":["Барабан холодный на ощупь и без следов масляной плёнки","На внешней поверхности есть лёгкий налёт дорожной пыли","На барабане видна трещина или его поверхность сильно изношена","На барабане видна свежая краска после недавнего обслуживания в мастерской"],"explanation":"Тормозной барабан с трещиной или сильным износом может разрушиться под нагрузкой и нагревом, поэтому машину нужно вывести из эксплуатации до ремонта."},"58":{"q":"Во время предрейсового осмотра вы накачиваете пневмосистему примерно до 125 psi, глушите двигатель и следите за манометром на панели. При отпущенных тормозах стрелка продолжает падать, значительно превышая допустимую скорость утечки, и не показывает признаков остановки. Сигнал низкого давления воздуха ещё не загорелся. Каково правильное действие?","options":["Запустить двигатель и ехать как обычно, ведь предупреждающий свет и зуммер ещё не сработали","Несколько раз нажать на педаль тормоза, чтобы клапаны снова сели, и продолжить маршрут по плану","Ехать прямо в ближайшую ремонтную мастерскую, пока давление держится выше 60 psi","Снять автомобиль с эксплуатации и устранить утечку до того, как куда-либо ехать"],"explanation":"Непрекращающаяся утечка воздуха сверх допустимой нормы может опустошить ресиверы и отключить тормоза, поэтому машину нужно вывести из эксплуатации до ремонта."},"59":{"q":"Я еду по шоссе на своём тягаче с прицепом, и вдруг на приборной панели загорается и не гаснет жёлтая лампа неисправности ABS (антиблокировочной системы). Грузовик при этом тормозит и управляется нормально. Исходя из того, о чём предупреждает эта лампа, какое утверждение является НАИБОЛЕЕ точным?","options":["Моя антиблокировочная система, возможно, не работает, но обычные рабочие тормоза по-прежнему функционируют, и мне следует проверить ABS.","Мои рабочие тормоза уже отказали, поэтому я должен немедленно съехать на обочину и поставить машину на стояночный тормоз.","Моя ABS полностью включена и активно сокращает мой тормозной путь на этом участке дороги.","Давление воздуха упало ниже 60 psi, и пружинные тормоза вот-вот заблокируют колёса."],"explanation":"Загоревшийся жёлтый индикатор ABS означает, что не работает только антиблокировочная функция; обычные рабочие тормоза действуют, а ABS нужно проверить."},"60":{"q":"Я веду гружёный составной грузовик по длинному маршруту и постоянно слежу за приборами на панели. Чтобы мои пневматические (воздушные) тормоза действительно срабатывали и отпускались каждый раз, когда я нажимаю на педаль, какое ОДНО условие я должен поддерживать на протяжении всей поездки?","options":["Полный топливный бак, поскольку тормоза получают энергию напрямую от подачи топлива в двигатель","Достаточное давление воздуха в системе, поскольку именно воздух приводит в действие и отпускает тормоза","Включённый ближний свет фар, чтобы датчики предупреждения о тормозах могли считывать приборы при дневном свете","Хотя бы одного пассажира в кабине, чтобы подтверждать работу стоп-сигналов на каждой остановке"],"explanation":"Пневматической тормозной системе нужно достаточное давление воздуха, потому что именно сжатый воздух включает и отпускает тормоза."},"61":{"q":"Во время предрейсового осмотра я даю воздушной системе зарядиться до отключения регулятора (cut-out), затем держу обороты двигателя на рабочем уровне и слежу, как стрелка манометра поднимается с 85 до 100 psi. Какое из следующих наблюдений говорит о том, что воздушный компрессор исправен, а скорость нарастания давления приемлема?","options":["Стрелка несколько долгих минут медленно ползёт с 85 до 100 psi, но в конце концов доходит","Давление вообще не меняется, потому что регулятор уже отключил компрессор","Стрелка поднимается с 85 до 100 psi примерно за 45 секунд, то есть за секунды, а не за минуты","Давление мгновенно подскакивает с 85 до 100 psi, как только я нажимаю на акселератор"],"explanation":"В двухконтурной пневмосистеме давление должно подняться с 85 до 100 psi примерно за 45 секунд, что говорит об исправном компрессоре, быстро восстанавливающем воздух."},"62":{"q":"Во время предрейсового осмотра я залезаю под прицеп и замечаю, что тормозные накладки на одном колесе износились настолько тонко, что почти сравнялись с заклёпками. Всё остальное в тормозной системе в порядке. Какое из перечисленных действий является правильным, прежде чем я выеду на этом транспортном средстве на дорогу?","options":["Оставить накладки как есть, поскольку ход штока и регулировочные рычаги (трещотки) по-прежнему укладываются в допустимый предел","Нанести тонкий слой тормозной жидкости на тонкие накладки, чтобы уменьшить скрип до ближайшей мастерской","Отметить это в отчёте об осмотре, но продолжать движение, пока сигнал низкого давления остаётся выше 60 psi","Снять транспортное средство с эксплуатации и заменить изношенные накладки на новые перед поездкой"],"explanation":"Слишком изношенные тормозные накладки уже не создают достаточного трения, поэтому их нужно заменить до того, как машина поедет."},"63":{"q":"Я везу гружёный прицеп вниз по длинному горному спуску. Чтобы сдерживать скорость, я снова и снова нажимаю и отпускаю педаль тормоза («подкачиваю» тормоза). Инструктор предупреждает меня прекратить так делать. Какова ГЛАВНАЯ причина, по которой такая «подкачка» опасна на длинном спуске?","options":["Это может расходовать воздух быстрее, чем компрессор успевает его накачивать, опустошая запас","Это слишком быстро охлаждает тормозные барабаны и может растрескать накладки от теплового удара","Это нагнетает лишний воздух в питающий бак прицепа и перегружает предохранительный клапан","Это заставляет регулировочные рычаги затягиваться, и ход штока становится слишком коротким"],"explanation":"Многократное «качание» тормозов выпускает воздух при каждом нажатии быстрее, чем компрессор успевает его восстановить, истощая запас воздуха."},"64":{"q":"Я только что пересел с легкового автомобиля на тягач с полуприцепом, оснащённый пневматической (воздушной) тормозной системой. Когда я нажимаю на педаль тормоза, я пытаюсь представить, что именно проходит по магистралям, чтобы прижать тормозные колодки к барабанам и замедлить машину. В этой пневматической тормозной системе усилие, которое я создаю на педали, передаётся к колёсам с помощью какой среды?","options":["Тормозная жидкость под давлением, вытесняемая из главного цилиндра, как в моём автомобиле","Сжатый воздух, хранящийся в баллонах и подаваемый по магистралям в тормозные камеры","Тяжёлый стальной трос и механическая тяга, натягиваемые от педали к каждому колесу","Электрический ток, идущий по проводу и питающий тормозной электромагнит на каждом колесе"],"explanation":"Пневматические тормоза передают усилие сжатым воздухом, который хранится в баллонах и подаётся по тормозным магистралям в камеры."},"65":{"q":"Я веду гружёный грузовик с пневматическими (воздушными) тормозами, когда лопается магистраль и давление воздуха падает до нуля. Стажёр в кабине спрашивает, почему такая система считается безопаснее гидравлических тормозов его пикапа. Какое утверждение ЛУЧШЕ всего объясняет реальное преимущество в безопасности моей пневмосистемы именно в этой ситуации?","options":["Поскольку рабочей средой является воздух, мои рабочие тормоза продолжат работать как обычно даже после того, как весь воздух вытечет из системы.","Именно зуммер предупреждения о низком давлении физически останавливает грузовик, как только давление падает ниже 60 psi.","Когда давление воздуха падает в диапазон 20–45 psi, пружинные (аварийные) тормоза срабатывают автоматически и останавливают грузовик.","Пневматические тормоза по конструкции всегда останавливают гружёный грузовик на меньшем расстоянии, чем гидравлические, независимо от любой утечки."],"explanation":"Когда давление воздуха падает до диапазона 20–45 psi, пружинные (аварийные) тормоза срабатывают автоматически и останавливают машину."},"66":{"q":"Я еду по шоссе на гружёном тягаче с прицепом, когда лопается магистраль и давление воздуха полностью падает. По мере того как система опустошается, что произойдёт с моими пружинными (стояночными) тормозами?","options":["С ними ничего не произойдёт, потому что пружинные тормоза работают как рабочие тормоза, только когда я нажимаю на педаль","Они останутся отпущенными, потому что мощным пружинам нужно запасённое давление воздуха, чтобы удерживать их в сжатом положении","Они полностью отпустятся, потому что потеря воздуха как раз и освобождает пружины, позволяя машине катиться","Они сработают автоматически, потому что пружины зажимают тормоза, как только пропадает воздух, удерживавший их отпущенными"],"explanation":"Пружинные тормоза удерживаются в отпущенном положении давлением воздуха, поэтому при его потере пружины автоматически зажимают тормоза — это безотказная защита."},"67":{"q":"Я выполняю проверку тормозов при выключенном двигателе и полностью заряженной системе. Я снова и снова нажимаю и отпускаю педаль тормоза, чтобы стравить воздух из ресиверов, и слежу за манометром. Пока стрелка продолжает падать, при каком примерно давлении клапан защиты тягача должен автоматически закрыться и отключить подачу воздуха к прицепу?","options":["Примерно от 20 до 45 psi, когда давление опускается в нижний диапазон","Примерно от 60 до 80 psi, как раз когда активно предупреждение о низком давлении","Примерно от 100 до 125 psi, около нормального рабочего диапазона регулятора","Примерно от 5 до 10 psi, только когда манометр почти показывает ноль"],"explanation":"Защитный клапан тягача и подача воздуха к прицепу закрываются автоматически, когда давление в системе падает до диапазона 20–45 psi."},"68":{"q":"Я сцеплен с гружёным прицепом и завершаю предрейсовый осмотр, находясь в кабине. Чтобы зарядить пневмосистему прицепа и растормозить его перед началом движения, мне нужно нажать одну конкретную кнопку на панели. Какого цвета и формы кнопка, которую я должен нажать, чтобы подать воздух в прицеп?","options":["Жёлтая кнопка в форме ромба, потому что именно она подаёт воздух к тормозам прицепа","Красная восьмиугольная (восьмигранная) кнопка, потому что это управление подачей воздуха в прицеп","Синяя круглая кнопка, потому что рабочая магистраль прицепа кодируется синим цветом","Жёлтая восьмиугольная (восьмигранная) кнопка, потому что подача воздуха в прицеп повторяет форму управления стояночным тормозом"],"explanation":"Управление подачей воздуха к прицепу — это красная восьмиугольная кнопка, которая заряжает пневмосистему прицепа и растормаживает его."},"69":{"q":"Я закончил парковку своего тягача с прицепом на стоянке для отдыха и собираюсь заглушить двигатель. Чтобы включить стояночный (пружинный) тормоз и удержать машину на месте, какой орган управления на панели мне нужно вытянуть?","options":["Синюю круглую кнопку, которая сбрасывает давление рабочего тормоза","Красную восьмиугольную (восьмигранную) ручку рядом с приборами на панели","Жёлтую ручку ромбовидной формы на панели управления","Зелёный квадратный рычаг рядом с ручным краном прицепа"],"explanation":"Управление стояночным (пружинным) тормозом — это жёлтая кнопка в форме ромба: её вытягивают для затормаживания и вдавливают для растормаживания."},"70":{"q":"Во время предрейсового осмотра двигатель глохнет и компрессор перестает вращаться, но я замечаю, что мой питающий ресивер удерживает давление, а не стравливает его обратно к заглохшему компрессору. Какой компонент отвечает за такое поведение?","options":["Предохранительный клапан, который запирает воздух в ресивере, как только распознает, что компрессор остановился","Регулятор (губернатор), который перекрывает питающий ресивер, как только достигается давление отключения","Автоматический сливной клапан, который плотно закрывается и запирает накопленный воздух внутри ресивера","Обратный клапан одностороннего действия, который не дает воздуху выходить обратно к остановившемуся компрессору"],"explanation":"Обратный клапан пропускает воздух только в баллон, поэтому он не даёт накопленному воздуху уходить обратно, когда компрессор останавливается."},"71":{"q":"Морозным январским утром в Амарилло диспетчер сообщает мне, что мой тягач оснащён спиртовым испарителем в пневматической тормозной системе. Во время предрейсового осмотра меня спрашивают, что именно даёт мне это устройство в таких условиях. Какое утверждение ЛУЧШЕ всего объясняет его назначение?","options":["Оно подаёт спирт в пневмосистему, чтобы снизить вероятность образования льда в магистралях и клапанах в холодную погоду","Оно сжигает спирт, чтобы нагреть тормозные барабаны, и стояночные тормоза не примёрзли в холод","Оно добавляет спирт в воздух для поглощения влаги, поэтому мне больше не нужно ежедневно сливать конденсат из ресиверов","Оно выпускает пары спирта, повышая производительность компрессора, чтобы давление росло быстрее в холод"],"explanation":"Спиртовой испаритель подаёт спирт в пневмосистему, чтобы снизить вероятность образования льда в магистралях и клапанах в холодную погоду."},"72":{"q":"Во время предрейсового осмотра я прослеживаю узел колодочного (фундаментного) тормоза на одном из колёс моего тягача с пневматическими тормозами. При нажатии на тормоз я вижу, как регулятор зазора (slack adjuster) поворачивает вал, который вращает S-образный кулачок, и тот раздвигает тормозные колодки с накладками наружу к внутренней поверхности барабана. Проверяя наличие и работу каждой детали, какой из перечисленных элементов я НЕ должен ожидать найти в этом S-кулачковом фундаментном тормозе?","options":["Регулятор зазора, который преобразует ход штока в поворот тормозного кулачка","Гидравлический главный тормозной цилиндр, который создаёт давление жидкости, чтобы раздвинуть колодки","Тормозной барабан, к которому прижимаются колодки, создавая тормозящее трение","Тормозные колодки с накладками, которые при торможении прижимаются к барабану"],"explanation":"Барабанный тормоз с S-образным кулаком на пневматике чисто механо-пневматический и не содержит жидкости, поэтому в нём нет гидравлического главного цилиндра."},"73":{"q":"Я везу гружёный прицеп вниз по длинному крутому спуску, когда рабочие тормоза слабеют и педаль становится мягкой. Мой тягач оснащён модулирующим управляющим клапаном. Что в этой ситуации этот клапан фактически позволяет мне сделать?","options":["Многократно прокачивать рабочие тормоза, чтобы восстановить давление воздуха в магистралях до их полного отказа","Обойти регулятор, чтобы компрессор отключался выше 125 psi и восстановил тормозное усилие","Плавно задействовать пружинные (аварийные) тормоза рукояткой управления вместо их резкого срабатывания целиком","Отключить ABS, чтобы колёса заблокировались и быстрее гасили скорость на спуске"],"explanation":"Модулирующий управляющий клапан позволяет плавно включать пружинные (аварийные) тормоза рукояткой управления для контролируемой остановки при отказе рабочих тормозов."},"74":{"q":"Я веду гружёный одиночный грузовик и замечаю, что загорелась лампа низкого давления воздуха и зазвучал зуммер. При предрейсовом осмотре я раньше заметил небольшую утечку воздуха, которую счёл незначительной. По сравнению с тем, как вела бы себя гидравлическая тормозная система при такой же небольшой утечке, чего мне сейчас ожидать от пневматических тормозов?","options":["Тормоза полностью откажут в тот же миг, как только начнётся утечка, точно как в гидравлической системе, и пригодного торможения не останется","Потеря давления воздуха вообще не даёт предупреждения, поэтому лампа и зуммер, должно быть, сигнализируют о какой-то другой, не связанной неисправности","Утечку невозможно толком подтвердить во время движения, поэтому стоит продолжать ехать на скорости, пока не остановлюсь и не осмотрю магистрали","Тормоза продолжают работать, пока остаётся давление воздуха, а предупреждение говорит мне безопасно остановиться, пока давление не упало слишком низко"],"explanation":"Воздушные тормоза работают, пока в баках есть пригодное давление, а предупреждение о низком давлении должно сработать до падения ниже 60 psi, чтобы вы успели безопасно остановиться."},"75":{"q":"Я выполняю проверку пневматических тормозов в рамках предрейсового осмотра одиночного тягача. Я уже слил конденсат из ресиверов и поднял давление до отключения регулятора (cut-out). Прежде чем выехать со двора, какой набор тормозных функций я обязан ещё подтвердить как реально работающий, чтобы завершить осмотр пневмотормозов?","options":["Звуковое/световое предупреждение о низком давлении, пружинные (стояночные) тормоза и рабочие тормоза","Только пружинные (стояночные) и рабочие тормоза, так как предупреждение само тестируется при запуске","Только предупреждение о низком давлении и рабочие тормоза, так как пружинные тормоза срабатывают автоматически","Только рабочие тормоза, ведь твёрдая педаль на скорости 5 миль/ч доказывает исправность всей системы"],"explanation":"Полная проверка воздушных тормозов должна подтвердить три вещи: предупреждение о низком давлении, пружинные (стояночные) тормоза и рабочие тормоза."},"76":{"q":"Я только что купил грузовик-одиночку с пневматическими (воздушными) тормозами, и у меня уже есть действующий CDL, который я получил на автомобиле с гидравлическими тормозами. Прежде чем я смогу легально управлять этим грузовиком с воздушными тормозами, какой дополнительный шаг требует от меня штат Техас, который НЕ применялся к моему прежнему автомобилю с гидравлическими тормозами?","options":["Ничего дополнительно — мой нынешний CDL уже охватывает любую тормозную систему, поэтому я могу ехать как есть","Я должен сдать тест на воздушные тормоза (без ограничения), иначе в моих правах будет стоять ограничение на воздушные тормоза","Мне нужно лишь добавить категорию Class C, чтобы соответствовать меньшему размеру грузовика","Я должен получить отдельное мотоциклетное подтверждение (endorsement), прежде чем управлять любой техникой с воздушными тормозами"],"explanation":"Нужно сдать тест на знания и навыки по воздушным тормозам, иначе на права наложат ограничение, запрещающее управлять транспортом с воздушными тормозами."},"77":{"q":"Я везу гружёный прицеп по мокрой автомагистрали, когда передо мной перестраивается машина и резко тормозит. Я с силой жму на педаль тормоза, и на моём тягаче с прицепом срабатывает антиблокировочная система (ABS). В этот момент резкого торможения чего мне реально стоит ожидать от ABS?","options":["Резко сократит мой общий тормозной путь, так что я остановлюсь намного раньше идущей впереди машины","Сама автоматически задействует тормоза ещё до того, как я нажму на педаль","Не даст колёсам заблокироваться, чтобы я мог рулить в объезд опасности, продолжая сильно тормозить","Возьмёт на себя роль основных рабочих тормозов, как только педаль будет нажата до упора"],"explanation":"ABS не дает колесам заблокироваться при резком торможении, благодаря чему вы сохраняете управление и можете объехать препятствие."},"78":{"q":"Я веду одиночный грузовик с одноконтурной пневматической тормозной системой, и на тихом участке шоссе глохнет двигатель. Накатом съезжая на обочину, я слежу за манометром давления воздуха, понимая, что давление будет медленно падать, ведь компрессор больше не работает. Примерно при каком давлении я ВПЕРВЫЕ должен ожидать срабатывания предупреждения о низком давлении воздуха (лампа и зуммер), сигнализирующего о том, что я теряю запас воздуха?","options":["Около 100 psi — точка, при которой регулятор обычно снова включает компрессор","Около 125 psi — точка, при которой регулятор обычно отключает компрессор","Около 30 psi — когда пружинные тормоза вот-вот сработают автоматически","Около 60 psi — задолго до того, как давление станет опасно низким"],"explanation":"Предупреждение о низком давлении воздуха должно срабатывать примерно при 60 psi, задолго до опасно низкого уровня."},"79":{"q":"Я провожу предрейсовый осмотр и пытаюсь представить, что на самом деле приводит в действие мои пневматические (воздушные) тормоза, когда я нажимаю на педаль. Если двигатель, приборы и магистрали исправны, мои воздушные тормоза будут останавливать грузовик до тех пор, пока остаётся достаточным что из перечисленного?","options":["Давление воздуха, накопленное и хранящееся в ресиверах (баллонах)","Гидравлическая тормозная жидкость в главном тормозном цилиндре","Давление моторного масла, питающее тормозной контур","Заряд 12-вольтовой аккумуляторной батареи, питающей тормозные клапаны"],"explanation":"Воздушные тормоза срабатывают и удерживаются за счет сжатого воздуха, накопленного и хранящегося в баках, а не жидкости."},"80":{"q":"Во время предрейсового осмотра я прослеживаю механизм пневматического барабанного тормоза. Я иду по пути от тормозной камеры через шток к регулировочному рычагу (slack adjuster), который поворачивает вал у колеса. На конце этого вала я нахожу S-образную деталь (S-кулачок) между двумя тормозными колодками. Когда я нажимаю на тормоз, какое действие является ПОСЛЕДНИМ механическим звеном, которое реально прижимает колодки к барабану, замедляя колесо?","options":["Шток выдвигается из тормозной камеры и напрямую прижимает тормозные колодки к барабану","S-кулачок поворачивается и разводит тормозные колодки, прижимая их накладки к внутренней поверхности барабана","Гидравлическая жидкость из главного цилиндра толкает колесный поршень, который прижимает колодки к барабану","Регулировочный рычаг сжимает пару колодок на тормозном диске, установленном на ступице колеса"],"explanation":"Давление воздуха перемещает шток и регулятор зазора, поворачивая S-кулак, который раздвигает тормозные колодки, прижимая накладки к внутренней поверхности барабана."},"81":{"q":"Во время предрейсового осмотра я замечаю, что на раме моего тягача установлено несколько металлических баллонов, отдельно от двигателя и топливной системы. Новичок спрашивает меня, для чего на самом деле нужны эти питающие (накопительные) ресиверы в системе пневматических тормозов. Какой ответ правильно объясняет их назначение?","options":["Они вырабатывают и нагнетают воздух, беря на себя работу насоса всякий раз, когда компрессор достигает отсечки регулятора около 125 psi","Они удаляют воду и масло из воздуха, поэтому магистрали никогда не нужно сливать в конце дня","Они хранят запас сжатого воздуха, чтобы всегда было достаточно давления для работы тормозов","Они определяют низкое давление и включают сигнальную лампу и зуммер до того, как давление упадёт ниже примерно 60 psi"],"explanation":"Ресиверы хранят запас сжатого воздуха, чтобы всегда было достаточно давления для работы рабочих, стояночных и аварийных тормозов."},"82":{"q":"Я веду гружёный одиночный грузовик, когда лопается основная воздушная магистраль. Стрелка манометра неуклонно падает, лампа и зуммер низкого давления уже сработали, а я не касаюсь педали тормоза. По мере дальнейшего падения давления что заставляет мой грузовик остановиться самостоятельно?","options":["Рабочие тормоза сами срабатывают через ножной клапан, как только стрелка проходит точку отключения регулятора","Предохранительный клапан стравливает систему, что механически прижимает рабочие тормоза к барабанам","Цепь предупреждения о низком давлении задействует тормоза в тот же миг, когда загораются лампа и зуммер","Пружинные тормоза срабатывают автоматически, как только падающее давление достигает низкого диапазона, где в действие вступают пружины"],"explanation":"Пружинные тормоза удерживаются отпущенными воздухом, поэтому при падении давления из-за утечки в низкий диапазон (около 20-45 psi) пружины автоматически включают тормоза."},"84":{"q":"Во время рейса с доставкой внезапно загорается сигнальная лампа низкого давления воздуха, и я замечаю, что один из двух манометров давления воздуха быстро падает, а второй держится стабильно. На моём тягаче двухконтурная пневматическая тормозная система. Какое утверждение ЛУЧШЕ объясняет, почему у меня сейчас всё ещё есть некоторая тормозная способность?","options":["Система разделена на два отдельных контура, поэтому потеря давления в отказавшем контуре не выводит из строя контур, который всё ещё держит давление","Оба контура питаются из одного большого общего ресивера, поэтому стабильный манометр подаёт воздух обратно в отказавшую сторону","Гидравлический резервный тормоз автоматически включается всякий раз, когда один пневмоконтур теряет давление","Двухконтурная система убирает стояночный тормоз, поэтому весь оставшийся воздух направляется к рабочим тормозам"],"explanation":"Двухконтурная пневматическая тормозная система имеет два независимых контура, поэтому утечка или отказ одного контура не разряжает другой, который сохраняет давление и тормозит свою часть автомобиля."},"85":{"q":"Я только что завел двигатель тягача с прицепом на холодной стоянке. Сигнальная лампа низкого давления воздуха погасла, но манометр все еще показывает только 65 psi, когда я собираюсь выехать с парковки. Согласно процедуре Техасского DPS, до какого НАИМЕНЬШЕГО давления следует дать воздуху накачаться, прежде чем начинать движение?","options":["65 psi, потому что сигнальная лампа низкого давления воздуха уже погасла","Около 100 psi, чтобы воздуха хватало для безопасной работы тормозов","Около 60 psi — точка, при которой гаснет сигнал низкого давления воздуха","Около 125 psi — отсечка регулятора, перед тем как отпустить стояночный тормоз"],"explanation":"Перед началом движения дайте давлению воздуха подняться как минимум примерно до 100 psi, чтобы хватало воздуха для безопасной работы рабочих и аварийных тормозов."},"86":{"q":"Во время предрейсового осмотра одиночного грузовика (прямой грузовик) я накачиваю пневмосистему примерно до 125 psi, глушу двигатель и подкладываю упоры под колёса. Я оставляю кнопку стояночного тормоза нажатой, чтобы тормоза оставались отпущенными, и слежу за манометром на панели. За первую минуту стрелка падает более чем на 4 psi. О чём это говорит относительно состояния машины?","options":["Ничего страшного; при заглушённом двигателе воздух в ресиверах просто остывает и сжимается, поэтому такое падение за первую минуту вполне ожидаемо.","Это показание доказывает, что пружинные (стояночные) тормоза сработали правильно, ведь давление всегда быстро стравливается, как только включается стояночная система.","Система теряет воздух быстрее допустимого; при отпущенных тормозах одиночное транспортное средство должно терять не более 2 psi в минуту, а более 4 psi означает утечку, которую нужно найти и устранить.","Это подтверждает, что регулятор (губернатор) достиг отсечки и остановил компрессор, а именно так и ведёт себя давление после остановки двигателя."],"explanation":"При отпущенных тормозах одиночный автомобиль должен терять не более 2 psi в минуту, поэтому потеря более 4 psi указывает на утечку воздуха, которую нужно найти и устранить."},"87":{"q":"Я стою у погрузочной платформы, когда медленная утечка воздуха опустошает ресиверы, и давление в системе продолжает падать к нулю. По мере падения давления что делает моя пневматическая тормозная система, чтобы машина не покатилась, и почему? Выберите ВЕРНОЕ утверждение.","options":["Рабочие тормоза используют запас гидравлической жидкости, чтобы зажать колёса, поэтому грузовик стоит на месте даже без воздуха в ресиверах.","Ничто не удержит грузовик, когда давление пропадёт; эта одна маленькая утечка мгновенно отпускает все тормоза, и машина свободно катится.","Компрессор автоматически накачивает утечку обратно до 125 psi, поэтому рабочие тормоза от педали сами удерживают машину на месте.","Пружинные (стояночные) тормоза срабатывают автоматически, когда давление падает в диапазон 20-45 psi, механически удерживая колёса без воздуха."],"explanation":"Пружинные стояночные тормоза удерживаются в отпущенном состоянии воздухом, поэтому при падении давления до диапазона 20-45 psi мощные пружины автоматически включают тормоза и удерживают колеса без воздуха."},"88":{"q":"Я только что завел двигатель своего тягача с пневматическими тормозами, и манометр воздушного давления показывает всего 50 psi, при этом зуммер предупреждения о низком давлении воздуха продолжает звучать. Машина запаркована, груженая, а я опаздываю с доставкой. Что мне следует сделать, прежде чем отпустить стояночный тормоз и выехать со двора?","options":["Подождать, не выключая двигатель, пока давление не поднимется примерно до 100 psi и предупреждение о низком давлении не отключится","Медленно выехать при 50 psi, ведь тормоза продолжат набирать давление, пока я еду к месту доставки","Открыть сливные клапаны баллонов, чтобы стравить накопившийся воздух и компрессор быстрее наполнил баллоны","Отключить зуммер предупреждения о низком давлении, чтобы он замолчал, и поехать, как только шум прекратится"],"explanation":"Не глуша двигатель, дождитесь, пока давление поднимется примерно до 100 psi и сигнал низкого давления воздуха отключится, прежде чем начинать движение."},"89":{"q":"Я везу гружёный автопоезд вниз по длинному горному спуску и всю дорогу удерживаю ровное давление на педали тормоза. Ближе к подножию педаль всё ещё ощущается твёрдой, но при нажатии машина почти не замедляется. Какое объяснение ЛУЧШЕ всего описывает, почему тормоза потеряли тормозную силу?","options":["Непрерывное торможение подняло давление воздуха в системе выше точки отключения регулятора, поэтому тормоза больше не могут создать достаточное усилие","Непрерывное торможение перегрело тормозные барабаны и накладки, а этот нагрев снижает силу трения, которую способны создать тормоза","Постоянное торможение постепенно стравило воздух из ресиверов, и пружинные тормоза частично растормозились, компенсируя это","Регулировочные рычаги затянулись от нагрева, отведя накладки от барабанов"],"explanation":"Длительное непрерывное торможение на затяжном спуске перегревает барабаны и накладки, и этот нагрев снижает трение, которое могут создать тормоза, вызывая угасание тормозов."},"90":{"q":"Я подъезжаю к знаку 'Стоп' на грузовике с пневматическими тормозами и сильно нажимаю на педаль тормоза. Есть заметная задержка, прежде чем я действительно почувствую, что грузовик начинает замедляться, хотя моя нога сработала мгновенно. Мой инструктор называет это 'запаздыванием тормозов' (brake lag). Что на самом деле происходит во время этой задержки?","options":["Мои регулировочные рычаги (slack adjusters) разрегулированы, поэтому штоки слишком медленно прижимают колодки","Моё время реакции как водителя и создаёт задержку между решением и торможением","Воздуху требуется доля секунды, чтобы пройти по магистралям и достичь тормозов","Давление воздуха упало ниже порога включения, поэтому регулятор должен сначала восстановить давление"],"explanation":"Запаздывание тормозов — это примерно полсекунды, за которые сжатый воздух проходит по магистралям от педали к тормозным камерам, нормальное свойство любой пневматической тормозной системы."},"91":{"q":"Во время предрейсового осмотра старого тягача с пневматическими тормозами я нагнетаю воздух, глушу двигатель и начинаю прокачивать тормоза, чтобы сбросить давление. Когда стрелка манометра опускается к 60 psi, небольшой механический рычаг внезапно падает мне в поле зрения над лобовым стеклом. Инструктор называет его 'wig-wag'. Каково назначение этого устройства?","options":["Это регулятор (губернатор), сигнализирующий, что компрессор достиг отсечки и прекратил нагнетать воздух в ресиверы","Это модулирующий управляющий клапан, опускающийся вниз, чтобы я мог постепенно применить пружинные тормоза в аварийной ситуации","Это автоматический сливной клапан, выпускающий воду и масло, скапливающиеся в питающем ресивере","Это механический сигнализатор низкого давления воздуха, который физически падает в поле зрения, предупреждая меня, что давление становится опасно низким"],"explanation":"Wig-wag — это механический сигнализатор низкого давления воздуха, подпружиненный рычаг которого опускается в поле зрения водителя, сигнализируя об опасно низком давлении воздуха."},"92":{"q":"Во время предрейсового осмотра я нажимаю на педаль тормоза и наблюдаю за тормозным механизмом на колесе. Когда воздух заполняет тормозную камеру, шток (толкатель) выдвигается наружу. В исправном барабанном тормозе с S-образным кулачком, что ДАЛЕЕ должно произойти в результате движения этого штока?","options":["Повернуть регулировочный рычаг (трещотку), который проворачивает S-образный кулачок и прижимает тормозные колодки к барабану","Напрямую прижать тормозные колодки к барабану без участия кулачка или рычага","Открыть камеру пружинного тормоза, чтобы пружины стояночного тормоза помогли применить рабочие тормоза","Подать дополнительный сжатый воздух в питающий ресивер, чтобы поддержать давление в системе"],"explanation":"Воздух в тормозной камере толкает шток, который поворачивает регулятор зазора и проворачивает S-образный кулак, разводя тормозные колодки и прижимая их к барабану."},"93":{"q":"Я только что купил седельный тягач 2020 года с пневматическими тормозами и прослеживаю проводку ABS, чтобы убедиться, что антиблокировочная система соответствует федеральному требованию для такого нового автомобиля. Проверяя каждую ось, на каких колёсах я обязан обнаружить ABS?","options":["Только на управляемых (передних) колёсах, ведь именно там блокировка приводит к потере управления","На всех колёсах тягача, поскольку новые тягачи должны иметь ABS на каждом колесе","Только на задних ведущих колёсах, ведь именно там приходится самая большая тормозная нагрузка","Ни на одном колесе, потому что ABS — необязательное оборудование, которое покупатель устанавливает позже"],"explanation":"ABS обязательна на каждом колесе седельных тягачей, выпущенных 1 марта 1997 года или позже, поэтому более новый тягач должен иметь ABS на всех колесах."},"94":{"q":"Во время предрейсового осмотра моего автопоезда приборная панель показывает, что ABS самого тягача в порядке, но мне всё ещё нужно убедиться, что ABS прицепа работает. Прицеп выпущен в 1999 году, поэтому у него своя система ABS и отдельная контрольная лампа неисправности, которую я обязан проверить. Обходя автопоезд, где мне искать эту лампу неисправности ABS прицепа?","options":["Спереди прицепа возле шкворня, чтобы она была обращена к кабине тягача","На приборной панели в кабине, рядом с собственной лампой ABS тягача","На левой стороне или слева сзади прицепа, где она видна во время обхода","Внутри воздушного ресивера прицепа, за ручным сливным клапаном"],"explanation":"На прицепе 1999 года контрольная лампа неисправности ABS установлена на левой стороне или левой задней части прицепа, чтобы её было видно при наружном осмотре."},"95":{"q":"Я управляю среднетоннажным грузовиком с пневмогидравлической тормозной системой (air-over-hydraulic). Во время предрейсового осмотра я хочу понять, что именно делает пневматическая часть этой системы, чтобы знать, чего я лишусь при отказе подачи воздуха. Какое утверждение правильно описывает роль давления воздуха в этой схеме?","options":["Давление воздуха циркулирует через суппорты, охлаждая тормозную жидкость и не давая ей перегреваться на длинных спусках","Давление воздуха поддерживает уровень тормозной жидкости, автоматически восполняя жидкость, теряемую через изношенные уплотнения","Давление воздуха приводит в действие компрессор, который заряжает аккумулятор, чтобы у гидронасоса всегда было питание","Давление воздуха воздействует на гидравлическую систему, усиливая тормозное усилие, которое водитель прикладывает к педали"],"explanation":"В пневмогидравлической системе давление воздуха усиливает усилие водителя на педали, которое затем гидравлическая жидкость передаёт на колёсные тормоза."},"96":{"q":"Во время предрейсового осмотра вы обнаруживаете, что регулировочные рычаги (slack adjusters) показывают чрезмерный ход штока, то есть тормоза не отрегулированы. Если вы всё равно поедете и начнёте спуск по длинному крутому уклону, какое последствие этого дефекта НАИБОЛЕЕ вероятно?","options":["Тормозная сила снизится, и тормоза могут полностью отказать по мере нагрева на спуске","Тормоза будут схватывать сильнее обычного, повышая риск блокировки колёс и заноса","Система просто будет расходовать меньше воздуха, поэтому можно дольше безопасно подкачивать педаль тормоза на спуске","Сигнал низкого давления воздуха сработает раньше, но сама тормозная сила останется неизменной"],"explanation":"Неотрегулированные тормоза снижают тормозную способность и могут перегреться и полностью отказать при тепловой нагрузке, например на длинном крутом спуске."},"97":{"q":"Я качусь вниз по небольшому уклону на грузовике с пневматическими тормозами и нажимаю на педаль тормоза немного сильнее, чтобы сбросить скорость. Когда я давлю на педаль, один из двух манометров поднимается тем выше, чем сильнее я нажимаю. На какой манометр я смотрю и о чём он мне говорит?","options":["Манометр запаса (подачи) воздуха, показывающий, сколько воздуха ещё хранится в моих баллонах","Манометр приложенного давления, показывающий, какое давление воздуха я подаю на тормоза педалью","Манометр отключения регулятора, показывающий, когда компрессор перестанет качать при 125 psi","Манометр предупреждения о низком давлении, показывающий, что давление вот-вот упадёт ниже 60 psi"],"explanation":"Манометр давления подачи показывает давление воздуха, подаваемое на тормоза, поэтому его показания растут при более сильном нажатии на педаль и падают при отпускании."},"98":{"q":"Я веду тягач с прицепом на пневматических тормозах со скоростью 55 миль/ч по сухому шоссе и вижу впереди заглохшую машину — резко жму на педаль тормоза. Однокурсник уверяет, что полсекунды, которые нужны воздуху, чтобы пройти по магистралям и сработали тормоза, почти ничего не решают на такой скорости. Примерно сколько ДОПОЛНИТЕЛЬНОГО тормозного пути добавляет эта задержка срабатывания при 55 милях/ч — сверх пути восприятия, реакции и фактического торможения?","options":["Ничего существенного — полусекундная задержка слишком коротка, чтобы добавить заметный путь при 55 милях/ч","Примерно 12 футов — примерно длина тягача, пока тормоза не схватят","Примерно 32 фута — почти длина прицепа пройдёт до того, как тормоза схватят","Примерно 60 футов — ведь путь задержки удваивается с ростом скорости"],"explanation":"У пневматических тормозов задержка около полусекунды, поэтому при 55 миль/ч автомобиль проезжает дополнительно около 32 футов, прежде чем тормоза сработают."},"99":{"q":"Во время предрейсового осмотра я заглушил двигатель при полностью заряженной системе и наблюдаю за манометром. Стрелка продолжает медленно ползти вниз и не останавливается, хотя все двери закрыты, а на педаль тормоза я не нажимаю. Прежде чем решить, безопасно ли вести этот грузовик, какое условие говорит мне, что утечка настолько серьёзна, что выезжать НЕЛЬЗЯ?","options":["При накачке манометр поднялся ровно до 125 psi, поэтому последующее медленное падение давления — это просто нормальное остывание ресиверов","Я слышу слабое шипение в районе компрессора, но пока не сработал зуммер предупреждения о низком давлении, ехать можно","Давление падает лишь до момента, когда снова срабатывает регулятор (отсечка cut-in), а это доказывает, что компрессор справляется с расходом","При заглушённом двигателе и отпущенных тормозах давление воздуха не держится стабильно и продолжает падать выше допустимой нормы утечки"],"explanation":"При выключенном двигателе и отпущенных тормозах давление должно держаться стабильно; если оно продолжает падать сверх допустимой нормы утечки, утечка слишком велика для безопасной езды."},"100":{"q":"Во время предрейсового осмотра зуммер предупреждения о низком давлении воздуха постоянно срабатывает, потому что давление не поднимается выше 70 psi, даже при работе двигателя на повышенных оборотах холостого хода. Механик говорит мне, что вышел из строя узел, отвечающий за выработку и нагнетание воздуха в баки, и его нужно заменить. О каком узле идёт речь?","options":["Воздушный компрессор, который нагнетает воздух в накопительные баки для питания системы","Регулятор (губернатор), который определяет, когда воздух нагнетается в накопительные баки","Регулировочный рычаг (трещотка), который регулирует подачу воздуха в тормозные камеры","Предохранительный клапан, который стравливает воздух для поддержания давления в баке"],"explanation":"Воздушный компрессор вырабатывает и нагнетает воздух в ресиверы, поэтому, если давление не нарастает, неисправен именно компрессор."},"101":{"q":"Во время предрейсового осмотра я оставляю двигатель работать и слежу за манометром воздуха. Примерно при 125 psi компрессор перестаёт нагнетать воздух в систему, а после нескольких нажатий на тормоз давление падает примерно до 100 psi, и компрессор снова начинает качать. Какой компонент отвечает за запуск и остановку компрессора при этих значениях давления?","options":["Предохранительный клапан, который сбрасывает воздух, когда давление в баллонах достигает примерно 150 psi","Регулятор (governor), который отключает компрессор около 125 psi и снова включает его около 100 psi","Устройство предупреждения о низком давлении воздуха, которое подаёт сигнал компрессору до падения давления ниже 60 psi","Собственные разгрузочные поршни компрессора, которые сами задают рабочее давление системы"],"explanation":"Регулятор управляет компрессором, отключая его примерно при 125 psi и снова включая примерно при 100 psi."},"102":{"q":"Во время предрейсового осмотра я запускаю двигатель и слежу за манометром давления воздуха, пока компрессор накачивает воздух. Я жду, когда регулятор (governor) достигнет точки отключения (cut-out) — момента, когда компрессор перестаёт нагнетать воздух в ресиверы. При каком примерно показании манометра это должно произойти?","options":["Около 100 psi, поскольку именно здесь регулятор управляет системой","Около 150 psi, как раз когда система достигает максимального безопасного давления","Около 125 psi, когда регулятор даёт компрессору команду прекратить нагнетание","Около 60 psi, как раз когда отключается предупреждающее устройство и нагнетание прекращается"],"explanation":"Отключение компрессора — момент, когда регулятор останавливает нагнетание, — происходит примерно при 125 psi."},"103":{"q":"Я провожу предрейсовый осмотр одиночного транспортного средства с пневматическими (воздушными) тормозами. При выключенном двигателе я нажимаю на педаль тормоза, чтобы стравить давление в системе, и слежу за манометром, как падает давление. В какой момент должны сработать сигнальная лампа и зуммер низкого давления воздуха, чтобы предупредить меня, что давление становится опасно низким?","options":["Как только манометр опустится ниже 100 psi, ведь именно там регулятор включается, чтобы восполнить воздух","Когда давление упадёт в диапазон от 20 до 45 psi, в тот самый момент, когда срабатывают пружинные тормоза","В то мгновение, когда давление поднимется выше 125 psi, где регулятор отключается и прекращает накачку","Прежде чем манометр опустится ниже 60 psi, пока ещё достаточно воздуха для безопасной остановки"],"explanation":"Сигнал низкого давления воздуха должен включиться до того, как давление упадёт ниже 60 psi, оставляя достаточно воздуха для безопасной остановки."},"104":{"q":"Во время предрейсового осмотра я запускаю двигатель и наблюдаю, как стрелка одного из приборов на панели неуклонно поднимается, пока регулятор не отключает компрессор примерно при 125 psi. Переводя взгляд между этим прибором и остальными, какое именно показание отображает данный прибор?","options":["Сколько давления воздуха сейчас накоплено в воздушных баллонах","С какой силой я нажимаю на педаль тормоза, то есть приложенное давление","Момент, при котором загорится контрольная лампа низкого давления воздуха","Сколько секунд воздух поднимался с 85 до 100 psi"],"explanation":"Манометр воздушного давления показывает, сколько воздуха сейчас находится в воздушных резервуарах."},"105":{"q":"Сейчас зима, и на воздушных ресиверах моего тягача с прицепом установлены ручные сливные краны. Я только что закончил длинную смену и замечаю, что в системе скопились вода и компрессорное масло. Зная, что за ночь это может замёрзнуть и повредить узлы, как часто мне следует открывать эти ручные сливные краны, чтобы удалять влагу?","options":["Только раз в неделю, так как осушитель воздуха удаляет большую часть влаги между сливами","В конце каждого дня, полностью сливая ресиверы перед тем, как поставить машину на стоянку","Только когда загорится сигнальная лампа низкого давления воздуха ниже 60 psi","Примерно раз в месяц или каждый раз, когда я замечаю явную утечку воздуха из ресиверов"],"explanation":"Сливайте воздушные резервуары с ручными клапанами полностью в конце каждого дня, чтобы удалить скапливающиеся воду и масло."},"106":{"q":"Во время предрейсового осмотра экзаменатор просит меня назвать три отдельные тормозные системы, объединённые в единую пневматическую тормозную установку. Я правильно называю рабочие тормоза и стояночные тормоза. Какую систему я должен назвать третьей, чтобы завершить ответ?","options":["Систему замедлителя (ретардера), которая замедляет грузовик без использования педали тормоза","Двухконтурную систему, которая разделяет воздух на первичный и вторичный контуры подачи","Аварийную тормозную систему, которая останавливает грузовик при отказе основной подачи воздуха","Модулирующую систему, которая позволяет плавно включать пружинные тормоза"],"explanation":"Система пневматических тормозов объединяет три системы: рабочие, стояночные и аварийные тормоза, которые останавливают машину при отказе подачи воздуха."},"107":{"q":"Я веду гружёный одиночный грузовик, когда лопается шланг и давление воздуха продолжает падать. Световой сигнал и зуммер низкого давления воздуха уже давно сработали, и теперь я чувствую, как грузовик сам резко замедляется, потому что пружинные (стояночные/аварийные) тормоза срабатывают самостоятельно. КРОМЕ точного значения, примерно до какого диапазона давления упал воздух в тот момент, когда эти пружинные тормоза сработали автоматически?","options":["Около 100 psi — точка, в которой регулятор обычно включается (cut-in)","Около 60 psi — та же точка, при которой впервые срабатывает предупреждение о низком давлении воздуха","Около 125 psi — точка, в которой регулятор выключается (cut-out) и прекращает накачку","Около 20–45 psi — там, где пружинные тормоза срабатывают автоматически"],"explanation":"Пружинные тормоза удерживаются воздушным давлением и срабатывают автоматически, когда давление падает до 20–45 psi."},"108":{"q":"Я только что спустил гружёный автопоезд по длинному крутому уклону, всю дорогу интенсивно работая пневматическими тормозами. Внизу я заезжаю на стоянку и чувствую, что колёса излучают сильный жар. КРОМЕ одного из этих действий, остальные разумны перед тем, как покинуть кабину. Какого действия мне следует ИЗБЕГАТЬ прямо сейчас?","options":["Затягивать стояночный (пружинный) тормоз, пока тормозные барабаны всё ещё очень горячие после спуска","Подложить противооткатные упоры и дать тормозам остыть, прежде чем полагаться на пружинные тормоза для удержания","Дать давлению воздуха снова подняться до отсечки регулятора, прежде чем рассчитывать на удержание системой","Проверить ход штока позже, ведь тормоза с нарушенной регулировкой — самый частый дефект пневмотормозов"],"explanation":"Никогда не включайте стояночные (пружинные) тормоза при сильно нагретых барабанах, например сразу после крутого спуска, так как это может их повредить."},"109":{"q":"Я спускаюсь по длинному крутому уклону на гружёном автопоезде. Чтобы сдерживать скорость, я снова и снова нажимаю и отпускаю педаль тормоза («прокачка»). Какой из перечисленных результатов НАИБОЛЕЕ вероятен, если делать это всю дорогу вниз?","options":["Тормоза останутся более холодными, потому что между нажатиями они успевают отпускаться и остывать","Давление воздуха упадёт, потому что каждый отпуск педали выпускает воздух быстрее, чем компрессор успевает его восполнять, и в итоге воздух израсходуется","Компрессор будет качать быстрее при каждом отпускании, поэтому баки на самом деле накопят больше воздуха, чем дольше я так делаю","Ничего не изменится, пока я всю дорогу остаюсь выше уровня предупреждения о низком давлении в 60 psi"],"explanation":"Не качайте тормоза на длинном спуске, так как каждый сброс выпускает воздух быстрее, чем компрессор его восполняет, в итоге расходуя весь запас."},"110":{"q":"Я веду тягач с прицепом, оборудованный пневматическими (воздушными) тормозами, и сильно нажимаю на педаль тормоза, но замечаю, что машина не начинает замедляться в тот же миг, как моя нога двигает педаль — проходит короткая задержка около половины секунды, прежде чем торможение фактически начнётся. Эта задержка, вызванная тем, что воздуху нужно пройти по тормозным магистралям к камерам, называется:","options":["Затухание тормозов (brake fade) — потеря тормозной силы из-за перегрева барабанов на долгом спуске","Увод при торможении (brake pull) — склонность машины уводить в сторону при нажатии на тормоз","Запаздывание тормозов (brake lag) — время, нужное воздуху для прохода по магистралям до срабатывания тормозов","Дисбаланс тормозов — неравномерное тормозное усилие между осями тягача и прицепа"],"explanation":"Запаздывание тормозов — это задержка около полусекунды, вызванная тем, что воздуху нужно время пройти по тормозным магистралям до срабатывания."},"111":{"q":"Я сравниваю свой тягач с пневматическими тормозами с автомобилем друга с гидравлическими тормозами. При одинаковых скорости, дороге и времени реакции, как примерно полусекундная задержка срабатывания пневмотормозов влияет на мой ОБЩИЙ тормозной путь по сравнению с машиной с гидравлическими тормозами?","options":["Никак не влияет, потому что общий тормозной путь определяется только дистанцией восприятия и реакции.","Он сокращает общий тормозной путь примерно вдвое, как только воздух достигает тормозных камер.","Он немного сокращает общий тормозной путь, потому что давление воздуха быстрее создаёт тормозное усилие.","Он немного увеличивает общий тормозной путь, потому что к нему добавляется дистанция задержки срабатывания тормозов."],"explanation":"Запаздывание тормозов около полусекунды добавляет к общему тормозному пути отрезок запаздывания, примерно 32 фута на скорости 55 миль/ч."},"112":{"q":"Во время предрейсового осмотра я продолжаю нагнетать воздух и вижу, как стрелка манометра проходит точку отключения регулятора (губернатора). Что-то вышло из строя, и компрессор не останавливается, поэтому давление продолжает расти. Примерно при каком давлении должен сработать предохранительный клапан в питающем (влажном) ресивере, чтобы защитить систему от избыточного давления?","options":["Примерно 150 psi","Примерно 125 psi","Примерно 100 psi","Примерно 60 psi"],"explanation":"Предохранительный клапан в питающем резервуаре открывается примерно при 150 psi, сбрасывая избыточное давление при отказе регулятора."},"113":{"q":"Во время предрейсового осмотра пневматических тормозов экзаменатор говорит мне: \"Нажми с усилием на ножной клапан (foot valve) и удерживай его\", пока мы следим за скоростью падения давления (утечкой воздуха). Я смотрю на органы управления и педали в кабине. На что именно велит нажать экзаменатор?","options":["На жёлтую ручку в форме ромба на приборной панели, так как именно она управляет подачей воздуха в тормоза","На тормозную педаль на полу кабины, потому что в пневматической тормозной системе её также называют ножным или педальным клапаном (foot/treadle valve)","На педаль газа, потому что перед началом проверки на утечку нужно поднять давление воздуха","На педаль сцепления, так как именно её нажатие отпускает пружинные тормоза для создания давления"],"explanation":"Педаль тормоза на полу кабины — это орган управления рабочими тормозами, также называемый ножным или педальным клапаном."},"114":{"q":"Я веду тягач с прицепом, оснащённый двойной (дублированной) пневматической тормозной системой, когда внезапно загораются сигнальная лампа и звучит зуммер низкого давления воздуха, сообщая, что основной (первичный) пневмоконтур потерял давление. Что из перечисленного ВЕРНО в отношении того, чего мне ожидать от тормозов в этот момент?","options":["Основной и вторичный контуры отключаются одновременно, поэтому у меня вообще не остаётся тормозного усилия","Пружинные (стояночные) тормоза мгновенно намертво блокируют все колёса, и я должен резко рулить, чтобы сохранить управление","Вторичный контур всё ещё заполнен воздухом и продолжит обеспечивать торможение, поэтому я могу безопасно затормозить до остановки","Моё тормозное усилие удваивается, потому что вторичный контур сбрасывает всё своё давление воздуха на колёса"],"explanation":"В двухконтурной пневматической тормозной системе при отказе основного контура отдельный вторичный контур остаётся заполненным воздухом и позволяет безопасно остановиться."},"115":{"q":"Во время предрейсового осмотра пневмосистема полностью заряжена, а двигатель заглушён. Я хочу убедиться, что устройство предупреждения о низком давлении воздуха работает исправно, прежде чем тронуться. Какое действие правильно проверяет его?","options":["Запустить двигатель и дать регулятору накачивать воздух, пока не откроется предохранительный клапан, затем слушать зуммер","Нажать и удерживать педаль тормоза с усилием в течение одной минуты и следить за манометром, ожидая резкого скачка давления","Вытянуть жёлтую кнопку стояночного тормоза и убедиться, что пружинные тормоза сработали до того, как прозвучит предупреждение","При заглушённом двигателе нажимать и отпускать педаль тормоза, стравливая воздух, и следить, чтобы предупреждение сработало к 60 psi"],"explanation":"При выключенном двигателе нажимайте и отпускайте педаль тормоза, стравливая воздух из ресиверов, и убедитесь, что предупреждение о низком давлении срабатывает до падения давления ниже 60 psi."},"116":{"q":"Я веду одиночный грузовик со стандартной пневматической тормозной системой, когда мой воздушный компрессор начинает выходить из строя и давление продолжает падать. Сигнальная лампа и зуммер низкого давления горят уже некоторое время, и я снижаю скорость, чтобы съехать на обочину. При каком примерно давлении мне следует ожидать, что пружинные (стояночные) тормоза сработают сами и остановят грузовик, ЗА ИСКЛЮЧЕНИЕМ случая, если я уже припарковался?","options":["Где-то в диапазоне от 20 до 45 psi","Чуть ниже 60 psi, в той же точке, где загорается сигнальная лампа","Около 100 psi, когда регулятор обычно включается","Около 125 psi, когда регулятор обычно отключается"],"explanation":"Пружинные (стояночные/аварийные) тормоза удерживаются в отпущенном состоянии воздухом и срабатывают автоматически, когда давление падает до диапазона 20-45 psi."},"117":{"q":"Во время предрейсового осмотра я собираюсь выполнить тест на скорость утечки воздуха на моём одиночном транспортном средстве. Я запустил двигатель, и манометр сейчас показывает около 90 psi и продолжает расти. Прежде чем начать засекать падение давления, что я должен сделать В ПЕРВУЮ ОЧЕРЕДЬ, чтобы тест был достоверным?","options":["Несколько раз нажать на педаль тормоза, чтобы стравить воздух из магистралей до давления включения (cut-in), и начать отсчёт","Дать системе накачаться, пока регулятор не отключится (cut-out) около 125 psi, затем заглушить двигатель","Полностью слить весь воздух из ресиверов, чтобы измерять утечку с чистой, пустой системы","Включить стояночный тормоз и газовать, пока предохранительный клапан не откроется около 150 psi"],"explanation":"Проверку утечки воздуха выполняют при полностью заряженной системе до отключения регулятора около 125 psi и выключенном двигателе, чтобы компрессор не скрывал утечку."},"118":{"q":"Во время предрейсового осмотра одиночного (прямого) грузовика я глушу двигатель, подкладываю упоры под колёса и накачиваю пневмосистему до отключения регулятора. Стояночный тормоз оставляю отпущенным и в течение одной минуты слежу за манометром на панели, проверяя утечки. Какое показание говорит о том, что утечка ещё в пределах нормы и можно продолжать?","options":["Падение до 3 psi за эту минуту допустимо, ведь это норма для одиночного автомобиля с отпущенными тормозами","Любое падение — это провал; при заглушённом двигателе и отпущенных тормозах стрелка должна стоять идеально неподвижно","Падение не более 2 psi за эту минуту укладывается в норму для этой проверки одиночного автомобиля с отпущенными тормозами","Падение до 4 psi за минуту нормально, ведь тормоза отпущены, а не нажаты"],"explanation":"Для одиночного транспортного средства с отпущенными тормозами потеря воздуха не более 2 psi в минуту находится в пределах допустимого."},"119":{"q":"Во время предрейсового осмотра одиночного (одиночного фургона) грузовика я полностью накачал систему примерно до 125 psi, заглушил двигатель и нажал и удерживаю педаль тормоза. Теперь я наблюдаю за манометром в течение одной полной минуты, чтобы проверить скорость утечки. Чтобы пройти этот тест, падение давления, которое я увижу, не должно превышать:","options":["2 psi за эту минуту, ведь удержание педали — тот же стандарт, что и проверка при отпущенных тормозах","4 psi за эту минуту — это предел, который разрешён одиночному грузовику","10 psi за эту минуту, пока во время теста не срабатывает предупреждение о низком давлении","3 psi за эту минуту — максимально допустимая потеря для одиночного транспортного средства при нажатых тормозах"],"explanation":"При нажатых тормозах одиночное транспортное средство может терять не более 3 psi в минуту и оставаться в пределах нормы."},"120":{"q":"Во время предрейсового осмотра я тяну за регулятор тормозного рычага (слэк-аджастер) и замечаю, что его свободный ход превышает дюйм, то есть тормоза разрегулированы. Если я поеду, не устранив это, какое НАИБОЛЕЕ прямое последствие для безопасности мне следует ожидать?","options":["Тормоза будут работать плохо, потому что чрезмерный ход штока снижает тормозное усилие","Зуммер предупреждения о низком давлении воздуха сработает до падения давления ниже 60 psi","Регулятор компрессора не отключит подачу воздуха примерно при 125 psi","Пружинные тормоза сработают автоматически, как только давление упадёт в диапазон 20–45 psi"],"explanation":"Слишком ослабленные регулировочные рычаги вызывают избыточный ход штока, что уменьшает тормозное усилие на колёсах и ухудшает работу тормозов."},"121":{"q":"Во время предрейсового осмотра я залезаю под прицеп и прошу напарника сильно нажать на тормоз, пока я наблюдаю за штоком тормозной камеры. Я хочу понять, в норме ли ещё регулировочный рычаг (трещотка). Примерно на сколько может перемещаться этот шток, прежде чем тормоза следует считать разрегулированными и отправить на обслуживание?","options":["Примерно на полфута хода, прежде чем выйдет за норму","Примерно на 1 дюйм хода, прежде чем выйдет за норму","Примерно на 6 дюймов хода, прежде чем выйдет за норму","Примерно на 2 фута хода, прежде чем выйдет за норму"],"explanation":"Ход штока при сильном нажатии на тормоз не должен превышать примерно 1 дюйм; в этих пределах регулировочный рычаг находится в норме."},"122":{"q":"Во время предрейсового осмотра я обнаруживаю тонкую трещину на одном из тормозных барабанов и замечаю, что тормозная колодка на этом колесе изношена почти до заклёпок. Давление воздуха полное, и тормоза срабатывают нормально при нажатии на педаль. Что это состояние означает для моего транспортного средства?","options":["Машину можно эксплуатировать, пока давление доходит до отключения регулятора и работает предупреждение о низком давлении","Это допустимо пока, ведь тормоза всё ещё срабатывают чётко во время теста остановки при 5 милях в час","Транспортное средство снимается с эксплуатации и не должно двигаться, пока треснувший барабан и изношенная колодка не будут отремонтированы","Это безопасно в сухую погоду, но следует избегать езды только под дождём или по мокрым дорогам"],"explanation":"Треснувший барабан или колодки, изношенные до заклёпок, автоматически выводят машину из эксплуатации, и ездить на ней нельзя до ремонта этих деталей."},"124":{"q":"Я везу гружёный прицеп по скользкому от дождя шоссе, когда впереди внезапно встаёт поток машин. Я выжимаю педаль тормоза до упора, и мой тягач оснащён ABS (антиблокировочной системой). Исходя из того, для чего на самом деле предназначена ABS, какую реальную пользу мне следует ожидать от неё при этом резком торможении?","options":["Она сократит мой общий тормозной путь значительно короче, чем у того же тягача без ABS","Она будет подкачивать тормоза за меня, так что мне никогда не понадобится прерывистое торможение на этой скользкой поверхности","Она автоматически понизит передачу и удержит давление воздуха, чтобы пружинные тормоза никогда не сработали","Она не даст моим колёсам заблокироваться, чтобы я всё ещё мог объехать остановившийся поток машин"],"explanation":"ABS не сокращает тормозной путь; она предотвращает блокировку колёс при резком торможении, сохраняя управляемость, чтобы объехать препятствие."},"125":{"q":"Во время предрейсового осмотра я прослеживаю путь сжатого воздуха от ресиверов к одному из колёс. Я хочу найти тот единственный компонент, где накопленное давление воздуха окончательно преобразуется в механическое толкающее усилие, которое физически приводит в движение тормозную тягу. Какой компонент я ищу?","options":["Тормозная камера, потому что она преобразует давление воздуха в механическое усилие, приводящее в действие тормоза","Регулировочный рычаг (трещотка), потому что именно он выдвигается и прижимает накладки к барабану","Воздушный компрессор, потому что он является источником давления, которое в итоге питает тормоза","Регулятор давления (губернатор), потому что он управляет давлением воздуха, подаваемым к колесу"],"explanation":"Тормозная камера преобразует давление сжатого воздуха в механическую силу, которая выдвигает шток и приводит в действие тормоза."},"126":{"q":"Во время предрейсового осмотра я залезаю под прицеп, чтобы проверить ход штока, потому что разрегулированные тормоза - самый распространённый дефект пневматических тормозов. Я прослеживаю шток от тормозной камеры и обнаруживаю, что он прикреплён болтом к одному концу регулировочного рычага (трещотки). Чтобы понять, как тормозное усилие на самом деле приводит в действие колёсный тормоз, мне нужно знать, что поворачивает ДРУГОЙ конец этого рычага. С каким компонентом регулировочный рычаг соединяет шток?","options":["С рычажной системой тормозной педали, чтобы нажатие на педаль оттягивало шток назад","С S-образным кулачком, который он поворачивает, разводя тормозные колодки к барабану","С осушителем воздуха, который он открывает для выпуска влаги из камеры","С регулятором, которому он подаёт сигнал отключить компрессор при 125 psi"],"explanation":"Регулятор зазора поворачивает S-образный кулак, который разводит тормозные колодки к барабану, останавливая колесо."},"127":{"q":"Во время предрейсового осмотра я проверяю тормоза у каждого колеса моего тягача с прицепом и замечаю S-образный кулак, который поворачивается и разводит тормозные колодки наружу к вращающемуся барабану. Экзаменатор спрашивает, почему я должен в первую очередь знать эту конструкцию. Какой ответ верный?","options":["Это единственная конструкция рабочего тормозного механизма, которую FMCSA до сих пор разрешает на транспортных средствах с пневматическими тормозами","Это клиновой тормозной механизм, и именно с ним сегодня выпускают большинство тяжёлых составных транспортных средств","Это барабанный тормоз с S-образным кулаком — конструкция тормозного механизма, которая чаще всего встречается на коммерческих машинах с пневматическими тормозами","Это дисковый пневматический тормозной механизм — тип, используемый на подавляющем большинстве грузовиков, которые сейчас на дорогах"],"explanation":"S-образный кулак, поворачивающийся для прижатия колодок к барабану, указывает на барабанный тормоз с S-кулаком — самый распространённый базовый тормоз на машинах с пневмотормозами."},"128":{"q":"Во время предрейсового осмотра инструктор объясняет мне, что когда я нажимаю на тормозную педаль, давление воздуха толкает кулак, который разводит тормозные колодки наружу, прижимая их к вращающейся детали, закреплённой на колесе, и трение между ними замедляет автомобиль. К какой детали прижимаются тормозные колодки, создавая это тормозное трение?","options":["К регулировочному рычагу (тре́щотке), который колодки сжимают, передавая тормозное усилие","К тормозной камере, которую колодки зажимают, чтобы удержать колесо","К ресиверу (воздушному баллону), на который колодки давят, сбрасывая давление","К тормозному барабану, к которому колодки прижимаются, создавая трение"],"explanation":"Тормозные колодки прижимаются наружу к вращающемуся тормозному барабану, и трение между ними замедляет и останавливает машину."},"129":{"q":"Во время предрейсового осмотра одиночного тягача я заканчиваю накачивать воздушную систему и хочу зафиксировать машину, чтобы она не покатилась, пока я её обхожу. Какой орган управления на панели мне использовать и как именно?","options":["Вытянуть жёлтую ручку в форме ромба, чтобы включить стояночный (пружинный) тормоз","Вытянуть красную восьмиугольную ручку, чтобы включить стояночный (пружинный) тормоз","Вдавить жёлтую ручку в форме ромба, чтобы включить стояночный (пружинный) тормоз","Нажать и удерживать педаль тормоза, которая механически блокирует пружинные тормоза"],"explanation":"Стояночный (пружинный) тормоз — это жёлтая ромбовидная рукоятка, которую вытягивают для включения и вдавливают для отпускания."},"130":{"q":"Рано утром я сажусь в тягач, запускаю двигатель и готов трогаться. Желтая ромбовидная кнопка стояночного тормоза все еще вытянута. Прежде чем вдавить эту кнопку, чтобы отпустить стояночные тормоза, какое условие я обязан обеспечить?","options":["Двигатель достиг нормальной рабочей температуры, и указатель охлаждающей жидкости вышел из холодной зоны","Давление воздуха поднялось достаточно высоко, система полностью заряжена, и сигнал низкого давления воздуха погас","Давление топлива стабилизировалось, и дизель полностью прокачался через линии впрыска","Давление моторного масла поднялось в нормальный диапазон, чтобы подшипники были должным образом смазаны"],"explanation":"Пружинные тормоза отпускаются давлением воздуха, поэтому перед отпусканием стояночного тормоза система должна быть полностью заряжена, а сигнал низкого давления — выключен."},"133":{"q":"Я выполняю предрейсовую проверку пневматических тормозов и слежу за манометром на панели, чтобы проверить регулятор. Я несколько раз нажимаю на тормоз, чтобы стравить воздух, и компрессор снова включается, начиная восстанавливать давление. При каком примерно показании манометра регулятор должен ВКЛЮЧИТЬ компрессор (точка включения), и он снова начнёт накачивать воздух?","options":["Около 60 psi, как раз когда должна загораться сигнализация низкого давления воздуха","Около 125 psi, в той же точке, где он ранее прекратил накачивать","Около 100 psi, несколько ниже точки, в которой он отключился","Около 20 psi, как раз когда начинают срабатывать пружинные тормоза"],"explanation":"Регулятор включает компрессор примерно при 100 psi, что несколько ниже давления отключения около 125 psi."},"134":{"q":"Во время предрейсового осмотра тягача с полуприцепом, оборудованного двойной пневматической тормозной системой, я довожу двигатель до повышенных оборотов холостого хода и слежу за манометром на панели. Я хочу убедиться, что скорость нарастания давления соответствует норме. Наблюдая, как стрелка проходит отметку 85 psi, к какому моменту она должна достичь 100 psi, чтобы нарастание давления считалось приемлемым?","options":["Примерно за 3 секунды после прохождения 85 psi","Примерно за 30 секунд после прохождения 85 psi","Примерно за 60 секунд после прохождения 85 psi","Примерно за 45 секунд после прохождения 85 psi"],"explanation":"В двухконтурной пневмотормозной системе давление должно подниматься с 85 до 100 psi примерно за 45 секунд, иначе в системе есть неисправность."},"135":{"q":"Во время предрейсового осмотра воздушный компрессор накачал мой питающий (влажный) бак, но я замечаю медленную утечку на линии после сервисного бака. Между баками установлен обратный (одноходовой) клапан. Пока эта утечка стравливает воздух, какую главную задачу выполняет для меня этот обратный клапан?","options":["Он не даёт уже накопленному воздуху в верхнем баке вытечь обратно через участок с утечкой","Он не даёт давлению воздуха подняться выше точки утечки, чтобы система никогда не была перекачана","Он не даёт воздуху из утечки достичь тормозных камер, чтобы тормоза всё равно срабатывали","Он не даёт запертому воздуху охладиться и замёрзнуть внутри линий во время утечки"],"explanation":"Обратный клапан пропускает воздух только в одном направлении, перекрывая утечку ниже по потоку, чтобы запасённый воздух в верхнем баке не вытекал назад."},"136":{"q":"Во время предрейсового осмотра я открываю сливные клапаны на воздушных ресиверах и замечаю, что один бак постоянно заполнен водой и масляным шламом гораздо больше остальных. Зная, как система направляет воздух от компрессора, какой это бак ВЕРОЯТНЕЕ всего?","options":["Сухой ресивер, потому что он расположен дальше по контуру, и именно в нём влага окончательно конденсируется после охлаждения","Влажный (питающий) ресивер, потому что он получает воздух напрямую от компрессора, и именно в нём первым собирается большая часть воды","Топливный бак, потому что конденсат из воздушных магистралей за ночь стекает обратно в него","Тот бак, что установлен ниже всех, ведь гравитация стягивает в него всю накопившуюся воду"],"explanation":"Влажный (питающий) бак получает горячий, насыщенный влагой воздух прямо от компрессора, поэтому большая часть воды и масла конденсируется и собирается в нём первым."},"137":{"q":"Во время предрейсового осмотра я паркуюсь на ровной площадке, подкладываю башмаки под колёса, включаю стояночный тормоз, вытянув жёлтую ромбовидную кнопку, затем убираю башмаки и на низкой передаче плавно трогаюсь вперёд против тормоза. Если стояночный тормоз исправен, что должно произойти?","options":["Машина должна медленно поползти вперёд, доказывая, что пружинные тормоза удерживают частичное давление","Должен сработать зуммер низкого давления воздуха, подтверждая, что пружинные тормоза включились из-за вовремя упавшего давления","Машина должна остаться на месте и не двигаться, показывая, что стояночный тормоз удерживает её неподвижно","Машина удержится на месте только после того, как я дополнительно крепко нажму и удержу педаль рабочего тормоза"],"explanation":"Исправный пружинный стояночный тормоз зажимает с полной силой и должен удерживать автомобиль на месте при плавном трогании на низкой передаче."},"138":{"q":"Во время предрейсового осмотра я отпускаю стояночный тормоз, даю автобусу медленно покатиться вперёд до скорости примерно 5 миль/ч по ровной площадке и хочу убедиться, что рабочие тормоза работают правильно, прежде чем выехать. Что мне сделать в этот момент?","options":["Быстро несколько раз прокачать педаль тормоза и каждый раз слушать, как стравливается воздух","Легко удерживать педаль и накатом медленно остановиться, следя, чтобы манометр оставался выше 60 psi","Сначала разогнаться примерно до 20 миль/ч, чтобы получить более реалистичную, как на трассе, оценку тормозов","Твёрдо нажать на педаль тормоза и проверить, что автобус останавливается прямо, без увода в сторону, а педаль ощущается твёрдой"],"explanation":"Исправная рабочая тормозная система останавливает автомобиль прямо, без увода в сторону, а педаль ощущается твёрдой, а не мягкой."},"139":{"q":"Во время предрейсовой проверки пневматических тормозов я качусь вперёд со скоростью около 5 миль/ч и нажимаю на педаль тормоза. Грузовик останавливается ровно, но педаль проваливается вниз и ощущается мягкой и губчатой под ногой вместо упругой. Какой вывод следует сделать из такого ощущения педали?","options":["Это, скорее всего, указывает на неисправность тормозной системы, которую нужно проверить перед поездкой","Это нормально, потому что пневматические тормоза всегда ощущаются мягче, чем гидравлические","Это просто означает, что давление воздуха выше точки отключения регулятора 125 psi","Это показывает, что регулировочные рычаги автоматически выбрали лишний свободный ход"],"explanation":"Мягкая или проваливающаяся педаль указывает на неисправность тормозов, например воздух в магистралях, низкое давление или утечку, которые нужно устранить до поездки."},"140":{"q":"Я заканчиваю предрейсовый осмотр и запускаю двигатель. Сигнальная лампа неисправности ABS на приборной панели сначала загорается, но не гаснет — она продолжает гореть на холостом ходу и после того, как давление поднялось до полного. Что мне следует заключить о своей антиблокировочной тормозной системе?","options":["Лампа просто подтверждает, что прошла самопроверка ABS, и система полностью исправна","ABS, возможно, работает неправильно, и её нужно проверить, прежде чем выезжать","Лампа сигнализирует только о низком давлении воздуха, поэтому нужно лишь дать регулятору поднять давление","Лампа означает, что включены пружинные тормоза, и она погаснет, как только я отпущу стояночную кнопку"],"explanation":"Лампа неисправности ABS должна загораться при запуске и гаснуть; если она горит постоянно, ABS может быть неисправна и требует проверки до поездки."},"141":{"q":"Я веду гружёный тягач с прицепом, и вдруг на панели загорается сигнальная лампа неисправности ABS (антиблокировочной системы). Тормоза по ощущениям работают как обычно, но я переживаю из-за случившегося. Какое из следующих описаний НАИБОЛЕЕ точно отражает мою ситуацию с торможением прямо сейчас?","options":["Я полностью потерял способность тормозить и должен останавливаться накатом, только с помощью двигателя и передач","Мой тормозной путь теперь автоматически стал короче, поэтому я могу тормозить позже, чем раньше","У меня по-прежнему есть обычные рабочие тормоза, и я могу остановить машину, но тормозить нужно аккуратно, чтобы не заблокировать колёса","Будет работать только стояночный тормоз, поэтому для остановки я должен вытянуть жёлтую рукоятку"],"explanation":"Неисправность ABS отключает только функцию антиблокировки, поэтому обычные рабочие тормоза полностью сохраняются, но тормозить нужно осторожно, чтобы не заблокировать колёса."},"142":{"q":"Во время предрейсового осмотра я замечаю чрезмерный ход штока на одной из тормозных камер. Мой тягач оснащён автоматическими регуляторами зазора (slack adjusters), и коллега утверждает, что они 'не требуют обслуживания', поэтому говорит, что о них больше можно не беспокоиться. Какое утверждение отражает правильное отношение к автоматическим регуляторам зазора?","options":["Поскольку они саморегулируются, они избавляют от необходимости любой проверки во время предрейсового осмотра","Мне следует вручную ослабить их во время движения, пока чрезмерный свободный ход не исчезнет","Они устраняют разрегулировку тормозов, поэтому коллега прав, и их можно игнорировать","Их всё равно нужно регулярно проверять, потому что разрегулировка тормозов — частый дефект даже при их наличии"],"explanation":"Тормоза, вышедшие из регулировки, — самый частый дефект пневмотормозов, поэтому даже автоматические регуляторы зазора нужно регулярно проверять, ведь они не безотказны."},"143":{"q":"Во время предрейсового осмотра я замечаю чрезмерный ход штока на регулировочном рычаге (трещотке), что говорит о том, что тормоза разрегулированы. Я опаздываю, а инструменты в гараже под рукой. Кто на самом деле должен выполнить регулировку тормозов, прежде чем эта машина выедет на дорогу?","options":["Только человек, обученный и имеющий квалификацию для регулировки тормозов","Любой действующий обладатель CDL, ведь наличие прав доказывает компетентность в тормозах","Я сам, прямо сейчас, ведь ход штока легко отрегулировать гаражными инструментами","Кто угодно, кто ближе всего и свободен, чтобы машина больше не задерживалась"],"explanation":"Поскольку нарушенная регулировка тормозов напрямую снижает тормозную силу, регулировку должен выполнять только обученный и квалифицированный для этого человек."},"144":{"q":"Я веду тягач с прицепом, как вдруг загорается сигнальная лампа низкого давления воздуха, и я быстро понимаю, что воздушный компрессор полностью перестал нагнетать воздух. Примерно через милю будет съезд с безопасной обочиной. Если система была полностью заряжена, на что я могу рассчитывать благодаря запасу воздуха в баллонах?","options":["Продолжать ехать как обычно целый день рейсов, ведь в баллонах хранится суточный запас воздуха","Сделать ещё несколько торможений, чтобы снизить скорость и безопасно съехать на обочину, пока давление не упало слишком низко","Ехать сколь угодно долго, ведь пружинные тормоза сами будут подзаряжать рабочие баллоны за меня","Практически не получить рабочего торможения, поэтому надо немедленно съезжать с дороги прямо там, где я нахожусь"],"explanation":"Воздушные ресиверы хранят запас сжатого воздуха, поэтому даже после остановки компрессора можно сделать ещё несколько торможений и безопасно съехать с дороги."},"145":{"q":"Морозное зимнее утро, и мой контрольный список перед поездкой напоминает мне ежедневно сливать воздушные баки, чтобы вода и компрессорное масло не скапливались и не замораживали систему. Я стою под тягачом и ищу нужные элементы, которые надо открыть. Какое устройство я на самом деле использую, чтобы слить скопившуюся воду из воздушных баков?","options":["Предохранительный клапан, который я открываю вручную, чтобы выпустить влагу из влагосборного (мокрого) бака","Жёлтую ромбовидную кнопку в кабине, которую я вытягиваю, чтобы выпустить воду из баков","Сливные клапаны, также называемые петкоками (краниками), расположенные внизу каждого воздушного бака","Регулятор (губернатор) компрессора, который я сбрасываю, чтобы он вытолкнул застрявшую воду обратно"],"explanation":"Воздушные ресиверы сливают через сливные клапаны, называемые петкоками, которые расположены внизу каждого бака для удаления скопившейся воды и масла."},"146":{"q":"Вы ведете груженый одиночный грузовик с пневматическими тормозами по сельской трассе в Техасе, когда загорается сигнальная лампа низкого давления воздуха и звучит зуммер. Стрелка манометра падает в зону низкого давления. Какое действие правильное?","options":["Продолжать движение на пониженной скорости до ближайшего съезда, ведь пружинные тормоза еще не сработали и немного воздуха пока остается","Продолжать движение, но несколько раз нажать на педаль тормоза, чтобы компрессор быстрее восстановил утраченное давление воздуха","Сохранять скорость и пока не обращать внимания на сигнал, ведь предупреждение часто загорается ненадолго и гаснет само, когда регулятор включается","Остановиться, как только это будет безопасно, и съехать с дороги, потому что продолжающееся падение давления может привести к внезапной опасной потере торможения"],"explanation":"При срабатывании сигнала низкого давления и падающем давлении остановитесь и съедьте с дороги как можно скорее, ведь дальнейшее падение может привести к внезапному отказу тормозов."},"147":{"q":"Я провожу предрейсовый осмотр своего тягача с прицепом, и механик замечает, что мои стоп-сигналы (тормозные огни) загораются только тогда, когда я действительно достаточно сильно нажимаю на педаль тормоза. На транспортном средстве с пневматическими (воздушными) тормозами что физически приводит в действие этот электрический выключатель стоп-сигнала и включает тормозные огни?","options":["Давление воздуха, нарастающее в тормозных магистралях при нажатии на педаль, замыкает выключатель стоп-сигнала","Механическое движение педали тормоза напрямую нажимает на выключатель, как в легковом автомобиле","Падение давления воздуха, которое происходит, когда пружинные тормоза начинают растормаживаться, замыкает выключатель","Тепло, выделяемое на тормозных барабанах, подаёт сигнал на выключатель для включения стоп-сигналов"],"explanation":"На пневмотормозах выключатель стоп-сигнала электрический и срабатывает от воздуха; рост давления в магистрали при нажатии педали замыкает его и включает стоп-фонари."},"148":{"q":"Холодным утром я первым делом сажусь в свой тягач с прицепом, завожу двигатель и готовлюсь отпустить пружинные (стояночные) тормоза и тронуться. Прежде чем нажать жёлтую кнопку стояночного тормоза, чтобы отпустить пружинные тормоза и поехать, каким должно быть давление воздуха в системе?","options":["Световой и звуковой сигнал низкого давления только что отключился, поэтому любого давления выше этого порога достаточно, чтобы отпустить тормоза и ехать","Давление сначала должно подняться достаточно высоко, до нормального рабочего диапазона около отметки отключения регулятора, и только потом можно отпускать пружинные тормоза","Давлению нужно лишь снова подняться выше диапазона 20–45 psi, при котором срабатывают пружинные тормоза, и тогда можно отпускать и ехать","Давление следует сбросить как можно ниже, чтобы пружинные тормоза легче освободились, а затем отпустить кнопку"],"explanation":"Пружинные тормоза удерживаются в отпущенном состоянии воздухом, поэтому давление сначала должно подняться до нормального рабочего диапазона у отсечки регулятора, прежде чем они отпустят."},"149":{"q":"Я везу гружёный прицеп вниз по длинному крутому спуску и всю дорогу сильно давлю на тормоза. Ближе к низу я замечаю, что тормозные барабаны сильно перегрелись. Какой эффект Этот перегрев СКОРЕЕ ВСЕГО окажет на мои пневматические тормоза?","options":["Расширяясь, барабаны плотнее прижимаются к колодкам, давая заметно более сильное торможение","Жар высушивает влагу в магистралях, поэтому тормоза срабатывают быстрее и чётче","Тормоза начнут «угасать» (fade): придётся давить всё сильнее, а тормозной эффект будет всё слабее","На ходу ничего не изменится, но раскалённые барабаны треснут в тот момент, когда я остановлюсь и встану на стоянку"],"explanation":"Перегретые тормозные барабаны теряют способность преобразовывать движение в тепло, поэтому тормоза слабеют, и приходится давить сильнее ради меньшего торможения."},"150":{"q":"Я веду тягач с прицепом по шоссе, как вдруг прицеп отрывается, его воздушные шланги разрываются, и весь воздух со стороны прицепа уходит. Какое устройство предназначено для того, чтобы перекрыть и защитить запас воздуха в моём тягаче, чтобы у меня осталось достаточно воздуха для управления и остановки самого тягача?","options":["Релейный клапан, который ускоряет срабатывание тормозов, подавая воздух к задним тормозам в момент нажатия на педаль","Клапан быстрого растормаживания, который быстро выпускает запертый воздух, чтобы тормоза отпускались сразу, как только я отпускаю педаль","Ножной (педальный) клапан, который регулирует, сколько тормозного воздуха подаётся, когда я нажимаю на педаль тормоза","Клапан защиты тягача, который перекрывает запас воздуха тягача, чтобы сохранить достаточно воздуха для торможения и управления тягачом"],"explanation":"Если прицеп отрывается или сильно травит воздух, клапан защиты тягача автоматически закрывается, перекрывая подачу воздуха тягача, чтобы хватило на торможение и управление."},"151":{"q":"Вы только что сцепили тягач с гружёным прицепом, подсоединили воздушные магистрали и подняли давление в системе до отключения регулятора (cut-out). Прежде чем тронуться с прицепом, вы тянетесь к красной восьмиугольной кнопке на панели. Что произойдёт, если НАЖАТЬ эту кнопку (вдавить внутрь)?","options":["Тормозная система прицепа заполнится воздухом, который подаётся из тягача в прицеп","Сработают пружинные (стояночные) тормоза прицепа, и прицеп останется на стоянке","Снимутся только стояночные тормоза тягача, а прицеп останется заблокированным","Воздушные магистрали прицепа стравятся, чтобы проверить зуммер предупреждения о низком давлении"],"explanation":"Нажатие красной восьмиугольной кнопки подачи воздуха на прицеп открывает магистраль и подаёт воздух от тягача для зарядки тормозной системы прицепа."},"152":{"q":"Я везу гружёный прицеп, когда утечка в питающей магистрали начинает стравливать воздух. Пока манометр продолжает падать, я хочу знать точку, при которой клапан защиты тягача закроется сам, чтобы перекрыть воздух тягача и сохранить остаток в системе. Примерно при каком давлении происходит это автоматическое закрытие?","options":["Примерно при 60 psi, в той же точке, где впервые загораются сигнальная лампа и зуммер низкого давления воздуха","В диапазоне от 20 до 45 psi, уже после того, как предупреждение какое-то время подаётся","Примерно при 100 psi, на уровне, где регулятор даёт команду компрессору включиться и возобновить накачку","Примерно при 150 psi, на уровне, где открывается предохранительный клапан в питающем ресивере"],"explanation":"Клапан защиты тягача закрывается автоматически, когда давление падает до диапазона 20–45 psi, уже после того как сигнал низкого давления подаётся некоторое время."},"153":{"q":"Во время предрейсового осмотра я замечаю, что задние тормозные камеры на моём прицепе установлены далеко сзади, на большом удалении по воздушной магистрали от ножного тормозного крана в кабине. Стажёр спрашивает, почему при нажатии на педаль тормоза эти дальние задние тормоза срабатывают не заметно медленнее передних, несмотря на всё это лишнее расстояние, которое должен пройти воздух. Каково правильное объяснение?","options":["Задние тормоза действительно срабатывают медленнее из-за расстояния, поэтому в воздушных тормозах используется встроенное запаздывание в 5 секунд, чтобы компенсировать длинный путь воздуха по магистрали","Передние и задние камеры соединены балансировочным клапаном, который намеренно задерживает передние тормоза, чтобы обе оси отпускали точно в один и тот же момент","Ускорительный (релейный) клапан, установленный рядом с задними камерами, использует местный воздушный сигнал, чтобы быстро привести в действие эти тормоза, а не ждать воздуха от педали","Клапан пружинного тормоза удерживает дополнительное давление сзади, чтобы эти тормоза сработали задолго до того, как туда вообще дойдёт воздух от педали"],"explanation":"Релейный клапан у задних камер срабатывает по местному воздушному сигналу, ускоряя торможение задних колёс вместо ожидания воздуха от педали."},"154":{"q":"Я провожу предрейсовый осмотр и замечаю, что в моей пневматической тормозной системе установлен клапан быстрого растормаживания (quick-release valve) на передней оси, рядом с тормозными камерами. Механик просит меня объяснить, что именно этот компонент делает для тормозов при обычной работе. Какое утверждение правильно описывает его назначение?","options":["Он замедляет поступление воздуха в тормозные камеры, чтобы тормоза срабатывали мягче и плавнее","Он удерживает остаточное давление воздуха в камерах, чтобы пружинные тормоза оставались заблокированными после парковки","Он стравливает масло компрессора и воду из магистралей, чтобы передние тормоза не замерзали","Он позволяет воздуху быстро выходить из тормозных камер, поэтому тормоза отпускаются быстрее, когда я отпускаю педаль"],"explanation":"Клапан быстрого растормаживания выпускает воздух из тормозных камер рядом с ними сразу после отпускания педали, поэтому тормоза отпускают быстрее и не подтормаживают."},"155":{"q":"Пружинная тормозная камера на моём припаркованном тягаче вышла из строя, и грузовик не двигается, но эвакуатору нужно оттащить его на небольшое расстояние с шоссе. Поскольку воздуха для растормаживания обычным способом нет, какое действие освободит колёса, чтобы машину можно было отбуксировать?","options":["Вручную «законтрить» (механически отвести болтом) пружинные тормоза на повреждённой камере","Накачать систему примерно до 125 psi по манометру, чтобы растормозить","Нажать жёлтую ромбовидную кнопку стояночного тормоза, чтобы отпустить пружины","Отсоединить и перерезать воздушные магистрали, чтобы камеры не держали давление"],"explanation":"Пружинные тормоза срабатывают пружинами и удерживаются воздухом, поэтому при отказе камеры их можно отпустить для буксировки только вручную, заклинив болтом каждой камеры."},"156":{"q":"На мокром скользком шоссе на моём тягаче с пневматическими тормозами другой водитель говорит мне, что я должен отключить или ослабить тормоза передних колёс, потому что они вызывают занос передних шин и затрудняют управление грузовиком под дождём. Согласно руководству CDL штата Техас, как мне следует относиться к тормозам передних колёс?","options":["Тормоза передних колёс следует отключать на мокрой дороге, потому что торможение передних шин вызывает занос передней части и потерю управления","Тормоза передних колёс важны и необходимы для нормальной остановки, и из-за них нет опасности заноса","Тормоза передних колёс полезны только для вида и почти не добавляют реальной тормозной силы, поэтому оставлять их слабыми допустимо","Тормоза передних колёс лучше оставить нерегулируемыми, чтобы основную работу выполняли задние тормоза, а передние шины служили дольше"],"explanation":"Тормоза передних колёс дают реальную и необходимую силу торможения, а мнение, что они вызывают занос, — это миф, поэтому они всегда должны работать исправно."},"157":{"q":"Я везу груз по мокрой двухполосной трассе и замечаю, что передние тормоза работают с большой нагрузкой при остановке. Опытный водитель однажды посоветовал мне отключать или не использовать передние тормоза, потому что они якобы вызывают занос на скользкой дороге. Прежде чем последовать этому совету, какое утверждение отражает то, что на самом деле говорит руководство CDL штата Техас о торможении передними колёсами?","options":["Он прав — передние тормоза являются главной причиной заносов, поэтому их следует держать отключёнными всякий раз, когда дорога мокрая.","Он прав, но только на скорости выше 55 миль/ч — ниже этой скорости передние тормоза можно использовать как обычно.","Он ошибается — представление о том, что передние тормоза вызывают занос, ложно, и наилучшее торможение достигается, когда все тормоза работают вместе.","Он отчасти прав — передние тормоза годятся на сухой дороге, но на них никогда нельзя полагаться как на тормозную силу в любых условиях."],"explanation":"Мнение, что передние тормоза вызывают занос, ошибочно; наилучшее и сбалансированное торможение достигается, когда все тормоза работают вместе."},"158":{"q":"Я везу груз со скоростью 55 миль/ч по сухому шоссе в Техасе, когда замечаю впереди остановившийся автомобиль и резко нажимаю на педаль тормоза. Инструктор напоминает мне, что у пневматических тормозов есть встроенная задержка перед тем, как они действительно схватят, поэтому грузовик продолжает катиться лишнее расстояние в течение этой половины секунды задержки ДО того, как колёса вообще начнут замедляться. Примерно какое ДОПОЛНИТЕЛЬНОЕ тормозное расстояние добавляет эта задержка срабатывания тормозов при 55 миль/ч?","options":["Около 2 футов, потому что задержка в полсекунды слишком мала, чтобы иметь значение на скорости шоссе","Около 300 футов, поскольку именно эта задержка делает пневматические тормоза намного медленнее гидравлических","Около 1 мили, потому что воздух должен пройти весь путь по магистралям, прежде чем начнётся торможение","Около 32 футов — расстояние, которое грузовик проезжает за полсекунды задержки срабатывания тормозов при 55 миль/ч"],"explanation":"У пневматических тормозов задержка около полусекунды, поэтому при 55 миль/ч грузовик проезжает примерно 32 фута, прежде чем тормоза начнут действовать."},"159":{"q":"Я просматриваю свои конспекты для CDL и уже учёл три из четырёх составляющих общего тормозного пути при пневматических тормозах: дистанцию восприятия, дистанцию реакции и дистанцию запаздывания тормозов. Какой составляющей мне ещё НЕ ХВАТАЕТ для полного значения?","options":["Дистанция эффективного торможения, путь, пройденный после того, как тормоза реально схватили и начали замедлять автомобиль","Дистанция эффективного руления, дополнительное пространство, нужное системе ABS, чтобы колёса не заблокировались","Дистанция накачки компрессора, пройденная, пока регулятор поднимает давление обратно до отсечки","Дистанция регулировочного рычага, пройденная, пока выбирается избыточный свободный ход штока перед торможением"],"explanation":"Полный тормозной путь пневматических тормозов — это расстояние восприятия плюс реакции плюс задержки плюс эффективное торможение, которое проходится после срабатывания тормозов."},"160":{"q":"Я веду гружёный автопоезд вниз по длинному крутому горному спуску и чувствую, как сила тяжести разгоняет грузовик всё быстрее. Чем дольше длится спуск, тем сильнее нагреваются пневматические тормоза. Какая техника торможения правильна, чтобы удержать машину под контролем до самого низа?","options":["Оставаться на повышенной передаче, чтобы двигатель работал ровнее, и сильно и непрерывно давить на педаль тормоза, удерживая скорость","Выбрать пониженную передачу перед спуском и применять лёгкое, равномерное торможение, отпуская тормоз, когда скорость упадёт примерно на 5 миль/ч ниже безопасной, а затем снова нажимая","Быстро прерывисто нажимать ('прокачивать') педаль тормоза, чтобы тормоза успевали остыть между нажатиями","Переключиться на нейтраль, чтобы поберечь двигатель, и подтормаживать только тогда, когда машина начнёт уходить из-под контроля"],"explanation":"Выберите низкую передачу перед спуском и тормозите легко и равномерно, отпуская тормоза примерно на 5 миль/ч ниже безопасной скорости и снова нажимая при разгоне."},"161":{"q":"Я спускаюсь на груженом тягаче по длинному горному спуску. Я уже выбрал низкую передачу, и инструктор говорит использовать правильное прерывистое торможение ('snub'), чтобы держать скорость под контролем. Какое из следующих утверждений правильно описывает мои действия?","options":["Нажать на тормоз сильно и непрерывно и держать его всю дорогу вниз, чтобы сохранять постоянную скорость","Слегка прерывисто нажимать и отпускать тормоз быстрыми касаниями, чтобы давление воздуха успевало восстанавливаться между нажатиями","Затормозить достаточно сильно, чтобы снизить скорость примерно на 5 миль/ч ниже безопасной, отпустить тормоз, затем снова нажать, когда скорость снова возрастёт","Включить нейтраль и слегка притормаживать, чтобы двигатель не мешал торможению"],"explanation":"Прерывистое торможение — это сильное нажатие, чтобы снизить скорость примерно на 5 миль/ч ниже безопасной, полное отпускание, а затем повторное нажатие при разгоне."},"162":{"q":"Я веду гружёный автопоезд и вижу знак, предупреждающий о длинном крутом горном спуске впереди. Чтобы безопасно контролировать скорость с помощью пневматических тормозов при спуске, когда мне следует выбрать передачу?","options":["Примерно на середине спуска, когда я почувствую, насколько крут уклон и как быстро набирается скорость","Только если двигатель начнёт перекручиваться или тормоза начнут терять эффективность и мне действительно понадобится более низкая передача","Ближе к низу, где дорога выравнивается и я могу понизить передачу, не перегружая коробку передач","Перед началом спуска, пока я ещё на ровной дороге и могу переключиться, не насилуя коробку передач"],"explanation":"Выберите низкую передачу до начала спуска, пока вы ещё на ровной дороге, так как переключение вниз затруднено или невозможно при быстром движении на крутом склоне."},"163":{"q":"Во время предрейсового осмотра я проверяю тормоза тягача с прицепом и замечаю, что тормозные накладки (колодки) на одном из колёс износились до опасно тонкого состояния. Всё остальное в машине в порядке. Согласно правилам DPS, что я должен сделать, прежде чем этой машине разрешат выезжать?","options":["Снять машину с эксплуатации до замены изношенных накладок, потому что опасно тонкие накладки делают её небезопасной для вождения.","Ехать как обычно, но увеличить дистанцию, так как тонкие накладки лишь незначительно снижают тормозную силу.","Несколько раз нажать на педаль тормоза, чтобы притереть тонкие накладки, и продолжить движение, если педаль ощущается твёрдо.","Продолжать движение, пока скорость утечки воздуха ниже 3 psi в минуту, так как толщина накладок не входит в проверку тормозов."],"explanation":"Слишком тонкие тормозные накладки автоматически выводят машину из эксплуатации, поэтому ездить нельзя, пока накладки не заменят."},"164":{"q":"Во время предрейсового осмотра я паркуюсь на ровной площадке, подкладываю противооткатные упоры под колёса, отпускаю стояночный тормоз и берусь за ручной регулятор зазора (slack adjuster), чтобы проверить чрезмерный ход штока. Я сильно тяну за него рукой. На сколько он должен сместиться, чтобы я мог считать тормоза правильно отрегулированными?","options":["Примерно один полный дюйм свободного хода — это максимум, допустимый до регулировки","При вытягивании рукой он должен смещаться менее чем примерно на один дюйм","Около шести дюймов хода всё ещё означает безопасно отрегулированный тормоз","Он не должен смещаться вообще, ведь любое движение означает нарушение регулировки"],"explanation":"При сильном нажатии рукой шток ручного регулятора зазора должен смещаться менее чем на дюйм; больший люфт означает разрегулированные тормоза."},"165":{"q":"Я веду гружёный тягач с полуприцепом на пневматических (воздушных) тормозах и приближаюсь к знаку «Стоп» у подножия небольшого спуска. Я замечаю, что при нажатии на педаль тормоза есть короткая задержка, прежде чем тормоза реально схватывают, по сравнению с гидравлическими тормозами моего пикапа. Чтобы безопасно учесть эту разницу, когда мне следует начинать торможение?","options":["В той же точке, что и на машине с гидравлическими тормозами, ведь задержка в полсекунды слишком мала, чтобы иметь значение","Чуть позже обычного, потому что давление воздуха создаёт дополнительную тормозную силу, когда доходит до тормозов","Чуть раньше обычного, чтобы учесть задержку пневмотормозов примерно в полсекунды, прежде чем тормоза сработают","Только после того, как тормоза прицепа сработают сами, а затем добавить давление на педаль, чтобы завершить остановку"],"explanation":"Из-за полусекундной задержки пневматических тормозов начинайте тормозить немного раньше обычного, чтобы задержка не увеличивала тормозной путь."},"166":{"q":"Я спускаюсь на гружёном автопоезде по длинному крутому горному уклону и всю дорогу держу лёгкое, постоянное давление на педаль тормоза вместо того, чтобы включить пониженную передачу. Если держать тормоза непрерывно нажатыми так на протяжении всего спуска, это вероятнее всего приведёт к тому, что мои тормоза:","options":["Останутся более холодными, потому что равномерное давление распределяет нагрузку поровну по всем барабанам","Будут лучше сдерживать грузовик, чем дольше я держу их нажатыми на уклоне","Будут изнашиваться медленнее, поскольку накладки никогда полностью не отходят от барабанов","Перегреются и потеряют эффективность, лишив меня тормозной силы ещё до конца спуска"],"explanation":"Постоянное удерживание тормозов на всём длинном спуске перегревает их и вызывает потерю эффективности, лишая тормозной силы до конца спуска."},"167":{"q":"Я только что проехал затопленный брод на своём грузовике с пневматическими (воздушными) тормозами, и на сухой дороге впереди замечаю, что тормоза стали слабыми и при первом торможении схватывают неравномерно. Как правильно поступить с мокрыми тормозами?","options":["Продолжать движение на малой скорости, слегка и плавно нажимая на педаль тормоза, чтобы тепло от трения высушило накладки","Вытянуть жёлтую кнопку стояночного тормоза и подержать пружинные тормоза включёнными минуту, чтобы выдавить воду","Резко разогнаться до максимальных оборотов, чтобы вращение колёс быстро стряхнуло воду с накладок","Несколько раз быстро прокачать педаль тормоза, чтобы вытолкнуть скопившуюся воду из тормозных камер"],"explanation":"Чтобы высушить мокрые тормозные накладки, двигайтесь медленно, слегка и равномерно нажимая на тормоз, чтобы тепло от трения испарило воду и восстановило равномерное торможение."},"168":{"q":"Я загнал свой автопоезд на крутую обочину, чтобы переждать перекрытие дороги. Я поставил стояночный тормоз, но опасаюсь, что на этом уклоне он может не удержать машину при длительной остановке. Согласно правилам безопасной эксплуатации пневматических тормозов, какой дополнительный шаг мне следует предпринять, чтобы автомобиль не скатился?","options":["Оставить двигатель работающим на низкой передаче, чтобы коробка передач помогала удерживать груз","Подложить противооткатные упоры (башмаки) под шины, чтобы механически заблокировать колёса от скатывания","Несколько раз нажать на педаль тормоза, чтобы создать дополнительное давление в пружинных тормозах","Вытянуть красную восьмиугольную кнопку подачи воздуха к прицепу, чтобы сильнее заблокировать колёса прицепа"],"explanation":"На уклоне стояночные тормоза могут постепенно стравливать воздух, поэтому подложите башмаки, чтобы механически заблокировать колёса."},"170":{"q":"Во время предрейсового осмотра я присел у колёс и проверяю компоненты пневматических тормозов на своём тягаче. Осматривая тормозные барабаны и колодки, какое состояние должно заставить меня снять машину с эксплуатации, а не ехать на ней?","options":["Поверхность барабана имеет гладкий, яркий металлический блеск по всему кругу","На фрикционных накладках колодок ещё остаётся достаточная толщина","На тормозном барабане есть трещины, идущие по его поверхности","На лицевой стороне барабана лёгкий слой дорожной пыли и грязи"],"explanation":"Тормозной барабан с трещинами на поверхности — это неисправность, которая может разрушиться под нагревом и нагрузкой при торможении, делая машину небезопасной."},"171":{"q":"Я провожу предрейсовый осмотр тягача 2015 года выпуска. Прослеживая тормозные магистрали, я нахожу клапан, который автоматически импульсами подаёт и сбрасывает давление воздуха на отдельное колесо сотни раз в секунду, чтобы это колесо не заблокировалось при резком торможении. Коллега утверждает, что эта деталь относится к совершенно другой системе грузовика. К какой системе на самом деле относится этот модуляторный клапан?","options":["К двойной системе подачи воздуха, поскольку он перераспределяет давление воздуха между первичным и вторичным баллонами","К системе стояночного тормоза, поскольку он управляет включением и отпусканием пружинных тормозов на каждом колесе","К системе рабочего тормоза, поскольку он напрямую дозирует воздух, который водитель подаёт педалью тормоза","К системе ABS (антиблокировочной системе тормозов), поскольку модуляторный клапан импульсами регулирует давление, не давая колёсам заблокироваться, чтобы вы могли управлять рулём"],"explanation":"Клапан, который много раз в секунду подаёт импульсы воздуха к колесу, чтобы предотвратить блокировку при резком торможении, — это модуляторный клапан ABS, сохраняющий управляемость."},"172":{"q":"Я сцепляю тягач с прицепом, и мне нужно соединить две воздушные магистрали (соединительные головки): рабочую (тормозную) и питающую (аварийную). Чтобы взять правильную питающую магистраль и не перепутать соединения, какой цвет я должен искать на питающей (аварийной) магистрали?","options":["Красный","Синий","Жёлтый","Зелёный"],"explanation":"Аварийная (питающая) воздушная линия прицепа окрашена в красный цвет, как и красная восьмиугольная кнопка подачи воздуха к прицепу в кабине."},"173":{"q":"Я сцепляю тягач с прицепом и тянусь к двум воздушным магистралям, идущим между секциями. Одна передаёт сигнал, который включает и отпускает тормоза прицепа, когда я нажимаю на педаль тормоза (рабочая/управляющая магистраль), а другая постоянно подаёт воздух для зарядки ресиверов прицепа и управления аварийной магистралью. Мне нужно взять правильную магистраль, чтобы подсоединить её к рабочей соединительной головке. Какой цвет обозначает рабочую (управляющую) магистраль, которую я ищу?","options":["Красная магистраль, потому что красный цвет обозначает контур, передающий тормозной сигнал от педали к прицепу","Синяя магистраль, потому что синий цвет обозначает рабочую (управляющую) магистраль, которая включает и отпускает тормоза прицепа","Чёрная магистраль, поскольку нейтральный по цвету шланг на большинстве автопоездов связан с ножным тормозом","Оранжевая магистраль, поскольку более яркий цвет выделяет шланг, реагирующий на педаль тормоза"],"explanation":"Рабочая (управляющая) линия, передающая сигнал от педали тормоза для приведения в действие и отпускания рабочих тормозов прицепа, имеет синий цвет."},"174":{"q":"Я везу гружёный прицеп по автомагистрали, когда прицеп внезапно отрывается от тягача и шланг подачи воздуха разрывается. Пока прицеп катится сам по себе, что должно произойти с его тормозами?","options":["Они останутся полностью отпущенными, и прицеп продолжит катиться, пока его не замедлит трение","Они сработают только после того, как я вытяну красную кнопку подачи воздуха в прицеп из кабины","Они сработают автоматически, потому что потеря подачи воздуха включает аварийные тормоза прицепа","Они будут быстро включаться и отключаться так же, как реагирует система ABS"],"explanation":"Если прицеп отрывается, потеря подачи воздуха автоматически приводит в действие пружинные аварийные тормоза, останавливая убежавший прицеп."},"175":{"q":"Вы ведёте тягач с полуприцепом, оснащённый исправной системой ABS, когда легковой автомобиль резко перестраивается перед вами и внезапно тормозит. Вы со всей силой давите на педаль тормоза, чтобы избежать столкновения сзади. Пока ABS выполняет свою работу при этом резком торможении, что вы реально сможете сделать?","options":["Выжать педаль до пола и положиться на то, что ABS заметно сократит общий тормозной путь","Быстро прерывисто нажимать на педаль тормоза, чтобы ABS срабатывала чаще и сильнее сцеплялась с дорогой","Удерживать педаль нажатой, но держать руль строго прямо, так как поворот руля при резком торможении отключит ABS","Держать педаль уверенно нажатой и при этом объезжать препятствие рулём, потому что колёса не заблокируются"],"explanation":"С ABS можно сильно нажимать на педаль тормоза и при этом объезжать препятствие, поскольку система не даёт колёсам заблокироваться."},"176":{"q":"Я веду старый тягач с прицепом без ABS, когда впереди меня резко останавливается легковой автомобиль. Я уже начал прерывистое (толчковое) торможение, но мне нужен второй приём, чтобы быстро остановить сцепку, не потеряв управления. Кроме прерывистого торможения, какой метод мне следует применить, чтобы остановиться как можно быстрее?","options":["Контролируемое торможение — жёстко нажимать на тормоз, не допуская блокировки колёс","Торможение с блокировкой колёс — вдавить педаль в пол, чтобы шины остановились юзом","Быстро прокачивать тормоз всю дорогу, чтобы сохранить максимальное давление на колёсах","Только торможение двигателем — понижать передачу и отпустить педаль, чтобы трансмиссия замедлила вас"],"explanation":"Контролируемое торможение — это максимально сильное нажатие на тормоз без блокировки колёс, поскольку заблокированные колёса вызывают занос и потерю управления."},"177":{"q":"Я выполняю наружный осмотр своего автопоезда и хочу убедиться, что у прицепа исправна система ABS, прежде чем выехать на трассу. Я залезаю проверить, но напарник говорит, что я ищу контрольную лампу неисправности ABS не там. Где именно на прицепе мне нужно искать эту предупреждающую лампу ABS?","options":["Спереди, возле шкворня, где зелёная лампа горит всякий раз, когда ABS прицепа включена и готова к работе","На левой задней части прицепа, где жёлтая лампа неисправности сигнализирует о проблеме с ABS","На задней двери, где загорается красная лампа, показывающая, что ABS прицепа полностью отказала","Сверху на крыше прицепа, где синяя лампа видна водителю в зеркалах"],"explanation":"Неисправность ABS прицепа сигнализируется жёлтой лампой, установленной на левой задней части прицепа."},"178":{"q":"Вы везете груженый прицеп по автомагистрали I-35, когда внезапно загорается контрольная лампа неисправности ABS на прицепе. Тягач, которым вы управляете, более новый, и его собственная система ABS по-прежнему работает нормально. Лампа неисправности указывает, что отказала только система ABS прицепа. Какое утверждение ЛУЧШЕ всего описывает то, на что вы можете рассчитывать до конца этой поездки?","options":["Поскольку отказала ABS прицепа, вы потеряли рабочие тормоза на прицепе и должны немедленно остановиться, чтобы избежать складывания.","Поскольку отказала ABS прицепа, ваш тормозной путь теперь короче, чем был до того, как загорелась лампа предупреждения.","Поскольку отказала только ABS, у вас по-прежнему есть нормальные рабочие тормоза на всей сцепке, но колеса прицепа теперь могут блокироваться при резком торможении.","Поскольку отказала только ABS прицепа, исправная ABS тягача автоматически возьмет на себя управление торможением колес прицепа."],"explanation":"Отказ ABS отключает только антиблокировочную функцию, поэтому обычные рабочие тормоза продолжают работать, но затронутые колёса могут заблокироваться при резком торможении."},"180":{"q":"Во время предрейсового осмотра я замечаю, что на панели пневмотормозов две отдельные стрелки давления вместо одной. Пока двигатель работает, обе стрелки поднимаются, пока регулятор не отключит компрессор, и каждая держится на своём показании. О чём говорит наличие этих двух стрелок в плане конструкции данного автомобиля?","options":["В нём два компрессора, каждый из которых независимо питает свою стрелку","Одна стрелка показывает рабочие тормоза, а другая — стояночные тормоза","В нём два регулятора, поэтому каждая система отключается при разном давлении (psi)","Это двухконтурная пневмотормозная система: основной и резервный воздушные контуры"],"explanation":"Две стрелки на приборной панели означают двухконтурную пневматическую тормозную систему с двумя раздельными контурами, основным и вторичным, использующими общие органы управления."},"181":{"q":"Я везу гружёный прицеп в городском потоке с частыми остановками и по привычке слегка держу левую ногу на педали тормоза между остановками, чтобы быстрее реагировать. Инструктор говорит мне полностью убирать ногу с педали всякий раз, когда я фактически не торможу. Какую ГЛАВНУЮ причину он называет?","options":["Даже лёгкое постоянное давление держит тормоза частично включёнными, из-за чего они перегреваются и преждевременно изнашиваются","Нога на педали блокирует автоматическое срабатывание пружинных тормозов при слишком сильном падении давления воздуха","Нажатие на педаль медленно стравливает воздух из ресивера и преждевременно включает предупреждение о низком давлении","Лёгкое давление на педаль перебивает регулятор и не даёт компрессору снова включиться при 100 psi"],"explanation":"Если держать ногу на педали, тормоза остаются слегка зажатыми, создавая постоянное трение, которое перегревает и преждевременно изнашивает накладки."},"182":{"q":"Механик только что заменил протекающую тормозную камеру на моём тягаче, я стою на площадке у мастерской с полным гружёным прицепом, а доставка уже опаздывает. Манометр показывает около 125 psi, и сигнал низкого давления воздуха не горит. Прежде чем выехать на трассу, что мне следует сделать В ПЕРВУЮ ОЧЕРЕДЬ?","options":["Довериться работе механика и сразу выехать на трассу, ведь манометр уже показывает около 125 psi","Проверить тормоза на малой скорости перед поездкой, включая медленную остановку примерно на 5 миль/ч, чтобы убедиться, что они держат и не уводят машину в сторону","Выехать и первую милю слегка придерживать тормоза, чтобы новая камера притёрлась","Несколько раз нажать на педаль тормоза на площадке, чтобы стравить воздух из только что отремонтированной магистрали"],"explanation":"После любого ремонта тормозов нужно лично проверить их работу, включая остановку на малой скорости около 5 миль/ч, чтобы убедиться, что они держат и не уводят в сторону."},"183":{"q":"Во время предрейсового осмотра я залезаю под тягач и замечаю, что у одного регулятора зазора (slack adjuster) на задней оси заметно больший свободный ход штока, чем у регулятора на противоположном колесе ТОЙ ЖЕ оси. Что из перечисленного верно в отношении того, как должны быть отрегулированы два регулятора зазора на этой оси?","options":["Регулятор на более загруженной стороне следует оставить слабее, чтобы уравновесить нагрузку прицепа","Разница в свободном ходе между ними — это нормально, и мне не нужно её устранять","Оба регулятора зазора на одной оси должны быть отрегулированы одинаково, поэтому неравномерный свободный ход необходимо устранить","Один следует снять, чтобы оставшийся тормоз на этой оси выполнял всю работу равномерно"],"explanation":"Оба регулятора зазора на одной оси должны иметь одинаковый свободный ход, поэтому неравномерный ход является неисправностью, которую нужно устранить до выезда."},"184":{"q":"Во время предрейсового осмотра холодным техасским утром я замечаю, что в моей пневматической тормозной системе установлен осушитель воздуха между компрессором и воздушными ресиверами. Механик предупреждает, что если этот узел выйдет из строя, зимой у меня гораздо чаще будут замерзать тормозные магистрали и ресиверы. Исходя из того, какова главная задача осушителя воздуха, почему его поломка вызовет такую проблему с замерзанием?","options":["Осушитель добавляет немного масла для смазки магистралей, и без этого масла магистрали заклинит и заморозит в холодную погоду","Осушитель подогревает сжатый воздух перед его поступлением в ресиверы, поэтому при поломке холодный воздух замораживает систему","Осушитель нагнетает воздух до давления отключения регулятора, и без достаточного давления оставшийся воздух замерзает прямо в магистралях","Осушитель удаляет влагу из воздуха, поэтому при его поломке вода скапливается в ресиверах и магистралях и может замерзнуть при низких температурах"],"explanation":"Осушитель воздуха удаляет влагу из сжатого воздуха, поэтому при его отказе вода скапливается в баках и магистралях и может замёрзнуть в холодную погоду."},"185":{"q":"Я только что отцепил гружёный прицеп на базе и еду на тягаче через весь город без прицепа (bobtail, «без хвоста»). По сравнению с тем, как было с прицепом, чего мне ожидать от поведения тягача при резком торможении?","options":["Его может быть на удивление труднее остановить, поэтому нужна особая осторожность и большая дистанция, ведь тягач без прицепа иначе ведёт себя при торможении","Он остановится заметно быстрее и на меньшем расстоянии, поэтому я могу безопасно держаться ближе к другим машинам, чем раньше","Ему не требуется особого внимания при торможении, ведь без прицепа вес уменьшился и теперь тормозам легко","Он потребует меньше усилий на рулёжку и поправок во время остановки, потому что тягач теперь намного легче"],"explanation":"Тягач без прицепа (бобтейл) сложнее остановить, так как на ведущие оси приходится меньше веса и сцепления, поэтому нужны дополнительная осторожность и дистанция торможения."},"186":{"q":"Во время предрейсового осмотра я залезаю под тягач и обнаруживаю, что один из воздушных ресиверов (баллонов) слегка смещается на кронштейне, потому что крепёжный хомут ослаб. Прежде чем выезжать на дорогу, как правильно должен быть закреплён этот воздушный баллон и почему это важно?","options":["Свободно на гибких хомутах, чтобы вибрация дороги и прогиб рамы не могли вызвать трещины в сварных швах баллона","Надёжно к раме, чтобы он оставался неподвижным, а трубки и фитинги не подвергались нагрузке и не выходили из строя","Сливным клапаном вверх, чтобы скопившаяся вода и масло не попадали на крепёжные детали","Высоко на лонжероне рамы или за кабиной, чтобы баллон сливался вперёд и в сторону от тормозных магистралей"],"explanation":"Воздушные ресиверы должны быть надёжно закреплены на раме, чтобы оставаться неподвижными при вибрации, а подключённые магистрали и фитинги не испытывали нагрузок и не повреждались."},"187":{"q":"Во время предрейсового осмотра я рассматриваю барабанный тормоз на прицепе и замечаю на нём механический индикатор износа тормозных накладок. Когда это устройство даёт показания, о чём именно оно сообщает мне относительно состояния тормозных накладок?","options":["Что накладки впитали влагу и их нужно просушить, прежде чем тормоза будут держать","Что регулировочные рычаги достигли максимально допустимого хода штока и требуют регулировки","Что накладки износились до такой степени, что их нужно заменить","Что накладки правильно притёрты и тормоза безопасны для этой поездки"],"explanation":"Индикатор износа тормозов показывает, когда тормозные накладки износились до состояния, требующего замены."},"188":{"q":"Я только что закончил длинный крутой горный спуск на гружёном составном транспортном средстве и хочу заехать на стоянку для отдыха, чтобы сделать перерыв. Мои тормоза раскалены от спуска. Какая из причин является ЛУЧШИМ объяснением, почему мне НЕ следует ставить стояночные (пружинные) тормоза прямо сейчас?","options":["Если поставить пружинные тормоза, пока они горячие, давление подачи воздуха в прицеп может упасть ниже 60 psi и сработает предупреждение о низком давлении воздуха","Горячие тормоза увеличивают ход штока, поэтому регулировочные рычаги (трещотки) будут разрегулированы, пока тормоза не остынут","Пружинные тормоза держат должным образом только после того, как давление воздуха упадёт в диапазон 20–45 psi, чему горячие тормоза препятствуют","Зажатие очень горячих тормозных элементов пружинными тормозами может их повредить, поэтому перед стоянкой мне следует дать тормозам остыть"],"explanation":"Включение пружинного (стояночного) тормоза на сильно нагретых тормозах может повредить детали, поэтому после долгого спуска дайте тормозам остыть перед стоянкой."},"189":{"q":"Во время предрейсового осмотра я сцепил тягач с груженым прицепом, накачал систему примерно до 125 psi, заглушил двигатель и нажал на педаль тормоза, удерживая ее, чтобы проверить утечку, наблюдая за манометром на панели. За одну полную минуту какое МАКСИМАЛЬНОЕ падение давления воздуха я могу увидеть и все же пройти эту проверку на утечку?","options":["4 psi","3 psi","2 psi","0 psi"],"explanation":"При нажатых тормозах падение давления воздуха у комбинированного транспортного средства не должно превышать 4 psi в минуту."},"190":{"q":"Во время предрейсового осмотра я проверяю утечку воздуха на своей сцепке тягач-прицеп. Двигатель выключен, система полностью заряжена примерно до 125 psi, а тормоза я оставил ОТПУЩЕННЫМИ (клапаны стояночного тормоза вытянуты, нога убрана с педали). Наблюдая за манометром в течение одной минуты, какую максимальную потерю воздуха я могу допустить, прежде чем утечка выйдет за норму?","options":["2 psi в минуту, потому что это предел утечки при отпущенных тормозах","3 psi в минуту, потому что у составного транспортного средства с отпущенными тормозами утечка может быть немного больше","4 psi в минуту, потому что это предел утечки для составного транспортного средства","Любая потеря допустима, пока ещё не сработало предупреждение о низком давлении воздуха"],"explanation":"При отпущенных тормозах комбинированное транспортное средство может терять до 3 psi в минуту, чуть больше, чем одиночное."},"191":{"q":"Во время предрейсового осмотра тягача с прицепом я глушу двигатель, отпускаю тормоза и начинаю нажимать на педаль тормоза, чтобы стравить воздух. Я слежу за манометром на панели, ожидая срабатывания лампы и зуммера предупреждения о низком давлении воздуха, чтобы убедиться в их исправности. Согласно руководству CDL штата Техас, при каком уровне давления в моём составном транспортном средстве предупреждение обязано сработать?","options":["До падения давления ниже 45 psi — момент, когда начинают срабатывать пружинные тормоза","До падения давления ниже 100 psi — момент, когда регулятор снова включает компрессор","До падения давления ниже 60 psi — задолго до того, как тормоза потеряют эффективность","До падения давления ниже 20 psi — момент, когда аварийные тормоза полностью задействованы"],"explanation":"Сигнал низкого давления воздуха должен включаться до падения давления ниже 60 psi, давая раннее предупреждение с запасом воздуха для безопасной остановки."},"192":{"q":"Я провожу предрейсовый осмотр и слежу, как растёт давление по манометру, пока компрессор нагнетает воздух. Примерно при 125 psi компрессор перестаёт подавать воздух в систему и удерживает давление. Инструктор просит меня назвать настройку регулятора (губернатора), которая только что остановила нагнетание. Какой термин верно называет эту настройку?","options":["Включение (cut-in) — настройка около 100 psi, при которой компрессор вновь начинает нагнетать воздух","Отключение (shut-off) — настройка, полностью отключающая компрессор до повторного запуска двигателя","Ожидание (stand-by) — настройка, переводящая компрессор в простой при включённом стояночном тормозе","Отключение нагнетания (cut-out) — настройка около 125 psi, при которой регулятор останавливает нагнетание воздуха компрессором"],"explanation":"Уставка отключения (cut-out), около 125 psi, — это точка, где регулятор останавливает нагнетание воздуха компрессором в систему."},"193":{"q":"Я веду гружёный автопоезд вниз по длинному горному спуску. Чтобы контролировать скорость, я включаю пониженную передачу, чтобы двигатель и трансмиссия в основном сдерживали движение, и лишь время от времени слегка нажимаю на рабочий тормоз. По сравнению с постоянным удержанием тормоза на всём спуске, в чём главное преимущество торможения двигателем на пониженной передаче?","options":["Рабочие тормоза остаются холодными и сохраняют полную тормозную силу, если внизу понадобится резкая остановка","Рабочие тормоза слегка нагреваются и за счёт этого лучше схватывают барабаны, сокращая тормозной путь","Воздушный компрессор быстрее набирает дополнительное давление, потому что на спуске тормоза почти не используются","Пружинные (стояночные) тормоза берут часть нагрузки на себя и автоматически замедляют машину"],"explanation":"Низкая передача позволяет двигателю поглощать энергию транспортного средства, сохраняя рабочие тормоза холодными и в полной тормозной готовности."},"194":{"q":"Я спускаюсь по длинному крутому склону на гружёном грузовике с пневматическими тормозами, и машина начинает разгоняться выше моей безопасной скорости. Приятель по рации советует мне многократно нажимать и отпускать педаль тормоза, чтобы сдерживать скорость. Почему следовать этому совету на таком спуске опасно?","options":["Многократное нажатие на педаль перегревает компрессор и срабатывает предохранительный клапан при 150 psi","Многократное нажатие на педаль стравливает воздух быстрее, чем компрессор успевает его восполнить, поэтому давление может упасть, пока вы не потеряете торможение","Многократное нажатие на педаль выдавливает воду и масло из ресиверов и загрязняет тормозные магистрали","Многократное нажатие на педаль нагнетает избыток воздуха, который включает пружинные тормоза, пока вы ещё едете"],"explanation":"Частое нажатие тормозов на длинном спуске выпускает воздух быстрее, чем компрессор его восполняет, и давление может упасть до потери торможения."},"195":{"q":"Я заехал на своём автопоезде на площадку для отдыха на 30-минутный перерыв. Чтобы удержать машину на месте, пока меня нет в кабине, я тянусь к ручному крану управления тормозами прицепа и включаю его. Почему это НЕПРАВИЛЬНЫЙ способ зафиксировать автопоезд?","options":["Ручной кран включает пружинные тормоза прицепа, которые могут перегреться и заклинить, пока машина стоит на стоянке","Ручной кран отпускает красную восьмиугольную кнопку подачи воздуха к прицепу, поэтому тягач сам покатится вперёд","Ручной кран подаёт на тормоза прицепа только рабочее давление воздуха, а этот воздух со временем может стравиться, и автопоезд покатится","Ручной кран подаёт воздух только на управляемую ось, поэтому колёса ведущей оси и прицепа остаются полностью без тормозов"],"explanation":"Ручной кран прицепа подаёт только рабочий воздух, который со временем стравливается и позволяет машине покатиться, поэтому парковаться нужно на пружинных тормозах."},"196":{"q":"Во время предрейсового осмотра одиночного тягача я нагнетаю давление в воздушной системе примерно до 125 psi, затем глушу двигатель и отпускаю тормоза. Колёса уже заблокированы башмаками, а предупреждение о низком давлении не горит. В чём именно смысл того, что на этом шаге двигатель глушится?","options":["Чтобы я мог несколько раз нажать на педаль тормоза и убедиться, что давление быстро восстанавливается","Чтобы заставить пружинные (стояночные) тормоза автоматически сработать и проверить, что они включаются в диапазоне 20–45 psi","Чтобы слить конденсат из влагоотделителя (мокрого бака) без того, чтобы компрессор включался и нагнетал больше масла и воды","Чтобы компрессор перестал подавать воздух и я мог засечь время падения давления и проверить скорость утечки"],"explanation":"Выключение двигателя останавливает подачу воздуха компрессором, позволяя засечь падение давления и точно измерить скорость утечки."},"197":{"q":"Во время предрейсового осмотра инструктор просит меня объяснить, что именно прижимает тормозные колодки к барабанам, когда я нажимаю на педаль тормоза. Двигатель работает, система полностью заряжена. Какой ответ правильно описывает форму накопленной энергии, на которую полагаются мои тормоза для выполнения этой работы?","options":["Сжатый воздух, хранящийся в ресиверах, который выпускается для приведения тормозов в действие","Гидравлическая жидкость под давлением главного цилиндра, как в тормозах легкового автомобиля","Электрический ток от аккумулятора, подаваемый на магниты у каждого колеса","Давление моторного масла, направленное из системы смазки к тормозам"],"explanation":"Пневматическая тормозная система хранит энергию в виде сжатого воздуха в баллонах, который выпускается для приведения тормозов в действие."},"198":{"q":"Во время предрейсового осмотра я запускаю двигатель и слежу за манометром на панели. Моей двухконтурной пневмосистеме требуется гораздо больше времени, чем положенные 45 секунд для набора давления с 85 до 100 psi, и оно поднимается вяло. Что из перечисленного является НАИБОЛЕЕ вероятной причиной такого медленного набора давления?","options":["Зуммер предупреждения о низком давлении срабатывает слишком рано, ниже 60 psi","Неисправный воздушный компрессор или утечка воздуха где-то в системе","Регулятор отсечки настроен слишком высоко, около уставки сброса в 150 psi","У тормозных регуляторов (трещоток) слишком большой ход штока и свободный люфт"],"explanation":"Слишком медленный набор давления, не достигающий 85-100 psi за 45 секунд, указывает на неисправный компрессор или утечку в системе."},"199":{"q":"Во время предрейсового осмотра я слышу громкий свист выходящего воздуха из предохранительного клапана на питающем (влажном) ресивере, пока двигатель работает и компрессор нагнетает воздух. Из перечисленного, от какого именно состояния этот клапан предназначен защищать ресиверы?","options":["От того, что сигнал низкого давления воздуха не включится до падения давления ниже 60 psi","От того, что регулятор (губернатор) не включит компрессор снова, когда давление упадёт примерно до 100 psi","От слишком высокого давления воздуха в системе; клапан настроен на открытие примерно при 150 psi","От того, что компрессор не поднимет давление с 85 до 100 psi за 45 секунд"],"explanation":"Предохранительный (сбросной) клапан в питающем баке открывается примерно при 150 psi, защищая систему от избыточного давления воздуха."},"200":{"q":"Я пересаживаюсь со своего личного пикапа с гидравлическими тормозами на грузовик класса B, оснащённый пневматической тормозной системой. Во время предрейсового осмотра я пытаюсь понять основное различие в том, как тормозное усилие достигает тормозов на каждом колесе. Какое утверждение правильно определяет, что физически передаёт усилие, приводящее в действие тормоза в моём автомобиле с пневматическими тормозами?","options":["Гидравлическая жидкость в главном цилиндре дополнительно сжимается, а затем направляется в тормозные камеры, чтобы прижать колодки","Давление моторного масла нарастает и отводится по тормозным магистралям, чтобы прижать регулировочные рычаги к барабанам","Электрический сигнал от педали тормоза запитывает электромагниты на каждом колесе, которые вытягивают тормозные колодки наружу","Сжатый воздух, хранящийся в баллонах и выпускаемый педалью, проходит по магистралям и создаёт усилие в тормозных камерах"],"explanation":"Пневматические тормоза используют сжатый воздух из баков, который при нажатии педали идёт по магистралям к тормозным камерам для создания тормозного усилия."},"201":{"q":"Я только что пересел с пикапа с гидравлическими тормозами на тягач с полуприцепом и пневматическими тормозами. Когда я впервые резко нажимаю на педаль тормоза, я замечаю, что грузовик НЕ начинает замедляться в тот же миг, как это было с моим старым пикапом. Какое утверждение ЛУЧШЕ всего объясняет это различие между пневматическими и гидравлическими тормозами?","options":["У пневматических тормозов есть встроенная задержка около полусекунды, потому что воздух должен пройти по магистралям, прежде чем тормоза сработают.","Пневматические тормоза вообще не дают тормозного усилия, пока система не достигнет давления отключения регулятора 125 фунтов на кв. дюйм.","Пневматические тормоза срабатывают мгновенно, как гидравлические, поэтому ощущённая задержка была лишь из-за изношенных разрегулированных регулировочных рычагов.","У пневматических тормозов нет обратной связи на педали, поэтому замедление на самом деле началось сразу, хотя я не мог этого почувствовать."],"explanation":"Пневматические тормоза имеют задержку около полусекунды, так как воздуху нужно пройти по магистралям до срабатывания тормозов."},"203":{"q":"Вы везёте груз по сельской автомагистрали Техаса, когда загорается сигнальная лампа низкого давления воздуха и начинает звучать зуммер. Примерно в 19 км впереди есть стоянка для грузовиков, где, как вы знаете, дежурит механик. КРОМЕ одного из перечисленных ниже, все действия являются небезопасной реакцией на это предупреждение. Что нужно сделать правильно?","options":["Сохранять скорость трассы и доехать до стоянки в 19 км впереди, чтобы механик осмотрел систему","Плавно затормозить, снизить скорость и как можно скорее безопасно съехать с дороги и остановиться","Многократно нажимать на педаль тормоза, чтобы восстановить давление в ресиверах, и продолжать движение","Продолжать движение, но сейчас же вытянуть кнопку стояночного тормоза, чтобы пружинные тормоза помогли остановиться позже"],"explanation":"При срабатывании сигнала низкого давления тормозите плавно и съезжайте с дороги, остановившись безопасно, прежде чем автоматически сработают пружинные тормоза."},"204":{"q":"Вы останавливаетесь на красный свет на грузовике с пневматическими тормозами. Горит контрольная лампа низкого давления воздуха и звучит зуммер, а манометр на панели показывает, что давление упало значительно ниже нормального рабочего диапазона. Загорается зелёный, и сзади начинают сигналить. Какое действие правильное?","options":["Медленно проехать перекрёсток, ведь пружинные тормоза срабатывают только при 20 psi, а у вас давление выше","Быстро перестроиться на обочину, пока хватает воздуха, чтобы колёса ещё катились","Остаться на месте и не трогаться, пока давление воздуха не поднимется обратно до нормального диапазона","Слегка несколько раз нажать на педаль тормоза, чтобы компрессор быстрее наполнил баллоны перед началом движения"],"explanation":"Горящий сигнал низкого давления означает, что торможение ненадёжно, поэтому стойте на месте, пока давление не восстановится до нормы."},"205":{"q":"Я веду гружёный автопоезд вниз по длинному крутому спуску и на полпути замечаю, что педаль тормоза становится мягкой, а грузовик почти не замедляется при нажатии. Мои тормоза явно перегреваются и теряют эффективность. Какое из следующих действий для меня НАИЛУЧШЕЕ?","options":["Нажать на педаль тормоза сильнее и удерживать постоянное давление до самого низа спуска, чтобы компенсировать потерянную тормозную силу","Быстро прокачивать педаль тормоза, чтобы восстановить ощущение педали и вернуть утраченную тормозную способность","Включить более высокую передачу, чтобы двигатель свободно вращался и грузовик плавно катился до низа спуска","Перейти на пониженную передачу для торможения двигателем и найти ближайшее безопасное место, чтобы съехать и остановить грузовик"],"explanation":"Если на длинном спуске пневматические тормоза начинают слабеть, переключитесь на пониженную передачу для торможения двигателем и остановитесь в ближайшем безопасном месте."},"206":{"q":"Я припарковал гружёный тягач с прицепом на небольшом уклоне и поставил стояночный тормоз жёлтой кнопкой. Пока я оформляю документы, двигатель заглушён, а давление воздуха в баллонах медленно падает ниже 45 psi в сторону нуля. Что на самом деле удерживает мой автопоезд от скатывания и почему он держит, даже когда воздух стравливается?","options":["Мощные пружины в тормозных камерах механически зажимают тормоза, поэтому удерживающее усилие сохраняется по мере стравливания воздуха","Воздух, запертый под давлением внутри тормозных камер, прижимает колодки к барабанам","Двигатель и коробка передач удерживают колёса за счёт компрессии после остановки","Жёлтая кнопка механически фиксирует тягу тормозного крана в нажатом положении, сохраняя усилие на педали"],"explanation":"Стояночные и аварийные тормоза удерживаются мощными пружинами в пружинных тормозных камерах, поэтому они держат даже при стравливании воздуха."},"207":{"q":"Я еду по шоссе, пневмосистема полностью заряжена до нормального рабочего давления, и я чувствую, что пружинные тормоза НЕ подтормаживают и не срабатывают. Какое утверждение правильно объясняет роль удерживающего давления (hold-off) в этой ситуации?","options":["Удерживающее давление держит пружинные тормоза частично зажатыми, чтобы они срабатывали быстрее при нажатии на педаль.","Удерживающее давление держит пружинные тормоза отпущенными, пока я еду, поэтому они остаются выключенными, пока давление не упадёт слишком низко.","Удерживающее давление постоянно держит пружинные тормоза полностью включёнными, чтобы дублировать рабочие тормоза.","Удерживающее давление полностью убрано из камер, именно поэтому пружинные тормоза кажутся выключенными."],"explanation":"Удерживающее давление воздуха сжимает пружины, держа пружинные тормоза отпущенными во время движения, и они срабатывают только при слишком низком давлении."},"208":{"q":"В конце смены я паркую тягач, глушу двигатель и чувствую, как пружинные тормоза блокируют колёса по мере стравливания воздуха. Стажёр спрашивает, на какую тормозную функцию воздушной системы я только что положился, чтобы удержать грузовик. Какой ответ верный?","options":["Функция рабочего тормоза, ведь именно педаль удерживает припаркованный автомобиль после выключения двигателя","Функция модуляции, ведь пружинные тормоза срабатывают постепенно, когда давление воздуха падает ниже 60 psi","Стояночная/аварийная функция, ведь пружинные тормоза срабатывают автоматически и удерживают автомобиль при потере давления воздуха","Функция предупреждения о низком давлении, ведь именно зуммер и лампа физически зажимают колёса"],"explanation":"Пружинные тормоза автоматически срабатывают, удерживая машину при потере давления воздуха, что является стояночно-аварийной функцией."},"210":{"q":"Во время предрейсового осмотра я открываю капот и замечаю, что мой воздушный компрессор приводится в действие ремнём, а не соединён напрямую с двигателем. Поскольку он ремённый, какой дополнительный элемент я должен особо проверить, который мне НЕ нужно было бы проверять на компрессоре с шестерёнчатым приводом?","options":["Что давление отключения регулятора показывает около 125 psi на манометре","Что из воздушных баллонов слита вода и компрессорное масло","Что сигнальная лампа низкого давления воздуха загорается до 60 psi","Что приводной ремень имеет надлежащее натяжение и не имеет признаков износа"],"explanation":"На компрессоре с ременным приводом проверяйте, что приводной ремень правильно натянут и не изношен, так как у компрессора с шестерённым приводом ремня нет."},"211":{"q":"Во время предрейсового осмотра я замечаю, что один из воздушных ресиверов под прицепом больше не закреплён плотно к монтажному кронштейну и сдвигается, когда я на него надавливаю. Почему этот незакреплённый ресивер является неисправностью, которую я обязан устранить до начала движения?","options":["Ресивер может тереться о детали автомобиля или расшататься и отвалиться от грузовика","Ресивер будет забирать лишний воздух у компрессора и заставит регулятор отключиться раньше времени","Ресивер будет удерживать меньше сжатого воздуха, поэтому сигнал низкого давления сработает раньше","Ресивер сам сольёт воду и масло, так что ежедневно сливать будет нечего"],"explanation":"Незакреплённый воздушный ресивер может вибрировать и тереться о детали машины либо отсоединиться и упасть с грузовика."},"212":{"q":"Вы загнали свой грузовик с пневматическими (воздушными) тормозами на ровную асфальтированную площадку у топливной колонки и заглушили двигатель. Манометры показывают полное давление в системе, и вы собираетесь выйти из кабины, чтобы начать заправку. Какое действие вы обязаны выполнить, прежде чем покинуть кабину?","options":["Оставить грузовик на самой низкой передней передаче и положиться на компрессию двигателя для удержания","Вытянуть жёлтую ромбовидную кнопку, чтобы включить стояночные (пружинные) тормоза","Удерживать грузовик, постоянно и крепко нажимая ногой на педаль рабочего тормоза","Вытянуть красную восьмиугольную кнопку, чтобы перекрыть линию подачи воздуха к прицепу"],"explanation":"Перед выходом из кабины всегда включайте стояночный (пружинный) тормоз, вытягивая жёлтую ромбовидную кнопку."},"213":{"q":"Я новый водитель и выбираю между двумя подержанными грузовиками: тяжёлым тягачом с прицепом, рассчитанным на перевозку груза почти на максимальную полную массу, и лёгким развозным фургоном. Механик говорит мне, что большой тягач использует пневматические (воздушные) тормоза, а фургон — гидравлические. Я хочу понять, почему тяжёлые коммерческие транспортные средства изначально оснащают воздушными тормозами. Какое утверждение ЛУЧШЕ всего объясняет, почему воздушные тормоза являются стандартным выбором для больших, тяжело гружёных грузовиков?","options":["Воздушные тормоза сокращают общий тормозной путь грузовика, поэтому полностью гружёный тягач останавливается на меньшем расстоянии, чем с гидравлическими тормозами","Воздушные тормоза выбирают в основном потому, что это самая дешёвая тормозная система для установки, и их баллоны никогда не нужно сливать или обслуживать","Воздушные тормоза используют сжатый воздух, а не фиксированный объём жидкости, поэтому они продолжают эффективно работать даже на крупных транспортных средствах, перевозящих тяжёлые грузы","Воздушные тормоза полностью устраняют запаздывание срабатывания, позволяя гружёному грузовику реагировать в тот же миг, как нажата педаль, без задержки в магистралях"],"explanation":"Пневматические тормоза используют постоянно пополняемый сжатый воздух вместо фиксированного объёма жидкости, поэтому они эффективно тормозят тяжёлые, полностью гружёные машины."},"214":{"q":"Я стою на уклоне и решаю вытянуть жёлтую кнопку стояночного тормоза (включая пружинные тормоза), при этом ВСЁ ЕЩЁ сильно удерживая педаль рабочего тормоза. Водитель рядом советует мне сначала отпустить педаль. Почему сильное одновременное применение рабочих и пружинных тормозов является проблемой?","options":["Это совершенно безвредно и даже даёт дополнительную удерживающую силу, поэтому нет причин сначала отпускать педаль рабочего тормоза","Это заставляет сигнал о низком давлении воздуха срабатывать раньше, ниже отметки 60 psi, и быстрее опустошает ресивер","Это экономит большое количество воздуха, потому что обе системы используют одно и то же накопленное давление при совместном применении","Тормозные усилия складываются и суммируются, и эта совокупная сила может создать чрезмерную нагрузку и повредить тормозные компоненты"],"explanation":"Сильное нажатие на рабочий тормоз при включённом пружинном тормозе складывает обе силы, создавая чрезмерную нагрузку, которая может повредить тормозные узлы."},"215":{"q":"Я ставлю тягач на стоянку и вытягиваю жёлтую кнопку, чтобы включить пружинные (стояночные) тормоза. По привычке я всё ещё сильно жму на педаль тормоза, поэтому воздух одновременно подаётся в те же тормозные камеры. Механик предупредил, что без определённого клапана приложение обеих сил вместе может сложиться и повредить тормоза. Какой клапан защищает от этой суммарной, «двойной» силы?","options":["Антикомпаундный клапан, который не даёт силе пружинных тормозов и силе воздушного привода сложиться на одних и тех же тормозах","Модулирующий управляющий клапан, который позволяет включать пружинные тормоза постепенно, чтобы две силы не накладывались","Предохранительный клапан, который открывается примерно при 150 psi и стравливает лишнее давление от двойного приложения","Клапан подачи воздуха в прицеп — красная восьмиугольная кнопка, которая отключает воздух к задним тормозам при двойном включении"],"explanation":"Антикомпаундный клапан сбрасывает давление подачи воздуха при включённом пружинном тормозе, чтобы две тормозные силы не складывались."},"216":{"q":"Во время предрейсового осмотра я выполняю проверки пневматических (воздушных) тормозов на тягаче с прицепом. Я хочу подтвердить, какое устройство ОБЯЗАНО предупредить меня в тот момент, когда давление воздуха в системе падает слишком низко (прежде чем оно опустится ниже 60 psi), чтобы я успел остановиться, пока ещё есть тормозная способность. Какое средство система обязана использовать, чтобы подать мне это предупреждение?","options":["Стрелка манометра, медленно опускающаяся вниз, за которой я обязан внимательно следить всю поездку","Предупреждающая лампа и/или зуммер, которые срабатывают до того, как давление упадёт ниже 60 psi","Пружинные (стояночные) тормоза, автоматически срабатывающие, чтобы физически вынудить меня остановиться","Предохранительный клапан, с громким шипением стравливающий воздух, как только давление становится слишком низким"],"explanation":"Машина с пневмотормозами должна иметь сигнальную лампу низкого давления воздуха, обычно и зуммер, срабатывающие до падения давления ниже 60 psi."},"217":{"q":"Я стою на холостом ходу на стоянке для грузовиков и слежу за манометром давления воздуха после полной зарядки системы. Стрелка постоянно колеблется: она поднимается, регулятор отключает компрессор, стрелка медленно немного опускается, затем регулятор снова включает компрессор и поднимает давление. Я хочу убедиться, что мой воздушный компрессор справляется с нагрузкой. Какое поведение манометра показывает, что компрессор выполняет свою работу?","options":["Манометр продолжает подниматься выше 150 psi, и предохранительный клапан стравливает воздух, доказывая, что у компрессора есть большой запас мощности","Манометр медленно опускается до самого нуля, а затем компрессор быстро наполняет систему одним рывком","Стрелка остаётся в пределах нормального рабочего диапазона, циклически переходя между включением и отключением регулятора по мере расходования и восполнения давления","Манометр держится абсолютно неподвижно на одном фиксированном значении psi и не двигается, показывая, что регулятор зафиксировал давление в системе"],"explanation":"Исправный компрессор удерживает давление в нормальном диапазоне, циклически переключаясь между отключением регулятора (около 125 psi) и включением (около 100 psi) по мере расхода и пополнения воздуха."},"219":{"q":"Я провожу предрейсовый осмотр одиночного тягача и оставляю двигатель работать на холостом ходу, чтобы накачать воздух. Я хочу полностью зарядить систему перед выездом, поэтому смотрю на манометр на панели и жду, когда регулятор компрессора отключится и прекратит подачу воздуха. При каком примерно давлении это должно произойти?","options":["Около 100 psi — точка, где регулятор включается и снова начинает накачивать воздух","Около 60 psi — где гаснут сигнальная лампа и зуммер низкого давления воздуха","Около 150 psi — где открывается предохранительный клапан, чтобы сбросить лишний воздух","Около 125 psi — где регулятор отключается и компрессор прекращает подачу воздуха"],"explanation":"Полностью заряженная система находится на давлении отключения регулятора, около 125 psi, при котором компрессор прекращает накачку воздуха."},"220":{"q":"Вы ведёте автопоезд, и вдруг прицеп отрывается от тягача, а его воздушная магистраль обрывается, полностью стравливая воздух из тормозной системы прицепа. Что произойдёт с оторвавшимся прицепом?","options":["Его пружинные (аварийные) тормоза сработают автоматически по мере падения давления воздуха, замедляя и останавливая прицеп","Его рабочие тормоза будут держать только до тех пор, пока вы держите ногу на педали тормоза в тягаче","Он покатится свободно без торможения, так как потеря воздуха также отпускает стояночные тормоза прицепа","С ним ничего не произойдёт, пока вы не вытянете красную ручку подачи воздуха к прицепу, чтобы включить тормоза"],"explanation":"Пружинные тормоза удерживаются в отпущенном состоянии давлением воздуха, поэтому при отрыве прицепа и потере воздуха они срабатывают автоматически и останавливают прицеп."},"221":{"q":"Вы ведете одиночный грузовик (без прицепа) с пневматической тормозной системой, и вдруг крупный разрыв магистрали полностью выпускает весь воздух из системы, а стрелки манометров падают до нуля. Вы не нажимали на педаль тормоза и не трогали орган стояночного тормоза. Что произойдет с грузовиком?","options":["Он покатится свободно без торможения, потому что потеря воздуха также растормаживает пружинные тормоза, и вы продолжаете катиться.","Он остановится сам собой, потому что пружинные тормоза срабатывают автоматически, как только давление воздуха падает достаточно низко.","Он продолжит ехать как обычно, и вы просто теряете рабочие тормоза, но рулевое управление и стояночный тормоз все еще работают.","Он теряет только усилитель, поэтому тормоза все еще работают, но педаль становится намного тяжелее при нажатии."],"explanation":"Пружинные тормоза удерживаются в отпущенном состоянии давлением воздуха, поэтому полная потеря воздуха включает их автоматически и останавливает машину."},"222":{"q":"Во время предрейсового осмотра тягача с прицепом я замечаю, что у одного переднего тормоза регулировочный рычаг имеет больший ход штока, чем остальные, поэтому этот тормоз работает меньше, а остальные больше. Приятель говорит, что это не важно. Что САМОЕ важное я теряю, когда тормоза не отрегулированы и больше не распределяют нагрузку равномерно?","options":["Лучшую экономию топлива, потому что равномерно работающие тормоза снижают сопротивление двигателя","Более быстрое нарастание давления воздуха с 85 до 100 psi во время проверки","Хорошую балансировку тормозов, чтобы машина останавливалась прямо, не уводя в сторону","Более сильное торможение двигателем при пониженной передаче на длинном спуске"],"explanation":"Когда все тормоза правильно отрегулированы и нагрузка распределена равномерно, баланс тормозов обеспечивает прямую остановку без увода в сторону."},"223":{"q":"Я провожу предрейсовый осмотр своего тягача с прицепом. Двигатель работает, и давление воздуха в баках нарастает. Прежде чем отпустить стояночный тормоз и выехать со стоянки, какое МИНИМАЛЬНОЕ давление воздуха в системе должно быть, чтобы ехать безопасно?","options":["Не менее примерно 60 psi, так как при этом значении гаснет сигнал предупреждения о низком давлении воздуха","Не менее примерно 20 psi, так как при этом значении пружинные тормоза растормаживаются и машина может катиться","Не менее примерно 125 psi, так как ехать небезопасно, пока регулятор не достигнет давления отключения","Не менее примерно 100 psi, так как это минимальное давление, необходимое для торможения и безопасной езды"],"explanation":"Перед началом движения необходимо накачать минимум около 100 psi, так как это минимальное давление воздуха для безопасного торможения и вождения."},"224":{"q":"Я езжу на одном и том же надёжном тягаче с прицепом по короткому маршруту доставки протяжённостью 40 миль, который выполняю несколько раз в день. Сегодня утром машина прошла полную проверку пневматических тормозов без замечаний, и после обеда я её не трогал. Садясь в кабину, чтобы начать дневной рейс, какой подход к проверке пневматических тормозов является правильным?","options":["Снова выполнить проверку пневматических тормозов перед этим дневным рейсом, как и перед любым рейсом","Пропустить проверку на этот раз, поскольку полная проверка той же машины уже была пройдена ранее сегодня","Повторять проверку только в том случае, если во время утреннего рейса срабатывала лампа или зуммер низкого давления воздуха","Подождать и повторно проверить тормоза раз в неделю или примерно через каждые 1000 миль пробега"],"explanation":"Проверку пневмотормозов нужно выполнять перед каждой поездкой, так как состояние тормозов, утечка воздуха и регулировка зазоров могут меняться между поездками."},"225":{"q":"Во время предрейсового осмотра я замечаю, что у регулировочных рычагов (трещоток) тормозов моего тягача слишком большой свободный ход, то есть тормоза разрегулированы. Если я всё равно поеду, не устранив это, чего мне следует ожидать на дороге?","options":["Тормоза начнут схватывать сильнее и остановят грузовик на более коротком расстоянии","Тормоза потеряют эффективность, и грузовик будет хуже останавливаться","Система будет экономить воздух, поэтому компрессор будет включаться гораздо реже","Тормозные накладки и барабаны будут изнашиваться намного медленнее со временем"],"explanation":"Чрезмерный ход штока из-за нерегулированных регулировочных рычагов снижает тормозное усилие, поэтому грузовик хуже останавливается."},"226":{"q":"Во время предрейсового осмотра я замечаю, что тормозной шланг проложен так, что он прижимается к острому кронштейну на раме, и его наружная поверхность стёрта в месте контакта с металлом. Почему эта находка важна для моей пневматической тормозной системы?","options":["Контакт со временем затягивает соединение, поэтому это фактически снижает вероятность того, что соединение ослабнет","Трение упрочняет резину, позволяя шлангу выдерживать более высокое давление, чем остальная часть системы","Постоянное трение может протереть шланг насквозь, пока он не разрушится и не начнёт пропускать воздух","Для тормозов ничего не меняется, но трение может ускорить охлаждение именно в этом месте"],"explanation":"Тормозной шланг, трущийся о деталь, изнашивается от постоянного трения, пока не протрётся насквозь и не начнёт пропускать воздух."},"227":{"q":"Во время предрейсового осмотра мой одиночный тягач полностью накачан примерно до 125 psi. Я глушу двигатель, оставляю тормоза отпущенными и слежу за манометром. Давление падает более чем на 2 psi за одну минуту, и я нахожу источник тихого шипения у тормозной камеры, где в резиновой диафрагме есть небольшой разрыв. Что эта порванная диафрагма делает с моей пневмосистемой?","options":["Она усиливает давление на шток, давая этому колесу дополнительную тормозную мощность","Это важно только при нажатых тормозах, поэтому при отпущенных тормозах это не имеет реального значения","Она помогает колодкам плотнее прижиматься к барабану на этом колесе во время остановки","Она выпускает сжатый воздух наружу, поэтому скорость утечки слишком высокая"],"explanation":"Порванная диафрагма тормозной камеры выпускает сжатый воздух через отверстие вместо торможения, повышая уровень утечки."},"228":{"q":"Во время предрейсового осмотра моего тягача с прицепом скорость утечки воздуха не проходит проверку—давление падает намного быстрее предела даже при выключенном двигателе и отпущенных тормозах. Я замечаю слабое шипение прямо там, где соединяются воздушные магистрали тягача и прицепа. Какая неисправность является НАИБОЛЕЕ вероятной причиной того, что я слышу, и провала теста на утечку?","options":["Изношенные уплотнения соединительных головок (glad hands) пропускают воздух в месте соединения магистралей тягача и прицепа","Регулировочный рычаг (slack adjuster) разрегулирован, что вызывает чрезмерный ход штока в одной из тормозных камер","Предохранительный клапан открылся, потому что давление в ресивере превысило 150 psi во время зарядки","Регулятор не достиг давления отключения, поэтому компрессор не прекратил нагнетать воздух в систему"],"explanation":"Изношенные уплотнения соединительных головок пропускают воздух в месте стыковки воздушных магистралей тягача и прицепа, вызывая шипение и чрезмерную утечку."},"229":{"q":"Я только что сцепил тягач с груженым прицепом и подсоединил воздушные шланги. Воздушные баки прицепа все еще пустые, и мне нужно подать воздух обратно в прицеп, чтобы зарядить его тормозную систему перед проверкой тормозов. Сидя в кабине, какой орган управления я использую, чтобы подать воздух в прицеп?","options":["Я вытягиваю желтую ромбовидную кнопку, чтобы подать давление на прицеп","Я вдавливаю красную восьмиугольную кнопку, чтобы подать воздух обратно в прицеп","Я нажимаю и удерживаю педаль рабочего тормоза, чтобы прокачать воздух по магистралям","Я вытягиваю красную восьмиугольную кнопку, чтобы открыть линию подачи воздуха в прицеп"],"explanation":"Нажатие на красную восьмиугольную кнопку подачи воздуха в прицеп направляет воздух от тягача для зарядки тормозной системы прицепа."},"230":{"q":"Я веду тягач с прицепом, когда утечка в системе приводит к падению давления воздуха значительно ниже уровня, необходимого для удержания клапана подачи воздуха к прицепу в открытом положении. Если я ничего не трогаю на приборной панели, что должно произойти с красной восьмиугольной кнопкой подачи воздуха к прицепу?","options":["Останется на месте, вдавленной, так как тормоза прицепа реагируют только на ножную педаль","Загорится и подаст звуковой сигнал, но останется вдавленной, пока я не вытяну её рукой","Сама выскочит и закроется, автоматически включив аварийные тормоза прицепа","Вдавится ещё глубже, чтобы перекрыть прицеп и сохранить оставшееся давление воздуха"],"explanation":"Если давление воздуха падает слишком низко, красная восьмиугольная кнопка выскакивает сама и закрывается, автоматически включая аварийные тормоза прицепа."},"231":{"q":"Во время предрейсового осмотра механик сообщает мне, что на одной оси моего тягача установлены тормозные камеры большего размера, чем на остальных, а едущий со мной новичок спрашивает, какую разницу это даёт при нажатии на педаль тормоза. По сравнению с камерами меньшего размера, что на самом деле даёт тормозная камера большего размера на этой оси?","options":["Она смягчает ощущение от педали, потому что большая камера вмещает больше воздуха до того, как сдвинется шток","Она снижает тормозное усилие, потому что большая камера отводит давление воздуха от регулировочного рычага","Она вообще не меняет торможение, так как размер камеры влияет только на скорость повторного наполнения воздухом","Она даёт большее тормозное усилие, потому что большая камера давит на регулировочный рычаг с большей силой"],"explanation":"Большая тормозная камера имеет большую площадь воздействия воздуха, толкая регулировочный рычаг с большей силой и создавая больше тормозного усилия."},"232":{"q":"Во время предрейсового осмотра я нажимаю на педаль тормоза и наблюдаю, как поворачивается S-образный кулак (S-cam) барабанного тормоза на ведущем мосту. Когда S-кулак поворачивается, что именно он делает внутри тормозного механизма, чтобы замедлить колесо?","options":["Раздвигает тормозные колодки наружу, чтобы их накладки прижались к внутренней поверхности тормозного барабана","Тянет тормозные колодки внутрь, от барабана, чтобы возвратные пружины могли их отпустить","Поворачивает регулятор зазора (трещотку), чтобы выбрать свободный ход штока перед началом торможения","Стравливает воздух из тормозной камеры, чтобы пружинные тормоза сработали против барабана"],"explanation":"Вращающийся S-кулак раздвигает тормозные колодки наружу, прижимая их накладки к внутренней поверхности крутящегося тормозного барабана для замедления колеса."},"233":{"q":"Во время предрейсового осмотра я проверяю тормозные механизмы на тягаче, оснащённом воздушными дисковыми тормозами вместо более распространённых барабанных. Глядя на колёсный узел, я вижу суппорт, охватывающий плоскую вращающуюся металлическую деталь, которую суппорт сжимает, чтобы замедлить колесо. Чтобы правильно описать эту систему воздушных дисковых тормозов при осмотре, деталь, которую зажимает суппорт, — это:","options":["Тормозной барабан, к которому колодки прижимаются изнутри наружу","Ротор (диск), который суппорт сжимает, создавая трение","Камера пружинного (стояночного) тормоза, создающая давление","Регулятор зазора (трещотка), к которому движется шток"],"explanation":"Дисковые тормоза используют суппорт, который прижимает фрикционные колодки к вращающемуся ротору (диску) на ступице колеса, создавая трение для замедления колеса."},"234":{"q":"Во время предрейсового осмотра механик указывает на большую тормозную камеру на моём грузовике и называет её камерой 'макси', говоря, что она НЕ использует давление воздуха для выталкивания штока и остановки колеса так, как это делает меньшая камера. Исходя из того, как этот компонент работает на самом деле, чем является камера 'макси'?","options":["Это рабочий тормоз, поскольку камера 'макси' — это часть, которая создаёт тормозное усилие каждый раз, когда я нажимаю на педаль при обычной езде","Это модулирующий управляющий клапан, поскольку камера 'макси' позволяет мне плавно подавать давление на заднюю ось в аварийной ситуации","Это пружинный тормоз, поскольку камера 'макси' содержит мощную пружину, которая приводит тормоза в действие при сбросе или потере давления воздуха","Это узел подачи воздуха в прицеп, поскольку камера 'макси' подаёт и пополняет воздух в баки прицепа во время движения"],"explanation":"Камера maxi (пружинный тормоз) содержит мощную сжатую пружину, которая включает тормоза при сбросе или потере давления воздуха, а не выдвигает шток подаваемым воздухом."},"235":{"q":"Я стою у погрузочной платформы, давление в системе полностью накачано примерно до 125 psi, утечек нет. Помимо падения давления воздуха до диапазона 20-45 psi, каким ДРУГИМ способом можно привести в действие мои пружинные тормоза?","options":["Нажав и удерживая педаль рабочего тормоза до упора в пол","Включив переключатель сигнализации антиблокировочной системы (ABS)","Раскрутив двигатель, чтобы регулятор достиг отсечки при 125 psi","Вытянув жёлтую ромбовидную рукоятку управления стояночным тормозом"],"explanation":"Пружинные тормоза включаются вручную вытягиванием жёлтой ромбовидной ручки управления стояночным тормозом."},"236":{"q":"Морозное зимнее утро в Техасском Панхендле, и мой тягач с прицепом оснащён спиртовым испарителем в системе пневматических (воздушных) тормозов. Когда я провожу предрейсовый осмотр и начинаю движение, какую ГЛАВНУЮ задачу выполняет это устройство в такую холодную погоду?","options":["Подаёт спирт в воздушную систему, чтобы не образовывался лёд и не забивались воздушные тормозные магистрали и клапаны","Поддерживает тормозные барабаны и накладки тёплыми, чтобы рабочие тормоза не теряли тормозную силу","Удаляет воду и масло компрессора из ресиверов, чтобы их больше не нужно было сливать ежедневно","Повышает давление отключения регулятора, чтобы компрессор быстрее нагнетал воздух на холоде"],"explanation":"Спиртовой испаритель добавляет спирт в воздушную систему, понижая точку замерзания влаги и не давая льду образовываться и забивать тормозные магистрали и клапаны в холод."},"238":{"q":"Во время предрейсового осмотра я оставляю двигатель работать и слежу за манометром, давление в котором растёт. Оно достигает примерно 125 psi, и стрелка перестаёт подниматься, хотя двигатель продолжает работать. Регулятор (губернатор) только что достиг своей точки отключения (cut-out). Что именно делает сам компрессор в этот момент?","options":["Он полностью отключился вместе с двигателем и снова запустится только тогда, когда давление упадёт примерно до 60 psi","Он продолжает вращаться, но перестаёт нагнетать воздух в баллоны (перешёл в режим холостого хода) до падения давления примерно до 100 psi","Он нагнетает ещё сильнее, чтобы поднять давление до уставки предохранительного клапана в 150 psi","Он заклинивает и стравливает лишний воздух через предохранительный клапан, чтобы защитить баллоны"],"explanation":"При точке отсечки регулятора (около 125 psi) компрессор продолжает вращаться, но разгружается и не подаёт воздух в баки, пока давление не упадёт до точки включения около 100 psi."},"239":{"q":"Я только что отцепил прицеп на площадке и веду тягач обратно на терминал без прицепа (бобтейл). По дороге есть длинный ровный участок, открытая гравийная площадка, через которую я срезаю путь, пара въездных рамп на шоссе и плавный поворот у съезда. Где мне нужно быть НАИБОЛЕЕ осторожным и снижать скорость, потому что тягач без прицепа здесь плохо управляется?","options":["На длинном ровном участке, ведь более лёгкий тягач позволяет ехать быстрее обычного","На открытой гравийной площадке, ведь рыхлая поверхность — единственное место, где бобтейл теряет сцепление","На поворотах и въездных рампах, где тягач без прицепа (бобтейл) может плохо управляться","Нигде особенно, ведь бобтейл без прицепа тормозит и проходит повороты лучше"],"explanation":"Тягач без прицепа (bobtail) лишён веса прицепа над ведущими осями и плохо управляется, поэтому дополнительно сбавляйте скорость на поворотах и въездах, где силы наибольшие."},"240":{"q":"Я завершаю предрейсовый осмотр тягача с прицепом на стоянке. Я уже слил воздух из ресиверов, убедился, что регулятор отключает компрессор около 125 psi, и проверил, что предупреждение о низком давлении воздуха включается до падения ниже 60 psi. Прежде чем выехать на дорогу, что из перечисленного я ещё обязан сделать в отношении фонарей в задней части моего автомобиля?","options":["Убедиться, что задние светоотражатели свежепокрашены, чтобы другие водители видели их ночью","Убедиться, что корпуса задних фонарей закрыты крышками для защиты ламп от дорожного мусора","Убедиться, что задние габаритные огни сняты для снижения нагрузки на электросеть","Убедиться, что стоп-сигналы действительно загораются, когда я нажимаю на педаль тормоза"],"explanation":"При предрейсовом осмотре необходимо убедиться, что стоп-сигналы действительно загораются при нажатии на педаль тормоза, чтобы движущиеся сзади видели, что вы тормозите."},"241":{"q":"Во время предрейсового теста торможения на скорости около 5 миль/ч я нажимаю на педаль тормоза, и грузовик резко уводит вправо, а педаль схватывает неравномерно перед остановкой. Какой вывод верен?","options":["Тормоза неисправны, и автомобиль нуждается в обслуживании, прежде чем на нем можно будет ехать","Это нормальное запаздывание тормозов, я могу отпустить педаль и продолжить рейс","Просто слишком высокое давление воздуха, нужно стравить ресиверы и повторить тест","Это работает АБС, прихватывая одно колесо, поэтому никаких действий не требуется"],"explanation":"При тесте тормозов на скорости 5 миль/ч тормоза, уводящие в сторону или схватывающие неравномерно, неисправны, и машину нельзя эксплуатировать до ремонта."},"242":{"q":"Во время предрейсового осмотра я залезаю под прицеп, чтобы проверить колёсные тормозные механизмы (foundation brakes) у каждого колеса. Я уже убедился, что тормозные барабаны и тормозные колодки в хорошем состоянии. Чтобы завершить осмотр именно компонентов колёсного тормозного механизма, какую деталь мне следует проверить дальше?","options":["Жёлтую ромбовидную кнопку стояночного тормоза в кабине","Регулировочные рычаги (slack adjusters), соединённые со штоком каждой тормозной камеры","Регулятор давления (губернатор), управляющий включением и выключением компрессора","Предохранительный клапан, установленный на питающем (влажном) ресивере"],"explanation":"Регулировочные рычаги (slack adjusters) соединяют шток каждой тормозной камеры с тормозным механизмом, преобразуя ход штока в тормозное усилие на колесе."},"243":{"q":"Во время предрейсового осмотра я соединяю соединительные головки (glad hands) тягача и прицепа, накачиваю воздушную систему примерно до 125 psi и глушу двигатель. Наклонившись к месту сцепки, я отчётливо слышу ровное шипение, исходящее от одного из соединений соединительных головок. О чём это шипение ВЕРОЯТНЕЕ ВСЕГО говорит применительно к этому соединению?","options":["Уплотнение полностью герметично, и соединение прошло проверку","Дополнительное давление воздуха направляется для усиления тормозов прицепа","Воздух выходит из соединения из-за утечки","Питающая магистраль только что закончила стравливать скопившуюся воду"],"explanation":"Постоянное шипение у соединения шлангов (glad hand) означает, что сжатый воздух выходит через утечку в уплотнении."},"244":{"q":"Я управляю тягачом с прицепом, оснащённым исправной системой ABS (антиблокировочные тормоза), когда легковой автомобиль внезапно останавливается прямо в моёй полосе. Мне нужно остановиться как можно резче, сохраняя контроль над автопоездом. Как правильно использовать тормоза в этой экстренной ситуации?","options":["Быстро прерывисто нажимать и отпускать педаль, чтобы у ABS было время сработать между нажатиями","Сильно нажать, затем отпустить, как только почувствую пульсацию педали, и повторять короткими рывками","Один раз коротко нажать на педаль, чтобы включить ABS, а затем объехать препятствие без дальнейшего торможения","Сильно нажать на педаль и удерживать постоянное давление, позволяя ABS не дать колёсам заблокироваться, чтобы я мог рулить"],"explanation":"При ABS нажимайте на педаль тормоза сильно и удерживайте равномерное давление, чтобы система предотвращала блокировку колёс и вы сохраняли управление рулём."},"245":{"q":"Морозное зимнее утро, и я провожу предрейсовый осмотр тягача с прицепом на пневматических тормозах. Я понимаю, что забыл сливать воздушные баки последние несколько дней, и замечаю влагу вокруг сливных клапанов. Почему это важно для тормозной системы?","options":["Вода и компрессорное масло, скапливающиеся в баках, могут повредить тормозную систему и замёрзнуть в холод, поэтому баки нужно сливать ежедневно","Небольшое количество воды и масла в баках на самом деле смазывает и уплотняет тормозные клапаны, поэтому изредка пропустить слив безопасно","Вода и масло не влияют на торможение, потому что предохранительный клапан автоматически выпускает их примерно при 150 psi","Влага важна только для стояночного тормоза, поэтому, пока рабочие тормоза держат, я могу безопасно отложить слив баков до весны"],"explanation":"Воздушные баллоны нужно сливать ежедневно, потому что в них скапливаются вода и масло компрессора, которые могут повредить тормозную систему или замёрзнуть в холод."},"246":{"q":"Морозное утро, и во время предрейсового осмотра вы замечаете, что за ночь в питающем (мокром) ресивере скопилась вода и немного маслянистого шлама. Какое устройство на этом ресивере нужно задействовать, чтобы удалить это загрязнение, прежде чем оно замёрзнет и повредит систему?","options":["Предохранительный клапан, открыв его вручную для стравливания ресивера","Сливной кран (петкок) в нижней части ресивера","Регулятор давления, отключив его, чтобы сбросить скопившееся","Сброс зуммера предупреждения о низком давлении, чтобы очистить магистраль"],"explanation":"Вода и масло удаляются открытием сливного клапана (petcock), расположенного в нижней части воздушного баллона."},"247":{"q":"Во время предрейсового осмотра я довожу воздушную систему до полного давления. Внезапно я слышу громкий выброс воздуха из предохранительного клапана на питающем (влажном) ресивере. Что это вероятнее всего говорит о моей системе перед поездкой?","options":["Сигнализатор низкого давления отказал, и давление в ресивере незаметно упало ниже 60 psi.","Регулятор (губернатор) сработал на включение раньше времени, и компрессор перестал подавать воздух в ресиверы.","Регулятор (губернатор) не отключился, давление поднялось выше примерно 150 psi, и клапан сбросил его.","Медленная утечка снизила давление до диапазона 20-45 psi и сработали пружинные тормоза."],"explanation":"Если регулятор (governor) не отключает компрессор, давление поднимается выше примерно 150 psi и предохранительный клапан открывается, сбрасывая избыток воздуха."},"248":{"q":"Во время предрейсового осмотра механик в мастерской просит меня проверить, надёжно ли держат \"макси-тормоза\", пока прицеп стоит на стоянке. Мне незнаком этот сленговый термин. Какой именно компонент пневматической тормозной системы он имеет в виду?","options":["Рабочие тормоза, которые я задействую педалью при обычной остановке","Модулирующий клапан, которым я плавно применяю тормоза в аварийной ситуации","Регулировочные рычаги, которые задают величину хода штока","Пружинные тормоза, которые удерживают машину и срабатывают при падении давления воздуха"],"explanation":"Maxi-тормоза — это другое название пружинных тормозов, которые удерживают стоящий автомобиль и срабатывают автоматически при потере давления воздуха."},"249":{"q":"Я пересаживаюсь с легкового автомобиля на гружёный тягач с полуприцепом, оснащённый пневматическими (воздушными) тормозами, и инструктор спрашивает, почему освоение пневматической тормозной системы важнее всего для водителя с CDL. Какой ответ лучше всего отражает главную цель изучения воздушных тормозов?","options":["Чтобы безопасно и под контролем остановить тяжёлое, гружёное транспортное средство","Чтобы машина свободно катилась и разгонялась до более высокой крейсерской скорости","Чтобы снизить расход топлива, удерживая компрессор двигателя в холостом режиме","Чтобы сократить общий тормозной путь по сравнению с гидравлическими тормозами"],"explanation":"Главное назначение пневматической тормозной системы — обеспечить безопасную и контролируемую остановку тяжёлого гружёного автомобиля."}},"tr":{"0":{"q":"Yola çıkış öncesi muayenemde, denetçi tır çekicimdeki hava fren düzenini açıklamamı istiyor. Hava frenlerinin aslında birkaç fren sisteminin tek bir sistemde birleşiminden oluştuğunu söylüyorum. Hangi cevap, bir hava fren sisteminin gerçekte kaç ayrı fren sistemini birleştirdiğini doğru şekilde belirtir ve bunları adlandırır?","options":["Üç sistem: servis frenleri, park frenleri ve acil durum frenleri.","İki sistem: tek kumanda takımına sahip birincil ve ikincil hava sistemleri.","Dört sistem: servis frenleri, park frenleri, acil durum frenleri ve ABS.","Tek sistem: normal duruşları, parkı ve acil durumları birlikte yöneten tek bir devre."],"explanation":"Havalı fren sistemi aslında üç ayrı sistemin birleşimidir: servis frenleri, park frenleri ve acil durum frenleri."},"1":{"q":"Yola çıkış öncesi kontrolü yapıyorum ve gösterge panelindeki manometreyi izlerken hava basıncını yükseltmek için motoru gazlıyorum. Hava kompresörünün depolara hava basmayı durdurduğu basıncı not ederek regülatörün doğru çalıştığını doğrulamak istiyorum. Regülatör devreyi kestiği (cut-out) için ibrenin yükselmeyi durdurması gereken yaklaşık değer nedir?","options":["Yaklaşık 100 psi; kompresörün depolara hava eklemeyi durdurduğu basınç budur","Yaklaşık 125 psi; bu noktada regülatör devreyi keser (cut-out) ve kompresör hava basmayı durdurur","Yaklaşık 150 psi; sistemin maksimuma ulaştığı ve kompresörün kapandığı nokta","Yaklaşık 60 psi; regülatörün dolu bir sistemde kompresörü durdurduğu nokta"],"explanation":"Regülatör yaklaşık 125 psi'de devreyi keserek kompresörün tanklara hava basmasını durdurur."},"2":{"q":"Park halinde sefer öncesi kontrolümü yapıyor ve hava basınç göstergesini izliyorum. Kompresör daha önce devreden çıkmış ve hava basmayı durdurmuştu, bu yüzden sistemi test ederken basınç yavaşça düşüyor. Regülatörün kompresörü tekrar devreye sokup yeniden hava basmaya başlamasını hangi gösterge değerinde beklemeliyim?","options":["Yaklaşık 60 psi, düşük hava basıncı uyarı ışığı ve sesli uyarının devreye girdiği nokta","Yaklaşık 125 psi, regülatörün kompresörün hava basmasını durdurduğu seviye","Yaklaşık 100 psi, regülatörün kompresöre yeniden hava basmaya başlaması için sinyal verdiği nokta","Yaklaşık 150 psi, emniyet tahliye valfinin basıncı boşaltmak için açıldığı seviye"],"explanation":"Regülatörün devreye girme noktası yaklaşık 100 psi'dir; bu noktada kompresörün tekrar hava basması sağlanır."},"3":{"q":"Sefer öncesi kontrolümde, hava kompresörü regülatörünün (governor) devreden çıkmadığını fark ediyorum — gösterge, pompalamanın durması gereken normal 125 psi noktasını geçerek yükselmeye devam ediyor. Regülatör hiç devreden çıkmazsa, sistemi aşırı basınçtan korumak için emniyet tahliye valfi yaklaşık hangi basınçta açılmalıdır?","options":["Yaklaşık 100 psi'de — regülatörün normalde devreye girip pompalamaya yeniden başladığı noktada","Yaklaşık 60 psi'de — düşük hava basıncı uyarı ışığını ve sesli uyarıyı tetikleyen eşikte","Yaklaşık 125 psi'de — iki cihaz birlikte çalışsın diye regülatörün devreden çıkışıyla aynı noktada","Yaklaşık 150 psi'de — sistemin tehlikeli basınca ulaşmasını önlemek için fazla havayı dışarı atarak"],"explanation":"Emniyet supabı yaklaşık 150 psi'de açılarak fazla havayı tahliye eder ve sistemi tehlikeli basınçtan korur."},"4":{"q":"Hava sistemi tam dolu tek bir çekici üzerinde sefer öncesi kontrol yapıyorum. Motor kapalıyken frene basarak havayı kademeli olarak boşaltıyor ve gösterge panelini izliyorum. Düşük hava basıncı uyarı ışığı ve sesli uyarı hangi noktada artık devrede olmalı — yani uyarı, basınç hangi seviyenin altına düşmeden önce ZATEN açık olmalı?","options":["Hava basıncı 60 psi'nin altına düşmeden önce","Hava basıncı 80 psi'nin altına düşmeden önce","Ancak basınç 20–45 psi aralığına düştükten sonra","Hava basıncı 100 psi'nin altına düşmeden önce"],"explanation":"Düşük hava basıncı uyarısı, sistem basıncı 60 psi'nin altına düşmeden önce devreye girmelidir."},"5":{"q":"Yüklü tek bir çekici-römork sürerken bir hat patlıyor ve hava basıncım hızla düşmeye başlıyor. Düşük hava uyarı ışığı ve sesli uyarı zaten devrede ve ibre düşmeye devam ediyor. Yaylı (acil durum) frenlerin kendiliğinden devreye girip beni durdurmasını yaklaşık hangi basınçta beklemeliyim?","options":["Yaklaşık 60 psi, düşük hava uyarısının ilk devreye girdiği noktayla aynı yerde","20 ila 45 psi aralığında bir yerde, uyarı zaten devreye girdikten sonra","Yaklaşık 100 psi, kompresörün yeniden çalıştığı regülatör devreye girme noktasında","Yaklaşık 5 ila 10 psi, ancak depolar neredeyse tamamen boşaldığında"],"explanation":"Yaylı (acil durum/park) frenler, sistem hava basıncı 20 ila 45 psi aralığına düştüğünde otomatik olarak devreye girer."},"6":{"q":"Sefer öncesi kontrolde eğitmenim, servis frenlerini uygulamak için ayağımla bastığım pedalı işaret ediyor ve diğer doğru adını soruyor. Doğru cevaplamak için işaret ettiği parça hangisidir?","options":["Regülatör (governor), çünkü pedalın tekerleklere ne kadar fren havası gönderdiğini kontrol eder","Boşluk ayarlayıcı (slack adjuster), çünkü ayak basıncımı mekanik fren kuvvetine dönüştürür","Ayak (treadle) valfi, çünkü bastığımda servis frenlerine hava gönderir","Glad hand bağlantısı, çünkü fren havamı frenlere taşıyan bağlantıdır"],"explanation":"Fren pedalının doğru adı ayak (pedal) supabıdır; basıldığında servis frenlerine hava gönderir."},"7":{"q":"Dondurucu bir kış sabahında, sefer öncesi kontrolüm sırasında hava tankının altındaki tahliye valfını açıyorum. Havayla birlikte süt gibi, yağlı bir sıvı fışkırıyor. Bir iş arkadaşım, bu sıvının tankta asla bulunmaması gerektiğini, dolayısıyla ciddi bir mekanik arızam olduğunu söylüyor. Ne gördüğümü ve tankları neden her gün boşaltığımı hangi ifade doğru açıklar?","options":["Sadece hava boşalmalı; sıvı, çatlak bir tankın hava beslemesine fren hidroliği sızdırdığı anlamına gelir","Soğutma suyu arızalı bir keçeden tanka sızmıştır, bu yüzden fren odacıklarına ulaşmadan önce boşaltmalıyım","Sızan fren hidroliği havayla karışmıştır ve her gün yapılan tahliye bu sıvıyı sistemden temizler","Sıkıştırılmış hava normalde su ve bir miktar kompresör yağı biriktirir; her gün yapılan tahliye, donmayı ve hasarı önlemek için bunları dışarı atar"],"explanation":"Sıkıştırılmış hava doğal olarak su ve bir miktar kompresör yağı toplar; bu yüzden donma ve hasarı önlemek için tanklar her gün boşaltılmalıdır."},"8":{"q":"Kış sabahı hava donuyor ve kamyonumun besleme (ıslak) tankına monte edilmiş bir hava kurutucusuyla donatıldığını fark ediyorum. Sefer öncesi kontrolde, bu parçanın yaptığı asıl işi hatırlamaya çalışıyorum. Hava kurutucusunun hava frenli sistemim için ne yaptığını EN İYİ hangi ifade açıklar?","options":["Sıkıştırılmış havadaki su ve kirleticileri, bu hava depolama tanklarına ulaşmadan önce giderir","Sıkıştırılmış havayı regülatör kesme basıncının üzerine çıkararak tankların daha yüksek bir çalışma basıncına ulaşmasını sağlar","Tank basıncı 60 psi'nin altına düşmeden önce düşük hava basıncı uyarı ışığını ve sesli uyarıyı tetikler","Uzun ve dik bir inişten sonra ısınan fren kampanalarını ve balatalarını soğutarak fren kaybını önler"],"explanation":"Hava kurutucu, sıkıştırılmış havadaki suyu ve kirleticileri depolama tanklarına ulaşmadan önce giderir."},"9":{"q":"Bir çekici-römork üzerinde sefer öncesi kontrol yapıyorum ve motor regülatör kesme (cut-out) basıncına yeni ulaştı. Gösterge panelini tararken yan yana iki hava göstergesi görüyorum. Frenleri bırakıp yola çıkmadan önce yeterli depolanmış havam olduğunu doğrulamak için, besleme basıncı göstergesindeki (supply pressure gauge) hangi okuma bana ihtiyacım olan bilgiyi verir?","options":["Pedala bastığımda fren körüklerine şu anda gönderdiğim basınç miktarı","Hava depolarında şu anda depolanmış olan hava basıncı miktarı (kesmede yaklaşık 125 psi)","Hava azaldığında yay frenlerinin otomatik olarak devreye gireceği basınç","Emniyet tahliye valfinin sistemi korumak için açılmaya ayarlandığı basınç"],"explanation":"Besleme basınç göstergesi, tanklarda şu anda depolanan hava basıncını gösterir; devre kesmede yaklaşık 125 psi'dir."},"10":{"q":"Yüklü kamyonumla uzun bir yokuştan iniyorum ve hızımı tutmak için fren pedalına daha sert basıyorum. Pedalı (fren valfini) daha derine bastıkça gösterge panelindeki bir gösterge yükseliyor, ayağımı çektiğimde ise tekrar sıfıra doğru düşüyor. Ayağımın pedaldaki hareketine tepki veren hangi göstergeyi izliyorum?","options":["Hava deposu (besleme) basınç göstergesi, çünkü depolarda ne kadar hava kaldığını gösterir","Regülatör kesme göstergesi, çünkü kompresörün yaklaşık 125 psi'de durduğunu gösterir","Uygulama basıncı göstergesi, çünkü frenlere ne kadar hava basıncı uyguladığımı gösterir","Düşük hava basıncı uyarı göstergesi, çünkü basınç 60 psi'nin altına düşmeden önce yanar"],"explanation":"Uygulama basınç göstergesi, fren pedalıyla frenlere gönderdiğiniz hava basıncını gösterir."},"11":{"q":"Sefer öncesi kontrolüm sırasında eğitmenim bir fren grubundaki S-kama (S-cam) işaret ediyor ve fren pedalına bastığım ve hava fren körüğüne ulaştığı anda bu parçada fiziksel olarak ne olduğunu açıklamamı istiyor. Hangi yanıt S-kamanın görevini doğru tanımlar?","options":["Hatların donmaması için hava depolarındaki su ve kompresör yağını dışarı boşaltır","Depolar yaklaşık 125 psi'ye ulaşınca regülatöre kompresörü durdurması için sinyal verir","İtme çubuğundaki boşluğu almak için ayar kolunu (slack adjuster) geri çeker","Döner ve fren pabuçlarını birbirinden ayırarak kampananın iç yüzeyine bastırır"],"explanation":"S-kam döner ve fren pabuçlarının arasına girerek onları kampananın iç yüzeyine doğru iter."},"12":{"q":"Sefer öncesi muayenede düz zemine park ediyorum, tekerleklere takoz koyuyorum, park frenlerini boşa alıyorum ve aşırı itme çubuğu hareketini kontrol etmek için manuel boşluk ayarlayıcısını bir levye ile zorluyorum. Boşluk ayarlayıcısı yaklaşık şu mesafeden FAZLA hareket ederse frenler ayarsızdır:","options":["1 inç, çünkü daha fazla serbest hareket frenlerin ayarsız olduğunu ve fren gücünü kaybettiğini gösterir","3 inç, ki bu frenler ayarsız hale gelmeden önce izin verilen azami harekettir","5 inç, çünkü bundan daha azı frenleri hâlâ uygun ayarda tutar","Serbestçe hareket edebilir, çünkü boşluk ayarlayıcıları herhangi bir hareket sınırı olmadan salınacak şekilde tasarlanmıştır"],"explanation":"Manuel ayarlayıcı elle çekildiğinde 1 inçten fazla hareket etmemeli, aksi halde frenler ayarsızdır."},"13":{"q":"Havalı frenli bir çekici-römork kullanıyorum ve önümdeki trafik için yavaşlamak amacıyla fren pedalına sertçe basıyorum. Arabamdaki hidrolik frenlere kıyasla, havalı frenler gerçekten kavramadan önce gözle görülür bir gecikme var. Bu havalı fren gecikmesi yaklaşık ne kadardır — pedala bastıktan sonra havanın hatlardan geçip etki etmesi için geçen süre?","options":["Yaklaşık 1/10 saniye; arabadaki hidrolik fren sisteminde hissettiğim aynı anlık tepki","Yaklaşık 1/2 saniye; bu sürede hava hatlardan geçer ve frenler tutmaya başlar","Yaklaşık 2 saniye; sürücü pedala basmadan önceki tepki mesafesi gecikmesiyle aşağı yukarı aynı","Yaklaşık 5 saniye; çünkü herhangi bir frenleme başlamadan önce havanın her hazneyi tamamen doldurması gerekir"],"explanation":"Havalı frenlerde, sıkıştırılmış hava hatlardan geçerken frenlerin tutması için yaklaşık yarım saniyelik gecikme vardır."},"14":{"q":"Havalı (basınçlı hava) frenli kamyonum için toplam durma mesafesini hesaplıyorum. Hidrolik frenli bir otomobilde toplam durma mesafesi sadece algılama mesafesi artı tepki mesafesi artı frenleme mesafesidir. Kamyonum havalı fren kullandığı için, otomobil sürücüsünde bulunmayan hangi EK bileşeni bu hesaba eklemem gerekir?","options":["Fazladan bir tepki mesafesi, çünkü havalı fren kumandalarını beynin çalıştırması daha uzun sürer","Daha uzun bir algılama mesafesi, çünkü kamyon daha büyük olduğundan tehlikeleri zamanında fark etmek zorlaşır","Bir fren gecikme mesafesi; havanın hatlardan geçip frenlerin uygulanması için geçen yaklaşık yarım saniye için","Fazladan hiçbir şey, çünkü dört temel mesafe her fren sistemi türü için aynıdır"],"explanation":"Havalı fren durma mesafesine, havanın hatlardan geçip uygulanması için yarım saniyelik fren gecikme mesafesi eklenir."},"15":{"q":"Sefer öncesi kontrolümde, sistem tam dolu yaklaşık 125 psi iken motoru kapatıyorum, tekerleklere takoz koyuyorum ve tek (römorksuz) kamyonumda park frenlerini BIRAKILMIŞ halde tutuyorum. Sızıntıyı ölçmek için gösterge panelini tam bir dakika izliyorum. Hava kaybı yalnızca hangi orana eşit veya altında kaldığı sürece kabul edilebilir?","options":["Dakikada 4 psi, çünkü motor kapalı ve depolar doluyken sınır budur","Dakikada 1 psi, sızdırmaz bir sistemden neredeyse hiç hava kaçmaması gerektiği varsayımıyla","Dakikada 3 psi, bu testte bir kombinasyon (römorklu) araca uygulanan aynı değer","Dakikada 2 psi, frenleri bırakılmış tek bir araç için izin verilen azami değer"],"explanation":"Tek araçta, frenler bırakılmışken hava kaybı dakikada 2 psi'yi geçmemelidir."},"16":{"q":"Bir çekici-römork üzerinde sefer öncesi kontrolümde sistemi yaklaşık 125 psi'ye tam olarak şarj ediyorum, motoru kapatıyorum ve hava kaçağını ölçmek için frenleri bırakılmış halde tutuyorum. Gösterge panelindeki manometreyi bir dakika boyunca izlerken, bu kontrolü geçebilmem için izin verilen EN FAZLA basınç düşüşü nedir?","options":["Bir dakikada 3 psi","Bir dakikada 2 psi","Bir dakikada 4 psi","Bir dakikada 6 psi"],"explanation":"Bağlantılı araçta, frenler bırakılmışken hava kaybı dakikada 3 psi'yi geçmemelidir."},"17":{"q":"Sefer öncesi kontrolümde hava sistemini yaklaşık 125 psi'ye kadar dolduruyorum, motoru kapatıyorum, tekerleklerin altına takoz koyuyorum ve römorksuz tek parça kamyonumda ayak frenine tam basıyorum. Hava kaçak oranını kontrol etmek için gösterge panelini bir dakika boyunca izliyorum. Hangi gösterge değeri kamyonumun yasal sınır içinde ve sürmek için güvenli olduğu anlamına gelir?","options":["Basınç o dakika içinde 4 psi düşer","Basınç o dakika içinde 2 psi düşer","Basınç o dakika içinde 5 psi düşer","Basınç o dakika içinde 6 psi düşer"],"explanation":"Tek araçta, frenler uygulanmışken hava kaybı dakikada 3 psi'nin altında kalmalıdır."},"18":{"q":"Çift devreli hava frenli bir sistemde sefer öncesi muayene sırasında motoru çalıştırıyorum, çalışma devrinde tutuyorum ve gösterge tablosundaki ibrelerin 85 psi'den yükselişini izliyorum. Hava basıncı yükselme testini geçmek için ibreler 100 psi'ye en geç ne kadar sürede ulaşmalı?","options":["Çalışma devrinde 10 saniye içinde","Çalışma devrinde 3 dakika içinde","Çalışma devrinde 45 saniye içinde","Çalışma devrinde 5 dakika içinde"],"explanation":"Çift havalı fren sisteminde basınç, çalışma devrinde 45 saniye içinde 85'ten 100 psi'ye yükselmelidir."},"19":{"q":"Sefer öncesi kontrolüm sırasında motor kapalı ve hava depolarım yaklaşık 125 psi'ye kadar dolu. Sürüşe başlamadan önce düşük hava basıncı uyarı cihazının doğru çalıştığını doğrulamak istiyorum. Bu kontrolü gerçekten hangi işlem yapar?","options":["Sistem doluyken motoru yüksek devirde çalıştırıp basınç 60 psi'nin üzerine çıkarken uyarının yanıp yanmadığını izlemek","Depo boşaltma vanalarını sonuna kadar açıp tüm havanın depolardan hızla boşalmasını sağlamak, sonra sesli uyarıyı dinlemek","Fren pedalına bir kez basıp uyarı cihazının 100 psi'nin üzerinde kapalı kaldığını doğrulamak","Motor kapalıyken fren pedalına tekrar tekrar basıp bırakarak basıncı düşürmek ve uyarı 60 psi'nin üzerinde devreye girene kadar devam etmek"],"explanation":"Motor kapalıyken frenlere basıp bırakarak basıncı düşürün ve düşük hava uyarısının basınç 60 psi'nin altına inmeden geldiğini doğrulayın."},"20":{"q":"Sefer öncesi havalı fren kontrolünde sistemi tam basınca kadar doldurdum, el frenini bıraktım ve servis frenlerinin aracı gerçekten tutup düz bir şekilde durdurduğunu kontrol etmeye hazırım. Servis freni durma testini yapmanın doğru yolu aşağıdakilerden hangisidir?","options":["Aracın yaklaşık 5 mil/saat hızla ileri gitmesine izin verin, ardından fren pedalına sıkıca basın ve aracın bir tarafa çekmeden durduğunu doğrulayın","Normal otoyol hızına çıkın ve frenlerin tam duruşu kaldırabildiğini doğrulamak için bir kez sert fren yapın","Aracı yerinde tutarken el freni düğmesini çekin ve çekicinin yerinde kilitli kalıp kalmadığını hissedin","Yaklaşık 5 mil/saat hızla giderken basıncın her seferinde yeniden oluştuğunu doğrulamak için fren pedalına hızlıca on kez basın"],"explanation":"Doğru servis freni kontrolü: yaklaşık 5 mil/saat ileri gidin, pedala sıkıca basın; araç bir tarafa çekmeden düz durmalıdır."},"21":{"q":"Sefer öncesi kontrolümde, fren kampanalarından birinin yüzeyinde uzanan bir çatlak buluyorum. Aracı servis dışı bırakıp bırakmayacağıma karar vermem gerekiyor. Texas CDL El Kitabına göre, çatlak aşağıdakilerden hangisinden daha uzun olduğunda çatlamış bir fren kampanası servis dışı sayılır?","options":["Kampana yüzeyindeki herhangi bir görünür kılcal (saç teli) çatlak","Kampananın sürtünme yüzeyi genişliğinin yarısı","Kampananın sürtünme yüzeyi genişliğinin dörtte biri","Kampananın sürtünme yüzeyinin tam genişliği"],"explanation":"Bir fren kampanasında çatlak, kampananın sürtünme yüzeyi genişliğinin yarısından uzunsa kampana servis dışı bırakılmalıdır."},"22":{"q":"Sefer öncesi kontrolümde bir tekerleği söküp römorkun altına girerek kampanalı frenleri inceliyorum. Bir sorun buluyorum ve sürüşe başlamadan önce balataların değiştirilmesi gerektiğine karar veriyorum. Aşağıdaki fren balatası durumlarından hangisi bu aracı servis dışı bırakmayı DOĞRU şekilde gerekçelendirir?","options":["Balatalar kalın, kuru ve destek plakasına sıkıca oturmuş durumda","Balatalar kampanaya tam temas ediyor ve düzgün, hafif yüzey aşınması gösteriyor","Balatalar yağ veya gresle ıslanmış ya da tehlikeli derecede ince aşınmış durumda","Balatalar yeni takılmış ve ilk oturma nedeniyle hafif parlaklık göstermekte"],"explanation":"Fren balatalarına yağ veya gres bulaşmışsa ya da tehlikeli derecede inceyse balatalar arızalıdır ve araç servis dışı bırakılmalıdır."},"23":{"q":"Yüklü bir katar ile uzun ve dik bir yokuştan aşağı iniyorum. İnişe başlamadan önce küçük bir vitese geçtim ve şimdi inişin geri kalanında havalı frenlerimi nasıl kullanacağımı düşünüyorum. Bu yokuş inişinde frenlerimin oynaması gereken rolü hangi ifade doğru şekilde tanımlar?","options":["Onlar ana hız kontrolümdür, bu yüzden inişin tamamı boyunca pedala sabit basınç uygulamalıyım","Tekrar tekrar basıp bırakarak, her uygulama arasında havanın yeniden dolmasına izin verildiğinde en iyi şekilde çalışırlar","Tekerleklerin hiç hız kazanmaması için sıkıca ve sürekli olarak basılı tutulmalıdırlar","Onlar motor frenlemesinin bir tamamlayıcısıdır; küçük vitesi desteklemek için hafif, düzenli uygulamalarla kullanılır"],"explanation":"Uzun bir inişte düşük vitesteki motor hızı kontrol etmenin birincil yoludur; frenler bunu yalnızca hafif ve düzenli uygulamalarla destekler."},"24":{"q":"Yüklü bir birleşik araçla uzun ve dik bir yokuştan iniyorum, zaten düşük vitesteyim ve hızımı kontrol altında tutmak için doğru aralıklı (snub) frenleme tekniğini kullanmak istiyorum. Frenlerle ne yapmam gerektiğini hangi seçenek doğru tanımlıyor?","options":["Hızım güvenli hızımın yaklaşık 5 mil/saat altına düşene kadar frene sıkıca basmak, sonra freni tamamen bırakmak ve gerektikçe bu döngüyü tekrarlamak","Hiç ısı oluşmaması için iniş boyunca fren pedalına sürekli sabit ve hafif basınç uygulamak","Tekerleklerin kilitlenmemesi için tüm iniş boyunca frenlere hızlıca basıp bırakarak pompalamak","Boşa alıp rölantide kaymak ve yalnızca hız göstergesi güvenli hızımın üzerine çıkarsa frene basmak"],"explanation":"Uzun inişte aralıklı (snub) frenleme kullanın: hızınız güvenli hızın yaklaşık 5 mil/saat altına düşene kadar sıkıca frenleyin, soğumaları için tamamen bırakın ve tekrarlayın."},"25":{"q":"Havalı (basınçlı hava) frenli yüklü bir kamyonla uzun ve dik bir dağ yokuşundan iniyorum. Yokuş bir türlü bitmiyor ve frenlerim için endişeleniyorum, bu yüzden hızımı kontrol altında tutmak için fren pedalına hızlı hızlı, tekrar tekrar basıp bırakmaya başlıyorum. Bunu yapmak neden tam olarak yapılmaması gereken şeydir?","options":["Sürekli aç-kapa frenleme fren ayar kollarını (slack adjuster) aşırı ısıtır ve ön tekerlekleri kilitleyerek kamyonun yokuşta savrulup kontrolden çıkmasına yol açar","Pedalı her bırakışınızda hava, kompresörün yerine koyabileceğinden daha hızlı kaçar; böylece basınç frenlerin çalışması için yeterli hava kalmayana kadar düşebilir","Pedalın hızlı basılıp bırakılması ABS'i tetikleyerek frenleri tamamen boşaltır ve yavaşlamanın tek yolu olarak yaylı (park) frenleri bırakır","Pedalı pompalamak emniyet supabını 150 psi'de açmaya zorlar ve inişin geri kalanında ihtiyaç duyacağınız depo havasını boşaltır"],"explanation":"Frenleri pompalamak, kompresörün yenileyebileceğinden daha hızlı hava boşaltır; bu yüzden hava basıncı, frenlerin çalışacak yeterli havası kalmayana kadar düşebilir."},"26":{"q":"Dik bir dağ yokuşundan uzun bir iniş yaptım, tüm yol boyunca hava frenlerine bastım ve zorunlu molam için bir dinlenme alanına giriyorum. Bu durumlardan hangisinde park (yay) frenini çekMEMELİ, bunun yerine tekerleklere takoz koymalıyım?","options":["Araç viteste bırakılırsa kayabileceği hafif bir iniş eğiminde park ediyorum","Kamyonu gece boyunca işaretli bir kamyon parkında başında olmadan bırakacağım","Fren kampanaları ve balataları, az önce yaptığım inişten dolayı hâlâ aşırı sıcak","Dururken alçak hava basıncı uyarı zili kısa bir süre çaldı"],"explanation":"Uzun bir inişten sonra kampanalar ve balatalar hâlâ çok sıcakken park (yay) frenini çekmeyin; bu, onlara zarar verebilir ve sıkışmaya neden olabilir."},"28":{"q":"2020 model bir çekici-römork (çalışır durumda ABS donanımlı) kullanırken bir otomobil aniden tam benim şeridimde duruyor. Banket yerine şeridimde kalarak mümkün olduğunca hızlı durmam gerekiyor. Bu acil durumda bana en iyi kontrolü hangi frenleme yöntemi sağlar?","options":["ABS'nin her bırakma arasında devreye girip kavraması için fren pedalına hızlıca basıp bırakmak","Çekici tekerleklerinin kaymasını önlemek için önce yalnızca römork el valfini uygulamak","Bir tekerleğin kaymaya başladığını hissettiğim anda basıncı azaltıp ardından tekrar bastırmak","Fren pedalına sertçe basıp basılı tutmak ve direksiyonu boş şeride doğru çevirmeye devam etmek"],"explanation":"ABS ile sert frenleyin ve direksiyonu kullanırken pedala basıncı sabit tutun; çünkü ABS tekerleklerin kilitlenmesini önler, böylece boş şeride doğru yönlenebilirsiniz."},"29":{"q":"ABS sistemi BULUNMAYAN eski bir çekici-römork kullanıyorum ve önüme aniden bir otomobil giriyor. Aracı kontrol altında tutarken sert bir acil duruş yapmam gerekiyor. Hangi frenleme yöntemini kullanmalıyım?","options":["Tekerlekler dönmeye devam etsin ve hâlâ direksiyonla yön verebileyim diye kontrollü veya kesik (dürtmeli) frenleme yapmalıyım","Fren pedalına sonuna kadar basıp duruncaya dek sertçe basılı tutmalıyım","Tekerlekleri kilitleyecek kadar sert frenlemeliyim, çünkü kilitli tekerlekler en kısa duruşu sağlar","Hava basıncını korumak için fren pedalına sonuna kadar hızlıca basıp bırakmalıyım"],"explanation":"ABS olmadan, tekerleklerin dönmeye devam etmesi için kontrollü veya kesik (stab) frenleme kullanın; bu hem durma gücünü hem de direksiyon kontrolünü korur."},"30":{"q":"ABS'siz yüklü bir kamyon kullanırken yola aniden bir şey fırlıyor ve sert fren yapmak zorunda kalıyorum. Fren pedalını sonuna kadar basıyorum, tekerlekler kilitleniyor ve aralıklı (stab) frenleme dizisine başlamak için pedalı bırakıyorum. Stab frenlemeyi doğru yapmak için pedala ne zaman tekrar sertçe basmalıyım?","options":["Pedalı bırakır bırakmaz, hiçbir şey beklemeden","Yalnızca tekerlekler tekrar dönmeye başladıktan sonra","Frenleri yaklaşık 10 saniye boyunca bıraktıktan sonra","Hiç basmamalıyım — bıraktıktan sonra direksiyonu kullanıp beklemeliyim"],"explanation":"Kesik (stab) frenlemede frenleri yalnızca tekerlekler tekrar dönmeye başladıktan sonra yeniden uygularsınız; çünkü kilitli tekerlekler yönlendirilemez ve etkili frenleyemez."},"31":{"q":"Sefere 30 mil girmişken gösterge panelindeki sarı ABS arıza lambası yanıyor ve yanık kalıyor. Düşük hava basıncı uyarınız devreye GİRMEDİ ve pedal hâlâ sıkı hissettiriyor. Aşağıdakilerden hangisi durumunuzu ve doğru hareket tarzını doğru biçimde tanımlar?","options":["Servis frenleriniz arızalandı; aracı kontrollü şekilde derhal banket üzerinde durdurun ve daha ileri gitmeden önce çekici çağırın.","Durma mesafeniz artık normalden daha uzun, bu yüzden takip mesafenizi artırın ve havanın tekerleklere ulaşmaya devam etmesi için fren pedalına pompa yapın.","Normal servis frenleriniz hâlâ çalışıyor ve dikkatlice sürmeye devam edebilirsiniz; yalnızca kilitlenmeyi önleyici işlev kayboldu, bu yüzden ABS'yi mümkün olan en kısa sürede servise götürün.","Yaylı (park) frenleriniz birazdan otomatik olarak devreye girecek, bu yüzden hızınızı azaltın ve tekerlekler kilitlenmeden önce bir sonraki çıkıştan ayrılın."],"explanation":"ABS uyarı lambası yalnızca kilitlenme önleyici işlevin kaybolduğunu gösterir; normal servis frenleriniz tam çalışır, bu yüzden dikkatli sürün ve ABS'yi en kısa sürede tamir ettirin."},"32":{"q":"İkinci el bir çekici (truck tractor) satın alıyorum ve federal kurallar belirli havalı frenli araçlarda ABS'yi zorunlu kıldığı için, aracın fabrika çıkışlı kilitlenmeyi önleyici fren sistemine (ABS) sahip olduğundan emin olmak istiyorum. Bayi bana farklı yıllarda üretilmiş dört çekici gösteriyor. Çekicinin fabrika montajlı ABS'ye sahip olmasını GEREKTİREN EN ERKEN üretim tarihi hangisidir?","options":["1 Mart 1998 ve sonrasında üretilen herhangi bir çekici","1 Mart 1995 ve sonrasında üretilen herhangi bir çekici","1 Mart 2000 ve sonrasında üretilen herhangi bir çekici","1 Mart 1997 ve sonrasında üretilen herhangi bir çekici"],"explanation":"Federal kurallar, 1 Mart 1997 tarihinde veya sonrasında üretilen çekicilerde fabrika ABS'sini zorunlu kılar."},"34":{"q":"Amarillo'da donma altı bir aralık sabahı, sefer öncesi kontrolümü yapıyorum. Çekicimin hava depolarında manuel boşaltma vanaları var ama geç kaldım, bu yüzden bugün boşaltmayı atlamak istiyorum. Yine de yola çıkmadan önce depo boşaltma vanalarını açmam için EN İYİ neden hangisidir?","options":["Depolarda biriken su soğuk havada donarak frenlerin çalışmasını engelleyebilir","Depoları boşaltmak regülatörün daha yüksek basınçta kesmesini sağlar, böylece sistem daha hızlı dolar","Vanaları açmak eski havayı atar, böylece emniyet supabı doğru 150 psi ayarında yeniden oturur","Havayı boşaltmak düşük hava uyarısını sıfırlar, böylece korna 60 psi altında çalmaz"],"explanation":"Hava depolarını her gün boşaltın, çünkü biriken su soğuk havada donarak frenlerin çalışmasını engelleyebilir."},"35":{"q":"Bir çekici-römork üzerinde yola çıkış öncesi kontrolümü bitiriyorum. Motor rölantide çalışıyor ve hava basıncı göstergesinin ibresi yükseliyor. El frenini bırakıp sahadan çıkmadan önce hava sistemini hangi basınç seviyesine kadar doldurmalıyım?","options":["Yaklaşık 100 psi'ye kadar, çünkü kompresörün devreye girdiği nokta budur ve çalıştığını anlarım","Normal çalışma aralığına, yaklaşık 125 psi'ye kadar; burada regülatör devreden çıkar ve pompalamayı durdurur","Yaklaşık 150 psi'ye kadar; bu, emniyet tahliye valfinin sistemi korumak için açıldığı seviyedir","Yaklaşık 60 psi yeterlidir, çünkü düşük hava basıncı uyarısı bu seviyede kapanır"],"explanation":"Sürmeden önce hava sistemini, regülatörün devreyi kestiği yaklaşık 125 psi'lik normal çalışma aralığına kadar şarj edin."},"36":{"q":"Sefer öncesi kontrolümde, hava kompresörünü çalıştıran kayışın parlaklaşıp sertleştiğini ve başparmağımla birkaç santim bastırılabildiğini fark ediyorum. Motor sorunsuz çalışıyor ve kabin radyosu çalışıyor. Bu gevşek tahrik kayışı güvenli sürüş için neden önemlidir?","options":["Gevşek kayış yalnızca cıyaklayıp düşük hava basıncı uyarı zilini duymayı zorlaştırabileceği için önemlidir","Önemlidir çünkü aynı kayış, römorkun acil durum aküsünü şarjlı tutan alternatörü de döndürür","Kayan bir kayış, kompresörün yeterince hızlı hava basmasını engelleyebilir; bu nedenle sistem yeterli hava basıncını hiç oluşturamayabilir veya tutamayabilir","Önemlidir çünkü tahrik kayışı, fren solmasını önlemek için ön fren kampanalarının üzerinden soğutucu hava yönlendirir"],"explanation":"Kayan kompresör tahrik kayışı kompresörün yeterince hızlı pompalamasını engeller, bu yüzden sistem doğru hava basıncını hiç oluşturamayabilir veya tutamayabilir."},"37":{"q":"Tek parçalı bir kombinasyon aracında sefer öncesi kontrol yapıyorum ve yola çıkmadan önce havalı fren bölümünün her parçasını tamamladığımdan emin olmak istiyorum. Başka bir sürücü, listelediğim kontrollerin bazılarının aslında havalı fren testinin parçası sayılmadığını söylüyor. Aşağıdakilerden hangisi gerçekten tam bir sefer öncesi havalı fren kontrolünün zorunlu bir parçasıdır?","options":["Yalnızca düşük hava uyarı cihazı testi, çünkü sınav görevlisinin dikkat ettiği şey zil ve ışıktır","Yalnızca hava basıncı yükselme süresi, çünkü bu kompresörün görevini yaptığını kanıtlar","Yalnızca durağan hava kaçak oranı, çünkü kaçak bulabileceğiniz en ciddi kusurdur","Hepsi — düşük hava uyarısı, basınç yükselme süresi ve hava kaçak oranının her biri kontrolün zorunlu parçalarıdır"],"explanation":"Tam bir sefer öncesi hava freni kontrolü bunların hepsini gerektirir: düşük hava uyarısı, basınç oluşturma süresi ve hava kaçağı oranı."},"38":{"q":"Havalı frenli bir çekicide sefer öncesi kontrolü yapıyorum ve havalı fren sisteminin kendisini GERÇEKTEN kontrol etmeyen herhangi bir adımı atlamak istiyorum. Listemdeki hangi madde farklı bir sisteme ait olup frenlerim hakkında bana hiçbir şey söylemez?","options":["Motor soğutma sistemini temiz tutmak için radyatörden su ve yağ boşaltmak","Sağlıklı bir basınç yükselme hızını doğrulamak için basıncın 85 psi'den 100 psi'ye çıkma süresini ölçmek","Sistemi doldurup motoru durdurarak göstergeden basınç düşme (kaçak) oranını izlemek","Düşük hava uyarı lambası ve zili 60 psi civarında devreye girene kadar pedala basıp bırakmak (yelpazeleme)"],"explanation":"Radyatörden su ve yağ boşaltmak motor soğutma sistemi bakımıdır ve hava freni sisteminde hiçbir şeyi test etmez."},"39":{"q":"ABS donanımlı bir çekici-römork kullanıyorum ve kuru zeminde sert, ani bir fren yapmam gerekiyor. ABS devreye girip pedalın titreştiğini hissederken, ABS'nin bu duruşta benim için gerçekte ne yaptığına dair hangi ifade DOĞRUDUR?","options":["ABS olmayan aynı araca kıyasla duruş mesafemi kısaltıyor","Tekerleklerimin kilitlenmesini önleyerek sert fren yaparken direksiyon hâkimiyetimi korumamı sağlıyor","Fren gecikmemi otomatik olarak normal yarım saniyenin altına düşürüyor","Ek durdurma kuvveti eklemek için yaylı (park) frenleri devreye sokuyor"],"explanation":"ABS tekerleklerin kilitlenmesini önler, böylece dönmeye devam ederler ve sert frenleme sırasında direksiyon hakimiyetini korursunuz."},"40":{"q":"Sabah sefer öncesi kontrolümü yaparken çekicimin hava depolarının dibinde su ve bir kat kompresör yağı karışımı biriktiğini fark ediyorum. Panhandle bölgesinde soğuk bir kış sabahı. Hava fren sisteminin güvenli çalışması ve donmayı önlemek için bu birikinti hakkında ne yapmalıyım?","options":["Hava kurutucusu ve fren ısısı yol boyunca suyu ve yağı buharlaştıracağı için olduğu gibi bırakmak","Nemin asılı kalması ve donmaması için depolara fazladan kompresör yağı eklemek","Su ve yağın sisteme zarar vermemesi ve donmaması için hava depolarını her gün boşaltma valfleriyle boşaltmak","Modern otomatik valfler gerisini kendi hallettiği için depoları yalnızca haftada bir boşaltmak"],"explanation":"Biriken su ve yağın sistemi bozmaması veya donmaması için hava depolarını her gün boşaltma valfleriyle boşaltın."},"41":{"q":"Sefer öncesi kontrolde, hava kaçağı testini yapmak için motoru kapattım ve motor kapalıyken hava göstergesinin tamamen yükselmeyi durdurduğunu fark ettim. Yanımdaki acemi bir sürücü, kompresörün kendi başına basınç üretmeye devam etmesi gerektiğinde ısrar ediyor. Motoru kapattığımda basıncın neden yükselmeyi durdurduğunu hangi ifade doğru açıklar?","options":["Regülatör (governor) hava tanklarını mekanik olarak pompalar ve yalnızca kamyon ileri giderken çalışır","Hava sistemini park freni yayı şarj eder, bu yüzden frenler çekildiğinde durur","Römork tekerleklerinin dönüşü kompresörü çevirir, bu yüzden basınç yalnızca hareket halindeyken oluşur","Kompresör motor tarafından (kayışla veya doğrudan) çalıştırılır, bu yüzden motor kapalıyken hava pompalanmaz"],"explanation":"Hava kompresörü motor tarafından çalıştırılır, bu yüzden motor kapalıyken hava pompalamaz."},"42":{"q":"Kış sabahı hava donma noktasının çok altında ve hava kurutucusuyla donatılmış bir çekicide sefer öncesi kontrolümü yapıyorum. Kompresör sisteme hava bastıkça bu cihazın beni neye karşı koruduğunu anlamak istiyorum. Bu durumda hava kurutucusunun asıl görevi nedir?","options":["Sıkıştırılmış havadaki su buharını (ve bir miktar yağı) depolara ulaşmadan önce çeker, böylece daha az nem birikir ve sistemin donmasını önler","Depo basıncı yaklaşık 125 psi kesme noktasına ulaştığında kompresöre pompalamayı durdurmasını bildirir","Basınç yaklaşık 150 psi emniyet supabı ayarının üzerine çıkarsa depoları otomatik olarak boşaltır","Soğuk havada fren valflerinin buzlanmaması için hatlara ölçülü miktarda alkol enjekte eder"],"explanation":"Hava kurutucusu, sıkıştırılmış havadaki su buharını ve bir miktar yağı tanklara ulaşmadan önce giderir, böylece donup frenleri devre dışı bırakabilecek nem azalır."},"43":{"q":"Sefer öncesi kontrolde, fren mekanizmalarını incelemek için römorkun altına giriyorum. Her tekerlekte bir fren kampanası, balatalı fren pabuçları ve bir itme çubuğuna bağlı bir ayar kolu buluyorum; bu çubuk, pabuçları birbirinden ayırmak için 'S' harfi şeklindeki bir parçayı döndürüyor. Gördüklerime dayanarak, bu araç hangi tip fren mekanizmasıyla donatılmış — çoğu ağır havalı frenli araçta bulunan tip hangisidir?","options":["Havalı disk frenler; bir kaliperin bir diski sıktığı, ağır kamyonlardaki en yaygın tasarım","S-kamlı kampanalı frenler; ağır havalı frenli araçlardaki en yaygın fren mekanizması","Kamalı kampanalı frenler; bir kamanın tek bir hazne aracılığıyla pabuçları ittiği tip","Hidrolik disk frenler; bir binek otomobildeki gibi ama römork için büyütülmüş"],"explanation":"S-kamlı kampanalı frenler, ağır havalı fren araçlarında en yaygın temel frendir ve itme çubuğunun pabuçları açmak için döndürdüğü S şeklindeki kamla tanınır."},"45":{"q":"Havalı (basınçlı hava) frenli, yüklü bir çekici-römork sürerken önümdeki bir otomobil aniden duruyor. Ayağımı fren pedalına tam bastırdığım anda, kamyon gerçekten yavaşlamaya başlamadan önce kısa bir gecikme oluyor. Eğitmenim buna 'fren gecikmesi' (brake lag) diyor. Bu gecikme sırasında fiziksel olarak ne oluyor?","options":["Ayağım pedala ulaşmadan önce beynim ve vücudum tehlikeyi hâlâ işliyor","Hava kompresörü, talebi karşılamak için depolarda ek basınç oluşturuyor","Basınçlı hava, frenleri uygulayabilmek için önce fren hatları boyunca ilerliyor","Herhangi bir fren girdisi başlamadan araç algılama mesafesini kat ediyor"],"explanation":"Pedala basıldıktan sonra, sıkıştırılmış havanın fren hatlarından geçip her tekerlekteki frenleri gerçekten uygulaması yaklaşık yarım saniye sürer."},"46":{"q":"CDL hava fren onayım için toplam durma mesafesini çalışıyorum. Bir otomobilin hidrolik frenlerinde toplam durma mesafesinin algılama mesafesi artı tepki mesafesi artı frenleme mesafesi olduğunu biliyorum. Eğitmenim, hava frenlerinin bu toplama bir bileşen daha eklediğini söylüyor. Hava fren sisteminin, hidrolik frenlerde OLMAYAN hangi bileşeni eklediğini seçin?","options":["Ek tepki mesafesi, çünkü hava fren pedalları hidrolik pedallardan daha ağırdır ve basılması daha yavaştır","Ek algılama mesafesi, çünkü daha büyük hava frenli araçlar daha yüksekte oturur ve tehlikeleri değerlendirmek daha uzun sürer","Daha uzun etkili frenleme mesafesi, çünkü hava frenli araçlar daha ağırdır ve durmak için daha fazla yere ihtiyaç duyar","Fren gecikme mesafesi; hava hatlardan geçip frenler tutmaya başlamadan önce kat edilen mesafe"],"explanation":"Havalı frenler dördüncü bir durma bileşeni ekler: fren gecikme mesafesi; bu, havanın hatlardan geçip frenler tutana kadar geçen yaklaşık yarım saniyeyi kapsar."},"47":{"q":"Sefer öncesi kontrolünüzü tamamladınız ve hava sistemi tam dolu. Şimdi servis frenlerinin kamyonu gerçekten durdurduğunu ve hiçbir şeyin sürtmediğini veya bir tarafa çekmediğini doğrulamak istiyorsunuz. Aşağıdakilerden hangisi servis freni durdurma kontrolünü yapmanın doğru yoludur?","options":["Park frenini bırakın, kamyonun yaklaşık 5 mil/saat hıza kadar ilerlemesine izin verin, ardından fren pedalına kararlı şekilde basın ve aracın hemen ve düzgün şekilde durup durmadığını hissedin","Kamyonu sabit tutun, fren pedalına sert basın ve basıncın bir dakikada 3 psi'den fazla düşmediğini doğrulamak için hava göstergesini izleyin","Dururken, yaylı frenlerin devreye girip çıktığını doğrulamak için sarı park freni düğmesini birkaç kez çekip bırakın","Yaklaşık 20 mil/saate kadar hızlanın, ardından sert bir fren yapın ve tekerleklerin her iki tarafta eşit şekilde kilitlendiğini kontrol edin"],"explanation":"Servis freni durma testi hareket halinde yapılır: aracın yaklaşık 5 mil/saate kadar ilerlemesine izin verin, sonra frenlere sıkıca basıp aracın bir tarafa çekmeden hemen durduğunu hissedin."},"48":{"q":"Sefer öncesi kontrolüm sırasında CDL eğitmenim, fren ayarlayıcılardan birini elimle tutup çekerek itme çubuğunun frenler devreye girmeden önce ne kadar hareket ettiğini kontrol etmemi söylüyor. Buradaki boşluk çok fazlaysa fren gücümün azaldığını söylüyor. Bunu yaparken aslında hangi parçayı kontrol ediyorum?","options":["Sistemin havayı pompalamayı ne zaman durduracağına ve yeniden başlayacağına karar veren hava kompresörü regülatörü","Fren itme çubuğunun frenler uygulanmadan önce ne kadar hareket edeceğini ayarlayan boşluk ayarlayıcısı (slack adjuster)","Depolar aşırı dolduğunda basıncı boşaltmak için açılan emniyet tahliye valfi","Acil durumda yay frenlerini kademeli olarak uygulamamı sağlayan modülasyon kontrol valfi"],"explanation":"Fren kolu (slack adjuster), frenler devreye girmeden önce itme çubuğunun ne kadar hareket edeceğini belirler ve aşırı boşluk—ayarsız frenler—en yaygın havalı fren arızasıdır."},"49":{"q":"Donma derecesindeki havada araç öncesi kontrol sırasında kamyonumun hava depolarının, elle herhangi bir şey açmama gerek kalmadan biriken suyu ve yağı kendiliğinden boşalttığını fark ediyorum. Servis, bu deponun donmayı önlemek için kendiliğinden boşalacak şekilde donatıldığını söylüyor. Bu işi yapan hangi parçadır?","options":["Arka frenlere giden hava sinyalini hızlandıran, ama aynı zamanda depodaki nemi kendiliğinden boşaltan bir röle (relay) valfi","Depo basıncı yeterince yükseldiğinde biriken suyu ve yağı otomatik olarak dışarı atan bir manuel (elle) boşaltma valfi","Suyu ve kompresör yağını kimsenin elle boşaltmasına gerek kalmadan depodan dışarı atan bir otomatik boşaltma valfi","Yaklaşık 150 psi'de açılan ve hava verirken besleme deposundaki birikmiş suyu ve yağı temizleyen bir emniyet (basınç tahliye) valfi"],"explanation":"Otomatik tahliye valfi, biriken suyu ve kompresör yağını elle boşaltma gerekmeden tanktan kendiliğinden atar; bu da soğuk havada donmayı önlemeye yardımcı olur."},"50":{"q":"Daha yeni bir bağlantılı araçta yola çıkış öncesi kontrolümü yaparken, hava basınç göstergesinde bir yerine iki ibre olduğunu fark ediyorum ve her iki gösterge de yükselene kadar kamyon normal şekilde basınç oluşturmama izin vermiyor. Eğitmenim bu aracın çift hava frenli sisteme sahip olduğunu söylüyor. Bu çift sistemin gerçekte nasıl kurulduğunu hangi ifade doğru şekilde tanımlar?","options":["Tek bir depodan beslenen büyük tek bir hava sistemidir ve ikinci gösterge ibresi yalnızca bilgi amaçlı olarak römork basıncını gösterir.","Servis, park ve acil durum frenlerini tek bir ortak hava hattında birleştirir, böylece üçü de tek bir basınç kaynağından çalışır.","Yalnızca ana kompresör tamamen arızalandıktan sonra devreye giren bir yedek kompresöre sahip tek bir hava sistemidir.","Bu, ek güvenlik için tek bir fren kumanda takımıyla kontrol edilen, biri birincil biri ikincil olmak üzere tamamen ayrı iki hava sistemidir."],"explanation":"Çift havalı fren sistemi, her biri kendi tankları ve hatları olan ancak yedek güvenlik için tek bir kumanda takımıyla çalıştırılan, birincil ve ikincil olmak üzere tamamen ayrı iki hava sistemidir."},"51":{"q":"Çift hava freni sistemiyle donatılmış bir çekici-römork kullanırken, düşük hava basıncı uyarısı aniden yalnızca birincil devre için devreye giriyor ve o tarafın gösterge ibresi sıfıra doğru düşüyor. İkincil sistemin göstergesi hâlâ normal aralıkta okuyor. Neyi beklemem ve ne yapmam gerektiğini en iyi hangi ifade açıklar?","options":["İkincil sistem frenleri çalıştırmaya devam edecektir, bu yüzden daha uzun bir durma mesafesi hesaba katarak güvenli bir şekilde durmalı, ardından kamyonu tamir ettirmeliyim.","Her iki devre tek bir kumanda setini paylaştığı için, ikincil sistem de birincil ile birlikte arıza yapar, böylece hiç frenim kalmaz ve durana kadar boşta kaymak zorunda kalırım.","Çalışan devreyi tüm tekerleklere hava göndermeye zorlamak ve arızalı tarafın tam basıncını geri kazandırmak için fren pedalına hızlıca basıp bırakmalıyım.","Bir devre arıza yaptığı anda yaylı frenler tüm tekerlekleri anında kilitler, bu yüzden ani ve sert bir durmaya hazırlanmalıyım."],"explanation":"Çift havalı fren sisteminin bir devresi arızalanırsa diğeri yine de frenleri çalıştırır; bu nedenle daha uzun durma mesafesini hesaba katarak kontrollü şekilde durun, sonra aracı tamir ettirin."},"52":{"q":"Çekici-römork aracımda sefer öncesi kontrol yapıyorum ve motor kapalı. Sistem yavaşça boşalırken göstergeyi izliyorum: ibre 60 psi'yi geçiyor ve 30 psi'ye doğru düşmeye devam ediyor. Park kumandasına hiç dokunmadığım hâlde yaylı (park) frenler aniden kendiliğinden devreye giriyor. Yaylı frenlerin o ana kadar serbest (çözülmüş) konumda kalmasını EN İYİ açıklayan ifade hangisidir?","options":["Piston (itme çubuğu) hareketi tükenene kadar fren ayarlayıcılar (slack adjuster) tarafından mekanik olarak tutuluyorlardı","Güçlü yaylar basınçlı hava tarafından sıkıştırılmış hâlde tutuluyordu ve bu basıncın kaybı yayların frenleri devreye sokmasına izin verdi","Düşük hava uyarı sesi onları serbest bırakana kadar sarı, baklava biçimli park kumandası tarafından açık konumda kilitlenmişlerdi","Onları serbest tutan şey servis fren pedalıydı ve ancak pedal basıncı azaldığında devreye girdiler"],"explanation":"Hava basıncı güçlü yaylı frenleri serbest konumda tutar; bu nedenle basınç 20-45 psi aralığının altına düştüğünde yaylar frenleri otomatik olarak uygular."},"53":{"q":"Sefer öncesi kontrolde yaylı (park) frenler serbest kalmıyor ve yaylı fren odacığında mekanik bir arıza olduğundan şüpheleniyorum. Bir iş arkadaşım bana bir alet verip güçlü yayların manuel olarak 'kafeslenebileceğini' (sıkıştırılabileceğini) söylüyor ki kamyonu tamirhaneye götürebileyim. Bu işlem konusunda hiç eğitim almadım. Doğru hareket nedir?","options":["Kamyonun tamirhaneye sadece kısa bir mesafe gitmesi gerektiği için yayları sadece bu seferlik kendim kafesleyeyim","Sıkışan odacığı yavaş yavaş gevşetmek için yaylı frenleri elle tekrar tekrar serbest bırakıp tekrar uygulayayım","Yaylara dokunmayayım ve onları kafeslemeye çalışmayayım, çünkü bu güçlü yayların kafeslenmesi yalnızca eğitimli personel tarafından yapılmalıdır","Güçlü yaylar kafeslenirken kolayca görünsün diye önce yaylı fren odacıklarını parlak bir renge boyayayım"],"explanation":"Yay frenlerini sıkıştırmak (caging) tehlikelidir çünkü yaylar büyük kuvvet depolar, bu yüzden yalnızca eğitimli personel yapmalıdır."},"54":{"q":"Sefer öncesi kontrolümü bitirdim ve sahadan çıkmadan önce hava freni kontrollerimi yapıyorum. Motor çalışırken ve hava basıncı tam dolmuşken, sarı elmas şeklindeki düğmeyi çekerek el frenini (park frenini) çektim. Şimdi yaylı frenlerin aracı gerçekten yerinde tutacağından emin olmak istiyorum. Bunu hangi işlem doğru şekilde test eder?","options":["Park frenini bırakıp ayak frenine sıkıca basarak pedalın sert olup olmadığını hissetmek","Fren pedalına birkaç kez ardı ardına basıp hava göstergesinde basınç düşüşü olup olmadığını izlemek","Motoru gazlayıp yaylı frenlerin yaklaşık 20-45 psi'de boşaldığını dinlemek","Park frenini çekili bırakıp debriyajı bırakarak araçla yavaşça öne, frene karşı doğru ilerlemek"],"explanation":"Park (yay) frenlerini kontrol etmek için onları çekili tutun ve düşük viteste yavaşça öne doğru çekerek aracı tuttuklarını doğrulayın."},"55":{"q":"Yüklü bir kombinasyon aracı uzun ve dik bir dağ yokuşundan aşağı indiriyorum ve hava frenlerimin kontrolünü kaybetmekten endişeleniyorum. Yokuşun en altına kadar hızımı güvenli bir şekilde yönetmek için hangi tekniği kullanmalıyım?","options":["İnişten önce düşük bir vitese geçmek ve hafif, düzenli fren basıncı uygulamak, hızım güvenli hızımın yaklaşık 5 mil/saat altına düştüğünde freni gevşetmek","Hızı sürekli düşük ve kontrol altında tutmak için iniş boyunca sert ve kesintisiz fren basıncı uygulamak","Frenlerin uygulamalar arasında soğuma fırsatı bulması için fren pedalına tekrar tekrar basıp bırakmak","Motoru korumak için boşa almak ve iniş boyunca gerektiğinde tüm yavaşlamayı frenlerin yapmasına izin vermek"],"explanation":"İnişte düşük vites seçin ve hafif, sabit fren basıncı uygulayın; güvenli hızınızın yaklaşık 5 mph altına düşünce frenden ayağınızı çekin."},"56":{"q":"Hava frenli kamyonumla normal hızda bir Teksas otoyolunda ilerliyorum ve trafik için yavaşlamak amacıyla ayak pedalına (treadle valfi) sertçe basıyorum. Bu pedalla hangi fren sistemini devreye sokuyorum?","options":["Hava ile boşta tutulan ve sarı düğmeyle ayarlanan park frenleri","Her türlü normal yavaşlama ve durma için kullandığım servis frenleri","Hava basıncı düştüğünde otomatik devreye giren acil durum frenleri","Yalnızca römork freni, römork el valfiyle ayrıca kontrol edilir"],"explanation":"Ayak pedalı (treadle valfi) servis frenlerini çalıştırır; bunlar tüm normal yavaşlama ve durmalarda kullanılır."},"57":{"q":"Sefer öncesi kontrolümde çekicimin fren kampanalarını ve disklerini inceliyorum. Hangi durum, bir kampana veya diskin tehlikeli olduğunu ve onarılana kadar araçla GİDİLMEMESİ gerektiğini gösterir?","options":["Kampana dokunulduğunda soğuktur ve hiçbir yağ filmi yoktur","Dış yüzeyde hafif bir yol tozu tabakası vardır","Kampanada görünür bir çatlak vardır veya yüzeyi aşırı derecede aşınmıştır","Kampanada yakın zamanda yapılan servisten kalan taze boya görünmektedir"],"explanation":"Çatlak veya aşırı aşınmış bir fren kampanası ısı ve yük altında bozulabilir, bu yüzden araç onarılana kadar servis dışı bırakılmalıdır."},"58":{"q":"Sefer öncesi muayene sırasında hava sistemini yaklaşık 125 psi'ye dolduruyor, motoru kapatıyor ve gösterge panelindeki saati izliyorsunuz. Frenler bırakılmışken ibre, izin verilen kaçak oranını çok aşacak şekilde düşmeye devam ediyor ve durma belirtisi göstermiyor. Düşük hava basıncı uyarısı henüz yanmadı. Doğru hareket nedir?","options":["Uyarı ışığı ve zil henüz çalmadığı için motoru çalıştırıp normal şekilde sürmek","Valflerin yeniden oturması için fren pedalına birkaç kez basıp planlandığı gibi yola devam etmek","Basınç 60 psi'nin üzerinde kaldığı sürece doğrudan en yakın tamirhaneye gitmek","Aracı hizmet dışı bırakıp, herhangi bir yere sürmeden önce kaçağı tamir ettirmek"],"explanation":"İzin verilen oranı aşan sürekli bir hava kaçağı depoları boşaltıp frenleri devre dışı bırakabilir, bu yüzden araç onarılana kadar servis dışı bırakılmalıdır."},"59":{"q":"Çekici-römork aracımla otoyolda ilerlerken gösterge panelimdeki sarı ABS arıza lambası yanıyor ve yanık kalıyor. Kamyon hâlâ normal şekilde fren yapıyor ve yönlendiriliyor. Bu lambanın bana söylediğine göre, hangi ifade EN doğru olanıdır?","options":["Kilitlenme önleyici sistemim çalışmıyor olabilir, ancak normal servis frenlerim hâlâ çalışıyor ve ABS'yi kontrol ettirmeliyim.","Servis frenlerim çoktan arızalandı, bu yüzden hemen kenara çekip park frenini çekmeliyim.","ABS'im tamamen devrede ve bu yol kesiminde durma mesafemi aktif olarak kısaltıyor.","Hava basıncım 60 psi'nin altına düştü ve yay frenleri tekerlekleri kilitlemek üzere."],"explanation":"Yanan sarı ABS lambası yalnızca kilitlenmeyi önleme işlevinin çalışmıyor olabileceğini gösterir; normal servis frenleri hâlâ çalışır ve ABS kontrol edilmelidir."},"60":{"q":"Uzun bir güzergâhta yüklü bir kombinasyon araç sürüyorum ve gösterge panelimdeki saatleri sürekli takip ediyorum. Pedala her bastığımda havalı frenlerimin gerçekten devreye girip bırakmasını sağlamak için, yolculuk boyunca sürekli korumam gereken TEK koşul hangisidir?","options":["Dolu bir yakıt deposu, çünkü frenler gücünü doğrudan motorun yakıt beslemesinden alır","Sistemde yeterli hava basıncı, çünkü frenleri devreye sokan ve bırakan şey havadır","Kısa huzme far ayarı, böylece fren uyarı sensörleri gündüz göstergeleri okuyabilir","Her durakta fren lambalarının çalıştığını doğrulamak için araçta en az bir yolcu bulunması"],"explanation":"Hava frenli sistem yeterli hava basıncına ihtiyaç duyar çünkü frenleri uygulayan ve serbest bırakan şey sıkıştırılmış havadır."},"61":{"q":"Sefer öncesi kontrolümde hava sistemini regülatör kesme (cut-out) seviyesine kadar dolduruyorum, ardından motoru çalışma devrinde tutup göstergenin 85 psi'den 100 psi'ye tırmanışını izliyorum. Aşağıdaki gözlemlerden hangisi hava kompresörünün sağlıklı olduğunu ve basınç yükselme hızının kabul edilebilir olduğunu gösterir?","options":["Gösterge 85 psi'den 100 psi'ye birkaç uzun dakika boyunca yavaşça sürünür ama sonunda ulaşır","Regülatör kompresörü zaten kestiği için basınç hiç hareket etmez","Gösterge 85 psi'den 100 psi'ye yaklaşık 45 saniyede, yani dakikalarla değil saniyelerle tırmanır","Gaza basar basmaz basınç anında 85 psi'den 100 psi'ye fırlar"],"explanation":"Çift devreli hava frenli sistemde basınç yaklaşık 45 saniyede 85'ten 100 psi'ye yükselmeli; bu sağlıklı kompresörün havayı hızla yenilediğini gösterir."},"62":{"q":"Sefer öncesi kontrolüm sırasında römorkun altına giriyorum ve bir tekerlekteki fren balatalarının perçinlerle neredeyse aynı seviyeye gelecek kadar inceldiğini fark ediyorum. Fren sistemindeki diğer her şey sorunsuz görünüyor. Bu aracı yola çıkarmadan önce aşağıdakilerden hangisi doğru harekettir?","options":["İtme çubuğu hareketi ve ayar kolları (gevşek ayarlayıcılar) hâlâ yasal sınır içinde test edildiği için balataları olduğu gibi bırakmak","Bir sonraki servise ulaşana kadar gıcırtıyı azaltmak için ince balatalara hafif bir kat fren hidroliği sürmek","Bunu kontrol raporuma not etmek ancak düşük hava uyarısı 60 psi üzerinde kaldığı sürece sürmeye devam etmek","Aracı servis dışı bırakmak ve sürmeden önce aşınmış balataları yenileriyle değiştirtmek"],"explanation":"Çok inceltmiş fren balataları artık yeterli sürtünme oluşturamaz, bu yüzden araç sürülmeden önce değiştirilmelidir."},"63":{"q":"Uzun bir dağ inişinde yüklü bir römork çekiyorum. Hızımı kontrol altında tutmak için fren pedalına tekrar tekrar basıp bırakıyorum (frenleri 'pompalıyorum'). Eğitmenim bunu bırakmam için beni uyarıyor. Uzun bir inişte fren pompalamanın TEHLİKELİ olmasının ANA nedeni aşağıdakilerden hangisidir?","options":["Havayı kompresörün yeniden basabileceğinden daha hızlı tüketerek hava deposunu boşaltabilir","Fren kampanalarını çok hızlı soğutur ve ısı şokuyla balataları çatlatabilir","Römork besleme deposuna fazladan hava iter ve emniyet supabını aşırı yükler","Fren ayarlayıcılarının sıkışmasına ve itme çubuğu hareketinin çok kısalmasına neden olur"],"explanation":"Frenleri tekrar tekrar pompalamak, her uygulamada havayı kompresörün yeniden basabileceğinden daha hızlı boşaltarak hava deposunu tüketir."},"64":{"q":"Otomobil kullanmaktan, havalı fren sistemiyle donatılmış bir çekici-römork kullanmaya yeni geçtim. Fren pedalına bastığımda, fren pabuçlarını kampanalara bastırıp aracı yavaşlatmak için hatlardan aslında neyin geçtiğini gözümde canlandırmaya çalışıyorum. Bu havalı fren sisteminde, pedalda oluşturduğum kuvvet tekerleklere hangi araçla iletilir?","options":["Tıpkı arabamdaki gibi, ana silindirden itilen basınçlı hidrolik fren sıvısı","Tanklarda depolanan ve hatlar üzerinden fren haznelerine bırakılan basınçlı hava","Pedaldan her tekerleğe kadar gerdirilen ağır bir çelik halat ve mekanik bağlantı","Bir tel boyunca gönderilip her tekerlekteki fren mıknatısını besleyen elektrik akımı"],"explanation":"Havalı frenler, depolarda saklanan ve fren hatlarından hazneler içine bırakılan basınçlı hava ile kuvvet iletir."},"65":{"q":"Havalı frenli yüklü bir kamyon kullanırken bir hat patlıyor ve hava basıncım tamamen sıfıra düşüyor. Yanımdaki bir aday sürücü, bu sistemin neden onun kamyonetindeki hidrolik frenlerden daha güvenli sayıldığını soruyor. Tam bu durumda havalı fren sistemimin gerçek güvenlik avantajını EN İYİ açıklayan ifade hangisidir?","options":["Çalışma akışkanı hava olduğu için, sistemdeki tüm hava sızdıktan sonra bile servis frenlerim normal şekilde çalışmaya devam eder.","Basınç 60 psi'nin altına düştüğünde kamyonu fiilen durduran şey, düşük hava basıncı uyarı zilidir.","Hava basıncı 20 ila 45 psi aralığına düştükçe, yaylı (acil durum) frenler otomatik olarak devreye girer ve kamyonu durdurur.","Havalı frenler, herhangi bir sızıntıdan bağımsız olarak yüklü bir kamyonu daima hidrolik frenlerden daha kısa mesafede durduracak şekilde tasarlanmıştır."],"explanation":"Hava basıncı 20 ila 45 psi aralığına düştüğünde, yaylı (acil) frenler otomatik olarak devreye girer ve aracı durdurur."},"66":{"q":"Yüklü bir çekici-römork ile otoyolda giderken bir hat patlıyor ve hava basıncım tamamen boşalıyor. Sistem boşaldıkça yaylı (park) frenlerime ne olur?","options":["Onlara hiçbir şey olmaz, çünkü yaylı frenler yalnızca pedala bastığımda servis frenim olarak çalışır","Serbest kalmış halde kalırlar, çünkü güçlü yayların sıkıştırılmış halde tutulması için depolanmış hava basıncına ihtiyacı vardır","Tamamen serbest kalırlar, çünkü havanın kaybolması tam da yayları serbest bırakıp aracın yuvarlanmasını sağlayan şeydir","Otomatik olarak devreye girerler, çünkü onları serbest tutan hava gidince yaylar frenleri sıkıştırır"],"explanation":"Yaylı frenler hava basıncıyla açık tutulur, bu nedenle hava kaybolduğunda yaylar arıza-emniyeti olarak frenleri otomatik sıkıştırır."},"67":{"q":"Motor kapalıyken ve sistem tamamen dolu durumdayken bir fren kontrolü yapıyorum. Hava depolarındaki havayı boşaltmak için fren pedalına sürekli basıp bırakıyor, hava göstergesinin düşüşünü izliyorum. İbre düşmeye devam ederken, çekici koruma valfinin otomatik olarak kapanıp römork hava beslemesini kesmesini yaklaşık hangi basınçta beklemeliyim?","options":["Basınç düşük aralığa inerken yaklaşık 20 ila 45 psi arasında","Düşük hava uyarısının etkin olduğu sırada yaklaşık 60 ila 80 psi arasında","Regülatörün normal çalışma bandına yakın, yaklaşık 100 ila 125 psi arasında","Yalnızca gösterge neredeyse boşu gösterdikten sonra, yaklaşık 5 ila 10 psi arasında"],"explanation":"Çekici koruma valfi ve römork hava beslemesi, sistem hava basıncı 20 ila 45 psi aralığına düştüğünde otomatik olarak kapanır."},"68":{"q":"Yüklü bir römorka bağlıyım ve kabinde ön kontrolümü bitiriyorum. Hareket etmeden önce römorkun hava sistemini doldurmak ve frenlerini boşaltmak için gösterge panelindeki belirli bir kumandayı içeri itmem gerekiyor. Römorka hava sağlamak için içeri itmem gereken düğmenin rengi ve şekli hangisidir?","options":["Sarı, baklava (eşkenar dörtgen) şeklindeki düğme, çünkü römork frenlerine havayı bu kumanda besler","Kırmızı, sekizgen (sekiz köşeli) düğme, çünkü römork hava besleme kumandası budur","Mavi, yuvarlak düğme, çünkü römorka giden servis hattı mavi renkle kodlanmıştır","Sarı, sekizgen (sekiz köşeli) düğme, çünkü römork beslemesi park kumandasının şekliyle aynıdır"],"explanation":"Römork hava besleme kumandası, römorkun hava sistemini dolduran ve frenlerini boşaltan kırmızı, sekizgen (oktagon) düğmedir."},"69":{"q":"Çekici-römork aracımı bir dinlenme tesisine park ettim ve motoru kapatmak üzereyim. Aracın yerinde kalması için park (yaylı) frenini devreye almak amacıyla gösterge panelindeki hangi kumandayı dışarı çekmem gerekir?","options":["Servis freni basıncını boşaltan mavi yuvarlak düğmeyi","Gösterge saatlerinin yanındaki kırmızı, sekizgen (oktagon) düğmeyi","Kumanda panelindeki sarı, baklava (eşkenar dörtgen) biçimli düğmeyi","Römork el valfinin yanındaki yeşil kare kolu"],"explanation":"Park (yaylı) fren kumandası, yaylı frenleri uygulamak için çekilen ve boşaltmak için itilen sarı, baklava şeklinde düğmedir."},"70":{"q":"Sefer öncesi kontrolde motor stop ediyor ve kompresör dönmeyi durduruyor, ancak besleme deposunun basıncını duran kompresöre doğru geri boşaltmak yerine koruduğunu fark ediyorum. Bu davranıştan hangi parça sorumludur?","options":["Kompresörün durduğunu algıladığında depo havasını hapseden emniyet supabı","Kesme basıncı ayarına ulaşıldığında besleme deposunu kapatan regülatör (governor)","Depolanmış havayı içeride kilitlemek için sıkıca kapanan otomatik tahliye valfi","Havanın durmuş kompresöre doğru geri akmasını engelleyen tek yönlü çek valf"],"explanation":"Tek yönlü çek valf havanın yalnızca depoya akmasına izin verir, böylece kompresör durduğunda depolanan havanın geri kaçmasını engeller."},"71":{"q":"Amarillo'da dondurucu bir Ocak sabahı, sevkiyat görevlisi traktörümün hava frenli sistemde bir alkol buharlaştırıcıyla donatıldığını söylüyor. Sefer öncesi kontrolü yaparken, bu cihazın bu koşullarda benim için ne yaptığı soruluyor. Hangi ifade amacını EN İYİ şekilde açıklar?","options":["Soğuk havada hatlarda ve valflerde buz oluşma olasılığını azaltmak için hava sistemine alkol verir","El frenlerinin soğukta donmaması için alkol yakarak fren kampanalarını ısıtır","Nemi emmesi için havaya alkol katar, böylece hava depolarını artık her gün boşaltmam gerekmez","Alkol buharı salarak hava kompresörü verimini artırır, böylece soğukta basınç daha hızlı yükselir"],"explanation":"Alkol buharlaştırıcı, soğuk havalarda hatlarda ve valflerde buz oluşma olasılığını azaltmak için hava sistemine alkol verir."},"72":{"q":"Sefer öncesi kontrolümde, havalı frenli çekicimin tekerleklerinden birindeki temel fren (foundation brake) grubunu adım adım inceliyorum. Fren uygulandığında, ayar kolunun (slack adjuster) bir mili döndürdüğünü, bu milin de S şeklindeki kamı çevirerek fren pabuçlarını ve balatalarını dışa, kampananın iç yüzeyine doğru ittiğini görüyorum. Her parçanın yerinde ve çalışır olduğunu doğrularken, bu S-kamlı temel frende bulmayı BEKLEMEMEM gereken parça aşağıdakilerden hangisidir?","options":["İtme çubuğu hareketini fren kamının dönüşüne çeviren ayar kolu (slack adjuster)","Pabuçları dışa itmek için sıvı basıncı oluşturan hidrolik ana fren merkezi (master silindir)","Pabuçların durdurma sürtünmesi oluşturmak için bastırdığı fren kampanası","Frenleme sırasında kampanaya doğru itilen fren pabuçları ve balataları"],"explanation":"S-kamlı havalı temel fren tamamen mekanik-pnömatiktir ve sıvı içermez, bu yüzden hidrolik ana silindir bulunmaz."},"73":{"q":"Yüklü bir römorku uzun ve dik bir yokuştan aşağı indirirken servis frenlerim zayıflıyor ve pedal yumuşuyor. Aracım modülasyonlu kumanda valfi ile donatılmış. Bu durumda bu valf bana gerçekte ne yapma imkânı verir?","options":["Tamamen arızalanmadan önce hatlardaki hava basıncını yeniden oluşturmak için servis frenlerine tekrar tekrar basmak","Regülatörü devre dışı bırakarak kompresörün 125 psi üzerinde kesmesini ve fren gücümü geri kazandırmasını sağlamak","Yaylı (acil) frenleri tek seferde tam kavramak yerine kumanda koluyla kademeli olarak uygulamak","Tekerleklerin kilitlenip yokuşta hızı daha çabuk kesebilmesi için ABS'yi kapatmak"],"explanation":"Modülasyonlu kumanda valfi, servis frenleri arıza yaparsa kumanda koluyla yaylı (acil) frenleri kademeli uygulayarak kontrollü durmayı sağlar."},"74":{"q":"Yüklü bir tek parça kamyonu kullanırken düşük hava basıncı uyarı ışığının yandığını ve uyarı sesinin öttüğünü fark ediyorum. Daha önceki sefer öncesi kontrolde önemsiz sandığım küçük bir hava kaçağı görmüştüm. Benzer küçük bir kaçakta hidrolik fren sisteminin nasıl davranacağıyla karşılaştırıldığında, şu anda hava frenlerimden ne beklemeliyim?","options":["Frenler kaçak başlar başlamaz tıpkı bir hidrolik sistem gibi anında tamamen devre dışı kalır, böylece kullanılabilir hiç frenim kalmaz","Hava basıncı kaybı hiçbir uyarı vermez, bu yüzden ışık ve uyarı sesi ilgisiz başka bir arızayı gösteriyor olmalı","Kaçak sürüş sırasında gerçekten doğrulanamaz, bu yüzden park edip hatları inceleyene kadar hızla devam etmeliyim","Hava basıncı kaldığı sürece frenler çalışmaya devam eder ve uyarı, basınç fazla düşmeden güvenle durmam için beni uyarıyor"],"explanation":"Hava frenleri tanklarda kullanılabilir hava basıncı kaldığı sürece çalışır ve düşük basınç uyarısı, güvenle durabilmeniz için basınç 60 psi altına düşmeden önce devreye girmelidir."},"75":{"q":"Tek çekicide sefer öncesi kontrolün hava freni kısmını yapıyorum. Depoları zaten boşalttım ve basıncı regülatör kesme (cut-out) seviyesine kadar yükselttim. Avludan çıkmadan önce, hava freni kontrolünü tamamlamak için gerçekten çalıştığını hâlâ doğrulamam gereken fren işlevleri hangileridir?","options":["Düşük hava basıncı uyarısı, yaylı (park) frenler ve servis frenleri","Sadece yaylı (park) frenler ve servis frenleri, çünkü uyarı çalıştırmada kendini test eder","Sadece düşük hava basıncı uyarısı ve servis frenleri, çünkü yaylı frenler otomatik devreye girer","Sadece servis frenleri, çünkü 5 mil/saatte sağlam bir pedal tüm sistemin sağlam olduğunu kanıtlar"],"explanation":"Tam bir hava freni kontrolü üç şeyi doğrulamalıdır: düşük hava basıncı uyarısı, yaylı (park) frenler ve servis frenleri."},"76":{"q":"Hidrolik frenli bir araçta kazandığım geçerli bir CDL'ye zaten sahibim ve az önce havalı (hava) frenli tek parça bir kamyon satın aldım. Bu havalı frenli kamyonu yasal olarak kullanmadan önce, eski hidrolik frenli aracıma uygulanMAYAN ve Teksas'ın benden istediği ek adım hangisidir?","options":["Ekstra hiçbir şey — mevcut CDL'm zaten her fren sistemini kapsıyor, bu yüzden olduğu gibi kullanabilirim","Havalı fren (kısıtlamasız) testini geçmeliyim, aksi takdirde ehliyetimde havalı fren kısıtlaması yer alır","Sadece daha küçük kamyon boyutuna uymak için bir Class C tanımı eklemem yeterli","Havalı frenli herhangi bir aracı kullanmadan önce ayrı bir motosiklet onayı (endorsement) almalıyım"],"explanation":"Hava freni bilgi ve beceri testini geçmelisiniz, aksi halde ehliyetinize hava freni kısıtlaması konur ve hava frenli araçları kullanmanız yasaklanır."},"77":{"q":"Yüklü bir römork çekerek ıslak bir otoyolda giderken bir araba önüme girip aniden duruyor. Fren pedalına sertçe basıyorum ve ABS donanımlı çekici-römork takımımda ABS devreye giriyor. Bu sert frenleme anında ABS'nin benim için gerçekçi olarak ne yapmasını beklemeliyim?","options":["Toplam durma mesafemi çarpıcı biçimde kısaltarak öndeki aracın çok gerisinde durmamı sağlamasını","Ben pedala basmadan önce bile frenleri benim yerime otomatik olarak uygulamasını","Tekerleklerimin kilitlenmesini önleyerek sert fren yaparken tehlikeye doğru direksiyonla manevra yapabilmemi sağlamasını","Pedal sonuna kadar basıldığında asıl servis frenlerimin yerini almasını"],"explanation":"ABS, sert frenlemede tekerleklerin kilitlenmesini önler, böylece direksiyon kontrolünü korur ve tehlikenin etrafından dönebilirsiniz."},"78":{"q":"Tek hava frenli bir kamyon kullanıyorum ve sessiz bir otoyol şeridinde motor stop ediyor. Kompresör artık çalışmadığı için havanın yavaşça boşalacağını bilerek banketin kenarına yanaşırken gözümü hava basınç göstergesinden ayırmıyorum. Hava rezervimi kaybettiğimi haber veren düşük hava basıncı uyarısının (ışık ve sesli uyarı) İLK olarak yaklaşık hangi basınçta devreye girmesini beklemeliyim?","options":["Yaklaşık 100 psi; regülatörün normalde kompresörü tekrar devreye soktuğu nokta","Yaklaşık 125 psi; regülatörün normalde kompresörü devre dışı bıraktığı nokta","Yaklaşık 30 psi; yay frenlerinin otomatik olarak devreye girmek üzere olduğu an","Yaklaşık 60 psi; basınç tehlikeli derecede düşmeden çok önce"],"explanation":"Düşük hava basıncı uyarısı, basınç tehlikeli derecede düşmeden çok önce yaklaşık 60 psi'de devreye girmelidir."},"79":{"q":"Sefer öncesi kontrolümü yapıyorum ve pedala bastığımda havalı frenlerimi gerçekte neyin devreye soktuğunu canlandırmaya çalışıyorum. Motorum, göstergelerim ve hatlarım sağlamken, havalı frenlerim aşağıdakilerden hangisi yeterli kaldığı sürece kamyonu durdurmaya devam eder?","options":["Depolarda (tanklarda) oluşturulup depolanan hava basıncı","Ana merkez silindirindeki hidrolik fren hidroliği (sıvısı)","Fren devresini besleyen motor yağı basıncı","Fren valflerini besleyen 12 voltluk akü şarjı"],"explanation":"Hava frenleri, sıvıyla değil, tanklarda biriktirilip depolanan sıkıştırılmış hava basıncıyla uygulanır ve tutar."},"80":{"q":"Sefer öncesi kontrolüm sırasında, kampanalı (drum) frenli bir aksın hava fren mekanizmasını takip ediyorum. Fren körüğünden (brake chamber) itme çubuğuna (pushrod), oradan da tekerlekteki bir mili döndüren ayar kolu (slack adjuster) yoluna kadar izliyorum. Bu milin ucunda, iki fren pabucu arasında S şeklinde bir parça buluyorum. Frene bastığımda, pabuçları kampanaya doğru iterek tekerleği yavaşlatan SON mekanik hareket hangisidir?","options":["İtme çubuğu fren körüğünden dışarı uzar ve doğrudan fren pabuçlarını kampanaya doğru bastırır","S-kam (S-cam) döner ve iki fren pabucunu birbirinden ayırarak balatalarını kampananın iç yüzeyine bastırır","Ana merkez silindirden gelen hidrolik sıvı, pabuçları kampanaya kenetleyen bir tekerlek pistonunu iter","Ayar kolu, tekerlek göbeğine takılı bir diske bir çift balatayı sıkıştırır"],"explanation":"Hava basıncı itme çubuğunu ve ayar kolunu hareket ettirerek S-kamı döndürür; bu da fren pabuçlarını açıp balatalarını kampananın iç yüzeyine bastırır."},"81":{"q":"Sefer öncesi muayenemde, çekicimin şasisi boyunca, motordan ve yakıt sisteminden ayrı, birkaç metal depo takılı olduğunu fark ediyorum. Yeni bir sürücü bu besleme (depolama) depolarının hava fren sistemi için gerçekte ne işe yaradığını soruyor. Hangi cevap görevlerini doğru açıklar?","options":["Havayı üretip basınçlandırırlar; kompresör yaklaşık 125 psi'de regülatör kesme noktasına ulaştığında pompalama işini devralırlar","Havadaki suyu ve yağı temizlerler, böylece hatların gün sonunda asla boşaltılması gerekmez","Sıkıştırılmış hava rezervini tutarlar, böylece frenleri çalıştırmak için her zaman yeterli basınç bulunur","Düşük basıncı algılarlar ve basınç yaklaşık 60 psi'nin altına düşmeden önce uyarı ışığını ve uyarı sesini tetiklerler"],"explanation":"Besleme tankları, servis, park ve acil frenleri çalıştırmak için her zaman yeterli basınç bulunsun diye bir sıkıştırılmış hava rezervi tutar."},"82":{"q":"Yüklü tek bir kamyon kullanırken ana hava hattı patlıyor. Hava göstergesinin ibresi sürekli düşüyor, düşük hava uyarı ışığı ve sesli uyarı zaten devreye girdi ve ben fren pedalına dokunmuyorum. Basınç düşmeye devam ederken kamyonumun kendiliğinden durmasına ne sebep olur?","options":["Gösterge regülatörün kesme noktasını geçince servis frenleri ayak valfi üzerinden kendiliğinden devreye girer","Emniyet tahliye valfi sistemi boşaltır ve bu mekanik olarak servis frenlerini kampanalara bastırır","Düşük hava uyarı devresi, ışık ve sesli uyarı yanar yanmaz frenleri anında devreye sokar","Yay frenleri, düşen basınç yayların devreye girdiği düşük aralığa ulaşır ulaşmaz otomatik olarak devreye girer"],"explanation":"Yaylı frenler hava basıncıyla açık tutulur; bu yüzden kaçak basıncı düşük aralığa (yaklaşık 20-45 psi) düştüğünde yaylar frenleri otomatik olarak uygular."},"84":{"q":"Bir teslimat seferinde düşük hava uyarı lambam aniden yanıyor ve iki hava basınç göstergemden birinin hızla düştüğünü, diğerinin ise sabit kaldığını fark ediyorum. Aracımda çift devreli havalı fren sistemi var. Şu anda hâlâ bir miktar frenleme kabiliyetine sahip olmamı EN İYİ açıklayan ifade hangisidir?","options":["Sistem iki ayrı devreye bölünmüştür, bu yüzden arızalanan devrenin basınç kaybı, hâlâ basınç tutan devreyi devre dışı bırakmaz","Her iki devre tek bir büyük ortak depodan beslenir, bu yüzden sabit gösterge arızalı tarafa geri hava besler","Bir hidrolik yedek fren, hava devrelerinden biri basınç kaybettiğinde otomatik olarak devreye girer","Çift devreli sistem el frenini ortadan kaldırır, böylece kalan tüm hava servis frenlerine yönlendirilir"],"explanation":"Çift hava fren sistemi iki bağımsız devreye sahiptir, bu yüzden bir devredeki kaçak veya arıza diğerini boşaltmaz; sağlam devre basıncı tutar ve kendi bölümünü frenler."},"85":{"q":"Soğuk bir sahada çekici-römork motorumu yeni çalıştırdım. Düşük hava basıncı uyarı ışığı söndü, ancak otoparktan çıkmaya hazırlanırken göstergem hâlâ yalnızca 65 psi gösteriyor. Texas DPS prosedürüne göre, sürmeye başlamadan önce basıncın yükselmesine izin vermem gereken EN DÜŞÜK basınç nedir?","options":["65 psi, çünkü düşük hava basıncı uyarı ışığı zaten söndü","Yaklaşık 100 psi, böylece frenleri güvenle çalıştıracak kadar hava olur","Yaklaşık 60 psi, düşük hava uyarısının söndüğü nokta","Yaklaşık 125 psi, regülatör kesme basıncı, el frenini bırakmadan önce"],"explanation":"Sürüşe başlamadan önce hava basıncının en az yaklaşık 100 psi'ye yükselmesine izin verin, böylece servis ve acil frenleri güvenle çalıştıracak yeterli hava olur."},"86":{"q":"Tek bir düz kamyonda yola çıkış öncesi kontrolümde hava sistemini yaklaşık 125 psi'ye kadar dolduruyorum, motoru kapatıyorum ve tekerleklere takoz koyuyorum. Frenler boşta kalsın diye el freni (park freni) düğmesini içeride bırakıyorum ve gösterge panelindeki manometreyi izliyorum. İlk dakikada ibre 4 psi'den fazla düşüyor. Bu, araç hakkında bana ne söylüyor?","options":["Bir sorun yok; motor kapalıyken depolardaki hava sadece soğuyup büzüldüğü için ilk dakikada bu boyutta bir düşüş beklenen bir durumdur.","Bu okuma, yaylı (park) frenlerinin doğru şekilde devreye girdiğini kanıtlar; çünkü park sistemi devreye girince basınç her zaman hızla boşalır.","Sistem izin verilenden daha hızlı hava kaçırıyor; frenler boştayken tek bir araç dakikada en fazla 2 psi kaybetmeli, 4 psi'den fazlası ise bulunup giderilmesi gereken bir kaçak demektir.","Bu, regülatörün (governor) kesme noktasına ulaşıp kompresörü durdurduğunu doğrular; motoru kapattıktan sonra basınç zaten böyle davranır."],"explanation":"Frenler bırakılmışken tek araç dakikada 2 psi'den fazla kaybetmemelidir, bu yüzden 4 psi'den fazla kayıp bulunup giderilmesi gereken bir hava kaçağına işaret eder."},"87":{"q":"Yükleme rampasında park hâlindeyim ve yavaş bir hava kaçağı hava depolarımı boşaltırken sistem basıncı sıfıra doğru düşmeye devam ediyor. Basınç boşalırken, aracın kaymasını önlemek için hava frenli sistemim ne yapar ve neden? DOĞRU ifadeyi seçin.","options":["Servis frenleri tekerlekleri sıkıştırmak için depolanmış hidrolik sıvı kullanır, bu yüzden depolarda hiç hava kalmasa bile kamyon yerinde durur.","Basınç gidince kamyonu hiçbir şey tutmaz; o tek küçük kaçak anında tüm frenleri serbest bırakır ve araç serbestçe kaymaya başlar.","Kompresör kaçağı otomatik olarak 125 psi'ye geri pompalar, böylece ayak valfli servis frenleri aracı kendi başına durdurur.","Yaylı (park) frenleri, basınç 20-45 psi aralığına düştüğünde otomatik olarak devreye girer ve hiç hava olmadan tekerlekleri mekanik olarak tutar."],"explanation":"Yaylı park frenleri hava ile açık tutulur, bu yüzden basınç 20-45 psi aralığına düştüğünde güçlü yaylar frenleri otomatik olarak uygular ve tekerlekleri hava olmadan tutar."},"88":{"q":"Havalı frenli çekicimin motorunu yeni çalıştırdım ve hava basınç göstergesi yalnızca 50 psi gösteriyor, düşük hava uyarı zili hâlâ çalıyor. Park halindeyim, yüküm dolu ve teslimat için geç kalıyorum. Park frenini bırakıp avludan çıkmadan önce ne yapmalıyım?","options":["Motoru çalışır halde tutarak, basınç yaklaşık 100 psi'ye yükselip düşük hava uyarısı kapanana kadar beklemeliyim","50 psi'de yavaşça çıkmalıyım, çünkü teslimata giderken frenler basıncı yola devam ettikçe artırmaya devam eder","Sıkışan havayı boşaltmak için tank tahliye vanalarını açmalıyım, böylece kompresör tankları daha hızlı doldurur","Düşük hava uyarı zilini devre dışı bırakıp sesi kesmeli, gürültü durduğunda yola çıkmalıyım"],"explanation":"Motoru çalışır durumda tutun ve sürmeden önce basınç yaklaşık 100 psi'ye yükselip düşük hava uyarısı kapanana kadar bekleyin."},"89":{"q":"Yüklü bir katarla uzun bir dağ yokuşunu iniyorum ve yol boyunca fren pedalına sabit bir basınç uyguladım. Yokuşun dibine yakın, pedal hâlâ sert hissettiriyor ama bastığımda araç neredeyse hiç yavaşlamıyor. Frenlerimin durdurma gücünü neden kaybettiğini EN İYİ hangi açıklama anlatır?","options":["Sürekli frenleme, sistem hava basıncını regülatör kesme noktasının üzerine çıkardı, bu yüzden frenler artık yeterli kuvvet üretemiyor","Sürekli frenleme fren kampanalarını ve balatalarını aşırı ısıttı ve bu ısı, frenlerin üretebildiği sürtünmeyi azaltır","Sürekli frenleme hava depolarını yavaşça boşalttı ve yay frenleri bunu telafi etmek için kısmen çözüldü","Ayar kolları ısıdan dolayı sıkıştı ve balataları kampanalardan uzaklaştırdı"],"explanation":"Uzun bir inişte sürekli sabit frenleme kampanaları ve balataları aşırı ısıtır ve bu ısı frenlerin üretebileceği sürtünmeyi azaltarak fren sönmesine yol açar."},"90":{"q":"Havalı frenli kamyonumla bir dur işaretine yaklaşıyorum ve fren pedalına sertçe basıyorum. Ayağım anında hareket etmesine rağmen, kamyonun gerçekten yavaşlamaya başladığını hissetmeden önce belirgin bir gecikme oluyor. Eğitmenim buna 'fren gecikmesi' (brake lag) diyor. Bu gecikme sırasında aslında ne oluyor?","options":["Fren ayar kollarım (slack adjuster) ayarsız, bu yüzden itme çubukları balataları çok yavaş oturtuyor","Sürücü olarak tepki sürem, karar verme ile frenleme arasındaki gecikmeyi yaratıyor","Havanın hatlardan geçip frenlere ulaşması bir saniyenin küçük bir kısmını alıyor","Hava basıncı devreye girme eşiğinin altına düştü, bu yüzden regülatörün önce yeniden basınç oluşturması gerekiyor"],"explanation":"Fren gecikmesi, sıkıştırılmış havanın pedaldan fren odacıklarına hatlar boyunca ulaşması için geçen yaklaşık yarım saniyedir ve her hava fren sisteminin normal bir özelliğidir."},"91":{"q":"Eski bir havalı frenli çekicide sefer öncesi muayene sırasında havayı dolduruyorum, motoru kapatıyorum ve basıncı düşürmek için frenlere art arda basmaya başlıyorum. Gösterge 60 psi'ye doğru düşerken, küçük mekanik bir kol aniden ön camın üzerinde görüş alanıma düşüyor. Eğitmen buna 'wig-wag' diyor. Bu cihazın amacı nedir?","options":["Kompresörün kesme noktasına ulaştığını ve depolara hava basmayı durdurduğunu bildiren regülatördür (governor)","Acil durumda yaylı frenleri kademeli olarak uygulamamı sağlamak için aşağı düşen modülasyonlu kontrol valfidir","Besleme deposunda biriken su ve yağı boşaltan otomatik tahliye valfidir","Basıncın tehlikeli derecede düştüğü konusunda beni uyarmak için görüş alanına fiziksel olarak düşen mekanik bir düşük hava basıncı uyarı cihazıdır"],"explanation":"Wig-wag, yaylı kolu sürücünün görüş alanına düşerek hava basıncının tehlikeli derecede düştüğünü bildiren mekanik bir düşük hava uyarı cihazıdır."},"92":{"q":"Sefer öncesi kontrolde fren pedalına basıp bir tekerlekteki fren mekanizmasını izliyorum. Hava fren körüğünü (brake chamber) doldurdukça itme çubuğu (push rod) dışarı doğru uzuyor. Düzgün çalışan bir S-kamlı kampanalı frende, bu itme çubuğunun hareketi BUNDAN SONRA ne yapmalıdır?","options":["Ayar kolunu (slack adjuster) döndürerek S-kamı çevirir ve fren pabuçlarını kampanaya bastırır","Hiçbir kam veya kol olmadan fren pabuçlarını doğrudan kampanaya bastırır","Yaylı fren körüğünü açar, böylece park yayları servis frenlerinin uygulanmasına yardım eder","Sistem basıncını korumak için besleme deposuna fazladan sıkıştırılmış hava gönderir"],"explanation":"Fren odacığındaki hava itme çubuğunu iter, bu da ayar kolunu döndürür ve S-kamını çevirerek fren pabuçlarını kampanaya karşı iter."},"93":{"q":"Havalı frenli 2020 model bir çekici aldım ve bu kadar yeni bir araç için anti-blokaj sisteminin federal şartı karşıladığını doğrulamak amacıyla ABS kablolarını izliyorum. Her aksı kontrol ederken hangi tekerleklerde ABS bulmam gerekiyor?","options":["Yalnızca ön (direksiyon) tekerleklerinde, çünkü kilitlenme orada direksiyon hâkimiyetini kaybettirir","Çekicinin tüm tekerleklerinde, çünkü yeni çekicilerin her tekerlekte ABS bulundurması gerekir","Yalnızca arka çeker tekerleklerinde, çünkü en ağır fren yükü orada oluşur","Hiçbir tekerlekte, çünkü ABS alıcının sonradan eklediği isteğe bağlı bir donanımdır"],"explanation":"ABS, 1 Mart 1997'de veya sonrasında üretilen çekicilerin her tekerleğinde gereklidir, bu yüzden daha yeni bir çekicinin tüm tekerleklerinde ABS bulunmalıdır."},"94":{"q":"Kombine aracımın sefer öncesi muayenesinde gösterge paneli çekicinin kendi ABS'sinin sorunsuz olduğunu söylüyor, ancak yine de römorkun ABS'sinin çalıştığını doğrulamam gerekiyor. Römork 1999 yılında üretildiği için kendi ABS sistemi ve kontrol etmem gereken ayrı bir arıza lambası var. Aracın etrafında dolaşırken bu römork ABS arıza lambasını nerede aramalıyım?","options":["Çekici kabinine baksın diye römorkun ön tarafında, kingpin yakınında","Kabinin içindeki gösterge panelinde, çekicinin kendi ABS uyarı lambasının hemen yanında","Etrafı dolaşırken görülebilecek şekilde römorkun sol tarafında veya sol arkasında","Römorkun hava deposunun içinde, manuel boşaltma vanasının arkasında"],"explanation":"1999 model bir römorkta, ABS arıza lambası, dış kontrol sırasında görülebilmesi için römorkun sol tarafına veya sol arkasına monte edilir."},"95":{"q":"Hava destekli hidrolik (air-over-hydraulic) fren sistemine sahip orta tonajlı bir kamyon kullanıyorum. Sefer öncesi kontrolde, hava beslemesi arızalanırsa neyi kaybedeceğimi bilmek için bu sistemdeki havanın gerçekte ne yaptığını anlamak istiyorum. Bu düzende hava basıncının rolünü hangi ifade doğru şekilde tanımlar?","options":["Hava basıncı kaliperlerin içinde dolaşarak hidrolik sıvısını soğutur ve uzun yokuş inişlerinde aşırı ısınmasını önler","Hava basıncı hidrolik sıvısını tam dolu tutar ve aşınmış contalardan kaybedilen sıvıyı otomatik olarak yerine koyar","Hava basıncı aküyü şarj eden kompresörü çalıştırır, böylece hidrolik pompa her zaman güç bulur","Hava basıncı hidrolik sisteme etki ederek sürücünün pedala uyguladığı fren kuvvetini artırır (güçlendirir)"],"explanation":"Hava destekli hidrolik sistemde hava basıncı, sürücünün pedala uyguladığı kuvveti artırır ve bu kuvvet hidrolik sıvı aracılığıyla tekerlek frenlerine iletilir."},"96":{"q":"Yola çıkış öncesi muayene sırasında, fren ayar kollarının (slack adjuster) aşırı itme çubuğu hareketi gösterdiğini, yani frenlerin ayarsız olduğunu fark ediyorsunuz. Yine de yola çıkıp uzun ve dik bir yokuştan aşağı inerseniz, bu kusurun EN olası sonucu nedir?","options":["Fren gücü azalır ve frenler yokuşta ısındıkça tamamen devre dışı kalabilir","Frenler normalden daha sert tutar, tekerleklerin kilitlenme ve kayma riskini artırır","Sistem sadece daha az hava harcar, böylece yokuşta fren pedalını daha uzun süre güvenle pompalayabilirsiniz","Düşük hava basıncı uyarısı erken devreye girer, ancak fren gücünün kendisi etkilenmez"],"explanation":"Ayarı bozuk frenler frenleme gücünü azaltır ve uzun, dik bir iniş gibi ısı yükü altında zayıflayıp tamamen devre dışı kalabilir."},"97":{"q":"Havalı frenli kamyonumla hafif bir yokuş aşağı iniyorum ve yavaşlamak için fren pedalına biraz daha sert basıyorum. Pedala bastıkça, iki basınç göstergemden biri ne kadar sert basarsam o kadar yükseliyor. Hangi göstergeye bakıyorum ve bana ne söylüyor?","options":["Depo (besleme) basınç göstergesi; tanklarımda hâlâ ne kadar hava depolandığını gösterir","Uygulama basınç göstergesi; fren pedalıyla frenlere uyguladığım hava basıncını gösterir","Regülatör kesme göstergesi; kompresörün 125 psi'de pompalamayı ne zaman durduracağını gösterir","Düşük hava uyarı göstergesi; basıncın 60 psi'nin altına düşmek üzere olduğunu gösterir"],"explanation":"Uygulama basınç göstergesi, frenlere gönderilen hava basıncını gösterir; bu nedenle pedala daha sert bastıkça değeri yükselir, gevşettikçe düşer."},"98":{"q":"Kuru bir otoyolda 55 mil/saat hızla havalı frenli bir çekici-römork kullanırken önde arızalı bir araba görüyorum ve fren pedalına sertçe basıyorum. Bir sınıf arkadaşım, havanın hatlardan geçip frenleri uygulaması için geçen yarım saniyenin otoyol hızında neredeyse hiç önemi olmadığını söylüyor. Bu fren gecikmesi 55 mil/saatte — algılama, tepki ve etkin fren mesafelerinin ÜZERİNE — yaklaşık ne kadar EK durma mesafesi ekler?","options":["Saydıracak hiçbir şey — yarım saniyelik gecikme 55 mil/saatte ölçülebilir bir mesafe ekleyemeyecek kadar kısadır","Yaklaşık 12 fit — frenler tutana kadar kabaca çekicinin boyu kadar","Yaklaşık 32 fit — frenler devreye girmeden önce neredeyse römorkun boyu kadar yol alınır","Yaklaşık 60 fit — çünkü gecikme mesafesi hız arttıkça iki katına çıkar"],"explanation":"Havalı frenlerde yaklaşık yarım saniyelik bir gecikme vardır, bu nedenle 55 mil/saatte araç frenler tutmadan önce yaklaşık 32 fit fazladan yol alır."},"99":{"q":"Sefer öncesi kontrolümde, sistem tam dolu haldeyken motoru kapattım ve göstergeyi izliyorum. Tüm kapılar kapalı ve fren pedalına basmadığım halde ibre yavaşça aşağı kaymaya devam ediyor ve sabitlenmiyor. Bu kamyonun sürüş için güvenli olup olmadığına karar vermeden önce, yola çıkmamam gerektiğini gösterecek kadar ciddi bir kaçağım olduğunu hangi durum bana söyler?","options":["Hava basarken gösterge tam 125 psi'ye çıktı, dolayısıyla sonrasındaki yavaş düşüş sadece depoların normal soğumasıdır","Kompresör bölgesinden hafif bir tıslama duyuyorum, ancak düşük hava uyarı zili henüz çalmadığı sürece sistem sürüş için sorunsuzdur","Basınç yalnızca regülatör tekrar devreye girene (cut-in) kadar düşüyor; bu da kompresörün talebi karşıladığını kanıtlar","Motor kapalı ve frenler bırakılmış haldeyken hava basıncı sabit kalmıyor ve izin verilen kaçak oranının üzerinde düşmeye devam ediyor"],"explanation":"Motor kapalı ve frenler bırakılmışken basınç sabit kalmalıdır; izin verilen kaçak oranını aşarak düşmeye devam ederse, kaçak güvenle sürmek için fazla büyüktür."},"100":{"q":"Sefer öncesi kontrolümde, motor yüksek rölantide çalışırken bile hava basıncı 70 psi'yi geçemediği için düşük hava basıncı uyarı zili sürekli çalıyor. Bir tamirci, havayı üretip depolara basan parçanın arızalandığını ve değiştirilmesi gerektiğini söylüyor. Bahsettiği parça hangisidir?","options":["Sistemi beslemek için havayı depolama tanklarına basan hava kompresörü","Havanın depolama tanklarına ne zaman basılacağını denetleyen regülatör (governor)","Fren hücrelerine giden hava akışını düzenleyen ayar kolu (slack adjuster)","Tank basıncını korumak için havayı tahliye eden emniyet supabı"],"explanation":"Hava kompresörü, depolama tanklarına hava üretip pompalar; bu nedenle basınç yükselemediğinde arızalı bileşen kompresördür."},"101":{"q":"Sefer öncesi kontrolümde motoru çalışır durumda bırakıp hava göstergesinin yükselmesini izliyorum. Yaklaşık 125 psi'de kompresör sisteme hava basmayı durduruyor, birkaç fren uygulamasından sonra basınç yaklaşık 100 psi'ye düşünce kompresör yeniden basmaya başlıyor. Bu basınçlarda kompresörü başlatıp durdurmaktan hangi parça sorumludur?","options":["Tanklar yaklaşık 150 psi'ye ulaştığında havayı boşaltan emniyet tahliye valfi","Kompresörü yaklaşık 125 psi'de devreden çıkaran ve yaklaşık 100 psi'de yeniden devreye sokan regülatör (governor)","Basınç 60 psi'nin altına düşmeden önce kompresöre sinyal veren düşük hava basıncı uyarı cihazı","Sistemin çalışma basıncını kendi başına belirleyen kompresörün kendi boşaltma pistonları"],"explanation":"Regülatör kompresörü kontrol eder; yaklaşık 125 psi'de devre dışı bırakır ve yaklaşık 100 psi'de tekrar devreye sokar."},"102":{"q":"Sefer öncesi kontrolümde motoru çalıştırıp kompresör hava bastıkça hava basınç göstergesinin yükselişini izliyorum. Regülatörün (governor) kesme (cut-out) noktasına, yani kompresörün depolara hava eklemeyi bıraktığı ana ulaşmasını bekliyorum. Bunun yaklaşık hangi gösterge değerinde gerçekleşmesini beklemeliyim?","options":["Yaklaşık 100 psi, çünkü regülatör sistemi burada kontrol eder","Yaklaşık 150 psi, tam sistem en yüksek güvenli basıncına ulaştığında","Yaklaşık 125 psi, regülatör kompresöre basmayı durdurmasını bildirdiğinde","Yaklaşık 60 psi, tam uyarı cihazı kapanıp basma işlemi sona erdiğinde"],"explanation":"Kompresörün durdurulması, yani regülatörün pompalamayı kestiği nokta, yaklaşık 125 psi'de gerçekleşir."},"103":{"q":"Havalı frenli tek bir araçta sefer öncesi kontrol yapıyorum. Motor kapalıyken sistemdeki basıncı boşaltmak için fren pedalına basıyorum ve basınç göstergesinin düşüşünü izliyorum. Basıncın tehlikeli derecede düştüğünü bana bildirmek için düşük hava basıncı uyarı ışığı ve sesli uyarısı hangi noktada devreye girmelidir?","options":["Gösterge 100 psi'nin altına düşer düşmez, çünkü regülatör havayı yeniden basmak için orada devreye girer","Basınç 20 ila 45 psi aralığına düştüğünde, tam yay frenlerinin devreye girdiği anda","Basınç 125 psi'nin üzerine çıktığı anda, regülatörün kesip pompalamayı durdurduğu yerde","Gösterge 60 psi'nin altına düşmeden önce, güvenli şekilde durmaya yetecek hava varken"],"explanation":"Düşük hava basıncı uyarısı, basınç 60 psi'nin altına düşmeden önce devreye girmeli ve aracı güvenle durduracak kadar hava bırakmalıdır."},"104":{"q":"Sefer öncesi kontrolüm sırasında motoru çalıştırıyorum ve gösterge panelindeki ibrelerden birinin, regülatör kompresörü yaklaşık 125 psi'de devreden çıkarana kadar düzenli olarak yükselişini izliyorum. Bu gösterge ile diğerleri arasında bakışlarımı gezdirirken, bu belirli gösterge bana aslında hangi değeri söylüyor?","options":["Hava depolarında şu anda ne kadar hava basıncı depolandığını","Fren pedalına ne kadar sert bastığımı, yani uygulama basıncını","Düşük hava basıncı uyarı ışığının hangi noktada yanacağını","Havanın 85'ten 100 psi'ye çıkmasının kaç saniye sürdüğünü"],"explanation":"Hava basınç göstergesi, hava depolarında o anda depolanan hava basıncını gösterir."},"105":{"q":"Mevsim kış ve çekici-römork aracımın hava depolarında manuel boşaltma vanaları var. Uzun bir vardiyayı yeni bitirdim ve sistemde su ile kompresör yağının biriktiğini fark ediyorum. Bunun gece boyunca donup parçalara zarar verebileceğini bildiğime göre, nemi boşaltmak için bu manuel boşaltma vanalarını ne zaman açmalıyım?","options":["Yalnızca haftada bir kez, çünkü hava kurutucusu boşaltmalar arasında nemin çoğunu zaten gideriyor","Her günün sonunda, aracı park etmeden önce depoları tamamen boşaltarak","Yalnızca düşük hava basıncı uyarı ışığı 60 psi'nin altında yandığında","Yaklaşık ayda bir kez veya depoların gözle görülür şekilde hava sızdırdığını fark ettiğim her seferde"],"explanation":"Manuel valfli hava depolarını her günün sonunda tamamen boşaltarak çalışma sırasında biriken su ve yağı giderin."},"106":{"q":"Sefer öncesi araç kontrolü sırasında sınav görevlisi, tek bir hava frenli düzenekte birleştirilen üç ayrı fren sistemini saymamı istiyor. Servis frenlerini ve park frenlerini doğru şekilde söylüyorum. Cevabı tamamlamak için üçüncü sistem olarak hangisini söylemeliyim?","options":["Fren pedalını kullanmadan kamyonu yavaşlatan yavaşlatıcı (retarder) sistemi","Havayı birincil ve ikincil besleme olarak ikiye ayıran çift devreli sistem","Ana hava beslemesi arızalanırsa kamyonu durduran acil durum fren sistemi","Yaylı frenleri kademeli olarak devreye sokmamı sağlayan modülasyon sistemi"],"explanation":"Hava fren sistemi üç sistemi birleştirir: servis frenleri, park frenleri ve hava beslemesi kesilirse aracı durduran acil frenler."},"107":{"q":"Yüklü tek bir kamyonu sürerken bir hortum patlıyor ve hava basıncım sürekli düşüyor. Düşük hava basıncı uyarı ışığı ve sesli uyarı bir süredir çalışıyor ve şimdi yaylı (park/acil durum) frenler kendiliğinden devreye girdikçe kamyonun kendi kendine sert şekilde yavaşladığını hissediyorum. Kesin bir değer HARİÇ, o yaylı frenler otomatik olarak devreye girdiği anda hava yaklaşık hangi basınç aralığına düşmüştü?","options":["Yaklaşık 100 psi — regülatörün normalde devreye girdiği (cut-in) nokta","Yaklaşık 60 psi — düşük hava basıncı uyarısının ilk tetiklendiği aynı nokta","Yaklaşık 125 psi — regülatörün devreden çıkıp (cut-out) pompalamayı durdurduğu nokta","Yaklaşık 20 ila 45 psi — yaylı frenlerin otomatik olarak devreye girdiği aralık"],"explanation":"Yaylı frenler hava basıncıyla açık tutulur ve basınç 20 ila 45 psi aralığına düştüğünde otomatik olarak devreye girer."},"108":{"q":"Yüklü çekicimi uzun ve dik bir yokuştan, hava frenlerini sonuna kadar kullanarak yeni indirdim. Aşağıda bir dinlenme alanına girince tekerleklerin yoğun ısı yaydığını hissediyorum. Aşağıdakilerden biri HARİÇ, diğerleri kabinden ayrılmadan önce yapılması doğru hareketlerdir. Şu anda hangi eylemden KAÇINMALIYIM?","options":["Fren kampanaları inişten dolayı hâlâ çok sıcakken park (yay) frenini çekmek","Tekerlekleri takozlamak ve tutması için yay frenlerine güvenmeden önce frenlerin soğumasını beklemek","Sistemin tutmasına güvenmeden önce hava basıncının regülatör kesme noktasına kadar yeniden yükselmesini beklemek","İtme çubuğu hareketini daha sonra kontrol etmek, çünkü ayarı bozuk frenler en yaygın hava freni arızasıdır"],"explanation":"Fren kampanaları çok sıcakken, örneğin dik bir inişin hemen ardından, park (yaylı) frenlerini asla çekmeyin çünkü onlara zarar verebilir."},"109":{"q":"Yüklü bir katar (çekici-römork) ile uzun ve dik bir inişten aşağı iniyorum. Hızımı kontrol altında tutmak için fren pedalına tekrar tekrar basıp bırakıyorum (\"fanlama\"). Bunu inişin sonuna kadar yaparsam, aşağıdakilerden hangisi EN olası sonuçtur?","options":["Frenlerim daha serin kalır çünkü her uygulama arasında bırakılıp nefes alma fırsatı bulurlar","Hava basıncım düşer çünkü her bırakışta hava, kompresörün yerine koyabileceğinden daha hızlı kaçar ve sonunda havam tükenir","Kompresör her bırakışta daha hızlı pompalar, böylece ne kadar uzun fanlarsam depolarım aslında o kadar çok hava biriktirir","Tüm iniş boyunca 60 psi düşük hava uyarı seviyesinin üzerinde kaldığım sürece hiçbir şey değişmez"],"explanation":"Uzun bir inişte frenlere basıp bırakmayın çünkü her bırakış, kompresörün yerine koyabileceğinden daha hızlı hava kaçırır ve sonunda havanızı tüketir."},"110":{"q":"Havalı (hava) frenli bir çekici-römork sürüyorum ve fren pedalına sertçe basıyorum, ancak ayağım pedalı hareket ettirdiği anda aracın yavaşlamaya başlamadığını fark ediyorum — frenleme gerçekten başlamadan önce yaklaşık yarım saniyelik kısa bir gecikme oluyor. Havanın fren hatları boyunca fren hücrelerine ulaşması gerektiğinden kaynaklanan bu gecikmeye ne ad verilir:","options":["Fren sönmesi (brake fade) — uzun bir inişte aşırı ısınan kampanaların fren gücünü kaybetmesi","Fren çekmesi (brake pull) — fren yapınca aracın bir tarafa yönelme eğilimi","Fren gecikmesi (brake lag) — havanın hatlar boyunca ilerleyip frenlerin devreye girmesi için gereken süre","Fren dengesizliği — çekici ile römork aksları arasındaki eşit olmayan fren kuvveti"],"explanation":"Fren gecikmesi, frenlerin tutmasından önce havanın fren hatlarından geçmesi için gereken yaklaşık yarım saniyelik gecikmedir."},"111":{"q":"Havalı frenli çekicimi, arkadaşımın hidrolik frenli arabasıyla karşılaştırıyorum. Hız, yol ve tepki süresinin aynı olduğunu varsayarsak, havalı frenlerin yaklaşık yarım saniyelik fren gecikmesi, hidrolik frenli araca kıyasla TOPLAM durma mesafemi nasıl etkiler?","options":["Hiçbir etkisi yoktur, çünkü toplam durma mesafesi yalnızca algılama ve tepki mesafesiyle belirlenir.","Hava fren odacıklarına ulaştığında toplam durma mesafesini yaklaşık yarıya indirir.","Toplam durma mesafesini biraz kısaltır, çünkü hava basıncı fren kuvvetini daha hızlı oluşturur.","Toplam durma mesafesini biraz uzatır, çünkü toplama fren gecikmesi mesafesi eklenir."],"explanation":"Yaklaşık yarım saniyelik fren gecikmesi, toplam durma mesafesine bir fren gecikme mesafesi ekler; 55 mil/saatte bu yaklaşık 32 fittir."},"112":{"q":"Sefer öncesi kontrolde havayı doldurmaya devam ediyorum ve göstergenin regülatör (governor) kesme noktasını geçtiğini görüyorum. Bir arıza yüzünden kompresör hiç durmuyor ve basınç yükselmeye devam ediyor. Sistemi aşırı basınçtan korumak için besleme (ıslak) deposundaki emniyet tahliye valfi yaklaşık hangi basınçta açmalıdır?","options":["Yaklaşık 150 psi","Yaklaşık 125 psi","Yaklaşık 100 psi","Yaklaşık 60 psi"],"explanation":"Besleme deposundaki emniyet supabı, regülatör arızalanırsa fazla basıncı tahliye etmek için yaklaşık 150 psi'de açılır."},"113":{"q":"Sefer öncesi hava freni muayenemde, hava kaçak oranını izlerken sınav görevlisi bana \"ayak valfine (foot valve) sıkıca bas ve basılı tut\" diyor. Kabindeki kumandalara ve pedallara bakıyorum. Görevli hangisine basmamı söylüyor?","options":["Gösterge panelindeki sarı, elmas şeklindeki düğmeye, çünkü fren hava beslemesini kontrol eden odur","Kabin tabanındaki fren pedalına, çünkü hava frenli sistemde buna ayak valfi veya tek pedallı valf (foot/treadle valve) da denir","Gaz pedalına, çünkü kaçak testi başlamadan önce hava basıncının yükseltilmesi gerekir","Debriyaj pedalına, çünkü ona basmak yaylı frenleri serbest bırakıp basınç uygulayan şeydir"],"explanation":"Kabin tabanındaki fren pedalı, ayak valfi veya pedal valfi olarak da adlandırılan servis fren kumandasıdır."},"114":{"q":"Çift (ikili) havalı fren sistemine sahip bir çekici-römork kullanırken, birden bire düşük hava basıncı uyarı ışığı ve sesli uyarı devreye giriyor ve birincil hava sisteminin basıncını kaybettiğini bildiriyor. Bu anda frenlerimden ne beklemem gerektiği konusunda aşağıdakilerden hangisi DOĞRUDUR?","options":["Birincil ve ikincil sistemler birlikte tamamen devre dışı kalır, bu yüzden hiç fren gücüm kalmaz","Yaylı (park) frenler anında tüm tekerlekleri kilitler ve kontrolü korumak için sert direksiyon kırmalıyım","İkincil sistem hâlâ basınç doludur ve fren sağlamaya devam eder, böylece güvenli bir şekilde durana kadar fren yapabilirim","İkincil sistem tüm hava basıncını tekerleklere boşalttığı için durma gücüm iki katına çıkar"],"explanation":"Çift hava frenli sistemde birincil devre arızalandığında ayrı ikincil devre basınçlı kalır ve aracı güvenli şekilde durduracak fren gücünü sağlamaya devam eder."},"115":{"q":"Sefer öncesi kontrolümde hava sistemi tamamen dolu ve motor kapalı. Sürüşe başlamadan önce düşük hava basıncı uyarı cihazının düzgün çalıştığını doğrulamak istiyorum. Hangi işlem onu doğru şekilde test eder?","options":["Motoru çalıştırıp regülatör emniyet supabı açılana kadar hava pompalasın, sonra zile kulak verin","Fren pedalına bir dakika boyunca sıkıca basıp tutun ve göstergede ani bir basınç sıçraması olup olmadığını izleyin","Sarı park freni düğmesini çekip, uyarı çalmadan önce yaylı frenlerin devreye girdiğini doğrulayın","Motor kapalıyken fren pedalına basıp bırakarak havayı boşaltın ve uyarının 60 psi'ye gelmeden çalıştığını izleyin"],"explanation":"Motor kapalıyken fren pedalına basıp bırakarak depolardan havayı boşaltın ve düşük basınç uyarısının basınç 60 psi'nin altına düşmeden devreye girdiğini doğrulayın."},"116":{"q":"Standart bir hava fren sistemine sahip tek bir düz kamyon kullanırken hava kompresörüm arızalanmaya başlıyor ve basınç düşmeye devam ediyor. Düşük hava uyarı ışığım ve sesli uyarıcım bir süredir yanıyor ve yolun kenarına çekmek için yavaşlıyorum. PARK ETMİŞ olmam durumu HARİÇ, yay (park) frenlerinin kendiliğinden devreye girip kamyonu durdurmasını yaklaşık hangi basınçta beklemeliyim?","options":["20 ile 45 psi aralığında bir yerde","60 psi'nin hemen altında, uyarı ışığının yandığı noktada","Regülatörün normalde devreye girdiği yaklaşık 100 psi'de","Regülatörün normalde devreden çıktığı yaklaşık 125 psi'de"],"explanation":"Yaylı (park/acil) frenler hava basıncıyla açık tutulur ve basınç 20 ile 45 psi aralığına düştüğünde otomatik olarak devreye girer."},"117":{"q":"Sefer öncesi kontrolümde, tek araçlı kamyonumda hava kaçak oranı testini yapmak üzereyim. Motoru çalıştırdım ve hava göstergesi şu anda yaklaşık 90 psi gösteriyor ve hâlâ yükseliyor. Basınç düşüşünü ölçmeye başlamadan önce, testin geçerli olması için İLK ÖNCE ne yapmalıyım?","options":["Hatlardaki havayı devreye girme (cut-in) basıncına kadar boşaltmak için fren pedalına birkaç kez basıp sonra süreyi tutmaya başlamak","Regülatör yaklaşık 125 psi'de devreden çıkana (cut-out) kadar sistemin dolmasını beklemek, sonra motoru kapatmak","Boş ve temiz bir sistemden kaybı ölçmek için tüm hava depolarını tamamen boşaltmak","El frenini çekip emniyet supabı yaklaşık 150 psi'de açılana kadar motoru yüksek devirde çalıştırmak"],"explanation":"Hava kaçağı testi, kompresörün kaçağı gizlememesi için sistem regülatör kesme noktası olan yaklaşık 125 psi'ye kadar tam dolu ve motor kapalıyken yapılmalıdır."},"118":{"q":"Tek (düz) bir kamyonda yola çıkış öncesi kontrolde motoru kapatıyorum, tekerleklere takoz koyuyorum ve hava sistemini regülatör kesme basıncına kadar dolduruyorum. Park frenini bırakılmış halde tutup bir dakika boyunca gösterge panelindeki manometreyi izleyerek kaçak kontrolü yapıyorum. Hangi okuma, kaçağın hâlâ yasal sınır içinde olduğunu ve devam edebileceğimi gösterir?","options":["O dakikada 3 psi'ye kadar düşüş kabul edilebilir, çünkü bu tek araç için frenler bırakılmışken geçerli sınırdır","Herhangi bir düşüş başarısızlıktır; motor kapalı ve frenler bırakılmışken gösterge tam olarak sabit kalmalıdır","O dakikada en fazla 2 psi düşüş, frenleri bırakılmış bu tek araç kontrolü için sınırlar içindedir","Dakikada 4 psi'ye kadar düşüş sorun değildir, çünkü frenler basılı değil bırakılmış durumdadır"],"explanation":"Frenleri bırakılmış tek bir araç için dakikada en fazla 2 psi hava kaybı izin verilen sınır içindedir."},"119":{"q":"Tek (düz, römorkösuz) bir kutu kamyonun yola çıkış öncesi muayenesinde sistemi yaklaşık 125 psi'ye kadar tam doldurdum, motoru kapattım ve fren pedalına basıp basılı tuttum. Şimdi kaçak oranını kontrol etmek için tam bir dakika boyunca hava göstergesini izliyorum. Bu testi geçmek için gözlemlediğim basınç düşüşü en fazla şu kadar olmalı:","options":["O dakikada 2 psi, çünkü pedalı basılı tutmak, frenler bırakılmış hâldeki kontrolle aynı standarttır","O dakikada 4 psi, çünkü tek bir düz kamyonun kaybetmesine izin verilen sınır budur","O dakikada 10 psi, yeter ki test sırasında düşük hava uyarısı hiç devreye girmesin","O dakikada 3 psi, frenler uygulanmış hâldeyken tek bir araç için izin verilen azami kayıp"],"explanation":"Frenler basılıyken tek bir araç dakikada en fazla 3 psi kaybedebilir ve yine de sınır içinde kalır."},"120":{"q":"Sefer öncesi kontrolde fren ayar kolunu (slack adjuster) çektiğimde bir inçten fazla boşluk olduğunu fark ediyorum; bu, frenlerin ayarsız olduğunu gösteriyor. Bunu düzeltmeden sürersem beklemem gereken EN doğrudan güvenlik sonucu nedir?","options":["Aşırı itme çubuğu hareketi fren gücünü azalttığı için frenler kötü çalışır","Düşük hava basıncı uyarı zili, basınç 60 psi'nin altına düşmeden önce çalar","Hava kompresörü regülatörü yaklaşık 125 psi'de havayı kesmez","Yaylı frenler, basınç 20-45 psi aralığına düştüğünde otomatik olarak devreye girer"],"explanation":"Çok gevşek ayar kolları aşırı itme çubuğu hareketine neden olur; bu da tekerleklere ulaşan fren gücünü azaltır ve frenlerin kötü çalışmasına yol açar."},"121":{"q":"Sefer öncesi kontrolde römorkun altına giriyorum ve yardımcıma fren pedalına sertçe basmasını söylerken bir fren körüğünün itme çubuğunu izliyorum. Ayar kolunun (slack adjuster) hâlâ ölçüde olup olmadığını bilmek istiyorum. Frenlerin ayarı bozuk sayılıp servise gönderilmesi gerekmeden önce bu itme çubuğu yaklaşık ne kadar hareket edebilir?","options":["Ölçü dışına çıkmadan önce yaklaşık yarım ayak hareket","Ölçü dışına çıkmadan önce yaklaşık 1 inç hareket","Ölçü dışına çıkmadan önce yaklaşık 6 inç hareket","Ölçü dışına çıkmadan önce kabaca 2 ayak hareket"],"explanation":"Frenlere sertçe basıldığında itme çubuğu hareketi yaklaşık 1 inç'i geçmemelidir; bu sınır içinde ayar kolu spesifikasyona uygundur."},"122":{"q":"Sefer öncesi muayenede, fren kampanalarımdan birinde ince bir çatlak buluyorum ve o tekerlekteki fren balatasının neredeyse perçinlere kadar aşındığını fark ediyorum. Hava basıncım tam ve pedala bastığımda frenler düzgün çalışıyor gibi. Bu durum aracım için ne anlama gelir?","options":["Basınç regülatör kesme noktasına ulaşıyorsa ve düşük hava uyarısı çalışıyorsa araç sürülebilir","Frenler 5 mil/saat durma testinde hâlâ sağlam tuttuğu için şimdilik kabul edilebilir","Araç servis dışıdır ve çatlak kampana ile aşınmış balata onarılana kadar sürülmemelidir","Kuru koşullarda güvenlidir, yalnızca yağmurda veya ıslak yollarda sürmekten kaçınılmalıdır"],"explanation":"Çatlak bir kampana veya perçinlere kadar aşınmış balatalar otomatik olarak hizmet dışı bırakma koşuludur ve bu parçalar onarılana kadar araç kullanılmamalıdır."},"124":{"q":"Yağmurdan kayganlaşmış bir otoyolda yüklü bir römork çekiyorum ve önümdeki trafik aniden duruyor. Fren pedalına sonuna kadar basıyorum ve aracım ABS ile donatılmış. ABS'nin gerçekte ne yapmak için tasarlandığını göz önüne alındığında, bu sert frenlemede ondan beklemem gereken gerçekçi fayda nedir?","options":["Toplam durma mesafemi, ABS'siz aynı aracın ihtiyaç duyacağından çok daha kısaltır","Frenleri benim yerime pompalar, böylece bu kaygan zeminde asla kademeli (stab) frenleme yapmama gerek kalmaz","Otomatik olarak vites küçültür ve hava basıncımı korur, böylece yaylı frenler asla devreye girmez","Tekerleklerimin kilitlenmesini önler, böylece duran trafiğin etrafından hâlâ direksiyonla yön verebilirim"],"explanation":"ABS durma mesafesini kısaltmaz; sert frenlemede tekerlek kilitlenmesini önleyerek direksiyon kontrolünü korumanızı ve tehlikenin etrafından dolaşmanızı sağlar."},"125":{"q":"Sefer öncesi kontrol sırasında, basınçlı havanın depolardan bir tekerleğe doğru izlediği yolu takip ediyorum. Depolanan hava basıncının sonunda fren bağlantısını fiziksel olarak hareket ettiren mekanik itme kuvvetine dönüştürüldüğü tek parçayı bulmak istiyorum. Hangi parçayı arıyorum?","options":["Fren körüğü (brake chamber), çünkü hava basıncını frenleri çalıştıran mekanik kuvvete dönüştürür","Boşluk ayarlayıcı (slack adjuster), çünkü balataları kampanaya bastırmak için dışarı doğru iten parça odur","Hava kompresörü, çünkü frenleri sonunda çalıştıran basıncın kaynağıdır","Regülatör (governor), çünkü tekerleğe iletilen hava basıncını kontrol eder"],"explanation":"Fren körüğü, sıkıştırılmış hava basıncını iticiyi dışarı iterek frenleri uygulayan mekanik kuvvete dönüştürür."},"126":{"q":"Sefer öncesi kontrolümde, ayar bozukluğu en yaygın hava freni arızası olduğu için itme çubuğu hareketini kontrol etmek üzere römorkun altına giriyorum. İtme çubuğunu fren körüğünden takip ediyorum ve onun fren ayarlayıcısının (slack adjuster) bir ucuna cıvatalandığını görüyorum. Fren kuvvetimin tekerlek frenini gerçekte nasıl devreye soktuğunu anlamak için, bu fren ayarlayıcısının DİĞER ucunun neyi döndürdüğünü bilmem gerekiyor. Fren ayarlayıcısı itme çubuğunu hangi parçaya bağlar?","options":["Fren pedalına, böylece pedala basmak itme çubuğunu geri çeker","S-kamına, onu döndürerek fren pabuçlarını kampanaya doğru açar","Hava kurutucusuna, onu açarak körükten nemi dışarı atar","Regülatöre, ona 125 psi'de kompresörü durdurma sinyali verir"],"explanation":"Fren ayarlayıcı, fren pabuçlarını davula doğru ayırarak tekerleği durduran S-kamını döndürür."},"127":{"q":"Sefer öncesi kontrolümde, çekici-römork aracımın her tekerleğindeki frenleri incelerken, dönerek fren pabuçlarını dışa, dönen bir kampanaya doğru iten S şeklinde bir kam fark ediyorum. Sınav görevlisi, bu tasarımı her şeyden önce neden bilmem gerektiğini soruyor. Hangi cevap doğru?","options":["FMCSA'nın havalı frenli araçlarda hâlâ izin verdiği tek temel fren tasarımı budur","Bu bir kama tipi temel frendir ve günümüzde ağır birleşik araçların çoğu bununla üretilmektedir","Bu, S-kamlı kampanalı frendir; havalı frenli ticari araçlarda en sık karşılaşılan temel fren tasarımıdır","Bu, havalı disk temel frendir; bugün yollardaki kamyonların büyük çoğunluğunda kullanılan tiptir"],"explanation":"Pabuçları davula doğru bastırmak için dönen S şeklindeki kam, hava frenli araçlarda en yaygın temel fren olan S-kamlı kampanalı freni tanımlar."},"128":{"q":"Sefer öncesi kontrol sırasında eğitmenim, fren pedalına bastığımda hava basıncının bir kamı iterek fren pabuçlarını dışarı doğru, tekerleğe bağlı dönen bir parçaya doğru bastırdığını ve aralarındaki sürtünmenin aracı yavaşlattığını söylüyor. Fren pabuçları bu durdurma sürtünmesini oluşturmak için hangi parçaya bastırır?","options":["Pabuçların fren kuvvetini aktarmak için sıktığı ayar koluna (slack adjuster)","Pabuçların tekerleği tutmak için kavradığı fren körüğüne (haznesine)","Pabuçların basınç boşaltmak için bastırdığı hava deposuna","Pabuçların sürtünme oluşturmak için bastırdığı fren kampanasına (tamburuna)"],"explanation":"Fren pabuçları dönen fren davuluna doğru dışarı bastırır ve aralarındaki sürtünme aracı yavaşlatıp durdurur."},"129":{"q":"Tek bir çekicide sefer öncesi kontrolümde hava sistemini doldurmayı bitiriyorum ve aracın etrafında dolaşırken kaymaması için onu sabitlemek istiyorum. Gösterge panelinde hangi kumandayı, nasıl kullanmalıyım?","options":["Park (yaylı) frenleri devreye sokmak için sarı, baklava (eşkenar dörtgen) biçimli düğmeyi dışarı çek","Park (yaylı) frenleri devreye sokmak için kırmızı, sekizgen biçimli düğmeyi dışarı çek","Park (yaylı) frenleri devreye sokmak için sarı, baklava biçimli düğmeyi içeri bas","Yaylı frenleri mekanik olarak kilitleyen fren pedalına basıp basılı tut"],"explanation":"Park (yay) freni, uygulamak için dışarı çekilen ve bırakmak için içeri itilen sarı, eşkenar dörtgen şeklindeki düğmedir."},"130":{"q":"Sabahın ilk saatinde çekiciye biniyorum, motoru çalıştırıyorum ve yola çıkmaya hazırım. Sarı, elmas şeklindeki park freni düğmesi hâlâ dışarı çekili. Park frenlerini boşaltmak için o düğmeyi içeri bastırmadan önce hangi şartın sağlandığından emin olmalıyım?","options":["Motor normal çalışma sıcaklığına ulaştı ve soğutma suyu göstergesi soğuk bölgeden çıktı","Hava basıncı sistem tam dolacak kadar yükseldi ve düşük hava basıncı uyarısı söndü","Yakıt basıncı dengelendi ve dizel, enjeksiyon hatları boyunca tamamen beslendi","Motor yağı basıncı normal aralığa yükseldi, böylece yataklar gereği gibi yağlandı"],"explanation":"Yay frenleri hava basıncıyla bırakıldığından, park freni bırakılmadan önce sistem tamamen dolu ve düşük hava uyarısı kapalı olmalıdır."},"133":{"q":"Sefer öncesi hava freni kontrolü yapıyorum ve regülatörü test etmek için göstergeyi izliyorum. Havayı boşaltmak için frene birkaç kez basıyorum ve kompresör tekrar devreye girip havayı yeniden basmaya başlıyor. Regülatörün DEVREYE GİRMESİ (cut-in) ve kompresörün yeniden hava basmaya başlaması için göstergede yaklaşık hangi değeri beklemeliyim?","options":["Yaklaşık 60 psi, tam düşük hava basıncı uyarısının yanacağı noktada","Yaklaşık 125 psi, daha önce basmayı durdurduğu aynı noktada","Yaklaşık 100 psi, devreden çıktığı noktadan biraz daha düşük bir değerde","Yaklaşık 20 psi, tam yaylı frenlerin devreye girmeye başladığı noktada"],"explanation":"Regülatör, yaklaşık 125 psi olan kesme basıncının biraz altında, yaklaşık 100 psi'de pompalamayı yeniden başlatmak için devreye girer."},"134":{"q":"Çift hava frenli bir çekici-dorse üzerinde sefer öncesi kontrolümü yaparken, motoru hızlı rölantiye getirip gösterge panelindeki manometrenin yükselişini izliyorum. Hava basıncı yükselme hızının standartlara uygun olduğunu doğrulamak istiyorum. İbrenin 85 psi'yi geçtiğini gördüğümde, yükselmenin kabul edilebilir sayılması için hangi süre içinde 100 psi'ye ulaşmış olması gerekir?","options":["85 psi'yi geçtikten yaklaşık 3 saniye içinde","85 psi'yi geçtikten yaklaşık 30 saniye içinde","85 psi'yi geçtikten yaklaşık 60 saniye içinde","85 psi'yi geçtikten yaklaşık 45 saniye içinde"],"explanation":"Çift hava frenli sistemde basınç, yaklaşık 45 saniye içinde 85 psi'den 100 psi'ye yükselmelidir, aksi halde sistemde bir sorun vardır."},"135":{"q":"Sefer öncesi kontrolümde hava kompresörü besleme (ıslak) deposunu doldurdu, ancak servis deposunun ardındaki bir hatta yavaş bir kaçak oluştuğunu fark ediyorum. Depolar arasına tek yönlü bir çek valf takılı. Bu kaçak havayı boşaltırken, çek valfin benim için yaptığı asıl iş nedir?","options":["Üst depoda zaten depolanmış havanın, kaçak yapan bölümden geriye doğru boşalmasını engeller","Hava basıncının kaçak noktasının ötesine asla çıkmasını engelleyerek sistemin aşırı basınçlanmasını önler","Kaçan havanın fren hücrelerine asla ulaşmamasını sağlar, böylece frenler yine de devreye girer","Kaçak sırasında hapsolmuş havanın hatların içinde soğuyup donmasını engeller"],"explanation":"Tek yönlü çek valf, havanın yalnızca tek yönde akmasına izin verir ve aşağı akıştaki kaçağı kapatarak yukarı akıştaki depoda saklanan havanın geri akmasını önler."},"136":{"q":"Sefer öncesi kontrolde hava depolarımın boşaltma vanalarını açıyorum ve özellikle bir deponun diğerlerine göre sürekli çok daha fazla su ve yağ tortusuyla dolu olduğunu fark ediyorum. Sistemin kompresörden havayı nasıl yönlendirdiğini bildiğime göre, bu EN OLASI hangi depodur?","options":["Kuru depo, çünkü akışın aşağısında yer alır ve nem soğuduktan sonra nihayet orada yoğuşur","Islak (besleme) deposu, çünkü havayı doğrudan kompresörden alır ve suyun çoğu ilk olarak orada birikir","Yakıt deposu, çünkü hava hatlarındaki yoğuşma gece boyunca geri ona akar","En alta monte edilmiş olan depo, çünkü yer çekimi biriken tüm suyu ona doğru çeker"],"explanation":"Islak (besleme) deposu, kompresörden doğrudan sıcak ve nemli havayı aldığından, suyun ve yağın çoğu önce orada yoğunlaşıp birikir."},"137":{"q":"Sefer öncesi kontrolümde düz zemine park ediyorum, tekerlek takozlarını koyuyorum, sarı eşkenar dörtgen düğmeyi çekerek park frenini uyguluyorum, sonra takozları çıkarıp düşük viteste frene karşı yavaşça ileri hareket ediyorum. Park freni doğru çalışıyorsa ne olmalı?","options":["Araç yavaşça ileri sürünmeli, yaylı frenlerin kısmi basıncı tuttuğunu kanıtlamalı","Düşük hava uyarı zili çalmalı, basınç zamanında düştüğü için yaylı frenlerin devreye girdiğini doğrulamalı","Araç yerinde kalmalı ve hareket etmemeli, park freninin aracı yerinde tuttuğunu göstermeli","Araç ancak servis fren pedalına da sıkıca basıp basılı tuttuğumda yerinde durmalı"],"explanation":"Düzgün çalışan yaylı park freni tam güçle kavrar ve düşük viteste hafifçe çekince aracı yerinde sabit tutmalıdır."},"138":{"q":"Sefer öncesi kontrolüm sırasında el frenini bırakıyorum, otobüsün düz bir alanda yaklaşık 5 mil/saat hıza kadar yavaşça ileri kaymasına izin veriyorum ve yola çıkmadan önce servis frenlerimin doğru çalıştığından emin olmak istiyorum. Bu noktada ne yapmalıyım?","options":["Fren pedalına hızlıca birkaç kez basıp her seferinde havanın boşalma sesini dinlemeliyim","Pedalı hafifçe basılı tutup yavaşça durana kadar kaymalı, hava göstergesinin 60 psi üzerinde kaldığını izlemeliyim","Önce yaklaşık 20 mil/saate hızlanmalıyım ki frenlerden daha gerçekçi, otoyola benzer bir tepki alayım","Fren pedalına sağlamca basmalı ve aracın bir tarafa çekmeden düz bir şekilde durduğunu ve pedalın sert hissettirdiğini kontrol etmeliyim"],"explanation":"Düzgün çalışan servis fren sistemi aracı bir tarafa çekmeden düz bir şekilde durdurur ve pedal süngerimsi değil sert hissedilir."},"139":{"q":"Sefer öncesi hava freni kontrolümde, yaklaşık 5 mil/saat hızla ileri yuvarlanıp fren pedalına basıyorum. Kamyon düz bir şekilde duruyor, ancak pedal sıkı yerine ayağımın altında alçalıyor ve yumuşak, süngerimsi hissettiriyor. Bu pedal hissinden ne sonuç çıkarmalıyım?","options":["Büyük olasılıkla sürüşten önce kontrol edilmesi gereken bir fren sistemi sorununa işaret eder","Normaldir çünkü hava frenleri her zaman hidrolik frenlerden daha yumuşak hissettirir","Sadece hava basıncının 125 psi regülatör kesme noktasının üzerinde olduğu anlamına gelir","Ayar kollarının fazla boşluğu otomatik olarak aldığını gösterir"],"explanation":"Yumuşak veya süngerimsi şekilde dibe inen pedal, hatlarda hava, düşük basınç veya kaçak gibi sürüş öncesi giderilmesi gereken bir fren sorununa işaret eder."},"140":{"q":"Sefer öncesi kontrolümü bitirip motoru çalıştırıyorum. Gösterge panelindeki ABS arıza lambası önce yanıyor ama hiç sönmüyor — rölantide ve tam basıncı oluşturduktan sonra da yanık kalıyor. Buna dayanarak kilitlenme önleyici fren sistemim hakkında ne sonuca varmalıyım?","options":["Lamba sadece ABS oto-testinin yapıldığını ve sistemin tam çalıştığını doğruluyor","ABS düzgün çalışmıyor olabilir ve sürmeden önce kontrol ettirilmelidir","Lamba yalnızca düşük hava basıncını gösterir, bu yüzden regülatörün daha fazla hava basmasını beklemem yeterli","Lamba yaylı frenlerin uygulandığı anlamına gelir, park düğmesini bırakınca sönecektir"],"explanation":"ABS arıza lambası çalıştırmada kısa süre yanıp sönmeli; sönmeyip yanık kalırsa ABS arızalı olabilir ve sürüşten önce kontrol edilmelidir."},"141":{"q":"Yüklü bir çekici-römork kullanırken gösterge panelimde ABS (kilitlenmeyi önleyici fren) arıza lambası yanıyor. Frenler hâlâ normal hissettiriyor ama az önce ne olduğu konusunda endişeliyim. Aşağıdakilerden hangisi şu anki fren durumumu EN doğru şekilde tanımlar?","options":["Tüm fren yeteneğimi kaybettim ve yalnızca motor ile vitesleri kullanarak yavaşlayıp durmalıyım","Durma mesafem artık otomatik olarak kısaldı, bu yüzden eskisine göre daha geç fren yapabilirim","Hâlâ normal servis frenlerime sahibim ve aracı durdurabilirim, ancak tekerlekleri kilitlememek için dikkatli fren yapmalıyım","Yalnızca el frenlerim çalışacak, bu yüzden durmak için sarı düğmeyi çekmeliyim"],"explanation":"ABS arızası yalnızca kilitlenme önleme özelliğini devre dışı bırakır; normal servis frenleriniz tam çalışır ama tekerlekleri kilitlememek için dikkatli fren yapmalısınız."},"142":{"q":"Sefer öncesi kontrolüm sırasında, fren haznelerinden birinde aşırı itme çubuğu hareketi (pushrod travel) fark ediyorum. Çekicimde otomatik fren ayarlayıcıları (slack adjuster) var ve bir iş arkadaşım bunların 'bakım gerektirmediğini' söyleyerek artık onlarla ilgilenmeme gerek olmadığını belirtiyor. Otomatik fren ayarlayıcılarına doğru yaklaşımı hangi ifade yansıtır?","options":["Kendi kendine ayarlandıkları için, sefer öncesi kontrolde herhangi bir muayeneye gerek bırakmazlar","Aşırı boşluk kaybolana kadar sürüş sırasında onları elle gevşetmeliyim","Ayarsız frenleri ortadan kaldırırlar, bu yüzden iş arkadaşım haklı ve onlar göz ardı edilebilir","Yine de düzenli olarak kontrol edilmelidirler, çünkü ayarsız frenler bunlar olsa bile yaygın bir kusurdur"],"explanation":"Ayarı bozuk frenler en yaygın hava freni arızasıdır; bu yüzden otomatik balata ayarlayıcılar bile kusursuz olmadığından düzenli kontrol edilmelidir."},"143":{"q":"Sefer öncesi kontrolümde, fren ayar kolunda (slack adjuster) aşırı itme çubuğu hareketi fark ediyorum; bu da frenlerin ayarının bozuk olduğunu gösteriyor. Geç kaldım ve garaj aletleri hemen orada duruyor. Bu araç yola çıkmadan önce fren ayarını gerçekte kim yapmalı?","options":["Yalnızca fren ayarı konusunda eğitimli ve yetkili olan bir kişi","Geçerli CDL sahibi herkes, çünkü ehliyet sahibi olmak fren yetkinliğini kanıtlar","Şu anda ben, çünkü itme çubuğu hareketini garaj aletleriyle ayarlamak basittir","Aracın daha fazla gecikmemesi için en yakında ve müsait olan kişi"],"explanation":"Ayarı bozuk frenler fren gücünü doğrudan azalttığından, fren ayarı yalnızca bu işi yapmak için eğitimli ve yetkili bir kişi tarafından yapılmalıdır."},"144":{"q":"Çekici-römork sürerken düşük hava basıncı uyarı ışığı yanıyor ve hava kompresörümün tamamen hava basmayı bıraktığını hemen anlıyorum. Yaklaşık bir mil ileride güvenli banketi olan bir çıkış var. Sistemim tam dolu olduğuna göre, depolardaki yedek hava bana ne yapma imkânı verir?","options":["Bir günlük seferler boyunca normal şekilde sürmeye devam etmek, çünkü depolar bir günlük hava stoğu tutar","Basınç tehlikeli derecede düşmeden önce yavaşlamak ve güvenle banket dışına çekmek için birkaç fren uygulaması daha yapmak","Süresiz olarak sürmek, çünkü yaylı frenler benim yerime servis depolarını yeniden dolduracaktır","Neredeyse hiç kullanılabilir fren almamak, bu yüzden tam bulunduğum yerde derhal yoldan çıkmak zorunda kalmak"],"explanation":"Hava tankları sıkıştırılmış hava rezervi tutar; böylece kompresör dursa bile güvenle kenara çekmek için birkaç kez daha fren uygulayabilirsiniz."},"145":{"q":"Dondurucu bir kış sabahı ve sefer öncesi kontrol listem, su ve kompresör yağının birikip sistemi dondurmaması için hava depolarını her gün boşaltmam gerektiğini hatırlatıyor. Çekicinin altında durmuş, açmam gereken doğru parçaları arıyorum. Hava depolarında biriken suyu boşaltmak için gerçekte hangi düzeneği kullanırım?","options":["Besleme (ıslak) deposundaki nemi dışarı atmak için elimle araladığım emniyet tahliye valfini","Depolardaki suyu boşaltmak için dışarı çektiğim, kabindeki sarı elmas biçimli düğmeyi","Her hava deposunun altında bulunan, petkok da denilen tahliye (drenaj) valflerini","Sıkışan suyu geri itmesi için sıfırladığım hava kompresörü regülatörünü (governor)"],"explanation":"Hava tankları, biriken su ve yağı boşaltmak için her tankın altında bulunan ve petcock da denilen tahliye valfleriyle boşaltılır."},"146":{"q":"Teksas'ta kırsal bir karayolunda havalı frenli yüklü tek bir kamyonu sürerken düşük hava uyarı ışığı yanıyor ve uyarı sesi çalıyor. Gösterge düşük basınç bölgesine doğru düşüyor. Hangi davranış doğrudur?","options":["Yaylı frenler henüz devreye girmediği ve hâlâ biraz havanız kaldığı için, düşük bir hızla bir sonraki çıkışa kadar sürmeye devam etmek","Sürmeye devam etmek ama kompresörün kaybedilen hava basıncını daha hızlı yeniden oluşturmasına yardımcı olmak için fren pedalına birkaç kez basmak","Hızınızı korumak ve şimdilik alarmı görmezden gelmek, çünkü uyarı genellikle kısa süre yanar ve regülatör devreye girince kendiliğinden söner","Güvenli olur olmaz durmak ve yoldan çıkmak, çünkü süregelen bir basınç düşüşü ani ve tehlikeli bir fren kaybına yol açabilir"],"explanation":"Düşük hava uyarısı yanıp basınç düşüyorsa, güvenli olur olmaz durup yoldan çıkın; çünkü basınç düşmeye devam ederse ani ve tehlikeli fren kaybı oluşabilir."},"147":{"q":"Çekici-römork aracımda sefer öncesi kontrol yapıyorum ve bir tamirci, fren (stop) lambalarımın yalnızca fren pedalına yeterince sert bastığımda yandığını söylüyor. Havalı frenli bir araçta, o elektrikli stop lambası anahtarını çalıştırıp fren lambalarını yakan şey fiziksel olarak nedir?","options":["Pedala basıldığında fren hatlarında yükselen hava basıncı, stop lambası anahtarını kapatır","Fren pedalının mekanik hareketi, tıpkı bir otomobildeki gibi anahtarı doğrudan iterek kapatır","Yaylı frenler boşalmaya başladığında oluşan hava basıncı düşüşü anahtarı kapatır","Fren kampanalarında oluşan ısı, stop lambalarına güç vermesi için anahtara sinyal gönderir"],"explanation":"Havalı frenlerde fren lambası anahtarı elektriklidir ve hava ile çalışır; pedala basınca yükselen hat basıncı anahtarı kapatarak fren lambalarını yakar."},"148":{"q":"Soğuk bir sabah ilk iş olarak çekici-römork aracıma biniyorum, motoru çalıştırıyorum ve yay (park) frenlerini bırakıp yola çıkmaya hazırlanıyorum. Yay frenlerini bırakıp sürmek için sarı park freni düğmesine basmadan önce, sistemdeki hava basıncı hakkında ne doğru olmalıdır?","options":["Düşük hava uyarı ışığı ve sesi yeni kapandı, bu yüzden o noktanın üzerindeki herhangi bir basınç bırakıp sürmek için yeterlidir","Basınç önce yeterince yükselmiş, yani regülatörün kesme noktasına yakın normal çalışma aralığına ulaşmış olmalı, ancak ondan sonra yay frenleri bırakılır","Basıncın yalnızca yay frenlerinin devreye girdiği 20-45 psi aralığının üzerine tekrar çıkması yeterli, sonra bırakıp gidebilirim","Basınç, yay frenlerinin kolayca boşa çıkması için olabildiğince düşürülmeli, sonra düğmeyi bırakırım"],"explanation":"Yaylı frenler hava basıncıyla açık tutulur, bu yüzden serbest kalmadan önce basıncın regülatör kesme noktasına yakın normal çalışma aralığına kadar yükselmesi gerekir."},"149":{"q":"Yüklü bir römorku uzun ve dik bir yokuşta aşağı indiriyorum ve tüm yol boyunca frenlere aşırı yüklendim. Aşağıya yaklaşırken fren kampanalarının aşırı ısındığını fark ediyorum. Bu aşırı ısınmanın havalı frenlerim üzerinde EN OLASI etkisi nedir?","options":["Genişleyen kampanalar pabuçlara daha sıkı bastırır ve bana belirgin şekilde daha güçlü fren sağlar","Isı, hatlardaki nemi kurutur, böylece frenler daha hızlı ve daha sağlam tepki verir","Frenler sönümlenir (fade): daha az durdurma gücü almak için giderek daha sert basmam gerekir","Hareket halindeyken hiçbir şey değişmez, ama kızgın kampanalar dururup park ettiğim anda çatlar"],"explanation":"Aşırı ısınan fren kampanaları hareketi ısıya çevirme yeteneğini kaybeder, böylece frenler zayıflar ve daha az frenleme için pedala daha sert basmanız gerekir."},"150":{"q":"Çekici-römork ile otoyolda giderken römork aniden kopuyor, hava hatları parçalanıyor ve römork tarafındaki tüm hava boşalıyor. Çekicimdeki hava beslemesini kapatıp koruyarak çekicinin kendisini kontrol edip durduracak kadar havayı bana bırakmak için hangi düzenek tasarlanmıştır?","options":["Röle valfi; pedala bastığım anda arka frenlere hava göndererek fren uygulamasını hızlandırır","Hızlı boşaltma valfi; pedalı bıraktığım anda frenlerin çözülmesi için hapsolmuş havayı hızla dışarı atar","Ayak valfi (pedal valfi); fren pedalına bastığımda ne kadar fren havası basıncı gönderdiğimi kontrol eder","Çekici koruma valfi; çekicinin hava beslemesini kapatarak çekiciyi frenleyip yönlendirmeye yetecek havayı korur"],"explanation":"Römork koparsa veya ağır şekilde hava kaçırırsa, çekici koruma valfi otomatik kapanarak çekicinin hava beslemesini keser ve fren ile direksiyon için yeterli havayı korur."},"151":{"q":"Çekicinizi yüklü bir römorka yeni bağladınız, hava hatlarını taktınız ve sistem basıncını regülatör kesme (cut-out) seviyesine kadar yükselttiniz. Römorku hareket ettirmeden önce gösterge panelindeki kırmızı, sekizgen düğmeye uzanıyorsunuz. Bu düğmeyi İÇERİ İTMEK ne sağlar?","options":["Çekiciden römorka hava göndererek römork fren sistemini doldurur (basınçlandırır)","Römorkun yaylı (park) frenlerini devreye sokarak römorkun park hâlinde kalmasını sağlar","Yalnızca çekicinin park frenlerini boşaltır, römork kilitli kalır","Düşük hava uyarı sesini test etmek için römork hava hatlarındaki havayı boşaltır"],"explanation":"Kırmızı sekizgen römork hava besleme düğmesini içeri itmek besleme hattını açar ve çekiciden römorkun fren sistemine hava göndererek onu doldurur."},"152":{"q":"Yüklü bir römork çekerken besleme hattındaki bir kaçak havamı boşaltmaya başlıyor. Gösterge düşmeye devam ederken, traktör koruma valfinin çekiciye giden havayı kapatıp sistemde kalanı korumak için kendiliğinden kapanacağı noktayı bilmek istiyorum. Bu otomatik kapanma yaklaşık hangi basınçta gerçekleşir?","options":["Yaklaşık 60 psi'de, düşük hava basıncı uyarı ışığı ve sesli uyarının ilk kez devreye girdiği aynı noktada","20 ila 45 psi aralığında, uyarı bir süredir devam ettikten sonra","Yaklaşık 100 psi'de, regülatörün kompresöre devreye girip pompalamaya devam etmesini söylediği seviyede","Yaklaşık 150 psi'de, besleme deposundaki emniyet supabının açılacağı seviyede"],"explanation":"Çekici koruma valfi, düşük hava uyarısı bir süredir aktifken hava basıncı 20 ila 45 psi aralığına düştüğünde otomatik olarak kapanır."},"153":{"q":"Sefer öncesi kontrolümde, römorkumun arka fren hazneleri çok geride, kabindeki ayak fren valfinden uzun bir hava hattı boyunca uzakta monte edilmiş durumda. Bir stajyer, havanın kat etmesi gereken onca fazladan mesafeye rağmen fren pedalına basıldığında bu uzaktaki arka frenlerin ön frenlere göre neden gözle görülür biçimde daha geç devreye girmediğini soruyor. Doğru açıklama nedir?","options":["Arka frenler mesafe yüzünden gerçekten daha geç devreye girer; bu yüzden hava frenlerinde uzun hava hattını telafi etmek için yerleşik 5 saniyelik bir fren gecikmesi kullanılır","Ön ve arka hazneler bir denge valfiyle bağlıdır; bu valf, her iki aksın tam olarak aynı anda bırakması için ön frenleri kasıtlı olarak geciktirir","Arka haznelerin yakınına monte edilmiş bir röle valfi, pedaldan gelecek havayı beklemek yerine yerel bir hava sinyaliyle bu frenleri hızlıca devreye sokar","Bir yaylı fren valfi arkada fazladan basıncı tutar, böylece pedaldan gelen hava oraya hiç ulaşmadan çok önce o frenler devreye girebilir"],"explanation":"Arka fren körüklerinin yanına monte edilen röle valfi, pedaldan gelecek havayı beklemek yerine yerel hava sinyaliyle bu frenleri uygulayarak arka frenlemeyi hızlandırır."},"154":{"q":"Sefer öncesi kontrol yaparken, hava frenli sistemimde ön aksta, fren hazneleri yakınında bir hızlı boşaltma valfi (quick-release valve) bulunduğunu fark ediyorum. Bir tamirci, bu parçanın normal çalışma sırasında frenler için gerçekte ne yaptığını açıklamamı istiyor. Hangi ifade onun amacını doğru tanımlar?","options":["Havanın fren haznelerine ulaşma hızını yavaşlatır, böylece frenler daha yumuşak ve düzgün devreye girer","Park ettikten sonra yaylı frenlerin kilitli kalması için haznelerdeki artık hava basıncını tutar","Ön frenlerin donmasını önlemek için hatlardaki kompresör yağını ve suyu dışarı atar","Pedalı bıraktığımda havanın fren haznelerinden hızla çıkmasını sağlar, böylece frenler daha hızlı boşalır (çözülür)"],"explanation":"Hızlı boşaltma valfi, pedalı bıraktığınız anda havanın fren körüklerinden yakından dışarı çıkmasını sağlar, böylece frenler daha hızlı çözülür ve sürtmez."},"155":{"q":"Park hâlindeki çekicimde bir yaylı fren körüğü arızalandı ve kamyon hareket etmiyor; ancak bir çekici onu otoyoldan kısa bir mesafe çekmesi gerekiyor. Frenleri normal yolla bırakacak hava bulunmadığına göre, aracın çekilebilmesi için tekerlekleri hangi işlem serbest bırakır?","options":["Arızalı körükteki yaylı frenleri elle kafesleyin (kafesleme cıvatasıyla yayı mekanik olarak geri sarın)","Onları bırakmak için sistemi göstergede yaklaşık 125 psi'ye kadar şişirin","Yayları bırakmak için sarı elmas biçimli park freni düğmesine basın","Körükler basıncı tutamasın diye hava hatlarını sökün ve kesin"],"explanation":"Yaylı frenler yaylarla uygulanır ve hava ile açık tutulur, bu yüzden bir körük arızalandığında çekme için tek çözüm onları kafesleme cıvatasıyla elle kafeslemektir."},"156":{"q":"Islak, kaygan bir karayolunda havalı frenli çekicimde, başka bir sürücü bana ön tekerlek frenlerini sökmem veya gevşetmem gerektiğini, çünkü direksiyon lastiklerinin kaymasına neden olup yağmurda kamyonu kontrol etmeyi zorlaştırdıklarını söylüyor. Texas CDL El Kitabı'na göre ön tekerlek frenlerime nasıl davranmalıyım?","options":["Ön tekerlek frenleri ıslak yollarda sökülmelidir, çünkü direksiyon lastiklerinin frenlenmesi ön taraf kaymasına ve direksiyon kaybına neden olur","Ön tekerlek frenleri normal durmak için önemli ve gereklidir ve onlar yüzünden kayma tehlikesi yoktur","Ön tekerlek frenleri yalnızca göstermelik faydalıdır ve gerçek durma gücüne çok az katkı sağlar, bu yüzden zayıf bırakılmaları kabul edilebilir","Ön tekerlek frenlerini ayarsız bırakmak en iyisidir, böylece işin çoğunu arka frenler yapar ve ön lastikler daha uzun ömürlü olur"],"explanation":"Ön tekerlek frenleri gerçek ve gerekli frenleme gücü sağlar; kaymaya yol açtıkları inancı bir efsanedir, bu yüzden her zaman düzgün çalışmalıdır."},"157":{"q":"Islak iki şeritli bir karayolunda yük taşıyorum ve durma sırasında ön frenlerimin çok zorlandığını fark ediyorum. Deneyimli bir sürücü bir keresinde bana, kaygan zeminde aracın kaymasına neden oldukları için ön frenleri devre dışı bırakmamı veya kullanmamamı söyledi. Bu tavsiyeye uymadan önce, Texas CDL El Kitabı'nın ön tekerlek frenlemesi hakkında gerçekte ne söylediğini hangi ifade yansıtır?","options":["Haklı — ön frenler kaymaların başlıca nedenidir, bu yüzden yol ıslak olduğunda onları daima devre dışı bırakmalısınız.","Haklı, ama yalnızca 55 mil/saatin üzerinde — bu hızın altında ön frenler normal şekilde güvenle kullanılabilir.","Yanılıyor — ön frenlerin kaymaya neden olduğu fikri yanlıştır ve en iyi frenlemeyi tüm frenler birlikte çalıştığında elde edersiniz.","Kısmen haklı — ön frenler kuru yolda sorun değildir, ancak hiçbir koşulda durma gücü için onlara asla güvenilmemelidir."],"explanation":"Ön frenlerin kaymaya neden olduğu inancı yanlıştır; en iyi ve en dengeli durma gücünü tüm frenler birlikte çalıştığında elde edersiniz."},"158":{"q":"Texas'ta kuru bir otoyolda saatte 55 mil hızla yük taşırken önümde duran bir araç görüp fren pedalına sertçe basıyorum. Eğitmenim, havalı frenlerimin gerçekten kavramadan önce yerleşik bir gecikmesi olduğunu, bu yüzden tekerlekler yavaşlamaya başlamadan ÖNCE bu yarım saniyelik gecikme boyunca kamyonun fazladan bir mesafe yuvarlanmaya devam ettiğini hatırlatıyor. Saatte 55 milde bu fren gecikmesi yaklaşık ne kadar EKSTRA durma mesafesi ekler?","options":["Yaklaşık 2 fit, çünkü yarım saniyelik gecikme otoyol hızında önemli olamayacak kadar kısadır","Yaklaşık 300 fit, çünkü havalı frenleri hidrolik frenlerden çok daha yavaş durduran şey bu gecikmedir","Yaklaşık 1 mil, çünkü herhangi bir frenleme başlamadan önce havanın hatlar boyunca tüm yolu kat etmesi gerekir","Yaklaşık 32 fit — kamyonun saatte 55 milde yarım saniyelik fren gecikmesi sırasında kat ettiği mesafe"],"explanation":"Havalı frenlerde yaklaşık yarım saniyelik gecikme vardır, bu yüzden 55 mil/saatte kamyon, frenler tutmaya başlamadan önce yaklaşık 32 fit yol alır."},"159":{"q":"CDL notlarımı gözden geçiriyorum ve havalı fren toplam durma mesafesini oluşturan dört parçanın üçünü zaten hesaba kattım: algılama mesafesi, tepki mesafesi ve fren gecikme mesafesi. Toplam için hâlâ EKSİK olan parça hangisi?","options":["Etkili frenleme mesafesi, frenler gerçekten tutup aracı yavaşlatmaya başladıktan sonra kat edilen mesafe","Etkili direksiyon mesafesi, ABS'nin tekerleklerin kilitlenmesini önlemek için ihtiyaç duyduğu ekstra mesafe","Kompresör basınç toplama mesafesi, regülatör basıncı tekrar kesme değerine çıkarırken kat edilen mesafe","Ayar kolu mesafesi, frenlemeden önce aşırı itme çubuğu boşluğu giderilirken kat edilen mesafe"],"explanation":"Toplam havalı fren durma mesafesi; algılama, tepki, fren gecikmesi ve frenler tutduktan sonra kat edilen etkili frenleme mesafesinin toplamıdır."},"160":{"q":"Yüklü bir çekici-römork takımıyla uzun ve dik bir dağ yokuşundan iniyorum ve yer çekiminin kamyonu giderek hızlandırdığını hissediyorum. İniş uzadıkça hava frenlerinin sıcaklığı yükseliyor. Aracı en alta kadar kontrol altında tutmak için doğru frenleme tekniği nedir?","options":["Motor daha düzgün çalışsın diye yüksek viteste kalmak ve hızı düşük tutmak için fren pedalına sert ve sürekli basmak","İnişten önce düşük vites seçmek ve hafif, dengeli fren basıncı uygulamak; güvenli hızımın yaklaşık 5 mil/saat altına düşünce bırakıp sonra tekrar basmak","Frenler uygulamalar arasında soğuyabilsin diye fren pedalını hızlıca açıp kapayarak ('pompalayarak') basmak","Motoru korumak için boşa almak ve ancak araç elimden kaçmaya başladığını hissedince frene hafifçe dokunmak"],"explanation":"İnişten önce düşük vites seçin ve hafif, düzenli fren uygulayın; güvenli hızınızın yaklaşık 5 mil/saat altına düşünce bırakın ve hız artınca tekrar uygulayın."},"161":{"q":"Yüklü çekicimle uzun bir dağ yokuşundan iniyorum. Düşük vitese zaten geçtim ve eğitmen, hızımı kontrol altında tutmak için doğru 'snub' (aralıklı) frenleme tekniğini kullanmamı söylüyor. Aşağıdakilerden hangisi yapmam gerekeni doğru şekilde açıklar?","options":["Sabit bir hız tutmak için sert ve sürekli fren basıncı uygulayıp tüm iniş boyunca basılı tutmak","Hava basıncının basışlar arasında toparlanmasına zaman tanımak için frenleri hızlı dokunuşlarla hafifçe açıp kapatarak yelpazelemek","Hızımı güvenli hızın yaklaşık 5 mil/saat altına düşürecek kadar sert fren yapmak, frenleri bırakmak, sonra hız tekrar artınca yeniden uygulamak","Boşa almak ve motorun frenlemeyle çatışmaması için frenlere hafifçe basıp gitmek"],"explanation":"Aralıklı (snub) frenleme, güvenli hızınızın yaklaşık 5 mil/saat altına düşürecek kadar sert fren yapıp tamamen bırakmak ve hız artınca tekrar uygulamaktır."},"162":{"q":"Yüklü bir çekici-römork takımı sürüyorum ve ileride uzun, dik bir dağ inişi olduğunu uyaran bir tabela görüyorum. İnişte hava frenlerimle hızımı güvenli bir şekilde kontrol etmek için vitesimi ne zaman seçmeliyim?","options":["İnişin yaklaşık yarısında, eğimin gerçekte ne kadar dik olduğunu ve ne kadar hızlı hızlandığımı hissedebildiğimde","Yalnızca motor aşırı devir yapmaya başlarsa ya da frenlerim zayıflamaya başlarsa ve gerçekten daha düşük bir vitese ihtiyaç duyarsam","Aşağıya yakın, yolun düzleştiği ve şanzımanı zorlamadan vites küçültebileceğim yerde","İnişe başlamadan önce, hâlâ düz zemindeyken ve vites kutusunu zorlamadan vites değiştirebilirken"],"explanation":"İnişe başlamadan önce, hâlâ düz zemindeyken düşük vitesi seçin; çünkü dik bir yokuşta hızlı giderken vites küçültmek zor ya da imkânsızdır."},"163":{"q":"Sefer öncesi kontrolümde bir çekici-römork aracının frenlerini incelerken, tekerleklerden birindeki fren balatalarının (pabuç astarlarının) tehlikeli ölçüde inceldiğini fark ediyorum. Aracın geri kalanı sorunsuz. DPS kurallarına göre, bu aracın çalışmasına izin verilmeden önce ne yapmalıyım?","options":["Aşınmış balatalar değiştirilene kadar aracı servis dışı bırakmalıyım, çünkü tehlikeli ölçüde ince balatalar aracı sürmeyi güvensiz kılar.","Normal şekilde sürmeli ama takip mesafesini artırmalıyım, çünkü ince balatalar fren gücünü yalnızca biraz azaltır.","İnce balataları oturtmak için fren pedalına birkaç kez basıp, pedal sağlam hissettiriyorsa devam etmeliyim.","Hava kaçak oranı dakikada 3 psi'nin altında kaldığı sürece devam etmeliyim, çünkü balata kalınlığı fren kontrolünün parçası değildir."],"explanation":"Aşırı incelmiş fren balataları otomatik bir hizmet dışı durumudur, bu yüzden balatalar değiştirilene kadar araç kullanılmamalıdır."},"164":{"q":"Sefer öncesi muayenede düz bir zemine park ediyorum, tekerleklere takoz koyuyorum, park frenlerini bırakıyorum ve aşırı itme çubuğu hareketini kontrol etmek için manuel bir balata ayarlayıcısını (slack adjuster) tutuyorum. Elimle sertçe çekiyorum. Frenlerin doğru ayarlı olduğuna karar vermem için ne kadar hareket etmesi gerekir?","options":["Yaklaşık tam bir inç serbest boşluk, ayar gerekmeden önce izin verilen azami değerdir","Elle çekildiğinde yaklaşık bir inçten daha az hareket etmelidir","Yaklaşık altı inçlik hareket bile güvenli ayarlanmış bir freni gösterir","Hiç hareket etmemelidir, çünkü herhangi bir hareket ayarın bozuk olduğu anlamına gelir"],"explanation":"Elle sert çekildiğinde, manuel ayar kolunun çubuğu yaklaşık bir inçten az hareket etmelidir; daha fazla boşluk frenlerin ayarsız olduğunu gösterir."},"165":{"q":"Havalı frenli, yüklü bir çekici-römork kullanıyorum ve hafif bir inişin dibindeki dur işaretine yaklaşıyorum. Fren pedalına bastığımda, kamyonetimdeki hidrolik frenlere kıyasla frenlerin gerçekten tutmasından önce kısa bir gecikme olduğunu fark ediyorum. Bu farkı güvenli bir şekilde hesaba katmak için frene ne zaman basmaya başlamalıyım?","options":["Hidrolik frenli bir araçtaki ile aynı noktada, çünkü yarım saniyelik gecikme önemsenmeyecek kadar küçüktür","Normalden biraz daha geç, çünkü hava basıncı frenlere ulaştığında ekstra durdurma kuvveti oluşturur","Normalden biraz daha erken, frenler tutmadan önceki yaklaşık yarım saniyelik havalı fren gecikmesini telafi etmek için","Yalnızca römork frenleri kendiliğinden devreye girdikten sonra, ardından durmayı tamamlamak için pedal basıncı ekleyerek"],"explanation":"Yaklaşık yarım saniyelik havalı fren gecikmesi nedeniyle, gecikmenin durma mesafenize eklenmemesi için her zamankinden biraz daha erken fren yapmaya başlayın."},"166":{"q":"Yüklü bir kombinasyonla uzun ve dik bir dağ yokuşundan iniyorum ve düşük vites kullanmak yerine tüm iniş boyunca fren pedalına hafif, sürekli bir basınç uyguluyorum. Frenleri tüm iniş boyunca bu şekilde sürekli basılı tutmak büyük olasılıkla frenlerimin:","options":["Daha serin kalmasına neden olur, çünkü sürekli basınç iş yükünü tüm kampanalara eşit dağıtır","Yokuşta ne kadar uzun basılı tutarsam kamyonu o kadar iyi tutmasına neden olur","Balatalar kampanalardan hiç tam ayrılmadığı için daha yavaş aşınmasına neden olur","Aşırı ısınıp etkisini yitirmesine ve daha yokuşun dibine varmadan durdurma gücümü kaybetmeme neden olur"],"explanation":"Uzun bir yokuşta inerken frenleri sürekli sürtmek onları aşırı ısıtır ve fren kaybına yol açarak dibe varmadan durma gücünü yok eder."},"167":{"q":"Hava (basınçlı) frenli düz kamyonumla suyla dolmuş bir alçak geçidi yeni geçtim ve ileride kuru yolda frenlerimin zayıf hissettirdiğini ve ilk duruşta düzensiz tuttuğunu fark ettim. Islak frenleri ele almanın doğru yolu nedir?","options":["Düşük hızda ilerlemeye devam ederken hafif ve nazik fren basıncı uygulayarak sürtünme ısısının onları kurutmasını sağlamak","Sarı park freni düğmesini çekip yay frenlerini bir dakika basılı tutarak suyu sıkıp çıkarmak","Tekerlek hızının suyu balatalardan hızla savurması için motoru sonuna kadar sertçe hızlandırmak","Hazneler içindeki sıkışmış suyu dışarı itmek için fren pedalına birkaç kez hızlıca basıp bırakmak"],"explanation":"Islanan fren balatalarını kurutmak için yavaş giderken hafif ve sabit fren basıncı uygulayın; sürtünme ısısı suyu buharlaştırıp dengeli frenlemeyi geri getirir."},"168":{"q":"Yol kapanmasını beklemek için aracımı dik bir banket üzerine çektim. El frenini (park frenini) çektim, ancak bu eğimde uzun süreli bir duruşta aracı tutamayabileceğinden endişeleniyorum. Güvenli hava frenli kullanım kurallarına göre, aracın kaymasını önlemek için hangi ek adımı atmalıyım?","options":["Şanzımanın yükü tutmaya yardımcı olması için motoru düşük viteste çalışır halde bırakmak","Tekerleklerin yuvarlanmasını mekanik olarak engellemek için lastiklerin önüne takoz yerleştirmek","Yaylı frenlerde ekstra basınç oluşturmak için fren pedalına birkaç kez basmak","Römork tekerleklerini daha sıkı kilitlemek için kırmızı sekizgen römork hava besleme düğmesini çekmek"],"explanation":"Eğimde park frenleri yavaşça hava kaçırabilir, bu yüzden tekerlekleri mekanik olarak engellemek için takoz koyun."},"170":{"q":"Yola çıkış öncesi kontrolümde, çekicimin havalı fren parçalarını incelemek için tekerleklerin yanına çömeldim. Fren kampanalarını ve balatalarını gözden geçirirken, hangi durum aracı sürmek yerine servis dışı bırakmamı gerektirir?","options":["Kampana yüzeyi her tarafında pürüzsüz, parlak metalik bir parlaklık gösteriyor","Fren balata kaplamalarında hâlâ bolca kalınlık kalmış durumda","Fren kampanasının yüzeyinde çatlaklar var","Kampana yüzeyinde hafif bir yol tozu ve kir tabakası var"],"explanation":"Yüzeyinde çatlak olan bir fren kampanası, frenleme ısısı ve kuvveti altında parçalanabilen bir kusurdur ve aracı sürmeyi tehlikeli yapar."},"171":{"q":"2015 model bir çekicide sürüş öncesi kontrol yapıyorum. Fren hatlarını izlerken, sert frenleme sırasında bir tekerleğin kilitlenmesini önlemek için o tekerleğe saniyede yüzlerce kez otomatik olarak hava basıncını darbeli şekilde veren ve boşaltan bir valf buluyorum. Bir iş arkadaşım bu parçanın kamyonun tamamen farklı bir sistemine ait olduğunu söylüyor. Bu modülatör valfi gerçekte hangi sisteme aittir?","options":["Çift hava besleme sistemine, çünkü hava basıncını birincil ve ikincil depolar arasında döngüye sokar","Park freni sistemine, çünkü yaylı frenlerin her tekerlekte devreye girip çözülmesini kontrol eder","Servis freni sistemine, çünkü sürücünün fren pedalıyla gönderdiği havayı doğrudan ayarlar","ABS (kilitlenmeyi önleyici fren) sistemine, çünkü modülatör valfi basıncı darbeli vererek tekerleklerin kilitlenmesini önler ve böylece fren yaparken direksiyon hâkimiyetini korursunuz"],"explanation":"Sert frenlemede tekerleğin kilitlenmesini önlemek için saniyede birçok kez hava darbesi gönderen valf, direksiyon kontrolünü koruyan ABS modülatör valfidir."},"172":{"q":"Çekicimi bir römorka bağlıyorum ve iki hava hattını (gladhand bağlantıları) takmam gerekiyor: servis hattı ve besleme/acil hat. Doğru besleme hattını tuttuğumdan ve bağlantıları çaprazlamadığımdan emin olmak için besleme (acil) hattında hangi rengi aramalıyım?","options":["Kırmızı","Mavi","Sarı","Yeşil"],"explanation":"Römorkun acil durum (besleme) hava hattı kırmızıdır ve kabindeki kırmızı sekizgen römork hava besleme düğmesiyle eşleşir."},"173":{"q":"Çekicimi bir römorka bağlıyorum ve birimler arasında uzanan iki hava hattına uzanıyorum. Biri fren pedalına bastığımda römorkun frenlerini uygulayan ve bırakan sinyali taşır (servis/kontrol hattı), diğeri ise römorkun deposunu doldurmak ve acil durum hattını kontrol etmek için sürekli hava sağlar. Servis bağlantı başlığına bağlamak için doğru olanı tutmam gerekiyor. Aradığım servis (kontrol) hattını hangi renk gösterir?","options":["Kırmızı hat, çünkü kırmızı, fren sinyalini pedalımdan römorka taşıyan devreyi işaret eder","Mavi hat, çünkü mavi, römorkun frenlerini uygulayan ve bırakan servis (kontrol) hattını işaret eder","Siyah hat, çünkü çoğu kombinasyonda ayak frenine bağlı olan hortum nötr renklidir","Turuncu hat, çünkü daha parlak renk, fren pedalına yanıt veren hortumu işaret eder"],"explanation":"Fren pedalı sinyalini römorkun servis frenlerini uygulamak ve bırakmak için ileten servis (kontrol) hattı mavidir."},"174":{"q":"Otoyolda yüklü bir römork çekerken römork aniden çekicimden ayrılıyor ve hava besleme hortumu kopuyor. Römork kendi başına serbest kayarken, römorkun frenlerine ne olmalıdır?","options":["Tamamen serbest kalırlar, böylece römork sürtünme onu yavaşlatana kadar kaymaya devam eder","Yalnızca kabinden kırmızı römork hava besleme düğmesini çektikten sonra serbest kalırlar","Hava beslemesinin kaybı römorkun acil durum frenlerini tetiklediği için otomatik olarak devreye girerler","Bir ABS sisteminin tepki vereceği gibi hızlıca açılıp kapanırlar"],"explanation":"Römork koparsa, hava beslemesinin kaybı yaylı acil frenlerin otomatik olarak devreye girmesini sağlar ve kaçan römorku durdurur."},"175":{"q":"Çalışan ABS sistemine sahip bir çekici-römork kullanırken, önünüze bir otomobil giriyor ve aniden duruyor. Arkadan çarpmamak için fren pedalına var gücünüzle basıyorsunuz. ABS bu sert frenleme sırasında görevini yaparken gerçekçi olarak ne yapmayı bekleyebilirsiniz?","options":["Pedalı sonuna kadar bastırıp ABS'nin toplam durma mesafenizi gözle görülür şekilde kısaltacağına güvenmek","ABS daha hızlı devreye girip yola daha iyi tutunsun diye fren pedalına hızlı hızlı pompalamak","Pedalı basılı tutmak ama direksiyonu dümdüz tutmak, çünkü sert frenleme sırasında direksiyon çevirmek ABS'yi devre dışı bırakır","Pedalı sıkıca basılı tutarken aynı anda tehlikenin etrafından direksiyonla manevra yapmak, çünkü tekerlekler kilitlenmeyecek"],"explanation":"ABS ile fren pedalına sertçe basıp aynı anda tehlikenin etrafından direksiyonu çevirebilirsiniz, çünkü sistem tekerleklerin kilitlenmesini önler."},"176":{"q":"ABS'siz eski bir çekici-römork kullanıyorum ve önümdeki bir otomobil aniden duruyor. Zaten sert bir kesik-kesik (stab) frenleme başlattım, ama aracı kontrolü kaybetmeden hızla durdurmak için ikinci bir tekniğe ihtiyacım var. Kesik-kesik frenleme dışında, mümkün olduğunca çabuk durmak için hangi yöntemi kullanmalıyım?","options":["Kontrollü frenleme; tekerlekleri kilitlemeden frene sağlam şekilde basmak","Kilitli-tekerlek frenlemesi; pedalı tabana kadar basıp lastikleri kaydırarak durdurmak","Tekerleklerde azami basıncı korumak için frene sürekli ve hızlıca pompa yapmak","Sadece motor freni; vites küçültüp pedalı bırakarak aktarma organlarıyla yavaşlamak"],"explanation":"Kontrollü frenleme, tekerlekleri kilitlemeden frenleri olabildiğince sert uygulamaktır, çünkü kilitli tekerlekler kaymaya ve direksiyon kaybına yol açar."},"177":{"q":"Kombinasyon aracımda dış kontrol yapıyorum ve otoyola çıkmadan önce römorkun ABS sisteminin çalıştığından emin olmak istiyorum. Kontrol etmek için yukarı çıkıyorum ama bir iş arkadaşım ABS arıza göstergesine yanlış yerde baktığımı söylüyor. Römorkta o ABS uyarı lambasını bulmak için gerçekte nereye bakmalıyım?","options":["Ön tarafta, kral pimi yakınında; römork ABS sistemi devrede ve hazır olduğunda yeşil bir lamba yanar","Römorkun sol arka tarafında; bir ABS sorununu bildiren sarı bir arıza lambası bulunur","Arka kapıda; römork ABS sistemi tamamen arızalandığında kırmızı bir lamba yanar","Römork tavanında; sürücünün aynalardan görebileceği mavi bir lamba bulunur"],"explanation":"Römorkun ABS arızası, römorkun sol arka tarafına monte edilmiş sarı bir lamba ile gösterilir."},"178":{"q":"Yüklü bir römork ile I-35 otoyolunda seyir halindeyken römorktaki ABS arıza lambası aniden yanar. Kullandığınız çekici daha yenidir ve kendi ABS sistemi hâlâ normal çalışmaktadır. Arıza lambası yalnızca römorkun ABS sisteminin devre dışı kaldığını gösterir. Bu yolculuğun geri kalanında neye güvenebileceğinizi EN İYİ açıklayan ifade hangisidir?","options":["Römork ABS'si arızalandığı için römorkun servis frenlerini kaybettiniz ve katlanmayı (jackknife) önlemek için hemen durmalısınız.","Römork ABS'si arızalandığı için durma mesafeniz artık uyarı lambası yanmadan öncekinden daha kısadır.","Yalnızca ABS arızalandığı için tüm araç katarında normal servis frenleriniz hâlâ vardır, ancak römork tekerlekleri artık sert frenlemede kilitlenebilir.","Yalnızca römork ABS'si arızalandığı için çekicinin çalışan ABS'si römork tekerleklerinin fren kontrolünü otomatik olarak devralır."],"explanation":"ABS arızası yalnızca kilitlenmeyi önleme işlevini devre dışı bırakır; normal servis frenleriniz çalışmaya devam eder, ancak ilgili tekerlekler sert frenlemede kilitlenebilir."},"180":{"q":"Sefer öncesi kontrolümde, hava fren gösterge panelimde tek iğne yerine iki ayrı basınç iğnesi olduğunu fark ediyorum. Motoru çalışır halde bırakınca, regülatör kompresörü kesene kadar iki iğne de yükseliyor ve her biri kendi değerinde sabit kalıyor. Bu iki iğnenin varlığı, bu aracın nasıl yapıldığı konusunda bana ne anlatır?","options":["İki hava kompresörü vardır, her biri bir iğneyi bağımsız olarak besler","Bir iğne servis frenlerini, diğeri park frenlerini gösterir","İki regülatörü vardır, bu yüzden her sistem farklı bir psi değerinde kesilir","Bu, çift hava fren sistemidir: birincil ve ikincil hava sistemi"],"explanation":"Göstergedeki iki ibre, ortak kumandaları paylaşan biri birincil biri ikincil iki ayrı hava sistemine sahip çift hava frenli sistemi gösterir."},"181":{"q":"Yüklü bir römorku dur-kalk şehir trafiğinde çekiyorum ve alışkanlıktan duraklar arasında daha hızlı tepki vermek için sol ayağımı hafifçe fren pedalının üzerinde tutuyorum. Eğitmenim, gerçekten fren yapmadığım her an ayağımı pedaldan tamamen çekmemi söylüyor. Bunun verdiği ANA neden nedir?","options":["Hafif ama sürekli basınç bile frenleri kısmen uygulanmış tutar; bu da onları ısıtır ve erkenden aşındırır","Ayağı pedalda tutmak, hava basıncı çok düşerse otomatik yaylı frenlerin devreye girmesini engeller","Pedalın üzerinde dinlenmek hava deposundan yavaşça hava boşaltır ve düşük hava uyarısını erken tetikler","Hafif pedal basıncı regülatörü geçersiz kılar ve kompresörün 100 psi'de yeniden devreye girmesini önler"],"explanation":"Ayağınızı pedalın üzerinde tutmak frenleri hafifçe basılı tutar; bu sürekli sürtünme balataları aşırı ısıtır ve erkenden aşındırır."},"182":{"q":"Bir tamirci çekicimdeki sızdıran fren körüğünü yeni değiştirdi; tam yüklü dorse bağlı hâlde atölye avlusunda park hâlindeyim ve teslimat gecikiyor. Hava göstergesi yaklaşık 125 psi gösteriyor ve düşük hava uyarısı sönük. Otoyola çıkmadan önce İLK olarak ne yapmalıyım?","options":["Gösterge zaten yaklaşık 125 psi gösterdiği için tamircinin işine güvenip doğrudan otoyola katılmak","Sürmeden önce frenleri düşük hızda denemek; yaklaşık 5 mil/saatte yavaşça durarak frenlerin tuttuğunu ve aracı bir tarafa çekmediğini doğrulamak","Yola çıkıp ilk bir mil boyunca yeni körüğün oturması için frenlere hafifçe basarak ilerlemek","Yeni onarılan hattaki havayı boşaltmak için avluda fren pedalına birkaç kez basıp pompalamak"],"explanation":"Herhangi bir fren onarımından sonra frenleri kendiniz doğrulamalısınız; bunun için yaklaşık 8 km/s hızda yavaş bir durma testi yaparak tuttuklarını ve düz çektiğini onaylayın."},"183":{"q":"Sefer öncesi kontrol sırasında çekicimin altına giriyorum ve arka akstaki bir fren ayarlayıcısının (slack adjuster) itme çubuğu boşluğunun, AYNI aksın karşı tekerleğindeki ayarlayıcıya göre belirgin şekilde daha fazla olduğunu fark ediyorum. O akstaki iki fren ayarlayıcısının nasıl ayarlanması gerektiği konusunda aşağıdakilerden hangisi doğrudur?","options":["Daha ağır yüklenen taraftaki fren ayarlayıcısı, römork ağırlığını dengelemek için daha gevşek bırakılmalıdır","İkisi arasındaki boşluk farkı normaldir ve düzeltmem gereken bir şey değildir","Aynı aks üzerindeki her iki fren ayarlayıcısı da aynı şekilde ayarlanmalıdır, bu yüzden eşit olmayan boşluk düzeltilmelidir","Biri sökülmeli ki o akstaki diğer fren tüm işi eşit şekilde yapsın"],"explanation":"Aynı aks üzerindeki her iki ayar kolu eşit boşluğa sahip olmalıdır; bu nedenle eşit olmayan boşluk, sürmeden önce giderilmesi gereken bir kusurdur."},"184":{"q":"Soğuk bir Teksas sabahında araç öncesi kontrolümü yaparken, hava fren sistemimde kompresör ile hava depoları arasına monte edilmiş bir hava kurutucusu olduğunu fark ediyorum. Bir tamirci, bu parça arızalanırsa kışın fren hatlarımda ve depolarımda donma yaşama olasılığımın çok daha yüksek olacağı konusunda beni uyarıyor. Hava kurutucusunun asıl görevinin ne olduğuna dayanarak, arızası neden bu donma sorununa yol açar?","options":["Hava kurutucusu hatları yağlamak için az miktarda yağ ekler ve bu yağ olmadan hatlar soğukta sıkışır ve donar","Hava kurutucusu sıkıştırılmış havayı depolara ulaşmadan önce ısıtır, bu yüzden arızalanırsa soğuk hava sistemi dondurur","Hava kurutucusu havayı regülatör kesme basıncına kadar basınçlandırır ve yeterli basınç olmadan kalan hava hatlarda donar","Hava kurutucusu havadan nemi alır, bu yüzden arızalanırsa su depolarda ve hatlarda birikir ve soğuk havalarda donabilir"],"explanation":"Hava kurutucu, sıkıştırılmış havadan nemi giderir; bu nedenle arızalanırsa depolarda ve hatlarda su birikir ve soğuk havada donabilir."},"185":{"q":"Yüklü römorkömu depoya bıraktım ve çekiciyi römorksuz olarak (bobtail) şehrin öbür ucuna sürüyorum. Yüklü römork takılıyken duruma göre, sert bir fren yapmam gerektiğinde bu aracın nasıl davranmasını beklemeliyim?","options":["şaşırtıcı bir şekilde durdurması daha zor olabilir; bu yüzden ekstra dikkat ve daha fazla mesafe bırakmalıyım, çünkü römorksuz çekici fren altında farklı davranır","Gözüle görülür şekilde daha hızlı ve daha kısa mesafede durur, böylece diğer araçları öncekinden daha yakından güvenle takip edebilirim","Dururken özel bir dikkat gerektirmez, çünkü römorku bırakmak ağırlığı kaldırdı ve artık frenlerin işi kolay","Dururken daha az direksiyon çabası ve düzeltme gerektirir, çünkü çekici artık genel olarak çok daha hafif"],"explanation":"Römorksuz bir çekici (bobtail), tahrik akslarında daha az ağırlık ve yol tutuşu olduğundan durdurmak daha zor olabilir; bu yüzden ekstra dikkat ve durma mesafesi bırakın."},"186":{"q":"Sefer öncesi kontrol sırasında çekicimin altına giriyorum ve bir bağlama kayışı gevşediği için hava deposunun (tankının) braketi üzerinde hafifçe kaydığını fark ediyorum. Bu aracı yola çıkarmadan önce, o hava tankının doğru montaj şekli nedir ve bu neden önemlidir?","options":["Yol titreşimi ve şasi esnemesi tankın kaynaklarını çatlatamasın diye esnek kayışlarla gevşek şekilde","Şasiye sağlam şekilde, böylece sabit kalır ve hatlar ile bağlantı parçaları zorlanmaz veya arızalanmaz","Biriken su ve yağ montaj donanımından uzak kalsın diye tahliye vanası yukarı bakacak şekilde","Tank öne ve fren hatlarından uzağa boşalsın diye şasi kirişinde yüksekte ya da kabinin arkasında"],"explanation":"Hava depoları, titreşime karşı sabit kalmaları ve bağlı hatlar ile rakorların zorlanmaması veya hasar görmemesi için şasiye sağlam bir şekilde monte edilmelidir."},"187":{"q":"Sefer öncesi kontrolüm sırasında römorkün tambur frenine bakıyorum ve üzerinde mekanik bir fren balçata aşınma göstergesi olduğunu fark ediyorum. Bu cihaz bir okuma verdiğinde, fren balçatalarının durumu hakkında bana aslında ne söylüyor?","options":["Balçataların nem çektiğini ve frenler tutmadan önce kurutulması gerektiğini","Ayar kollarının (slack adjuster) izin verilen azami itme çubuğu hareketine ulaştığını ve ayar gerektirdiğini","Balçataların değiştirilmesi gereken noktaya kadar aşındığını","Balçataların doğru oturduğunu ve frenlerin bu sefer için güvenli olduğunu"],"explanation":"Fren aşınma göstergesi, fren balatalarının değiştirilmesi gereken noktaya kadar aşındığını gösterir."},"188":{"q":"Yüklü bir bağlantılı araçla uzun ve dik bir dağ inişini yeni bitirdim ve mola vermek için bir dinlenme alanına girmek istiyorum. Frenlerim inişten dolayı kıpkırmızı sıcak. Şu anda park (yaylı) frenleri çekMEMEM için EN İYİ neden aşağıdakilerden hangisidir?","options":["Yaylı frenleri sıcakken çekmek, römork hava besleme basıncının 60 psi'nin altına düşmesine ve düşük hava uyarısının devreye girmesine neden olabilir","Sıcak frenler itme çubuğu hareketini artırır, bu yüzden frenler soğuyana kadar gevşek ayarlayıcılar (slack adjuster) ayar dışı kalır","Yaylı frenler ancak hava basıncı 20–45 psi aralığına düştüğünde düzgün tutar ve sıcak frenler bunu engeller","Çok sıcak fren parçalarını yaylı frenlerle sıkıştırmak onlara zarar verebilir, bu yüzden park etmeden önce frenlerin soğumasını beklemeliyim"],"explanation":"Yay (park) frenlerini çok sıcak frenlere uygulamak parçalara zarar verebilir; bu nedenle uzun bir inişten sonra park etmeden önce frenlerin soğumasını bekleyin."},"189":{"q":"Sefer öncesi muayene sırasında çekicimi yüklü bir römorka bağladım, sistemi yaklaşık 125 psi'ye kadar şarj ettim, motoru kapattım ve kaçağı kontrol etmek için fren pedalına basıp basılı tutarak gösterge panelindeki manometreyi izledim. Tam bir dakika boyunca, bu kaçak testini yine de geçebilmem için görebileceğim EN FAZLA hava basıncı düşüşü nedir?","options":["4 psi","3 psi","2 psi","0 psi"],"explanation":"Frenler basılıyken, kombine bir araçta hava kaybı dakikada 4 psi'nin altında kalmalıdır."},"190":{"q":"Sefer öncesi kontrolümde, çekici-römork kombinasyonumda hava kaçağını ölçüyorum. Motor kapalı, sistem yaklaşık 125 psi'ye tam dolu ve frenleri SERBEST bıraktım (park valfleri dışarı çekili, ayağım pedalda değil). Bir dakika boyunca göstergemi izlerken, kaçak standart dışı sayılmadan önce izin verebileceğim azami hava kaybı nedir?","options":["Dakikada 2 psi, çünkü frenler serbestken kaçak sınırı budur","Dakikada 3 psi, çünkü frenleri serbest bırakılmış bir kombinasyon aracı biraz daha fazla kaçak yapabilir","Dakikada 4 psi, çünkü bir kombinasyon aracı için kaçak sınırı budur","Düşük hava uyarısı henüz devreye girmediği sürece her türlü kayıp kabul edilebilir"],"explanation":"Frenler bırakıldığında, kombine bir araç dakikada 3 psi'ye kadar hava kaybedebilir, tek araçtan biraz daha fazla."},"191":{"q":"Bir çekici-römork üzerinde sefer öncesi kontrolümü yaparken motoru kapatıyorum, frenleri bırakıyorum ve havayı boşaltmak için fren pedalına ardı ardına basıyorum. Düşük hava basıncı uyarı ışığının ve sesli uyarıcısının çalıştığını doğrulamak için gösterge panelini izliyorum. Texas CDL El Kitabı'na göre, birleşik aracımdaki hava basıncı hangi seviyenin altına düşmeden önce uyarının devreye girmesi gerekir?","options":["Basınç 45 psi altına düşmeden önce — yaylı frenlerin devreye girmeye başladığı nokta","Basınç 100 psi altına düşmeden önce — regülatörün kompresörü tekrar devreye soktuğu nokta","Basınç 60 psi altına düşmeden önce — frenler etkili durdurma gücünü kaybetmeden çok önce","Basınç 20 psi altına düşmeden önce — acil durum frenlerinin tamamen devreye girdiği nokta"],"explanation":"Düşük hava basıncı uyarısı, güvenle durmaya yetecek hava kalmışken erken uyarı vermek için basınç 60 psi'nin altına düşmeden önce yanmalıdır."},"192":{"q":"Yol öncesi muayenemi yapıyorum ve kompresör hava basarken basınç göstergesinin yükselişini izliyorum. Yaklaşık 125 psi'de kompresör sisteme hava eklemeyi durduruyor ve basıncı orada tutuyor. Eğitmen, kompresörün hava basmasını az önce durduran regülatör ayarını adlandırmamı istiyor. Bu ayarı doğru şekilde adlandıran terim hangisidir?","options":["Devreye girme (cut-in) — kompresörün yaklaşık 100 psi'de tekrar hava basmaya başladığı ayar","Kapatma (shut-off) — motor yeniden çalıştırılana kadar kompresörü tamamen devre dışı bırakan ayar","Bekleme (stand-by) — park frenleri uygulandığında kompresörü boşta bekleten ayar","Devreden çıkma (cut-out) — regülatörün yaklaşık 125 psi'de kompresörün hava basmasını durdurduğu ayar"],"explanation":"Yaklaşık 125 psi'deki kesme (cut-out) ayarı, regülatörün kompresörün sisteme hava pompalamasını durdurduğu noktadır."},"193":{"q":"Yüklü bir katar ile uzun bir dağ yokuşundan aşağı iniyorum. Hızımı kontrol etmek için düşük bir vites seçiyorum; böylece motor ve şanzıman beni geri tutma işinin çoğunu yapıyor ve servis frenlerine yalnızca ara sıra hafifçe basıyorum. Tüm iniş boyunca frene basılı tutmaya kıyasla, hızı motor ve düşük vitesle tutmanın temel avantajı nedir?","options":["Servis frenleri serin kalır, böylece yokuş dibinde sert bir duruş gerekirse tam fren gücünü korurlar","Servis frenleri tam yeterince ısınır ve kampanaları daha iyi kavrayarak durma mesafemi kısaltır","Frenler yokuşta neredeyse hiç kullanılmadığı için hava kompresörü fazla basıncı daha hızlı oluşturur","Yay (park) frenleri yükü servis frenleriyle paylaşır ve aracı otomatik olarak yavaşlatır"],"explanation":"Düşük vites, motorun aracın enerjisini emmesini sağlar, servis frenlerini soğuk tutarak sert bir duruş için tam fren gücünü korur."},"194":{"q":"Hava frenli, yüklü bir kamyonla uzun ve dik bir yokuştan iniyorum ve araç güvenli hızımın üzerine çıkmaya başlıyor. Telsizdeki bir arkadaşım, hızımı tutmak için fren pedalına tekrar tekrar basıp bırakmamı söylüyor. Bu tür bir inişte bu tavsiyeye uymak neden tehlikelidir?","options":["Pedala tekrar tekrar basmak kompresörü aşırı ısıtır ve emniyet tahliye valfini 150 psi'de açtırır","Pedala tekrar tekrar basmak, havayı kompresörün yenileyebileceğinden daha hızlı boşaltır, böylece basınç düşerek frenlemeyi kaybedebilirsiniz","Pedala tekrar tekrar basmak, depolardaki suyu ve yağı dışarı iter ve fren hatlarını kirletir","Pedala tekrar tekrar basmak fazla hava biriktirir ve siz daha hareket halindeyken yaylı frenleri devreye sokar"],"explanation":"Uzun bir inişte frenleri sık sık pompalamak, kompresörün yenileyebileceğinden daha hızlı hava boşaltır, böylece basınç düşüp frenleme kaybedilebilir."},"195":{"q":"Birleşik aracımı 30 dakikalık mola için bir dinlenme alanına çektim. Kabinden uzaktayken aracı yerinde tutmak için römork el valfine uzanıp onu uyguluyorum. Bu, aracı sabitlemenin neden YANLIŞ yoludur?","options":["El valfi römorkun yaylı frenlerini devreye sokar; bunlar araç park hâlindeyken aşırı ısınıp kilitlenebilir","El valfi kırmızı sekizgen römork hava besleme düğmesini bırakır, böylece çekici kendiliğinden öne kayar","El valfi römork frenlerine yalnızca servis havası uygular; bu hava zamanla sızıp boşalabilir ve araç kayabilir","El valfi havayı yalnızca direksiyon aksına gönderir, böylece çeker aks ve römork tekerlekleri tamamen frensiz kalır"],"explanation":"Römork el valfi yalnızca servis havasını uygular; bu hava zamanla sızar ve aracın kaymasına izin verir, bu yüzden daima yaylı frenle park edin."},"196":{"q":"Tek çekicili bir araçta sefer öncesi kontrolüm sırasında hava sistemini yaklaşık 125 psi'ye kadar dolduruyorum, ardından motoru kapatıp frenleri bırakıyorum. Tekerlekleri zaten takozladım ve düşük hava uyarısı yanmıyor. Bu adımda motoru kapatmanın asıl AMACI nedir?","options":["Fren pedalına birkaç kez basıp hava basıncının hızla geri yükseldiğini doğrulayabilmem için","Yaylı (park) frenlerini otomatik olarak devreye sokup 20–45 psi aralığında oturduklarını doğrulamak için","Kompresör devreye girip daha fazla yağ ve su pompalamadan ıslak depoyu (su deposunu) boşaltılabilmem için","Kompresörün hava eklemesini durdurup basınç düşüşünü süreyle ölçerek kaçak oranını kontrol edebilmem için"],"explanation":"Motoru kapatmak kompresörün hava eklemesini durdurur, böylece basınç düşüşünü zamanlayıp kaçak oranını doğru ölçebilirsiniz."},"197":{"q":"Sefer öncesi kontrolümde eğitmenim, fren pedalına bastığımda fren balatalarını kampanalara karşı asıl neyin ittiğini açıklamamı istiyor. Motor çalışıyor ve sistem tamamen dolu. Frenlerimin bu işi yapmak için dayandığı depolanmış enerjinin biçimini hangi cevap doğru şekilde açıklar?","options":["Depolarda tutulan ve frenleri uygulamak için boşaltılan basınçlı hava","Bir otomobil freni gibi, ana silindir tarafından basınçlandırılan hidrolik sıvı","Aküden her tekerlekteki mıknatıslara gönderilen elektrik akımı","Yağlama sisteminden frenlere yönlendirilen motor yağı basıncı"],"explanation":"Havalı fren sistemi enerjiyi tanklarda sıkıştırılmış hava olarak depolar ve bu hava frenleri uygulamak için bırakılır."},"198":{"q":"Sefer öncesi kontrolümde motoru çalıştırıp gösterge panelindeki manometreyi izliyorum. Çift devreli hava sistemim, gereken 45 saniyede 85'ten 100 psi'ye çıkması gerekirken çok daha uzun sürüyor ve basınç ağır ağır yükseliyor. Aşağıdakilerden hangisi bu yavaş basınç oluşumunun EN olası nedenidir?","options":["Düşük hava basıncı uyarı zili 60 psi'nin altında, çok erken çalıyor","Arızalı bir hava kompresörü veya sistemde bir yerde hava kaçağı","Regülatör kesme ayarı çok yüksek, 150 psi'lik emniyet supabı ayarına yakın","Fren ayarlayıcılarında (slack adjuster) aşırı itme çubuğu hareketi ve boşluk var"],"explanation":"45 saniyede 85-100 psi'ye ulaşamayacak kadar yavaş yükselen hava basıncı, arızalı bir kompresörü veya sistemdeki bir kaçağı gösterir."},"199":{"q":"Yola çıkış öncesi kontrolümde, motor çalışırken ve kompresör hava basarken besleme (ıslak) deposundaki emniyet (tahliye) valfinden yüksek sesle hava kaçtığını duyuyorum. Aşağıdakilerden hangisine karşı bu valf depoları korumak için özel olarak tasarlanmıştır?","options":["Basınç 60 psi'nin altına düşmeden önce düşük hava basıncı uyarısının yanmamasına karşı","Basınç yaklaşık 100 psi'ye düştüğünde regülatörün (governor) kompresörü tekrar devreye sokmamasına karşı","Sistemdeki hava basıncının çok yükselmesine karşı; valf yaklaşık 150 psi'de açılacak şekilde ayarlıdır","Kompresörün basıncı 45 saniye içinde 85'ten 100 psi'ye çıkaramamasına karşı"],"explanation":"Besleme deposundaki emniyet (basınç boşaltma) valfi, sistemi aşırı hava basıncından korumak için yaklaşık 150 psi'de açılır."},"200":{"q":"Hidrolik frenli kişisel kamyonetimden, havalı fren sistemine sahip bir B Sınıfı kamyona geçiş yapıyorum. Sefer öncesi kontrol sırasında, gerçek durdurma kuvvetinin her tekerlekteki frenlere nasıl ulaştığı konusundaki temel farkı anlamaya çalışıyorum. Hangi ifade, havalı frenli aracımda frenleri uygulayan kuvveti fiziksel olarak neyin ilettiğini doğru şekilde tanımlar?","options":["Ana silindirdeki hidrolik sıvı daha da basınçlandırılır, ardından pabuçları sıkıştırmak için fren haznelerine yönlendirilir","Motor yağı basıncı yükselir ve ayar kollarını kampanalara bastırmak için fren hatlarından geçirilir","Fren pedalından gelen elektrik sinyali, her tekerlekteki mıknatısları besleyerek fren pabuçlarını dışarı doğru çeker","Depolarda saklanan ve pedalla serbest bırakılan basınçlı hava, hatlardan geçerek fren haznelerinde kuvvet uygular"],"explanation":"Hava frenleri, depolarda biriken basınçlı havayı kullanır; pedalla bırakılan hava hatlardan fren odacıklarına giderek fren kuvveti uygular."},"201":{"q":"Hidrolik frenli bir kamyonetten, havalı frenli bir çekici-römork kombinasyonuna yeni geçtim. Fren pedalına ilk kez sertçe bastığımda, kamyonun ayağım hareket eder etmez yavaşlamaya başlamadığını, eski kamyonetimde olduğu gibi olmadığını fark ediyorum. Havalı frenler ile hidrolik frenler arasındaki bu farkı EN İYİ açıklayan ifade hangisidir?","options":["Havalı frenlerde yaklaşık yarım saniyelik yerleşik bir gecikme vardır, çünkü frenler devreye girmeden önce havanın hatlar boyunca ilerlemesi gerekir.","Havalı frenler, sistem 125 psi'lik regülatör kesme basıncına ulaşana kadar hiç durdurma gücü vermez.","Havalı frenler hidrolikler gibi anında tepki verir, bu yüzden hissettiğim gecikme sadece ayarı bozulmuş aşınmış fren ayarlayıcılarından kaynaklanıyordu.","Havalı frenlerde pedal geri bildirimi yoktur, bu yüzden hissedemesem de yavaşlama aslında hemen başlamıştı."],"explanation":"Hava frenlerinde yaklaşık yarım saniyelik gecikme vardır çünkü hava, frenler devreye girmeden önce hatlardan geçmek zorundadır."},"203":{"q":"Teksas'ta kırsal bir otoyolda yük taşırken düşük hava basıncı uyarı ışığı yanıyor ve uyarı sesi çalmaya başlıyor. Yaklaşık 19 km ileride, bir tamircinin görevde olduğunu bildiğiniz bir kamyon durağı var. Aşağıdakilerden biri DIŞINDA tüm eylemler bu uyarıya verilen güvensiz tepkilerdir. Doğru olan davranış hangisidir?","options":["Otoyol hızını koruyup, tamircinin sistemi incelemesi için 19 km ileride kamyon durağına kadar devam etmek","Yumuşakça frene basıp hızı düşürmek ve aracı en kısa sürede güvenli bir şekilde yoldan çıkarıp durdurmak","Depolardaki basıncı yeniden oluşturmak için fren pedalına tekrar tekrar basıp normal şekilde sürmeye devam etmek","Yola devam ederek şimdi park freni düğmesini çekmek, böylece yay frenleri daha sonra durmana yardımcı olur"],"explanation":"Düşük hava uyarısı yandığında, yavaşça frenleyin ve yay frenleri otomatik devreye girmeden aracı güvenle yoldan çekip durdurun."},"204":{"q":"Havalı frenli düz kamyonunuzla kırmızı ışıkta duruyorsunuz. Düşük hava uyarı ışığı ve sesli uyarı açık ve gösterge basıncın normal çalışma aralığının çok altına düştüğünü gösteriyor. Işık yeşile dönüyor ve arkanızdakiler korna çalmaya başlıyor. Doğru davranış nedir?","options":["Kavşaktan yavaşça ileri geçin, çünkü yaylı frenler ancak 20 psi'de kilitlenir ve siz hâlâ bunun üzerindesiniz","Tekerlekleri döndürecek kadar havanız varken hızlıca banket şeridine geçin","Durduğunuz yerde kalın ve hava basıncı normal aralığa geri yükselene kadar kamyonu hareket ettirmeyin","Hareket etmeden önce kompresörün depoları daha hızlı doldurmasına yardımcı olmak için fren pedalına birkaç kez hafifçe basın"],"explanation":"Yanan düşük hava uyarısı, frenlemenin artık güvenilir olmadığı anlamına gelir; bu yüzden hava basıncı normale dönene kadar durmuş kalın."},"205":{"q":"Yüklü bir kombinasyon aracı uzun ve dik bir yokuştan aşağı sürüyorum ve yarı yolda fren pedalının yumuşadığını ve bastığımda kamyonun neredeyse hiç yavaşlamadığını fark ediyorum. Frenlerim açıkça zayıflıyor (fade). Aşağıdakilerden hangisi yapmam gereken EN İYİ hareket?","options":["Kaybettiğim fren gücünü telafi etmek için fren pedalına daha sert basıp yokuşun en altına kadar sabit basınç uygulamak","Pedal hissini yeniden oluşturmak ve kaybettiğim durdurma gücünü geri kazanmak için fren pedalını hızlıca pompalamak","Motorun serbestçe dönmesi ve kamyonun yokuşun altına kadar düzgünce yuvarlanması için daha yüksek bir vitese geçmek","Motor freni için daha düşük bir vitese geçmek ve kenara çekip kamyonu durdurmak için en yakın güvenli yeri bulmak"],"explanation":"Uzun bir inişte hava frenleri zayıflamaya başlarsa, motor freni için daha düşük vitese geçin ve durmak için en yakın güvenli yerde yoldan çekilin."},"206":{"q":"Yüklü çekici-römork aracımı hafif bir eğime park ettim ve sarı düğmeyle park frenini çektim. Ben evrak işlerini yaparken motor kapalı ve depolardaki hava basıncı yavaşça 45 psi'nin altına, sıfıra doğru düşüyor. Aracımın kaçmasını gerçekte ne engelliyor ve hava boşalırken bile neden tutuyor?","options":["Fren körüklerindeki güçlü yaylar frenleri mekanik olarak sıkıştırır, böylece hava boşalsa da tutma kuvveti devam eder","Fren körüklerinin içinde basınç altında hapsolan hava, pabuçları kampanalara bastırarak tutar","Motor ve şanzıman, kapatıldıktan sonra kompresyon yoluyla tekerlekleri tutar","Sarı düğme, pedal kuvvetini korumak için ayak valfi bağlantısını mekanik olarak basılı kilitler"],"explanation":"Park ve acil durum frenleri, yay fren odacıklarındaki güçlü yaylarla kapalı tutulur; bu yüzden hava boşalsa bile tutmaya devam ederler."},"207":{"q":"Otoyolda ilerliyorum, hava sistemim normal çalışma basıncında tam dolu ve yaylı frenlerin sürtmediğini ya da devreye girmediğini hissediyorum. Bu durumda tutma basıncının (hold-off) rolünü hangi ifade doğru açıklar?","options":["Tutma basıncı, pedala bastığımda daha hızlı tepki versinler diye yaylı frenleri kısmen sıkışık tutuyor.","Tutma basıncı, ben sürerken yaylı frenleri serbest bırakılmış halde tutuyor; bu yüzden hava çok düşene kadar devre dışı kalıyorlar.","Tutma basıncı, servis frenlerimi desteklemek için yaylı frenleri her zaman tam uygulanmış halde tutuyor.","Tutma basıncı odacıklardan tamamen kaldırıldı; yaylı frenlerin kapalı hissettirmesinin nedeni budur."],"explanation":"Tutma (hold-off) hava basıncı yayları sıkıştırarak sürüş sırasında yay frenlerini açık tutar; frenler ancak hava çok düşerse devreye girer."},"208":{"q":"Vardiyamın sonunda aracımı park ediyorum, motoru kapatıyorum ve hava boşalırken yay frenlerinin tekerlekleri kilitlediğini hissediyorum. Bir stajyer, kamyonu tutmak için hava sisteminin hangi fren işlevine güvendiğimi soruyor. Hangi yanıt doğrudur?","options":["Servis fren işlevi, çünkü motor kapatıldığında park edilmiş aracı tutan şey ayak pedalıdır","Modülasyon işlevi, çünkü yay frenleri hava basıncı 60 psi'nin altına düştüğünde kademeli olarak devreye girer","Park/acil durum işlevi, çünkü yay frenleri hava basıncı kaybolduğunda aracı tutmak için otomatik olarak devreye girer","Düşük hava uyarı işlevi, çünkü tekerlekleri fiziksel olarak sıkan şey zil ve ışıktır"],"explanation":"Yay frenleri, hava basıncı kaybolduğunda aracı tutmak için otomatik devreye girer; bu, park/acil durum işlevidir."},"210":{"q":"Sefer öncesi kontrolüm sırasında kaputu açıyorum ve hava kompresörümün motora doğrudan bağlı olmak yerine bir kayışla tahrik edildiğini fark ediyorum. Kayışla tahrik edildiği için, dişli tahrikli bir kompresörde kontrol etmem GEREKMEYECEK olan hangi ek unsuru özellikle incelemem gerekir?","options":["Regülatör kesme basıncının göstergede yaklaşık 125 psi gösterdiğini","Hava depolarındaki su ve kompresör yağının boşaltıldığını","Düşük hava basıncı uyarı ışığının 60 psi'nin altına düşmeden yandığını","Tahrik kayışının uygun şekilde gergin olduğunu ve aşınma belirtisi göstermediğini"],"explanation":"Kayışla çalışan kompresörde tahrik kayışının doğru gerginlikte ve aşınmamış olduğunu kontrol edin; dişliyle çalışanda kayış yoktur."},"211":{"q":"Sefer öncesi kontrolümde, römorkun altındaki hava deposunun montaj braketine artık sıkıca tutturulmadığını ve üzerine bastırdığımda oynadığını fark ediyorum. Bu gevşek depo, sürmeden önce gidermem gereken bir kusur olmasının nedeni nedir?","options":["Depo aracın parçalarına sürtebilir veya gevşeyip kamyondan düşebilir","Depo kompresörden fazladan hava çeker ve regülatörün erken kesmesine yol açar","Depo daha az sıkıştırılmış hava tutar, böylece düşük hava basıncı uyarım daha erken çalar","Depo suyu ve yağı kendiliğinden boşaltır, böylece her gün boşaltacak bir şey kalmaz"],"explanation":"Gevşek bir hava tankı titreşip aracın parçalarına sürtebilir ya da yerinden çıkıp kamyondan düşebilir."},"212":{"q":"Havalı frenli tek parça kamyonunuzu bir yakıt adasındaki düz, asfalt zemine çektiniz ve motoru kapattınız. Göstergeler tam sistem basıncını gösteriyor ve yakıt almaya başlamak için kabinden inmek üzeresiniz. Kabinden ayrılmadan önce hangi işlemi mutlaka tamamlamalısınız?","options":["Kamyonu en düşük ileri vitesinde bırakıp tutması için motor kompresyonuna güvenmek","Sarı, elmas şeklindeki düğmeyi dışarı çekerek park (yay) frenlerini devreye almak","Servis fren pedalına ayağınızla sürekli ve sağlam basınç uygulayarak kamyonu tutmak","Kırmızı, sekizgen şeklindeki düğmeyi dışarı çekerek römork hava besleme hattını kilitlemek"],"explanation":"Kabinden çıkmadan önce sarı elmas şeklindeki düğmeyi çekerek park (yay) frenlerini daima devreye alın."},"213":{"q":"Yeni bir sürücüyüm ve iki ikinci el kamyon arasında karar veriyorum: azami brüt ağırlığına yakın yük taşıyabilen ağır bir çekici-römork ve hafif bir dağıtım minibüsü. Bir tamirci, büyük kamyonun havalı fren, minibüsün ise hidrolik fren kullandığını söylüyor. Ağır ticari araçların en başta neden havalı frenle üretildiğini anlamak istiyorum. Hangi ifade, havalı frenlerin büyük ve ağır yüklü kamyonlar için neden standart tercih olduğunu EN İYİ şekilde açıklar?","options":["Havalı frenler kamyonun toplam durma mesafesini kısaltır, böylece tam yüklü bir çekici hidrolik frenlere göre daha kısa mesafede durabilir","Havalı frenler esas olarak kurulumu en ucuz fren sistemi oldukları ve depolarının hiçbir zaman boşaltılması veya bakımı gerekmediği için seçilir","Havalı frenler sabit miktarda sıvı yerine basınçlı hava kullanır, bu yüzden ağır yük taşıyan büyük araçlarda bile etkili bir şekilde çalışmaya devam eder","Havalı frenler fren gecikmesini tamamen ortadan kaldırır ve yüklü bir kamyonun pedala basıldığı anda, hatlarda hiç gecikme olmadan tepki vermesini sağlar"],"explanation":"Hava frenleri sabit miktarda sıvı yerine sürekli yenilenen basınçlı hava kullanır, bu yüzden ağır ve tam yüklü araçlarda etkili fren sağlar."},"214":{"q":"Bir eğimde park etmiş durumdayım ve hizmet freni pedalını HÂLÂ sertçe basılı tutarken sarı park freni düğmesini çekmeye (yaylı frenleri devreye sokmaya) karar veriyorum. Yanımdaki bir sürücü önce pedaldan ayağımı çekmem konusunda beni uyarıyor. Hizmet frenleri ile yaylı frenleri aynı anda sertçe uygulamak neden bir sorundur?","options":["Hiçbir zararı yoktur ve aslında bana ekstra tutma gücü verir, bu yüzden önce hizmet pedalından ayağı çekmek için bir neden yoktur","Düşük hava basıncı uyarısının 60 psi noktasının altında erken devreye girmesine neden olur ve besleme deposunu daha hızlı boşaltır","Çok miktarda hava tasarrufu sağlar çünkü birlikte uygulandığında her iki sistem de aynı depolanmış basıncı paylaşır","Frenleme kuvvetleri birleşip toplanır ve bu bileşik kuvvet fren bileşenlerine aşırı yük bindirip onlara hasar verebilir"],"explanation":"Yay frenleri devredeyken servis frenine sert basmak iki kuvvetin birleşmesine yol açar ve fren parçalarına zarar verebilecek aşırı yük bindirir."},"215":{"q":"Aracımı park ediyorum ve yaylı (park) frenleri devreye almak için sarı düğmeyi dışarı çekiyorum. Alışkanlıkla ayağım hâlâ fren pedalına sertçe basıyor, bu yüzden aynı anda aynı fren odacıklarına da hava basıncı gönderiliyor. Tamirci, belirli bir valf olmadan iki kuvvetin birlikte uygulanmasının birleşip frenlere zarar verebileceği konusunda beni uyardı. Bu birleşik, 'çift uygulama' kuvvetine karşı hangi valf koruma sağlar?","options":["Anti-kompaunding valfi; yaylı fren kuvveti ile hava uygulama kuvvetinin aynı frenler üzerinde toplanmasını önler","Modülasyon kontrol valfi; yaylı frenleri kademeli uygulamanızı sağlayarak iki kuvvetin asla çakışmamasını sağlar","Emniyet tahliye valfi; yaklaşık 150 psi'de açılarak çift uygulamanın yarattığı fazla basıncı boşaltır","Römork hava besleme valfi; her ikisi de uygulandığında arka frenlere havayı kesen kırmızı sekizgen düğme"],"explanation":"Anti-kompaund valfi, yay frenleri devredeyken hava uygulama basıncını boşaltır, böylece iki fren kuvveti toplanmaz."},"216":{"q":"Sefer öncesi muayenemde, bir çekici-römork üzerinde hava fren kontrollerini yapıyorum. Sistemdeki hava basıncı çok düştüğü anda (60 psi'nin altına inmeden önce) beni uyarması ZORUNLU olan cihazı doğrulamak istiyorum; böylece hâlâ fren gücüm varken durabileyim. Sistemin bu uyarıyı bana vermek için kullanması gereken özellik hangisidir?","options":["Yavaşça aşağı doğru inen hava basınç göstergesi; tüm yolculuk boyunca onu yakından izlemem beklenir","Basınç 60 psi'nin altına düşmeden önce devreye giren bir uyarı ışığı ve/veya bir korna (zil)","Beni fiziksel olarak durmaya zorlamak için otomatik olarak devreye giren yaylı (park) frenleri","Basınç çok düştüğünde yüksek bir tıslamayla hava boşaltan emniyet tahliye valfi"],"explanation":"Hava frenli bir araçta, basınç 60 psi'nin altına düşmeden önce devreye giren bir düşük hava basıncı uyarı ışığı ve genellikle bir zil bulunmalıdır."},"217":{"q":"Sistem tam dolduktan sonra bir kamyon durağında rölantide bekleyip hava basıncı göstergemi izliyorum. İbre sürekli döngü yapıyor: yükseliyor, regülatör kompresörü devre dışı bırakıyor, ibre yavaşça biraz düşüyor, sonra regülatör kompresörü tekrar devreye sokup basıncı yükseltiyor. Hava kompresörümün talebi karşıladığından emin olmak istiyorum. Hangi gösterge davranışı kompresörün işini yaptığını gösterir?","options":["Gösterge 150 psi'yi geçerek yükselmeye devam ediyor ve emniyet tahliye valfi havayı boşaltıyor, bu da kompresörün bol kapasite fazlası olduğunu kanıtlıyor","Gösterge yavaşça tamamen sıfıra kadar düşüyor, ardından kompresör tek bir hızlı hamlede sistemi yeniden dolduruyor","İbre normal çalışma aralığında kalır, basınç kullanılıp yeniden sağlandıkça regülatörün devreye girme ve çıkma noktaları arasında döngü yapar","Gösterge tek bir sabit psi değerinde kıpırdamadan duruyor ve hiç hareket etmiyor, bu da regülatörün sistem basıncını yerinde kilitlediğini gösteriyor"],"explanation":"Çalışan bir kompresör basıncı normal aralıkta tutar; hava kullanılıp yenilendikçe regülatörün kesme (yaklaşık 125 psi) ve devreye girme (yaklaşık 100 psi) noktaları arasında döngü yapar."},"219":{"q":"Tek bir çekicide sefer öncesi kontrolümü yapıyorum ve hava basıncı oluşturmak için motoru rölantide bırakıyorum. Yola çıkmadan önce sistemin tam dolu olmasını istiyorum, bu yüzden gösterge panelindeki manometreyi izliyorum ve kompresör regülatörünün devreyi kesip hava pompalamayı durdurmasını bekliyorum. Bunun yaklaşık hangi basınçta gerçekleşmesini beklemeliyim?","options":["Yaklaşık 100 psi — regülatörün devreye girip tekrar hava pompalamaya başladığı nokta","Yaklaşık 60 psi — düşük hava basıncı uyarı ışığının ve uyarı sesinin kapandığı nokta","Yaklaşık 150 psi — emniyet supabının açılıp fazla havayı boşalttığı nokta","Yaklaşık 125 psi — regülatörün devreyi kestiği ve kompresörün pompalamayı durdurduğu nokta"],"explanation":"Tam dolu bir sistem, kompresörün hava pompalamayı durdurduğu regülatör kesme basıncında, yaklaşık 125 psi'de bulunur."},"220":{"q":"Bir kombine araç kullanırken römorkunuz aniden çekiciden kopuyor ve hava besleme hattı kopararak römork fren sisteminin tüm havasını boşaltıyor. Kontrolden çıkan römorka ne olur?","options":["Hava basıncı düştükçe yaylı (acil) frenleri otomatik olarak devreye girer ve römorku yavaşlatıp durdurur","Servis frenleri yalnızca siz çekicideki fren pedalına ayağınızı bastığınız sürece tutar","Hiç fren olmadan serbestçe kayar, çünkü havanın kaybı römorkun park frenlerini de serbest bırakır","Frenleri devreye sokmak için kırmızı römork hava besleme düğmesini çekene kadar ona hiçbir şey olmaz"],"explanation":"Yay frenleri hava basıncıyla açık tutulur; bu yüzden kopan bir römork havasını kaybettiğinde frenler otomatik devreye girip römorku durdurur."},"221":{"q":"Havalı fren sistemli, tek (römorksuz) düz bir kamyon kullanıyorsunuz ve büyük bir hat arızası sistemdeki tüm havayı dışarı boşaltıyor; basınç göstergeleri sıfıra düşüyor. Fren pedalına da el freni kumandasına da dokunmadınız. Kamyon ne yapar?","options":["Frensiz şekilde serbestçe kayar, çünkü havanın kaybı yay frenlerini de serbest bırakır ve siz yuvarlanmaya devam edersiniz.","Kendi kendine durur, çünkü hava basıncı yeterince düştüğünde yay frenleri otomatik olarak devreye girer.","Normal şekilde hareket etmeye devam eder ve siz yalnızca servis frenlerinizi kaybedersiniz, ama direksiyon ve el freni hâlâ çalışır.","Yalnızca güç desteğini kaybeder, bu yüzden frenler hâlâ çalışır ama pedala basmak çok daha zorlaşır."],"explanation":"Yay frenleri hava basıncıyla açık tutulduğu için havanın tamamen kaybı frenleri otomatik devreye sokar ve aracı durdurur."},"222":{"q":"Bir çekici-römork üzerinde sefer öncesi kontrolüm sırasında, ön frenlerden birinin ayar kolunun diğerlerinden daha fazla itme çubuğu hareketine sahip olduğunu fark ediyorum; böylece o fren daha az iş yaparken diğerleri daha fazla çalışıyor. Bir arkadaşım bunun pek önemli olmadığını söylüyor. Frenlerim ayarsız olduğunda ve fren işini artık eşit şekilde paylaşmadığında kaybettiğim EN önemli şey nedir?","options":["Daha iyi yakıt ekonomisi, çünkü eşit çalışan frenler motor sürtünmesini azaltır","Test sırasında hava basıncının 85'ten 100 psi'ye daha hızlı yükselmesi","İyi fren dengesi, böylece araç bir tarafa çekmeden düz şekilde durur","Uzun bir yokuşta vites küçültürken daha güçlü motor frenlemesi"],"explanation":"Tüm frenler doğru ayarlandığında ve yükü eşit paylaştığında, fren dengesi aracın bir tarafa çekmeden düz şekilde durmasını sağlar."},"223":{"q":"Çekici-römork aracımda sefer öncesi kontrol yapıyorum. Motor çalışıyor ve depolarda hava basıncı yükseliyor. Park frenlerini bırakıp sahadan çıkmadan önce, güvenli sürüş için sistemde bulunması gereken EN DÜŞÜK hava basıncı nedir?","options":["En az yaklaşık 60 psi, çünkü düşük hava basıncı uyarısının söndüğü nokta budur","En az yaklaşık 20 psi, çünkü yaylı frenlerin çözülüp aracın yuvarlanmasına izin verdiği nokta budur","En az yaklaşık 125 psi, çünkü regülatör kesme basıncına ulaşana kadar araç güvenli sürülemez","En az yaklaşık 100 psi, çünkü fren yapmak ve güvenli sürmek için gereken en düşük basınç budur"],"explanation":"Sürüşten önce en az yaklaşık 100 psi basınç oluşturmalısınız, çünkü güvenli fren yapmak ve sürmek için gereken minimum hava basıncı budur."},"224":{"q":"Günde birkaç kez yaptığım kısa 40 millik bir teslimat turunda aynı güvenilir çekici-römork ile araç kullanıyorum. Araç bu sabah tam hava freni muayenesini sorunsuz geçti ve öğle yemeğinden beri ona dokunmadım. Öğleden sonraki seferime başlamak için kabine tekrar binerken, hava frenlerini kontrol etmek için hangi yaklaşım doğrudur?","options":["Bu öğleden sonra seferinden önce, her seferde olduğu gibi hava freni kontrollerini yeniden yapmak","Bu sefer kontrolleri atlamak, çünkü bugün daha önce aynı araçta tam bir muayene zaten geçildi","Kontrolleri yalnızca sabah seferi sırasında düşük hava basıncı uyarı ışığı veya sesli uyarısı yandıysa tekrarlamak","Frenleri haftada bir kez veya yaklaşık her 1.000 mil sürüşten sonra yeniden kontrol etmek için beklemek"],"explanation":"Hava freni kontrolleri her seferden önce yapılmalıdır, çünkü fren durumu, hava kaçağı ve boşluk ayarı seferler arasında değişebilir."},"225":{"q":"Sefer öncesi kontrolümde, çekicimin fren ayar kollarındaki (slack adjuster) boşluğun olması gerekenden fazla olduğunu, yani frenlerin ayarsız olduğunu fark ediyorum. Bunu düzeltmeden yine de sürersem, yolda en çok ne olmasını beklemeliyim?","options":["Frenler aslında daha güçlü tutacak ve kamyonu daha kısa mesafede durduracak","Frenlerin gücü azalacak ve kamyon o kadar iyi durmayacak","Sistem havayı koruyacak, böylece kompresör çok daha seyrek devreye girecek","Fren balataları ve kampanaları zamanla çok daha yavaş aşınacak"],"explanation":"Ayarsız boşluk ayarlayıcılardan kaynaklanan aşırı itme çubuğu hareketi fren gücünü azaltır, bu yüzden kamyon iyi duramaz."},"226":{"q":"Sefer öncesi kontrolüm sırasında bir fren hortumunun şasi üzerindeki keskin bir braketе bastıracak şekilde döşendiğini ve metalle temas ettiği yerde dış yüzeyinin aşınmış olduğunu fark ediyorum. Bu bulgu hava frenli sistemim için neden önemlidir?","options":["Temas zamanla bağlantıyı sıkıştırır, bu yüzden aslında bir bağlantının gevşeme olasılığını azaltır","Sürtünme lastiği sertleştirir ve hortumun sistemin geri kalanından daha yüksek basınca dayanmasını sağlar","Sürekli sürtünme hortumu delinip arızalanana ve hava kaçırana kadar aşındırabilir","Frenler için hiçbir şey değişmez, ancak sürtünme yalnızca o noktada soğumayı hızlandırabilir"],"explanation":"Bir parçaya sürtünen fren hortumu, sürekli aşınmayla zamanla delinip hava sızdırana kadar yıpranır."},"227":{"q":"Sefer öncesi kontrolümde, tekli çekicim yaklaşık 125 psi'ye kadar tam dolu. Motoru kapatıyorum, frenleri bırakılmış halde bırakıyorum ve göstergeyi izliyorum. Basınç bir dakikada 2 psi'den fazla düşüyor ve hafif bir tıslama sesini, lastik diyaframında küçük bir yırtık bulunan bir fren haznesine kadar takip ediyorum. Bu yırtık diyafram hava sistemime ne yapıyor?","options":["İtme çubuğunu iten kuvveti artırıyor ve o tekerleğe fazladan fren gücü veriyor","Yalnızca frenler basılıyken önemlidir, bu yüzden frenler bırakılmışken gerçek bir etkisi yoktur","Duruş sırasında o tekerlekteki pabuçların kampanaya daha sıkı tutunmasına yardımcı oluyor","Sıkıştırılmış havanın kaçmasına izin veriyor, kaçak oranımın çok yüksek olmasının nedeni bu"],"explanation":"Yırtılmış fren körüğü diyaframı, fren yapmak yerine basınçlı havanın delikten kaçmasına yol açar ve kaçak oranını yükseltir."},"228":{"q":"Çekici-römork aracımın sefer öncesi kontrolünde hava kaçak oranı testten geçmiyor—motor kapalı ve frenler bırakılmış olsa bile basınç sınırdan çok daha hızlı düşüyor. Tam çekici ile römorkun hava hatlarının birleştiği noktada hafif bir tıslama sesi fark ediyorum. Duyduğum sesin ve başarısız kaçak testinin EN olası nedeni hangisidir?","options":["Aşınmış glad-hand (hortum bağlantı başlığı) contaları, çekici ile römork arasındaki bağlantı noktasında havanın kaçmasına izin veriyor","Bir fren ayar kolu (slack adjuster) ayarsız olduğu için fren haznelerinden birinde itme çubuğu aşırı hareket ediyor","Şarj sırasında depo basıncı 150 psi'yi aştığı için emniyet supabı açıldı","Regülatör kesme basıncına ulaşmadı, bu yüzden kompresör sisteme hava basmayı hiç durdurmadı"],"explanation":"Aşınmış gladhand contaları, çekici ve römork hava hatlarının birleştiği yerden hava kaçırarak tıslamaya ve aşırı kaçağa neden olur."},"229":{"q":"Çekiciyi yüklü bir römorka yeni bağladım ve hava hortumlarını taktım. Römorkun hava depoları hâlâ boş ve fren kontrollerini yapmadan önce fren sistemini doldurmak için römorka geri hava göndermem gerekiyor. Kabinde otururken römorka hava göndermek için hangi kumandayı kullanırım?","options":["Römorka basınç vermek için sarı, baklava şeklindeki düğmeyi dışarı çekerim","Römorka geri hava göndermek için kırmızı, sekizgen düğmeyi içeri iterim","Havayı hatlardan geçirmek için servis fren pedalına basıp basılı tutarım","Römorka hava besleme hattını açmak için kırmızı, sekizgen düğmeyi dışarı çekerim"],"explanation":"Kırmızı, sekiz kenarlı römork hava besleme düğmesini içeri itmek, çekiciden römorkun fren sistemini doldurmak için hava gönderir."},"230":{"q":"Bir römork çekerken sistemdeki bir kaçak, hava basıncımın römork hava besleme valfini açık tutmak için gereken seviyenin çok altına düşmesine neden oluyor. Gösterge panelinde hiçbir şeye dokunmadığımda, kırmızı sekizgen römork hava besleme düğmesinin ne yapmasını beklemeliyim?","options":["Yerinde basılı kalır, çünkü römork frenleri yalnızca ayak pedalına tepki verir","Yanıp bir uyarı sesi çıkarır ama ben elimle çekene kadar basılı kalır","Kendiliğinden dışarı fırlar ve kapanır, römorkun acil durum frenlerini otomatik olarak devreye sokar","Römorku yalıtmak ve kalan hava basıncını korumak için daha da içeri itilir"],"explanation":"Hava basıncı çok düşerse, kırmızı sekiz kenarlı düğme kendiliğinden dışarı fırlar ve kapanarak römorkun acil frenlerini otomatik olarak uygular."},"231":{"q":"Sefer öncesi kontrolüm sırasında tamircim, çekicimin bir aksına diğerlerinden daha büyük fren körükleri takıldığını söylüyor ve yanımdaki acemi bir öğrenci, fren pedalına bastığımda bunun ne fark yarattığını soruyor. Daha küçük körüklere kıyasla, o aksdaki daha büyük fren körüğü gerçekte ne sağlar?","options":["Pedal hissini yumuşatır, çünkü büyük körük itme çubuğu hareket etmeden önce daha fazla hava tutar","Fren gücünü azaltır, çünkü büyük körük hava basıncını ayar kolundan kaçırır","Frenlemede hiçbir değişiklik yaratmaz, çünkü körük boyutu yalnızca havanın ne kadar hızlı dolduğunu etkiler","Daha fazla fren gücü sağlar, çünkü büyük körük ayar koluna daha büyük bir kuvvetle baskı yapar"],"explanation":"Daha büyük bir fren körüğü, havanın etki edeceği daha geniş bir yüzeye sahiptir ve boşluk ayarlayıcıyı daha büyük kuvvetle iterek daha fazla fren gücü sağlar."},"232":{"q":"Sefer öncesi kontrolde fren pedalına basıp tahrik aksındaki S-kam (S-cam) kampanalı freninin döndüğünü izliyorum. S-kam dönerken, tekerleği yavaşlatmak için o fren grubunun içinde gerçekte ne yapıyor?","options":["Fren pabuçlarını dışarı doğru iterek balatalarının fren kampanasının iç yüzeyine bastırmasını sağlar","Fren pabuçlarını içeri, kampanadan uzağa çeker, böylece geri dönüş yayları onları serbest bırakabilir","Frenleme başlamadan önce itme çubuğundaki boşluğu almak için fren ayar kolunu (slack adjuster) döndürür","Fren körüğünden havayı boşaltarak yay frenlerinin kampanaya karşı devreye girmesini sağlar"],"explanation":"Dönen S-kam, fren pabuçlarının arasına girerek onları dışa doğru iter ve balataların dönen fren kampanasının iç yüzeyine bastırarak tekerleği yavaşlatır."},"233":{"q":"Sefer öncesi kontrolümde, daha yaygın olan kampana tipi yerine havalı disk frenlerle donatılmış bir çekicinin temel frenlerini inceliyorum. Tekerlek grubuna baktığımda, kaliperin tekerleği yavaşlatmak için sıktığı düz, dönen metal bir parçayı kavradığını görüyorum. Bu havalı disk fren sistemini kontrolümde doğru tanımlamak için, kaliperin sıkıştırdığı parça şudur:","options":["Pabuçların dışa doğru bastırdığı fren kampanası (tambur)","Kaliperin sürtünme oluşturmak için sıktığı rotor (disk)","Basıncı uygulayan yay (park) fren körüğü","İtme çubuğunun hareket ettiği fren ayarlayıcısı (slack adjuster)"],"explanation":"Havalı disk frenler, tekerlek göbeğine bağlı dönen bir rotora (diske) sürtünme balatalarını sıkıştıran bir kaliper kullanarak tekerleği yavaşlatan sürtünmeyi oluşturur."},"234":{"q":"Sefer öncesi kontrolde, bir tamirci kamyonumdaki büyük bir fren körüğünü göstererek ona 'maxi' körük diyor ve bunun, küçük körüğün yaptığı gibi tekerleği durdurmak için itme çubuğunu dışarı itmek amacıyla hava basıncı KULLANMADIĞINI söylüyor. Bu parçanın gerçekte nasıl çalıştığına göre, 'maxi' körük nedir?","options":["Servis frenidir, çünkü 'maxi' körük, normal sürüş sırasında ayak pedalına her bastığımda frenleme kuvveti uygulayan parçadır","Modülasyonlu kontrol valfidir, çünkü 'maxi' körük, acil durumda arka aksa kademeli olarak basınç uygulamamı sağlayan parçadır","Yaylı frendir, çünkü 'maxi' körük, hava basıncı bırakıldığında veya kaybedildiğinde frenleri devreye sokan güçlü bir yay barındırır","Römork hava besleme ünitesidir, çünkü 'maxi' körük, sürüş sırasında römorkun tanklarına hava besleyip dolduran parçadır"],"explanation":"Maxi (yaylı fren) hazne, basınçlı havayla çubuğu itmek yerine, hava basıncı boşaldığında veya kaybolduğunda frenleri uygulayan güçlü bir sıkıştırılmış yay içerir."},"235":{"q":"Yükleme rampasında park halindeyim, kamyonum yaklaşık 125 psi'ye kadar tamamen havalandı ve hiç kaçak yok. Hava basıncının 20-45 psi aralığına düşmesi DIŞINDA, yay frenlerimi devreye sokmanın DİĞER yolu nedir?","options":["Servis fren pedalına basıp tabana kadar sonuna kadar basılı tutarak","Kilitlenmeyi önleyici fren sistemi (ABS) uyarı düğmesini açarak","Motoru yükselterek regülatörün 125 psi'de kesme noktasına ulaşmasını sağlayarak","Sarı, elmas şeklindeki park freni kumanda düğmesini çekerek"],"explanation":"Yaylı frenler, sarı elmas şeklindeki park freni kumanda düğmesi çekilerek elle uygulanır."},"236":{"q":"Panhandle bölgesinde dondurucu bir kış sabahı ve çekici-römork aracımın havalı fren sisteminde bir alkol buharlaştırıcı (alcohol evaporator) bulunuyor. Sefer öncesi kontrolümü yapıp yola çıkarken, bu cihazın bu soğuk havada benim için yaptığı ANA iş nedir?","options":["Hava sistemine alkol katarak buz oluşmasını ve havalı fren hatları ile valflerin tıkanmasını önlemek","Fren kampanalarını ve balatalarını sıcak tutarak servis frenlerinin durdurma gücünü kaybetmesini engellemek","Depolardaki suyu ve kompresör yağını alarak artık her gün boşaltma (drenaj) yapmama gerek bırakmamak","Regülatör kesme basıncını yükselterek kompresörün soğukta havayı daha hızlı basmasını sağlamak"],"explanation":"Alkol buharlaştırıcı, hava sistemine alkol ekleyerek nemin donma noktasını düşürür ve soğukta buzun oluşup fren hatlarını ve valfleri tıkamasını önler."},"238":{"q":"Sefer öncesi kontrolümde motoru çalışır halde bırakıp hava göstergesinin yükselişini izliyorum. Basınç yaklaşık 125 psi'ye ulaşıyor ve motor çalışmaya devam etse de ibre yükselmeyi durduruyor. Regülatör (governor) cut-out (kesme) ayarına yeni ulaştı. Kompresörün kendisi tam bu anda ne yapıyor?","options":["Motorla birlikte tamamen kapandı ve ancak basınç yaklaşık 60 psi'ye düştüğünde yeniden çalışacak","Dönmeye devam ediyor ama tanklara hava pompalamayı durduruyor (yüksüz duruma geçti); basınç yaklaşık 100 psi'ye düşene kadar böyle kalır","Basıncı 150 psi'lik emniyet supabı ayarına doğru itmek için daha da güçlü pompalıyor","Kilitleniyor ve tankları korumak için fazla havayı emniyet supabından dışarı boşaltıyor"],"explanation":"Regülatör kesme noktasında (yaklaşık 125 psi) kompresör dönmeye devam eder ama yük boşaltır, basınç yaklaşık 100 psi devreye girme noktasına düşene kadar tanklara hava basmayı durdurur."},"239":{"q":"Römorkumu sahaya bıraktım ve çekiciyi römorksuz (bobtail) olarak terminale geri sürüyorum. Eve giden yolda uzun düz bir kesim, içinden kestirme geçtiğim açık çakıllı bir alan, birkaç otoyol giriş rampası ve çıkışa yakın geniş bir viraj var. Römorksuz bir çekici kötü yol tuttuğu için EN çok nerede yavaşlamaya dikkat etmeliyim?","options":["Uzun düz kesimde, çünkü daha hafif araç normalden daha hızlı gitmeme izin verir","Açık çakıllı alanda, çünkü gevşek zemin bir bobtail'in tutuş kaybettiği tek yerdir","Virajlarda ve giriş rampalarında, çünkü römorksuz çekici (bobtail) kötü yol tutabilir","Hiçbir yerde özellikle değil, çünkü römorksuz bir bobtail daha iyi frenler ve viraj alır"],"explanation":"Bobtail (römorksuz) çekicide tahrik akslarının üzerinde römork ağırlığı bulunmadığından kötü yol tutar, bu yüzden kuvvetlerin en yüksek olduğu virajlarda ve giriş rampalarında fazladan yavaşlayın."},"240":{"q":"Otoparkta bir çekici-römork üzerinde sefer öncesi kontrolümü tamamlıyorum. Hava depolarını boşalttım, regülatörün yaklaşık 125 psi'de devreyi kestiğini doğruladım ve düşük hava basıncı uyarısının 60 psi'nin altına düşmeden önce yandığını teyit ettim. Yola çıkmadan önce, aracımın arkasındaki lambalarla ilgili hâlâ yapmam gereken şey aşağıdakilerden hangisidir?","options":["Diğer sürücülerin geceleri görebilmesi için arka reflektörlerin yeni boyandığını doğrulamak","Ampulleri yol döküntülerinden korumak için arka lamba muhafazalarının kapatıldığını doğrulamak","Elektrik yükünü azaltmak için arka işaret lambalarının söküldüğünü doğrulamak","Fren pedalına bastığımda fren lambalarının gerçekten yandığını doğrulamak"],"explanation":"Yola çıkış öncesi muayenede, fren pedalına basıldığında fren lambalarının gerçekten yandığı doğrulanmalıdır; böylece arkadaki sürücüler yavaşladığınızı veya durduğunuzu görür."},"241":{"q":"Sefer öncesi yaklaşık 5 mil/saat hızda yaptığım fren durma testinde fren pedalına basıyorum ve kamyon sertçe sağa savruluyor, durmadan önce pedal düzensiz şekilde tutuyor. Hangi sonuç doğrudur?","options":["Frenler arızalıdır ve araç sürülmeden önce servise ihtiyaç duyar","Bu normal fren gecikmesi davranışıdır, bırakıp yola devam edebilirim","Hava basıncı çok yüksektir, depoları boşaltıp testi tekrarlamalıyım","ABS bir tekeri tutarak görevini yapıyor, bu yüzden işlem gerekmez"],"explanation":"5 mil/saat fren testinde, bir tarafa çeken veya düzensiz tutan frenler arızalıdır ve araç servise alınıp onarılana kadar kullanılmamalıdır."},"242":{"q":"Sefer öncesi kontrolümde, her tekerlekteki temel fren (foundation brake) bileşenlerini denetlemek için römorkun altına giriyorum. Fren kampanalarının ve fren balatalarının iyi durumda olduğunu zaten doğruladım. Temel fren bileşenlerinin kendisini denetlemeyi tamamlamak için bir sonraki hangi parçayı kontrol etmeliyim?","options":["Kabindeki sarı, baklava şeklindeki park freni düğmesini","Her fren körüğünün itme çubuğuna bağlı boşluk ayarlayıcıları (slack adjusters)","Kompresörün devreye girme ve çıkmasını kontrol eden regülatörü (governor)","Besleme (ıslak) deposuna takılı emniyet tahliye valfini"],"explanation":"Fren ayar kolları (slack adjuster), her fren haznesinin itme çubuğunu fren mekanizmasına bağlayarak çubuğun hareketini tekerlekteki fren kuvvetine dönüştürür."},"243":{"q":"Sefer öncesi kontrolümde çekici ile römorkun glad hand (hava hattı bağlantı başlıkları) parçalarını birleştiriyorum, hava sistemini yaklaşık 125 psi'ye dolduruyorum ve motoru kapatıyorum. Bağlantı noktasına eğildiğimde, glad hand bağlantılarından birinden gelen sürekli bir tıslama sesini açıkça duyuyorum. Bu tıslama o bağlantı hakkında BÜYÜK OLASILIKLA neyi gösterir?","options":["Conta tamamen hava sızdırmazdır ve bağlantı testi geçmiştir","Römork frenlerini güçlendirmek için fazladan hava basıncı yönlendiriliyor","Bir kaçak nedeniyle bağlantıdan hava dışarı çıkıyor","Besleme hattı az önce içinde biriken suyu boşaltmayı bitirdi"],"explanation":"Glad hand bağlantısındaki sürekli tıslama, basınçlı havanın contadaki bir kaçaktan dışarı çıktığı anlamına gelir."},"244":{"q":"Çalışan bir ABS (kilitlenmeyi önleyici fren) sistemine sahip bir çekici-römork kullanırken, önümdeki bir otomobil şeridimde aniden duruyor. Aracı kontrol altında tutarken mümkün olduğunca sert durmam gerekiyor. Bu acil durumda frenleri doğru kullanma şekli nedir?","options":["ABS'nin uygulamalar arasında tepki vermeye zamanı olması için fren pedalına hızlıca basıp bırakarak pompalamak","Sert bas, pedalın titreşimini hisseder hissetmez bırak ve bunu kısa aralıklarla tekrarla","ABS'yi devreye sokmak için pedala bir kez dokun, sonra daha fazla fren yapmadan tehlikenin etrafından direksiyon çevirerek geç","Pedala sert bas ve sabit basınç uygulamaya devam et; ABS tekerleklerin kilitlenmesini önlesin ki direksiyon hakimiyetini koruyabileyim"],"explanation":"ABS varken fren pedalına sıkıca basıp sabit basınç uygulayın; böylece sistem tekerlek kilitlenmesini önler ve direksiyon kontrolünüz korunur."},"245":{"q":"Dondurucu bir kış sabahı ve hava frenli bir çekici-römork üzerinde yola çıkış öncesi kontrolümü yapıyorum. Son birkaç gündür hava tanklarını boşaltmayı unuttuğumu fark ediyorum ve boşaltma valflerinin etrafında nem görüyorum. Bu, fren sistemi için neden önemli?","options":["Tanklarda biriken su ve kompresör yağı fren sistemine zarar verebilir ve soğuk havada donabilir, bu yüzden tanklar her gün boşaltılmalıdır","Tanklardaki az miktarda su ve yağ aslında fren valflerini yağlayıp sızdırmazlık sağlar, bu yüzden ara sıra boşaltmayı atlamak zararsızdır","Su ve yağın frenlemeye etkisi yoktur çünkü emniyet tahliye valfi bunları yaklaşık 150 psi'de otomatik olarak dışarı atar","Nem yalnızca park frenleri için önemlidir, bu yüzden servis frenleri tuttuğu sürece tankları boşaltmayı ilkbahara kadar güvenle erteleyebilirim"],"explanation":"Hava depoları her gün boşaltılmalıdır çünkü içlerinde su ve kompresör yağı birikir; bu, fren sistemine zarar verebilir veya soğukta donabilir."},"246":{"q":"Dondurucu bir sabahta, sefer öncesi kontrol sırasında gece boyunca besleme (ıslak) deposunda su ve biraz yağlı çamur biriktiğini fark ediyorsunuz. Bu kirlilik donup sisteme zarar vermeden önce onu boşaltmak için o depo üzerindeki hangi cihazı kullanırsınız?","options":["Emniyet tahliye valfini, depoyu havalandırmak için elle açarak","Deponun altındaki boşaltma valfi (petcock)","Regülatörü, birikimi salmak için kesime alarak","Hattı temizlemek için düşük hava uyarı zilini sıfırlayarak"],"explanation":"Su ve yağ, hava deposunun altındaki tahliye valfi (petcock) açılarak boşaltılır."},"247":{"q":"Sefer öncesi kontrolde hava sistemini tam basınca kadar dolduruyorum. Birden besleme (ıslak) deposundaki emniyet tahliye valfinden yüksek sesli bir hava boşalması duyuyorum. Sürmeden önce bu büyük olasılıkla sistemim hakkında bana neyi gösterir?","options":["Düşük hava basıncı uyarısı arızalandı ve depo basıncı sessizce 60 psi'nin altına düştü.","Regülatör (governor) erken devreye girdi ve kompresör depolara hava göndermeyi durdurdu.","Regülatör (governor) kesmeyi yapamadı, basınç yaklaşık 150 psi'nin üzerine çıktı ve valf fazlasını boşalttı.","Yavaş bir kaçak basıncı 20-45 psi aralığına düşürdü ve yaylı frenleri devreye soktu."],"explanation":"Regülatör (governor) kompresörü devre dışı bırakamazsa basınç yaklaşık 150 psi'yi aşar ve emniyet tahliye valfi açılarak fazla havayı dışarı atar."},"248":{"q":"Sefer öncesi kontrolümde, atölyedeki tamirci römork park hâlindeyken \"maksi frenlerin\" düzgün tutup tutmadığını gidip kontrol etmemi söylüyor. Bu argo terime aşina değilim. Havalı fren araçımdaki hangi bileşenden aslında bahsediyor?","options":["Normal duruşta ayak pedalıyla uyguladığım servis frenleri","Acil durumda frenleri kademeli uygulamak için kullandığım modüle edici valf","İtme çubuğunun ne kadar hareket ettiğini ayarlayan boşluk ayarlayıcılar","Aracı tutan ve hava basıncı kaybolduğunda devreye giren yaylı frenler"],"explanation":"Maxi-frenler, yaylı frenlerin başka bir adıdır; park edilmiş aracı tutar ve hava basıncı kaybedildiğinde otomatik olarak devreye girer."},"249":{"q":"Bir otomobilden, havalı (basınçlı hava) frenlerle donatılmış yüklü bir çekici-römork kombinasyonuna geçiyorum ve eğitmenim havalı fren sistemini iyi öğrenmenin bir CDL sürücüsü için neden en önemli olduğunu soruyor. Havalı frenleri öğrenmenin temel amacını en iyi hangi cevap özetler?","options":["Ağır, yüklü bir aracı güvenli ve kontrollü bir şekilde durdurmak için","Aracın serbestçe süzülmesini ve daha yüksek seyir hızlarına çıkmasını sağlamak için","Motor kompresörünü rölantide tutarak yakıt tüketimini azaltmak için","Hidrolik frenlere kıyasla toplam durma mesafesini kısaltmak için"],"explanation":"Havalı fren sisteminin temel amacı, ağır ve yüklü bir aracı güvenli ve kontrollü bir şekilde durdurmaktır."}},"es":{"0":{"q":"Durante mi inspección previaje, un examinador me pide que explique el sistema de frenos de aire de mi tractocamión. Le digo que los frenos de aire son en realidad varios sistemas de frenado combinados en uno. ¿Qué respuesta indica correctamente cuántos sistemas de frenado separados combina en realidad un sistema de frenos de aire, y los nombra?","options":["Tres sistemas: los frenos de servicio, los frenos de estacionamiento y los frenos de emergencia.","Dos sistemas: el sistema de aire primario y el secundario con un solo juego de controles.","Cuatro sistemas: los frenos de servicio, de estacionamiento, de emergencia y el ABS.","Un sistema: un solo circuito que maneja las paradas normales, el estacionamiento y las emergencias juntos."],"explanation":"Un sistema de frenos de aire es en realidad tres sistemas combinados: los frenos de servicio, los frenos de estacionamiento y los frenos de emergencia."},"1":{"q":"Estoy haciendo mi inspección previa al viaje y acelero el motor para acumular presión de aire mientras observo el manómetro del tablero. Quiero confirmar que el gobernador funciona correctamente anotando la presión a la cual el compresor de aire deja de bombear aire a los tanques. ¿Aproximadamente en qué lectura debería dejar de subir la aguja porque el gobernador ha cortado (cut-out)?","options":["Unos 100 psi, que es la presión a la cual el compresor deja de agregar aire a los tanques","Unos 125 psi, punto en el cual el gobernador corta (cut-out) y el compresor deja de bombear","Unos 150 psi, donde el sistema alcanza su máximo y el compresor se apaga","Unos 60 psi, el punto en el cual el gobernador detiene el compresor en un sistema cargado"],"explanation":"El gobernador corta a unas 125 psi, deteniendo que el compresor siga bombeando aire a los tanques."},"2":{"q":"Estoy estacionado haciendo mi inspección previaje y observando el manómetro de aire. El compresor se había apagado antes y dejó de bombear aire, así que la presión ha estado bajando lentamente mientras pruebo el sistema. ¿En qué lectura del manómetro debo esperar que el gobernador vuelva a activar el compresor y reanude el bombeo de aire?","options":["Unas 60 psi, el mismo punto en que se encienden la luz y el zumbador de advertencia de baja presión de aire","Unas 125 psi, el nivel en que el gobernador detiene el bombeo de aire del compresor","Unas 100 psi, el punto en que el gobernador le indica al compresor que reanude el bombeo","Unas 150 psi, el nivel en que la válvula de alivio de seguridad se abre para liberar presión"],"explanation":"El punto de activación del gobernador es de unas 100 psi, donde indica al compresor que reanude el bombeo de aire."},"3":{"q":"Durante mi inspección previaje, noto que el regulador (governor) del compresor de aire no corta — el manómetro sigue subiendo más allá del punto normal de 125 psi donde el bombeo debería detenerse. Si el regulador nunca corta, ¿a qué presión aproximada debería abrirse la válvula de alivio de seguridad para proteger el sistema de un exceso de presión?","options":["A unos 100 psi, el mismo punto donde el regulador normalmente arranca y reanuda el bombeo","A unos 60 psi, el mismo umbral que activa la luz y el zumbador de advertencia de baja presión de aire","A unos 125 psi, coincidiendo con el corte del regulador para que ambos dispositivos actúen juntos","A unos 150 psi, liberando el aire sobrante para evitar que el sistema alcance una presión peligrosa"],"explanation":"La válvula de alivio de seguridad se abre a unas 150 psi para liberar el aire excesivo y proteger el sistema de presión peligrosa."},"4":{"q":"Estoy haciendo una inspección previaje en un tractocamión sencillo con el sistema de aire totalmente cargado. Con el motor apagado, libero el aire paso a paso accionando el freno y observo el tablero. ¿En qué momento deben ya estar activos la luz y el zumbador de baja presión de aire, es decir, la advertencia debe estar ENCENDIDA antes de que la presión baje de qué nivel?","options":["Antes de que la presión de aire baje de 60 psi","Antes de que la presión de aire baje de 80 psi","Solo después de que la presión ya haya bajado al rango de 20 a 45 psi","Antes de que la presión de aire baje de 100 psi"],"explanation":"La advertencia de baja presión de aire debe activarse antes de que la presión del sistema baje de 60 psi."},"5":{"q":"Conduzco un tractocamión sencillo cargado cuando se revienta una línea y mi presión de aire empieza a caer rápidamente. La luz y el zumbador de advertencia de baja presión ya están encendidos, y la aguja sigue bajando. ¿A qué presión aproximada debo esperar que los frenos de resorte (de emergencia) se apliquen solos y me detengan?","options":["Alrededor de 60 psi, el mismo punto donde se activa por primera vez la advertencia de baja presión","En algún punto del rango de 20 a 45 psi, después de que la advertencia ya se haya activado","Alrededor de 100 psi, el punto de conexión del gobernador donde el compresor reinicia","Alrededor de 5 a 10 psi, solo cuando los tanques están casi completamente vacíos"],"explanation":"Los frenos de resorte (de emergencia/estacionamiento) se aplican automáticamente cuando la presión de aire cae al rango de 20 a 45 psi."},"6":{"q":"Durante mi inspección previaje, mi instructor señala el pedal que presiono con el pie para aplicar los frenos de servicio y me pregunta su otro nombre correcto. Para responder bien, ¿a qué componente está señalando?","options":["El gobernador (governor), ya que controla cuánto aire de frenado libera el pedal hacia las ruedas","El ajustador de holgura (slack adjuster), porque transfiere la presión de mi pie a fuerza de frenado mecánica","La válvula de pedal (treadle), que envía aire a los frenos de servicio cuando la presiono","La conexión glad hand, ya que es el acople que lleva mi aire de frenado hasta los frenos"],"explanation":"El pedal de freno se llama correctamente válvula de pie o de pedal, que envía aire a los frenos de servicio al presionarlo."},"7":{"q":"Es una mañana de invierno bajo cero y, durante mi inspección previaje, abro la válvula de drenaje en el fondo del tanque de aire. Junto con el aire sale a borbotones un líquido lechoso y aceitoso. Un compañero me dice que debo tener una avería mecánica grave porque ese líquido nunca debería estar en el tanque. ¿Qué afirmación explica correctamente lo que veo y por qué dreno los tanques a diario?","options":["Solo debería salir aire; el líquido indica que un tanque agrietado está filtrando líquido de frenos al suministro de aire","El refrigerante se ha filtrado a través de un sello dañado hacia el tanque, así que debo drenarlo antes de que llegue a las cámaras de freno","El líquido de frenos con fugas se ha mezclado con el aire, y el drenaje diario expulsa ese líquido del sistema","El aire comprimido normalmente acumula agua y algo de aceite del compresor, y el drenaje diario lo elimina para evitar la congelación y los daños"],"explanation":"El aire comprimido acumula naturalmente agua y algo de aceite del compresor, por lo que los tanques deben drenarse a diario para evitar congelamiento y daños."},"8":{"q":"Es una mañana de invierno bajo cero y noto que mi camión está equipado con un secador de aire montado en el tanque de suministro (húmedo). Durante mi inspección previaje, intento recordar la función principal de este componente. ¿Qué afirmación describe MEJOR lo que hace el secador de aire para mi sistema de frenos de aire?","options":["Elimina el agua y los contaminantes del aire comprimido antes de que ese aire llegue a los tanques de almacenamiento","Eleva el aire comprimido por encima del corte del gobernador para que los tanques alcancen una presión de trabajo más alta","Activa la luz y el zumbador de advertencia de baja presión de aire antes de que la presión del tanque baje de 60 psi","Enfría los tambores y forros de freno recalentados tras una bajada larga y pronunciada para evitar la pérdida de frenado"],"explanation":"El secador de aire elimina el agua y los contaminantes del aire comprimido antes de que llegue a los tanques de almacenamiento."},"9":{"q":"Estoy haciendo la inspección previaje de un tractocamión con remolque y el motor acaba de alcanzar el corte del gobernador (cut-out). Al revisar el tablero, veo dos manómetros de aire uno al lado del otro. Para confirmar que tengo suficiente aire almacenado antes de soltar los frenos y arrancar, ¿qué lectura del manómetro de presión de suministro (supply pressure gauge) me da la información que necesito?","options":["La cantidad de presión que estoy enviando a las cámaras de freno cuando piso el pedal","La cantidad de presión de aire almacenada actualmente en los tanques de aire (unas 125 psi al corte)","La presión a la que los frenos de resorte se activarán automáticamente si baja el aire","La presión a la que está ajustada la válvula de alivio de seguridad para abrirse y proteger el sistema"],"explanation":"El manómetro de presión de suministro muestra cuánta presión de aire hay almacenada actualmente en los tanques, unas 125 psi al cortar el gobernador."},"10":{"q":"Voy bajando una pendiente larga con mi camión cargado y piso el pedal del freno con más fuerza para mantener la velocidad. Cuanto más hundo el pedal (la válvula de freno), más sube la aguja de uno de los indicadores del tablero, y vuelve a bajar hacia cero cuando suelto el pedal. ¿Qué indicador estoy observando responder al movimiento de mi pie?","options":["El manómetro de presión del tanque de aire (suministro), porque muestra cuánto aire queda en los depósitos","El manómetro de corte del regulador, porque muestra que el compresor se detiene a unos 125 psi","El manómetro de presión de aplicación, porque muestra cuánta presión de aire estoy aplicando a los frenos","El indicador de advertencia de baja presión de aire, porque se enciende antes de que la presión baje de 60 psi"],"explanation":"El manómetro de presión de aplicación muestra cuánta presión de aire envía a los frenos con el pedal."},"11":{"q":"Durante mi inspección previa al viaje, mi instructor señala la leva en S (S-cam) de un conjunto de frenos y me pide que explique qué ocurre físicamente en ese componente en el instante en que piso el pedal del freno y el aire llega a la cámara de freno. ¿Qué respuesta describe correctamente la función de la leva en S?","options":["Drena el agua y el aceite del compresor de los tanques de aire para que las líneas no se congelen","Le indica al gobernador que detenga el compresor cuando los tanques alcanzan unos 125 psi","Retrae el ajustador de holgura (slack adjuster) para eliminar el juego libre del vástago","Gira y empuja las zapatas del freno separándolas contra la superficie interior del tambor"],"explanation":"La leva en S gira y se mete entre las zapatas, separándolas contra el interior del tambor."},"12":{"q":"Durante mi inspección previaje, estaciono en terreno plano, calzo las ruedas, suelto los frenos de estacionamiento y hago palanca contra un ajustador de holgura manual con una barra para revisar el recorrido excesivo de la varilla de empuje. Los frenos están desajustados si el ajustador de holgura se mueve MÁS de aproximadamente:","options":["1 pulgada, ya que un mayor juego libre significa que los frenos están desajustados y pierden fuerza de frenado","3 pulgadas, que es el recorrido máximo permitido antes de que los frenos queden desajustados","5 pulgadas, ya que cualquier valor menor a eso aún mantiene los frenos en el ajuste correcto","Puede moverse libremente, porque los ajustadores de holgura están diseñados para oscilar sin límite de recorrido"],"explanation":"El ajustador de holgura manual no debe moverse más de 1 pulgada al jalarlo, o los frenos están desajustados."},"13":{"q":"Conduzco un tractocamión con frenos de aire y piso fuerte el pedal del freno para reducir la velocidad por el tráfico que tengo delante. Comparado con los frenos hidráulicos de mi auto, hay un retraso notable antes de que los frenos de aire realmente agarren. ¿Aproximadamente cuánto dura este retraso de los frenos de aire — el tiempo que tarda el aire en recorrer las líneas y actuar después de que piso el pedal?","options":["Alrededor de 1/10 de segundo, la misma respuesta casi instantánea que siento en el sistema de frenos hidráulicos de un auto","Alrededor de 1/2 segundo para que el aire recorra las líneas y los frenos se accionen","Alrededor de 2 segundos, lo que coincide aproximadamente con el retraso de la distancia de reacción antes de que el conductor pise el pedal","Alrededor de 5 segundos, ya que el aire debe llenar por completo cada cámara antes de que comience cualquier frenado"],"explanation":"Los frenos de aire tienen un retardo de medio segundo mientras el aire comprimido viaja por las líneas antes de actuar."},"14":{"q":"Estoy calculando la distancia total de frenado de mi camión con frenos de aire. Para un automóvil con frenos hidráulicos, la distancia total de frenado es solo la distancia de percepción más la distancia de reacción más la distancia de frenado. Como mi camión usa frenos de aire, ¿qué componente ADICIONAL debo agregar a ese cálculo que el conductor del automóvil no tiene?","options":["Una distancia de reacción adicional, porque al cerebro le toma más tiempo accionar los controles de los frenos de aire","Una distancia de percepción más larga, porque el mayor tamaño del camión dificulta detectar los peligros a tiempo","Una distancia de retardo del freno, por el medio segundo aproximado que tarda el aire en recorrer las líneas y aplicar los frenos","Nada adicional, ya que las cuatro distancias básicas son idénticas para todo tipo de sistema de frenos"],"explanation":"La distancia de frenado con aire añade una distancia de retardo por el medio segundo que tarda el aire en llegar y actuar."},"15":{"q":"Durante mi inspección previaje, apago el motor con el sistema totalmente cargado a unos 125 psi, coloco calzos en las ruedas y dejo los frenos de estacionamiento SUELTOS en mi camión sencillo (sin remolque). Observo el manómetro del tablero durante un minuto para cronometrar la fuga. La pérdida de aire solo es aceptable mientras se mantenga igual o por debajo de qué tasa?","options":["4 psi por minuto, ya que ese es el límite una vez que el motor está apagado y los tanques llenos","1 psi por minuto, suponiendo que casi nada de aire debería escapar de un sistema sellado","3 psi por minuto, la misma cifra que se aplica a un vehículo combinado en esta prueba","2 psi por minuto, el máximo permitido para un vehículo sencillo con los frenos sueltos"],"explanation":"En un vehículo simple con los frenos liberados, la pérdida de aire no debe superar 2 psi por minuto."},"16":{"q":"Durante mi inspección previaje en un tractocamión con remolque, cargo el sistema por completo hasta unos 125 psi, apago el motor y dejo los frenos liberados para cronometrar la fuga de aire. Observando el manómetro del tablero durante un minuto, ¿cuál es la caída MÁXIMA de presión que puedo tener y aún así aprobar esta parte de la inspección?","options":["3 psi en un minuto","2 psi en un minuto","4 psi en un minuto","6 psi en un minuto"],"explanation":"En un vehículo combinado con los frenos liberados, la pérdida de aire no debe superar 3 psi por minuto."},"17":{"q":"Durante mi inspección previaje, cargo el sistema de aire hasta unos 125 psi, apago el motor, pongo calzos en las ruedas y aplico a fondo el freno de pie en mi camión rígido individual (sin remolque). Observo el manómetro del tablero durante un minuto para verificar la tasa de fuga de aire. ¿Qué lectura significa que mi camión está dentro del límite legal y es seguro para conducir?","options":["La presión baja 4 psi en ese minuto","La presión baja 2 psi en ese minuto","La presión baja 5 psi en ese minuto","La presión baja 6 psi en ese minuto"],"explanation":"En un vehículo simple con los frenos aplicados, la pérdida de aire debe mantenerse por debajo de 3 psi por minuto."},"18":{"q":"Durante mi inspección previaje en un sistema de frenos de aire dual, arranco el motor, lo mantengo a las rpm de operación y observo cómo los manómetros del tablero suben desde 85 psi. Para aprobar la parte de acumulación de presión de aire, ¿en cuánto tiempo deben llegar los manómetros a 100 psi?","options":["Dentro de 10 segundos a las rpm de operación","Dentro de 3 minutos a las rpm de operación","Dentro de 45 segundos a las rpm de operación","Dentro de 5 minutos a las rpm de operación"],"explanation":"En un sistema de frenos de aire doble, la presión debe subir de 85 a 100 psi en 45 segundos a rpm de operación."},"19":{"q":"Durante mi inspección previaje, el motor está apagado y mis tanques de aire están cargados a unos 125 psi. Quiero confirmar que el dispositivo de advertencia de baja presión de aire funciona correctamente antes de conducir. ¿Qué acción realiza realmente esta verificación?","options":["Acelerar el motor a altas revoluciones con el sistema cargado y observar si la advertencia se enciende cuando la presión sube por encima de 60 psi","Abrir del todo las válvulas de drenaje de los tanques para que todo el aire salga rápido de los tanques y escuchar el zumbador","Pisar el pedal del freno una vez y confirmar que el dispositivo de advertencia permanece apagado por encima de 100 psi","Con el motor apagado, pisar y soltar el pedal del freno repetidamente para bajar la presión hasta que la advertencia se encienda por encima de 60 psi"],"explanation":"Con el motor apagado, bombee los frenos para bajar la presión y confirme que la alerta de aire bajo se activa antes de caer bajo 60 psi."},"20":{"q":"Durante mi inspección de frenos de aire antes del viaje, he cargado el sistema a presión completa, solté el freno de estacionamiento y estoy listo para verificar que los frenos de servicio realmente sujeten y detengan el camión en línea recta. ¿Cuál de estas es la forma correcta de realizar la prueba de parada con los frenos de servicio?","options":["Dejar que el vehículo avance a unas 5 millas por hora, luego pisar el pedal del freno con firmeza y confirmar que se detiene sin desviarse hacia un lado","Acelerar a la velocidad normal de carretera y frenar fuerte una vez para confirmar que los frenos pueden lograr una parada completa","Mantener el vehículo detenido, tirar de la perilla del freno de estacionamiento y sentir si el tractor permanece bloqueado en su sitio","Mientras avanza a unas 5 millas por hora, bombear el pedal del freno diez veces rápidamente para confirmar que la presión se recupera cada vez"],"explanation":"Prueba correcta del freno de servicio: avanzar a unas 5 mph, pisar el pedal con firmeza y el vehículo debe detenerse recto sin desviarse hacia un lado."},"21":{"q":"Durante mi inspección previaje, encuentro una grieta que recorre la cara de uno de los tambores de freno. Debo decidir si saco el camión de servicio. Según el Manual CDL de Texas, un tambor de freno agrietado queda fuera de servicio cuando la grieta es más larga que ¿cuál de las siguientes opciones?","options":["Cualquier grieta fina (capilar) visible en la cara del tambor","La mitad del ancho de la superficie de fricción del tambor","Un cuarto del ancho de la superficie de fricción del tambor","El ancho completo de la superficie de fricción del tambor"],"explanation":"Un tambor de freno debe ponerse fuera de servicio cuando una grieta es más larga que la mitad del ancho de la superficie de fricción del tambor."},"22":{"q":"Durante mi inspección previaje, quito una rueda y me meto debajo del remolque para revisar los frenos de tambor. Encuentro un problema y decido que las balatas deben reemplazarse antes de conducir. ¿Cuál de las siguientes condiciones de las balatas justificaría CORRECTAMENTE retirar este vehículo del servicio?","options":["Las balatas están gruesas, secas y firmemente asentadas contra la placa de soporte","Las balatas hacen contacto parejo con el tambor y muestran un desgaste superficial leve y uniforme","Las balatas están empapadas de aceite o grasa, o están desgastadas peligrosamente delgadas","Las balatas se acaban de instalar y tienen un ligero vidriado del asentamiento inicial"],"explanation":"Las balatas de freno están defectuosas y el vehículo debe ponerse fuera de servicio cuando están empapadas de aceite o grasa o gastadas peligrosamente delgadas."},"23":{"q":"Voy bajando una pendiente larga y empinada con una combinación cargada. Antes de empezar a bajar puse una marcha baja, y ahora estoy pensando en cómo usar mis frenos de aire durante el resto del descenso. ¿Qué afirmación describe correctamente el papel que deben cumplir mis frenos en esta bajada?","options":["Son mi principal control de velocidad, así que debo mantener una presión constante en el pedal durante toda la bajada","Funcionan mejor cuando se bombean encendiéndolos y apagándolos repetidamente, dejando que el aire se recargue entre cada aplicación","Deben mantenerse pisados con firmeza y de forma continua para que las ruedas no ganen ninguna velocidad","Son un complemento del freno motor, usados en aplicaciones ligeras y constantes para respaldar la marcha baja"],"explanation":"En una bajada larga el motor en una marcha baja es el control principal de velocidad, y los frenos solo lo complementan con aplicaciones ligeras y constantes."},"24":{"q":"Estoy descendiendo una pendiente larga y empinada con mi vehículo combinado cargado, ya en una marcha baja, y quiero usar la técnica correcta de frenado intermitente (snub) para mantener mi velocidad bajo control. ¿Qué acción describe correctamente lo que debo hacer con los frenos?","options":["Aplicar los frenos con firmeza hasta que mi velocidad baje a unas 5 mph por debajo de mi velocidad segura, luego soltarlos por completo y repetir el ciclo según sea necesario","Mantener una presión ligera y constante sobre el pedal del freno de forma continua durante toda la bajada para nunca generar calor","Bombear los frenos rápidamente, presionando y soltando durante todo el descenso para evitar que las ruedas se bloqueen","Poner en punto muerto y rodar por inercia, aplicando los frenos solo si el velocímetro supera mi velocidad segura"],"explanation":"Use el frenado intermitente en una bajada larga: frene con firmeza hasta que la velocidad baje unas 5 mph por debajo de su velocidad segura, suelte por completo para que se enfríen y repita."},"25":{"q":"Estoy bajando una pendiente larga y empinada de montaña en un camión cargado con frenos de aire. La bajada no termina y me preocupan los frenos, así que empiezo a pisar y soltar el pedal del freno rápidamente una y otra vez para controlar la velocidad. ¿Por qué hacer esto es precisamente lo que NO se debe hacer?","options":["El frenado intermitente repetido recalienta los ajustadores de holgura (slack adjusters) y bloquea las ruedas delanteras, haciendo que el camión patine y se descontrole en la bajada","Cada vez que sueltas el pedal escapa aire más rápido de lo que el compresor puede reponerlo, por lo que la presión puede caer hasta que los frenos ya no tengan suficiente aire para funcionar","El bombeo rápido del pedal activa el ABS y suelta los frenos por completo, dejando los frenos de resorte (estacionamiento) como única forma de frenar","Bombear el pedal fuerza la apertura de la válvula de alivio de seguridad a 150 psi, liberando el aire del tanque que necesitas para el resto del descenso"],"explanation":"Bombear los frenos libera aire más rápido de lo que el compresor puede reponer, por lo que la presión puede caer hasta que los frenos ya no tengan aire suficiente para funcionar."},"26":{"q":"Acabo de terminar un largo descenso por una pendiente montañosa empinada, usando los frenos de aire todo el camino, y entro a un área de descanso para tomar mi pausa obligatoria. ¿En cuál de estas situaciones NO debería poner el freno de estacionamiento (de resorte) y, en su lugar, calzar las ruedas?","options":["Estoy estacionando en una leve pendiente cuesta abajo donde el camión podría rodar si lo dejo en marcha","Dejaré el camión sin vigilancia toda la noche en un lote señalizado para camiones","Los tambores y las zapatas de freno siguen extremadamente calientes por el descenso que acabo de hacer","El zumbador de advertencia de baja presión de aire sonó brevemente mientras me detenía"],"explanation":"No aplique el freno de estacionamiento (de resorte) cuando los tambores y las balatas aún están muy calientes tras un descenso largo, porque puede dañarlos y causar agarrotamiento."},"28":{"q":"Conduzco un tractocamión modelo 2020 (equipado con ABS en funcionamiento) cuando un auto se detiene en seco en mi carril. Debo detenerme lo más rápido posible manteniendo el equipo en mi carril para evitar el acotamiento. ¿Qué método de frenado me da el mejor control en esta emergencia?","options":["Bombear rápidamente el pedal del freno para que el ABS pueda activarse y agarrar entre cada liberación","Aplicar primero solo la válvula manual del remolque para evitar que las ruedas del tractor patinen","Aliviar la presión en el instante en que siento que una rueda empieza a derrapar, y luego volver a apretar","Pisar el pedal del freno con fuerza, mantenerlo presionado y seguir dirigiendo hacia el carril libre"],"explanation":"Con ABS, frene fuerte y mantenga la presión firme en el pedal mientras dirige, porque el ABS evita que las ruedas se bloqueen y así puede guiar hacia el carril libre."},"29":{"q":"Estoy conduciendo un tractocamión antiguo que NO está equipado con ABS, y un automóvil se me atraviesa de repente. Necesito hacer una parada de emergencia fuerte manteniendo el control del vehículo. ¿Qué método de frenado debo usar?","options":["Usar frenado controlado o frenado por impulsos (stab) para que las ruedas sigan girando y yo pueda seguir dirigiendo","Pisar el pedal del freno hasta el fondo y mantenerlo presionado con fuerza hasta detenerme","Frenar lo suficientemente fuerte para bloquear las ruedas, ya que las ruedas bloqueadas dan la parada más corta","Bombear el pedal del freno rápidamente hasta el fondo para mantener alta la presión de aire"],"explanation":"Sin ABS, use frenado controlado o intermitente para que las ruedas sigan girando, lo que conserva tanto la capacidad de frenado como el control de la dirección."},"30":{"q":"Conduzco un camión cargado sin ABS cuando algo se cruza de repente en la vía y tengo que frenar con fuerza. Piso el pedal del freno hasta el fondo, las ruedas se bloquean y suelto el pedal para iniciar una secuencia de frenado intermitente (stab). Para hacer el frenado intermitente correctamente, ¿cuándo debo volver a pisar el pedal con fuerza?","options":["En cuanto suelto el pedal, sin esperar nada","Solo después de que las ruedas hayan empezado a girar de nuevo","Después de mantener los frenos sueltos durante unos 10 segundos","No debo volver a pisarlo — una vez suelto, debo dirigir y aguantar"],"explanation":"En el frenado intermitente, vuelve a aplicar los frenos solo después de que las ruedas hayan empezado a girar de nuevo, ya que las ruedas bloqueadas no pueden dirigir ni frenar bien."},"31":{"q":"Lleva 30 millas de recorrido cuando la luz ámbar de avería del ABS en el tablero se enciende y permanece encendida. Su advertencia de baja presión de aire NO se ha activado y el pedal todavía se siente firme. ¿Cuál de las siguientes describe correctamente su situación y la acción correcta a seguir?","options":["Sus frenos de servicio han fallado; detenga la unidad de forma controlada en el arcén de inmediato y llame a una grúa antes de seguir conduciendo.","Su distancia de frenado ahora es más larga de lo normal, así que aumente su distancia de seguimiento y bombee el pedal del freno para mantener el aire fluyendo a las ruedas.","Todavía tiene sus frenos de servicio normales y puede seguir conduciendo con cuidado; solo se perdió la función antibloqueo, así que lleve el ABS a revisión lo antes posible.","Sus frenos de resorte (de estacionamiento) están a punto de aplicarse automáticamente, así que reduzca la velocidad y salga en la próxima rampa antes de que las ruedas se bloqueen."],"explanation":"La luz de advertencia del ABS indica que solo se pierde la función antibloqueo; conserva los frenos de servicio normales completos, así que conduzca con cuidado y repare el ABS pronto."},"32":{"q":"Estoy comprando un tractocamión usado y quiero confirmar que venía de fábrica con frenos antibloqueo (ABS), ya que las normas federales hicieron obligatorio el ABS en ciertos vehículos con frenos de aire. El concesionario me muestra cuatro tractocamiones fabricados en años diferentes. ¿Cuál es la fecha de fabricación MÁS TEMPRANA que OBLIGARÍA a que el tractocamión tenga ABS instalado de fábrica?","options":["Cualquier tractocamión fabricado el 1 de marzo de 1998 o después","Cualquier tractocamión fabricado el 1 de marzo de 1995 o después","Cualquier tractocamión fabricado el 1 de marzo de 2000 o después","Cualquier tractocamión fabricado el 1 de marzo de 1997 o después"],"explanation":"Las normas federales exigen ABS de fábrica en los tractocamiones fabricados a partir del 1 de marzo de 1997."},"34":{"q":"Es una mañana bajo cero de diciembre en Amarillo y estoy haciendo mi inspección previa al viaje. Mi camión tiene válvulas de drenaje manuales en los tanques de aire, pero voy con retraso, así que me tienta saltarme el drenaje hoy. ¿Cuál es la MEJOR razón por la que aun así debo abrir los drenajes de los tanques antes de salir?","options":["El agua que se acumula en los tanques puede congelarse con el frío e impedir que los frenos funcionen","Drenar los tanques permite que el gobernador corte a una presión más alta y el sistema cargue más rápido","Abrir los drenajes purga el aire viejo para que la válvula de alivio de seguridad se reasiente en los 150 psi correctos","Liberar el aire reinicia la advertencia de baja presión para que el zumbador no suene por debajo de 60 psi"],"explanation":"Drene los tanques de aire a diario, porque el agua acumulada puede congelarse en clima frío e impedir que los frenos funcionen."},"35":{"q":"Estoy terminando mi inspección previaje en un tractocamión con remolque. El motor está en ralentí y la aguja del manómetro de presión de aire va subiendo. Antes de soltar el freno de estacionamiento y salir del patio, ¿hasta qué nivel de presión debo dejar que cargue el sistema de aire?","options":["Hasta unos 100 psi, porque es el punto donde el compresor arranca y sé que está funcionando","Hasta el rango normal de operación, unos 125 psi, donde el gobernador corta y deja de bombear aire","Hasta unos 150 psi, el nivel donde se abre la válvula de alivio de seguridad para proteger el sistema","Hasta unos 60 psi es suficiente, ya que ahí es donde se apaga la advertencia de baja presión de aire"],"explanation":"Cargue el sistema de aire hasta su rango operativo normal, unos 125 psi, donde el gobernador corta, antes de conducir."},"36":{"q":"Durante mi inspección previaje, noto que la banda que impulsa el compresor de aire está vidriada y puedo hundirla un par de centímetros con el pulgar. El motor arranca bien y la radio de la cabina funciona. ¿Por qué importa esta banda floja para una operación segura?","options":["Una banda floja solo preocupa porque puede chirriar y dificultar oír el zumbador de advertencia de baja presión de aire","Importa porque esa misma banda hace girar el alternador que mantiene cargada la batería de emergencia del remolque","Una banda que patina puede impedir que el compresor bombee con suficiente rapidez, así que el sistema quizá nunca acumule ni mantenga suficiente presión de aire","Importa porque la banda de transmisión dirige aire de enfriamiento sobre los tambores de freno delanteros para evitar el desvanecimiento del freno"],"explanation":"Una correa de transmisión del compresor que patina impide que este bombee lo bastante rápido, por lo que el sistema puede no alcanzar ni mantener la presión de aire adecuada."},"37":{"q":"Estoy haciendo mi inspección previa al viaje en un vehículo combinado simple y quiero asegurarme de haber completado cada parte de la sección de frenos de aire antes de arrancar. Otro conductor me dice que algunas de las pruebas que enumeré en realidad no cuentan como parte de la prueba de frenos de aire. ¿Cuál de estas es realmente una parte obligatoria de una inspección completa de frenos de aire previa al viaje?","options":["Solo la prueba del dispositivo de advertencia de baja presión de aire, ya que el zumbador y la luz son lo que vigila el examinador","Solo el tiempo de acumulación de presión de aire, ya que demuestra que el compresor está cumpliendo su función","Solo la tasa estática de fuga de aire, ya que una fuga es el defecto más grave que se puede encontrar","Todas ellas: la advertencia de baja presión, el tiempo de acumulación y la tasa de fuga de aire son cada una parte obligatoria de la inspección"],"explanation":"Una revisión completa de frenos de aire antes del viaje exige todo esto: la advertencia de baja presión, el tiempo de acumulación y la tasa de fuga de aire."},"38":{"q":"Estoy haciendo la inspección previaje de un tractocamión con frenos de aire y quiero omitir cualquier paso que NO compruebe realmente el propio sistema de frenos de aire. ¿Cuál de los puntos de mi lista pertenece a otro sistema y no me dice nada sobre mis frenos?","options":["Drenar agua y aceite del radiador para mantener limpio el sistema de enfriamiento del motor","Cronometrar cuánto tarda la presión en subir de 85 a 100 psi para confirmar un buen ritmo de acumulación","Cargar el sistema, apagar el motor y observar el manómetro para medir el ritmo de fuga (caída de presión)","Bombear el pedal hasta que la luz y el zumbador de advertencia de baja presión se activen cerca de 60 psi"],"explanation":"Drenar agua y aceite del radiador es mantenimiento del sistema de enfriamiento del motor y no comprueba nada del sistema de frenos de aire."},"39":{"q":"Conduzco un tractocamión equipado con ABS y tengo que hacer una frenada brusca de emergencia sobre pavimento seco. Cuando el ABS se activa y siento el pedal pulsando, ¿cuál afirmación sobre lo que el ABS realmente está haciendo por mí en esta frenada es VERDADERA?","options":["Está acortando mi distancia de frenado en comparación con el mismo equipo sin ABS","Está evitando que mis ruedas se bloqueen para que pueda seguir dirigiendo mientras freno fuerte","Está reduciendo automáticamente el retardo de frenado por debajo del medio segundo habitual","Está aplicando los frenos de resorte (de estacionamiento) para añadir fuerza de frenado extra"],"explanation":"El ABS evita que las ruedas se bloqueen, de modo que siguen girando y permite dirigir mientras frena fuerte."},"40":{"q":"Estoy haciendo mi inspección matutina antes del viaje y noto que los tanques de aire de mi tractor han acumulado una mezcla de agua y una película de aceite del compresor en el fondo. Es una fría mañana de invierno en el Panhandle. Para que el sistema de frenos de aire funcione con seguridad y evitar el congelamiento, ¿qué debo hacer con esta acumulación?","options":["Dejarlo así, ya que el secador de aire y el calor de los frenos evaporarán el agua y el aceite durante el viaje","Llenar los tanques con aceite de compresor adicional para que la humedad quede suspendida y no pueda congelarse","Drenar los tanques de aire diariamente usando las válvulas de drenaje para que el agua y el aceite no dañen el sistema ni se congelen","Drenar los tanques solo una vez por semana, ya que las válvulas automáticas modernas se encargan del resto por sí solas"],"explanation":"Drene los tanques de aire a diario con las válvulas de drenaje para que el agua y el aceite acumulados no dañen el sistema ni se congelen."},"41":{"q":"Durante mi inspección previaje, apagué el motor para hacer la prueba de fuga de aire y noto que la aguja del manómetro deja de subir por completo mientras el motor está apagado. Un novato a mi lado insiste en que el compresor debería seguir generando presión por sí solo. ¿Qué afirmación explica correctamente por qué la presión dejó de subir una vez que apagué el motor?","options":["El regulador (governor) bombea mecánicamente los tanques de aire y solo funciona mientras el camión avanza hacia adelante","El resorte del freno de estacionamiento es lo que carga el sistema de aire, así que se detiene cuando se aplican los frenos","La rotación de las ruedas del remolque hace girar el compresor, así que la presión solo sube en movimiento","El compresor es accionado por el motor (mediante una correa o directamente), por eso no se bombea aire una vez que el motor está apagado"],"explanation":"El compresor de aire es accionado por el motor, así que no bombea aire una vez apagado el motor."},"42":{"q":"Es una mañana de invierno muy por debajo de cero y estoy haciendo la inspección previaje de un tractor equipado con un secador de aire. Quiero entender de qué me protege este dispositivo mientras el compresor mete aire al sistema. ¿Cuál es la función principal del secador de aire en esta situación?","options":["Extrae el vapor de agua (y un poco de aceite) del aire comprimido antes de que llegue a los tanques, para que se acumule menos humedad y no se congele el sistema","Le indica al compresor que deje de bombear cuando la presión del tanque sube al punto de corte cercano a 125 psi","Purga los tanques automáticamente si la presión llega a superar el ajuste de la válvula de seguridad de unos 150 psi","Inyecta una cantidad medida de alcohol en las líneas para evitar que las válvulas de freno se congelen con el frío"],"explanation":"El secador de aire elimina el vapor de agua y algo de aceite del aire comprimido antes de llegar a los tanques, reduciendo la humedad que podría congelarse e inutilizar los frenos."},"43":{"q":"Durante mi inspección previa al viaje, me meto debajo del remolque para examinar los frenos de rueda. En cada rueda encuentro un tambor de freno, zapatas con forros y un ajustador de holgura conectado a una varilla que gira una pieza con forma de la letra 'S' para separar las zapatas. Según lo que estoy viendo, ¿con qué tipo de freno de rueda está equipado este vehículo, el que se encuentra en la mayoría de los vehículos pesados con frenos de aire?","options":["Frenos de disco de aire, donde una mordaza aprieta un rotor, el diseño más común en camiones pesados","Frenos de tambor de leva en S, el freno de rueda más común en vehículos pesados con frenos de aire","Frenos de tambor de cuña, donde una cuña separa las zapatas a través de una sola cámara","Frenos de disco hidráulicos, como los de un automóvil pero ampliados para el remolque"],"explanation":"Los frenos de tambor de leva en S son el freno de servicio más común en vehículos pesados con frenos de aire, reconocibles por la leva en forma de S que la varilla gira para separar las zapatas."},"45":{"q":"Conduzco un tractocamión cargado con frenos de aire cuando un auto se detiene de repente delante de mí. En el instante en que piso a fondo el pedal del freno, hay una breve demora antes de que el camión realmente empiece a frenar. Mi instructor llama a esto 'retardo del freno' (brake lag). ¿Qué ocurre físicamente durante esa demora?","options":["Mi cerebro y mi cuerpo aún están procesando el peligro antes de que mi pie llegue al pedal","El compresor está generando presión adicional en los tanques para satisfacer la demanda","El aire comprimido viaja por las líneas de freno antes de poder aplicar los frenos","El vehículo recorre la distancia de percepción antes de que comience cualquier frenado"],"explanation":"Tras pisar el pedal, el aire comprimido tarda alrededor de medio segundo en recorrer las líneas de freno y aplicar realmente los frenos en cada rueda."},"46":{"q":"Estoy estudiando la distancia total de frenado para mi endoso de frenos de aire del CDL. Sé que con los frenos hidráulicos de un automóvil, la distancia total de frenado es la distancia de percepción más la distancia de reacción más la distancia de frenado. Mi instructor dice que los frenos de aire añaden un componente más a ese total. ¿Qué componente añade un sistema de frenos de aire que los frenos hidráulicos NO tienen?","options":["Distancia de reacción adicional, porque los pedales de los frenos de aire son más pesados y más lentos de pisar que los hidráulicos","Distancia de percepción adicional, porque los vehículos grandes con frenos de aire son más altos y toma más tiempo evaluar los peligros","Mayor distancia de frenado efectivo, porque los vehículos con frenos de aire son más pesados y necesitan más espacio para detenerse","Distancia de retardo del freno: la distancia recorrida mientras el aire viaja por las líneas antes de que los frenos agarren"],"explanation":"Los frenos de aire añaden un cuarto componente de la distancia de frenado, la distancia de retardo del freno, que cubre el medio segundo aproximado que el aire tarda en recorrer las líneas antes de que los frenos agarren."},"47":{"q":"Ha terminado su inspección previaje y el sistema de aire está completamente cargado. Ahora quiere verificar que los frenos de servicio realmente detienen el camión y que nada se arrastra ni tira hacia un lado. ¿Cuál de las siguientes es la forma correcta de realizar la prueba de parada con los frenos de servicio?","options":["Suelte el freno de estacionamiento, deje que el camión avance lentamente hasta unas 5 millas por hora, luego pise con firmeza el pedal del freno y sienta si se detiene pronto y en línea recta","Mantenga el camión inmóvil, pise fuerte el pedal del freno y observe el manómetro para confirmar que la presión no baja más de 3 psi en un minuto","Estando detenido, jale y suelte varias veces la perilla amarilla del freno de estacionamiento para confirmar que los frenos de resorte se activan y se sueltan","Acelere hasta unas 20 millas por hora, luego haga una parada brusca y verifique que las ruedas se bloqueen de manera uniforme en ambos lados"],"explanation":"La prueba de frenado de servicio se hace en movimiento: deje que el vehículo avance hasta unos 5 mph, luego aplique los frenos con firmeza y compruebe que se detiene pronto sin desviarse hacia un lado."},"48":{"q":"Durante mi inspección previaje, mi instructor de CDL me dice que agarre uno de los ajustadores de freno y tire de él con la mano para comprobar cuánto se mueve la varilla de empuje antes de que los frenos actúen. Dice que si hay demasiado juego libre aquí, mi capacidad de frenado se reduce. ¿Qué componente estoy comprobando realmente cuando hago esto?","options":["El regulador (gobernador) del compresor de aire, que decide cuándo el sistema deja de bombear aire y cuándo lo reanuda","El ajustador de holgura (slack adjuster), que fija cuánto recorre la varilla de empuje del freno antes de que los frenos actúen","La válvula de alivio de seguridad, que se abre para liberar presión si los tanques se sobrecargan","La válvula de control modulada, que me permite aplicar los frenos de resorte de forma gradual en una emergencia"],"explanation":"El ajustador de holgura determina cuánto recorre la varilla del freno antes de que los frenos actúen, y el juego excesivo—frenos desajustados—es el defecto más común de los frenos de aire."},"49":{"q":"Durante una inspección previaje con clima bajo cero, noto que los tanques de aire de mi camión expulsan por sí solos el agua y el aceite acumulados, sin que yo tenga que abrir nada con la mano. El taller dice que este tanque está equipado para que el drenaje ocurra solo y ayude a evitar el congelamiento. ¿Qué dispositivo realiza esta función?","options":["Una válvula de relé, que acelera la señal de aire hacia los frenos traseros pero también purga la humedad del tanque por sí sola","Una válvula de drenaje manual, que deja escapar el agua y el aceite acumulados de forma automática cuando la presión del tanque es lo bastante alta","Una válvula de drenaje automática, que expulsa el agua y el aceite del compresor del tanque sin que nadie lo drene a mano","Una válvula de alivio de seguridad, que se abre cerca de 150 psi y elimina el agua y el aceite acumulados del tanque de suministro al ventilar"],"explanation":"Una válvula de drenaje automática expulsa por sí sola el agua acumulada y el aceite del compresor del tanque, sin drenaje manual, lo que ayuda a evitar el congelamiento en clima frío."},"50":{"q":"Durante mi inspección previaje en un vehículo combinado más nuevo, noto que el manómetro de presión de aire tiene dos agujas en lugar de una, y el camión no me deja generar presión normalmente hasta que ambas lecturas suben. Mi instructor dice que esta unidad tiene un sistema de frenos de aire doble. ¿Qué afirmación describe correctamente cómo está construido realmente este sistema doble?","options":["Es un solo sistema de aire grande alimentado por un único tanque, y la segunda aguja del manómetro solo muestra la presión del remolque como lectura informativa.","Combina los frenos de servicio, de estacionamiento y de emergencia en una sola línea de aire compartida, de modo que los tres funcionan con una única fuente de presión.","Es un solo sistema de aire con un compresor de respaldo que se activa únicamente después de que el compresor principal falle por completo.","Son dos sistemas de aire completamente separados, uno primario y otro secundario, controlados por un solo conjunto de controles de freno para mayor seguridad."],"explanation":"Un sistema de frenos de aire dual son dos sistemas de aire completamente separados, uno primario y otro secundario, cada uno con sus propios tanques y líneas pero operados por un solo juego de controles como respaldo de seguridad."},"51":{"q":"Conduzco un tractocamión con remolque equipado con un sistema de frenos de aire doble cuando, de repente, se activa la advertencia de baja presión de aire solo para el circuito primario, y la aguja del manómetro de ese lado cae hacia cero. El manómetro del sistema secundario sigue marcando dentro del rango normal. ¿Qué afirmación describe mejor lo que debo esperar y hacer?","options":["El sistema secundario seguirá accionando los frenos, así que debo frenar hasta detenerme de forma segura previendo una distancia de frenado más larga, y luego llevar el camión a reparar.","Como ambos circuitos comparten un solo juego de controles, el sistema secundario falla junto con el primario, así que me quedo sin frenos y debo rodar en punto muerto hasta detenerme.","Debo bombear el pedal del freno rápidamente para obligar al circuito que funciona a enviar aire a todas las ruedas y restaurar la presión completa en el lado averiado.","Los frenos de resorte bloquearán todas las ruedas al instante en el momento en que falle un circuito, así que debo prepararme para una parada brusca inmediata."],"explanation":"Si un circuito de un sistema de frenos de aire dual falla, el otro aún acciona los frenos, así que frene hasta una parada controlada permitiendo una distancia de frenado mayor y luego repárelo."},"52":{"q":"Estoy haciendo la inspección previa al viaje de mi tractocamión con remolque y el motor está apagado. Mientras el sistema se purga lentamente, miro el manómetro: la aguja pasa de los 60 psi y sigue bajando hacia los 30 psi. De repente, los frenos de resorte (de estacionamiento) se aplican solos, aunque nunca toqué el control de estacionamiento. ¿Qué afirmación explica MEJOR por qué los frenos de resorte habían permanecido liberados hasta ese momento?","options":["Los mantenían mecánicamente liberados los ajustadores de holgura hasta que se agotó el recorrido del vástago","La presión de aire mantenía comprimidos los potentes resortes, y al perderse esa presión los resortes aplicaron los frenos","Estaban bloqueados en posición abierta por la perilla amarilla en forma de diamante hasta que el zumbador de baja presión los liberó","El pedal del freno de servicio los mantenía liberados y solo se aplicaron cuando se desvaneció la presión del pedal"],"explanation":"La presión de aire mantiene los potentes frenos de resorte en la posición liberada, por lo que cuando la presión baja del rango de 20-45 psi los resortes aplican los frenos automáticamente."},"53":{"q":"En mi inspección previaje, los frenos de resorte (de estacionamiento) no se liberan y sospecho de una falla mecánica en la cámara del freno de resorte. Un compañero me da una herramienta y dice que los potentes resortes pueden 'enjaularse' (comprimirse) manualmente para que pueda mover el camión al taller. Nunca me han capacitado en este procedimiento. ¿Cuál es la acción correcta?","options":["Enjaular los resortes yo mismo solo esta vez, ya que el camión solo debe rodar una corta distancia hasta el taller","Liberar y reaplicar repetidamente los frenos de resorte a mano para ir soltando poco a poco la cámara atascada","Dejar los resortes en paz y no intentar enjaularlos, porque enjaular estos potentes resortes solo debe hacerlo personal capacitado","Pintar primero las cámaras del freno de resorte de un color brillante para que los fuertes resortes se vean bien mientras los enjaulas"],"explanation":"Enjaular (caging) los frenos de resorte es peligroso porque los resortes almacenan una fuerza enorme, por lo que debe hacerlo solo personal capacitado."},"54":{"q":"Terminé mi inspección previa al viaje y estoy realizando las verificaciones de los frenos de aire antes de salir del patio. Con el motor en marcha y la presión de aire totalmente acumulada, activo el freno de estacionamiento jalando la perilla amarilla con forma de diamante. Ahora quiero confirmar que los frenos de resorte realmente sostendrán el vehículo en su lugar. ¿Qué acción prueba esto correctamente?","options":["Soltar el freno de estacionamiento y aplicar el freno de pie con firmeza para sentir si el pedal está firme","Bombear el pedal del freno varias veces y observar el manómetro por si hay una caída de presión","Acelerar el motor y escuchar cómo los frenos de resorte se liberan a unas 20-45 psi","Dejar el freno de estacionamiento activado, soltar el embrague y avanzar suavemente hacia adelante contra él"],"explanation":"Para probar los frenos de estacionamiento (de resorte), déjelos aplicados y avance suavemente en marcha baja para confirmar que sujetan el vehículo."},"55":{"q":"Voy bajando un conjunto cargado por una pendiente de montaña larga y pronunciada, y me preocupa mantener el control de mis frenos de aire. ¿Qué técnica debo usar para manejar mi velocidad con seguridad hasta el fondo?","options":["Seleccionar una marcha baja antes del descenso y aplicar presión de freno ligera y constante, soltando cuando baje unas 5 millas por hora por debajo de mi velocidad segura","Aplicar presión de freno firme y continua durante todo el descenso para mantener la velocidad fija, baja y bajo control","Bombear el pedal del freno presionando y soltando en ráfagas repetidas para que los frenos puedan enfriarse entre aplicaciones","Poner el vehículo en punto muerto para cuidar el motor y dejar que los frenos hagan toda la desaceleración según sea necesario durante la bajada"],"explanation":"En una bajada, elija una marcha baja y use presión de freno ligera y constante, soltando al reducir unas 5 mph por debajo de su velocidad segura."},"56":{"q":"Voy circulando por una autopista de Texas en mi camión con frenos de aire a velocidad normal y piso firmemente el pedal (válvula treadle) para reducir la marcha por el tráfico. ¿Qué sistema de frenos estoy aplicando con ese pedal?","options":["Los frenos de estacionamiento, mantenidos sueltos por el aire y accionados con la perilla amarilla","Los frenos de servicio, que uso para toda reducción y parada normal","Los frenos de emergencia, que se aplican solos cuando baja la presión de aire","Solo los frenos del remolque, controlados aparte por la válvula manual del remolque"],"explanation":"El pedal (válvula de pie) acciona los frenos de servicio, que se usan para toda reducción de velocidad y parada normal."},"57":{"q":"Durante mi inspección previaje estoy revisando los tambores y discos de freno de mi tractocamión. ¿Qué condición significa que un tambor o disco es peligroso y que NO se debe conducir el vehículo hasta repararlo?","options":["El tambor está frío al tacto y sin ninguna película de aceite","Hay una capa ligera de polvo del camino en la superficie exterior","El tambor tiene una grieta visible o la superficie está muy desgastada","El tambor muestra pintura fresca de un servicio reciente en el taller"],"explanation":"Un tambor de freno agrietado o muy desgastado puede fallar bajo calor y carga, por lo que el vehículo debe retirarse del servicio hasta su reparación."},"58":{"q":"Durante una inspección previaje, carga el sistema de aire a unos 125 psi, apaga el motor y observa el manómetro del tablero. Con los frenos liberados, la aguja sigue cayendo muy por encima del índice de fuga permitido y no da señales de detenerse. La advertencia de baja presión de aire aún no se ha encendido. ¿Cuál es la acción correcta?","options":["Arrancar el motor y conducir normalmente, ya que la luz y el zumbador de advertencia todavía no se han activado","Bombear el pedal del freno varias veces para reasentar las válvulas y continuar la ruta según lo planeado","Conducir directamente al taller más cercano mientras la presión se mantenga por encima de 60 psi","Sacar el vehículo de servicio y hacer reparar la fuga antes de conducir a cualquier parte"],"explanation":"Una fuga de aire continua que supera la tasa permitida puede vaciar los tanques y dejar sin frenos, por lo que el vehículo debe retirarse del servicio hasta repararse."},"59":{"q":"Voy circulando por la autopista en mi tractocamión con remolque cuando la luz amarilla de falla del ABS en el tablero se enciende y permanece encendida. El camión sigue frenando y dirigiéndose con normalidad. Según lo que me indica esta luz, ¿cuál afirmación es la MÁS precisa?","options":["Mi sistema antibloqueo quizá no esté funcionando, pero mis frenos de servicio normales aún funcionan y debo hacer revisar el ABS.","Mis frenos de servicio ya fallaron, así que debo orillarme de inmediato y aplicar el freno de estacionamiento.","Mi ABS está totalmente activado y reduciendo activamente mi distancia de frenado en este tramo del camino.","Mi presión de aire bajó por debajo de 60 psi y los frenos de resorte están a punto de bloquear las ruedas."],"explanation":"Una luz amarilla de ABS encendida indica que solo el antibloqueo puede estar fallando; los frenos de servicio normales aún funcionan y debe revisarse el ABS."},"60":{"q":"Voy conduciendo un vehículo combinado cargado en una ruta larga y vigilo constantemente los indicadores del tablero. Para asegurarme de que mis frenos de aire realmente apliquen y suelten cada vez que piso el pedal, ¿qué ÚNICA condición debo mantener durante todo el viaje?","options":["Un tanque de combustible lleno, ya que los frenos obtienen su energía directamente del suministro de combustible del motor","Suficiente presión de aire en el sistema, ya que es el aire lo que aplica y suelta los frenos","Las luces bajas encendidas, para que los sensores de advertencia de frenos puedan leer los indicadores a la luz del día","Al menos un pasajero a bordo para confirmar que las luces de freno funcionan en cada parada"],"explanation":"Un sistema de frenos de aire necesita suficiente presión de aire porque el aire comprimido es lo que aplica y libera los frenos."},"61":{"q":"Durante mi inspección previaje, dejo que el sistema de aire se cargue hasta el corte del gobernador (cut-out), luego mantengo el motor a las RPM de operación y observo cómo el manómetro sube de 85 a 100 psi. ¿Cuál de las siguientes observaciones me indicaría que el compresor de aire está en buen estado y que la tasa de acumulación es aceptable?","options":["El manómetro tarda varios minutos largos en arrastrarse de 85 a 100 psi, pero al final lo alcanza","La presión no se mueve en absoluto porque el gobernador ya ha cortado el compresor","El manómetro sube de 85 a 100 psi en unos 45 segundos, cuestión de segundos, no de minutos","La presión salta de 85 a 100 psi al instante en cuanto piso el acelerador"],"explanation":"En un sistema de frenos de aire doble, la presión debe subir de 85 a 100 psi en unos 45 segundos, lo que indica que un compresor sano restaura el aire rápido."},"62":{"q":"Durante mi inspección previaje, me meto debajo del remolque y noto que los forros de freno de una rueda se han desgastado tan delgados que están casi al ras de los remaches. Todo lo demás en el sistema de frenos está en orden. ¿Cuál de las siguientes es la acción correcta antes de sacar este vehículo a la carretera?","options":["Dejar los forros como están, ya que el recorrido del vástago y los ajustadores de holgura aún dan dentro del límite legal","Aplicar una capa ligera de líquido de frenos a los forros delgados para reducir el chirrido hasta llegar al próximo taller","Anotarlo en mi informe de inspección pero seguir conduciendo, mientras la advertencia de baja presión se mantenga por encima de 60 psi","Poner el vehículo fuera de servicio y reemplazar los forros desgastados por unos nuevos antes de conducir"],"explanation":"Las cintas de freno demasiado desgastadas ya no generan suficiente fricción, por lo que deben reemplazarse antes de conducir el vehículo."},"63":{"q":"Estoy bajando una pendiente larga de montaña con un remolque cargado. Para controlar la velocidad, presiono y suelto el pedal del freno una y otra vez ('bombear' los frenos). Mi instructor me advierte que deje de hacerlo. ¿Cuál es la razón PRINCIPAL por la que bombear los frenos es peligroso en una bajada larga?","options":["Puede gastar el aire más rápido de lo que el compresor lo repone, agotando la reserva","Enfría los tambores de freno demasiado rápido y puede agrietar las balatas por choque térmico","Mete aire extra en el tanque de suministro del remolque y sobrecarga la válvula de alivio","Hace que los ajustadores de holgura se aprieten y el recorrido del vástago quede demasiado corto"],"explanation":"Bombear repetidamente los frenos libera aire en cada aplicación más rápido de lo que el compresor puede reponerlo, agotando el suministro de aire."},"64":{"q":"Acabo de pasar de conducir un automóvil a manejar un tractocamión con remolque equipado con sistema de frenos de aire. Cuando piso el pedal del freno, intento imaginar qué es lo que realmente viaja por las líneas para empujar las zapatas contra los tambores y frenar la unidad. En este sistema de frenos de aire, ¿mediante qué medio se transmite a las ruedas la fuerza que genero en el pedal?","options":["Líquido de frenos hidráulico a presión empujado desde un cilindro maestro, igual que en mi auto","Aire comprimido almacenado en los tanques y liberado por las líneas hacia las cámaras de freno","Un cable de acero pesado y un varillaje mecánico tensados desde el pedal hasta cada rueda","Corriente eléctrica enviada por un cable que energiza un imán de freno en cada rueda"],"explanation":"Los frenos de aire transmiten fuerza usando aire comprimido almacenado en los tanques y liberado por las líneas de freno hacia las cámaras."},"65":{"q":"Conduzco un camión cargado con frenos de aire cuando se rompe una línea y mi presión de aire baja por completo hasta cero. Un aprendiz que va conmigo pregunta por qué este sistema se considera más seguro que los frenos hidráulicos de su camioneta. ¿Qué afirmación explica MEJOR la verdadera ventaja de seguridad de mi sistema de frenos de aire en esta situación exacta?","options":["Como el aire es el fluido de trabajo, mis frenos de servicio seguirán funcionando con normalidad incluso después de que se haya fugado todo el aire del sistema.","El zumbador de advertencia de baja presión de aire es lo que físicamente detiene el camión una vez que la presión cae por debajo de 60 psi.","A medida que la presión de aire cae al rango de 20 a 45 psi, los frenos de resorte (de emergencia) se aplican automáticamente y detienen el camión.","Los frenos de aire están diseñados para detener siempre un camión cargado en una distancia más corta que los frenos hidráulicos, sin importar la fuga."],"explanation":"Cuando la presión de aire baja al rango de 20 a 45 psi, los frenos de resorte (de emergencia) se aplican automáticamente y detienen el vehículo."},"66":{"q":"Voy circulando por la autopista en un tractocamión cargado cuando se revienta una línea y mi presión de aire se vacía por completo. A medida que el sistema se queda sin aire, ¿qué pasará con mis frenos de resorte (de estacionamiento)?","options":["No les pasa nada, porque los frenos de resorte solo funcionan como mis frenos de servicio cuando piso el pedal","Permanecen liberados, porque los potentes resortes necesitan la presión de aire almacenada para mantenerlos apretados","Se liberan por completo, porque perder el aire es justo lo que suelta los resortes y deja rodar el camión","Se aplican automáticamente, porque los resortes aprietan los frenos en cuanto se acaba el aire que los mantenía liberados"],"explanation":"Los frenos de resorte se mantienen sueltos por la presión de aire, así que al perderse ese aire los resortes aplican los frenos automáticamente como medida a prueba de fallos."},"67":{"q":"Estoy haciendo una revisión de frenos con el motor apagado y el sistema totalmente cargado. Sigo pisando y soltando el pedal del freno para purgar el aire de los tanques mientras observo cómo baja el manómetro. A medida que la aguja sigue cayendo, ¿a qué presión aproximada debo esperar que la válvula de protección del tractor se cierre automáticamente y corte el suministro de aire al remolque?","options":["Entre unos 20 y 45 psi, cuando la presión baja al rango inferior","Entre unos 60 y 80 psi, justo cuando está activa la advertencia de baja presión","Entre unos 100 y 125 psi, cerca de la banda normal de operación del regulador","Entre unos 5 y 10 psi, solo después de que el manómetro marque casi vacío"],"explanation":"La válvula de protección del tractor y el suministro de aire al remolque se cierran automáticamente cuando la presión del sistema baja al rango de 20 a 45 psi."},"68":{"q":"Estoy enganchado a un remolque cargado y termino mi inspección previa al viaje dentro de la cabina. Para cargar el sistema de aire del remolque y liberar sus frenos antes de arrancar, debo presionar un control específico del tablero. ¿De qué color y forma es la perilla que debo presionar para suministrar aire al remolque?","options":["La perilla amarilla en forma de rombo, porque ese control envía aire a los frenos del remolque","La perilla roja, de ocho lados (octágono), porque ese es el control de suministro de aire al remolque","La perilla azul y redonda, porque la línea de servicio al remolque tiene el código de color azul","La perilla amarilla de ocho lados (octágono), porque el suministro del remolque comparte la forma del control de estacionamiento"],"explanation":"El control del suministro de aire al remolque es la perilla roja de ocho lados (octágono) que carga el sistema de aire del remolque y suelta sus frenos."},"69":{"q":"Acabo de estacionar mi tractocamión con remolque en un área de descanso y estoy por apagar el motor. Para activar el freno de estacionamiento (de resorte) y que la unidad no se mueva, ¿qué control del tablero debo jalar hacia afuera?","options":["El botón azul redondo que libera la presión del freno de servicio","La perilla roja de ocho lados (octágono) junto a los indicadores del tablero","La perilla amarilla con forma de diamante (rombo) del panel de control","La palanca verde cuadrada junto a la válvula de mano del remolque"],"explanation":"El control del freno de estacionamiento (de resorte) es la perilla amarilla en forma de rombo, que se jala para aplicar y se empuja para soltar los frenos de resorte."},"70":{"q":"Durante mi inspección previaje, el motor se apaga y el compresor deja de girar, pero noto que mi tanque de suministro conserva su presión en lugar de purgarla de regreso hacia el compresor apagado. ¿Qué componente es responsable de este comportamiento?","options":["La válvula de alivio de seguridad, que atrapa el aire del tanque cuando detecta que el compresor se ha detenido","El regulador (gobernador), que cierra el tanque de suministro una vez que alcanza la presión de corte","La válvula de drenaje automática, que se cierra herméticamente para encerrar el aire almacenado dentro del tanque","La válvula de retención de un solo sentido, que impide que el aire fluya de regreso hacia el compresor detenido"],"explanation":"La válvula de retención de un solo sentido solo deja que el aire fluya hacia el tanque, así que impide que el aire almacenado se escape cuando el compresor se detiene."},"71":{"q":"Es una gélida mañana de enero en Amarillo, y mi despachador me dice que mi tractor está equipado con un evaporador de alcohol en el sistema de frenos de aire. Mientras hago mi inspección previaje, me preguntan qué hace realmente este dispositivo por mí en estas condiciones. ¿Qué afirmación explica MEJOR su propósito?","options":["Introduce alcohol en el sistema de aire para reducir la probabilidad de que se forme hielo en las líneas y válvulas en clima frío","Quema alcohol para calentar los tambores de freno y que los frenos de estacionamiento no se congelen en el frío","Agrega alcohol al aire para absorber la humedad, así ya no necesito drenar los tanques de aire a diario","Libera vapor de alcohol que aumenta la salida del compresor para que la presión suba más rápido cuando hace frío"],"explanation":"El evaporador de alcohol introduce alcohol en el sistema de aire para reducir la posibilidad de que se forme hielo en las líneas y válvulas en clima frío."},"72":{"q":"Durante mi inspección previaje, estoy rastreando el conjunto del freno de fundación (foundation brake) en una de las ruedas de mi tractocamión con frenos de aire. Al aplicar el freno, observo que el ajustador de holgura (slack adjuster) gira un eje que hace girar una leva en forma de S, la cual empuja las zapatas y forros hacia afuera contra la cara interior del tambor. Mientras confirmo que cada pieza esté presente y funcione, ¿cuál de los siguientes elementos NO debería esperar encontrar en este freno de fundación de leva en S?","options":["El ajustador de holgura que convierte el recorrido de la varilla en rotación de la leva del freno","Un cilindro maestro hidráulico que presuriza líquido para empujar las zapatas hacia afuera","El tambor de freno contra el cual las zapatas presionan para crear fricción de frenado","Las zapatas y forros de freno que son empujados contra el tambor al frenar"],"explanation":"El freno de base de aire con leva en S es puramente mecánico-neumático y sin líquido, por lo que no tiene cilindro maestro hidráulico."},"73":{"q":"Voy bajando una pendiente larga y empinada con un remolque cargado cuando los frenos de servicio se debilitan y el pedal se ablanda. Mi vehículo tiene una válvula de control modulante. En esta situación, ¿qué me permite hacer realmente esa válvula?","options":["Bombear los frenos de servicio repetidamente para recuperar la presión de aire en las líneas antes de que fallen del todo","Anular el regulador para que el compresor corte por encima de 125 psi y restablezca mi capacidad de frenado","Aplicar los frenos de resorte (de emergencia) de forma gradual con la palanca de control en lugar de que actúen de golpe","Desactivar el ABS para que las ruedas se bloqueen y reduzcan la velocidad más rápido en la bajada"],"explanation":"La válvula de control modulante permite aplicar gradualmente los frenos de resorte (emergencia) con la palanca para frenar de forma controlada si fallan los frenos de servicio."},"74":{"q":"Conduzco un camión rígido cargado cuando noto que se enciende la luz de advertencia de baja presión de aire y suena el zumbador. En una inspección previa al viaje había visto una pequeña fuga de aire que creí insignificante. Comparado con cómo se comportaría un sistema de frenos hidráulicos ante una fuga pequeña similar, ¿qué debo esperar ahora de mis frenos de aire?","options":["Los frenos fallarán por completo en el instante en que empiece la fuga, igual que un sistema hidráulico, de modo que no me queda capacidad de frenado utilizable","La pérdida de presión de aire no da ninguna advertencia, así que la luz y el zumbador deben señalar otra falla no relacionada","La fuga no puede confirmarse realmente mientras conduzco, así que debo seguir a velocidad hasta poder estacionar e inspeccionar las líneas","Los frenos siguen funcionando mientras quede presión de aire, y la advertencia me avisa para detenerme con seguridad antes de que baje demasiado"],"explanation":"Los frenos de aire siguen funcionando mientras quede presión de aire utilizable, y la advertencia de baja presión debe activarse antes de que la presión baje de 60 psi para detenerse con seguridad."},"75":{"q":"Estoy haciendo la parte de frenos de aire de mi inspección previaje en un tractor sencillo. Ya drené los tanques y subí la presión hasta el corte del gobernador (cut-out). Antes de salir del patio, ¿qué conjunto de funciones de freno debo confirmar todavía que funcionan realmente para completar la inspección de frenos de aire?","options":["La advertencia de baja presión de aire, los frenos de resorte (de estacionamiento) y los frenos de servicio","Solo los frenos de resorte (de estacionamiento) y los de servicio, ya que la advertencia se autocomprueba al arrancar","Solo la advertencia de baja presión y los frenos de servicio, ya que los frenos de resorte se activan solos","Solo los frenos de servicio, porque un pedal firme a 5 mph demuestra que todo el sistema está bien"],"explanation":"Una revisión completa de frenos de aire debe confirmar tres cosas: la advertencia de baja presión, los frenos de resorte (estacionamiento) y los frenos de servicio."},"76":{"q":"Acabo de comprar un camión rígido equipado con frenos de aire y ya tengo una CDL válida que obtuve en un vehículo con frenos hidráulicos. Antes de poder conducir legalmente este camión con frenos de aire, ¿qué paso adicional me exige Texas que NO se aplicaba a mi antiguo vehículo con frenos hidráulicos?","options":["Nada adicional — mi CDL actual ya cubre cualquier sistema de frenos, así que puedo conducirlo tal cual","Debo aprobar el examen de frenos de aire (sin restricción), o mi licencia llevará una restricción de frenos de aire","Solo necesito añadir una designación Class C para ajustarme al menor tamaño del camión","Debo obtener un aval (endorsement) de motocicleta por separado antes de operar cualquier unidad con frenos de aire"],"explanation":"Debes aprobar el examen de conocimientos y destrezas de frenos de aire, o el estado pondrá una restricción de frenos de aire en tu licencia que te prohíbe conducir vehículos con frenos de aire."},"77":{"q":"Voy conduciendo con un remolque cargado por una autopista mojada cuando un auto se mete delante de mí y frena en seco. Piso el pedal del freno con fuerza y se activa el ABS de mi tractocamión con remolque. En ese momento de frenado fuerte, ¿qué debo esperar realistamente que el ABS haga por mí?","options":["Que reduzca drásticamente mi distancia total de frenado para que me detenga mucho antes del auto de adelante","Que aplique los frenos por mí automáticamente incluso antes de que yo pise el pedal","Que evite que mis ruedas se bloqueen para que pueda seguir dirigiendo y esquivar el peligro mientras freno con fuerza","Que asuma el papel de mis frenos de servicio principales una vez que el pedal esté pisado a fondo"],"explanation":"El ABS evita que las ruedas se bloqueen al frenar fuerte, así mantienes el control de la dirección y puedes esquivar un peligro."},"78":{"q":"Conduzco un camión rígido con un sistema de frenos de aire de un solo circuito y el motor se apaga en un tramo tranquilo de la carretera. Mientras me dejo rodar hacia el arcén, no le quito el ojo al manómetro de presión de aire, sabiendo que el aire se irá agotando lentamente al no estar funcionando el compresor. ¿A qué presión aproximada debo esperar que se active POR PRIMERA VEZ la advertencia de baja presión de aire (la luz y el zumbador), avisándome de que estoy perdiendo mi reserva de aire?","options":["Unas 100 psi, el punto donde el regulador normalmente vuelve a activar el compresor","Unas 125 psi, el punto donde el regulador normalmente desactiva el compresor","Unas 30 psi, cuando los frenos de resorte están a punto de aplicarse automáticamente","Unas 60 psi, mucho antes de que la presión llegue a un nivel peligrosamente bajo"],"explanation":"La advertencia de baja presión de aire debe activarse a unos 60 psi, mucho antes de que la presión llegue a niveles peligrosamente bajos."},"79":{"q":"Estoy haciendo mi inspección previaje y tratando de imaginar qué es lo que realmente acciona mis frenos de aire cuando piso el pedal. Mientras mi motor, mis indicadores y mis líneas estén en buen estado, mis frenos de aire seguirán deteniendo el camión mientras siga siendo suficiente, ¿cuál de los siguientes?","options":["La presión de aire acumulada y almacenada en los tanques (depósitos)","El líquido de frenos hidráulico en el cilindro maestro","La presión del aceite del motor que alimenta el circuito de frenos","La carga de la batería de 12 voltios que alimenta las válvulas de freno"],"explanation":"Los frenos de aire se aplican y mantienen con la presión de aire comprimido acumulada y almacenada en los tanques, no con líquido."},"80":{"q":"Durante mi inspección previaje, sigo el sistema de frenos de aire en un eje con frenos de tambor. Recorro el camino desde la cámara de freno, pasando por la varilla de empuje (pushrod), hasta el ajustador de holgura (slack adjuster), que hace girar un eje en la rueda. Al final de ese eje encuentro una pieza con forma de S situada entre las dos zapatas de freno. Cuando aplico el freno, ¿cuál es la ÚLTIMA acción mecánica que realmente fuerza las zapatas contra el tambor para frenar la rueda?","options":["La varilla de empuje sale de la cámara de freno y presiona directamente las zapatas contra el tambor","La leva en S (S-cam) gira y separa las dos zapatas de freno, presionando sus forros contra la cara interior del tambor","El líquido hidráulico del cilindro maestro empuja un pistón de rueda que aprieta las zapatas contra el tambor","El ajustador de holgura aprieta un par de pastillas contra un disco montado en el cubo de la rueda"],"explanation":"La presión de aire mueve la varilla y el ajustador para girar la leva en S, que separa las zapatas y presiona sus forros contra el interior del tambor."},"81":{"q":"Durante mi inspección previaje noto que mi tractocamión tiene varios tanques metálicos montados a lo largo del chasis, separados del motor y del sistema de combustible. Un conductor nuevo me pregunta para qué sirven realmente estos tanques de suministro (almacenamiento) en el sistema de frenos de aire. ¿Qué respuesta explica correctamente su función?","options":["Generan y presurizan el aire, asumiendo el trabajo de bombeo cada vez que el compresor llega al corte del gobernador a unas 125 psi","Eliminan el agua y el aceite del aire, por lo que las líneas nunca necesitan drenarse al final del día","Guardan la reserva de aire comprimido para que siempre haya suficiente presión disponible para accionar los frenos","Detectan la presión baja y activan la luz y el zumbador de advertencia antes de que el aire baje de unas 60 psi"],"explanation":"Los tanques de suministro guardan una reserva de aire comprimido para que siempre haya suficiente presión para accionar los frenos de servicio, estacionamiento y emergencia."},"82":{"q":"Conduzco un camión rígido cargado cuando se rompe una línea de aire principal. La aguja del manómetro baja sin parar, la luz y el zumbador de baja presión de aire ya se activaron, y no toco el pedal del freno. A medida que la presión sigue cayendo, ¿qué hace que mi camión se detenga por sí solo?","options":["Los frenos de servicio se aplican solos a través de la válvula de pie en cuanto la aguja pasa el punto de corte del regulador","La válvula de alivio de seguridad libera el sistema, lo que mecánicamente fuerza los frenos de servicio contra los tambores","El circuito de aviso de baja presión activa los frenos en el instante en que se encienden la luz y el zumbador","Los frenos de resorte se aplican automáticamente en cuanto la presión que cae llega al rango bajo donde los resortes toman el control"],"explanation":"Los frenos de resorte se mantienen sueltos por el aire, así que cuando la presión por fuga baja al rango bajo (unos 20-45 psi) los resortes aplican los frenos automáticamente."},"84":{"q":"Durante un reparto, mi luz de advertencia de baja presión de aire se enciende de repente y noto que uno de mis dos manómetros de presión de aire baja rápidamente mientras el otro se mantiene estable. Mi vehículo tiene un sistema de frenos de aire dual. ¿Qué afirmación explica MEJOR por qué todavía tengo algo de capacidad de frenado en este momento?","options":["El sistema está dividido en dos circuitos separados, por lo que la pérdida del circuito averiado no inhabilita el circuito que sigue manteniendo presión","Ambos circuitos toman aire de un solo tanque grande compartido, por lo que el manómetro estable devuelve aire al lado averiado","Un freno hidráulico de respaldo se activa automáticamente cada vez que un circuito de aire pierde presión","El sistema dual elimina el freno de estacionamiento, por lo que todo el aire restante se desvía a los frenos de servicio"],"explanation":"Un sistema de frenos de aire dual tiene dos circuitos independientes, por lo que una fuga o falla en un circuito no vacía el otro, que mantiene presión y frena su parte del vehículo."},"85":{"q":"Acabo de arrancar el motor de mi tractocamión en un patio frío. La luz de advertencia de baja presión de aire está apagada, pero mi manómetro aún marca solo 65 psi cuando me preparo para salir del estacionamiento. Según el procedimiento del DPS de Texas, ¿cuál es la presión MÍNIMA que debo dejar acumular antes de empezar a conducir?","options":["65 psi, porque la luz de advertencia de baja presión de aire ya se apagó","Unas 100 psi, para que haya suficiente aire para operar los frenos con seguridad","Unas 60 psi, el punto en que se apaga la advertencia de baja presión de aire","Unas 125 psi, el corte del gobernador, antes de soltar el freno de estacionamiento"],"explanation":"Deje que la presión de aire suba a por lo menos unas 100 psi antes de conducir para que haya suficiente aire para operar con seguridad los frenos de servicio y de emergencia."},"86":{"q":"Durante mi inspección previaje en un camión rígido sencillo, cargo el sistema de aire hasta unas 125 psi, apago el motor y coloco calzos en las ruedas. Dejo la perilla del freno de estacionamiento metida para que los frenos queden liberados, y observo el manómetro del tablero. En el primer minuto la aguja baja más de 4 psi. ¿Qué me indica esto sobre el vehículo?","options":["No pasa nada; con el motor apagado el aire de los tanques simplemente se enfría y se contrae, así que una caída de este tamaño en el primer minuto es lo esperado.","La lectura demuestra que los frenos de resorte (de estacionamiento) se aplicaron correctamente, ya que la presión siempre se purga rápido en cuanto se activa el sistema de estacionamiento.","El sistema pierde aire más rápido de lo permitido; con los frenos liberados un vehículo sencillo no debe perder más de 2 psi por minuto, y más de 4 psi significa una fuga que hay que localizar y reparar.","Esto confirma que el gobernador llegó al punto de corte y detuvo el compresor, que es la forma normal en que se comporta la presión después de apagar el motor."],"explanation":"Con los frenos liberados un vehículo solo debe perder no más de 2 psi por minuto, así que una pérdida mayor a 4 psi indica una fuga de aire que se debe encontrar y reparar."},"87":{"q":"Estoy estacionado en un muelle de carga cuando una fuga lenta de aire vacía mis tanques de suministro y la presión del sistema sigue cayendo hacia cero. A medida que se escapa la presión, ¿qué hace mi sistema de frenos de aire para evitar que el camión ruede, y por qué? Elija el enunciado VERDADERO.","options":["Los frenos de servicio usan líquido hidráulico almacenado para sujetar las ruedas, así que el camión queda quieto incluso sin aire en los tanques.","Nada sujeta el camión una vez que se va la presión; esa sola fuga pequeña suelta al instante todos los frenos y el vehículo queda libre para rodar.","El compresor bombea automáticamente la fuga de vuelta hasta 125 psi, así que los frenos de servicio del pedal mantienen el vehículo detenido por sí solos.","Los frenos de resorte (de estacionamiento) se aplican automáticamente cuando la presión baja al rango de 20-45 psi, sujetando las ruedas mecánicamente sin aire alguno."],"explanation":"Los frenos de estacionamiento de resorte se mantienen sueltos con aire, así que al caer la presión al rango de 20-45 psi unos resortes potentes aplican los frenos automáticamente y sostienen las ruedas sin aire."},"88":{"q":"Acabo de arrancar el motor de mi tractor con frenos de aire y el manómetro de presión de aire marca solo 50 psi, mientras la alarma sonora de baja presión sigue sonando. Estoy estacionado, cargado y voy retrasado para mi entrega. ¿Qué debo hacer antes de soltar el freno de estacionamiento y salir del patio?","options":["Esperar, con el motor en marcha, hasta que la presión suba a unos 100 psi y la alarma de baja presión se apague","Salir despacio con 50 psi, ya que los frenos seguirán acumulando presión mientras conduzco hacia la entrega","Abrir las válvulas de drenaje de los tanques para purgar el aire atrapado y que el compresor llene los tanques más rápido","Desconectar la alarma sonora de baja presión para que deje de sonar y conducir una vez que cese el ruido"],"explanation":"Mantenga el motor en marcha y espere hasta que la presión suba a unas 100 psi y se apague la advertencia de aire bajo antes de conducir."},"89":{"q":"Voy bajando una pendiente larga de montaña con una combinación cargada y he mantenido una presión constante en el pedal del freno todo el trayecto. Cerca del final, el pedal todavía se siente firme pero el camión apenas reduce la velocidad cuando lo piso. ¿Qué explicación describe MEJOR por qué mis frenos han perdido su poder de frenado?","options":["El frenado continuo elevó la presión de aire del sistema por encima del corte del regulador, así que los frenos ya no pueden generar suficiente fuerza","El frenado continuo sobrecalentó los tambores y las balatas de freno, y ese calor reduce la fricción que los frenos pueden producir","El frenado constante vació poco a poco los tanques de aire, y los frenos de resorte se soltaron parcialmente para compensar","Los ajustadores de holgura se apretaron por el calor, separando las balatas de los tambores"],"explanation":"El frenado continuo sostenido en una bajada larga sobrecalienta los tambores y forros, y ese calor reduce la fricción que los frenos pueden producir, causando pérdida de frenado."},"90":{"q":"Me acerco a una señal de alto en mi camión con frenos de aire y piso el pedal del freno con firmeza. Hay un retraso notable antes de que realmente sienta que el camión empieza a frenar, aunque mi pie se movió al instante. Mi instructor llama a esto 'retardo de frenado' (brake lag). ¿Qué está ocurriendo en realidad durante ese retraso?","options":["Mis reguladores de holgura (slack adjusters) están desajustados, por lo que las varillas asientan las zapatas demasiado lento","Mi tiempo de reacción como conductor es lo que crea el retraso entre decidir y frenar","El aire tarda una fracción de segundo en recorrer las líneas y llegar a los frenos","La presión de aire bajó por debajo del punto de reactivación, así que el gobernador debe represurizar primero"],"explanation":"El retardo de frenado es el medio segundo aproximado que tarda el aire comprimido en viajar por las líneas desde el pedal hasta las cámaras de freno, una característica normal de todo sistema de frenos de aire."},"91":{"q":"Durante mi inspección previaje en un tractocamión antiguo con frenos de aire, dejo que se acumule el aire, apago el motor y empiezo a bombear los frenos para bajar la presión. Cuando la aguja del manómetro cae hacia 60 psi, un pequeño brazo mecánico baja de repente a mi campo de visión sobre el parabrisas. El instructor lo llama 'wig-wag'. ¿Cuál es el propósito de este dispositivo?","options":["Es el gobernador indicando que el compresor llegó al corte y dejó de bombear aire a los tanques","Es la válvula de control modulante bajando para permitirme aplicar gradualmente los frenos de resorte en una emergencia","Es la válvula de drenaje automático liberando el agua y el aceite que se acumulan en el tanque de suministro","Es una advertencia mecánica de baja presión de aire que cae físicamente al campo de visión para avisarme de que la presión está bajando peligrosamente"],"explanation":"Un wig-wag es una advertencia mecánica de aire bajo cuyo brazo accionado por resorte cae al campo de visión del conductor para señalar que la presión de aire está peligrosamente baja."},"92":{"q":"Durante mi inspección previaje, piso el pedal del freno y observo el mecanismo de freno en una rueda. A medida que el aire llena la cámara de freno, la varilla de empuje (push rod) se extiende hacia afuera. En un freno de tambor de leva en S que funciona correctamente, ¿qué es lo SIGUIENTE que debe hacer este movimiento de la varilla?","options":["Girar el ajustador de holgura (slack adjuster), que hace girar la leva en S y presiona las zapatas contra el tambor","Empujar las zapatas directamente contra el tambor sin que intervenga ninguna leva ni palanca","Abrir la cámara del freno de resorte para que los resortes de estacionamiento ayuden a aplicar los frenos de servicio","Enviar aire comprimido adicional al tanque de suministro para mantener la presión del sistema"],"explanation":"El aire en la cámara de freno empuja la varilla de empuje, que gira el ajustador de holgura y tuerce la leva en S, forzando las zapatas de freno contra el tambor."},"93":{"q":"Acabo de comprar un tractocamión de 2020 con frenos de aire y estoy rastreando el cableado del ABS para confirmar que el sistema antibloqueo cumple el requisito federal para un vehículo tan nuevo. Al revisar cada eje, ¿en qué ruedas estoy obligado a encontrar ABS?","options":["Solo en las ruedas delanteras (de dirección), ya que ahí el bloqueo causaría la pérdida de la dirección","En todas las ruedas del tractocamión, ya que los tractores nuevos deben tener ABS en cada rueda","Solo en las ruedas traseras de tracción, ya que ahí ocurre la mayor carga de frenado","En ninguna rueda, porque el ABS es un equipo opcional que el comprador añade después"],"explanation":"El ABS es obligatorio en cada rueda de los tractocamiones fabricados a partir del 1 de marzo de 1997, así que un tractor más nuevo debe tener ABS en todas las ruedas."},"94":{"q":"Durante la inspección previa al viaje de mi vehículo combinado, el tablero me indica que el ABS del propio tractocamión está bien, pero todavía necesito confirmar que el ABS del remolque funciona. El remolque se fabricó en 1999, así que tiene su propio ABS y una luz de avería separada que debo revisar. Al caminar alrededor del conjunto, ¿dónde debo buscar esa luz de avería del ABS del remolque?","options":["Montada en la parte delantera del remolque cerca del perno rey, para que mire hacia la cabina del tractocamión","En el tablero dentro de la cabina, justo al lado de la luz de advertencia del ABS del propio tractocamión","En el lado izquierdo o en la parte trasera izquierda del remolque, donde es visible durante el recorrido a pie","Dentro del tanque de aire del remolque, detrás de la válvula de drenaje manual"],"explanation":"En un remolque de 1999, la luz de falla del ABS se monta en el lado izquierdo o la parte trasera izquierda del remolque para que sea visible durante la inspección de recorrido."},"95":{"q":"Conduzco un camión de tonelaje medio equipado con un sistema de frenos hidráulicos asistidos por aire (air-over-hydraulic). Durante mi inspección previa al viaje, quiero entender qué hace realmente la parte de aire de este sistema para saber qué perderé si falla el suministro de aire. ¿Qué afirmación describe correctamente la función de la presión de aire en este montaje?","options":["La presión de aire circula por las pinzas para enfriar el líquido hidráulico y evitar que se sobrecaliente en bajadas largas","La presión de aire mantiene lleno el líquido hidráulico, reemplazando automáticamente el líquido que se pierde por sellos desgastados","La presión de aire acciona el compresor que recarga la batería para que la bomba hidráulica siempre tenga energía","La presión de aire actúa sobre el sistema hidráulico para potenciar (aumentar) la fuerza de frenado que el conductor aplica en el pedal"],"explanation":"En un sistema de aire sobre hidráulico, la presión del aire refuerza la fuerza que el conductor aplica en el pedal, que el líquido hidráulico transmite a los frenos de las ruedas."},"96":{"q":"Durante una inspección previaje, descubre que los ajustadores de holgura (slack adjusters) muestran un recorrido excesivo del vástago, lo que significa que los frenos están desajustados. Si conduce de todos modos y comienza a bajar una pendiente larga y empinada, ¿cuál es la consecuencia MÁS probable de este defecto?","options":["La potencia de frenado se reducirá y los frenos pueden fallar por completo a medida que se calientan en la bajada","Los frenos agarrarán con más fuerza de lo normal, aumentando el riesgo de bloquear las ruedas y derrapar","El sistema simplemente usará menos aire, por lo que puede bombear el pedal del freno más tiempo de forma segura en la bajada","La advertencia de baja presión de aire se activará antes, pero la fuerza de frenado en sí no se verá afectada"],"explanation":"Los frenos desajustados reducen la potencia de frenado y pueden desvanecerse y fallar por completo bajo carga térmica, como en una bajada larga y empinada."},"97":{"q":"Voy bajando una pendiente leve en mi camión con frenos de aire y piso el pedal del freno un poco más fuerte para reducir la velocidad. A medida que piso el pedal, uno de mis dos manómetros sube más cuanto más fuerte presiono. ¿Qué manómetro estoy mirando y qué me indica?","options":["El manómetro de presión de suministro, que me dice cuánto aire queda almacenado en mis tanques","El manómetro de presión de aplicación, que me dice cuánta presión de aire estoy aplicando a los frenos con el pedal","El manómetro de corte del gobernador, que me dice cuándo el compresor dejará de bombear a 125 psi","El manómetro de advertencia de aire bajo, que me dice que la presión está por caer debajo de 60 psi"],"explanation":"El manómetro de presión de aplicación muestra la presión de aire enviada a los frenos, por lo que su lectura sube al pisar más el pedal y baja al soltarlo."},"98":{"q":"Conduzco un tractocamión con frenos de aire a 55 mph por una autopista seca cuando veo un auto averiado adelante y piso el pedal del freno con fuerza. Un compañero insiste en que el medio segundo que tarda el aire en recorrer las líneas y aplicar los frenos apenas importa a velocidad de autopista. ¿Aproximadamente cuánta distancia de frenado ADICIONAL agrega ese retardo del freno a 55 mph, por encima de mis distancias de percepción, reacción y frenado efectivo?","options":["Ninguna que valga la pena contar: el retardo de medio segundo es demasiado corto para agregar distancia medible a 55 mph","Unos 12 pies: aproximadamente el largo del tractor antes de que los frenos agarren","Unos 32 pies: casi el largo del remolque se recorre antes de que los frenos actúen","Unos 60 pies: ya que la distancia del retardo sigue duplicándose al subir la velocidad"],"explanation":"Los frenos de aire tienen un retardo de aproximadamente medio segundo, por lo que a 55 mph el vehículo avanza unos 32 pies adicionales antes de que los frenos actúen."},"99":{"q":"Durante mi inspección previaje, apagué el motor con el sistema totalmente cargado y observo el manómetro. La aguja sigue bajando poco a poco y no se estabiliza, aunque todas las puertas están cerradas y no estoy pisando el pedal del freno. Antes de decidir si este camión es seguro para conducir, ¿qué condición me indica que tengo una fuga lo bastante grave como para NO salir a la carretera?","options":["El manómetro subió exactamente a 125 psi durante el llenado, así que la lenta caída posterior es solo el enfriamiento normal de los tanques","Oigo un leve silbido cerca del compresor, pero mientras no haya sonado el zumbador de baja presión, el sistema está bien para conducir","La presión solo baja hasta que el gobernador vuelve a activarse (cut-in), lo que demuestra que el compresor cubre la demanda","Con el motor apagado y los frenos liberados, la presión de aire no se mantiene estable y sigue cayendo por encima del índice de fuga permitido"],"explanation":"Con el motor apagado y los frenos liberados, la presión debe mantenerse estable; si sigue cayendo más allá de la tasa de fuga permitida, la fuga es demasiado grande para conducir con seguridad."},"100":{"q":"Durante mi inspección previaje, la alarma de baja presión de aire suena constantemente porque la presión no sube más allá de 70 psi, incluso con el motor en ralentí acelerado. Un mecánico me dice que el componente encargado de generar y bombear aire a los tanques ha fallado y debe reemplazarse. ¿A qué componente se refiere?","options":["El compresor de aire, que bombea aire a los tanques de almacenamiento para alimentar el sistema","El regulador (gobernador), que controla cuándo se bombea aire a los tanques de almacenamiento","El ajustador de holgura, que regula el flujo de aire a las cámaras de freno","La válvula de alivio de seguridad, que libera aire para mantener la presión del tanque"],"explanation":"El compresor de aire genera y bombea aire a los tanques de almacenamiento, por lo que cuando la presión no aumenta, el compresor es el componente que falla."},"101":{"q":"Durante mi inspección previaje, dejo el motor en marcha y observo cómo sube el manómetro de aire. A unos 125 psi el compresor deja de cargar aire al sistema, y después de aplicar varias veces el freno la presión baja a unos 100 psi y el compresor vuelve a bombear. ¿Qué componente es responsable de arrancar y detener el compresor a estas presiones?","options":["La válvula de alivio de seguridad, que libera aire cuando los tanques alcanzan unos 150 psi","El regulador (governor), que desactiva el compresor cerca de 125 psi y lo reactiva cerca de 100 psi","El dispositivo de advertencia de baja presión de aire, que avisa al compresor antes de que la presión baje de 60 psi","Los propios pistones de descarga del compresor, que fijan por sí solos la presión de trabajo del sistema"],"explanation":"El gobernador controla el compresor, desconectándolo a unas 125 psi y volviéndolo a conectar a unas 100 psi."},"102":{"q":"Durante mi inspección previaje, arranco el motor y observo cómo sube el manómetro de presión de aire mientras el compresor bombea. Estoy esperando que el gobernador (governor) llegue al corte (cut-out), el punto en que el compresor deja de agregar aire a los tanques. ¿En qué lectura aproximada del manómetro debería esperar que eso ocurra?","options":["Alrededor de 100 psi, ya que ahí es donde el gobernador controla el sistema","Alrededor de 150 psi, justo cuando el sistema alcanza su máxima presión segura","Alrededor de 125 psi, cuando el gobernador le indica al compresor que deje de bombear","Alrededor de 60 psi, justo cuando el dispositivo de advertencia se apaga y termina el bombeo"],"explanation":"La desconexión del compresor, el punto donde el gobernador detiene el bombeo, ocurre a unas 125 psi."},"103":{"q":"Estoy haciendo una inspección previaje a un vehículo sencillo con frenos de aire. Con el motor apagado, bombeo el pedal del freno para purgar la presión del sistema y observo cómo cae el manómetro. ¿En qué momento deben activarse la luz y el zumbador de advertencia de baja presión de aire para avisarme de que la presión se está volviendo peligrosamente baja?","options":["En cuanto el manómetro baje de 100 psi, ya que ahí es donde el regulador se activa para reponer aire","Cuando la presión caiga al rango de 20 a 45 psi, en el mismo instante en que se aplican los frenos de resorte","En el instante en que la presión suba por encima de 125 psi, donde el regulador corta y deja de bombear","Antes de que el manómetro baje de 60 psi, mientras todavía queda aire suficiente para detenerse con seguridad"],"explanation":"La advertencia de baja presión de aire debe activarse antes de que la presión baje de 60 psi, dejando suficiente aire para detener el vehículo de forma segura."},"104":{"q":"Durante mi inspección previaje, arranco el motor y observo cómo una de las agujas del tablero sube de forma constante hasta que el gobernador desconecta el compresor a unas 125 psi. Mirando de un lado a otro entre ese indicador y los demás, ¿qué lectura me está mostrando realmente este indicador en concreto?","options":["Cuánta presión de aire hay almacenada en este momento en los tanques de aire","Con cuánta fuerza piso el pedal del freno, es decir, la presión de aplicación","El punto en que se encenderá la luz de advertencia de baja presión de aire","Cuántos segundos tardó el aire en subir de 85 a 100 psi"],"explanation":"El manómetro de aire muestra cuánta presión de aire hay almacenada actualmente en los tanques de aire."},"105":{"q":"Es invierno y mi tractocamión con remolque tiene válvulas de drenaje manuales en sus tanques de aire. Acabo de terminar un turno largo y noto que se han acumulado agua y aceite del compresor en el sistema. Sabiendo que esto puede congelarse y dañar los componentes durante la noche, ¿cuándo debo abrir estas válvulas de drenaje manuales para extraer la humedad?","options":["Solo una vez por semana, ya que el secador de aire elimina la mayor parte de la humedad entre drenajes","Al final de cada día, drenando los tanques por completo antes de estacionar el vehículo","Solo cuando se enciende la luz de advertencia de baja presión de aire por debajo de 60 psi","Aproximadamente una vez al mes, o cada vez que noto que los tanques pierden aire visiblemente"],"explanation":"Vacíe por completo los tanques de aire con válvulas manuales al final de cada día para eliminar el agua y el aceite acumulados."},"106":{"q":"Durante mi inspección previaje, el examinador me pide nombrar los tres sistemas de frenado independientes que se combinan en un solo sistema de frenos de aire. Digo correctamente los frenos de servicio y los frenos de estacionamiento. ¿Cuál debo nombrar como tercer sistema para completar la respuesta?","options":["El sistema retardador, que frena el camión sin usar el pedal del freno","El sistema de doble circuito, que divide el aire en un suministro primario y otro secundario","El sistema de freno de emergencia, que detiene el camión si falla el suministro principal de aire","El sistema modulador, que me permite aplicar gradualmente los frenos de resorte"],"explanation":"Un sistema de frenos de aire combina tres sistemas: los frenos de servicio, los de estacionamiento y los de emergencia que detienen el vehículo si falla el suministro de aire."},"107":{"q":"Voy conduciendo un camión rígido cargado cuando se rompe una manguera y mi presión de aire sigue cayendo. La luz y el zumbador de advertencia de baja presión de aire ya llevan un rato sonando, y ahora siento que el camión frena con fuerza por sí solo a medida que los frenos de resorte (de estacionamiento/emergencia) se aplican automáticamente. EXCEPTO por una lectura exacta, ¿hasta qué rango aproximado de presión había bajado el aire en el momento en que esos frenos de resorte se activaron solos?","options":["Unos 100 psi, el punto donde normalmente se activaría (cut-in) el gobernador","Unos 60 psi, el mismo punto donde se activa por primera vez la advertencia de baja presión de aire","Unos 125 psi, el punto donde el gobernador se desconecta (cut-out) y deja de bombear","Unos 20 a 45 psi, donde los frenos de resorte se aplican automáticamente"],"explanation":"Los frenos de resorte se mantienen liberados por la presión de aire y se aplican automáticamente cuando la presión cae al rango de 20 a 45 psi."},"108":{"q":"Acabo de bajar mi camión cargado por una pendiente larga y empinada, usando los frenos de aire con fuerza todo el camino. Abajo entro a un área de descanso y noto que las ruedas desprenden un calor intenso. EXCEPTO una de estas, las demás son acciones correctas antes de salir de la cabina. ¿Qué acción debo EVITAR en este momento?","options":["Poner el freno de estacionamiento (de resorte) mientras los tambores de freno siguen muy calientes por el descenso","Calzar las ruedas y dejar que los frenos se enfríen antes de confiar en los frenos de resorte para retener","Dejar que la presión de aire suba de nuevo hasta el corte del gobernador antes de confiar en que el sistema retenga","Revisar el recorrido del vástago más tarde, ya que los frenos desajustados son el defecto más común de los frenos de aire"],"explanation":"Nunca aplique los frenos de estacionamiento (de resorte) cuando los tambores estén muy calientes, como justo después de una bajada pronunciada, porque puede dañarlos."},"109":{"q":"Estoy bajando una pendiente larga y empinada en un vehículo combinado cargado. Para controlar mi velocidad, sigo pisando y soltando el pedal del freno una y otra vez (\"bombeo\" o \"fanning\"). ¿Cuál de los siguientes es el resultado MÁS probable de hacer esto durante toda la bajada?","options":["Mis frenos se mantendrán más fríos porque tienen la oportunidad de soltarse y respirar entre cada aplicación","Mi presión de aire bajará porque cada vez que suelto el pedal escapa aire más rápido de lo que el compresor puede reponerlo, y al final agotaré mi aire","El compresor bombeará más rápido con cada liberación, así que mis tanques en realidad acumularán más aire cuanto más tiempo bombee","Nada cambia mientras me mantenga por encima del nivel de advertencia de baja presión de 60 psi durante toda la bajada"],"explanation":"No bombee los frenos en una bajada larga, porque cada liberación deja escapar el aire más rápido de lo que el compresor lo repone, agotando finalmente su aire."},"110":{"q":"Estoy conduciendo un tractocamión con remolque equipado con frenos de aire y piso fuerte el pedal del freno, pero noto que el vehículo no comienza a frenar en el instante en que mi pie mueve el pedal: hay una breve demora de aproximadamente medio segundo antes de que el frenado realmente empiece. Esta demora, causada porque el aire debe recorrer las líneas de freno hasta las cámaras, se conoce como:","options":["Desvanecimiento del freno (brake fade): la pérdida de potencia de frenado por tambores sobrecalentados en una bajada larga","Tiro del freno (brake pull): la tendencia del vehículo a desviarse hacia un lado al aplicar los frenos","Retardo del freno (brake lag): el tiempo que el aire necesita para recorrer las líneas antes de que los frenos actúen","Desbalance del freno: la fuerza de frenado desigual entre los ejes del tractor y los del remolque"],"explanation":"El retardo de frenado es el atraso de aproximadamente medio segundo causado porque el aire necesita tiempo para viajar por las líneas antes de que los frenos actúen."},"111":{"q":"Estoy comparando mi tractocamión con frenos de aire con el carro de un amigo que tiene frenos hidráulicos. Suponiendo la misma velocidad, carretera y tiempo de reacción, ¿cómo afecta el retraso de los frenos de aire de aproximadamente medio segundo a mi distancia TOTAL de frenado en comparación con el vehículo de frenos hidráulicos?","options":["No tiene ningún efecto, porque la distancia total de frenado la determinan solo la distancia de percepción y de reacción.","Reduce la distancia total de frenado aproximadamente a la mitad una vez que el aire llega a las cámaras de freno.","Acorta ligeramente la distancia total de frenado porque la presión del aire genera la fuerza de frenado más rápido.","Alarga ligeramente la distancia total de frenado porque se añade la distancia del retraso de frenado al total."],"explanation":"El retardo de frenado de aproximadamente medio segundo añade un tramo de distancia de retardo a la distancia total de frenado, unos 32 pies a 55 mph."},"112":{"q":"Durante mi inspección previaje, sigo cargando aire y veo cómo la aguja del manómetro sube más allá del corte del gobernador (governor). Algo falló y el compresor nunca deja de bombear, así que la presión sigue subiendo. ¿A qué presión aproximada debería abrirse la válvula de alivio de seguridad del tanque de suministro (tanque húmedo) para proteger el sistema de la sobrepresión?","options":["Unas 150 psi","Unas 125 psi","Unas 100 psi","Unas 60 psi"],"explanation":"La válvula de seguridad del tanque de suministro se abre a unos 150 psi para liberar el exceso de presión si falla el gobernador."},"113":{"q":"Durante mi inspección pre-viaje de los frenos de aire, el examinador me dice: \"aplica presión firme a la válvula de pie (foot valve) y manténla\" mientras observamos la tasa de fuga de aire. Miro los controles y pedales de la cabina. ¿A cuál me está diciendo el examinador que presione?","options":["A la perilla amarilla con forma de diamante del tablero, ya que es la que controla el suministro de aire para frenar","Al pedal de freno en el piso de la cabina, porque en un sistema de frenos de aire también se le llama válvula de pie o de pedal (foot/treadle valve)","Al pedal del acelerador, porque hay que subir la presión de aire antes de poder iniciar la prueba de fuga","Al pedal del embrague, ya que pisarlo es lo que libera los frenos de resorte para aplicar presión"],"explanation":"El pedal del freno en el piso de la cabina es el control del freno de servicio, también llamado válvula de pie o válvula de pedal."},"114":{"q":"Estoy conduciendo un tractocamión con un sistema de frenos de aire doble cuando, de repente, se encienden la luz y el zumbador de advertencia de baja presión de aire, indicándome que el sistema de aire primario ha perdido presión. ¿Cuál de las siguientes afirmaciones es VERDADERA sobre lo que puedo esperar de mis frenos en este momento?","options":["Tanto el sistema primario como el secundario se apagan juntos, así que no me queda nada de capacidad de frenado","Los frenos de resorte (de estacionamiento) bloquean de inmediato todas las ruedas, y debo girar el volante con fuerza para mantener el control","El sistema secundario sigue cargado y continuará proporcionando frenado, así que puedo frenar hasta detenerme de forma segura","Mi capacidad de frenado se duplica porque el sistema secundario descarga toda su presión de aire en las ruedas"],"explanation":"En un sistema de frenos de aire dual, el circuito secundario independiente permanece cargado cuando falla el primario, por lo que aún puede frenar el vehículo hasta detenerse con seguridad."},"115":{"q":"Durante mi inspección previaje, el sistema de aire está completamente cargado y el motor apagado. Quiero confirmar que el dispositivo de advertencia de baja presión de aire funciona correctamente antes de conducir. ¿Qué acción lo prueba correctamente?","options":["Arrancar el motor y dejar que el gobernador bombee hasta que se abra la válvula de alivio de seguridad, luego escuchar el zumbador","Pisar y mantener el pedal del freno con firmeza durante un minuto y observar el manómetro esperando un pico repentino de presión","Tirar de la perilla amarilla del freno de estacionamiento y confirmar que los frenos de resorte se activan antes de que suene la advertencia","Con el motor apagado, pisar y soltar el pedal del freno para purgar el aire y observar que la advertencia se active al llegar a 60 psi"],"explanation":"Con el motor apagado, bombee el pedal del freno para purgar el aire de los tanques y confirme que la advertencia de baja presión se active antes de que la presión baje de 60 psi."},"116":{"q":"Estoy conduciendo un camión rígido sencillo con un sistema de frenos de aire estándar cuando mi compresor de aire empieza a fallar y la presión sigue bajando. Mi luz y zumbador de advertencia de baja presión llevan ya un rato encendidos, y estoy reduciendo la velocidad para salirme de la carretera. ¿A qué presión aproximada debo esperar que los frenos de resorte (de estacionamiento) se apliquen solos y detengan el camión, EXCEPTO si ya he estacionado?","options":["En algún punto del rango de 20 a 45 psi","Justo por debajo de 60 psi, el mismo punto donde se enciende la luz de advertencia","Alrededor de 100 psi, cuando el regulador normalmente se activa","Cerca de 125 psi, cuando el regulador normalmente se desactiva"],"explanation":"Los frenos de resorte (estacionamiento/emergencia) se mantienen sueltos por el aire y se aplican automáticamente cuando la presión cae al rango de 20 a 45 psi."},"117":{"q":"Durante mi inspección previaje, estoy a punto de realizar la prueba de tasa de fuga de aire en mi vehículo sencillo. Arranqué el motor y el manómetro de aire marca ahora unas 90 psi y sigue subiendo. Antes de empezar a cronometrar la caída de presión, ¿qué debo hacer PRIMERO para que la prueba sea válida?","options":["Bombear el pedal del freno varias veces para purgar las líneas hasta la presión de conexión (cut-in) y entonces empezar a cronometrar","Dejar que el sistema siga cargando hasta que el gobernador corte (cut-out) cerca de 125 psi y luego apagar el motor","Drenar por completo todos los tanques de aire para medir la pérdida desde un sistema limpio y vacío","Aplicar el freno de estacionamiento y acelerar el motor hasta que la válvula de seguridad abra cerca de 150 psi"],"explanation":"La prueba de fuga de aire debe hacerse con el sistema totalmente cargado hasta el corte del gobernador, cerca de 125 psi, y el motor apagado para que el compresor no oculte una fuga."},"118":{"q":"Durante mi inspección previaje en un camión simple (recto), apago el motor, coloco calzos en las ruedas y cargo el sistema de aire hasta el corte del gobernador. Dejo el freno de estacionamiento liberado y observo el manómetro del tablero durante un minuto para revisar fugas. ¿Qué lectura me indica que la fuga sigue dentro del límite legal y puedo continuar?","options":["Una caída de hasta 3 psi en ese minuto es aceptable, ya que ese es el límite con frenos liberados para un vehículo simple","Cualquier caída es una falla; con el motor apagado y los frenos liberados el manómetro debe mantenerse perfectamente fijo","Una caída de no más de 2 psi en ese minuto está dentro del límite para esta prueba de vehículo simple con frenos liberados","Una caída de hasta 4 psi en ese minuto está bien porque los frenos están liberados, no aplicados"],"explanation":"Para un vehículo simple con los frenos sueltos, una pérdida de aire no mayor a 2 psi por minuto está dentro del límite permitido."},"119":{"q":"Durante mi inspección previaje de un camión de caja sencillo (unidad simple, sin remolque), cargué el sistema por completo hasta unos 125 psi, apagué el motor y pisé y mantuve presionado el pedal del freno. Ahora observo el manómetro de aire durante un minuto completo para verificar la tasa de fuga. Para aprobar esta prueba, la caída de presión que observe no debe superar:","options":["2 psi en ese minuto, ya que mantener el pedal pisado es el mismo estándar que la prueba con los frenos liberados","4 psi en ese minuto, que es el límite que se le permite perder a un camión sencillo","10 psi en ese minuto, siempre que la advertencia de baja presión nunca se active durante la prueba","3 psi en ese minuto, la pérdida máxima permitida para un vehículo sencillo con los frenos aplicados"],"explanation":"Con los frenos aplicados, un vehículo simple no debe perder más de 3 psi por minuto para estar dentro del límite."},"120":{"q":"Durante una inspección previa al viaje, tiro del ajustador de holgura (slack adjuster) y noto que tiene más de una pulgada de juego libre, lo que indica que los frenos están desajustados. Si conduzco sin corregir esto, ¿cuál es la consecuencia de seguridad MÁS directa que debo esperar?","options":["Los frenos funcionarán mal porque el recorrido excesivo de la varilla de empuje reduce la potencia de frenado","El zumbador de advertencia de baja presión de aire sonará antes de que la presión baje de 60 psi","El gobernador del compresor de aire no cortará el aire a unas 125 psi","Los frenos de resorte se aplicarán automáticamente cuando la presión caiga al rango de 20 a 45 psi"],"explanation":"Los ajustadores de holgura demasiado flojos causan un recorrido excesivo de la varilla de empuje, lo que reduce la fuerza de frenado en las ruedas y hace que los frenos funcionen mal."},"121":{"q":"Durante mi inspección previaje me meto debajo del remolque y le pido a mi ayudante que pise el freno con fuerza mientras observo la varilla de empuje de una cámara de freno. Quiero saber si el ajustador de holgura (slack adjuster) sigue dentro de especificación. ¿Aproximadamente cuánto puede desplazarse esa varilla antes de que deba considerar que los frenos están desajustados y mandarlos a servicio?","options":["Aproximadamente medio pie de recorrido antes de salirse de especificación","Aproximadamente 1 pulgada de recorrido antes de salirse de especificación","Aproximadamente 6 pulgadas de recorrido antes de salirse de especificación","Aproximadamente 2 pies de recorrido antes de salirse de especificación"],"explanation":"El recorrido de la varilla de empuje no debe superar aproximadamente 1 pulgada al frenar con fuerza; dentro de eso, el ajustador de holgura está en especificación."},"122":{"q":"Durante mi inspección previa al viaje, encuentro una grieta fina que atraviesa uno de mis tambores de freno y noto que la zapata de freno de esa rueda está desgastada casi hasta los remaches. Todavía tengo presión de aire completa y los frenos parecen aplicarse bien cuando piso el pedal. ¿Qué significa esta condición para mi vehículo?","options":["El vehículo se puede conducir mientras la presión llegue al corte del gobernador y la advertencia de baja presión funcione","Es aceptable por ahora porque los frenos aún se aplican con firmeza durante la prueba de parada a 5 mph","El vehículo está fuera de servicio y no debe conducirse hasta que se reparen el tambor agrietado y la zapata desgastada","Es seguro en condiciones secas, pero solo debe evitarse al conducir bajo la lluvia o en carreteras mojadas"],"explanation":"Un tambor agrietado o zapatas desgastadas hasta los remaches es una condición automática de fuera de servicio, y el vehículo no debe conducirse hasta reparar esas piezas."},"124":{"q":"Voy conduciendo con un remolque cargado por una autopista resbaladiza por la lluvia cuando el tráfico de adelante se detiene de golpe. Piso el pedal del freno hasta el fondo y mi camión está equipado con ABS (sistema antibloqueo). Según lo que el ABS está realmente diseñado para hacer, ¿cuál es el beneficio realista que debo esperar de él en esta frenada brusca?","options":["Acortará mi distancia total de frenado mucho más de lo que necesitaría el mismo camión sin ABS","Bombeará los frenos por mí, así que nunca tendré que usar frenado intermitente en esta superficie resbaladiza","Reducirá la marcha automáticamente y mantendrá mi presión de aire para que los frenos de resorte nunca se activen","Evitará que mis ruedas se bloqueen, para que todavía pueda esquivar el tráfico detenido con la dirección"],"explanation":"El ABS no acorta la distancia de frenado; evita que las ruedas se bloqueen al frenar con fuerza para que conserve el control de la dirección y pueda maniobrar alrededor de los peligros."},"125":{"q":"Durante una inspección previaje, sigo el recorrido del aire comprimido desde los tanques hacia una rueda. Quiero encontrar el único componente donde la presión de aire almacenada finalmente se convierte en la fuerza mecánica de empuje que mueve físicamente el varillaje del freno. ¿Qué componente busco?","options":["La cámara de freno, porque convierte la presión de aire en la fuerza mecánica que acciona los frenos","El ajustador de holgura (slack adjuster), porque es la pieza que se extiende para presionar las balatas contra el tambor","El compresor de aire, porque es la fuente de la presión que en última instancia alimenta los frenos","El gobernador (regulador), porque controla la presión de aire que se envía hacia la rueda"],"explanation":"La cámara de freno convierte la presión del aire comprimido en la fuerza mecánica que empuja la varilla para aplicar los frenos."},"126":{"q":"Durante mi inspección previaje, me meto debajo del remolque para revisar el recorrido de la varilla de empuje, porque los frenos desajustados son el defecto más común del sistema de frenos de aire. Sigo la varilla de empuje desde la cámara de freno y la encuentro empernada a un extremo del ajustador de tensión (slack adjuster). Para entender cómo mi fuerza de frenado realmente acciona el freno de la rueda, necesito saber qué hace girar el OTRO extremo de ese ajustador. ¿A qué componente conecta el ajustador de tensión la varilla de empuje?","options":["Al varillaje del pedal de freno, para que pisar el pedal jale la varilla hacia atrás","A la leva en S, que hace girar para separar las zapatas contra el tambor","Al secador de aire, que abre para liberar la humedad de la cámara","Al gobernador, al que le indica cortar el compresor a 125 psi"],"explanation":"El ajustador de holgura gira la leva en S, que separa las zapatas de freno contra el tambor para detener la rueda."},"127":{"q":"Durante mi inspección previaje, estoy revisando los frenos en cada rueda de mi tractocamión con remolque y noto una leva en forma de S que gira para empujar las zapatas hacia afuera contra un tambor giratorio. El examinador me pregunta por qué debo conocer este diseño antes que nada. ¿Cuál respuesta es correcta?","options":["Es el único diseño de freno de base que la FMCSA todavía permite en vehículos equipados con frenos de aire","Es un freno de base tipo cuña, que es con el que se fabrican hoy la mayoría de los vehículos combinados pesados","Es el freno de tambor con leva en S, el diseño de freno de base que se encuentra con mayor frecuencia en vehículos comerciales con frenos de aire","Es un freno de base de disco de aire, el tipo usado en la gran mayoría de los camiones que circulan hoy"],"explanation":"Una leva en S que gira para presionar las zapatas contra un tambor identifica el freno de tambor de leva en S, el freno de base más común en vehículos con frenos de aire."},"128":{"q":"Durante una inspección previaje, mi instructor me dice que cuando piso el pedal del freno, la presión de aire empuja una leva que presiona las zapatas de freno hacia afuera contra una pieza giratoria fijada a la rueda, y la fricción entre ellas frena el vehículo. ¿Contra qué pieza presionan las zapatas de freno para generar esa fricción de frenado?","options":["Contra el ajustador de holgura (slack adjuster), que las zapatas aprietan para transmitir la fuerza de frenado","Contra la cámara de freno, que las zapatas aprietan para sujetar la rueda","Contra el tanque de aire, que las zapatas presionan para liberar presión","Contra el tambor de freno, contra el cual las zapatas presionan para generar fricción"],"explanation":"Las zapatas de freno presionan hacia afuera contra el tambor de freno giratorio, y la fricción entre ellos frena y detiene el vehículo."},"129":{"q":"Durante mi inspección previa al viaje en un tractocamión sin remolque, termino de cargar el sistema de aire y quiero asegurar el vehículo para que no ruede mientras lo rodeo a pie. En el tablero, ¿qué control debo accionar y cómo?","options":["Jalar hacia afuera la perilla amarilla con forma de diamante para aplicar el freno de estacionamiento (de resorte)","Jalar hacia afuera la perilla roja de ocho lados para aplicar el freno de estacionamiento (de resorte)","Empujar hacia adentro la perilla amarilla con forma de diamante para aplicar el freno de estacionamiento (de resorte)","Presionar y mantener el pedal del freno, que bloquea mecánicamente los frenos de resorte"],"explanation":"El freno de estacionamiento (de resorte) es la perilla amarilla en forma de diamante que se jala para aplicar y se empuja para liberar."},"130":{"q":"Subo a mi tractocamión a primera hora de la mañana, arranco el motor y estoy listo para salir. La perilla amarilla con forma de diamante del freno de estacionamiento sigue afuera. Antes de empujar esa perilla para soltar los frenos de estacionamiento, ¿qué condición debo asegurarme de cumplir?","options":["El motor alcanzó la temperatura normal de funcionamiento y el indicador del refrigerante salió de la zona fría","La presión de aire subió lo suficiente para que el sistema esté totalmente cargado y la alerta de baja presión de aire se apagó","La presión del combustible se estabilizó y el diésel se cebó por completo a través de las líneas de inyección","La presión del aceite del motor subió a la franja normal para que los cojinetes queden bien lubricados"],"explanation":"Los frenos de resorte se liberan con presión de aire, por lo que el sistema debe estar totalmente cargado y la advertencia de aire bajo apagada antes de soltar el freno de estacionamiento."},"133":{"q":"Estoy haciendo una inspección previa al viaje de los frenos de aire y observo el manómetro del tablero para probar el gobernador. Bombeo los frenos para purgar el aire y el compresor vuelve a arrancar para empezar a recuperar la presión. ¿Aproximadamente en qué lectura del manómetro debo esperar que el gobernador se ACTIVE (cut-in) y el compresor vuelva a bombear?","options":["Unas 60 psi, justo cuando se encendería la advertencia de baja presión de aire","Unas 125 psi, en el mismo punto donde dejó de bombear antes","Unas 100 psi, algo por debajo del punto en el que se desactivó","Unas 20 psi, justo cuando los frenos de resorte empiezan a aplicarse"],"explanation":"El regulador se activa para reanudar el bombeo a unas 100 psi, algo por debajo de la presión de corte de aproximadamente 125 psi."},"134":{"q":"Durante mi inspección previaje en un tractocamión con sistema de frenos de aire dual, acelero el motor a ralentí rápido y observo cómo sube el manómetro del tablero. Quiero confirmar que la velocidad de acumulación de aire esté dentro de lo especificado. Al ver que la aguja pasa las 85 psi, ¿en qué momento debería haber alcanzado las 100 psi para que la acumulación se considere aceptable?","options":["En unos 3 segundos después de pasar las 85 psi","En unos 30 segundos después de pasar las 85 psi","En unos 60 segundos después de pasar las 85 psi","En unos 45 segundos después de pasar las 85 psi"],"explanation":"En un sistema de frenos de aire doble, la presión debe subir de 85 a 100 psi en unos 45 segundos, o el sistema tiene un problema."},"135":{"q":"Durante mi inspección previaje, el compresor de aire ha cargado mi tanque de suministro (húmedo), pero noto una fuga lenta que se desarrolla en una línea aguas abajo de mi tanque de servicio. Hay una válvula de retención unidireccional instalada entre los tanques. Mientras esa fuga purga el aire, ¿cuál es la función principal que esta válvula de retención cumple para mí?","options":["Impide que el aire ya almacenado en el tanque superior se drene hacia atrás a través de la sección con la fuga","Impide que la presión de aire suba por encima del punto de la fuga para que el sistema nunca se sobrepresurice","Evita que el aire que se fuga llegue a las cámaras de freno para que los frenos sigan aplicándose","Evita que el aire atrapado se enfríe y se congele dentro de las líneas durante la fuga"],"explanation":"Una válvula de retención de un solo sentido permite el flujo de aire en una sola dirección, sellando una fuga aguas abajo para que el aire almacenado en el tanque aguas arriba no se drene hacia atrás."},"136":{"q":"Durante mi inspección previaje, abro las válvulas de drenaje de mis tanques de aire y noto que un tanque en particular está constantemente lleno de agua y lodo de aceite, mucho más que los demás. Sabiendo cómo el sistema dirige el aire desde el compresor, ¿cuál es MÁS probable que sea este tanque?","options":["El tanque seco, porque está más abajo en el circuito y es donde la humedad finalmente se condensa tras enfriarse","El tanque húmedo (de suministro), porque recibe el aire directamente del compresor y es donde primero se acumula la mayor parte del agua","El tanque de combustible, porque la condensación de las líneas de aire drena de regreso a él durante la noche","El tanque que esté montado más bajo, ya que la gravedad arrastra hacia él toda el agua acumulada"],"explanation":"El tanque húmedo (de suministro) recibe aire caliente y cargado de humedad directamente del compresor, por lo que la mayor parte del agua y el aceite se condensan y acumulan allí primero."},"137":{"q":"Durante mi inspección previaje, estaciono en terreno plano, coloco las cuñas en las ruedas, aplico el freno de estacionamiento jalando la perilla amarilla en forma de rombo, luego quito las cuñas y avanzo suavemente hacia adelante contra el freno en una marcha baja. Si el freno de estacionamiento funciona correctamente, ¿qué debería pasar?","options":["El vehículo debería avanzar lentamente, demostrando que los frenos de resorte retienen presión parcial","Debería sonar el zumbador de baja presión de aire, confirmando que los frenos de resorte se activaron porque la presión bajó a tiempo","El vehículo debería quedarse quieto y no moverse, mostrando que el freno de estacionamiento lo mantiene en su lugar","El vehículo debería quedarse quieto solo después de que también presione y mantenga firme el pedal del freno de servicio"],"explanation":"Un freno de estacionamiento de resorte en buen estado se aplica con fuerza total y debe mantener el vehículo inmóvil al tirar suavemente en marcha baja."},"138":{"q":"Durante mi inspección previaje, suelto el freno de estacionamiento, dejo que el autobús avance lentamente hasta unas 5 mph en un terreno nivelado y quiero confirmar que mis frenos de servicio funcionan correctamente antes de salir. ¿Qué debo hacer en este momento?","options":["Bombear rápidamente el pedal del freno varias veces y escuchar cómo se libera el aire en cada ocasión","Mantener el pedal ligeramente presionado y dejar que el vehículo se detenga rodando despacio, vigilando que el manómetro se mantenga por encima de 60 psi","Acelerar primero hasta unas 20 mph para obtener una lectura de los frenos más realista, parecida a la de carretera","Pisar el pedal del freno con firmeza y comprobar que el vehículo se detiene recto sin desviarse hacia un lado y que el pedal se siente firme"],"explanation":"Un sistema de frenos de servicio en buen estado detiene el vehículo en línea recta sin desviarse hacia un lado, y el pedal se siente firme y no esponjoso."},"139":{"q":"Durante mi inspección previaje de los frenos de aire, avanzo rodando a unos 5 mph y piso el pedal del freno. El camión se detiene recto, pero el pedal se hunde y se siente blando y esponjoso bajo mi pie en lugar de firme. ¿Qué debo concluir de esta sensación del pedal?","options":["Probablemente indica un problema en el sistema de frenos que debe revisarse antes de conducir","Es normal porque los frenos de aire siempre se sienten más blandos que los frenos hidráulicos","Solo significa que la presión de aire está por encima del corte del gobernador de 125 psi","Muestra que los ajustadores de holgura han absorbido automáticamente el recorrido adicional"],"explanation":"Un pedal blando o esponjoso que se hunde indica un problema de frenos como aire en las líneas, baja presión o una fuga que debe corregirse antes de conducir."},"140":{"q":"Estoy terminando mi inspección previa al viaje y arranco el motor. La luz de fallo del ABS en el tablero se enciende al principio, pero nunca se apaga: permanece encendida al ralentí y después de haber alcanzado la presión completa. Según esto, ¿qué debo concluir sobre mi sistema de frenos antibloqueo?","options":["La luz solo confirma que se realizó el autodiagnóstico del ABS y que el sistema funciona perfectamente","El ABS podría no estar funcionando bien y debe inspeccionarse antes de conducir","La luz solo indica baja presión de aire, así que solo necesito dejar que el gobernador acumule más aire","La luz significa que los frenos de resorte están aplicados, así que se apagará al soltar la perilla de estacionamiento"],"explanation":"La luz de falla del ABS debe encenderse brevemente al arrancar y luego apagarse; si permanece encendida, el ABS puede estar averiado y debe inspeccionarse antes de conducir."},"141":{"q":"Voy conduciendo un tractocamión con remolque cargado cuando se enciende en mi tablero la luz de avería del ABS (sistema antibloqueo de frenos). Los frenos todavía se sienten normales, pero me preocupa lo que acaba de pasar. ¿Cuál de las siguientes opciones describe con MAYOR exactitud mi situación de frenado en este momento?","options":["He perdido toda capacidad de frenado y debo detenerme por inercia usando solo el motor y los cambios","Mi distancia de frenado ahora es automáticamente más corta, así que puedo frenar más tarde que antes","Todavía tengo mis frenos de servicio normales y puedo detener el vehículo, pero debo frenar con cuidado para no bloquear las ruedas","Solo funcionarán mis frenos de estacionamiento, así que debo jalar la perilla amarilla para detenerme"],"explanation":"Una falla del ABS solo desactiva la función antibloqueo, por lo que conserva los frenos de servicio normales completos pero debe frenar con cuidado para no bloquear las ruedas."},"142":{"q":"Durante mi inspección previaje, noto un recorrido excesivo del vástago (pushrod) en una de las cámaras de freno. Mi tractocamión está equipado con ajustadores de holgura automáticos (slack adjusters), que un compañero dice que 'no requieren mantenimiento', así que me dice que ya no debo preocuparme por ellos. ¿Qué afirmación refleja la forma correcta de tratar los ajustadores de holgura automáticos?","options":["Como se ajustan solos, eliminan la necesidad de cualquier inspección durante la revisión previaje","Debo aflojarlos manualmente mientras conduzco hasta que desaparezca el juego excesivo","Eliminan los frenos desajustados, así que mi compañero tiene razón y pueden ignorarse","Aún así deben revisarse con regularidad, porque los frenos desajustados son un defecto común incluso con ellos"],"explanation":"Los frenos desajustados son el defecto más común de los frenos de aire, por lo que incluso los ajustadores automáticos deben revisarse con regularidad ya que no son infalibles."},"143":{"q":"Durante mi inspección previaje, noto un recorrido excesivo de la varilla de empuje en un ajustador de tensión (slack adjuster), lo que me indica que los frenos están desajustados. Voy retrasado y las herramientas del taller están ahí mismo. ¿Quién debería realizar realmente el ajuste de los frenos antes de que este vehículo salga a la carretera?","options":["Únicamente una persona capacitada y calificada para ajustar frenos","Cualquier titular vigente de CDL, ya que tener la licencia demuestra competencia en frenos","Yo mismo, ahora mismo, porque el recorrido de la varilla es fácil de ajustar con las herramientas del taller","Quien esté más cerca y disponible para que el vehículo no se retrase más"],"explanation":"Como los frenos desajustados reducen directamente la potencia de frenado, el ajuste de frenos solo debe hacerlo una persona capacitada y calificada para ese trabajo."},"144":{"q":"Voy conduciendo mi tractocamión cuando se enciende la luz de advertencia de baja presión de aire y rápidamente me doy cuenta de que mi compresor de aire ha dejado de bombear por completo. Hay una salida con un acotamiento seguro a aproximadamente una milla. Suponiendo que mi sistema estaba totalmente cargado, ¿qué me permite hacer el aire de reserva de mis tanques?","options":["Seguir conduciendo con normalidad durante todo un día de viajes, ya que los tanques almacenan el suministro de un día","Hacer varias aplicaciones más de freno para reducir la velocidad y salir de forma segura antes de que la presión baje demasiado","Conducir indefinidamente, porque los frenos de resorte recargarán los tanques de servicio por mí","No obtener prácticamente ningún frenado útil, así que debo salirme de la carretera de inmediato justo donde estoy"],"explanation":"Los tanques de aire almacenan una reserva de aire comprimido para que, aun cuando el compresor se detenga, pueda hacer varias frenadas más y salir de la vía con seguridad."},"145":{"q":"Es una mañana helada de invierno y mi lista de inspección previa al viaje me recuerda que debo drenar los tanques de aire a diario para que el agua y el aceite del compresor no se acumulen ni congelen el sistema. Estoy parado debajo del tractocamión buscando las piezas correctas que debo abrir. ¿Qué dispositivo opero realmente para drenar el agua acumulada de los tanques de aire?","options":["La válvula de alivio de seguridad, que abro a mano para ventear la humedad del tanque de suministro (húmedo)","La perilla amarilla en forma de diamante de la cabina, que jalo hacia afuera para liberar el agua de los tanques","Las válvulas de drenaje, también llamadas llaves de purga (petcocks), ubicadas en la parte inferior de cada tanque de aire","El regulador (gobernador) del compresor de aire, que reinicio para que empuje hacia afuera el agua atrapada"],"explanation":"Los tanques de aire se drenan con las válvulas de drenaje, también llamadas petcocks, ubicadas en la parte inferior de cada tanque para eliminar el agua y el aceite acumulados."},"146":{"q":"Conduce un camión rígido cargado con frenos de aire por una carretera rural de Texas cuando se enciende la luz de advertencia de baja presión de aire y suena el zumbador. La aguja del manómetro baja hacia la zona de baja presión. ¿Cuál es la acción correcta?","options":["Seguir conduciendo a velocidad reducida hasta la próxima salida, ya que los frenos de resorte aún no se han aplicado y todavía le queda algo de aire","Continuar conduciendo pero bombear el pedal del freno varias veces para que el compresor recupere más rápido la presión de aire perdida","Mantener la velocidad e ignorar la alarma por ahora, porque la advertencia suele encenderse brevemente y se apaga sola cuando el regulador conecta","Detenerse en cuanto sea seguro y salir de la carretera, porque una caída continua de presión puede provocar una pérdida repentina y peligrosa de frenado"],"explanation":"Cuando se enciende la alarma de baja presión de aire y la presión cae, deténgase y salga de la vía en cuanto sea seguro, pues la pérdida continua puede causar una falla súbita de frenos."},"147":{"q":"Estoy haciendo la inspección previaje de mi tractocamión y un mecánico menciona que mis luces de freno (de alto) solo se encienden cuando piso el pedal del freno con suficiente fuerza. En un vehículo con frenos de aire, ¿qué activa físicamente ese interruptor eléctrico de la luz de freno para encender las luces?","options":["La presión de aire que sube en las líneas de freno al aplicar el pedal cierra el interruptor de la luz de freno","El movimiento mecánico del pedal del freno empuja directamente el interruptor para cerrarlo, igual que en un automóvil","La caída de presión de aire que ocurre cuando los frenos de resorte empiezan a soltarse cierra el interruptor","El calor generado en los tambores de freno le indica al interruptor que encienda las luces de alto"],"explanation":"En frenos de aire el interruptor de la luz de freno es eléctrico y funciona con aire; al pisar el pedal la presión que sube en las líneas lo cierra y enciende las luces de freno."},"148":{"q":"Una mañana fría, lo primero que hago es subir a mi tractocamión con remolque, arranco el motor y me preparo para soltar los frenos de resorte (de estacionamiento) y salir. Antes de presionar la perilla amarilla del freno de estacionamiento para soltar los frenos de resorte y conducir, ¿qué debe ser cierto sobre la presión de aire en mi sistema?","options":["La luz y el zumbador de baja presión acaban de apagarse, así que cualquier presión por encima de ese punto basta para soltar los frenos y conducir","La presión debe haber subido primero lo suficientemente alto, hasta el rango normal de operación cerca del corte del gobernador, antes de soltar los frenos de resorte","La presión solo necesita volver a subir por encima del rango de 20 a 45 psi donde se aplican los frenos de resorte, y entonces puedo soltarlos y arrancar","La presión debe bajarse lo más posible para que los frenos de resorte se liberen con facilidad, y luego suelto la perilla"],"explanation":"Los frenos de resorte se mantienen sueltos con aire, por eso la presión primero debe subir al rango normal de operación cerca del corte del gobernador antes de que se liberen."},"149":{"q":"Voy bajando una pendiente larga y empinada con un remolque cargado y he venido frenando con fuerza todo el camino. Cerca del fondo noto que los tambores de freno se han calentado mucho. ¿Cuál es el efecto MÁS probable que este sobrecalentamiento tendrá sobre mis frenos de aire?","options":["Los tambores se dilatan y presionan más fuerte contra las zapatas, dándome una frenada notablemente más potente","El calor seca la humedad de las líneas, por lo que los frenos responden de forma más rápida y firme","Los frenos se desvanecerán (fade): tendré que pisar cada vez más fuerte para obtener menos poder de frenado","Nada cambia mientras me muevo, pero los tambores calientes se agrietarán en cuanto me detenga y estacione"],"explanation":"Los tambores de freno sobrecalentados pierden su capacidad de convertir el movimiento en calor, por eso los frenos se desvanecen y hay que pisar más fuerte para frenar menos."},"150":{"q":"Voy conduciendo un tractocamión con remolque por la carretera cuando el remolque se desprende de repente, se rompen sus mangueras de aire y se vacía todo el aire del lado del remolque. ¿Qué dispositivo está diseñado para cerrar y proteger el suministro de aire de mi tractor de modo que me quede aire suficiente para controlar y detener el tractor?","options":["La válvula de relé, que acelera la aplicación de los frenos enviando aire a los frenos traseros en cuanto piso el pedal","La válvula de liberación rápida, que expulsa rápidamente el aire atrapado para que los frenos se suelten apenas dejo de pisar el pedal","La válvula de pie (pedal), que controla cuánta presión de aire de frenado envío cuando piso el pedal del freno","La válvula de protección del tractor, que cierra el suministro de aire del tractor para conservar aire suficiente para frenar y dirigir el tractor"],"explanation":"Si el remolque se desprende o tiene una fuga grave, la válvula de protección del tractor se cierra automáticamente para sellar el aire del tractor y dejar suficiente para frenar y dirigir."},"151":{"q":"Acaba de acoplar el tractor a un remolque cargado, conectó las líneas de aire y elevó la presión del sistema hasta el corte del gobernador (cut-out). Antes de mover el remolque, alcanza la perilla roja de ocho lados en el tablero. ¿Qué logra al EMPUJAR esta perilla hacia ADENTRO?","options":["Carga el sistema de frenos del remolque enviando aire desde el tractor hacia el remolque","Activa los frenos de resorte del remolque para que este permanezca estacionado","Libera solo los frenos de estacionamiento del tractor y deja el remolque bloqueado","Purga las líneas de aire del remolque para probar el zumbador de baja presión"],"explanation":"Empujar la perilla roja octagonal del suministro de aire del remolque abre la línea de suministro y envía aire del tractor para cargar el sistema de frenos del remolque."},"152":{"q":"Voy remolcando un remolque cargado cuando una fuga en la línea de suministro empieza a drenar mi aire. Mientras el manómetro sigue cayendo, quiero saber el punto en el que la válvula de protección del tractor se cerrará por sí sola para aislar el aire del tractor y proteger lo que queda en el sistema. ¿A qué presión aproximada ocurre ese cierre automático?","options":["A unas 60 psi, el mismo punto en que se encienden por primera vez la luz y el zumbador de advertencia de baja presión de aire","En el rango de 20 a 45 psi, después de que la advertencia ya lleva un rato sonando","A unas 100 psi, el nivel en que el regulador le indica al compresor que arranque y reanude el bombeo","A unas 150 psi, el nivel en que se abriría la válvula de alivio de seguridad del tanque de suministro"],"explanation":"La válvula de protección del tractor se cierra automáticamente cuando la presión cae al rango de 20 a 45 psi, después de que la alerta de aire bajo lleva ya un rato activa."},"153":{"q":"En mi inspección previaje, noto que las cámaras de freno traseras de mi remolque están montadas muy atrás, a un largo tramo de línea de aire de distancia de la válvula de freno de pie que está en la cabina. Un aprendiz me pregunta por qué, al pisar el pedal del freno, esos frenos traseros lejanos no tardan notablemente más en aplicarse que los delanteros, dada toda esa distancia extra que el aire debe recorrer. ¿Cuál es la explicación correcta?","options":["Los frenos traseros sí se aplican más lento por la distancia, por eso los frenos de aire usan un retardo de frenado incorporado de 5 segundos para compensar el largo recorrido de la línea de aire","Las cámaras delanteras y traseras están unidas por una válvula de equilibrio que retrasa a propósito los frenos delanteros para que ambos ejes suelten exactamente en el mismo instante","Una válvula de relevo montada cerca de las cámaras traseras usa una señal de aire local para aplicar esos frenos rápido, en vez de esperar el aire del pedal","Una válvula de freno de resorte retiene presión extra atrás para que esos frenos puedan aplicarse mucho antes de que el aire del pedal llegue siquiera hasta allí"],"explanation":"Una válvula de relevo montada cerca de las cámaras traseras aplica esos frenos con una señal de aire local, acelerando el frenado trasero en vez de esperar el aire del pedal."},"154":{"q":"Estoy haciendo una inspección previaje y noto que mi sistema de frenos de aire incluye una válvula de liberación rápida (quick-release valve) montada en el eje delantero, cerca de las cámaras de freno. Un mecánico me pide que explique qué hace realmente este componente para los frenos durante la operación normal. ¿Qué afirmación describe correctamente su propósito?","options":["Reduce la velocidad con que el aire llega a las cámaras de freno para que los frenos se apliquen de forma más suave","Retiene la presión de aire residual en las cámaras para que los frenos de resorte queden bloqueados al estacionar","Purga el aceite del compresor y el agua de las líneas para evitar que los frenos delanteros se congelen","Permite que el aire salga rápidamente de las cámaras de freno para que los frenos se suelten más rápido al soltar el pedal"],"explanation":"Una válvula de liberación rápida deja salir el aire de las cámaras de freno cerca de ellas en cuanto sueltas el pedal, así los frenos se liberan más rápido y no se arrastran."},"155":{"q":"Una cámara de freno de resorte de mi camión estacionado falló y el vehículo no se mueve, pero una grúa necesita remolcarlo una corta distancia fuera de la autopista. Sin aire disponible para liberar los frenos de la forma normal, ¿qué acción liberará las ruedas para poder remolcar la unidad?","options":["Enjaular (enrollar mecánicamente con el perno) manualmente los frenos de resorte de la cámara afectada","Inflar el sistema hasta que el manómetro llegue a unos 125 psi para liberarlos","Empujar la perilla amarilla en forma de diamante del freno de estacionamiento para soltar los resortes","Desconectar y cortar las líneas de aire para que las cámaras no retengan presión"],"explanation":"Los frenos de resorte se aplican por resortes y se mantienen sueltos con aire, por eso al fallar una cámara la única forma de liberarlos para remolcar es enjaularlos manualmente con el perno."},"156":{"q":"En una carretera mojada y resbaladiza, en mi tractocamión con frenos de aire, otro conductor me dice que debería desconectar o aflojar los frenos de las ruedas delanteras porque hacen que las llantas de dirección patinen y dificultan el control del camión bajo la lluvia. Según el Manual CDL de Texas, ¿cómo debo tratar los frenos de las ruedas delanteras?","options":["Los frenos de las ruedas delanteras deben desconectarse en carreteras mojadas porque frenar las llantas de dirección provoca un patinazo del frente y pérdida de la dirección","Los frenos de las ruedas delanteras son importantes y necesarios para frenar normalmente, y no hay peligro de patinar por causa de ellos","Los frenos de las ruedas delanteras solo sirven de adorno y aportan poca fuerza de frenado real, así que es aceptable dejarlos débiles","Es mejor dejar los frenos de las ruedas delanteras desajustados para que los frenos traseros hagan la mayor parte del trabajo y las llantas delanteras duren más"],"explanation":"Los frenos de las ruedas delanteras dan una fuerza de frenado real y necesaria, y creer que causan derrapes es un mito, por eso siempre deben funcionar bien."},"157":{"q":"Voy transportando una carga por una carretera mojada de dos carriles y noto que mis frenos delanteros trabajan con mucho esfuerzo al detenerme. Un conductor veterano me dijo una vez que desconectara o evitara usar los frenos delanteros porque hacen que el camión derrape en superficies resbaladizas. Antes de seguir ese consejo, ¿qué afirmación refleja lo que realmente dice el Manual CDL de Texas sobre el frenado de las ruedas delanteras?","options":["Tiene razón — los frenos delanteros son la principal causa de derrapes, así que debes mantenerlos desconectados siempre que la carretera esté mojada.","Tiene razón, pero solo por encima de 55 mph — por debajo de esa velocidad los frenos delanteros son seguros de usar con normalidad.","Está equivocado — la idea de que los frenos delanteros causan derrapes es falsa, y se obtiene el mejor frenado cuando todos los frenos trabajan juntos.","Tiene razón en parte — los frenos delanteros están bien en carretera seca, pero nunca se debe confiar en ellos como fuerza de frenado en ninguna condición."],"explanation":"La creencia de que los frenos delanteros causan derrapes es falsa; obtienes la mejor frenada y más equilibrada cuando todos los frenos trabajan juntos."},"158":{"q":"Voy transportando una carga a 55 mph por una autopista seca de Texas cuando veo un vehículo detenido adelante y piso el freno con fuerza. Mi instructor me recuerda que mis frenos de aire tienen un retardo incorporado antes de que realmente agarren, así que el camión sigue rodando una distancia extra durante ese medio segundo de retardo ANTES de que las ruedas siquiera empiecen a frenar. ¿Aproximadamente cuánta distancia de frenado ADICIONAL agrega este retardo de los frenos a 55 mph?","options":["Unos 2 pies, porque el medio segundo de retardo es demasiado breve para importar mucho a velocidad de autopista","Unos 300 pies, ya que este retardo es lo que hace que los frenos de aire frenen mucho más lento que los hidráulicos","Alrededor de 1 milla, porque el aire debe recorrer todo el trayecto por las líneas antes de que comience cualquier frenado","Unos 32 pies, la distancia que recorre el camión durante el medio segundo de retardo de los frenos a 55 mph"],"explanation":"Los frenos de aire tienen un retraso de aproximadamente medio segundo, por lo que a 55 mph el camión recorre unos 32 pies antes de que los frenos empiecen a actuar."},"159":{"q":"Estoy repasando mis apuntes de la CDL y ya he contado tres de las cuatro partes que componen la distancia total de frenado con frenos de aire: la distancia de percepción, la distancia de reacción y la distancia de retardo del freno. ¿Qué parte me sigue FALTANDO para el total?","options":["La distancia de frenado efectivo, la distancia recorrida una vez que los frenos realmente agarran y desaceleran el vehículo","La distancia de dirección efectiva, el espacio extra que necesita el ABS para evitar que las ruedas se bloqueen","La distancia de bombeo del compresor, recorrida mientras el regulador sube la presión de vuelta al corte","La distancia del ajustador de holgura, recorrida mientras se elimina el juego excesivo de la varilla antes de frenar"],"explanation":"La distancia total de frenado con frenos de aire es la suma de percepción, reacción, retraso del freno y la distancia de frenado efectiva, recorrida tras activarse los frenos."},"160":{"q":"Voy bajando una pendiente de montaña larga y empinada con un conjunto combinado cargado, y siento cómo la gravedad empuja el camión cada vez más rápido. Cuanto más dura el descenso, más se calientan los frenos de aire. ¿Cuál es la técnica de frenado correcta para mantener el vehículo bajo control hasta el final de la bajada?","options":["Mantener una marcha alta para que el motor funcione más suave y pisar el freno fuerte y de forma continua para sujetar la velocidad","Seleccionar una marcha baja antes del descenso y aplicar presión de freno ligera y constante, soltando cuando baje unas 5 mph por debajo de mi velocidad segura y volviendo a aplicar","Bombear o 'abanicar' rápidamente el pedal del freno encendido y apagado para que los frenos se enfríen entre aplicaciones","Poner en neutral para cuidar el motor y rozar los frenos solo cuando el conjunto empiece a sentirse como que se me escapa"],"explanation":"Selecciona una marcha baja antes de la bajada y frena de forma ligera y constante, soltando unas 5 mph por debajo de tu velocidad segura y volviendo a aplicar al subir."},"161":{"q":"Voy bajando una pendiente larga de montaña con mi camión cargado. Ya seleccioné una marcha baja y el instructor me dice que use el frenado intermitente ('snub') correcto para mantener mi velocidad bajo control. ¿Cuál de las siguientes opciones describe correctamente lo que debo hacer?","options":["Aplicar presión de freno firme y continua y mantenerla todo el descenso para conservar una velocidad constante","Bombear suavemente los frenos con toques rápidos para que la presión de aire tenga tiempo de recuperarse entre cada aplicación","Frenar con la fuerza suficiente para reducir unas 5 mph por debajo de mi velocidad segura, soltar los frenos y luego volver a aplicarlos cuando la velocidad vuelva a subir","Poner en punto muerto y rozar los frenos suavemente para que el motor no se oponga a mi frenado"],"explanation":"El frenado intermitente consiste en frenar con firmeza hasta unas 5 mph por debajo de tu velocidad segura, soltar por completo y volver a aplicar al subir la velocidad."},"162":{"q":"Conduzco un conjunto tractocamión con remolque cargado y veo una señal que advierte de una bajada de montaña larga y empinada más adelante. Para controlar mi velocidad de forma segura con mis frenos de aire durante el descenso, ¿cuándo debo elegir mi marcha?","options":["Aproximadamente a mitad del descenso, cuando ya puedo sentir lo empinada que es la pendiente y la rapidez con que gano velocidad","Solo si el motor empieza a revolucionarse en exceso o mis frenos comienzan a fallar y realmente necesito una marcha más baja","Cerca del final, donde la carretera se nivela y puedo reducir la marcha sin forzar la transmisión","Antes de empezar a bajar, mientras todavía estoy en terreno llano y puedo cambiar sin forzar la caja de cambios"],"explanation":"Elige una marcha baja antes de empezar a bajar, mientras estás en terreno llano, porque es difícil o imposible reducir de marcha una vez que ruedas rápido en una pendiente."},"163":{"q":"Durante mi inspección previaje, estoy revisando los frenos de un tractocamión con remolque y noto que las balatas (forros de freno) de una de las ruedas se han desgastado peligrosamente delgadas. Todo lo demás del vehículo está bien. Según las reglas del DPS, ¿qué debo hacer antes de que se permita operar este vehículo?","options":["Dejar el vehículo fuera de servicio hasta reemplazar las balatas desgastadas, porque las balatas peligrosamente delgadas hacen inseguro conducirlo.","Conducir normalmente pero dejar más distancia de seguimiento, ya que las balatas delgadas solo reducen ligeramente la potencia de frenado.","Bombear el pedal del freno varias veces para asentar las balatas delgadas y continuar si el pedal se siente firme.","Continuar mientras la tasa de fuga de aire se mantenga por debajo de 3 psi por minuto, ya que el grosor de la balata no forma parte de la revisión de frenos."],"explanation":"Las balatas de freno demasiado desgastadas son una condición automática de fuera de servicio, por lo que no se debe conducir el vehículo hasta reemplazarlas."},"164":{"q":"Durante una inspección previa al viaje, estaciono en terreno plano, coloco calzos en las ruedas, suelto los frenos de estacionamiento y tomo un ajustador de holgura manual (slack adjuster) para revisar el recorrido excesivo de la varilla. Lo jalo con fuerza con la mano. ¿Cuánto debe moverse para que yo concluya que los frenos están bien ajustados?","options":["Aproximadamente una pulgada completa de juego libre es el máximo permitido antes de ajustar","Debe moverse menos de aproximadamente una pulgada cuando se jala con la mano","Unas seis pulgadas de movimiento todavía indican un freno ajustado de forma segura","No debe moverse en absoluto, ya que cualquier movimiento significa que está desajustado"],"explanation":"Al tirar con fuerza a mano, la varilla del ajustador de holgura manual debe moverse menos de una pulgada; más juego indica que los frenos están desajustados."},"165":{"q":"Conduzco un tractocamión con remolque cargado y frenos de aire, y me acerco a una señal de alto al pie de una pendiente leve. Noto que, al pisar el pedal del freno, hay un breve retraso antes de que los frenos realmente agarren, en comparación con los frenos hidráulicos de mi camioneta. Para tener en cuenta esta diferencia de forma segura, ¿cuándo debo empezar a aplicar los frenos?","options":["En el mismo punto que en un vehículo con frenos hidráulicos, ya que el retraso de medio segundo es demasiado pequeño para importar","Un poco más tarde de lo habitual, porque la presión de aire genera fuerza de frenado adicional cuando llega a los frenos","Un poco antes de lo habitual, para compensar el retraso de los frenos de aire de aproximadamente medio segundo antes de que agarren","Solo después de que los frenos del remolque se activen solos, y luego añadir presión al pedal para completar la parada"],"explanation":"Debido al retraso de medio segundo de los frenos de aire, empieza a frenar un poco antes de lo habitual para que ese retraso no aumente tu distancia de frenado."},"166":{"q":"Voy bajando una pendiente de montaña larga y empinada con una combinación cargada y mantengo una presión ligera y constante en el pedal del freno durante todo el descenso en lugar de usar una marcha baja. Mantener los frenos aplicados de forma continua así durante todo el descenso muy probablemente hará que mis frenos:","options":["Se mantengan más fríos, porque la presión constante reparte la carga de trabajo por igual entre todos los tambores","Frenen mejor el camión cuanto más tiempo los mantenga aplicados en la pendiente","Se desgasten más despacio, ya que las balatas nunca se separan del todo de los tambores","Se sobrecalienten y pierdan eficacia, dejándome sin la fuerza de frenado que necesito antes de llegar abajo"],"explanation":"Arrastrar los frenos continuamente durante toda una bajada larga los sobrecalienta y provoca pérdida de frenado, quedándote sin potencia antes de llegar abajo."},"167":{"q":"Acabo de cruzar un vado inundado con mi camión rígido de frenos de aire, y en el camino seco que sigue noto que los frenos se sienten débiles y agarran de forma despareja en la primera frenada. ¿Cuál es la forma correcta de manejar los frenos mojados?","options":["Seguir avanzando a baja velocidad aplicando presión de freno suave y ligera para que el calor de la fricción los seque","Jalar la perilla amarilla del freno de estacionamiento y mantener aplicados los frenos de resorte un minuto para exprimir el agua","Acelerar a fondo hasta el máximo de revoluciones para que la velocidad de las ruedas expulse el agua de las balatas","Bombear el pedal de freno rápidamente varias veces para empujar el agua atrapada fuera de las cámaras"],"explanation":"Seca las balatas de freno mojadas conduciendo despacio mientras aplicas presión de freno ligera y constante, para que el calor de la fricción evapore el agua y restablezca el frenado uniforme."},"168":{"q":"He metido mi camión en un arcén con mucha pendiente para esperar a que reabran la carretera. He puesto el freno de estacionamiento, pero me preocupa que en esta pendiente no aguante durante una parada prolongada. Según las prácticas seguras de frenos de aire, ¿qué paso adicional debo tomar para evitar que el vehículo ruede?","options":["Dejar el motor en marcha en una marcha baja para que la transmisión ayude a sostener la carga","Colocar calzos contra los neumáticos para bloquear físicamente las ruedas y evitar que rueden","Bombear el pedal del freno varias veces para crear presión adicional en los frenos de resorte","Tirar de la perilla roja octogonal de suministro de aire del remolque para bloquear más las ruedas del remolque"],"explanation":"En una pendiente los frenos de estacionamiento pueden perder aire poco a poco, así que coloca calzos para bloquear físicamente las ruedas como respaldo mecánico."},"170":{"q":"Durante mi inspección previaje, estoy agachado junto a las ruedas revisando los componentes de los frenos de aire de mi tractocamión. Al examinar los tambores y las zapatas de freno, ¿qué condición debería hacer que ponga el vehículo fuera de servicio en lugar de conducirlo?","options":["La superficie del tambor muestra un brillo metálico liso y reluciente en toda su circunferencia","Las balatas de las zapatas de freno todavía conservan bastante grosor","El tambor de freno tiene grietas que recorren su superficie","Hay una capa ligera de polvo y suciedad del camino en la cara del tambor"],"explanation":"Un tambor de freno con grietas en su superficie es un defecto que puede fallar bajo el calor y la fuerza del frenado, haciendo inseguro el vehículo."},"171":{"q":"Estoy haciendo la inspección previaje de un tractocamión fabricado en 2015. Mientras rastreo las líneas de freno, encuentro una válvula que automáticamente pulsa y libera la presión de aire en una rueda individual cientos de veces por segundo para evitar que esa rueda se bloquee durante un frenado fuerte. Un compañero insiste en que esta pieza pertenece a un sistema completamente distinto del camión. ¿A qué sistema pertenece en realidad esta válvula moduladora?","options":["Al sistema dual de suministro de aire, porque cicla la presión de aire entre los tanques primario y secundario","Al sistema de freno de estacionamiento, porque controla cómo se aplican y liberan los frenos de resorte en cada rueda","Al sistema de freno de servicio, porque dosifica directamente el aire que el conductor envía con el pedal del freno","Al sistema ABS (frenos antibloqueo), porque la válvula moduladora pulsa la presión para evitar que las ruedas se bloqueen y así poder dirigir mientras frena fuerte"],"explanation":"La válvula que pulsa aire a una rueda muchas veces por segundo para evitar que se bloquee durante una frenada fuerte es la válvula moduladora del ABS, que conserva la dirección."},"172":{"q":"Estoy enganchando mi tractor a un remolque y tengo que conectar dos líneas de aire (acoples): la línea de servicio y la línea de suministro/emergencia. Para asegurarme de tomar la línea de suministro correcta y no cruzar las conexiones, ¿qué color debo buscar en la línea de suministro (emergencia)?","options":["Rojo","Azul","Amarillo","Verde"],"explanation":"La línea de aire de emergencia (suministro) del remolque es roja, igual que la perilla octagonal roja de suministro de aire del remolque en la cabina."},"173":{"q":"Estoy enganchando mi tractor a un remolque y alcanzo las dos líneas de aire que van entre las unidades. Una lleva la señal que aplica y libera los frenos del remolque cuando piso el pedal de freno (la línea de servicio/control), y la otra suministra aire constantemente para cargar los depósitos del remolque y controlar la línea de emergencia. Necesito tomar la correcta para conectarla al acoplamiento de servicio. ¿Qué color identifica la línea de servicio (control) que debo buscar?","options":["La línea roja, porque el rojo marca el circuito que lleva la señal de frenado desde mi pedal hasta el remolque","La línea azul, porque el azul marca la línea de servicio (control) que aplica y libera los frenos del remolque","La línea negra, ya que la manguera de color neutro es la que se conecta al freno de pie en la mayoría de las combinaciones","La línea naranja, ya que el color más brillante señala la manguera que responde al pedal de freno"],"explanation":"La línea de servicio (control), que transmite la señal del pedal de freno para aplicar y soltar los frenos de servicio del remolque, es azul."},"174":{"q":"Voy conduciendo con un remolque cargado por la autopista cuando el remolque se separa de repente del tractor y la línea de suministro de aire se rompe. Mientras el remolque rueda libre por sí solo, ¿qué debería pasar con los frenos del remolque?","options":["Se quedan totalmente sueltos, así que el remolque sigue rodando hasta que la fricción lo frene","Se sueltan solo después de que yo tire de la perilla roja de suministro de aire del remolque desde la cabina","Se aplican automáticamente porque la pérdida del suministro de aire activa los frenos de emergencia del remolque","Se accionan intermitentemente y rápido, igual que reaccionaría un sistema ABS"],"explanation":"Si un remolque se desengancha, la pérdida del suministro de aire hace que los frenos de emergencia de resorte se apliquen automáticamente, deteniendo el remolque suelto."},"175":{"q":"Conduce un tractocamión con remolque equipado con ABS en buen estado cuando un automóvil se mete delante de usted y frena de golpe. Pisa el pedal del freno con toda su fuerza para evitar chocar por detrás. Mientras el ABS hace su trabajo durante esta frenada brusca, ¿qué puede esperar realmente poder hacer?","options":["Pisar el pedal a fondo y confiar en que el ABS acortará notablemente su distancia total de frenado","Bombear el pedal del freno rápidamente para que el ABS actúe más veces y se agarre mejor al pavimento","Mantener el pedal pisado pero el volante totalmente recto, ya que girar al frenar fuerte anularía el ABS","Mantener el pedal pisado con firmeza mientras dirige el volante para esquivar el peligro, porque las ruedas no se bloquearán"],"explanation":"Con ABS puedes pisar firme el pedal de freno y aun así esquivar el peligro con la dirección, porque el sistema evita que las ruedas se bloqueen."},"176":{"q":"Conduzco un tractocamión viejo sin ABS cuando un automóvil se detiene de golpe delante de mí. Ya inicié un frenado intermitente (stab) enérgico, pero necesito una segunda técnica para detener el conjunto rápidamente sin perder el control. Además del frenado intermitente, ¿qué método debo usar para detenerme lo más rápido posible?","options":["Frenado controlado, aplicando los frenos con firmeza sin permitir que las ruedas se bloqueen","Frenado con ruedas bloqueadas, pisando el pedal a fondo para que los neumáticos derrapen hasta parar","Bombear los frenos rápidamente todo el trayecto para mantener la máxima presión en las ruedas","Solo freno de motor, reduciendo de marcha y soltando el pedal para que la transmisión lo frene"],"explanation":"El frenado controlado consiste en aplicar los frenos lo más fuerte posible sin bloquear las ruedas, ya que las ruedas bloqueadas causan derrape y pérdida de dirección."},"177":{"q":"Estoy haciendo la inspección externa de mi equipo combinado y quiero confirmar que el remolque tenga el ABS funcionando antes de salir a la carretera. Me subo a revisar, pero un compañero me dice que estoy buscando en el lugar equivocado la luz de falla del ABS. ¿Dónde debo buscar realmente en el remolque esa luz de advertencia del ABS?","options":["Al frente, cerca del perno rey, donde una luz verde se enciende cada vez que el ABS del remolque está activado y listo","En la parte trasera izquierda del remolque, donde una luz amarilla de falla indica un problema con el ABS","En la puerta trasera, donde una luz roja se enciende para mostrar que el ABS del remolque falló por completo","Arriba en el techo del remolque, donde una luz azul es visible para el conductor en los espejos"],"explanation":"Una falla del ABS del remolque se indica con una lámpara amarilla montada en la parte trasera izquierda del remolque."},"178":{"q":"Usted conduce con un remolque cargado por la autopista I-35 cuando de repente se enciende la luz de avería del ABS en el remolque. El tractor que conduce es más nuevo y su propio ABS sigue funcionando normalmente. La luz de avería indica que solo ha fallado el ABS del remolque. ¿Qué afirmación describe MEJOR aquello en lo que puede confiar durante el resto del viaje?","options":["Como falló el ABS del remolque, ha perdido los frenos de servicio del remolque y debe detenerse de inmediato para evitar un efecto tijera.","Como falló el ABS del remolque, su distancia de frenado ahora es más corta que antes de que se encendiera la luz de advertencia.","Como solo falló el ABS, aún tiene los frenos de servicio normales en todo el conjunto, pero las ruedas del remolque ahora pueden bloquearse al frenar con fuerza.","Como solo falló el ABS del remolque, el ABS en funcionamiento del tractor asumirá automáticamente el control del frenado de las ruedas del remolque."],"explanation":"Una falla del ABS desactiva solo la función antibloqueo, por lo que los frenos de servicio normales siguen funcionando, pero las ruedas afectadas pueden bloquearse al frenar fuerte."},"180":{"q":"Durante mi inspección previa al viaje, noto que el tablero de frenos de aire tiene dos agujas de presión separadas en lugar de una. Mientras dejo el motor en marcha, ambas agujas suben hasta que el gobernador corta el compresor, y cada una se mantiene fija en su propia lectura. ¿Qué me indica la presencia de estas dos agujas sobre cómo está construido este vehículo?","options":["Tiene dos compresores de aire, cada uno alimentando una aguja de forma independiente","Una aguja indica los frenos de servicio y la otra los frenos de estacionamiento","Tiene dos gobernadores, por lo que cada sistema corta a un psi diferente","Es un sistema de frenos de aire dual: un sistema de aire primario y uno secundario"],"explanation":"Dos agujas en el tablero indican un sistema de frenos de aire dual con dos sistemas de aire separados, uno primario y uno secundario, que comparten los mismos mandos."},"181":{"q":"Estoy remolcando un tráiler cargado en tráfico urbano con paradas constantes y, por costumbre, mantengo el pie izquierdo apoyado ligeramente en el pedal del freno entre paradas para reaccionar más rápido. Mi instructor me dice que quite el pie por completo del pedal siempre que no esté frenando de verdad. ¿Cuál es la razón PRINCIPAL que da?","options":["Incluso una presión ligera y constante mantiene los frenos parcialmente aplicados, lo que los calienta y desgasta prematuramente","Mantener el pie en el pedal bloquea la activación automática de los frenos de resorte si la presión de aire cae demasiado","Apoyarse en el pedal purga lentamente el aire del tanque de suministro y activa antes la advertencia de baja presión","La presión ligera del pedal anula el regulador e impide que el compresor vuelva a arrancar a 100 psi"],"explanation":"Apoyar el pie en el pedal mantiene los frenos parcialmente aplicados, generando fricción constante que sobrecalienta y desgasta las balatas prematuramente."},"182":{"q":"Un mecánico acaba de reemplazar una cámara de freno que goteaba en mi tractocamión, y estoy estacionado en el patio del taller con una carga completa enganchada y una entrega atrasada. El manómetro marca unas 125 psi y la alerta de baja presión de aire está apagada. Antes de salir a la autopista, ¿qué debo hacer PRIMERO?","options":["Confiar en el trabajo del mecánico e incorporarme directamente a la autopista, ya que el manómetro marca unas 125 psi","Probar los frenos a baja velocidad antes de conducir, incluyendo una parada lenta a unas 5 mph para confirmar que sujetan y no desvían el vehículo hacia un lado","Salir y rozar los frenos suavemente durante la primera milla para que la cámara nueva se asiente","Bombear el pedal del freno varias veces en el patio para purgar el aire de la línea recién reparada"],"explanation":"Después de cualquier reparación de frenos debe verificarlos usted mismo, incluida una parada a baja velocidad de unas 5 mph para confirmar que retienen y no se desvían."},"183":{"q":"Durante una inspección previaje, me meto debajo de mi tractocamión y noto que uno de los ajustadores de holgura (slack adjuster) del eje trasero tiene notablemente más juego libre (recorrido de la varilla) que el ajustador de la rueda opuesta del MISMO eje. ¿Cuál de las siguientes afirmaciones es correcta sobre cómo deben estar ajustados los dos ajustadores de holgura de ese eje?","options":["El ajustador del lado con más carga debe dejarse más flojo para equilibrar el peso del remolque","Una diferencia de juego libre entre ambos es normal y no es algo que deba corregir","Ambos ajustadores de holgura del mismo eje deben estar ajustados igual, por lo que el juego libre desigual debe corregirse","Uno debe quitarse para que el freno restante de ese eje haga todo el trabajo de manera uniforme"],"explanation":"Ambos ajustadores de holgura del mismo eje deben tener el mismo juego libre, por lo que un recorrido desigual es un defecto que debe corregirse antes de conducir."},"184":{"q":"Durante mi inspección previaje en una fría mañana de Texas, noto que mi sistema de frenos de aire tiene un secador de aire montado entre el compresor y los tanques de aire. Un mecánico me advierte que si este componente llega a fallar, será mucho más probable que se me congelen las líneas de freno y los tanques durante el invierno. Según cuál es la función principal del secador de aire, ¿por qué su falla causaría este problema de congelamiento?","options":["El secador de aire agrega un poco de aceite para lubricar las líneas, y sin ese aceite las líneas se agarrotarían y congelarían en clima frío","El secador de aire calienta el aire comprimido antes de que llegue a los tanques, así que si falla el aire frío congela el sistema","El secador de aire presuriza el aire hasta el corte del regulador, y sin suficiente presión el aire restante se congela en las líneas","El secador de aire elimina la humedad del aire, así que si falla, el agua se acumula en los tanques y las líneas y puede congelarse con bajas temperaturas"],"explanation":"El secador de aire elimina la humedad del aire comprimido, por lo que si falla, el agua se acumula en los tanques y líneas y puede congelarse en clima frío."},"185":{"q":"Acabo de dejar mi remolque cargado en el patio y conduzco mi tractor de regreso por la ciudad sin remolque enganchado (bobtail). En comparación con cuando llevaba el remolque cargado, ¿qué debo esperar sobre cómo se comporta este vehículo cuando tengo que hacer una frenada brusca?","options":["Puede ser sorprendentemente más difícil de detener, así que debo tener cuidado adicional y dejar más distancia, porque un tractor sin remolque se comporta de forma distinta al frenar","Se detendrá notablemente más rápido y en menor distancia, así que puedo seguir a otros vehículos más de cerca que antes con seguridad","No necesita ninguna atención especial al frenar, ya que soltar el remolque quitó peso y ahora los frenos tienen una tarea fácil","Requerirá menos esfuerzo de dirección y corrección durante la frenada porque el tractor ahora es mucho más ligero en general"],"explanation":"Un tractor sin remolque (bobtail) puede ser más difícil de detener porque sus ejes motrices tienen menos peso y tracción, así que deje mayor cuidado y distancia de frenado."},"186":{"q":"Durante una inspección previaje me meto debajo de mi tractocamión y encuentro que uno de los tanques de aire se desplaza ligeramente en su soporte porque una correa de montaje se aflojó. Antes de sacar esta unidad a la carretera, ¿cuál es la forma correcta de montar ese tanque de aire y por qué importa?","options":["Holgadamente con correas flexibles, para que la vibración del camino y la flexión del chasis no agrieten las soldaduras del tanque","Firmemente al chasis, para que quede fijo en su lugar y las líneas y conexiones no sufran esfuerzo ni fallen","Con la válvula de drenaje hacia arriba, para que el agua y el aceite acumulados no toquen los herrajes de montaje","Alto en el larguero del chasis o detrás de la cabina, para que el tanque drene hacia adelante y lejos de las líneas de freno"],"explanation":"Los depósitos de aire deben montarse firmemente al chasis para que permanezcan fijos ante la vibración y las líneas y conexiones no sufran esfuerzo ni daños."},"187":{"q":"Durante mi inspección previaje estoy mirando un freno de tambor en el remolque y noto que tiene un indicador mecánico de desgaste de las balatas. Cuando este dispositivo da su lectura, ¿qué me está indicando realmente sobre el estado de las balatas (forros) del freno?","options":["Que las balatas han absorbido humedad y deben secarse antes de que los frenos agarren","Que los reguladores de holgura han alcanzado el recorrido máximo permitido del vástago y necesitan ajuste","Que las balatas se han desgastado hasta el punto en que necesitan reemplazarse","Que las balatas están correctamente asentadas y los frenos son seguros para este viaje"],"explanation":"El indicador de desgaste de los frenos muestra cuándo las balatas se han desgastado hasta el punto de necesitar reemplazo."},"188":{"q":"Acabo de terminar una bajada de montaña larga y empinada con mi vehículo combinado cargado, y quiero entrar en un área de descanso para tomar un respiro. Mis frenos están al rojo vivo por el descenso. ¿Cuál de las siguientes es la MEJOR razón por la que NO debería poner los frenos de estacionamiento (de resorte) ahora mismo?","options":["Poner los frenos de resorte mientras están calientes puede hacer que la presión de suministro de aire del remolque caiga por debajo de 60 psi y active la advertencia de baja presión de aire","Los frenos calientes aumentan el recorrido de la varilla de empuje, así que los ajustadores de holgura quedarán desajustados hasta que se enfríen","Los frenos de resorte solo sujetan correctamente una vez que la presión de aire baja al rango de 20 a 45 psi, algo que los frenos calientes impiden","Apretar componentes de freno muy calientes con los frenos de resorte puede dañarlos, así que debería dejar que los frenos se enfríen antes de estacionar"],"explanation":"Aplicar los frenos de resorte (estacionamiento) sobre frenos muy calientes puede dañar los componentes, así que deje que se enfríen antes de estacionar tras una bajada larga."},"189":{"q":"Durante una inspección previaje, he acoplado mi tractocamión a un remolque cargado, he cargado el sistema hasta unos 125 psi, he apagado el motor y he presionado y mantenido pisado el pedal del freno para comprobar si hay fugas mientras observo el manómetro del tablero. A lo largo de un minuto completo, ¿cuál es la caída MÁXIMA de presión de aire que puedo ver y aun así aprobar esta prueba de fugas?","options":["4 psi","3 psi","2 psi","0 psi"],"explanation":"Con los frenos aplicados, la pérdida de aire de un vehículo combinado debe mantenerse por debajo de 4 psi por minuto."},"190":{"q":"Durante mi inspección previaje, estoy revisando la fuga de aire en mi combinación de tractor y remolque. El motor está apagado, el sistema está totalmente cargado a unas 125 psi y he dejado los frenos SUELTOS (válvulas de freno de estacionamiento hacia afuera, pie fuera del pedal). Observando el manómetro durante un minuto, ¿cuál es la pérdida máxima de aire que debo permitir antes de que la fuga quede fuera de norma?","options":["2 psi por minuto, porque ese es el límite de fuga cuando los frenos están sueltos","3 psi por minuto, porque un vehículo combinado con los frenos sueltos puede tener una fuga ligeramente mayor","4 psi por minuto, porque ese es el límite de fuga para un vehículo combinado","Cualquier pérdida es aceptable mientras no se haya activado la alerta de baja presión de aire"],"explanation":"Con los frenos liberados, un vehículo combinado puede perder hasta 3 psi por minuto, algo más que un vehículo sencillo."},"191":{"q":"Durante mi inspección previa al viaje en un tractocamión con remolque, apago el motor, libero los frenos y empiezo a bombear el pedal del freno para purgar el aire. Observo el manómetro del tablero esperando que se activen la luz y el zumbador de advertencia de baja presión de aire para confirmar que funcionan. Según el Manual CDL de Texas, ¿antes de que la presión de aire en mi vehículo combinado caiga por debajo de qué nivel debe encenderse la advertencia?","options":["Antes de que la presión caiga por debajo de 45 psi, el punto en que los frenos de resorte empiezan a aplicarse","Antes de que la presión caiga por debajo de 100 psi, el punto en que el regulador reactiva el compresor","Antes de que la presión caiga por debajo de 60 psi, mucho antes de que los frenos pierdan poder de frenado efectivo","Antes de que la presión caiga por debajo de 20 psi, el punto en que los frenos de emergencia quedan totalmente aplicados"],"explanation":"La advertencia de baja presión de aire debe encenderse antes de que la presión baje de 60 psi, dando un aviso temprano con aire suficiente para detenerse con seguridad."},"192":{"q":"Estoy haciendo mi inspección previaje y observo cómo sube el manómetro mientras el compresor bombea aire. A unos 125 psi el compresor deja de añadir aire al sistema y mantiene la presión ahí. El instructor me pide nombrar el ajuste del regulador (gobernador) que acaba de detener el bombeo del compresor. ¿Qué término nombra correctamente ese ajuste?","options":["Entrada (cut-in) — el ajuste cerca de 100 psi donde el compresor reanuda el bombeo de aire al sistema","Apagado (shut-off) — el ajuste que desactiva por completo el compresor hasta que se reinicie el motor","En espera (stand-by) — el ajuste que pone el compresor en reposo cuando se aplican los frenos de estacionamiento","Corte (cut-out) — el ajuste cerca de 125 psi donde el regulador detiene el bombeo de aire del compresor"],"explanation":"El ajuste de corte (cut-out), cerca de 125 psi, es donde el regulador detiene el bombeo de aire del compresor al sistema."},"193":{"q":"Voy bajando una pendiente larga de montaña con una combinación cargada. Para controlar mi velocidad, selecciono una marcha baja para que el motor y la transmisión hagan la mayor parte del trabajo de retenerme, y solo piso el freno de servicio ligeramente de vez en cuando. En comparación con mantener pisado el freno durante toda la bajada, ¿cuál es la principal ventaja de dejar que el motor y una marcha baja controlen la velocidad?","options":["Los frenos de servicio se mantienen fríos, así conservan toda su potencia de frenado si necesito una parada fuerte al final","Los frenos de servicio se calientan lo justo para agarrar mejor los tambores y acortar mi distancia de frenado","El compresor de aire genera presión extra más rápido porque los frenos casi no se usan en la pendiente","Los frenos de resorte (de estacionamiento) comparten la carga con los de servicio y frenan el vehículo de forma automática"],"explanation":"Una marcha baja deja que el motor absorba la energía del vehículo, manteniendo los frenos de servicio fríos para conservar toda su capacidad de frenado."},"194":{"q":"Voy bajando una pendiente larga y empinada en un camión cargado con frenos de aire, y el vehículo empieza a acelerar por encima de mi velocidad segura. Un compañero por la radio me dice que bombee y suelte repetidamente el pedal del freno para controlar la velocidad. ¿Por qué seguir ese consejo es peligroso en este tipo de bajada?","options":["Bombear el pedal repetidamente sobrecalienta el compresor y dispara la válvula de alivio de seguridad a 150 psi","Bombear el pedal repetidamente libera aire más rápido de lo que el compresor puede reponer, así que la presión puede caer hasta que pierdas el frenado","Bombear el pedal repetidamente expulsa el agua y el aceite de los tanques y contamina las líneas de freno","Bombear el pedal repetidamente acumula aire en exceso que activa los frenos de resorte mientras aún estás rodando"],"explanation":"Bombear los frenos en una bajada larga libera aire más rápido de lo que el compresor lo repone, y la presión puede caer hasta perder el frenado."},"195":{"q":"He estacionado mi equipo combinado en un área de descanso para una pausa de 30 minutos. Para mantener la unidad en su lugar mientras estoy fuera de la cabina, alcanzo la válvula de mano del remolque y la aplico. ¿Por qué es esta la forma INCORRECTA de asegurar el equipo?","options":["La válvula de mano activa los frenos de resorte del remolque, que pueden sobrecalentarse y bloquearse mientras el equipo está estacionado","La válvula de mano libera la perilla roja octagonal de suministro de aire del remolque, por lo que el tractor avanzará solo","La válvula de mano solo aplica aire de servicio a los frenos del remolque, y ese aire puede fugarse con el tiempo y dejar que el equipo ruede","La válvula de mano envía aire solo al eje de dirección, por lo que las ruedas motrices y del remolque quedan completamente sin frenos"],"explanation":"La válvula manual del remolque aplica solo aire de servicio, que se fuga con el tiempo y deja rodar el vehículo, así que estacione siempre con los frenos de resorte."},"196":{"q":"Durante mi inspección previaje en un tractocamión sencillo, subo el sistema de aire hasta unas 125 psi, luego apago el motor y suelto los frenos. Ya calcé las ruedas y la advertencia de baja presión está apagada. ¿Cuál es exactamente el PROPÓSITO de apagar el motor en este paso?","options":["Para poder bombear el pedal del freno varias veces y confirmar que la presión de aire se recupera rápidamente","Para forzar que los frenos de resorte (estacionamiento) se apliquen automáticamente y confirmar que actúan en el rango de 20 a 45 psi","Para drenar el tanque húmedo sin que el compresor se active y meta más aceite y agua","Para que el compresor deje de añadir aire y yo pueda cronometrar la caída de presión y verificar la tasa de fuga"],"explanation":"Apagar el motor evita que el compresor agregue aire, para poder cronometrar la caída de presión y medir con precisión la tasa de fuga."},"197":{"q":"Durante mi inspección previaje, mi instructor me pide que explique qué empuja realmente las zapatas contra los tambores cuando piso el pedal de freno. El motor está en marcha y el sistema está totalmente cargado. ¿Qué respuesta describe correctamente la forma de energía almacenada de la que dependen mis frenos para hacer ese trabajo?","options":["Aire comprimido almacenado en los tanques, que se libera para aplicar los frenos","Líquido hidráulico presurizado por un cilindro maestro, como los frenos de un auto","Corriente eléctrica de la batería enviada a imanes en cada rueda","Presión de aceite del motor desviada del sistema de lubricación hacia los frenos"],"explanation":"Un sistema de frenos de aire almacena energía como aire comprimido en los tanques, que se libera para aplicar los frenos."},"198":{"q":"Durante mi inspección previaje, arranco el motor y observo el manómetro del tablero. Mi sistema de aire doble tarda mucho más que los 45 segundos requeridos para subir de 85 a 100 psi, y la presión sube con mucha lentitud. De lo siguiente, ¿cuál es la causa MÁS probable de esta acumulación lenta de presión?","options":["La alarma de advertencia de baja presión de aire suena demasiado pronto, por debajo de 60 psi","Un compresor de aire defectuoso o una fuga de aire en algún punto del sistema","El corte del regulador está ajustado demasiado alto, cerca del valor de alivio de 150 psi","Los ajustadores de holgura tienen demasiado recorrido de varilla y juego libre"],"explanation":"Una presión de aire que sube demasiado lento para alcanzar 85-100 psi en 45 segundos indica un compresor defectuoso o una fuga en el sistema."},"199":{"q":"Durante mi inspección previaje, escucho un fuerte silbido de aire que sale por la válvula de seguridad (de alivio) del tanque de suministro (tanque húmedo) mientras el motor está en marcha y el compresor genera aire. De lo siguiente, ¿contra qué condición está diseñada específicamente esta válvula para proteger los tanques?","options":["Contra que la advertencia de baja presión de aire no se active antes de que la presión baje de 60 psi","Contra que el regulador (governor) no vuelva a activar el compresor cuando la presión cae a unos 100 psi","Contra que la presión de aire suba demasiado en el sistema; la válvula está ajustada para abrirse a unos 150 psi","Contra que el compresor no logre subir la presión de 85 a 100 psi en 45 segundos"],"explanation":"La válvula de alivio de seguridad del tanque de suministro se abre a unas 150 psi para proteger el sistema del exceso de presión de aire."},"200":{"q":"Estoy cambiando de mi camioneta personal, que tiene frenos hidráulicos, a un camión Clase B equipado con un sistema de frenos de aire. Durante la inspección previaje, intento entender la diferencia fundamental en cómo la fuerza de frenado real llega a los frenos de cada rueda. ¿Qué afirmación identifica correctamente qué transmite físicamente la fuerza que aplica los frenos en mi vehículo con frenos de aire?","options":["El líquido hidráulico del cilindro maestro se presuriza aún más y luego se dirige a las cámaras de freno para apretar las zapatas","La presión del aceite del motor se acumula y se desvía por las líneas de freno para empujar los ajustadores de holgura contra los tambores","Una señal eléctrica del pedal de freno energiza imanes en cada rueda que tiran de las zapatas hacia afuera","El aire comprimido, almacenado en los tanques y liberado por el pedal, viaja por las líneas para aplicar fuerza en las cámaras de freno"],"explanation":"Los frenos de aire usan aire comprimido almacenado en los tanques, liberado por el pedal a través de las líneas hacia las cámaras de freno para aplicar la fuerza de frenado."},"201":{"q":"Acabo de pasar de una camioneta con frenos hidráulicos a un tractocamión con frenos de aire. La primera vez que piso el pedal del freno con fuerza, noto que el camión NO comienza a frenar en el instante en que muevo el pie, como sí lo hacía mi camioneta vieja. ¿Qué afirmación explica MEJOR esta diferencia entre los frenos de aire y los frenos hidráulicos?","options":["Los frenos de aire tienen un retardo incorporado de aproximadamente medio segundo, porque el aire debe recorrer las líneas antes de que los frenos se apliquen.","Los frenos de aire no proporcionan ninguna fuerza de frenado hasta que el sistema alcanza la presión de corte del regulador de 125 psi.","Los frenos de aire responden al instante como los hidráulicos, así que el retraso que sentí solo se debía a ajustadores de holgura desgastados y desajustados.","Los frenos de aire no tienen retroalimentación en el pedal, así que el frenado en realidad comenzó de inmediato aunque yo no pudiera sentirlo."],"explanation":"Los frenos de aire tienen un retardo de aproximadamente medio segundo porque el aire debe recorrer las líneas antes de que se apliquen los frenos."},"203":{"q":"Va transportando una carga por una carretera rural de Texas cuando se enciende la luz de advertencia de baja presión de aire y empieza a sonar el zumbador. Hay una parada de camiones a unos 19 km más adelante donde sabe que hay un mecánico de turno. EXCEPTO una de las siguientes, todas las acciones son respuestas inseguras ante esta advertencia. ¿Cuál es lo correcto que debe hacer?","options":["Mantener la velocidad de la carretera y continuar hasta la parada de camiones a 19 km para que un mecánico revise el sistema","Frenar suavemente para reducir la velocidad y sacar el vehículo de la carretera y detenerlo de forma segura cuanto antes","Bombear el pedal del freno repetidamente para recuperar presión en los tanques y seguir conduciendo con normalidad","Seguir avanzando pero tirar ahora de la perilla del freno de estacionamiento para que los frenos de resorte ayuden a detenerse después"],"explanation":"Cuando se enciende la alerta de baja presión, frene suavemente y saque el vehículo de la vía para detenerlo con seguridad antes de que los frenos de resorte se apliquen solos."},"204":{"q":"Se detiene en un semáforo en rojo con su camión rígido de frenos de aire. La luz y el zumbador de baja presión de aire están encendidos, y el manómetro del tablero muestra que la presión bajó muy por debajo del rango normal de operación. La luz cambia a verde y los de atrás empiezan a tocar la bocina. ¿Cuál es la acción correcta?","options":["Avanzar despacio por el cruce, ya que los frenos de resorte solo se bloquean a 20 psi y usted todavía está por encima","Hacer un cambio de carril rápido hacia el acotamiento mientras todavía tenga aire suficiente para que rueden las ruedas","Permanecer detenido y no mover el camión hasta que la presión de aire suba de nuevo al rango normal","Bombear suavemente el pedal del freno varias veces para que el compresor llene los tanques más rápido antes de arrancar"],"explanation":"Una alerta de baja presión encendida significa que el frenado ya no es confiable, así que permanezca detenido hasta que la presión vuelva al rango normal."},"205":{"q":"Voy conduciendo una combinación cargada cuesta abajo por una pendiente larga y empinada y, a medio camino, noto que el pedal del freno se pone blando y el camión apenas reduce la velocidad cuando lo piso. Mis frenos claramente están perdiendo eficacia (desvanecimiento). ¿Cuál de las siguientes es la MEJOR acción que debo tomar?","options":["Pisar el pedal del freno con más fuerza y mantener una presión constante hasta el fondo de la pendiente para compensar la fuerza de frenado perdida","Bombear rápidamente el pedal del freno para recuperar la sensación del pedal y restaurar la capacidad de frenado que he perdido","Poner una marcha más alta para que el motor gire libremente y el camión pueda rodar suavemente hasta el fondo de la pendiente","Cambiar a una marcha más baja para usar el freno de motor y buscar el lugar seguro más cercano para salirme de la vía y detener el camión"],"explanation":"Si los frenos de aire empiezan a fallar en una bajada larga, reduzca a una marcha más baja para usar el freno motor y deténgase en el lugar seguro más cercano."},"206":{"q":"He estacionado mi tractocamión cargado en una pendiente leve y puse el freno de estacionamiento con la perilla amarilla. Mientras hago el papeleo, el motor está apagado y la presión de aire en los tanques baja lentamente por debajo de 45 psi hacia cero. ¿Qué mantiene realmente mi camión sin rodar y por qué sigue sujetando incluso mientras se fuga el aire?","options":["Resortes potentes dentro de las cámaras de freno aprietan los frenos mecánicamente, por lo que la fuerza de sujeción se mantiene a medida que el aire se escapa","El aire atrapado a presión dentro de las cámaras de freno mantiene las zapatas presionadas contra los tambores","El motor y la transmisión sujetan las ruedas mediante compresión una vez apagado","La perilla amarilla traba mecánicamente el varillaje de la válvula de pie para mantener la fuerza del pedal"],"explanation":"Los frenos de estacionamiento y de emergencia se mantienen aplicados por resortes potentes en las cámaras de freno de resorte, por lo que siguen sujetando aunque se escape el aire."},"207":{"q":"Voy por la autopista con el sistema de aire totalmente cargado a presión normal de operación, y siento que los frenos de resorte NO están arrastrando ni aplicándose. ¿Qué afirmación explica correctamente la función de la presión de retención (hold-off) en esta situación?","options":["La presión de retención mantiene los frenos de resorte parcialmente apretados para que respondan más rápido cuando piso el pedal.","La presión de retención mantiene los frenos de resorte liberados mientras conduzco, así que siguen desactivados hasta que el aire baje demasiado.","La presión de retención mantiene los frenos de resorte totalmente aplicados en todo momento para respaldar mis frenos de servicio.","La presión de retención se ha eliminado por completo de las cámaras, por eso siento los frenos de resorte desactivados."],"explanation":"La presión de retención comprime los resortes para mantener los frenos de resorte liberados al conducir, y solo se aplican si el aire baja demasiado."},"208":{"q":"Al terminar mi turno estaciono el camión, apago el motor y siento cómo los frenos de resorte bloquean las ruedas mientras el aire se purga. Un aprendiz me pregunta en qué función de frenado del sistema de aire acabo de confiar para retener el camión. ¿Cuál respuesta es correcta?","options":["La función de frenos de servicio, ya que el pedal es lo que retiene un vehículo estacionado una vez apagado el motor","La función moduladora, ya que los frenos de resorte se aplican gradualmente cuando la presión de aire baja de 60 psi","La función de estacionamiento/emergencia, ya que los frenos de resorte se aplican automáticamente para retener el vehículo cuando se pierde la presión de aire","La función de advertencia de baja presión, ya que el zumbador y la luz son lo que físicamente sujeta las ruedas"],"explanation":"Los frenos de resorte se aplican automáticamente para sujetar el vehículo cuando se pierde la presión de aire, lo cual es la función de estacionamiento/emergencia."},"210":{"q":"Durante mi inspección previaje, abro el capó y noto que mi compresor de aire es accionado por una correa en lugar de estar conectado directamente al motor. Como es accionado por correa, ¿qué elemento adicional debo inspeccionar específicamente que NO necesitaría revisar en un compresor accionado por engranajes?","options":["Que la presión de corte del gobernador marque unas 125 psi en el manómetro","Que los tanques de aire hayan sido drenados de agua y aceite del compresor","Que la luz de advertencia de baja presión de aire se encienda antes de los 60 psi","Que la correa de transmisión tenga la tensión adecuada y no muestre desgaste"],"explanation":"En un compresor accionado por correa, verifique que la correa de transmisión esté bien tensada y sin desgaste, ya que el accionado por engranajes no tiene correa."},"211":{"q":"Durante mi inspección previaje, noto que uno de los tanques de almacenamiento de aire debajo del remolque ya no está sujeto firmemente a su soporte de montaje y se mueve cuando lo empujo. ¿Por qué este tanque suelto es un defecto que debo corregir antes de conducir?","options":["El tanque puede rozar contra partes del vehículo o aflojarse y caerse del camión","El tanque extraerá aire adicional del compresor y obligará al regulador a cortar antes de tiempo","El tanque retendrá menos aire comprimido, por lo que mi advertencia de baja presión de aire sonará antes","El tanque drenará el agua y el aceite por sí solo, dejando nada que purgar a diario"],"explanation":"Un tanque de aire suelto puede vibrar y rozar contra las piezas del vehículo o aflojarse y caerse del camión."},"212":{"q":"Ha estacionado su camión rígido con frenos de aire sobre suelo nivelado y pavimentado en una isla de combustible y ha apagado el motor. Los manómetros indican presión total del sistema y está a punto de bajarse de la cabina para empezar a cargar combustible. ¿Qué acción debe completar antes de salir de la cabina?","options":["Dejar el camión en la marcha más baja hacia adelante y confiar en la compresión del motor para retenerlo","Jalar hacia afuera la perilla amarilla en forma de diamante para aplicar los frenos de estacionamiento (de resorte)","Sujetar el camión manteniendo presión firme y constante con el pie sobre el pedal del freno de servicio","Jalar hacia afuera la perilla roja octagonal para bloquear la línea de suministro de aire del remolque"],"explanation":"Siempre aplique los frenos de estacionamiento (de resorte) tirando de la perilla amarilla en forma de diamante antes de salir de la cabina."},"213":{"q":"Soy un conductor nuevo y estoy decidiendo entre dos camiones usados: un tractocamión pesado capaz de transportar carga cerca de su peso bruto máximo, y una furgoneta ligera de reparto. Un mecánico me dice que el camión grande usa frenos de aire mientras que la furgoneta usa frenos hidráulicos. Quiero entender por qué los vehículos comerciales pesados se fabrican con frenos de aire en primer lugar. ¿Qué afirmación explica MEJOR por qué los frenos de aire son la opción estándar para camiones grandes y muy cargados?","options":["Los frenos de aire acortan la distancia total de frenado del camión, de modo que un tractocamión completamente cargado puede detenerse en menos espacio que con frenos hidráulicos","Los frenos de aire se eligen principalmente porque son el sistema de frenado más barato de instalar y sus tanques nunca necesitan drenarse ni mantenerse","Los frenos de aire usan aire comprimido en lugar de una cantidad fija de líquido, por lo que siguen funcionando de forma eficaz incluso en vehículos grandes que transportan cargas pesadas","Los frenos de aire eliminan por completo el retardo de frenado, permitiendo que un camión cargado responda en el instante en que se pisa el pedal, sin demora en las líneas"],"explanation":"Los frenos de aire usan aire comprimido que se repone continuamente en lugar de una cantidad fija de líquido, por lo que frenan eficazmente en vehículos pesados y con carga completa."},"214":{"q":"Estoy estacionado en una pendiente y decido jalar la perilla amarilla del freno de estacionamiento (activando los frenos de resorte) mientras TODAVÍA mantengo el pedal del freno de servicio presionado con fuerza. Un conductor a mi lado me advierte que primero suelte el pedal. ¿Por qué aplicar los frenos de servicio y los frenos de resorte con fuerza al mismo tiempo es un problema?","options":["No causa ningún daño y de hecho me da una fuerza de retención adicional, así que no hay razón para soltar primero el pedal de servicio","Hace que la advertencia de baja presión de aire se active antes, por debajo del punto de 60 psi, y vacía el tanque de suministro más rápido","Ahorra una gran cantidad de aire porque ambos sistemas comparten la misma presión almacenada cuando se aplican juntos","Las fuerzas de frenado se combinan y se suman, y esa fuerza compuesta puede ejercer demasiada tensión y dañar los componentes de los frenos"],"explanation":"Pisar fuerte el freno de servicio mientras los frenos de resorte están aplicados hace que ambas fuerzas se sumen, creando una tensión excesiva que puede dañar los componentes del freno."},"215":{"q":"Estoy estacionando mi camión y jalo la perilla amarilla para aplicar los frenos de resorte (de estacionamiento). Por costumbre, mi pie sigue presionando con fuerza el pedal del freno, así que también se envía presión de aire a las mismas cámaras de freno al mismo tiempo. El mecánico me advirtió que, sin cierta válvula, aplicar ambas fuerzas juntas podría sumarse y dañar los frenos. ¿Qué válvula protege contra esta fuerza combinada de 'doble aplicación'?","options":["La válvula anticompounding, que evita que la fuerza del freno de resorte y la fuerza de aplicación de aire se sumen sobre los mismos frenos","La válvula de control modulador, que permite aplicar los frenos de resorte gradualmente para que las dos fuerzas nunca se superpongan","La válvula de alivio de seguridad, que se abre a unos 150 psi para liberar la presión extra creada por la doble aplicación","La válvula de suministro de aire del remolque, la perilla roja octagonal que corta el aire a los frenos traseros cuando ambos se aplican"],"explanation":"La válvula anticompuesta libera la presión de aplicación de aire cuando los frenos de resorte están aplicados para que las dos fuerzas de frenado no se sumen."},"216":{"q":"Durante mi inspección previaje, estoy realizando las verificaciones de los frenos de aire en un tractocamión con remolque. Quiero confirmar el dispositivo que es OBLIGATORIO que me alerte en el momento en que la presión de aire del sistema baje demasiado (antes de que caiga por debajo de 60 psi) para saber que debo detenerme mientras todavía tengo capacidad de frenado. ¿Qué elemento está obligado a usar el sistema para darme esa advertencia?","options":["El manómetro de presión de aire bajando lentamente, que se espera que yo vigile de cerca durante todo el viaje","Una luz de advertencia y/o un zumbador que se activa antes de que la presión caiga por debajo de 60 psi","Los frenos de resorte (de estacionamiento) accionándose automáticamente para obligarme físicamente a detenerme","La válvula de alivio de seguridad liberando aire con un fuerte silbido en cuanto la presión baja demasiado"],"explanation":"Un vehículo con frenos de aire debe tener una luz de advertencia de baja presión de aire, y normalmente un zumbador, que se activa antes de que la presión caiga por debajo de 60 psi."},"217":{"q":"Estoy al ralentí en una parada de camiones observando mi manómetro de presión de aire después de una carga completa. La aguja sigue ciclando: sube, el gobernador corta, la aguja baja lentamente un poco, luego el gobernador vuelve a activarse y la sube de nuevo. Quiero confirmar que mi compresor de aire está al día con la demanda. ¿Qué comportamiento del manómetro me indica que el compresor está cumpliendo su función?","options":["El manómetro sigue subiendo por encima de 150 psi y la válvula de alivio de seguridad libera aire, lo que demuestra que el compresor tiene capacidad de sobra","El manómetro baja lentamente hasta cero por completo y luego el compresor lo rellena de una sola vez de forma rápida","La aguja se mantiene dentro del rango normal de operación, ciclando entre la activación y el corte del gobernador a medida que se usa y se repone la presión","El manómetro se mantiene totalmente fijo en un valor de psi y nunca se mueve, mostrando que el gobernador ha bloqueado la presión del sistema en su sitio"],"explanation":"Un compresor en buen estado mantiene la presión en el rango normal, alternando entre el corte del regulador (unos 125 psi) y la activación (unos 100 psi) a medida que se usa y repone el aire."},"219":{"q":"Estoy haciendo la inspección previaje en un tractocamión sencillo y dejo el motor en ralentí para acumular aire. Quiero el sistema totalmente cargado antes de salir, así que observo el manómetro del tablero subir y espero a que el gobernador del compresor corte y deje de bombear aire. ¿A qué presión aproximada debo esperar que eso ocurra?","options":["Unos 100 psi, el punto donde el gobernador se activa y vuelve a bombear aire","Unos 60 psi, donde se apagan la luz y el zumbador de advertencia de baja presión de aire","Unos 150 psi, donde la válvula de seguridad se abre para liberar el aire sobrante","Unos 125 psi, donde el gobernador corta y el compresor deja de bombear aire"],"explanation":"Un sistema completamente cargado se encuentra a la presión de corte del regulador, unos 125 psi, donde el compresor deja de bombear aire."},"220":{"q":"Conduce un vehículo combinado cuando su remolque se desprende de repente del tractor y su línea de suministro de aire se arranca, vaciando todo el aire del sistema de frenos del remolque. ¿Qué le ocurrirá al remolque desbocado?","options":["Sus frenos de resorte (de emergencia) se aplicarán automáticamente al caer la presión de aire, frenando y deteniendo el remolque","Sus frenos de servicio solo sujetarán mientras usted mantenga el pie en el pedal de freno del tractor","Rodará libremente sin frenar, ya que perder el aire también suelta los frenos de estacionamiento del remolque","No le pasará nada hasta que tire de la perilla roja de suministro de aire del remolque para aplicar los frenos"],"explanation":"Los frenos de resorte se mantienen sueltos por la presión de aire, así que cuando un remolque que se desprende pierde aire, se aplican automáticamente y detienen el remolque."},"221":{"q":"Está conduciendo un camión rígido individual (sin remolque) con sistema de frenos de aire cuando una falla mayor en una línea expulsa todo el aire del sistema y los manómetros caen a cero. Usted no tocó el pedal del freno ni el control del freno de estacionamiento. ¿Qué hace el camión?","options":["Rueda libremente sin frenado, porque al perder el aire también se liberan los frenos de resorte y usted sigue rodando.","Se detiene por sí solo, porque los frenos de resorte se aplican automáticamente en cuanto la presión de aire baja lo suficiente.","Sigue avanzando con normalidad y usted simplemente pierde los frenos de servicio, pero la dirección y el freno de estacionamiento aún funcionan.","Pierde solo la asistencia de potencia, así que los frenos aún funcionan pero el pedal se vuelve mucho más duro de pisar."],"explanation":"Los frenos de resorte se mantienen sueltos por la presión de aire, por lo que una pérdida total de aire los aplica automáticamente y detiene el vehículo."},"222":{"q":"Durante mi inspección previaje en un tractocamión con remolque, noto que el ajustador de holgura de uno de los frenos delanteros tiene más recorrido de varilla que los demás, por lo que ese freno trabaja menos mientras los otros trabajan más. Un compañero dice que esto no importa mucho. ¿Qué es lo MÁS importante que pierdo cuando mis frenos están desajustados y ya no comparten el trabajo de frenado de manera uniforme?","options":["Mejor economía de combustible, porque los frenos que trabajan parejo reducen el arrastre del motor","Una acumulación de presión de aire más rápida de 85 a 100 psi durante la prueba","Buen equilibrio de frenado, para que el vehículo se detenga derecho sin jalar hacia un lado","Mayor poder de frenado del motor al reducir la marcha en una bajada larga"],"explanation":"Cuando todos los frenos están bien ajustados y reparten el trabajo por igual, el equilibrio de frenado detiene el vehículo recto sin tirar hacia un lado."},"223":{"q":"Estoy haciendo la inspección previaje de mi tractocamión con remolque. El motor ha estado en marcha y la presión de aire sube en los tanques. Antes de soltar los frenos de estacionamiento y salir del patio, ¿cuál es la presión de aire MÍNIMA que debo tener en el sistema para conducir con seguridad?","options":["Al menos unas 60 psi, ya que ese es el punto donde se apaga la advertencia de baja presión de aire","Al menos unas 20 psi, ya que ahí se sueltan los frenos de resorte y el equipo puede rodar","Al menos unas 125 psi, ya que el equipo no es seguro de conducir hasta que el regulador llegue al corte","Al menos unas 100 psi, ya que esa es la presión mínima necesaria para frenar y conducir con seguridad"],"explanation":"Debes acumular al menos unas 100 psi antes de conducir, ya que esa es la presión de aire mínima necesaria para frenar y conducir con seguridad."},"224":{"q":"Conduzco el mismo tractocamión confiable en una ruta corta de reparto de 40 millas que recorro varias veces al día. La unidad pasó esta mañana su inspección completa de frenos de aire sin problemas, y no la he tocado desde el almuerzo. Al subir de nuevo para iniciar mi recorrido de la tarde, ¿cuál es el enfoque correcto para revisar los frenos de aire?","options":["Realizar de nuevo las revisiones de los frenos de aire antes de este viaje de la tarde, igual que antes de cualquier viaje","Omitir las revisiones esta vez, ya que una inspección completa de este mismo vehículo ya fue aprobada hoy más temprano","Repetir las revisiones solo si la luz o el zumbador de advertencia de baja presión de aire se activaron durante el recorrido de la mañana","Esperar y volver a revisar los frenos una vez por semana o aproximadamente cada 1,000 millas recorridas"],"explanation":"Las pruebas de los frenos de aire deben realizarse antes de cada viaje, ya que el estado de los frenos, las fugas de aire y el ajuste de holgura pueden cambiar entre viajes."},"225":{"q":"Durante mi inspección previa al viaje, noto que los ajustadores de holgura de mi tractocamión tienen más juego libre del que deberían, lo que significa que los frenos están desajustados. Si conduzco de todos modos sin corregirlo, ¿qué debo esperar principalmente que ocurra en la carretera?","options":["Los frenos en realidad agarrarán con más fuerza y detendrán el camión en una distancia más corta","Los frenos tendrán menos potencia y el camión no se detendrá tan bien","El sistema conservará aire, por lo que el compresor se activará con mucha menos frecuencia","Las balatas y los tambores de freno se desgastarán mucho más lentamente con el tiempo"],"explanation":"El recorrido excesivo de la varilla por reguladores de holgura desajustados reduce la fuerza de frenado, por lo que el camión no frena tan bien."},"226":{"q":"Durante mi inspección previaje, noto que una manguera de freno está colocada de modo que presiona contra un soporte afilado del chasis, y su superficie exterior está raspada donde toca el metal. ¿Por qué importa este hallazgo para mi sistema de frenos de aire?","options":["El contacto aprieta el acople con el tiempo, así que en realidad reduce la posibilidad de que una conexión se afloje","La fricción endurece el caucho, permitiendo que la manguera resista mayor presión que el resto del sistema","El roce constante puede desgastar la manguera hasta que falle y deje escapar el aire","Nada cambia para los frenos, pero el roce podría acelerar el enfriamiento solo en ese punto"],"explanation":"Una manguera de freno que roza contra una pieza se desgasta por la fricción constante hasta perforarse y dejar escapar aire."},"227":{"q":"Durante mi inspección previaje, mi tractor sencillo está totalmente cargado a unos 125 psi. Apago el motor, dejo los frenos liberados y observo el manómetro. La presión baja más de 2 psi en un minuto, y rastreo un leve siseo hasta una cámara de freno donde el diafragma de caucho tiene un pequeño desgarro. ¿Qué le está haciendo a mi sistema de aire este diafragma desgarrado?","options":["Está aumentando la fuerza que empuja la varilla de empuje, dando a esa rueda potencia de frenado adicional","Solo importa con los frenos aplicados, así que con los frenos liberados no tiene efecto real","Está ayudando a que las zapatas agarren con más fuerza el tambor de esa rueda durante la parada","Está dejando escapar aire comprimido, por eso mi tasa de fuga es demasiado alta"],"explanation":"Un diafragma roto de la cámara de freno deja escapar el aire comprimido por el agujero en lugar de aplicar los frenos, elevando la tasa de fuga."},"228":{"q":"Durante mi inspección previaje de mi camión con remolque, la tasa de fuga de aire no pasa la prueba—la presión baja mucho más rápido que el límite incluso con el motor apagado y los frenos liberados. Noto un leve siseo justo donde se acoplan las líneas de aire del tractor y del remolque. ¿Cuál es la causa MÁS probable de lo que escucho y de la prueba de fuga fallida?","options":["Los sellos desgastados de las cabezas de acoplamiento (glad hands) dejan escapar aire en la unión entre el tractor y el remolque","Un ajustador de holgura (slack adjuster) está desajustado, permitiendo un recorrido excesivo del vástago en una de las cámaras de freno","La válvula de alivio de seguridad se abrió porque la presión del tanque superó los 150 psi durante la carga","El gobernador no alcanzó el corte, por lo que el compresor nunca dejó de bombear aire al sistema"],"explanation":"Los sellos gastados de las uniones glad-hand dejan escapar aire donde se acoplan las líneas de aire del tractor y el remolque, causando el silbido y la fuga excesiva."},"229":{"q":"Acabo de acoplar mi tractocamión a un remolque cargado y conecté las líneas de aire. Los tanques de aire del remolque siguen vacíos y necesito enviar aire de vuelta al remolque para cargar su sistema de frenos antes de hacer mis revisiones de frenos. Sentado en la cabina, ¿qué control acciono para enviar aire al remolque?","options":["Jalo hacia afuera la perilla amarilla en forma de diamante para dar presión al remolque","Empujo hacia adentro la perilla roja octagonal para enviar aire de vuelta al remolque","Presiono y mantengo el pedal del freno de servicio para bombear aire por las líneas","Jalo hacia afuera la perilla roja octagonal para abrir la línea de suministro al remolque"],"explanation":"Presionar la perilla roja octagonal de suministro de aire del remolque envía aire desde el tractor para cargar el sistema de frenos del remolque."},"230":{"q":"Voy conduciendo un tractocamión cuando una fuga en el sistema hace que mi presión de aire caiga muy por debajo del nivel necesario para mantener abierta la válvula de suministro de aire del remolque. Sin que yo toque nada en el tablero, ¿qué debo esperar que haga la perilla roja octagonal de suministro de aire del remolque?","options":["Permanecer asentada y presionada hacia adentro, ya que los frenos del remolque solo responden al pedal","Encenderse y sonar una alarma, pero permanecer presionada hasta que yo la jale con la mano","Saltar por sí sola y cerrarse, aplicando automáticamente los frenos de emergencia del remolque","Empujarse más hacia adentro para sellar el remolque y conservar la presión de aire restante"],"explanation":"Si la presión de aire baja demasiado, la perilla roja octagonal salta sola y se cierra, aplicando automáticamente los frenos de emergencia del remolque."},"231":{"q":"Durante mi inspección previaje, mi mecánico me comenta que a un eje de mi camión le instalaron cámaras de freno más grandes que a los demás, y un estudiante novato que viaja conmigo me pregunta qué diferencia hace eso al pisar el pedal del freno. En comparación con las cámaras más pequeñas, ¿qué produce en realidad la cámara de freno más grande en ese eje?","options":["Suaviza la sensación del pedal porque la cámara más grande retiene más aire antes de que se mueva la varilla de empuje","Reduce el frenado porque la cámara más grande desvía la presión de aire fuera del ajustador de holgura","No produce ningún cambio en el frenado, ya que el tamaño de la cámara solo afecta la rapidez con que se rellena el aire","Produce más fuerza de frenado porque la cámara más grande empuja el ajustador de holgura con mayor esfuerzo"],"explanation":"Una cámara de freno más grande tiene más superficie sobre la que actúa el aire, empujando el regulador de holgura con mayor fuerza para más potencia de frenado."},"232":{"q":"Durante mi inspección previaje, piso el pedal del freno y observo cómo gira la leva en S (S-cam) del freno de tambor en un eje de tracción. Cuando la leva en S gira, ¿qué hace en realidad dentro de ese conjunto de freno para frenar la rueda?","options":["Empuja las zapatas del freno hacia afuera para que sus forros presionen contra el interior del tambor del freno","Jala las zapatas del freno hacia adentro, alejándolas del tambor, para que los resortes de retorno puedan soltarlas","Gira el ajustador de holgura (slack adjuster) para eliminar el juego de la varilla antes de que comience el frenado","Purga el aire de la cámara de freno para que los frenos de resorte se apliquen contra el tambor"],"explanation":"La leva S giratoria se inserta entre las zapatas y las empuja hacia afuera para que sus forros presionen contra el interior del tambor de freno y frenen la rueda."},"233":{"q":"Durante mi inspección previaje, estoy revisando los frenos de base de un tractocamión equipado con frenos de disco de aire en lugar del tipo de tambor, más común. Al observar el conjunto de la rueda, veo la mordaza (caliper) abrazando un componente metálico plano y giratorio que la mordaza aprieta para frenar la rueda. Para describir correctamente este sistema de frenos de disco de aire en mi inspección, la pieza que la mordaza sujeta es el:","options":["Tambor de freno contra el que las zapatas presionan hacia afuera","Rotor (disco) que la mordaza aprieta para generar fricción","Cámara del freno de resorte (estacionamiento) que aplica la presión","Ajustador de holgura contra el que se mueve la varilla de empuje"],"explanation":"Los frenos de disco de aire usan una mordaza que aprieta las pastillas contra un rotor (disco) giratorio montado en el cubo de la rueda para crear la fricción que frena la rueda."},"234":{"q":"Durante mi inspección previaje, un mecánico señala una cámara de freno grande en mi camión y la llama cámara 'maxi', diciéndome que NO usa presión de aire para empujar la varilla y detener la rueda como lo hace la cámara más pequeña. Según cómo funciona realmente este componente, ¿qué es la cámara 'maxi'?","options":["Es el freno de servicio, ya que la cámara 'maxi' es la parte que aplica la fuerza de frenado cada vez que piso el pedal durante la conducción normal","Es la válvula de control modulante, ya que la cámara 'maxi' es lo que me permite aplicar presión gradualmente al eje trasero en una emergencia","Es el freno de resorte, ya que la cámara 'maxi' contiene un resorte potente que aplica los frenos cuando se libera o se pierde la presión de aire","Es la unidad de suministro de aire al remolque, ya que la cámara 'maxi' es lo que alimenta y recarga aire a los tanques del remolque mientras conduzco"],"explanation":"La cámara maxi (freno de resorte) contiene un potente resorte comprimido que aplica los frenos cuando la presión de aire se libera o se pierde, en vez de empujar la varilla con aire."},"235":{"q":"Estoy estacionado en un muelle de carga y mi camión está completamente cargado de aire a unos 125 psi sin fugas. Aparte de que la presión de aire caiga al rango de 20-45 psi, ¿cuál es la OTRA forma en que se pueden aplicar mis frenos de resorte?","options":["Pisando y manteniendo el pedal del freno de servicio hasta el fondo","Activando el interruptor de advertencia del sistema de frenos antibloqueo (ABS)","Acelerando el motor para que el regulador alcance el corte a 125 psi","Tirando de la perilla amarilla en forma de diamante del freno de estacionamiento"],"explanation":"Los frenos de resorte se aplican manualmente tirando de la perilla amarilla en forma de diamante del control del freno de estacionamiento."},"236":{"q":"Es una mañana de invierno bajo cero en el Panhandle y mi tractocamión con remolque está equipado con un evaporador de alcohol en el sistema de frenos de aire. Mientras hago mi inspección previaje y empiezo a conducir, ¿cuál es la función PRINCIPAL que cumple este dispositivo para mí con este frío?","options":["Agregar alcohol al sistema de aire para evitar que se forme hielo y se obstruyan las líneas de aire y las válvulas de los frenos","Mantener calientes los tambores y las balatas para que los frenos de servicio no pierdan su capacidad de frenado","Eliminar el agua y el aceite del compresor de los tanques para que ya no tenga que drenarlos a diario","Aumentar la presión de corte del gobernador para que el compresor genere aire más rápido con el frío"],"explanation":"El evaporador de alcohol agrega alcohol al sistema de aire para bajar el punto de congelación de la humedad y evitar que el hielo se forme y obstruya las líneas y válvulas de freno."},"238":{"q":"Durante mi inspección previaje, dejo el motor en marcha y observo cómo sube el manómetro de aire. Llega a unas 125 psi y la aguja deja de subir aunque el motor sigue funcionando. El gobernador acaba de alcanzar su punto de corte (cut-out). ¿Qué está haciendo el compresor en sí en este preciso momento?","options":["Se ha apagado por completo junto con el motor y solo volverá a arrancar cuando la presión baje a unas 60 psi","Sigue girando pero deja de bombear aire a los tanques (se ha descargado) hasta que la presión baje a unas 100 psi","Bombea con más fuerza para subir la presión hacia el ajuste de 150 psi de la válvula de alivio de seguridad","Se traba y purga el aire sobrante por la válvula de alivio de seguridad para proteger los tanques"],"explanation":"En el punto de corte del gobernador (unas 125 psi) el compresor sigue girando pero se descarga y deja de enviar aire a los tanques hasta que la presión baja al punto de enganche de unas 100 psi."},"239":{"q":"Acabo de dejar mi remolque en el patio y conduzco el tractor de regreso a la terminal sin remolque (bobtail). El camino a casa tiene un tramo largo y plano, un lote de grava abierto por el que atajo, un par de rampas de acceso a la autopista y una curva amplia cerca de la salida. ¿Dónde debo tener MÁS cuidado en reducir la velocidad, porque un tractor sin remolque se maneja mal allí?","options":["En el tramo largo y plano, ya que el vehículo más ligero me deja ir más rápido de lo normal","En el lote de grava abierto, ya que la superficie suelta es el único lugar donde un bobtail pierde agarre","En las curvas y las rampas de acceso, donde un tractor sin remolque (bobtail) puede manejarse mal","En ningún lugar en particular, ya que un bobtail sin remolque frena y toma curvas mejor"],"explanation":"Un tractor bobtail no tiene el peso del remolque sobre los ejes de tracción y maneja mal, así que reduzca más la velocidad en curvas y rampas de acceso, donde las fuerzas son mayores."},"240":{"q":"Estoy terminando mi inspección previaje en un tractocamión con remolque en el patio. Ya drené los tanques de aire, confirmé que el gobernador corta cerca de 125 psi y verifiqué que la advertencia de baja presión de aire se enciende antes de bajar de 60 psi. Antes de salir a la carretera, ¿cuál de las siguientes acciones debo realizar todavía respecto a las luces en la parte trasera de mi vehículo?","options":["Confirmar que los reflectores traseros estén recién pintados para que otros conductores los vean de noche","Confirmar que las carcasas de las lámparas traseras estén cubiertas para proteger los focos de los residuos del camino","Confirmar que las luces de gálibo traseras hayan sido retiradas para reducir la carga eléctrica","Confirmar que las luces de freno realmente se enciendan cuando piso el pedal del freno"],"explanation":"La inspección previaje exige confirmar que las luces de freno realmente se enciendan al pisar el pedal, para que el tráfico que viene detrás sepa que está frenando o deteniéndose."},"241":{"q":"Durante mi prueba de frenado de servicio a unos 5 mph antes del viaje, piso el pedal del freno y el camión se sacude bruscamente hacia la derecha y el pedal agarra de forma despareja antes de detenerse. ¿Cuál conclusión es correcta?","options":["Los frenos están defectuosos y el vehículo necesita servicio antes de poder conducirse","Es el retardo normal del freno y puedo soltar y continuar el viaje","La presión de aire simplemente es muy alta, así que debo purgar los tanques y repetir","El ABS hace su trabajo agarrando una rueda, así que no se requiere ninguna acción"],"explanation":"En la prueba de frenos a 5 mph, los frenos que jalan hacia un lado o agarran de forma despareja están defectuosos y el vehículo no debe conducirse hasta repararlo."},"242":{"q":"Durante mi inspección previaje, me meto debajo del remolque para revisar los frenos de fundación (foundation brakes) en cada rueda. Ya confirmé que los tambores y las zapatas de freno están en buen estado. Para terminar de inspeccionar los componentes del freno de fundación en sí, ¿qué pieza debería revisar a continuación?","options":["La perilla amarilla en forma de diamante del freno de estacionamiento en la cabina","Los ajustadores de holgura (slack adjusters) conectados al vástago de cada cámara de freno","El gobernador que controla la conexión y desconexión del compresor","La válvula de alivio de seguridad montada en el tanque de suministro (húmedo)"],"explanation":"Los ajustadores de holgura conectan la varilla de empuje de cada cámara de freno con el mecanismo de freno, convirtiendo el recorrido de la varilla en fuerza de frenado en la rueda."},"243":{"q":"Durante mi inspección previaje, conecto las uñas de acoplamiento (glad hands) del tractor y del remolque, cargo el sistema de aire a unos 125 psi y apago el motor. Al inclinarme cerca del acople, escucho con claridad un silbido constante que proviene de una de las conexiones de las uñas de acoplamiento. ¿Qué indica este silbido MÁS probablemente sobre esa conexión?","options":["El sello es totalmente hermético y la conexión pasó la prueba","Se está desviando presión de aire adicional para reforzar los frenos del remolque","El aire se está escapando de la conexión debido a una fuga","La línea de suministro acaba de terminar de purgar el agua acumulada"],"explanation":"Un silbido constante en el acople de las mangueras (glad hand) indica que el aire a presión se escapa por una fuga en el sello."},"244":{"q":"Conduzco un tractocamión con remolque equipado con un sistema ABS (frenos antibloqueo) en buen estado cuando un automóvil se detiene de golpe en mi carril. Necesito frenar lo más fuerte posible manteniendo el control del vehículo. ¿Cuál es la forma correcta de usar los frenos en esta emergencia?","options":["Bombear rápidamente el pedal del freno hacia arriba y abajo para que el ABS tenga tiempo de reaccionar entre cada aplicación","Pisar fuerte y soltar en cuanto sienta pulsar el pedal, repitiéndolo en ráfagas cortas","Tocar el pedal una vez para activar el ABS y luego esquivar el obstáculo sin volver a frenar","Pisar el pedal con firmeza y mantener una presión constante, dejando que el ABS evite que las ruedas se bloqueen para poder seguir dirigiendo"],"explanation":"Con ABS, pise el pedal de freno con firmeza y mantenga presión constante para que el sistema evite el bloqueo de las ruedas y usted conserve el control de la dirección."},"245":{"q":"Es una mañana de invierno helada y estoy haciendo mi inspección previa al viaje en un tractocamión con frenos de aire. Me doy cuenta de que olvidé drenar los tanques de aire durante los últimos días y noto humedad alrededor de las válvulas de drenaje. ¿Por qué importa esto para el sistema de frenos?","options":["El agua y el aceite del compresor que se acumulan en los tanques pueden dañar el sistema de frenos y congelarse con el frío, por eso los tanques deben drenarse a diario","Una pequeña cantidad de agua y aceite en los tanques en realidad lubrica y sella las válvulas de freno, así que saltarse el drenaje de vez en cuando es inofensivo","El agua y el aceite no afectan al frenado porque la válvula de alivio de seguridad simplemente los expulsa automáticamente a unos 150 psi","La humedad solo importa para los frenos de estacionamiento, así que mientras los frenos de servicio sujeten, puedo retrasar el drenaje con seguridad hasta la primavera"],"explanation":"Los tanques de aire deben drenarse a diario porque en ellos se acumulan agua y aceite del compresor, que pueden dañar el sistema de frenos o congelarse con el frío."},"246":{"q":"Es una mañana helada y durante la inspección previa al viaje nota que durante la noche se acumuló agua y un poco de lodo aceitoso en el tanque de suministro (húmedo). Para sacar esta contaminación antes de que se congele y dañe el sistema, ¿qué dispositivo acciona en ese tanque?","options":["La válvula de alivio de seguridad, abriéndola para ventear el tanque","La válvula de drenaje (llave de purga) en el fondo del tanque","El gobernador, desactivándolo para liberar la acumulación","El reinicio del zumbador de baja presión, para limpiar la línea"],"explanation":"El agua y el aceite se eliminan abriendo la válvula de drenaje, o llave de purga (petcock), ubicada en el fondo del tanque de aire."},"247":{"q":"Durante una inspección previaje, dejo que el sistema de aire suba a la presión máxima. De repente escucho un fuerte escape de aire desde la válvula de alivio de seguridad del tanque de suministro (húmedo). Antes de conducir, ¿qué me indica esto con mayor probabilidad sobre mi sistema?","options":["La advertencia de baja presión de aire falló, así que la presión del tanque cayó sin aviso por debajo de 60 psi.","El gobernador se activó antes de tiempo y el compresor dejó de enviar aire a los tanques.","El gobernador no logró cortar, así que la presión subió por encima de unos 150 psi y la válvula la liberó.","Una fuga lenta dejó caer la presión al rango de 20 a 45 psi y activó los frenos de resorte."],"explanation":"Si el regulador (governor) no desactiva el compresor, la presión sube por encima de unos 150 psi y la válvula de seguridad se abre para liberar el aire en exceso."},"248":{"q":"Durante mi inspección previaje, el mecánico del taller me dice que vaya a verificar que los \"maxi-frenos\" estén sujetando bien mientras el remolque está estacionado. No conozco ese término coloquial. ¿A qué componente de mi vehículo con frenos de aire se refiere realmente?","options":["Los frenos de servicio que aplico con el pedal durante una parada normal","La válvula moduladora que uso para aplicar los frenos gradualmente en una emergencia","Los ajustadores de holgura que controlan cuánto recorre la varilla de empuje","Los frenos de resorte que sujetan el vehículo y se aplican al perderse la presión de aire"],"explanation":"Los maxi-frenos son otro nombre de los frenos de resorte, que retienen el vehículo estacionado y se aplican automáticamente cuando se pierde la presión de aire."},"249":{"q":"Estoy pasando de un automóvil a un tractocamión cargado equipado con frenos de aire, y mi instructor me pregunta por qué dominar el sistema de frenos de aire es lo más importante para un conductor con CDL. ¿Qué respuesta refleja mejor el propósito principal de aprender los frenos de aire?","options":["Detener de forma segura y controlada un vehículo pesado y cargado","Permitir que el camión ruede libre y acelere a velocidades de crucero más altas","Reducir el consumo de combustible manteniendo el compresor del motor inactivo","Acortar la distancia total de frenado en comparación con los frenos hidráulicos"],"explanation":"El propósito principal de un sistema de frenos de aire es detener un vehículo pesado y cargado de forma segura y controlada."}},"hi":{"0":{"q":"अपने यात्रा-पूर्व निरीक्षण के दौरान, परीक्षक मुझसे अपने ट्रैक्टर पर एयर ब्रेक की व्यवस्था समझाने को कहता है। मैं बताता हूं कि एयर ब्रेक असल में कई अलग-अलग ब्रेकिंग सिस्टम मिलकर एक में बने होते हैं। कौन सा उत्तर सही बताता है कि एक एयर ब्रेक सिस्टम वास्तव में कितने अलग ब्रेकिंग सिस्टम को जोड़ता है, और उनके नाम बताता है?","options":["तीन सिस्टम: सर्विस ब्रेक, पार्किंग ब्रेक और इमरजेंसी ब्रेक।","दो सिस्टम: एक ही नियंत्रण सेट के साथ प्राथमिक और द्वितीयक वायु प्रणालियां।","चार सिस्टम: सर्विस ब्रेक, पार्किंग ब्रेक, इमरजेंसी ब्रेक और ABS।","एक सिस्टम: एक ही सर्किट जो सामान्य रुकाव, पार्किंग और आपात स्थितियों को एक साथ संभालता है।"],"explanation":"वायु ब्रेक प्रणाली वास्तव में तीन प्रणालियों का संयोजन है: सर्विस ब्रेक, पार्किंग ब्रेक और आपातकालीन ब्रेक।"},"1":{"q":"मैं अपनी प्री-ट्रिप जांच कर रहा हूं और डैशबोर्ड गेज को देखते हुए वायु दाब बढ़ाने के लिए इंजन को रेव कर रहा हूं। मैं उस दाब को नोट करके पुष्टि करना चाहता हूं कि गवर्नर सही काम कर रहा है जिस पर एयर कंप्रेसर टैंकों में हवा पंप करना बंद कर देता है। लगभग किस रीडिंग पर सुई का ऊपर चढ़ना रुक जाना चाहिए क्योंकि गवर्नर कट-आउट हो गया है?","options":["लगभग 100 psi, यह वह दाब है जिस पर कंप्रेसर टैंकों में हवा जोड़ना बंद कर देता है","लगभग 125 psi, इस बिंदु पर गवर्नर कट-आउट करता है और कंप्रेसर पंप करना बंद कर देता है","लगभग 150 psi, जहां सिस्टम अपने अधिकतम पर पहुंचता है और कंप्रेसर बंद हो जाता है","लगभग 60 psi, वह बिंदु जहां गवर्नर चार्ज सिस्टम में कंप्रेसर को रोकता है"],"explanation":"गवर्नर लगभग 125 psi पर कट-आउट होता है, जिससे कंप्रेसर टैंकों में और हवा भरना बंद कर देता है।"},"2":{"q":"मैं पार्क करके अपनी प्री-ट्रिप जाँच कर रहा हूँ और हवा के दबाव गेज को देख रहा हूँ। कंप्रेसर पहले बंद हो गया था और हवा पंप करना रोक चुका था, इसलिए जब मैं सिस्टम की जाँच कर रहा हूँ तो दबाव धीरे-धीरे गिर रहा है। गेज के किस रीडिंग पर मुझे उम्मीद करनी चाहिए कि गवर्नर कंप्रेसर को फिर से चालू कर दे और दोबारा हवा पंप करना शुरू कर दे?","options":["लगभग 60 psi, वही बिंदु जहाँ कम हवा दबाव चेतावनी लाइट और बजर चालू होते हैं","लगभग 125 psi, वह स्तर जिस पर गवर्नर कंप्रेसर को हवा पंप करने से रोक देता है","लगभग 100 psi, वह बिंदु जहाँ गवर्नर कंप्रेसर को दोबारा हवा पंप करने का संकेत देता है","लगभग 150 psi, वह स्तर जिस पर सुरक्षा रिलीफ वाल्व दबाव छोड़ने के लिए खुलता है"],"explanation":"गवर्नर का कट-इन बिंदु लगभग 100 psi होता है, जहाँ यह कंप्रेसर को फिर से हवा भरने का संकेत देता है।"},"3":{"q":"अपनी प्री-ट्रिप जाँच के दौरान मैं देखता हूँ कि एयर कंप्रेसर का गवर्नर कट-आउट नहीं हो रहा — गेज सामान्य 125 psi बिंदु, जहाँ पंपिंग रुकनी चाहिए, से ऊपर बढ़ता ही जा रहा है। यदि गवर्नर कभी कट-आउट न हो, तो सिस्टम को अधिक दबाव से बचाने के लिए सेफ्टी रिलीफ वाल्व लगभग किस दबाव पर खुलना चाहिए?","options":["लगभग 100 psi पर — उसी बिंदु पर जहाँ गवर्नर सामान्यतः कट-इन होकर पंपिंग फिर से शुरू करता है","लगभग 60 psi पर — उसी सीमा पर जो कम वायु दबाव की चेतावनी लाइट और बज़र को सक्रिय करती है","लगभग 125 psi पर — गवर्नर कट-आउट से मेल खाते हुए, ताकि दोनों उपकरण एक साथ काम करें","लगभग 150 psi पर — अतिरिक्त हवा को बाहर निकालकर ताकि सिस्टम खतरनाक दबाव तक न पहुँचे"],"explanation":"सुरक्षा रिलीफ वाल्व लगभग 150 psi पर खुलता है ताकि अतिरिक्त हवा निकाली जा सके और प्रणाली को खतरनाक दबाव से बचाया जा सके।"},"4":{"q":"मैं पूरी तरह चार्ज की गई एयर प्रणाली वाले एक अकेले ट्रैक्टर पर प्री-ट्रिप निरीक्षण कर रहा हूँ। इंजन बंद करके, मैं ब्रेक दबाकर चरण-दर-चरण हवा निकालता हूँ और डैशबोर्ड देखता हूँ। कम-हवा चेतावनी लाइट और बज़र किस बिंदु तक सक्रिय हो जाने चाहिए — यानी दबाव किस स्तर से नीचे गिरने से पहले चेतावनी पहले से ही चालू होनी चाहिए?","options":["हवा का दबाव 60 psi से नीचे गिरने से पहले","हवा का दबाव 80 psi से नीचे गिरने से पहले","केवल तब, जब दबाव पहले ही 20 से 45 psi की सीमा में गिर चुका हो","हवा का दबाव 100 psi से नीचे गिरने से पहले"],"explanation":"कम वायु दबाव की चेतावनी तब चालू होनी चाहिए जब प्रणाली का दबाव 60 psi से नीचे गिरने से पहले हो।"},"5":{"q":"मैं एक लदा हुआ अकेला ट्रैक्टर-ट्रेलर चला रहा हूँ, तभी एक लाइन फट जाती है और मेरा हवा का दबाव तेज़ी से गिरने लगता है। कम-हवा चेतावनी बत्ती और बज़र पहले से ही चालू हैं, और सूई गिरती जा रही है। लगभग किस दबाव पर मुझे उम्मीद करनी चाहिए कि स्प्रिंग (आपातकालीन) ब्रेक अपने आप लग जाएँ और मुझे रोक दें?","options":["लगभग 60 psi, वही बिंदु जहाँ कम-हवा चेतावनी पहली बार सक्रिय होती है","20 से 45 psi की सीमा में कहीं, चेतावनी पहले से चालू हो जाने के बाद","लगभग 100 psi, गवर्नर कट-इन बिंदु जहाँ कंप्रेसर फिर से चालू होता है","लगभग 5 से 10 psi, केवल तभी जब टैंक लगभग पूरी तरह खाली हो जाएँ"],"explanation":"स्प्रिंग (आपातकालीन/पार्किंग) ब्रेक तब स्वतः लग जाते हैं जब प्रणाली का वायु दबाव 20 से 45 psi की सीमा में गिर जाता है।"},"6":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, मेरा प्रशिक्षक उस पेडल की ओर इशारा करता है जिसे मैं सर्विस ब्रेक लगाने के लिए पैर से दबाता हूं, और उसका दूसरा सही नाम पूछता है। सही उत्तर देने के लिए, वह किस घटक की ओर इशारा कर रहा है?","options":["गवर्नर, क्योंकि यह नियंत्रित करता है कि पेडल कितनी ब्रेकिंग हवा पहियों तक छोड़ता है","स्लैक एडजस्टर, क्योंकि यह मेरे पैर के दबाव को यांत्रिक ब्रेकिंग बल में बदलता है","फुट (ट्रेडल) वाल्व, जो दबाने पर सर्विस ब्रेक तक हवा भेजता है","ग्लैड हैंड, क्योंकि यह वह कनेक्शन है जो मेरी ब्रेकिंग हवा को ब्रेक तक ले जाता है"],"explanation":"ब्रेक पेडल को सही रूप से फुट या ट्रेडल वाल्व कहा जाता है, जो दबाने पर सर्विस ब्रेक को हवा भेजता है।"},"7":{"q":"कड़ाके की ठंड वाली सर्दियों की सुबह है और अपनी यात्रा-पूर्व जांच के दौरान मैं एयर टैंक के निचले हिस्से पर लगा ड्रेन वाल्व खोलता हूं। हवा के साथ-साथ एक दूधिया, तैलीय तरल छीटें मारता बाहर आता है। एक सहकर्मी कहता है कि मुझे कोई गंभीर यांत्रिक समस्या होगी क्योंकि यह तरल टैंक में कभी नहीं होना चाहिए। कौन सा कथन सही ढंग से बताता है कि मैं क्या देख रहा हूं और मैं टैंकों को रोज़ाना क्यों ड्रेन करता हूं?","options":["केवल हवा निकलनी चाहिए; यह तरल बताता है कि एक चटका हुआ टैंक हवा आपूर्ति में ब्रेक फ्लुइड लीक कर रहा है","शीतलक (कूलेंट) एक खराब सील से होकर टैंक में रिस गया है, इसलिए मुझे इसे ब्रेक चैंबरों तक पहुंचने से पहले ड्रेन करना चाहिए","लीक हो रहा ब्रेक फ्लुइड हवा के साथ मिल गया है, और रोज़ाना ड्रेन करना उस तरल को सिस्टम से बाहर निकाल देता है","संपीडित हवा आमतौर पर पानी और कुछ कंप्रेसर तेल जमा कर लेती है, और रोज़ाना ड्रेन करना इसे हटा देता है ताकि जमने और नुकसान से बचा जा सके"],"explanation":"संपीड़ित हवा में स्वाभाविक रूप से पानी और कुछ कंप्रेसर तेल जमा हो जाता है, इसलिए जमने और क्षति से बचने के लिए टैंकों को रोज़ निकालना चाहिए।"},"8":{"q":"सर्दियों की एक सुबह तापमान जमाव बिंदु से नीचे है, और मुझे दिखता है कि मेरा ट्रक सप्लाई (वेट) टैंक पर लगे एयर ड्रायर से सुसज्जित है। अपनी प्री-ट्रिप जाँच के दौरान, मैं इस पुर्जे का मुख्य काम याद करने की कोशिश कर रहा हूँ। कौन-सा कथन सबसे अच्छी तरह बताता है कि एयर ड्रायर मेरे एयर ब्रेक सिस्टम के लिए क्या करता है?","options":["यह संपीड़ित हवा से पानी और दूषित पदार्थों को हटाता है, इससे पहले कि वह हवा भंडारण टैंकों तक पहुँचे","यह संपीड़ित हवा को गवर्नर कट-आउट से ऊपर बढ़ाता है ताकि टैंक अधिक कार्यशील दबाव तक पहुँच सकें","यह टैंक का दबाव 60 psi से नीचे गिरने से पहले कम वायु दबाव चेतावनी बत्ती और बजर चालू करता है","यह लंबी, खड़ी ढलान के बाद गर्म हुए ब्रेक ड्रम और लाइनिंग को ठंडा करता है ताकि ब्रेक फेड से बचा जा सके"],"explanation":"एयर ड्रायर संपीड़ित हवा से पानी और दूषित पदार्थ हटा देता है, इससे पहले कि वह भंडारण टैंकों तक पहुँचे।"},"9":{"q":"मैं एक ट्रैक्टर-ट्रेलर पर अपनी प्री-ट्रिप जांच कर रहा हूं और इंजन अभी-अभी गवर्नर कट-आउट तक पहुंचा है। डैशबोर्ड को देखते समय, मुझे साथ-साथ दो एयर गेज दिखते हैं। ब्रेक छोड़कर निकलने से पहले यह पुष्टि करने के लिए कि मेरे पास पर्याप्त संग्रहित हवा है, सप्लाई प्रेशर गेज (supply pressure gauge) की कौन-सी रीडिंग मुझे वह जानकारी देती है जिसकी मुझे जरूरत है?","options":["पेडल दबाने पर मैं इस समय ब्रेक चैंबरों में जितना दबाव भेज रहा हूं, उसकी मात्रा","इस समय एयर टैंकों में संग्रहित हवा के दबाव की मात्रा (कट-आउट पर लगभग 125 psi)","वह दबाव जिस पर हवा कम होने पर स्प्रिंग ब्रेक अपने आप लग जाएंगे","वह दबाव जिस पर सिस्टम की सुरक्षा के लिए सेफ्टी रिलीफ वाल्व खुलने के लिए सेट है"],"explanation":"सप्लाई प्रेशर गेज दिखाता है कि इस समय वायु टैंकों में कितना वायु दबाव संग्रहीत है, कट-आउट पर लगभग 125 psi।"},"10":{"q":"मैं अपने लदे हुए ट्रक के साथ एक लंबी ढलान से नीचे उतर रहा हूँ और अपनी गति बनाए रखने के लिए ब्रेक पेडल को और जोर से दबा रहा हूँ। जैसे-जैसे मैं पेडल (ब्रेक वाल्व) को और गहरा दबाता हूँ, डैश पर एक गेज ऊपर चढ़ता जाता है, और जब मैं पैर हटाता हूँ तो वह वापस शून्य की ओर गिर जाता है। मैं किस गेज को अपने पैर की गति पर प्रतिक्रिया करते हुए देख रहा हूँ?","options":["एयर टैंक (सप्लाई) प्रेशर गेज, क्योंकि यह बताता है कि टंकियों में कितनी हवा बची है","गवर्नर कट-आउट गेज, क्योंकि यह दिखाता है कि कंप्रेसर लगभग 125 psi पर रुकता है","एप्लिकेशन प्रेशर गेज, क्योंकि यह दिखाता है कि मैं ब्रेक पर कितना हवा का दबाव लगा रहा हूँ","लो एयर प्रेशर चेतावनी गेज, क्योंकि दबाव 60 psi से नीचे गिरने से पहले यह जल उठता है"],"explanation":"एप्लिकेशन प्रेशर गेज दिखाता है कि आप पैडल से ब्रेक पर कितना हवा का दबाव भेज रहे हैं।"},"11":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, मेरा प्रशिक्षक ब्रेक असेंबली पर लगे S-कैम (S-cam) की ओर इशारा करता है और मुझसे समझाने को कहता है कि जिस क्षण मैं ब्रेक पेडल दबाता हूँ और हवा ब्रेक चैंबर तक पहुँचती है, उस पुर्जे पर भौतिक रूप से क्या होता है। कौन-सा उत्तर S-कैम के काम का सही वर्णन करता है?","options":["यह हवा के टैंकों से पानी और कंप्रेसर का तेल बाहर निकालता है ताकि लाइनें जम न जाएँ","जब टैंक लगभग 125 psi तक पहुँच जाते हैं तो यह गवर्नर को कंप्रेसर रोकने का संकेत देता है","यह पुशरॉड के फ्री-प्ले को कम करने के लिए स्लैक एडजस्टर को पीछे खींचता है","यह घूमकर ब्रेक शूज़ को अलग धकेलता है और उन्हें ड्रम की भीतरी सतह से दबाता है"],"explanation":"S-कैम घूमकर ब्रेक शूज़ के बीच फंस जाता है और उन्हें ड्रम की अंदरूनी सतह की ओर धकेलता है।"},"12":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान मैं समतल जमीन पर वाहन खड़ा करता हूँ, पहियों के नीचे चॉक लगाता हूँ, पार्किंग ब्रेक छोड़ता हूँ, और अत्यधिक पुशरॉड गति जाँचने के लिए एक प्राइ बार से मैनुअल स्लैक एडजस्टर को दबाता हूँ। यदि स्लैक एडजस्टर लगभग इससे अधिक हिलता है तो ब्रेक एडजस्टमेंट से बाहर हैं:","options":["1 इंच, क्योंकि अधिक खाली खेल का मतलब है कि ब्रेक एडजस्टमेंट से बाहर हैं और ब्रेकिंग शक्ति खो देते हैं","3 इंच, जो ब्रेक के एडजस्टमेंट से बाहर होने से पहले अनुमत अधिकतम गति है","5 इंच, क्योंकि इससे कम कुछ भी ब्रेक को अब भी सही एडजस्टमेंट में रखता है","यह स्वतंत्र रूप से हिल सकता है, क्योंकि स्लैक एडजस्टर बिना किसी गति सीमा के झूलने के लिए बनाए जाते हैं"],"explanation":"मैनुअल स्लैक एडजस्टर खींचने पर लगभग 1 इंच से ज़्यादा नहीं हिलना चाहिए, वरना ब्रेक एडजस्टमेंट से बाहर हैं।"},"13":{"q":"मैं एयर ब्रेक वाला एक ट्रैक्टर-ट्रेलर चला रहा हूँ और आगे के ट्रैफ़िक के लिए गति कम करने के लिए ब्रेक पेडल को ज़ोर से दबाता हूँ। मेरी कार के हाइड्रोलिक ब्रेक की तुलना में, एयर ब्रेक के वास्तव में पकड़ने से पहले एक स्पष्ट देरी होती है। यह एयर ब्रेक लैग लगभग कितना होता है — पेडल दबाने के बाद हवा को लाइनों से होकर गुज़रने और काम करने में लगने वाला समय?","options":["लगभग 1/10 सेकंड, वही लगभग तुरंत प्रतिक्रिया जो मैं कार की हाइड्रोलिक ब्रेक प्रणाली में महसूस करता हूँ","लगभग 1/2 सेकंड, जिसमें हवा लाइनों से होकर गुज़रती है और ब्रेक पकड़ने लगते हैं","लगभग 2 सेकंड, जो चालक के पेडल दबाने से पहले की प्रतिक्रिया-दूरी की देरी से लगभग मेल खाता है","लगभग 5 सेकंड, क्योंकि कोई भी ब्रेकिंग शुरू होने से पहले हवा को हर चैंबर को पूरी तरह भरना पड़ता है"],"explanation":"एयर ब्रेक में लगभग आधे सेकंड की देरी होती है क्योंकि संपीड़ित हवा लाइनों से होकर पहुंचने में समय लेती है।"},"14":{"q":"मैं अपने एयर-ब्रेक (वायु ब्रेक) ट्रक के लिए कुल रुकने की दूरी की गणना कर रहा हूँ। हाइड्रोलिक ब्रेक वाली कार के लिए कुल रुकने की दूरी केवल बोध दूरी (perception) जमा प्रतिक्रिया दूरी (reaction) जमा ब्रेकिंग दूरी होती है। चूँकि मेरा ट्रक एयर ब्रेक का उपयोग करता है, इस गणना में मुझे कौन-सा अतिरिक्त भाग जोड़ना होगा जो कार चालक के पास नहीं होता?","options":["एक अतिरिक्त प्रतिक्रिया दूरी, क्योंकि एयर-ब्रेक नियंत्रण चलाने में दिमाग को अधिक समय लगता है","एक लंबी बोध दूरी, क्योंकि ट्रक बड़ा होने से खतरों को समय पर देखना कठिन हो जाता है","एक ब्रेक-लैग दूरी, उस लगभग आधे सेकंड के लिए जिसमें हवा लाइनों से होकर पहुँचती है और ब्रेक लगते हैं","कुछ भी अतिरिक्त नहीं, क्योंकि चारों मूल दूरियाँ हर प्रकार की ब्रेक प्रणाली के लिए एक समान होती हैं"],"explanation":"एयर ब्रेक की रुकने की दूरी में ब्रेक-लैग दूरी जुड़ती है, उस आधे सेकंड के लिए जब हवा लाइनों से गुज़रकर लगती है।"},"15":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, मैं सिस्टम को लगभग 125 psi तक पूरी तरह चार्ज करके इंजन बंद कर देता हूँ, पहियों के नीचे चॉक लगाता हूँ, और अपने एकल (बिना ट्रेलर वाले) ट्रक में पार्किंग ब्रेक छोड़े हुए (रिलीज़) रखता हूँ। रिसाव मापने के लिए मैं डैश गेज को पूरे एक मिनट तक देखता हूँ। हवा का नुकसान केवल तभी स्वीकार्य है जब वह किस दर पर या उससे कम बना रहे?","options":["4 psi प्रति मिनट, क्योंकि इंजन बंद और टैंक भरे होने पर यही सीमा है","1 psi प्रति मिनट, इस धारणा पर कि सीलबंद सिस्टम से लगभग कोई हवा नहीं निकलनी चाहिए","3 psi प्रति मिनट, यही आँकड़ा इस परीक्षण में संयुक्त (कॉम्बिनेशन) वाहन पर लागू होता है","2 psi प्रति मिनट, ब्रेक छोड़े हुए एकल वाहन के लिए अनुमत अधिकतम सीमा"],"explanation":"फ्रेन छोड़े जाने पर एकल वाहन के लिए हवा की हानि प्रति मिनट 2 psi से अधिक नहीं होनी चाहिए।"},"16":{"q":"ट्रैक्टर-ट्रेलर पर अपने प्री-ट्रिप निरीक्षण के दौरान, मैं सिस्टम को पूरी तरह लगभग 125 psi तक चार्ज करता हूँ, इंजन बंद करता हूँ, और हवा के रिसाव को मापने के लिए ब्रेक छोड़े हुए रखता हूँ। एक मिनट तक डैश के दबावमापी को देखते हुए, इस निरीक्षण के इस भाग को पास करने के लिए अधिकतम कितना दबाव गिर सकता है?","options":["एक मिनट में 3 psi","एक मिनट में 2 psi","एक मिनट में 4 psi","एक मिनट में 6 psi"],"explanation":"फ्रेन छोड़े जाने पर संयोजन वाहन के लिए हवा की हानि प्रति मिनट 3 psi से अधिक नहीं होनी चाहिए।"},"17":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं हवा प्रणाली को लगभग 125 psi तक भरता हूँ, इंजन बंद करता हूँ, पहियों के नीचे चॉक लगाता हूँ, और बिना ट्रेलर वाले अपने एकल सीधे ट्रक में पैर के ब्रेक को पूरी तरह दबाता हूँ। हवा रिसाव दर जाँचने के लिए मैं एक मिनट तक डैशबोर्ड गेज को देखता हूँ। कौन-सा रीडिंग दर्शाता है कि मेरा ट्रक कानूनी सीमा के भीतर है और चलाने के लिए सुरक्षित है?","options":["उस मिनट में दबाव 4 psi गिरता है","उस मिनट में दबाव 2 psi गिरता है","उस मिनट में दबाव 5 psi गिरता है","उस मिनट में दबाव 6 psi गिरता है"],"explanation":"फ्रेन लगाने पर एकल वाहन के लिए हवा की हानि प्रति मिनट 3 psi से कम रहनी चाहिए।"},"18":{"q":"ड्यूल एयर ब्रेक सिस्टम पर अपने यात्रा-पूर्व निरीक्षण के दौरान, मैं इंजन चालू करता हूं, उसे ऑपरेटिंग आरपीएम पर रखता हूं और डैश गेज को 85 psi से ऊपर चढ़ते हुए देखता हूं। हवा के दबाव बनने वाली जांच को पास करने के लिए, गेज को कितने समय में 100 psi तक पहुंचना चाहिए?","options":["ऑपरेटिंग आरपीएम पर 10 सेकंड के भीतर","ऑपरेटिंग आरपीएम पर 3 मिनट के भीतर","ऑपरेटिंग आरपीएम पर 45 सेकंड के भीतर","ऑपरेटिंग आरपीएम पर 5 मिनट के भीतर"],"explanation":"डुअल एयर ब्रेक सिस्टम में दबाव ऑपरेटिंग आरपीएम पर 45 सेकंड के भीतर 85 से 100 psi तक बढ़ना चाहिए।"},"19":{"q":"अपनी प्री-ट्रिप जाँच के दौरान इंजन बंद है और मेरे एयर टैंक लगभग 125 psi तक चार्ज हैं। गाड़ी चलाने से पहले मैं पुष्टि करना चाहता हूँ कि कम वायु दबाव चेतावनी उपकरण सही काम कर रहा है। कौन-सी क्रिया वास्तव में यह जाँच करती है?","options":["सिस्टम चार्ज रखते हुए इंजन को ऊँची आरपीएम पर चलाएँ और देखें कि जैसे ही दबाव 60 psi से ऊपर बढ़े, चेतावनी जलती है या नहीं","टैंक के ड्रेन वाल्व पूरे खोल दें ताकि सारी हवा टैंकों से तेज़ी से निकल जाए, फिर बज़र की आवाज़ सुनें","ब्रेक पेडल एक बार दबाएँ और पुष्टि करें कि 100 psi से ऊपर चेतावनी उपकरण बंद रहता है","इंजन बंद रखते हुए ब्रेक पेडल को बार-बार दबाएँ और छोड़ें ताकि दबाव घटे और 60 psi से ऊपर ही चेतावनी चालू हो जाए"],"explanation":"इंजन बंद करके ब्रेक को बार-बार दबाकर दबाव कम करें और पुष्टि करें कि दबाव 60 psi से नीचे गिरने से पहले लो-एयर चेतावनी चालू हो जाती है।"},"20":{"q":"अपनी यात्रा-पूर्व एयर ब्रेक जाँच के दौरान, मैंने सिस्टम को पूर्ण दबाव तक भर लिया है, पार्किंग ब्रेक छोड़ दिया है, और यह जाँचने के लिए तैयार हूँ कि सर्विस ब्रेक वास्तव में रिग को पकड़कर सीधा रोकते हैं। सर्विस ब्रेक स्टॉप परीक्षण करने का सही तरीका इनमें से कौन-सा है?","options":["वाहन को लगभग 5 मील प्रति घंटे की गति से आगे बढ़ने दें, फिर ब्रेक पेडल को मजबूती से दबाएँ और पुष्टि करें कि यह किसी एक ओर खिंचे बिना रुक जाता है","सामान्य हाईवे गति तक तेज़ करें और एक बार ज़ोर से ब्रेक लगाएँ ताकि पुष्टि हो कि ब्रेक पूर्ण रोक को संभाल सकते हैं","वाहन को स्थिर रखकर पार्किंग ब्रेक नॉब को बाहर खींचें और महसूस करें कि ट्रैक्टर अपनी जगह पर लॉक रहता है या नहीं","लगभग 5 मील प्रति घंटे की गति से चलते हुए ब्रेक पेडल को तेज़ी से दस बार दबाएँ ताकि पुष्टि हो कि दबाव हर बार फिर से बनता है"],"explanation":"सर्विस ब्रेक की सही जांच: लगभग 5 mph पर आगे बढ़ें, पेडल को मजबूती से दबाएं, और वाहन एक तरफ खिंचे बिना सीधा रुकना चाहिए।"},"21":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मुझे एक ब्रेक ड्रम की सतह पर फैली हुई एक दरार मिलती है। मुझे यह तय करना है कि रिग को सेवा से बाहर करना है या नहीं। टेक्सास CDL हैंडबुक के अनुसार, एक दरार वाला ब्रेक ड्रम तब सेवा से बाहर माना जाता है जब दरार निम्नलिखित में से किससे अधिक लंबी हो?","options":["ड्रम की सतह पर कोई भी दिखाई देने वाली महीन (बाल जैसी) दरार","ड्रम की घर्षण सतह की चौड़ाई का आधा हिस्सा","ड्रम की घर्षण सतह की चौड़ाई का एक-चौथाई हिस्सा","ड्रम की घर्षण सतह की पूरी चौड़ाई"],"explanation":"ब्रेक ड्रम को सेवा से बाहर करना चाहिए जब दरार ड्रम की घर्षण सतह की चौड़ाई के आधे से अधिक लंबी हो।"},"22":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं एक पहिया निकालकर ट्रेलर के नीचे रेंगकर ड्रम ब्रेक देखता हूँ। मुझे एक समस्या मिलती है और मैं तय करता हूँ कि गाड़ी चलाने से पहले ब्रेक लाइनिंग बदलनी होगी। निम्नलिखित में से ब्रेक लाइनिंग की कौन-सी स्थिति इस वाहन को सेवा से बाहर करने को सही रूप से उचित ठहराएगी?","options":["लाइनिंग मोटी, सूखी और बैकिंग प्लेट से मजबूती से सटी हुई हैं","लाइनिंग ड्रम से समान रूप से सटी हैं और समान, हल्का सतही घिसाव दिखाती हैं","लाइनिंग तेल या ग्रीस से तर हैं, या खतरनाक रूप से पतली घिस गई हैं","लाइनिंग अभी-अभी लगाई गई हैं और शुरुआती बैठने से हल्की चमक है"],"explanation":"ब्रेक लाइनिंग दोषपूर्ण है और वाहन को सेवा से बाहर करना चाहिए जब वे तेल या ग्रीस से भीगी हों या खतरनाक रूप से पतली घिस गई हों।"},"23":{"q":"मैं एक लदे हुए संयोजन वाहन को एक लंबी, खड़ी ढलान से नीचे ले जा रहा हूँ। नीचे उतरना शुरू करने से पहले मैंने एक निचले गियर में बदल लिया है, और अब मैं सोच रहा हूँ कि बाकी उतराई के लिए अपने एयर ब्रेक का उपयोग कैसे करूँ। कौन सा कथन सही ढंग से बताता है कि इस ढलान पर मेरे ब्रेक की क्या भूमिका होनी चाहिए?","options":["वे मेरा मुख्य गति नियंत्रण हैं, इसलिए मुझे पूरी उतराई के दौरान पैडल पर लगातार दबाव बनाए रखना चाहिए","वे तब सबसे अच्छा काम करते हैं जब उन्हें बार-बार दबाया और छोड़ा जाए, हर बार के बीच हवा को फिर से भरने दिया जाए","पहियों को बिल्कुल भी गति न पकड़ने देने के लिए उन्हें मजबूती से और लगातार दबाए रखना चाहिए","वे इंजन ब्रेकिंग के पूरक हैं, जिन्हें निचले गियर का समर्थन करने के लिए हल्के, स्थिर रूप से लगाया जाता है"],"explanation":"लंबी ढलान पर कम गियर में इंजन गति नियंत्रण का मुख्य साधन है, और ब्रेक केवल हल्के, स्थिर प्रयोग से उसका पूरक होते हैं।"},"24":{"q":"मैं अपने लदे हुए संयुक्त वाहन के साथ एक लंबी, खड़ी ढलान पर उतर रहा हूँ, पहले से ही निचले गियर में हूँ, और अपनी गति को नियंत्रण में रखने के लिए सही स्नब-ब्रेकिंग (अंतराल वाली ब्रेकिंग) तकनीक का उपयोग करना चाहता हूँ। कौन-सी क्रिया सही ढंग से बताती है कि मुझे ब्रेक के साथ क्या करना चाहिए?","options":["ब्रेक को तब तक मजबूती से लगाएँ जब तक मेरी गति मेरी सुरक्षित गति से लगभग 5 मील प्रति घंटे नीचे न आ जाए, फिर उन्हें पूरी तरह छोड़ दें, और आवश्यकतानुसार इस चक्र को दोहराएँ","गर्मी कभी न बने इसके लिए पूरी ढलान भर ब्रेक पेडल पर लगातार स्थिर, हल्का दबाव बनाए रखें","पहियों को लॉक होने से बचाने के लिए पूरे उतार के दौरान ब्रेक को तेज़ी से दबाते और छोड़ते हुए पंप करें","न्यूट्रल में डालकर लुढ़कने दें, और केवल तभी ब्रेक लगाएँ जब स्पीडोमीटर मेरी सुरक्षित गति से ऊपर चढ़े"],"explanation":"लंबी ढलान पर स्नब ब्रेकिंग का उपयोग करें: गति आपकी सुरक्षित गति से लगभग 5 mph नीचे आने तक ब्रेक को मजबूती से लगाएं, ठंडा होने के लिए पूरी तरह छोड़ें, फिर दोहराएं।"},"25":{"q":"मैं एयर ब्रेक वाले लदे हुए ट्रक में एक लंबी, खड़ी पहाड़ी ढलान से नीचे उतर रहा हूँ। ढलान खत्म ही नहीं हो रही और मुझे अपने ब्रेक की चिंता है, इसलिए मैं अपनी गति को नियंत्रण में रखने के लिए ब्रेक पैडल को बार-बार तेजी से दबाना और छोड़ना शुरू कर देता हूँ। ऐसा करना बिल्कुल गलत क्यों है?","options":["बार-बार रुक-रुक कर ब्रेक लगाने से स्लैक एडजस्टर अधिक गर्म हो जाते हैं और आगे के पहिए जाम हो जाते हैं, जिससे ट्रक ढलान पर फिसलकर नियंत्रण से बाहर हो जाता है","हर बार पैडल छोड़ने पर हवा उतनी तेजी से निकलती है जितनी जल्दी कंप्रेसर उसकी भरपाई नहीं कर पाता, इसलिए दबाव इतना गिर सकता है कि ब्रेक के पास काम करने के लिए पर्याप्त हवा न बचे","पैडल को तेजी से दबाने-छोड़ने से ABS सक्रिय होकर ब्रेक पूरी तरह छोड़ देता है, जिससे धीमा होने का एकमात्र तरीका स्प्रिंग (पार्किंग) ब्रेक रह जाते हैं","पैडल पंप करने से सुरक्षा रिलीफ वाल्व 150 psi पर खुल जाता है, जिससे टैंक की वह हवा निकल जाती है जिसकी आपको बाकी उतराई के लिए जरूरत है"],"explanation":"ब्रेक को बार-बार पंप करने से हवा कंप्रेसर की पूर्ति की तुलना में तेजी से निकलती है, इसलिए दबाव गिरकर इतना कम हो सकता है कि ब्रेक को काम करने के लिए पर्याप्त हवा न बचे।"},"26":{"q":"मैंने अभी-अभी एक खड़ी पहाड़ी ढलान से लंबा उतराई पूरा किया है, पूरे रास्ते एयर ब्रेक दबाए रखे, और अपने अनिवार्य विश्राम के लिए एक विश्राम स्थल में प्रवेश कर रहा हूँ। इनमें से किस स्थिति में मुझे पार्किंग (स्प्रिंग) ब्रेक नहीं लगाना चाहिए, बल्कि पहियों के नीचे रोक (चॉक) लगाना चाहिए?","options":["मैं हल्की उतराई वाली ढलान पर पार्क कर रहा हूँ जहाँ गियर में छोड़ने पर गाड़ी लुढ़क सकती है","मैं ट्रक को रात भर एक चिह्नित ट्रक लॉट में बिना निगरानी के छोड़ूँगा","ब्रेक ड्रम और शू अभी-अभी किए गए उतराई से अब भी बेहद गर्म हैं","रुकते समय कम वायु दबाव चेतावनी बजर थोड़ी देर के लिए बजा"],"explanation":"लंबी उतराई के बाद जब ड्रम और शूज़ अभी भी बहुत गर्म हों तो पार्किंग (स्प्रिंग) ब्रेक न लगाएं, क्योंकि इससे वे क्षतिग्रस्त हो सकते हैं और जाम हो सकते हैं।"},"27":{"q":"यदि गाड़ी चलाते समय लो-एयर चेतावनी (low-air warning) आ जाए, तो आपको चाहिए:","options":["अगले शहर तक चलते रहना","सुरक्षित होते ही रुककर पार्क करना","चेतावनी को बंद कर देना","एयर बनाने के लिए गति बढ़ाना"],"explanation":"एयर के नुकसान से स्प्रिंग ब्रेक अचानक लग सकते हैं।"},"28":{"q":"मैं 2020 का ट्रैक्टर-ट्रेलर (चालू ABS से लैस) चला रहा हूं, तभी एक कार अचानक मेरी ही लेन में रुक जाती है। मुझे जितनी जल्दी हो सके रुकना है और साथ ही रिग को अपनी लेन में रखकर किनारे (शोल्डर) पर जाने से बचना है। इस आपात स्थिति में मुझे सबसे अच्छा नियंत्रण कौन सा ब्रेकिंग तरीका देगा?","options":["ब्रेक पैडल को तेज़ी से पंप करूं ताकि ABS हर बार छोड़ने के बीच चक्र चला सके और पकड़ बना सके","ट्रैक्टर के पहियों को फिसलने से रोकने के लिए पहले केवल ट्रेलर हैंड वाल्व लगाऊं","जैसे ही मुझे लगे कि कोई पहिया स्किड करने लगा है, उसी क्षण दबाव कम करूं, फिर दोबारा दबाऊं","ब्रेक पैडल को ज़ोर से दबाऊं, दबाए रखूं, और स्टीयरिंग को खुली लेन की ओर मोड़ता रहूं"],"explanation":"ABS के साथ, स्टीयर करते हुए ब्रेक को जोर से दबाएं और पेडल पर दृढ़ दबाव बनाए रखें, क्योंकि ABS पहियों को लॉक होने से रोकता है ताकि आप खुली लेन की ओर मुड़ सकें।"},"29":{"q":"मैं एक पुराना ट्रैक्टर-ट्रेलर चला रहा हूँ जिसमें ABS नहीं लगा है, और अचानक एक कार मेरे सामने आ जाती है। मुझे वाहन को नियंत्रण में रखते हुए कठोर आपातकालीन रोक लगानी है। मुझे कौन-सी ब्रेकिंग विधि का उपयोग करना चाहिए?","options":["नियंत्रित या स्टैब (रुक-रुक कर) ब्रेकिंग का उपयोग करूँ ताकि पहिए घूमते रहें और मैं स्टीयरिंग कर सकूँ","ब्रेक पेडल को पूरी तरह फर्श तक दबाऊँ और रुकने तक उसे ज़ोर से दबाए रखूँ","इतनी ज़ोर से ब्रेक लगाऊँ कि पहिए लॉक हो जाएँ, क्योंकि लॉक हुए पहिए सबसे छोटी रोक देते हैं","हवा का दबाव बनाए रखने के लिए ब्रेक पेडल को पूरी तरह नीचे तक तेज़ी से पंप करूँ"],"explanation":"ABS के बिना, नियंत्रित या स्टैब ब्रेकिंग का उपयोग करें ताकि पहिए घूमते रहें, जिससे रुकने की शक्ति और स्टीयरिंग नियंत्रण दोनों बने रहें।"},"30":{"q":"मैं बिना ABS वाला एक लदा हुआ ट्रक चला रहा हूं, तभी कोई चीज़ अचानक सड़क पर आ जाती है और मुझे ज़ोर से ब्रेक लगाना पड़ता है। मैं ब्रेक पैडल पूरी तरह दबाता हूं, पहिए लॉक हो जाते हैं, और मैं स्टैब (रुक-रुककर) ब्रेकिंग शुरू करने के लिए पैडल छोड़ देता हूं। स्टैब ब्रेकिंग सही ढंग से करने के लिए, मुझे पैडल को दोबारा ज़ोर से कब दबाना चाहिए?","options":["जैसे ही मैं पैडल छोड़ूं, किसी चीज़ का इंतज़ार किए बिना","केवल तब, जब पहिए दोबारा घूमना शुरू कर दें","ब्रेक को लगभग 10 सेकंड तक छोड़े रखने के बाद","बिल्कुल नहीं — एक बार छोड़ने के बाद, मुझे स्टियर करके संभालना चाहिए"],"explanation":"स्टैब ब्रेकिंग में आप ब्रेक को तभी फिर से लगाते हैं जब पहिए दोबारा घूमने लगें, क्योंकि लॉक हुए पहिए न तो स्टीयर कर सकते हैं और न ही प्रभावी ढंग से ब्रेक लगा सकते हैं।"},"31":{"q":"आप अपने सफर में 30 मील चल चुके हैं जब डैशबोर्ड पर ABS खराबी की पीली चेतावनी बत्ती जलती है और जलती ही रहती है। आपकी कम वायु दाब चेतावनी सक्रिय नहीं हुई है और पेडल अब भी मजबूत महसूस होता है। निम्नलिखित में से कौन-सा आपकी स्थिति और सही कार्रवाई का सही वर्णन करता है?","options":["आपके सर्विस ब्रेक फेल हो गए हैं; वाहन को तुरंत नियंत्रित तरीके से किनारे रोकें और आगे चलने से पहले टो (खींचने वाली गाड़ी) बुलाएँ।","अब आपकी रुकने की दूरी सामान्य से अधिक है, इसलिए अपनी पीछा करने की दूरी बढ़ाएँ और पहियों तक हवा पहुँचती रहे इसके लिए ब्रेक पेडल को बार-बार दबाएँ।","आपके पास अब भी सामान्य सर्विस ब्रेक हैं और आप सावधानी से चलाते रह सकते हैं; केवल एंटी-लॉक कार्य खत्म हुआ है, इसलिए जल्द से जल्द ABS की सर्विसिंग करवाएँ।","आपके स्प्रिंग (पार्किंग) ब्रेक अपने-आप लगने वाले हैं, इसलिए गति कम करें और पहिए लॉक होने से पहले अगले रैंप से बाहर निकलें।"],"explanation":"ABS चेतावनी लाइट का मतलब है कि केवल एंटी-लॉक कार्य खो गया है; आपके सामान्य सर्विस ब्रेक पूरी तरह काम करते हैं, इसलिए सावधानी से चलाएं और ABS की जल्द मरम्मत कराएं।"},"32":{"q":"मैं एक पुराना ट्रक ट्रैक्टर खरीद रहा हूँ और यह पुष्टि करना चाहता हूँ कि यह फैक्ट्री से एंटी-लॉक ब्रेक (ABS) के साथ आया था, क्योंकि संघीय नियमों ने कुछ एयर-ब्रेक वाहनों पर ABS को अनिवार्य कर दिया है। डीलर मुझे अलग-अलग वर्षों में बने चार ट्रैक्टर दिखाता है। वह सबसे पहली निर्माण तिथि कौन सी है जो ट्रैक्टर में फैक्ट्री-स्थापित ABS होना अनिवार्य बना देगी?","options":["1 मार्च 1998 या उसके बाद बना कोई भी ट्रैक्टर","1 मार्च 1995 या उसके बाद बना कोई भी ट्रैक्टर","1 मार्च 2000 या उसके बाद बना कोई भी ट्रैक्टर","1 मार्च 1997 या उसके बाद बना कोई भी ट्रैक्टर"],"explanation":"संघीय नियम 1 मार्च 1997 को या उसके बाद बने ट्रक ट्रैक्टरों में फैक्ट्री ABS अनिवार्य करते हैं।"},"33":{"q":"यदि गाड़ी चलाते समय ड्यूल सिस्टम का एक सर्किट फेल हो जाए:","options":["आप पूरी ब्रेकिंग खो देते हैं","दूसरा फिर भी आपको रोक देता है","इंजन बंद हो जाता है","केवल लाइटें फेल होती हैं"],"explanation":"दूसरा सर्किट फिर भी आपको ब्रेक करता है; चेतावनी आ जाती है।"},"34":{"q":"अमरिलो में दिसंबर की एक हिमांक-से-नीचे वाली सुबह है और मैं अपनी यात्रा-पूर्व जांच कर रहा हूं। मेरे ट्रक के एयर टैंकों पर मैनुअल ड्रेन वाल्व हैं, पर मुझे देर हो रही है, इसलिए मन कर रहा है कि आज ड्रेन करना छोड़ दूं। फिर भी निकलने से पहले मुझे टैंक ड्रेन खोलने का सबसे अच्छा कारण कौन सा है?","options":["टैंकों में जमा होने वाला पानी ठंड में जम सकता है और ब्रेक को काम करने से रोक सकता है","टैंक ड्रेन करने से गवर्नर अधिक दबाव पर कट-आउट करता है जिससे सिस्टम तेजी से चार्ज होता है","ड्रेन खोलने से पुरानी हवा निकल जाती है ताकि सेफ्टी रिलीफ वाल्व सही 150 psi सेटिंग पर फिर से बैठ जाए","हवा छोड़ने से लो-एयर चेतावनी रीसेट हो जाती है ताकि 60 psi से नीचे बजर न बजे"],"explanation":"हवा टैंक रोज़ खाली करें, क्योंकि जमा पानी ठंडे मौसम में जम सकता है और ब्रेक को काम करने से रोक सकता है।"},"35":{"q":"मैं एक ट्रैक्टर-ट्रेलर पर अपनी प्री-ट्रिप जांच पूरी कर रहा हूं। इंजन निष्क्रिय (आइडल) चल रहा है और एयर प्रेशर गेज की सुई ऊपर चढ़ रही है। पार्किंग ब्रेक छोड़कर यार्ड से बाहर निकलने से पहले, मुझे एयर सिस्टम को किस दबाव स्तर तक चार्ज होने देना चाहिए?","options":["लगभग 100 psi तक, क्योंकि यही वह बिंदु है जहां कंप्रेसर कट-इन करता है और मुझे पता चलता है कि वह काम कर रहा है","सामान्य संचालन सीमा तक, लगभग 125 psi, जहां गवर्नर कट-आउट करके हवा पंप करना बंद कर देता है","लगभग 150 psi तक, वह स्तर जहां सिस्टम की सुरक्षा के लिए सेफ्टी रिलीफ वाल्व खुलता है","लगभग 60 psi पर्याप्त है, क्योंकि यहीं पर कम वायु दबाव की चेतावनी बंद हो जाती है"],"explanation":"गाड़ी चलाने से पहले हवा प्रणाली को उसकी सामान्य ऑपरेटिंग सीमा, लगभग 125 psi, तक चार्ज करें, जहाँ गवर्नर कट-आउट करता है।"},"36":{"q":"अपने यात्रा-पूर्व निरीक्षण के दौरान मैं देखता हूँ कि एयर कंप्रेसर को चलाने वाली बेल्ट चिकनी पड़ गई है और अंगूठे से दबाने पर कुछ सेंटीमीटर नीचे चली जाती है। इंजन ठीक से चालू होता है और केबिन का रेडियो काम करता है। सुरक्षित संचालन के लिए यह ढीली ड्राइव बेल्ट क्यों मायने रखती है?","options":["ढीली बेल्ट केवल इसलिए चिंता का विषय है क्योंकि यह चरचरा सकती है और कम-वायु चेतावनी बजर को सुनना कठिन बना सकती है","यह इसलिए मायने रखती है क्योंकि यही बेल्ट उस अल्टरनेटर को भी घुमाती है जो ट्रेलर की आपातकालीन बैटरी को चार्ज रखता है","फिसलती हुई बेल्ट कंप्रेसर को पर्याप्त तेज़ी से हवा पंप करने से रोक सकती है, इसलिए सिस्टम कभी भी पर्याप्त वायु दाब न बना पाए और न ही बनाए रखे","यह इसलिए मायने रखती है क्योंकि ड्राइव बेल्ट ब्रेक फेड रोकने के लिए सामने के ब्रेक ड्रम पर ठंडी हवा भेजती है"],"explanation":"कम्प्रेसर की फिसलती ड्राइव बेल्ट कम्प्रेसर को पर्याप्त तेज़ी से पंप करने से रोकती है, इसलिए सिस्टम सही हवा का दबाव कभी बना या बनाए नहीं रख सकता।"},"37":{"q":"मैं एक एकल संयोजन वाहन (single combination vehicle) पर अपनी यात्रा-पूर्व जाँच कर रहा हूँ और चलने से पहले यह सुनिश्चित करना चाहता हूँ कि मैंने एयर-ब्रेक वाले हिस्से का हर भाग पूरा कर लिया है। एक साथी ड्राइवर मुझसे कहता है कि मैंने जो कुछ जाँचें गिनाईं, उनमें से कुछ वास्तव में एयर-ब्रेक परीक्षण का हिस्सा नहीं मानी जातीं। इनमें से कौन-सी वास्तव में पूर्ण यात्रा-पूर्व एयर-ब्रेक जाँच का अनिवार्य भाग है?","options":["केवल कम-वायु चेतावनी उपकरण का परीक्षण, क्योंकि बजर और लाइट ही वह चीज़ है जिस पर परीक्षक ध्यान देता है","केवल वायु दाब बढ़ने का समय, क्योंकि यह साबित करता है कि कंप्रेसर अपना काम कर रहा है","केवल स्थिर वायु रिसाव दर, क्योंकि रिसाव सबसे गंभीर खराबी है जो आप पा सकते हैं","ये सभी — कम-वायु चेतावनी, दाब बढ़ने का समय और वायु रिसाव दर, इनमें से प्रत्येक जाँच का अनिवार्य भाग है"],"explanation":"पूर्ण प्री-ट्रिप एयर-ब्रेक जांच में ये सभी आवश्यक हैं: कम-हवा चेतावनी, दबाव बनने का समय, और हवा रिसाव दर।"},"38":{"q":"मैं एयर ब्रेक वाले ट्रैक्टर की प्री-ट्रिप जांच कर रहा हूं और कोई भी ऐसा कदम छोड़ना चाहता हूं जो वास्तव में एयर-ब्रेक सिस्टम की जांच नहीं करता। मेरी सूची में कौन-सा काम किसी दूसरे सिस्टम से जुड़ा है और मेरे ब्रेक के बारे में कुछ नहीं बताता?","options":["इंजन की कूलिंग प्रणाली साफ रखने के लिए रेडिएटर से पानी और तेल निकालना","स्वस्थ बिल्ड-अप दर पुष्टि करने हेतु दबाव को 85 से 100 psi तक चढ़ने में लगने वाला समय मापना","सिस्टम चार्ज करके, इंजन बंद कर, गेज पर दबाव गिरने (लीक-डाउन) की दर देखना","पेडल को बार-बार दबाकर लगभग 60 psi पर कम-हवा चेतावनी बत्ती और बजर चालू होने तक प्रतीक्षा करना"],"explanation":"रेडिएटर से पानी और तेल निकालना इंजन शीतलन प्रणाली का रखरखाव है और एयर-ब्रेक प्रणाली में कुछ भी जांच नहीं करता।"},"39":{"q":"मैं ABS से लैस एक ट्रैक्टर-ट्रेलर चला रहा हूँ और मुझे सूखी सड़क पर एक तेज, आपातकालीन ब्रेक लगाना है। जब ABS सक्रिय होता है और मुझे पैडल में स्पंदन महसूस होता है, तो इस रुकाव में ABS वास्तव में मेरे लिए क्या कर रहा है, इसके बारे में कौन सा कथन सही है?","options":["यह बिना ABS वाले उसी वाहन की तुलना में मेरी रुकने की दूरी को कम कर रहा है","यह मेरे पहियों को लॉक होने से रोक रहा है ताकि मैं जोर से ब्रेक लगाते हुए भी स्टीयरिंग कर सकूँ","यह मेरे ब्रेक-लैग समय को स्वचालित रूप से सामान्य आधे सेकंड से नीचे घटा रहा है","यह अतिरिक्त रुकने का बल जोड़ने के लिए स्प्रिंग (पार्किंग) ब्रेक लगा रहा है"],"explanation":"ABS पहियों को लॉक होने से रोकता है ताकि वे घूमते रहें, जिससे आप ज़ोर से ब्रेक लगाते समय भी स्टीयर कर सकें।"},"40":{"q":"मैं अपनी सुबह की प्री-ट्रिप जांच कर रहा हूं और देखता हूं कि मेरे ट्रैक्टर के एयर टैंकों के तल में पानी और कंप्रेसर तेल की एक परत का मिश्रण जमा हो गया है। पैनहैंडल में एक ठंडी सर्दियों की सुबह है। एयर ब्रेक सिस्टम को सुरक्षित रूप से चालू रखने और जमने से रोकने के लिए, मुझे इस जमाव के बारे में क्या करना चाहिए?","options":["इसे ऐसे ही छोड़ दें, क्योंकि एयर ड्रायर और ब्रेक की गर्मी यात्रा के दौरान पानी और तेल को जला देगी","टैंकों में अतिरिक्त कंप्रेसर तेल भर दें ताकि नमी निलंबित रहे और जम न सके","एयर टैंकों को रोज़ाना ड्रेन वाल्वों से खाली करें ताकि पानी और तेल सिस्टम को नुकसान न पहुंचाएं या जमें नहीं","टैंकों को केवल सप्ताह में एक बार खाली करें, क्योंकि आधुनिक स्वचालित वाल्व बाकी काम खुद संभाल लेते हैं"],"explanation":"जमा पानी और तेल से सिस्टम को नुकसान या जमाव न हो, इसके लिए ड्रेन वाल्व से हवा टैंक रोज़ खाली करें।"},"41":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, मैंने हवा रिसाव परीक्षण करने के लिए इंजन बंद किया और देखा कि इंजन बंद होते ही मेरा एयर गेज पूरी तरह से ऊपर चढ़ना रुक गया। मेरे पास खड़ा एक नौसिखिया जोर देकर कहता है कि कंप्रेसर को अपने आप दबाव बनाते रहना चाहिए। कौन सा कथन सही ढंग से समझाता है कि इंजन बंद करने के बाद दबाव बढ़ना क्यों रुक गया?","options":["गवर्नर (नियामक) यांत्रिक रूप से एयर टैंकों को पंप करता है और केवल तभी काम करता है जब ट्रक आगे की ओर चल रहा हो","पार्किंग ब्रेक का स्प्रिंग ही एयर सिस्टम को चार्ज करता है, इसलिए ब्रेक लगाने पर यह रुक जाता है","ट्रेलर के पहियों का घूमना कंप्रेसर को घुमाता है, इसलिए दबाव केवल चलते समय बनता है","कंप्रेसर इंजन द्वारा चलाया जाता है (बेल्ट से या सीधे), इसलिए इंजन बंद होने पर हवा पंप नहीं होती"],"explanation":"हवा कम्प्रेसर इंजन से चलता है, इसलिए इंजन बंद होने पर यह कोई हवा पंप नहीं करता।"},"42":{"q":"सर्दियों की सुबह तापमान जमाव बिंदु से काफी नीचे है और मैं एयर ड्रायर से लैस एक ट्रैक्टर की प्री-ट्रिप जांच कर रहा हूं। मैं समझना चाहता हूं कि जब कंप्रेसर सिस्टम में हवा भर रहा है, तब यह उपकरण मुझे किस चीज से बचा रहा है। इस स्थिति में एयर ड्रायर का मुख्य काम क्या है?","options":["यह संपीड़ित हवा से जल वाष्प (और थोड़ा तेल) को टैंकों तक पहुंचने से पहले ही निकाल देता है, ताकि कम नमी जमा हो और सिस्टम जम न जाए","जब टैंक का दबाव लगभग 125 psi के कट-आउट बिंदु तक चढ़ता है तो यह कंप्रेसर को पंपिंग रोकने का संकेत देता है","यदि दबाव कभी लगभग 150 psi के सुरक्षा रिलीफ सेटिंग से ऊपर बढ़ जाए तो यह टैंकों को स्वतः खाली कर देता है","यह ठंड में ब्रेक वाल्वों को बर्फ जमने से रोकने के लिए लाइनों में मापी हुई मात्रा में अल्कोहल डालता है"],"explanation":"एयर ड्रायर संपीड़ित हवा से जलवाष्प और कुछ तेल को टैंकों तक पहुंचने से पहले हटा देता है, जिससे वह नमी कम हो जाती है जो जम कर ब्रेक को काम करने से रोक सकती है।"},"43":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, मैं फाउंडेशन ब्रेक देखने के लिए ट्रेलर के नीचे जाता हूं। हर पहिये पर मुझे एक ब्रेक ड्रम, लाइनिंग वाली ब्रेक शू और एक स्लैक एडजस्टर मिलता है जो एक पुशरॉड से जुड़ा है; यह पुशरॉड 'S' अक्षर के आकार वाले एक हिस्से को घुमाकर शू को अलग धकेलता है। मैं जो देख रहा हूं उसके आधार पर, यह वाहन किस प्रकार के फाउंडेशन ब्रेक से लैस है — वह प्रकार जो अधिकांश भारी एयर-ब्रेक वाले वाहनों में पाया जाता है?","options":["एयर डिस्क ब्रेक, जहां एक कैलिपर रोटर को दबाता है — भारी ट्रकों में सबसे आम डिज़ाइन","S-कैम ड्रम ब्रेक, भारी एयर-ब्रेक वाले वाहनों में सबसे आम फाउंडेशन ब्रेक","वेज ड्रम ब्रेक, जहां एक वेज एक ही चैंबर के माध्यम से शू को अलग धकेलता है","हाइड्रोलिक डिस्क ब्रेक, यात्री कार जैसे लेकिन ट्रेलर के लिए बड़े आकार के"],"explanation":"S-कैम ड्रम ब्रेक भारी एयर-ब्रेक वाहनों पर सबसे आम फाउंडेशन ब्रेक हैं, जिन्हें उस S-आकार की कैम से पहचाना जाता है जिसे पुशरॉड घुमाकर शू फैलाती है।"},"44":{"q":"जब आप ब्रेक पेडल को ज़्यादा ज़ोर से दबाते हैं, तो ब्रेक:","options":["कमज़ोर हो जाते हैं","अधिक एयर और बल पाते हैं","पूरी तरह छूट जाते हैं","बंद हो जाते हैं"],"explanation":"फुट (ट्रेडल) वाल्व अधिक ब्रेकिंग बल के लिए अधिक एयर प्रेशर भेजता है।"},"45":{"q":"मैं एयर ब्रेक (वायु दाब वाले ब्रेक) से लदा हुआ ट्रैक्टर-ट्रेलर चला रहा हूँ, तभी मेरे आगे एक कार अचानक रुक जाती है. जिस क्षण मैं ब्रेक पेडल को पूरी तरह दबाता हूँ, ट्रक के वास्तव में धीमा होने से पहले एक छोटी-सी देरी होती है. मेरे प्रशिक्षक इसे 'ब्रेक लैग' कहते हैं. उस देरी के दौरान भौतिक रूप से क्या हो रहा होता है?","options":["मेरा पैर पेडल तक पहुँचे, उससे पहले मेरा दिमाग और शरीर अभी भी खतरे को समझ रहे हैं","एयर कंप्रेसर माँग पूरी करने के लिए टैंकों में अतिरिक्त दाब बना रहा है","ब्रेक लगने से पहले संपीड़ित हवा ब्रेक लाइनों से होकर गुज़र रही है","किसी भी ब्रेकिंग इनपुट से पहले वाहन परसेप्शन दूरी तय कर रहा है"],"explanation":"पेडल दबाने के बाद, संपीड़ित हवा को ब्रेक लाइनों से गुजरकर हर पहिये पर ब्रेक वास्तव में लगाने में लगभग आधा सेकंड लगता है।"},"46":{"q":"मैं अपने CDL एयर ब्रेक एंडोर्समेंट के लिए कुल रोकने की दूरी का अध्ययन कर रहा हूँ। मुझे पता है कि कार के हाइड्रोलिक ब्रेक में, कुल रोकने की दूरी प्रत्यक्षण दूरी जमा प्रतिक्रिया दूरी जमा ब्रेकिंग दूरी होती है। मेरे प्रशिक्षक कहते हैं कि एयर ब्रेक इस कुल में एक और घटक जोड़ते हैं। एयर ब्रेक सिस्टम कौन सा घटक जोड़ता है जो हाइड्रोलिक ब्रेक में नहीं होता?","options":["अतिरिक्त प्रतिक्रिया दूरी, क्योंकि एयर ब्रेक के पैडल हाइड्रोलिक पैडल से भारी और दबाने में धीमे होते हैं","अतिरिक्त प्रत्यक्षण दूरी, क्योंकि बड़े एयर ब्रेक वाहन ऊंचे बैठते हैं और खतरों का आकलन करने में अधिक समय लगता है","लंबी प्रभावी ब्रेकिंग दूरी, क्योंकि एयर ब्रेक वाहन भारी होते हैं और रुकने के लिए अधिक जगह चाहिए","ब्रेक लैग दूरी — वह दूरी जो हवा के लाइनों से गुजरने और ब्रेक पकड़ने से पहले तय की जाती है"],"explanation":"एयर ब्रेक रुकने में एक चौथा घटक जोड़ते हैं, ब्रेक-लैग दूरी, जो उन लगभग आधे सेकंड को कवर करती है जब ब्रेक पकड़ने से पहले हवा लाइनों से गुजरती है।"},"47":{"q":"आपने अपना प्री-ट्रिप निरीक्षण पूरा कर लिया है और एयर सिस्टम पूरी तरह चार्ज है। अब आप यह सत्यापित करना चाहते हैं कि सर्विस ब्रेक वास्तव में ट्रक को रोकते हैं और कुछ भी घिस या एक तरफ खिंच नहीं रहा है। सर्विस-ब्रेक स्टॉप जांच करने का सही तरीका निम्नलिखित में से कौन सा है?","options":["पार्किंग ब्रेक छोड़ें, ट्रक को लगभग 5 मील प्रति घंटा तक धीरे-धीरे आगे बढ़ने दें, फिर ब्रेक पेडल को मजबूती से दबाएं और महसूस करें कि वह तुरंत और सीधा रुकता है या नहीं","ट्रक को स्थिर रखें, ब्रेक पेडल को जोर से दबाएं, और एयर गेज देखें ताकि पुष्टि हो कि एक मिनट में दबाव 3 psi से अधिक नहीं गिरता","रुके हुए, पीली पार्किंग-ब्रेक नॉब को कई बार खींचें और छोड़ें ताकि पुष्टि हो कि स्प्रिंग ब्रेक लगते और छूटते हैं","लगभग 20 मील प्रति घंटा तक गाड़ी चलाएं, फिर तेज ब्रेक लगाएं और जांचें कि दोनों तरफ के पहिए समान रूप से लॉक होते हैं"],"explanation":"सर्विस-ब्रेक स्टॉप टेस्ट चलते वाहन में किया जाता है: वाहन को लगभग 5 मील/घंटा तक बढ़ने दें, फिर ब्रेक मजबूती से लगाएं और महसूस करें कि वह बिना किसी ओर खिंचे तुरंत रुक जाता है।"},"48":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, मेरा CDL प्रशिक्षक मुझसे एक ब्रेक एडजस्टर को हाथ से पकड़कर खींचने को कहता है ताकि यह जांचा जा सके कि ब्रेक लगने से पहले पुशरॉड कितनी दूर तक जाता है। वह कहता है कि यदि यहां बहुत अधिक खाली खेल (फ्री प्ले) है, तो मेरी ब्रेकिंग शक्ति कम हो जाती है। ऐसा करते समय मैं वास्तव में किस घटक की जांच कर रहा हूं?","options":["एयर कंप्रेसर गवर्नर, जो तय करता है कि सिस्टम कब हवा पंप करना बंद करे और कब फिर से शुरू करे","स्लैक एडजस्टर, जो यह निर्धारित करता है कि ब्रेक लगने से पहले ब्रेक पुशरॉड कितनी दूर तक जाएगा","सुरक्षा रिलीफ वाल्व, जो टैंकों में अधिक दबाव होने पर दबाव छोड़ने के लिए खुलता है","मॉड्यूलेटिंग कंट्रोल वाल्व, जो मुझे आपात स्थिति में स्प्रिंग ब्रेक को धीरे-धीरे लगाने देता है"],"explanation":"स्लैक एडजस्टर तय करता है कि ब्रेक लगने से पहले ब्रेक पुशरॉड कितनी दूर तक चलता है, और अत्यधिक खाली खेल—बेमेल ब्रेक—एयर-ब्रेक की सबसे आम खराबी है।"},"49":{"q":"जमा देने वाली ठंड में प्री-ट्रिप जाँच के दौरान मैं देखता हूँ कि मेरे ट्रक के एयर टैंक बिना मेरे हाथ से कुछ खोले, जमा हुआ पानी और तेल अपने आप बाहर निकाल रहे हैं। वर्कशॉप कहती है कि यह टैंक इस तरह लगाया गया है कि जमने से बचाने के लिए ड्रेनिंग अपने आप हो जाए। यह काम कौन-सा उपकरण कर रहा है?","options":["एक रिले वाल्व, जो पिछले ब्रेकों तक हवा का संकेत तेज़ करता है पर साथ ही टैंक से नमी को अपने आप निकाल देता है","एक मैनुअल ड्रेन वाल्व, जो टैंक का दबाव पर्याप्त ऊँचा होने पर जमा पानी और तेल को स्वतः बाहर निकलने देता है","एक ऑटोमैटिक ड्रेन वाल्व, जो किसी के हाथ से निकाले बिना ही टैंक से पानी और कंप्रेसर का तेल बाहर निकाल देता है","एक सेफ्टी रिलीफ वाल्व, जो लगभग 150 psi पर खुलता है और हवा छोड़ते समय सप्लाई टैंक से जमा पानी और तेल हटा देता है"],"explanation":"स्वचालित ड्रेन वाल्व बिना हाथ से निकाले टैंक से जमा पानी और कंप्रेसर तेल को स्वयं बाहर निकाल देता है, जो ठंडे मौसम में जमने से रोकने में मदद करता है।"},"50":{"q":"एक नए संयोजन वाहन की यात्रा-पूर्व जांच के दौरान, मैं देखता हूं कि वायु दाब गेज में एक के बजाय दो सुइयां हैं, और जब तक दोनों रीडिंग ऊपर नहीं आ जातीं, ट्रक मुझे सामान्य रूप से दाब बनाने नहीं देता। मेरे प्रशिक्षक कहते हैं कि इस वाहन में दोहरी वायु ब्रेक प्रणाली है। कौन सा कथन सही ढंग से बताता है कि यह दोहरी प्रणाली वास्तव में कैसे बनी है?","options":["यह एक ही टैंक से चलने वाली एक बड़ी वायु प्रणाली है, और गेज की दूसरी सुई केवल सूचना के तौर पर ट्रेलर का दाब दिखाती है।","यह सेवा, पार्किंग और आपातकालीन ब्रेकों को एक ही साझा वायु लाइन में जोड़ देती है, ताकि तीनों एक ही दाब स्रोत से काम करें।","यह एक ही वायु प्रणाली है जिसमें एक बैकअप कंप्रेसर होता है जो केवल तभी चालू होता है जब मुख्य कंप्रेसर पूरी तरह विफल हो जाए।","यह दो पूरी तरह अलग वायु प्रणालियां हैं, एक प्राथमिक और एक द्वितीयक, जिन्हें अतिरिक्त सुरक्षा के लिए ब्रेक नियंत्रणों के एक ही सेट से नियंत्रित किया जाता है।"],"explanation":"डुअल एयर ब्रेक प्रणाली दो पूरी तरह अलग एयर प्रणालियाँ हैं, एक प्राथमिक और एक द्वितीयक, प्रत्येक के अपने टैंक और लाइनें होती हैं पर बैकअप सुरक्षा के लिए एक ही नियंत्रण सेट से चलती हैं।"},"51":{"q":"मैं एक डुअल एयर ब्रेक प्रणाली से लैस ट्रैक्टर-ट्रेलर चला रहा हूँ, तभी अचानक केवल प्राथमिक सर्किट के लिए कम वायु दाब चेतावनी सक्रिय हो जाती है, और उस तरफ के गेज की सुई शून्य की ओर गिरने लगती है। द्वितीयक प्रणाली का गेज अब भी सामान्य सीमा में दिखा रहा है। कौन सा कथन सबसे अच्छी तरह बताता है कि मुझे क्या अपेक्षा करनी चाहिए और क्या करना चाहिए?","options":["द्वितीयक प्रणाली अब भी ब्रेक को संचालित करती रहेगी, इसलिए मुझे लंबी रुकने की दूरी का ध्यान रखते हुए सुरक्षित रूप से ब्रेक लगाकर रुकना चाहिए, फिर ट्रक की मरम्मत करवानी चाहिए।","चूँकि दोनों सर्किट एक ही नियंत्रण सेट साझा करते हैं, द्वितीयक प्रणाली भी प्राथमिक के साथ विफल हो जाती है, इसलिए मेरे पास कोई ब्रेक नहीं बचेगा और मुझे लुढ़कते हुए रुकना पड़ेगा।","मुझे ब्रेक पैडल को तेज़ी से बार-बार दबाना चाहिए ताकि काम करने वाला सर्किट सभी पहियों को हवा भेजने के लिए मजबूर हो और विफल हुई तरफ का पूरा दाब बहाल हो जाए।","एक सर्किट विफल होते ही स्प्रिंग ब्रेक तुरंत सभी पहियों को लॉक कर देंगे, इसलिए मुझे तत्काल कठोर रुकावट के लिए तैयार रहना चाहिए।"],"explanation":"यदि डुअल एयर ब्रेक प्रणाली का एक सर्किट विफल हो जाए, तो दूसरा फिर भी ब्रेक चलाता है, इसलिए लंबी रुकने की दूरी का ध्यान रखते हुए नियंत्रित रूप से रुकें, फिर मरम्मत कराएं।"},"52":{"q":"मैं अपने ट्रैक्टर-ट्रेलर की यात्रा-पूर्व जाँच कर रहा हूँ और इंजन बंद है। जैसे-जैसे सिस्टम धीरे-धीरे हवा छोड़ता है, मैं गेज देखता हूँ: सुई 60 psi को पार करके 30 psi की ओर गिरती रहती है। अचानक स्प्रिंग (पार्किंग) ब्रेक अपने आप लग जाते हैं, जबकि मैंने पार्किंग नियंत्रण को छुआ तक नहीं। कौन-सा कथन सबसे अच्छी तरह समझाता है कि उस क्षण तक स्प्रिंग ब्रेक छूटे (रिलीज़) क्यों बने रहे थे?","options":["जब तक पुशरॉड की गति समाप्त नहीं हुई, तब तक उन्हें स्लैक एडजस्टर द्वारा यांत्रिक रूप से पीछे रोका जा रहा था","हवा का दबाव शक्तिशाली स्प्रिंगों को दबाकर रखे हुए था, और वह दबाव खोने पर स्प्रिंगों ने ब्रेक लगा दिए","जब तक कम-हवा वाला बज़र उन्हें मुक्त नहीं करता, तब तक उन्हें पीले हीरे-आकार वाले पार्किंग नियंत्रण द्वारा खुली स्थिति में रोका गया था","सर्विस ब्रेक पैडल उन्हें छूटा हुआ रखे था और वे तभी लगे जब पैडल का दबाव कम हो गया"],"explanation":"हवा का दबाव शक्तिशाली स्प्रिंग ब्रेक को रिलीज स्थिति में रोके रखता है, इसलिए जब दबाव 20-45 psi की सीमा से नीचे गिरता है तो स्प्रिंग स्वतः ही ब्रेक लगा देती हैं।"},"53":{"q":"अपनी यात्रा-पूर्व जाँच में स्प्रिंग (पार्किंग) ब्रेक रिलीज नहीं हो रहे हैं और मुझे स्प्रिंग-ब्रेक चैंबर में यांत्रिक खराबी का संदेह है। एक सहकर्मी मुझे एक औज़ार देता है और कहता है कि शक्तिशाली स्प्रिंगों को हाथ से 'केज' (दबाया) किया जा सकता है ताकि मैं ट्रक को वर्कशॉप तक ले जा सकूँ। मुझे इस प्रक्रिया का कभी प्रशिक्षण नहीं मिला है। सही कार्रवाई क्या है?","options":["बस इस एक बार स्प्रिंगों को मैं खुद केज कर लूँ, क्योंकि ट्रक को वर्कशॉप तक केवल थोड़ी दूरी ही जाना है","अटके हुए चैंबर को धीरे-धीरे ढीला करने के लिए स्प्रिंग ब्रेक को बार-बार हाथ से रिलीज और फिर लगाऊँ","स्प्रिंगों को न छुऊँ और उन्हें केज करने की कोशिश न करूँ, क्योंकि इन शक्तिशाली स्प्रिंगों को केज करना केवल प्रशिक्षित कर्मियों द्वारा ही किया जाना चाहिए","पहले स्प्रिंग-ब्रेक चैंबरों को चमकीले रंग से रंग दूँ ताकि केज करते समय मजबूत स्प्रिंग आसानी से दिखें"],"explanation":"स्प्रिंग ब्रेक को केज करना खतरनाक है क्योंकि स्प्रिंग में भारी बल जमा रहता है, इसलिए यह केवल प्रशिक्षित कर्मियों द्वारा ही किया जाना चाहिए।"},"54":{"q":"मैंने अपनी प्री-ट्रिप जांच पूरी कर ली है और यार्ड से निकलने से पहले एयर-ब्रेक की जांच कर रहा हूं। इंजन चालू है और हवा का दबाव पूरी तरह बन चुका है, मैं पीली हीरे के आकार की नॉब खींचकर पार्किंग ब्रेक लगाता हूं। अब मैं पुष्टि करना चाहता हूं कि स्प्रिंग ब्रेक वास्तव में वाहन को अपनी जगह पर रोके रखेंगे। कौन-सी क्रिया इसकी सही जांच करती है?","options":["पार्किंग ब्रेक छोड़ें और पैडल की मजबूती महसूस करने के लिए फुट ब्रेक को मजबूती से दबाएं","ब्रेक पैडल को कई बार पंप करें और दबाव गिरने के लिए एयर गेज पर नज़र रखें","इंजन को रेव करें और सुनें कि स्प्रिंग ब्रेक लगभग 20-45 psi पर कैसे छूटते हैं","पार्किंग ब्रेक लगा रहने दें, क्लच छोड़ें और वाहन को धीरे-धीरे आगे, ब्रेक के विरुद्ध बढ़ाएं"],"explanation":"पार्किंग (स्प्रिंग) ब्रेक की जाँच के लिए उन्हें लगा रहने दें और धीरे से नीची गियर में आगे खींचें ताकि पुष्टि हो कि वे वाहन को रोके रखते हैं।"},"55":{"q":"मैं एक लदे हुए संयोजन वाहन को एक लंबी, खड़ी पहाड़ी ढलान से नीचे ले जा रहा हूँ और मुझे अपने एयर ब्रेक पर नियंत्रण बनाए रखने की चिंता है। ढलान के बिल्कुल नीचे तक अपनी गति को सुरक्षित रूप से प्रबंधित करने के लिए मुझे कौन सी तकनीक का उपयोग करना चाहिए?","options":["ढलान से पहले निचला गियर चुनें और हल्का, स्थिर ब्रेक दबाव लगाएं, और जब गति सुरक्षित गति से लगभग 5 मील प्रति घंटा नीचे आ जाए तो ब्रेक छोड़ दें","गति को लगातार कम और नियंत्रण में रखने के लिए पूरी ढलान भर मजबूत, निरंतर ब्रेक दबाव लगाएं","ब्रेक पेडल को बार-बार दबाएं और छोड़ें ताकि अनुप्रयोगों के बीच ब्रेक को ठंडा होने का मौका मिले","इंजन को बचाने के लिए न्यूट्रल में डाल दें और ढलान पर आवश्यकतानुसार सारी गति-कमी ब्रेक पर छोड़ दें"],"explanation":"ढलान पर नीची गियर चुनें और हल्के, स्थिर ब्रेक दबाव का उपयोग करें, और सुरक्षित गति से लगभग 5 mph नीचे आने पर ब्रेक छोड़ दें।"},"56":{"q":"मैं अपने एयर-ब्रेक ट्रक में टेक्सास हाईवे पर सामान्य गति से चल रहा हूँ और ट्रैफिक के लिए धीमा होने हेतु फुट पेडल (ट्रेडल वाल्व) को मजबूती से दबाता हूँ। उस पेडल से मैं कौन-सी ब्रेक प्रणाली लगा रहा हूँ?","options":["पार्किंग ब्रेक, जो हवा से छूटे रखे जाते हैं और पीली नॉब से लगाए जाते हैं","सर्विस ब्रेक, जिन्हें मैं हर सामान्य धीमा करने और रुकने के लिए उपयोग करता हूँ","इमरजेंसी ब्रेक, जो हवा का दबाव कम होने पर अपने आप लग जाते हैं","केवल ट्रेलर ब्रेक, जो अलग से ट्रेलर हैंड वाल्व द्वारा नियंत्रित होते हैं"],"explanation":"फुट पेडल (ट्रेडल वाल्व) सर्विस ब्रेक को चलाता है, जिनका उपयोग सभी सामान्य धीमा करने और रुकने के लिए होता है।"},"57":{"q":"अपनी प्री-ट्रिप जाँच के दौरान मैं अपने ट्रैक्टर के ब्रेक ड्रम और डिस्क की जाँच कर रहा हूँ। कौन सी स्थिति यह दर्शाती है कि ड्रम या डिस्क खतरनाक है और मरम्मत होने तक वाहन को नहीं चलाना चाहिए?","options":["ड्रम छूने पर ठंडा है और उस पर तेल की कोई परत नहीं है","बाहरी सतह पर सड़क की धूल की हल्की परत है","ड्रम में दिखाई देने वाली दरार है या उसकी सतह बुरी तरह घिस चुकी है","ड्रम पर हाल ही में हुई वर्कशॉप सर्विस से ताज़ी पेंट दिख रही है"],"explanation":"दरार वाला या बुरी तरह घिसा हुआ ब्रेक ड्रम गर्मी और भार में फेल हो सकता है, इसलिए मरम्मत होने तक वाहन को सेवा से बाहर करना चाहिए।"},"58":{"q":"प्री-ट्रिप निरीक्षण के दौरान आप अपने एयर सिस्टम को लगभग 125 psi तक चार्ज करते हैं, इंजन बंद करते हैं और डैश गेज को देखते हैं। ब्रेक रिलीज़ होने पर सुई अनुमत रिसाव दर से कहीं अधिक नीचे गिरती रहती है और रुकने का कोई संकेत नहीं देती। कम वायु दबाव की चेतावनी अभी तक नहीं जली है। सही कार्रवाई क्या है?","options":["इंजन चालू करें और सामान्य रूप से चलाएं, क्योंकि चेतावनी लाइट और बज़र अभी तक नहीं बजे हैं","वाल्व को फिर से बैठाने के लिए ब्रेक पेडल को कुछ बार दबाएं, फिर योजना के अनुसार अपना मार्ग जारी रखें","जब तक दबाव 60 psi से ऊपर रहता है, सीधे निकटतम मरम्मत की दुकान तक चलाएं","वाहन को सेवा से बाहर करें और कहीं भी चलाने से पहले रिसाव की मरम्मत करवाएं"],"explanation":"अनुमत दर से अधिक लगातार हवा रिसाव टैंक खाली कर ब्रेक बंद कर सकता है, इसलिए मरम्मत होने तक वाहन को सेवा से बाहर करना चाहिए।"},"59":{"q":"मैं अपने ट्रैक्टर-ट्रेलर में हाईवे पर चल रहा हूँ, तभी मेरे डैशबोर्ड पर पीली ABS खराबी की बत्ती जलती है और जलती रहती है। ट्रक अभी भी सामान्य रूप से ब्रेक लगा रहा है और मुड़ रहा है। यह बत्ती मुझे जो बता रही है, उसके आधार पर कौन-सा कथन सबसे सटीक है?","options":["मेरा एंटीलॉक सिस्टम शायद काम नहीं कर रहा है, लेकिन मेरे सामान्य सर्विस ब्रेक अभी भी काम कर रहे हैं और मुझे ABS की जाँच करवानी चाहिए।","मेरे सर्विस ब्रेक पहले ही फेल हो चुके हैं, इसलिए मुझे तुरंत किनारे रुककर पार्किंग ब्रेक लगाना चाहिए।","मेरा ABS पूरी तरह सक्रिय है और इस सड़क पर मेरी रुकने की दूरी को सक्रिय रूप से कम कर रहा है।","मेरा हवा का दबाव 60 psi से नीचे गिर गया है और स्प्रिंग ब्रेक पहियों को लॉक करने वाले हैं।"],"explanation":"पीली ABS बत्ती जलने का मतलब केवल एंटीलॉक फंक्शन बंद हो सकता है; सामान्य सर्विस ब्रेक अब भी काम करते हैं और ABS की जाँच करानी चाहिए।"},"60":{"q":"मैं एक लंबे रूट पर एक लदा हुआ कॉम्बिनेशन वाहन चला रहा हूँ और अपने डैशबोर्ड के गेजों पर लगातार नज़र रखता हूँ। यह सुनिश्चित करने के लिए कि जब भी मैं पेडल दबाऊँ तो मेरे एयर ब्रेक वास्तव में लगें और छूटें, पूरी यात्रा के दौरान मुझे कौन सी एक शर्त बनाए रखनी चाहिए?","options":["एक भरा हुआ ईंधन टैंक, क्योंकि ब्रेक अपनी शक्ति सीधे इंजन की ईंधन आपूर्ति से लेते हैं","सिस्टम में पर्याप्त हवा का दबाव, क्योंकि हवा ही ब्रेक को लगाती और छोड़ती है","लो-बीम हेडलाइट सेटिंग, ताकि ब्रेक चेतावनी सेंसर दिन के उजाले में गेज पढ़ सकें","वाहन में कम से कम एक यात्री, ताकि हर पड़ाव पर ब्रेक लाइटों के काम करने की पुष्टि हो सके"],"explanation":"एयर ब्रेक सिस्टम को पर्याप्त वायु दबाव चाहिए क्योंकि संपीड़ित हवा ही ब्रेक लगाती और छोड़ती है।"},"61":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं एयर सिस्टम को गवर्नर कट-आउट तक चार्ज होने देता हूं, फिर इंजन को ऑपरेटिंग RPM पर चलाकर गेज को 85 से 100 psi तक चढ़ते हुए देखता हूं। निम्नलिखित में से कौन-सा अवलोकन मुझे बताएगा कि एयर कंप्रेसर ठीक है और प्रेशर बनने की दर स्वीकार्य है?","options":["गेज को 85 से 100 psi तक रेंगने में कई लंबे मिनट लगते हैं, लेकिन अंततः वह पहुंच जाता है","प्रेशर बिल्कुल नहीं हिलता क्योंकि गवर्नर पहले ही कंप्रेसर को कट कर चुका है","गेज 85 से 100 psi तक लगभग 45 सेकंड में चढ़ जाता है, यानी सेकंडों की बात है, मिनटों की नहीं","जैसे ही मैं एक्सेलेरेटर दबाता हूं, प्रेशर तुरंत 85 से 100 psi तक उछल जाता है"],"explanation":"दोहरे एयर ब्रेक सिस्टम में दबाव लगभग 45 सेकंड में 85 से 100 psi तक बढ़ना चाहिए, जो दिखाता है कि स्वस्थ कंप्रेसर हवा तेज़ी से बहाल करता है।"},"62":{"q":"अपनी यात्रा-पूर्व जांच के दौरान मैं ट्रेलर के नीचे जाता हूं और देखता हूं कि एक पहिये पर ब्रेक लाइनिंग इतनी पतली घिस चुकी है कि वह लगभग रिवेट के बराबर आ गई है। ब्रेक सिस्टम में बाकी सब कुछ ठीक है। इस वाहन को सड़क पर ले जाने से पहले निम्नलिखित में से कौन-सा सही कदम है?","options":["लाइनिंग को जैसी है वैसी ही छोड़ दें, क्योंकि पुशरॉड ट्रैवल और स्लैक एडजस्टर अभी भी कानूनी सीमा के भीतर परीक्षण में हैं","अगली दुकान तक चरचराहट कम करने के लिए पतली लाइनिंग पर हल्की ब्रेक फ्लूइड की परत लगा दें","इसे अपनी जांच रिपोर्ट में नोट कर लें लेकिन चलाते रहें, जब तक कम-हवा चेतावनी 60 psi से ऊपर बनी रहती है","वाहन को सेवा से बाहर करें और चलाने से पहले घिसी हुई लाइनिंग को नई से बदलवाएं"],"explanation":"बहुत पतली घिस चुकी ब्रेक लाइनिंग पर्याप्त घर्षण नहीं बना पातीं, इसलिए वाहन चलाने से पहले उन्हें बदलना ज़रूरी है।"},"63":{"q":"मैं एक लदे हुए ट्रेलर के साथ लंबी पहाड़ी ढलान पर नीचे जा रहा हूँ। अपनी गति को नियंत्रित रखने के लिए मैं बार-बार ब्रेक पेडल दबाता और छोड़ता रहता हूँ (ब्रेक को 'फैनिंग' करना)। मेरा प्रशिक्षक मुझे ऐसा न करने की चेतावनी देता है। लंबी ढलान पर ब्रेक फैनिंग करना खतरनाक होने का मुख्य कारण निम्न में से क्या है?","options":["यह कंप्रेसर के दोबारा हवा भरने की तुलना में हवा को तेज़ी से खर्च कर सकता है, जिससे भंडार खाली हो जाता है","यह ब्रेक ड्रम को बहुत तेज़ी से ठंडा करता है और थर्मल शॉक से लाइनिंग को चटका सकता है","यह ट्रेलर सप्लाई टैंक में अतिरिक्त हवा भर देता है और रिलीफ वाल्व पर अधिक भार डालता है","यह स्लैक एडजस्टर को कस देता है जिससे पुशरॉड की गति बहुत छोटी हो जाती है"],"explanation":"बार-बार ब्रेक पंप करने से हर बार हवा कंप्रेसर के दोबारा भरने की गति से तेज़ निकलती है, जिससे हवा की आपूर्ति खत्म हो जाती है।"},"64":{"q":"मैं अभी-अभी कार चलाने से हटकर एयर ब्रेक सिस्टम से लैस एक ट्रैक्टर-ट्रेलर चलाने लगा हूँ। जब मैं ब्रेक पेडल दबाता हूँ, तो मैं यह कल्पना करने की कोशिश करता हूँ कि लाइनों से होकर असल में क्या गुज़रता है जो ब्रेक शूज़ को ड्रमों पर दबाकर रिग को धीमा करता है। इस एयर ब्रेक सिस्टम में, पेडल पर मैं जो बल बनाता हूँ वह पहियों तक किस माध्यम से पहुँचाया जाता है?","options":["मास्टर सिलिंडर से धकेला गया दबावयुक्त हाइड्रोलिक ब्रेक फ्लूइड, बिल्कुल मेरी कार की तरह","टैंकों में जमा संपीड़ित हवा, जो लाइनों के ज़रिए ब्रेक चैंबरों में छोड़ी जाती है","पेडल से हर पहिये तक खींचा गया भारी स्टील का केबल और यांत्रिक लिंकेज","तार से भेजी गई विद्युत धारा जो हर पहिये पर एक ब्रेक चुंबक को सक्रिय करती है"],"explanation":"एयर ब्रेक टैंकों में संग्रहीत संपीड़ित हवा का उपयोग करके बल पहुंचाते हैं, जो ब्रेक लाइनों से होकर चैंबरों में छोड़ी जाती है।"},"65":{"q":"मैं एयर ब्रेक वाला एक लदा हुआ ट्रक चला रहा हूँ, तभी एक लाइन फट जाती है और मेरा हवा का दबाव गिरकर बिल्कुल शून्य हो जाता है। मेरे साथ बैठा एक प्रशिक्षु पूछता है कि यह व्यवस्था उसकी पिकअप के हाइड्रॉलिक ब्रेक से अधिक सुरक्षित क्यों मानी जाती है। ठीक इसी स्थिति में मेरे एयर ब्रेक सिस्टम के असली सुरक्षा लाभ को कौन-सा कथन सबसे अच्छी तरह समझाता है?","options":["चूँकि हवा ही कार्यकारी माध्यम है, इसलिए सिस्टम से सारी हवा निकल जाने के बाद भी मेरे सर्विस ब्रेक सामान्य रूप से काम करते रहेंगे।","जब दबाव 60 psi से नीचे गिरता है, तो ट्रक को वास्तव में रोकने वाला कम हवा दबाव चेतावनी बज़र ही होता है।","जैसे ही हवा का दबाव 20 से 45 psi की सीमा में गिरता है, स्प्रिंग (आपातकालीन) ब्रेक स्वतः लग जाते हैं और ट्रक को रोक देते हैं।","एयर ब्रेक इस तरह बनाए गए हैं कि किसी भी रिसाव की परवाह किए बिना वे लदे हुए ट्रक को हमेशा हाइड्रॉलिक ब्रेक से कम दूरी में रोकते हैं।"],"explanation":"जब हवा का दबाव 20 से 45 psi की सीमा में गिरता है, तो स्प्रिंग (आपातकालीन) ब्रेक स्वतः लग जाते हैं और वाहन को रोक देते हैं।"},"66":{"q":"मैं एक भरे हुए ट्रैक्टर-ट्रेलर में हाईवे पर चल रहा हूँ, तभी एक लाइन फट जाती है और मेरा हवा का दबाव पूरी तरह खत्म हो जाता है। जैसे-जैसे सिस्टम खाली होता है, मेरे स्प्रिंग (पार्किंग) ब्रेक के साथ क्या होगा?","options":["उनके साथ कुछ नहीं होता, क्योंकि स्प्रिंग ब्रेक केवल तभी मेरे सर्विस ब्रेक के रूप में काम करते हैं जब मैं पैडल दबाता हूँ","वे छूटे हुए ही रहते हैं, क्योंकि शक्तिशाली स्प्रिंगों को कसा हुआ रखने के लिए संग्रहित हवा के दबाव की ज़रूरत होती है","वे पूरी तरह छूट जाते हैं, क्योंकि हवा का खत्म होना ही वह चीज़ है जो स्प्रिंगों को मुक्त कर वाहन को लुढ़कने देती है","वे अपने आप लग जाते हैं, क्योंकि जैसे ही उन्हें छूटा हुआ रखने वाली हवा खत्म होती है, स्प्रिंग ब्रेक को कस देते हैं"],"explanation":"स्प्रिंग ब्रेक हवा के दबाव से खुले रखे जाते हैं, इसलिए हवा खत्म होने पर स्प्रिंग सुरक्षा-उपाय के रूप में ब्रेक को स्वतः कस देते हैं।"},"67":{"q":"मैं इंजन बंद करके और सिस्टम पूरी तरह चार्ज होने पर ब्रेक जाँच कर रहा हूँ। टैंकों से हवा निकालने के लिए मैं बार-बार ब्रेक पेडल दबाता और छोड़ता हूँ और एयर गेज को गिरते हुए देखता हूँ। जैसे-जैसे सुई गिरती रहती है, लगभग किस दबाव पर मुझे यह अपेक्षा करनी चाहिए कि ट्रैक्टर प्रोटेक्शन वाल्व अपने आप बंद हो जाए और ट्रेलर की हवा आपूर्ति कट जाए?","options":["लगभग 20 से 45 psi के बीच, जब दबाव निचली सीमा में गिरता है","लगभग 60 से 80 psi के बीच, ठीक तब जब कम हवा की चेतावनी सक्रिय होती है","लगभग 100 से 125 psi के बीच, गवर्नर की सामान्य संचालन सीमा के पास","लगभग 5 से 10 psi के बीच, केवल तभी जब गेज लगभग खाली दिखाए"],"explanation":"जब सिस्टम का हवा दबाव 20 से 45 psi की सीमा में गिरता है, तो ट्रैक्टर सुरक्षा वाल्व और ट्रेलर एयर सप्लाई स्वतः बंद हो जाते हैं।"},"68":{"q":"मैं एक भरे हुए ट्रेलर से जुड़ा हूँ और कैब के अंदर अपनी प्री-ट्रिप जाँच पूरी कर रहा हूँ। चलने से पहले ट्रेलर की हवा प्रणाली को चार्ज करने और उसके ब्रेक छोड़ने के लिए, मुझे डैश पर एक विशेष नियंत्रण को अंदर दबाना होगा। ट्रेलर को हवा देने के लिए जिस नॉब को मुझे दबाना है, उसका रंग और आकार कौन-सा है?","options":["पीली, हीरे (समचतुर्भुज) के आकार वाली नॉब, क्योंकि वही नियंत्रण ट्रेलर के ब्रेक को हवा देता है","लाल, आठ भुजाओं वाली (अष्टकोण) नॉब, क्योंकि यही ट्रेलर एयर सप्लाई नियंत्रण है","नीली, गोल नॉब, क्योंकि ट्रेलर की सर्विस लाइन नीले रंग से कोडित होती है","पीली, आठ भुजाओं वाली (अष्टकोण) नॉब, क्योंकि ट्रेलर सप्लाई पार्किंग नियंत्रण के आकार से मेल खाती है"],"explanation":"ट्रेलर एयर सप्लाई नियंत्रण लाल, आठ-भुजा वाला (अष्टकोण) नॉब है जो ट्रेलर की एयर प्रणाली को चार्ज करता है और उसके ब्रेक छोड़ता है।"},"69":{"q":"मैंने अपने ट्रैक्टर-ट्रेलर को एक विश्राम स्थल पर पार्क कर लिया है और अब इंजन बंद करने वाला हूँ। पार्किंग (स्प्रिंग) ब्रेक लगाने के लिए ताकि वाहन अपनी जगह पर खड़ा रहे, मुझे डैशबोर्ड का कौन सा नियंत्रण बाहर खींचना चाहिए?","options":["नीला गोल बटन जो सर्विस-ब्रेक का दबाव छोड़ता है","डैश गेजों के पास वाली लाल, आठ-भुजा वाली (अष्टकोण) घुंडी","कंट्रोल पैनल पर लगी पीली, हीरे के आकार (समचतुर्भुज) वाली घुंडी","ट्रेलर हैंड वाल्व के पास वाला हरा चौकोर लीवर"],"explanation":"पार्किंग (स्प्रिंग) ब्रेक नियंत्रण पीला, हीरे के आकार का नॉब है, जिसे लगाने के लिए खींचा और स्प्रिंग ब्रेक छोड़ने के लिए दबाया जाता है।"},"70":{"q":"अपनी प्री-ट्रिप जाँच के दौरान इंजन बंद हो जाता है और कंप्रेसर घूमना रोक देता है, फिर भी मैं देखता हूँ कि मेरा सप्लाई टैंक अपना दबाव बनाए रखता है, बजाय इसके कि वह बंद पड़े कंप्रेसर की ओर वापस लीक हो जाए। इस व्यवहार के लिए कौन सा कंपोनेंट ज़िम्मेदार है?","options":["सेफ्टी रिलीफ वाल्व, जो यह भाँपते ही कि कंप्रेसर रुक गया है, टैंक की हवा को रोक लेता है","गवर्नर, जो कट-आउट दबाव सेटिंग पर पहुँचते ही सप्लाई टैंक को सील कर देता है","ऑटोमैटिक ड्रेन वाल्व, जो कसकर बंद होकर संग्रहित हवा को टैंक के भीतर बंद कर देता है","एक-तरफ़ा चेक वाल्व, जो हवा को रुके हुए कंप्रेसर की ओर वापस बहने से रोकता है"],"explanation":"एकतरफा चेक वाल्व हवा को केवल टैंक में जाने देता है, इसलिए कंप्रेसर रुकने पर यह संग्रहीत हवा को वापस निकलने से रोकता है।"},"71":{"q":"अमरिलो में जनवरी की एक हाड़ कंपा देने वाली सुबह है, और मेरा डिस्पैचर मुझे बताता है कि मेरे ट्रैक्टर की एयर ब्रेक प्रणाली में एक अल्कोहल एवापोरेटर लगा है। प्री-ट्रिप जाँच करते समय मुझसे पूछा जाता है कि इन परिस्थितियों में यह उपकरण वास्तव में मेरे लिए क्या करता है। कौन सा कथन इसके उद्देश्य को सबसे अच्छी तरह समझाता है?","options":["यह हवा प्रणाली में अल्कोहल डालता है ताकि ठंडे मौसम में लाइनों और वाल्वों में बर्फ बनने की संभावना कम हो","यह अल्कोहल जलाकर ब्रेक ड्रमों को गर्म करता है ताकि पार्किंग ब्रेक ठंड में जम न जाएँ","यह नमी सोखने के लिए हवा में अल्कोहल मिलाता है, इसलिए मुझे अब रोज़ एयर टैंक खाली करने की ज़रूरत नहीं","यह अल्कोहल वाष्प छोड़ता है जो एयर कंप्रेसर का उत्पादन बढ़ाता है ताकि ठंड में दबाव तेज़ी से बने"],"explanation":"अल्कोहल एवापोरेटर ठंडे मौसम में लाइनों और वाल्वों में बर्फ जमने की संभावना कम करने के लिए एयर प्रणाली में अल्कोहल डालता है।"},"72":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं अपने एयर-ब्रेक ट्रैक्टर के एक पहिये पर फाउंडेशन ब्रेक असेंबली को क्रम से जांच रहा हूं। जब ब्रेक लगाया जाता है, तो मैं देखता हूं कि स्लैक एडजस्टर एक शाफ्ट को घुमाता है जो S-आकार के कैम को घुमाता है, और वह कैम ब्रेक शूज़ तथा लाइनिंग को बाहर की ओर ड्रम की भीतरी सतह की ओर धकेलता है। हर पुर्जे की मौजूदगी और कार्यप्रणाली की पुष्टि करते समय, निम्नलिखित में से किस पुर्जे को इस S-कैम फाउंडेशन ब्रेक में पाने की मुझे उम्मीद नहीं करनी चाहिए?","options":["स्लैक एडजस्टर जो पुशरॉड की गति को ब्रेक कैम की घूर्णन गति में बदलता है","एक हाइड्रोलिक मास्टर सिलिंडर जो शूज़ को बाहर धकेलने के लिए तरल पदार्थ पर दबाव बनाता है","ब्रेक ड्रम जिसके खिलाफ शूज़ दबकर रुकने वाला घर्षण पैदा करते हैं","ब्रेक शूज़ और लाइनिंग जो ब्रेक लगाने पर ड्रम के खिलाफ धकेले जाते हैं"],"explanation":"S-कैम एयर फाउंडेशन ब्रेक पूरी तरह यांत्रिक-वायवीय है और इसमें कोई तरल नहीं होता, इसलिए इसमें हाइड्रॉलिक मास्टर सिलेंडर नहीं होता।"},"73":{"q":"मैं एक लदे हुए ट्रेलर को एक लंबी, खड़ी ढलान पर नीचे ले जा रहा हूँ, तभी मेरे सर्विस ब्रेक कमजोर पड़ जाते हैं और पैडल नरम हो जाता है। मेरे वाहन में एक मॉड्युलेटिंग कंट्रोल वाल्व लगा है। इस स्थिति में वह वाल्व मुझे असल में क्या करने देता है?","options":["लाइनों में हवा का दबाव पूरी तरह विफल होने से पहले फिर से बनाने के लिए सर्विस ब्रेक को बार-बार पंप करना","गवर्नर को बायपास करना ताकि कंप्रेसर 125 psi से ऊपर कट-आउट हो और मेरी ब्रेकिंग शक्ति बहाल कर दे","स्प्रिंग (आपातकालीन) ब्रेक को एक साथ पूरी तरह लगने के बजाय कंट्रोल हैंडल से धीरे-धीरे लगाना","ABS को बंद करना ताकि पहिए लॉक हो जाएँ और ढलान पर गति तेजी से कम कर सकें"],"explanation":"मॉड्युलेटिंग कंट्रोल वाल्व सेवा ब्रेक फेल होने पर कंट्रोल हैंडल से स्प्रिंग (आपातकालीन) ब्रेक को धीरे-धीरे लगाकर नियंत्रित रोक देता है।"},"74":{"q":"मैं एक लदा हुआ एकल ट्रक चला रहा हूँ जब मुझे दिखता है कि कम हवा दबाव की चेतावनी बत्ती जल गई है और बज़र बज रहा है। यात्रा से पहले की जांच में मैंने एक छोटा हवा रिसाव देखा था जिसे मैंने मामूली समझा था। एक वैसे ही छोटे रिसाव पर हाइड्रॉलिक ब्रेक प्रणाली कैसे व्यवहार करती है, उसकी तुलना में मुझे अभी अपने एयर ब्रेक से क्या उम्मीद करनी चाहिए?","options":["जैसे ही रिसाव शुरू होगा, ब्रेक ठीक हाइड्रॉलिक प्रणाली की तरह उसी क्षण पूरी तरह फेल हो जाएंगे, इसलिए मेरे पास कोई उपयोगी ब्रेकिंग नहीं बचेगी","हवा दबाव की हानि कोई चेतावनी नहीं देती, इसलिए बत्ती और बज़र ज़रूर किसी दूसरी असंबंधित खराबी का संकेत दे रहे होंगे","रिसाव को गाड़ी चलाते समय सचमुच पुष्ट नहीं किया जा सकता, इसलिए जब तक मैं रोककर लाइनों की जांच न कर लूँ, मुझे गति पर चलते रहना चाहिए","जब तक हवा का दबाव बना रहता है तब तक ब्रेक काम करते रहते हैं, और चेतावनी मुझे दबाव बहुत नीचे गिरने से पहले सुरक्षित रूप से रुकने के लिए सतर्क कर रही है"],"explanation":"जब तक टैंकों में उपयोगी हवा का दबाव रहता है तब तक एयर ब्रेक काम करते हैं, और कम दबाव की चेतावनी दबाव 60 psi से नीचे गिरने से पहले आनी चाहिए ताकि आप सुरक्षित रूप से रुक सकें।"},"75":{"q":"मैं एक सिंगल ट्रैक्टर पर अपनी प्री-ट्रिप जाँच का एयर-ब्रेक हिस्सा कर रहा हूँ। मैं टैंक पहले ही ड्रेन कर चुका हूँ और दबाव को गवर्नर कट-आउट तक बढ़ा चुका हूँ। यार्ड से निकलने से पहले, एयर-ब्रेक वॉकअराउंड पूरा करने के लिए मुझे किन ब्रेक कार्यों के वास्तव में काम करने की पुष्टि अब भी करनी चाहिए?","options":["कम-वायु दबाव चेतावनी, स्प्रिंग (पार्किंग) ब्रेक, और सर्विस ब्रेक","केवल स्प्रिंग (पार्किंग) ब्रेक और सर्विस ब्रेक, क्योंकि चेतावनी स्टार्ट-अप पर स्वयं जाँच लेती है","केवल कम-वायु दबाव चेतावनी और सर्विस ब्रेक, क्योंकि स्प्रिंग ब्रेक अपने आप लग जाते हैं","केवल सर्विस ब्रेक, क्योंकि 5 मील/घंटा पर मज़बूत पेडल पूरी प्रणाली के ठीक होने को साबित करता है"],"explanation":"पूर्ण एयर ब्रेक जांच में तीन चीज़ों की पुष्टि होनी चाहिए: कम हवा दबाव चेतावनी, स्प्रिंग (पार्किंग) ब्रेक, और सेवा ब्रेक।"},"76":{"q":"मैंने अभी एयर ब्रेक वाला एक सीधा (स्ट्रेट) ट्रक खरीदा है, और मेरे पास पहले से ही एक वैध CDL है जो मैंने हाइड्रॉलिक ब्रेक वाले वाहन में अर्जित किया था। इस एयर ब्रेक ट्रक को कानूनी रूप से चलाने से पहले, टेक्सास मुझसे कौन सा अतिरिक्त कदम मांगता है जो मेरे पुराने हाइड्रॉलिक ब्रेक वाहन पर लागू नहीं होता था?","options":["कुछ भी अतिरिक्त नहीं — मेरा मौजूदा CDL पहले से ही किसी भी ब्रेकिंग प्रणाली को कवर करता है, इसलिए मैं इसे जैसे है वैसे चला सकता हूँ","मुझे एयर ब्रेक (बिना प्रतिबंध) टेस्ट पास करना होगा, अन्यथा मेरे लाइसेंस पर एयर ब्रेक प्रतिबंध (restriction) लग जाएगा","मुझे केवल छोटे ट्रक आकार से मेल खाने के लिए एक Class C पदनाम जोड़ना है","किसी भी एयर ब्रेक इकाई को चलाने से पहले मुझे एक अलग मोटरसाइकिल समर्थन (endorsement) प्राप्त करना होगा"],"explanation":"आपको एयर ब्रेक ज्ञान और कौशल परीक्षा पास करनी होगी, अन्यथा राज्य आपके लाइसेंस पर एयर ब्रेक प्रतिबंध लगा देगा जो एयर ब्रेक वाहनों को चलाने से रोकता है।"},"77":{"q":"मैं एक गीले इंटरस्टेट हाईवे पर लदे हुए ट्रेलर के साथ गाड़ी चला रहा हूँ, तभी एक कार मेरे आगे आकर अचानक रुक जाती है। मैं ब्रेक पैडल को ज़ोर से दबाता हूँ और मेरे ABS-युक्त ट्रैक्टर-ट्रेलर का ABS सक्रिय हो जाता है। उस तेज़ ब्रेकिंग के पल में, मुझे वास्तव में ABS से क्या करने की उम्मीद करनी चाहिए?","options":["मेरी कुल रुकने की दूरी को नाटकीय रूप से घटा दे ताकि मैं आगे वाली कार से काफ़ी पहले रुक जाऊँ","मेरे पैडल दबाने से पहले ही अपने आप मेरे ब्रेक लगा दे","मेरे पहियों को लॉक होने से रोके ताकि ज़ोर से ब्रेक लगाते हुए भी मैं स्टीयरिंग करके खतरे से बच सकूँ","जैसे ही पैडल पूरा नीचे दबाया जाए, मेरे मुख्य सर्विस ब्रेक की जगह ले ले"],"explanation":"ABS तेज़ ब्रेकिंग के दौरान पहियों को लॉक होने से रोकता है ताकि आप स्टीयरिंग नियंत्रण बनाए रखें और खतरे के चारों ओर मोड़ सकें।"},"78":{"q":"मैं एकल वायु ब्रेक प्रणाली वाला एक सीधा ट्रक चला रहा हूँ और राजमार्ग के एक शांत हिस्से पर इंजन बंद हो जाता है। जब मैं किनारे की ओर लुढ़कता हूँ, तो मैं वायु दाब गेज पर नज़र बनाए रखता हूँ, यह जानते हुए कि कंप्रेसर अब नहीं चलने से हवा धीरे-धीरे कम होती जाएगी। लगभग किस दाब पर मुझे पहली बार कम वायु दाब चेतावनी (बत्ती और बज़र) के सक्रिय होने की उम्मीद करनी चाहिए, जो संकेत देती है कि मैं अपना वायु भंडार खो रहा हूँ?","options":["लगभग 100 psi, वह बिंदु जहाँ गवर्नर सामान्यतः कंप्रेसर को फिर से चालू करता है","लगभग 125 psi, वह बिंदु जहाँ गवर्नर सामान्यतः कंप्रेसर को बंद करता है","लगभग 30 psi, जब स्प्रिंग ब्रेक स्वतः लगने ही वाले होते हैं","लगभग 60 psi, दाब के खतरनाक रूप से कम होने से काफी पहले"],"explanation":"कम हवा दबाव चेतावनी लगभग 60 psi पर आनी चाहिए, दबाव खतरनाक रूप से कम होने से बहुत पहले।"},"79":{"q":"मैं अपनी प्री-ट्रिप जांच कर रहा हूं और यह कल्पना करने की कोशिश कर रहा हूं कि पेडल दबाने पर मेरे एयर ब्रेक वास्तव में किससे लगते हैं। जब तक मेरा इंजन, गेज और लाइनें ठीक हैं, मेरे एयर ब्रेक तब तक ट्रक को रोकते रहेंगे जब तक निम्नलिखित में से क्या पर्याप्त बना रहता है?","options":["टैंकों (जलाशयों) में बनाया और संग्रहीत वायु दाब","मास्टर सिलेंडर में हाइड्रोलिक ब्रेक फ्लूइड (द्रव)","ब्रेक सर्किट को आपूर्ति करने वाला इंजन तेल का दाब","ब्रेक वाल्व को शक्ति देने वाली 12-वोल्ट बैटरी चार्ज"],"explanation":"एयर ब्रेक तरल पदार्थ से नहीं, बल्कि टैंकों में बनी और संग्रहीत संपीड़ित हवा के दबाव से लगते और टिके रहते हैं।"},"80":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं ड्रम (drum) ब्रेक वाले एक एक्सल पर एयर ब्रेक प्रणाली का मार्ग खोजता हूँ। मैं ब्रेक चैम्बर से पुशरॉड (pushrod) होते हुए स्लैक एडजस्टर (slack adjuster) तक का रास्ता अनुसरण करता हूँ, जो पहिए पर एक शाफ्ट को घुमाता है। उस शाफ्ट के सिरे पर मुझे दो ब्रेक शू (shoes) के बीच एक S-आकार का पुर्जा मिलता है। जब मैं ब्रेक लगाता हूँ, तो वह अंतिम यांत्रिक क्रिया कौन-सी है जो वास्तव में शू को ड्रम के विरुद्ध दबाकर पहिए को धीमा करती है?","options":["पुशरॉड ब्रेक चैम्बर से बाहर निकलता है और सीधे ब्रेक शू को ड्रम के विरुद्ध दबाता है","S-कैम (S-cam) घूमता है और दोनों ब्रेक शू को अलग-अलग फैलाता है, उनकी लाइनिंग को ड्रम की अंदरूनी सतह के विरुद्ध दबाता है","मास्टर सिलिंडर से आने वाला हाइड्रोलिक तरल एक व्हील पिस्टन को धकेलता है जो शू को ड्रम पर कसता है","स्लैक एडजस्टर पहिए के हब पर लगे एक रोटर के विरुद्ध एक जोड़ी पैड को दबाता है"],"explanation":"हवा का दबाव पुशरॉड और स्लैक एडजस्टर को हिलाकर S-कैम को घुमाता है, जो ब्रेक शू को फैलाकर उनकी लाइनिंग को ड्रम की भीतरी सतह से दबाता है।"},"81":{"q":"अपने प्री-ट्रिप निरीक्षण के दौरान मैं देखता हूँ कि मेरे ट्रक के फ्रेम पर इंजन और ईंधन प्रणाली से अलग, कई धातु के टैंक लगे हैं। एक नया चालक मुझसे पूछता है कि ये सप्लाई (भंडारण) टैंक एयर ब्रेक प्रणाली के लिए असल में क्या करते हैं। कौन सा उत्तर इनके काम को सही ढंग से समझाता है?","options":["ये हवा बनाते और दबाव में लाते हैं, और जब भी कंप्रेसर लगभग 125 psi पर गवर्नर कट-आउट तक पहुँचता है तो पंपिंग का काम संभाल लेते हैं","ये हवा से पानी और तेल हटा देते हैं, इसलिए लाइनों को दिन के अंत में कभी निकालने की जरूरत नहीं पड़ती","ये संपीड़ित हवा का भंडार रखते हैं ताकि ब्रेक चलाने के लिए हमेशा पर्याप्त दबाव उपलब्ध रहे","ये कम दबाव को भांपते हैं और दबाव लगभग 60 psi से नीचे गिरने से पहले चेतावनी बत्ती और बजर चालू कर देते हैं"],"explanation":"सप्लाई टैंक संपीड़ित हवा का भंडार रखते हैं ताकि सेवा, पार्किंग और आपातकालीन ब्रेक चलाने के लिए हमेशा पर्याप्त दबाव उपलब्ध रहे।"},"82":{"q":"मैं एक भरा हुआ सीधा ट्रक चला रहा हूँ जब एक मुख्य एयर लाइन फट जाती है। एयर गेज की सुई लगातार गिर रही है, कम-हवा चेतावनी लाइट और बज़र पहले ही चालू हो चुके हैं, और मैं ब्रेक पेडल को नहीं छूता। जैसे-जैसे दबाव गिरता रहता है, मेरे ट्रक को अपने आप रुकने पर क्या मजबूर करता है?","options":["जैसे ही सुई गवर्नर कट-आउट बिंदु को पार करती है, सर्विस ब्रेक फुट वाल्व के जरिए खुद लग जाते हैं","सेफ्टी रिलीफ वाल्व सिस्टम को बाहर निकाल देता है, जो यांत्रिक रूप से सर्विस ब्रेक को ड्रम पर दबा देता है","कम-हवा चेतावनी सर्किट उसी पल ब्रेक को सक्रिय कर देता है जब लाइट और बज़र चालू होते हैं","जैसे ही गिरता हुआ दबाव उस कम रेंज तक पहुँचता है जहाँ स्प्रिंग नियंत्रण ले लेते हैं, स्प्रिंग ब्रेक अपने आप लग जाते हैं"],"explanation":"स्प्रिंग ब्रेक हवा के दबाव से खुले रहते हैं, इसलिए जब रिसाव से दबाव कम सीमा (लगभग 20-45 psi) में गिरता है तो स्प्रिंग अपने आप ब्रेक लगा देते हैं।"},"83":{"q":"ज़ोरदार ब्रेकिंग के दौरान, ABS पहियों को इससे रोकता है:","options":["बिल्कुल भी घूमने से","लॉक होने और स्किड होने से","गर्म होने से","अपनी एयर खोने से"],"explanation":"ABS पहियों के लॉक होने को रोकता है ताकि ज़ोरदार ब्रेकिंग के दौरान आप स्टीयर कर सकें।"},"84":{"q":"एक डिलीवरी के दौरान, मेरी कम-वायुदाब चेतावनी बत्ती अचानक जल जाती है और मैं देखता हूँ कि मेरे दो वायुदाब गेजों में से एक तेज़ी से गिर रहा है जबकि दूसरा स्थिर बना हुआ है। मेरे ट्रक में दोहरी वायु ब्रेक प्रणाली है। कौन सा कथन सबसे अच्छा बताता है कि अभी भी मेरे पास कुछ ब्रेकिंग क्षमता क्यों है?","options":["प्रणाली दो अलग-अलग सर्किटों में बँटी है, इसलिए खराब सर्किट के दबाव खोने से वह सर्किट निष्क्रिय नहीं होता जो अभी भी दबाव बनाए हुए है","दोनों सर्किट एक ही बड़े साझा टैंक से हवा खींचते हैं, इसलिए स्थिर गेज खराब हिस्से में वापस हवा भेज रहा है","जब भी कोई एक वायु सर्किट दबाव खोता है, एक हाइड्रोलिक बैकअप ब्रेक अपने आप कार्यभार सँभाल लेता है","दोहरी प्रणाली पार्किंग ब्रेक को हटा देती है, इसलिए सारी बची हुई हवा सर्विस ब्रेकों की ओर भेज दी जाती है"],"explanation":"दोहरी एयर ब्रेक प्रणाली में दो स्वतंत्र सर्किट होते हैं, इसलिए एक सर्किट में रिसाव या विफलता दूसरे को खाली नहीं करती, जो दबाव बनाए रखकर वाहन के अपने हिस्से को ब्रेक करता है।"},"85":{"q":"मैंने अभी एक ठंडे यार्ड में अपने ट्रैक्टर-ट्रेलर का इंजन चालू किया है। कम वायु दाब की चेतावनी बत्ती बंद है, लेकिन जब मैं पार्किंग से निकलने की तैयारी कर रहा हूँ तब भी मेरा गेज केवल 65 psi दिखा रहा है। टेक्सास DPS प्रक्रिया के अनुसार, गाड़ी चलाना शुरू करने से पहले मुझे दाब को कम से कम कितना बढ़ने देना चाहिए?","options":["65 psi, क्योंकि कम वायु दाब की चेतावनी बत्ती पहले ही बंद हो चुकी है","लगभग 100 psi, ताकि ब्रेक को सुरक्षित रूप से चलाने के लिए पर्याप्त हवा हो","लगभग 60 psi, वह बिंदु जहाँ कम वायु दाब की चेतावनी बंद होती है","लगभग 125 psi, गवर्नर कट-आउट, पार्किंग ब्रेक छोड़ने से पहले"],"explanation":"गाड़ी चलाने से पहले हवा का दबाव कम से कम लगभग 100 psi तक बढ़ने दें ताकि सेवा और आपातकालीन ब्रेक को सुरक्षित रूप से चलाने के लिए पर्याप्त हवा हो।"},"86":{"q":"एकल सीधे ट्रक की अपनी प्री-ट्रिप जांच के दौरान, मैं एयर सिस्टम को लगभग 125 psi तक चार्ज करता हूं, इंजन बंद करता हूं और पहियों के नीचे चॉक लगाता हूं। मैं पार्किंग ब्रेक नॉब को अंदर दबाए रखता हूं ताकि ब्रेक रिलीज़ रहें, और डैश के गेज को देखता हूं। पहले मिनट में सुई 4 psi से अधिक गिर जाती है। यह मुझे वाहन के बारे में क्या बता रहा है?","options":["कुछ भी गलत नहीं है; इंजन बंद होने पर टैंकों की हवा बस ठंडी होकर सिकुड़ रही है, इसलिए पहले मिनट में इतनी गिरावट अपेक्षित है।","यह रीडिंग साबित करती है कि स्प्रिंग (पार्किंग) ब्रेक सही ढंग से लग गए हैं, क्योंकि पार्किंग सिस्टम के सक्रिय होते ही दबाव हमेशा तेज़ी से निकल जाता है।","सिस्टम अनुमत दर से तेज़ हवा खो रहा है; ब्रेक रिलीज़ होने पर एकल वाहन को प्रति मिनट 2 psi से अधिक नहीं खोना चाहिए, और 4 psi से अधिक का अर्थ है एक लीक जिसे ढूंढकर ठीक करना ज़रूरी है।","यह पुष्टि करता है कि गवर्नर कट-आउट तक पहुंच गया और कंप्रेसर को रोक दिया, जो इंजन बंद करने के बाद दबाव का सामान्य व्यवहार है।"],"explanation":"ब्रेक छोड़ने पर एकल वाहन को प्रति मिनट 2 psi से अधिक नहीं खोना चाहिए, इसलिए 4 psi से अधिक की हानि हवा के रिसाव का संकेत है जिसे ढूंढकर ठीक करना चाहिए।"},"87":{"q":"मैं एक लोडिंग डॉक पर खड़ा हूँ, तभी हवा का धीमा रिसाव मेरे सप्लाई टैंकों को खाली कर देता है और सिस्टम का दबाव लगातार शून्य की ओर गिरता रहता है। जैसे-जैसे दबाव निकलता है, मेरा एयर ब्रेक सिस्टम ट्रक को लुढ़कने से रोकने के लिए क्या करता है, और क्यों? सही कथन चुनें।","options":["सर्विस ब्रेक पहियों को जकड़ने के लिए संग्रहित हाइड्रोलिक द्रव का उपयोग करते हैं, इसलिए टैंकों में हवा न होने पर भी ट्रक अपनी जगह पर खड़ा रहता है।","दबाव खत्म होने पर ट्रक को कुछ भी नहीं रोकता; वह एक छोटा सा रिसाव तुरंत सभी ब्रेक छोड़ देता है और वाहन स्वतंत्र रूप से लुढ़कने लगता है।","कंप्रेसर अपने आप रिसाव को वापस 125 psi तक पंप कर देता है, इसलिए पैडल वाले सर्विस ब्रेक वाहन को अपने आप रोके रखते हैं।","स्प्रिंग (पार्किंग) ब्रेक तब अपने आप लग जाते हैं जब दबाव 20-45 psi की सीमा में गिरता है, जो बिना किसी हवा के पहियों को यांत्रिक रूप से रोके रखते हैं।"],"explanation":"स्प्रिंग पार्किंग ब्रेक हवा से छूटे रहते हैं, इसलिए जब दबाव 20-45 psi की सीमा में गिरता है तो शक्तिशाली स्प्रिंग्स अपने आप ब्रेक लगा देते हैं और बिना हवा के पहियों को रोके रखते हैं।"},"88":{"q":"मैंने अभी अपने एयर-ब्रेक ट्रैक्टर का इंजन चालू किया है और हवा के दबाव का गेज केवल 50 psi दिखा रहा है, जबकि कम-हवा चेतावनी का बज़र अभी भी बज रहा है। मैं खड़ा हूँ, लदा हुआ हूँ, और अपनी डिलीवरी के लिए देर हो रही है। पार्किंग ब्रेक छोड़कर यार्ड से बाहर निकलने से पहले मुझे क्या करना चाहिए?","options":["इंजन चालू रखते हुए तब तक प्रतीक्षा करूँ जब तक दबाव लगभग 100 psi तक न पहुँच जाए और कम-हवा चेतावनी बंद न हो जाए","50 psi पर धीरे-धीरे निकल जाऊँ, क्योंकि डिलीवरी की ओर चलते समय ब्रेक दबाव बढ़ाते रहेंगे","फँसी हुई हवा निकालने के लिए टैंक के ड्रेन वाल्व खोल दूँ ताकि कंप्रेसर टैंकों को तेज़ी से भर सके","कम-हवा चेतावनी बज़र को डिस्कनेक्ट कर दूँ ताकि वह बजना बंद हो जाए, और शोर रुकते ही चला जाऊँ"],"explanation":"इंजन चालू रखें और गाड़ी चलाने से पहले तब तक प्रतीक्षा करें जब तक दबाव लगभग 100 psi तक न बढ़ जाए और कम-हवा चेतावनी बंद न हो जाए।"},"89":{"q":"मैं एक लदे हुए कॉम्बिनेशन के साथ एक लंबी पहाड़ी ढलान से नीचे उतर रहा हूँ और पूरे रास्ते मैंने ब्रेक पेडल पर लगातार दबाव बनाए रखा है। नीचे के पास, पेडल अब भी मज़बूत महसूस होता है पर दबाने पर गाड़ी मुश्किल से ही धीमी होती है। मेरे ब्रेक की रोकने की शक्ति क्यों खत्म हो गई, इसे कौन-सा स्पष्टीकरण सबसे अच्छी तरह बताता है?","options":["लगातार ब्रेक लगाने से सिस्टम का हवा दबाव गवर्नर कट-आउट से ऊपर चला गया, इसलिए ब्रेक अब पर्याप्त बल नहीं बना पाते","लगातार ब्रेक लगाने से ब्रेक ड्रम और लाइनिंग ज़्यादा गरम हो गए, और यह गरमी ब्रेक द्वारा पैदा किए जाने वाले घर्षण को कम कर देती है","लगातार ब्रेक लगाने से हवा के टैंक धीरे-धीरे खाली हो गए, और इसकी भरपाई के लिए स्प्रिंग ब्रेक आंशिक रूप से छूट गए","गरमी से स्लैक एडजस्टर कस गए, जिससे लाइनिंग ड्रम से दूर खिंच गई"],"explanation":"लंबी ढलान पर लगातार ब्रेक लगाने से ड्रम और लाइनिंग अधिक गरम हो जाते हैं, और यह गर्मी ब्रेक द्वारा उत्पन्न घर्षण को कम कर देती है, जिससे ब्रेक फेड होता है।"},"90":{"q":"मैं अपने एयर-ब्रेक ट्रक में स्टॉप साइन के पास पहुँच रहा हूँ और ब्रेक पेडल को मजबूती से दबाता हूँ। मेरा पैर तुरंत हिलने के बावजूद, ट्रक के वास्तव में धीमा होने का एहसास होने से पहले एक स्पष्ट देरी होती है। मेरे प्रशिक्षक इसे 'ब्रेक लैग' (brake lag) कहते हैं। उस देरी के दौरान वास्तव में क्या हो रहा है?","options":["मेरे स्लैक एडजस्टर (slack adjusters) गलत संरेखित हैं, इसलिए पुशरॉड शूज़ को बहुत धीरे बैठाते हैं","एक चालक के रूप में मेरी प्रतिक्रिया का समय ही निर्णय और ब्रेकिंग के बीच की देरी पैदा करता है","हवा को लाइनों से होकर ब्रेक तक पहुँचने में एक सेकंड का अंश लगता है","हवा का दबाव कट-इन से नीचे गिर गया है, इसलिए गवर्नर को पहले फिर से दबाव बनाना होगा"],"explanation":"ब्रेक लैग वह लगभग आधा सेकंड है जो संपीड़ित हवा को पेडल से ब्रेक चैंबरों तक लाइनों के माध्यम से जाने में लगता है, जो हर एयर ब्रेक प्रणाली की सामान्य विशेषता है।"},"91":{"q":"एक पुराने एयर-ब्रेक ट्रैक्टर पर अपने यात्रा-पूर्व निरीक्षण के दौरान, मैं हवा का दबाव बनने देता हूँ, इंजन बंद करता हूँ, और दबाव घटाने के लिए ब्रेक को बार-बार दबाना शुरू करता हूँ। जैसे ही गेज 60 psi की ओर गिरता है, विंडशील्ड के ऊपर एक छोटी यांत्रिक भुजा अचानक मेरी नज़र के सामने नीचे आ जाती है। प्रशिक्षक इसे 'wig-wag' कहते हैं। इस उपकरण का उद्देश्य क्या है?","options":["यह गवर्नर है जो संकेत देता है कि कंप्रेसर कट-आउट तक पहुँच गया है और टैंकों में हवा भरना बंद कर दिया है","यह मॉड्युलेटिंग कंट्रोल वाल्व है जो नीचे गिरकर मुझे आपातकाल में स्प्रिंग ब्रेक धीरे-धीरे लगाने देता है","यह स्वचालित ड्रेन वाल्व है जो सप्लाई टैंक में जमा पानी और तेल को बाहर निकालता है","यह एक यांत्रिक कम-हवा चेतावनी उपकरण है जो शारीरिक रूप से नज़र के सामने गिरकर मुझे आगाह करता है कि दबाव खतरनाक रूप से कम हो रहा है"],"explanation":"विग-वैग एक यांत्रिक कम-हवा चेतावनी है जिसकी स्प्रिंग-युक्त भुजा चालक की दृष्टि में गिरकर संकेत देती है कि हवा का दबाव खतरनाक रूप से कम हो रहा है।"},"92":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं ब्रेक पेडल दबाता हूं और एक पहिये के फाउंडेशन ब्रेक को देखता हूं। जैसे-जैसे हवा ब्रेक चैंबर को भरती है, पुश रॉड बाहर की ओर बढ़ती है। सही ढंग से काम करने वाले S-कैम ड्रम ब्रेक में, इस पुश रॉड की गति के बाद अगला कदम क्या होना चाहिए?","options":["स्लैक एडजस्टर को घुमाना, जो S-कैम को घुमाता है और ब्रेक शूज़ को ड्रम के विरुद्ध दबाता है","किसी कैम या लीवर के बिना ब्रेक शूज़ को सीधे ड्रम के विरुद्ध दबाना","स्प्रिंग ब्रेक चैंबर को खोलना ताकि पार्किंग स्प्रिंग्स सर्विस ब्रेक लगाने में मदद करें","सिस्टम का दबाव बनाए रखने के लिए सप्लाई टैंक में अतिरिक्त संपीड़ित हवा भेजना"],"explanation":"ब्रेक चैंबर में हवा पुश रॉड को धकेलती है, जो स्लैक एडजस्टर को घुमाती है और S-कैम को मोड़ती है, जिससे ब्रेक शूज़ अलग होकर ड्रम पर दबते हैं।"},"93":{"q":"मैंने अभी हवा ब्रेक वाला 2020 का ट्रक ट्रैक्टर खरीदा है, और मैं ABS की वायरिंग का पता लगा रहा हूँ ताकि पुष्टि हो सके कि इतने नए वाहन के लिए एंटी-लॉक प्रणाली संघीय आवश्यकता को पूरा करती है। हर एक्सल जाँचते समय, मुझे किन पहियों पर ABS मिलना ज़रूरी है?","options":["केवल अगले (स्टीयरिंग) पहियों पर, क्योंकि वहीं लॉक होने से स्टीयरिंग नियंत्रण खो जाता है","ट्रैक्टर के सभी पहियों पर, क्योंकि नए ट्रैक्टरों में हर पहिये पर ABS होना अनिवार्य है","केवल पिछले ड्राइव पहियों पर, क्योंकि सबसे भारी ब्रेकिंग भार वहीं पड़ता है","किसी भी पहिये पर नहीं, क्योंकि ABS एक वैकल्पिक उपकरण है जिसे खरीदार बाद में जोड़ता है"],"explanation":"1 मार्च 1997 या उसके बाद बने ट्रक ट्रैक्टरों के हर पहिये पर ABS आवश्यक है, इसलिए नए ट्रैक्टर में सभी पहियों पर ABS होना चाहिए।"},"94":{"q":"अपने संयोजन वाहन की यात्रा-पूर्व जाँच के दौरान, डैशबोर्ड बताता है कि ट्रैक्टर का अपना ABS ठीक है, लेकिन मुझे फिर भी यह पुष्टि करनी है कि ट्रेलर का ABS काम कर रहा है। ट्रेलर 1999 में बना था, इसलिए इसका अपना ABS और एक अलग खराबी लैंप है जिसे मुझे जाँचना होगा। वाहन के चारों ओर घूमते समय, मुझे वह ट्रेलर ABS खराबी लैंप कहाँ खोजना चाहिए?","options":["ट्रेलर के अगले हिस्से पर किंगपिन के पास लगा हुआ, ताकि वह ट्रैक्टर केबिन की ओर मुँह करे","केबिन के अंदर डैशबोर्ड पर, ट्रैक्टर के अपने ABS चेतावनी लैंप के ठीक बगल में","ट्रेलर के बाईं ओर या बाएँ पिछले हिस्से पर, जहाँ वह चारों ओर घूमते समय दिखाई देता है","ट्रेलर के एयर टैंक के अंदर, मैनुअल ड्रेन वाल्व के पीछे"],"explanation":"1999 के ट्रेलर पर, ABS खराबी की चेतावनी लाइट ट्रेलर के बाईं ओर या बाएं पिछले हिस्से पर लगाई जाती है ताकि वॉक-अराउंड निरीक्षण के दौरान दिखाई दे।"},"95":{"q":"मैं एयर-ओवर-हाइड्रॉलिक ब्रेक सिस्टम से लैस एक मध्यम-भार वाला ट्रक चला रहा हूँ। अपनी प्री-ट्रिप जाँच के दौरान, मैं समझना चाहता हूँ कि इस सिस्टम का हवा वाला हिस्सा असल में क्या करता है, ताकि मुझे पता रहे कि हवा की आपूर्ति विफल होने पर मैं क्या खो दूँगा। इस व्यवस्था में हवा के दबाव की भूमिका को कौन-सा कथन सही ढंग से बताता है?","options":["हवा का दबाव कैलिपरों के अंदर घूमकर हाइड्रॉलिक द्रव को ठंडा करता है और लंबी ढलानों पर उसे ज़्यादा गरम होने से रोकता है","हवा का दबाव हाइड्रॉलिक द्रव को भरा रखता है और घिसी हुई सील से निकल जाने वाले द्रव को अपने आप बदल देता है","हवा का दबाव उस कंप्रेसर को चलाता है जो बैटरी को चार्ज करता है, ताकि हाइड्रॉलिक पंप को हमेशा बिजली मिलती रहे","हवा का दबाव हाइड्रॉलिक सिस्टम पर काम करके चालक द्वारा पेडल पर लगाए गए ब्रेकिंग बल को बढ़ा (बूस्ट) देता है"],"explanation":"एयर-ओवर-हाइड्रोलिक सिस्टम में, हवा का दबाव चालक द्वारा पेडल पर लगाए बल को बढ़ाता है, जिसे हाइड्रोलिक द्रव फिर पहिया ब्रेक तक पहुंचाता है।"},"96":{"q":"प्री-ट्रिप निरीक्षण के दौरान आपको पता चलता है कि स्लैक एडजस्टर में पुशरॉड की गति अत्यधिक है, यानी ब्रेक एडजस्टमेंट से बाहर हैं। यदि आप फिर भी गाड़ी चलाते हैं और एक लंबी, तीखी ढलान से नीचे उतरते हैं, तो इस खराबी का सबसे संभावित परिणाम क्या होगा?","options":["ब्रेकिंग शक्ति कम हो जाएगी, और ढलान पर गर्म होते ही ब्रेक पूरी तरह से फेल हो सकते हैं","ब्रेक सामान्य से अधिक मजबूती से पकड़ेंगे, जिससे पहिए लॉक होने और फिसलने का खतरा बढ़ जाएगा","सिस्टम बस कम हवा का उपयोग करेगा, इसलिए आप ढलान पर ब्रेक पैडल को सुरक्षित रूप से अधिक देर तक पंप कर सकते हैं","कम हवा दबाव की चेतावनी जल्दी सक्रिय हो जाएगी, लेकिन ब्रेकिंग शक्ति स्वयं अप्रभावित रहेगी"],"explanation":"ठीक से समायोजित न किए गए ब्रेक ब्रेकिंग शक्ति को कम करते हैं और लंबी, खड़ी ढलान जैसे गर्मी के दबाव में पूरी तरह विफल हो सकते हैं।"},"97":{"q":"मैं अपने एयर-ब्रेक ट्रक में हल्की ढलान पर नीचे जा रहा हूँ और गति कम करने के लिए ब्रेक पेडल को थोड़ा ज़ोर से दबाता हूँ। जैसे-जैसे मैं पेडल दबाता हूँ, मेरे दो दबाव गेजों में से एक उतना ही ऊपर चढ़ता है जितना ज़ोर से मैं दबाता हूँ। मैं कौन-सा गेज देख रहा हूँ, और वह मुझे क्या बता रहा है?","options":["सप्लाई (भंडारण) दबाव गेज, जो बताता है कि मेरी टंकियों में अभी कितनी हवा जमा है","एप्लिकेशन दबाव गेज, जो बताता है कि मैं पेडल से ब्रेकों पर कितना हवा का दबाव लगा रहा हूँ","गवर्नर कट-आउट गेज, जो बताता है कि कंप्रेसर 125 psi पर पंप करना कब बंद करेगा","लो-एयर चेतावनी गेज, जो बताता है कि दबाव 60 psi से नीचे गिरने वाला है"],"explanation":"एप्लिकेशन प्रेशर गेज ब्रेक तक भेजे जा रहे हवा के दबाव को दिखाता है, इसलिए पेडल जोर से दबाने पर इसका पाठ बढ़ता है और छोड़ने पर घटता है।"},"98":{"q":"मैं एक सूखे राजमार्ग पर 55 मील प्रति घंटा की रफ़्तार से एयर ब्रेक वाला ट्रैक्टर-ट्रेलर चला रहा हूं, तभी आगे एक खराब खड़ी कार दिखती है और मैं ज़ोर से ब्रेक पैडल दबाता हूं। एक सहपाठी ज़ोर देकर कहता है कि हवा को लाइनों से गुज़रकर ब्रेक लगाने में जो आधा सेकंड लगता है, वह राजमार्ग की गति पर लगभग कोई मायने नहीं रखता। इस ब्रेक देरी से 55 मील प्रति घंटा पर — मेरी दृष्टि, प्रतिक्रिया और प्रभावी ब्रेकिंग दूरी के ऊपर — लगभग कितनी अतिरिक्त रुकने की दूरी जुड़ती है?","options":["गिनने लायक कुछ नहीं — आधा सेकंड की देरी 55 मील प्रति घंटा पर कोई मापने योग्य दूरी जोड़ने के लिए बहुत छोटी है","लगभग 12 फुट — ब्रेक पकड़ने से पहले लगभग ट्रैक्टर की लंबाई जितनी","लगभग 32 फुट — ब्रेक लगने से पहले लगभग ट्रेलर की लंबाई जितनी दूरी तय होती है","लगभग 60 फुट — क्योंकि गति बढ़ने पर देरी की दूरी दोगुनी होती रहती है"],"explanation":"एयर ब्रेक में लगभग आधा सेकंड की देरी होती है, इसलिए 55 मील प्रति घंटे पर ब्रेक पकड़ने से पहले वाहन लगभग 32 फीट अतिरिक्त चलता है।"},"99":{"q":"अपने ट्रिप-पूर्व निरीक्षण के दौरान, मैंने सिस्टम पूरी तरह चार्ज होने पर इंजन बंद कर दिया और गेज देख रहा हूँ। सभी दरवाज़े बंद हैं और मैं ब्रेक पेडल भी नहीं दबा रहा, फिर भी सुई धीरे-धीरे नीचे खिसकती जा रही है और स्थिर नहीं होती। यह तय करने से पहले कि यह ट्रक चलाने के लिए सुरक्षित है या नहीं, कौन-सी स्थिति मुझे बताती है कि लीक इतनी गंभीर है कि मुझे इसे सड़क पर नहीं ले जाना चाहिए?","options":["भरते समय गेज ठीक 125 psi तक चढ़ गया था, इसलिए उसके बाद का धीमा गिरना केवल टैंकों के सामान्य ठंडा होने के कारण है","मुझे कंप्रेसर के पास से हल्की सी सीटी जैसी आवाज़ सुनाई देती है, पर जब तक कम-हवा चेतावनी का बज़र नहीं बजा, तब तक सिस्टम चलाने के लिए ठीक है","दबाव केवल तब तक गिरता है जब तक गवर्नर फिर से चालू (cut-in) नहीं हो जाता, जो साबित करता है कि कंप्रेसर माँग के अनुसार हवा बना रहा है","इंजन बंद और ब्रेक छोड़े हुए होने पर, हवा का दबाव स्थिर नहीं रहता और अनुमत लीकेज दर से अधिक गिरता ही रहता है"],"explanation":"इंजन बंद और ब्रेक छोड़े जाने पर दबाव स्थिर रहना चाहिए; यदि यह अनुमत रिसाव दर से अधिक गिरता रहे, तो रिसाव सुरक्षित रूप से चलाने के लिए बहुत बड़ा है।"},"100":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, इंजन के तेज़ आइडल पर चलने के बावजूद मेरा हवा का दबाव 70 psi से ऊपर नहीं बढ़ रहा, जिससे कम हवा दबाव की चेतावनी का बज़र बार-बार बज रहा है। एक मैकेनिक मुझे बताता है कि हवा उत्पन्न करके टंकियों में पंप करने वाला पुर्ज़ा खराब हो गया है और उसे बदलना होगा। वह किस पुर्ज़े की बात कर रहा है?","options":["एयर कंप्रेसर, जो सिस्टम को चलाने के लिए भंडारण टंकियों में हवा पंप करता है","गवर्नर, जो यह नियंत्रित करता है कि हवा कब भंडारण टंकियों में पंप की जाए","स्लैक एडजस्टर, जो ब्रेक चैंबरों तक हवा के प्रवाह को नियंत्रित करता है","सेफ्टी रिलीफ वाल्व, जो टंकी का दबाव बनाए रखने के लिए हवा छोड़ता है"],"explanation":"एयर कंप्रेसर हवा बनाकर भंडारण टैंकों में पंप करता है, इसलिए जब दबाव नहीं बढ़ पाता, तो खराब घटक कंप्रेसर ही है।"},"101":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान मैं इंजन चालू रखता हूँ और एयर गेज को ऊपर चढ़ते देखता हूँ। लगभग 125 psi पर कंप्रेसर सिस्टम में हवा भरना बंद कर देता है, और कई बार ब्रेक लगाने के बाद जब दबाव लगभग 100 psi तक गिरता है तो कंप्रेसर फिर से पंप करना शुरू कर देता है। इन दबावों पर कंप्रेसर को चालू और बंद करने के लिए कौन-सा घटक जिम्मेदार है?","options":["सुरक्षा रिलीफ वाल्व, जो टैंकों के लगभग 150 psi तक पहुँचने पर हवा बाहर निकाल देता है","गवर्नर (governor), जो लगभग 125 psi पर कंप्रेसर को बंद करता है और लगभग 100 psi पर उसे फिर से चालू करता है","कम एयर प्रेशर चेतावनी उपकरण, जो दबाव 60 psi से नीचे गिरने से पहले कंप्रेसर को संकेत देता है","कंप्रेसर के अपने अनलोडर पिस्टन, जो सिस्टम का कार्यशील दबाव स्वयं निर्धारित करते हैं"],"explanation":"गवर्नर कंप्रेसर को नियंत्रित करता है, इसे लगभग 125 psi पर बंद करता है और लगभग 100 psi पर फिर से चालू करता है।"},"102":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं इंजन चालू करता हूँ और देखता हूँ कि कंप्रेसर हवा पंप करते हुए वायु दाब गेज ऊपर चढ़ रहा है। मैं इंतज़ार कर रहा हूँ कि गवर्नर (governor) कट-आउट (cut-out) तक पहुँचे, यानी वह बिंदु जहाँ कंप्रेसर टैंकों में हवा डालना बंद कर देता है। मुझे यह लगभग किस गेज रीडिंग पर होने की उम्मीद करनी चाहिए?","options":["लगभग 100 psi, क्योंकि यहीं गवर्नर सिस्टम को नियंत्रित करता है","लगभग 150 psi, ठीक तब जब सिस्टम अपने सबसे उच्च सुरक्षित दाब पर पहुँचता है","लगभग 125 psi, जब गवर्नर कंप्रेसर को पंप करना बंद करने का संकेत देता है","लगभग 60 psi, ठीक तब जब चेतावनी उपकरण बंद होता है और पंपिंग समाप्त होती है"],"explanation":"कंप्रेसर कट-आउट, वह बिंदु जहां गवर्नर पंपिंग रोकता है, लगभग 125 psi पर होता है।"},"103":{"q":"मैं एयर ब्रेक वाले एक सिंगल वाहन की प्री-ट्रिप जांच कर रहा हूं। इंजन बंद होने पर, मैं सिस्टम का दबाव कम करने के लिए ब्रेक पेडल को बार-बार दबाता हूं और एयर गेज को गिरते हुए देखता हूं। दबाव खतरनाक रूप से कम होने की चेतावनी देने के लिए कम वायु दबाव वाली चेतावनी बत्ती और बजर किस बिंदु पर सक्रिय होने चाहिए?","options":["जैसे ही गेज 100 psi से नीचे गिरे, क्योंकि वहीं गवर्नर हवा फिर से भरने के लिए चालू होता है","जब दबाव 20 से 45 psi की सीमा में गिर जाए, ठीक उसी क्षण जब स्प्रिंग ब्रेक लग जाते हैं","जिस क्षण दबाव 125 psi से ऊपर चढ़े, जहां गवर्नर कट-आउट होकर पंप करना बंद कर देता है","गेज के 60 psi से नीचे गिरने से पहले, जब सुरक्षित रूप से रुकने के लिए अभी भी पर्याप्त हवा मौजूद हो"],"explanation":"कम हवा दबाव की चेतावनी दबाव 60 psi से नीचे गिरने से पहले आनी चाहिए, ताकि वाहन को सुरक्षित रूप से रोकने के लिए पर्याप्त हवा बची रहे।"},"104":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, मैं इंजन चालू करता हूं और देखता हूं कि डैशबोर्ड के एक गेज की सूई लगातार ऊपर चढ़ती जाती है, जब तक कि गवर्नर लगभग 125 psi पर कंप्रेसर को बंद नहीं कर देता। उस गेज और बाकी गेजों के बीच नज़र घुमाते हुए, यह खास गेज मुझे असल में कौन-सा माप बता रहा है?","options":["इस समय एयर टैंकों में कितना हवा का दबाव जमा है","मैं ब्रेक पेडल को कितनी ज़ोर से दबा रहा हूं, यानी एप्लिकेशन प्रेशर","वह बिंदु जिस पर कम हवा दबाव की चेतावनी बत्ती जलेगी","हवा को 85 से 100 psi तक चढ़ने में कितने सेकंड लगे"],"explanation":"वायु दाब गेज दिखाता है कि इस समय हवा की टंकियों में कितना वायु दाब संग्रहीत है।"},"105":{"q":"अभी सर्दी का मौसम है, और मेरे ट्रैक्टर-ट्रेलर के हवा के टैंकों पर मैनुअल ड्रेन वाल्व लगे हैं। मैंने अभी-अभी एक लंबी शिफ्ट पूरी की है और मुझे लगता है कि सिस्टम में पानी और कंप्रेसर का तेल जमा हो गया है। यह जानते हुए कि रात भर में यह जम सकता है और पुर्जों को नुकसान पहुंचा सकता है, मुझे नमी निकालने के लिए ये मैनुअल ड्रेन वाल्व कब खोलने चाहिए?","options":["केवल सप्ताह में एक बार, क्योंकि एयर ड्रायर दो ड्रेन के बीच अधिकांश नमी हटा देता है","हर दिन के अंत में, वाहन को पार्क करने से पहले टैंकों को पूरी तरह से ड्रेन करते हुए","केवल तब जब कम हवा दबाव की चेतावनी लाइट 60 psi से नीचे जलती है","लगभग महीने में एक बार, या जब भी मुझे टैंकों से स्पष्ट रूप से हवा का रिसाव दिखाई दे"],"explanation":"हर दिन के अंत में मैनुअल वाल्व वाली हवा की टंकियों को पूरी तरह खाली करें ताकि संचालन के दौरान जमा पानी और तेल निकल जाए।"},"106":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान परीक्षक मुझसे उन तीन अलग-अलग ब्रेकिंग प्रणालियों के नाम पूछता है जो एक ही एयर ब्रेक व्यवस्था में संयुक्त होती हैं। मैं सही ढंग से सर्विस ब्रेक और पार्किंग ब्रेक बता देता हूँ। उत्तर पूरा करने के लिए मुझे तीसरी प्रणाली के रूप में किसका नाम लेना चाहिए?","options":["रिटार्डर प्रणाली, जो ब्रेक पैडल का उपयोग किए बिना ट्रक को धीमा करती है","दोहरी-परिपथ प्रणाली, जो हवा को प्राथमिक और द्वितीयक आपूर्ति में बाँटती है","आपातकालीन ब्रेक प्रणाली, जो मुख्य वायु आपूर्ति विफल होने पर ट्रक को रोक देती है","मॉड्यूलेटिंग प्रणाली, जो मुझे स्प्रिंग ब्रेक को धीरे-धीरे लगाने देती है"],"explanation":"वायु ब्रेक प्रणाली तीन प्रणालियों को जोड़ती है: सर्विस ब्रेक, पार्किंग ब्रेक, और आपातकालीन ब्रेक जो हवा की आपूर्ति विफल होने पर वाहन रोकते हैं।"},"107":{"q":"मैं एक लदा हुआ सीधा ट्रक चला रहा हूँ, तभी एक नली फट जाती है और मेरा हवा का दबाव लगातार गिरता रहता है। कम हवा दबाव की चेतावनी बत्ती और भोंपू काफी देर से बज रहे हैं, और अब मुझे महसूस हो रहा है कि स्प्रिंग (पार्किंग/आपातकालीन) ब्रेक अपने आप लगने के कारण ट्रक खुद ही ज़ोर से धीमा हो रहा है। सटीक रीडिंग को छोड़कर (EXCEPT), जिस क्षण वे स्प्रिंग ब्रेक अपने आप लगे, उस समय हवा लगभग किस दबाव सीमा तक गिर चुकी थी?","options":["लगभग 100 psi, वह बिंदु जहाँ गवर्नर सामान्यतः चालू (cut-in) होता है","लगभग 60 psi, वही बिंदु जहाँ कम हवा दबाव की चेतावनी पहली बार चालू होती है","लगभग 125 psi, वह बिंदु जहाँ गवर्नर बंद (cut-out) होकर पंप करना रोक देता है","लगभग 20 से 45 psi, जहाँ स्प्रिंग ब्रेक अपने आप लग जाते हैं"],"explanation":"स्प्रिंग ब्रेक वायु दाब से खुले रहते हैं और जब दाब 20 से 45 psi की सीमा में गिरता है तो स्वतः लग जाते हैं।"},"108":{"q":"मैंने अभी-अभी अपना लदा हुआ ट्रक एक लंबी, तीखी ढलान से नीचे उतारा है, पूरे रास्ते एयर ब्रेक का ज़ोरदार इस्तेमाल करते हुए। नीचे मैं एक विश्राम स्थल पर रुकता हूँ और महसूस करता हूँ कि पहिए तेज़ गर्मी छोड़ रहे हैं। इनमें से एक को छोड़कर, बाकी सब केबिन से निकलने से पहले सही कदम हैं। मुझे अभी किस कार्य से बचना चाहिए?","options":["जब ब्रेक ड्रम ढलान से उतरने के कारण अभी भी बहुत गर्म हों, तब पार्किंग (स्प्रिंग) ब्रेक लगाना","पहियों को चॉक लगाना और रोके रखने के लिए स्प्रिंग ब्रेक पर भरोसा करने से पहले ब्रेक को ठंडा होने देना","सिस्टम के रोके रखने पर भरोसा करने से पहले हवा का दबाव फिर से गवर्नर कट-आउट तक बढ़ने देना","पुशरॉड ट्रैवल को बाद में जाँचना, क्योंकि गलत समायोजन वाले ब्रेक सबसे आम एयर-ब्रेक दोष हैं"],"explanation":"जब ब्रेक ड्रम बहुत गर्म हों, जैसे तीव्र ढलान के तुरंत बाद, तब पार्किंग (स्प्रिंग) ब्रेक कभी न लगाएं क्योंकि इससे वे क्षतिग्रस्त हो सकते हैं।"},"109":{"q":"मैं एक लदे हुए संयुक्त वाहन (ट्रैक्टर-ट्रेलर) में एक लंबी, खड़ी ढलान पर नीचे उतर रहा हूं। अपनी गति नियंत्रित रखने के लिए, मैं बार-बार ब्रेक पैडल को दबाता और छोड़ता रहता हूं (\"फैनिंग\")। पूरी ढलान पर ऐसा करने का सबसे संभावित परिणाम निम्न में से कौन सा है?","options":["मेरे ब्रेक ज़्यादा ठंडे रहेंगे क्योंकि हर बार दबाने के बीच उन्हें छूटने और सांस लेने का मौका मिलता है","मेरा हवा का दबाव गिर जाएगा क्योंकि हर बार पैडल छोड़ने पर हवा कंप्रेसर के पूरा करने से तेज़ी से निकलती है, और अंत में मेरी हवा खत्म हो जाएगी","हर बार छोड़ने पर कंप्रेसर तेज़ी से पंप करेगा, इसलिए मैं जितनी देर फैनिंग करूंगा, मेरे टैंक वास्तव में उतनी ही ज़्यादा हवा जमा करेंगे","जब तक मैं पूरी ढलान पर 60 psi के कम-हवा चेतावनी स्तर से ऊपर रहता हूं, तब तक कुछ नहीं बदलता"],"explanation":"लंबी ढलान पर ब्रेक को बार-बार न दबाएं, क्योंकि हर बार छोड़ने पर कंप्रेसर की भरपाई से तेज़ हवा निकलती है और अंततः आपकी हवा खत्म हो जाती है।"},"110":{"q":"मैं एयर ब्रेक (हवा वाले ब्रेक) से लैस एक ट्रैक्टर-ट्रेलर चला रहा हूँ और ब्रेक पैडल को ज़ोर से दबाता हूँ, लेकिन मैं देखता हूँ कि जिस क्षण मेरा पैर पैडल हिलाता है उसी पल वाहन धीमा होना शुरू नहीं होता — ब्रेकिंग वास्तव में शुरू होने से पहले लगभग आधे सेकंड की एक छोटी देरी होती है। यह देरी, जो हवा को ब्रेक लाइनों से होकर चैंबरों तक पहुँचने में लगने के कारण होती है, कहलाती है:","options":["ब्रेक फेड (brake fade) — लंबी ढलान पर अधिक गरम ड्रमों के कारण ब्रेकिंग शक्ति का नुकसान","ब्रेक पुल (brake pull) — ब्रेक लगाने पर वाहन का एक ओर मुड़ने का झुकाव","ब्रेक लैग (brake lag) — ब्रेकों के काम करने से पहले हवा को लाइनों से गुज़रने में लगने वाला समय","ब्रेक असंतुलन — ट्रैक्टर और ट्रेलर के एक्सलों के बीच असमान ब्रेकिंग बल"],"explanation":"ब्रेक लैग लगभग आधे सेकंड की वह देरी है जो ब्रेक के असर करने से पहले हवा को ब्रेक लाइनों से गुज़रने में लगने वाले समय के कारण होती है।"},"111":{"q":"मैं अपने एयर-ब्रेक ट्रैक्टर की तुलना अपने दोस्त की हाइड्रॉलिक ब्रेक वाली कार से कर रहा हूँ। समान गति, सड़क और प्रतिक्रिया समय मानते हुए, एयर ब्रेक का लगभग आधे सेकंड का ब्रेक लैग, हाइड्रॉलिक ब्रेक वाले वाहन की तुलना में मेरी कुल रुकने की दूरी को कैसे प्रभावित करता है?","options":["इसका कोई प्रभाव नहीं पड़ता, क्योंकि कुल रुकने की दूरी केवल प्रत्यक्षण दूरी और प्रतिक्रिया दूरी से तय होती है।","जैसे ही हवा ब्रेक चैंबर तक पहुँचती है, यह कुल रुकने की दूरी को लगभग आधा कर देता है।","यह कुल रुकने की दूरी को थोड़ा कम कर देता है, क्योंकि हवा का दबाव ब्रेकिंग बल को तेज़ी से बनाता है।","यह कुल रुकने की दूरी को थोड़ा बढ़ा देता है, क्योंकि कुल में ब्रेक-लैग दूरी जुड़ जाती है।"],"explanation":"लगभग आधे सेकंड का ब्रेक लैग कुल रुकने की दूरी में एक ब्रेक-लैग दूरी जोड़ता है, जो 55 मील प्रति घंटे पर लगभग 32 फीट होती है।"},"112":{"q":"अपनी प्री-ट्रिप जांच के दौरान मैं हवा भरता रहता हूं और देखता हूं कि गेज की सुई गवर्नर के कट-आउट बिंदु से आगे बढ़ रही है। कोई खराबी आ गई है और कंप्रेसर कभी रुकता ही नहीं, इसलिए दबाव बढ़ता ही जाता है। सिस्टम को अत्यधिक दबाव से बचाने के लिए सप्लाई (वेट) टैंक में लगा सेफ्टी रिलीफ वाल्व लगभग कितने दबाव पर खुलना चाहिए?","options":["लगभग 150 psi","लगभग 125 psi","लगभग 100 psi","लगभग 60 psi"],"explanation":"आपूर्ति टंकी में सुरक्षा रिलीफ वाल्व लगभग 150 psi पर खुलता है ताकि गवर्नर के विफल होने पर अतिरिक्त दाब बाहर निकाला जा सके।"},"113":{"q":"अपनी यात्रा-पूर्व एयर ब्रेक जांच के दौरान, परीक्षक मुझसे कहता है कि \"फुट वाल्व (foot valve) पर मजबूती से दबाव डालो और उसे दबाए रखो\", जबकि हम हवा के रिसाव की दर देखते हैं। मैं केबिन के नियंत्रणों और पैडल पर नजर डालता हूं। परीक्षक मुझे किसे दबाने के लिए कह रहा है?","options":["डैशबोर्ड पर लगे पीले, हीरे के आकार वाले नॉब को, क्योंकि वही ब्रेकिंग की हवा की आपूर्ति को नियंत्रित करता है","केबिन के फर्श पर लगे ब्रेक पैडल को, क्योंकि एयर ब्रेक सिस्टम में इसे फुट या ट्रेडल वाल्व (foot/treadle valve) भी कहा जाता है","एक्सेलरेटर पैडल को, क्योंकि रिसाव परीक्षण शुरू करने से पहले हवा का दबाव बढ़ाना जरूरी है","क्लच पैडल को, क्योंकि इसे दबाने से ही स्प्रिंग ब्रेक छूटकर दबाव लागू होता है"],"explanation":"कैब के फर्श पर स्थित ब्रेक पेडल सर्विस ब्रेक का नियंत्रण है, जिसे फुट वाल्व या ट्रेडल वाल्व भी कहते हैं।"},"114":{"q":"मैं डुअल (दोहरी) एयर ब्रेक प्रणाली वाला एक ट्रैक्टर-ट्रेलर चला रहा हूँ, तभी अचानक कम वायु दाब की चेतावनी बत्ती और बज़र चालू हो जाते हैं, जो बताते हैं कि प्राथमिक वायु प्रणाली का दाब गिर गया है। इस समय अपने ब्रेक से मुझे क्या उम्मीद करनी चाहिए, इसके बारे में निम्नलिखित में से कौन सा कथन सही है?","options":["प्राथमिक और द्वितीयक दोनों प्रणालियाँ एक साथ बंद हो जाती हैं, इसलिए मेरे पास बिल्कुल भी ब्रेकिंग शक्ति नहीं बचती","स्प्रिंग (पार्किंग) ब्रेक तुरंत सभी पहियों को जकड़ कर लॉक कर देते हैं, और नियंत्रण बनाए रखने के लिए मुझे तेज़ी से स्टीयरिंग घुमानी चाहिए","द्वितीयक प्रणाली अब भी हवा से भरी हुई है और ब्रेकिंग देती रहेगी, इसलिए मैं सुरक्षित रूप से रुकने तक ब्रेक लगा सकता हूँ","मेरी रुकने की शक्ति दोगुनी हो जाती है क्योंकि द्वितीयक प्रणाली अपना पूरा वायु दाब पहियों में छोड़ देती है"],"explanation":"दोहरी एयर ब्रेक प्रणाली में प्राथमिक सर्किट विफल होने पर अलग द्वितीयक सर्किट चार्ज रहता है, इसलिए वाहन को सुरक्षित रूप से रोका जा सकता है।"},"115":{"q":"मेरी यात्रा-पूर्व जांच के दौरान एयर सिस्टम पूरी तरह चार्ज है और इंजन बंद है। गाड़ी चलाने से पहले मैं पुष्टि करना चाहता हूं कि कम हवा दबाव चेतावनी उपकरण ठीक से काम कर रहा है। कौन सी क्रिया इसे सही तरीके से जांचती है?","options":["इंजन चालू करें और गवर्नर को तब तक हवा पंप करने दें जब तक सुरक्षा राहत वाल्व न खुले, फिर बजर सुनें","ब्रेक पैडल को एक मिनट तक मजबूती से दबाकर रखें और गेज पर अचानक दबाव बढ़ने को देखें","पीले पार्किंग-ब्रेक नॉब को बाहर खींचें और पुष्टि करें कि चेतावनी बजने से पहले स्प्रिंग ब्रेक लग जाते हैं","इंजन बंद रखते हुए ब्रेक पैडल को दबाएं और छोड़ें ताकि हवा निकले, और देखें कि चेतावनी 60 psi तक पहुंचने से पहले सक्रिय हो जाए"],"explanation":"इंजन बंद रखकर ब्रेक पैडल को दबाएं और छोड़ें ताकि टैंक से हवा निकले, और पुष्टि करें कि दबाव 60 psi से नीचे गिरने से पहले लो-एयर चेतावनी चालू हो जाए।"},"116":{"q":"मैं एक मानक एयर ब्रेक सिस्टम वाला अकेला सीधा ट्रक चला रहा हूँ, तभी मेरा एयर कंप्रेसर खराब होने लगता है और दबाव लगातार गिरता रहता है। मेरी कम-हवा चेतावनी लाइट और बजर काफी देर से चालू हैं, और मैं सड़क से किनारे हटने के लिए धीमा हो रहा हूँ। यदि मैं पहले ही पार्क कर चुका हूँ उस स्थिति को छोड़कर (EXCEPT), लगभग किस दबाव पर मुझे यह उम्मीद करनी चाहिए कि स्प्रिंग (पार्किंग) ब्रेक अपने आप लग जाएँ और ट्रक को रोक दें?","options":["लगभग 20 से 45 psi की सीमा में कहीं","60 psi से ठीक नीचे, उसी बिंदु पर जहाँ चेतावनी लाइट जलती है","लगभग 100 psi, जब गवर्नर सामान्य रूप से कट-इन होता है","लगभग 125 psi, जब गवर्नर सामान्य रूप से कट-आउट होता है"],"explanation":"स्प्रिंग (पार्किंग/आपातकालीन) ब्रेक हवा के दबाव से खुले रहते हैं और दबाव 20 से 45 psi की सीमा में गिरने पर अपने आप लग जाते हैं।"},"117":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, मैं अपने सिंगल वाहन पर एयर लीकेज रेट टेस्ट करने वाला हूँ। मैंने इंजन चालू कर दिया है और एयर गेज अभी लगभग 90 psi दिखा रहा है और अब भी बढ़ रहा है। दबाव गिरने का समय मापना शुरू करने से पहले, टेस्ट को सही बनाने के लिए मुझे सबसे पहले क्या करना चाहिए?","options":["ब्रेक पेडल को कई बार दबाकर लाइनों की हवा कट-इन दबाव तक निकालें, फिर समय मापना शुरू करें","सिस्टम को तब तक भरने दें जब तक गवर्नर लगभग 125 psi पर कट-आउट न हो जाए, फिर इंजन बंद कर दें","सभी एयर टैंक पूरी तरह खाली कर दें ताकि एक साफ, खाली सिस्टम से नुकसान मापा जा सके","पार्किंग ब्रेक लगाएँ और इंजन को तब तक रेस करें जब तक सेफ्टी रिलीफ वाल्व लगभग 150 psi पर न खुल जाए"],"explanation":"हवा रिसाव परीक्षण तब करना चाहिए जब सिस्टम गवर्नर कट-आउट यानी लगभग 125 psi तक पूरी तरह चार्ज हो और इंजन बंद हो, ताकि कंप्रेसर रिसाव को छिपा न सके।"},"118":{"q":"एक सीधे (सिंगल) ट्रक की प्री-ट्रिप जाँच के दौरान मैं इंजन बंद करता हूँ, पहियों के नीचे चॉक लगाता हूँ और एयर सिस्टम को गवर्नर कट-आउट तक भर देता हूँ। पार्किंग ब्रेक छोड़े हुए रखकर मैं एक मिनट तक डैश गेज देखता हूँ ताकि लीकेज जाँच सकूँ। कौन-सा रीडिंग बताता है कि लीकेज अभी भी कानूनी सीमा में है और मैं आगे बढ़ सकता हूँ?","options":["उस एक मिनट में 3 psi तक की गिरावट स्वीकार्य है, क्योंकि सिंगल वाहन में ब्रेक छोड़े होने पर यही सीमा है","कोई भी गिरावट विफलता है; इंजन बंद और ब्रेक छोड़े होने पर गेज को बिल्कुल स्थिर रहना चाहिए","उस एक मिनट में अधिकतम 2 psi की गिरावट इस सिंगल वाहन की ब्रेक-छोड़ी जाँच के लिए सीमा के भीतर है","उस मिनट में 4 psi तक की गिरावट ठीक है क्योंकि ब्रेक छोड़े हुए हैं, लगाए नहीं गए हैं"],"explanation":"फ्रेन छोड़े हुए एकल वाहन के लिए, प्रति मिनट 2 psi से अधिक की हवा हानि अनुमेय सीमा के भीतर है।"},"119":{"q":"एक इकहरे (सीधे, बिना ट्रेलर के) बॉक्स ट्रक की प्री-ट्रिप जाँच के दौरान, मैंने सिस्टम को लगभग 125 psi तक पूरी तरह चार्ज किया, इंजन बंद किया, और ब्रेक पैडल को दबाकर दबाए रखा। अब मैं लीकेज दर जाँचने के लिए एक पूरे मिनट तक एयर गेज देख रहा हूँ। इस टेस्ट को पास करने के लिए, जो दबाव गिरावट मैं देखूँ वह इससे अधिक नहीं होनी चाहिए:","options":["उस मिनट में 2 psi, क्योंकि पैडल दबाए रखना ब्रेक छोड़े हुए वाली जाँच जैसा ही मानक है","उस मिनट में 4 psi, जो एक इकहरे सीधे ट्रक को खोने की अनुमति वाली सीमा है","उस मिनट में 10 psi, जब तक टेस्ट के दौरान लो-एयर चेतावनी कभी सक्रिय न हो","उस मिनट में 3 psi, जो ब्रेक लगाए हुए एक इकहरे वाहन के लिए अधिकतम अनुमत हानि है"],"explanation":"ब्रेक लगे होने पर, एकल वाहन प्रति मिनट 3 psi से अधिक नहीं खो सकता और तभी सीमा के भीतर रहता है।"},"120":{"q":"यात्रा-पूर्व निरीक्षण के दौरान, मैं स्लैक एडजस्टर को खींचता हूँ और देखता हूँ कि इसमें एक इंच से अधिक का खाली खिंचाव है, जो बताता है कि ब्रेक एडजस्टमेंट से बाहर हैं। यदि मैं इसे ठीक किए बिना गाड़ी चलाता हूँ, तो मुझे किस सबसे सीधे सुरक्षा परिणाम की उम्मीद करनी चाहिए?","options":["ब्रेक खराब काम करेंगे क्योंकि अत्यधिक पुशरॉड यात्रा ब्रेकिंग शक्ति को कम कर देती है","हवा का दबाव 60 psi से नीचे गिरने से पहले कम हवा दबाव चेतावनी बजर बजेगा","एयर कंप्रेसर गवर्नर लगभग 125 psi पर हवा काटना बंद नहीं करेगा","जैसे ही दबाव 20 से 45 psi की सीमा में गिरेगा, स्प्रिंग ब्रेक स्वतः लग जाएंगे"],"explanation":"बहुत ढीले स्लैक एडजस्टर के कारण पुशरॉड की अत्यधिक गति होती है, जिससे पहियों तक पहुंचने वाला ब्रेकिंग बल कम हो जाता है और ब्रेक ठीक से काम नहीं करते।"},"121":{"q":"अपनी प्री-ट्रिप जांच के दौरान मैं ट्रेलर के नीचे जाता हूं और अपने सहायक से ब्रेक को जोर से दबाए रखने को कहता हूं, जबकि मैं ब्रेक चैंबर की पुशरॉड को देखता हूं। मैं जानना चाहता हूं कि स्लैक एडजस्टर अभी भी सही माप में है या नहीं। ब्रेक को 'एडजस्टमेंट से बाहर' मानकर सर्विस के लिए भेजने से पहले वह पुशरॉड लगभग कितना खिसक सकती है?","options":["माप से बाहर होने से पहले लगभग आधा फुट की गति","माप से बाहर होने से पहले लगभग 1 इंच की गति","माप से बाहर होने से पहले लगभग 6 इंच की गति","माप से बाहर होने से पहले लगभग 2 फुट की गति"],"explanation":"ब्रेक जोर से लगाने पर पुशरॉड की गति लगभग 1 इंच से अधिक नहीं होनी चाहिए; इसके भीतर स्लैक एडजस्टर सही सीमा में है।"},"122":{"q":"यात्रा-पूर्व जाँच के दौरान, मुझे अपने एक ब्रेक ड्रम पर एक बारीक दरार मिलती है और मैं देखता हूँ कि उस पहिए की ब्रेक जूती (शू) लगभग रिवेटों तक घिस चुकी है। मेरे पास अभी भी पूरा हवा दाब है और पैडल दबाने पर ब्रेक ठीक से लगते हैं। मेरे वाहन के लिए इस स्थिति का क्या अर्थ है?","options":["जब तक दाब गवर्नर कट-आउट तक बनता है और कम-हवा चेतावनी काम करती है, तब तक वाहन चलाना ठीक है","यह अभी स्वीकार्य है क्योंकि 5 मील प्रति घंटा रुकने के परीक्षण में ब्रेक अभी भी मजबूती से लगते हैं","वाहन सेवा से बाहर (आउट ऑफ सर्विस) है और तब तक नहीं चलाया जाना चाहिए जब तक दरारवाला ड्रम और घिसी जूती ठीक नहीं हो जाते","यह सूखी स्थिति में सुरक्षित है, केवल बारिश में या गीली सड़कों पर चलाने से बचना चाहिए"],"explanation":"दरार वाला ड्रम या रिवेट तक घिसे हुए शू अपने आप वाहन को सेवा से बाहर कर देते हैं, और इन पुर्जों की मरम्मत होने तक वाहन नहीं चलाना चाहिए।"},"123":{"q":"जब आप ब्रेक पेडल को ज़्यादा ज़ोर से दबाते हैं, तो एयर ब्रेक:","options":["पूरी तरह से छूट जाते हैं","अधिक ब्रेकिंग बल लगाते हैं","तुरंत बंद हो जाते हैं","टायरों में हवा भरते हैं"],"explanation":"ज़्यादा ज़ोर से दबाने पर अधिक एयर और अधिक ब्रेकिंग बल लगता है।"},"124":{"q":"मैं बारिश से फिसलन भरे हाईवे पर एक लदे हुए ट्रेलर को खींच रहा हूँ, तभी आगे ट्रैफिक अचानक रुक जाता है। मैं ब्रेक पेडल को पूरी तरह दबा देता हूँ और मेरे ट्रक में ABS (एंटी-लॉक ब्रेक सिस्टम) लगा है। ABS असल में जो करने के लिए बनाया गया है, उसके आधार पर इस कड़ी ब्रेकिंग में मुझे इससे क्या वास्तविक लाभ की उम्मीद करनी चाहिए?","options":["यह मेरी कुल रुकने की दूरी को उसी ट्रक की बिना ABS वाली दूरी से कहीं ज़्यादा कम कर देगा","यह मेरे लिए ब्रेक पंप करेगा, ताकि इस फिसलन वाली सतह पर मुझे कभी स्टैब ब्रेकिंग न करनी पड़े","यह अपने आप गियर कम कर देगा और मेरा हवा का दबाव बनाए रखेगा, ताकि स्प्रिंग ब्रेक कभी न लगें","यह मेरे पहियों को लॉक होने से रोकेगा, ताकि मैं रुके हुए ट्रैफिक के चारों ओर स्टीयरिंग से बच निकल सकूँ"],"explanation":"ABS रुकने की दूरी कम नहीं करता; यह जोर से ब्रेक लगाने पर पहियों को लॉक होने से रोकता है ताकि आप स्टीयरिंग नियंत्रण बनाए रखकर बाधाओं से बच सकें।"},"125":{"q":"प्री-ट्रिप निरीक्षण के दौरान मैं टैंकों से एक पहिये तक संपीड़ित हवा के रास्ते का पता लगाता हूँ। मैं वह एकमात्र पुर्जा ढूँढना चाहता हूँ जहाँ संग्रहीत हवा का दबाव अंततः उस यांत्रिक धक्का देने वाले बल में बदलता है जो वास्तव में ब्रेक की कड़ी को हिलाता है। मैं कौन सा पुर्जा ढूँढ रहा हूँ?","options":["ब्रेक चैंबर, क्योंकि यह हवा के दबाव को उस यांत्रिक बल में बदलता है जो ब्रेक लगाता है","स्लैक एडजस्टर, क्योंकि यही वह पुर्जा है जो बाहर निकलकर लाइनिंग को ड्रम पर दबाता है","एयर कंप्रेसर, क्योंकि यह उस दबाव का स्रोत है जो अंततः ब्रेक को शक्ति देता है","गवर्नर, क्योंकि यह पहिये तक पहुँचाए जाने वाले हवा के दबाव को नियंत्रित करता है"],"explanation":"ब्रेक चैंबर संपीड़ित हवा के दबाव को यांत्रिक बल में बदलता है जो पुशरॉड को बाहर धकेलकर ब्रेक लगाता है।"},"126":{"q":"अपने प्री-ट्रिप निरीक्षण के दौरान, मैं ट्रेलर के नीचे जाकर पुशरॉड की गति जाँचता हूँ, क्योंकि गलत समायोजन वाले ब्रेक एयर-ब्रेक का सबसे आम दोष हैं। मैं पुशरॉड को ब्रेक चैंबर से आगे तक देखता हूँ और पाता हूँ कि वह स्लैक एडजस्टर के एक सिरे से बोल्ट से जुड़ा है। यह समझने के लिए कि मेरा ब्रेकिंग बल वास्तव में पहिए के ब्रेक को कैसे लगाता है, मुझे यह जानना होगा कि उस स्लैक एडजस्टर का दूसरा सिरा किसे घुमाता है। स्लैक एडजस्टर पुशरॉड को किस घटक से जोड़ता है?","options":["ब्रेक पैडल लिंकेज से, ताकि पैडल दबाने पर पुशरॉड पीछे खिंचे","S-कैम से, जिसे यह घुमाकर ब्रेक शूज़ को ड्रम के विरुद्ध फैलाता है","एयर ड्रायर से, जिसे यह खोलकर चैंबर से नमी बाहर निकालता है","गवर्नर से, जिसे यह 125 psi पर कंप्रेसर बंद करने का संकेत देता है"],"explanation":"स्लैक एडजस्टर S-कैम को घुमाता है, जो ब्रेक शूज़ को ड्रम के विरुद्ध फैलाकर पहिए को रोकता है।"},"127":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, मैं अपने ट्रैक्टर-ट्रेलर के हर पहिए पर ब्रेक की जाँच कर रहा हूँ और एक S-आकार का कैम देखता हूँ जो घूमकर ब्रेक शू को बाहर की ओर, एक घूमते हुए ड्रम के विरुद्ध धकेलता है। मेरा परीक्षक पूछता है कि मुझे सबसे पहले इस डिज़ाइन से परिचित क्यों होना चाहिए। कौन-सा उत्तर सही है?","options":["यह एकमात्र फाउंडेशन ब्रेक डिज़ाइन है जिसे FMCSA अभी भी एयर ब्रेक वाले वाहनों पर अनुमति देता है","यह वेज-प्रकार का फाउंडेशन ब्रेक है, और आज अधिकांश भारी संयुक्त वाहन इसी के साथ बनाए जाते हैं","यह S-कैम ड्रम ब्रेक है, एयर ब्रेक वाले वाणिज्यिक वाहनों पर सबसे अधिक पाया जाने वाला फाउंडेशन ब्रेक डिज़ाइन","यह एयर डिस्क फाउंडेशन ब्रेक है, वह प्रकार जो आज सड़क पर चल रहे अधिकांश ट्रकों में उपयोग होता है"],"explanation":"एक S-आकार का कैम जो ब्रेक शूज़ को ड्रम के विरुद्ध दबाने के लिए घूमता है, वह S-कैम ड्रम ब्रेक है, जो एयर-ब्रेक वाहनों पर सबसे आम फाउंडेशन ब्रेक है।"},"128":{"q":"प्री-ट्रिप निरीक्षण के दौरान, मेरे प्रशिक्षक मुझे बताते हैं कि जब मैं ब्रेक पेडल दबाता हूँ, तो हवा का दबाव एक कैम को धकेलता है जो ब्रेक शूज़ को बाहर की ओर, पहिये से जुड़े एक घूमने वाले हिस्से के विरुद्ध दबाता है, और उनके बीच का घर्षण वाहन को धीमा करता है। यह रुकने वाला घर्षण पैदा करने के लिए ब्रेक शूज़ किस हिस्से के विरुद्ध दबते हैं?","options":["स्लैक एडजस्टर के विरुद्ध, जिसे शूज़ ब्रेकिंग बल स्थानांतरित करने के लिए दबाते हैं","ब्रेक चैंबर के विरुद्ध, जिसे शूज़ पहिये को रोकने के लिए जकड़ते हैं","हवा के भंडारण टैंक के विरुद्ध, जिसे शूज़ दबाव छोड़ने के लिए दबाते हैं","ब्रेक ड्रम के विरुद्ध, जिसके विरुद्ध शूज़ घर्षण पैदा करने के लिए दबते हैं"],"explanation":"ब्रेक शूज़ घूमते हुए ब्रेक ड्रम के विरुद्ध बाहर की ओर दबते हैं, और उनके बीच का घर्षण वाहन को धीमा करके रोकता है।"},"129":{"q":"एक अकेले ट्रैक्टर पर अपनी ट्रिप-पूर्व जाँच के दौरान, मैं वायु प्रणाली को चार्ज करना पूरा करता हूँ और चाहता हूँ कि वाहन इस तरह सेट हो जाए कि जब मैं उसके चारों ओर घूमूँ तो वह लुढ़के नहीं। डैशबोर्ड पर मुझे कौन-सा नियंत्रण और कैसे चलाना चाहिए?","options":["पार्किंग (स्प्रिंग) ब्रेक लगाने के लिए पीले, हीरे के आकार वाले नॉब को बाहर खींचें","पार्किंग (स्प्रिंग) ब्रेक लगाने के लिए लाल, आठ भुजाओं वाले नॉब को बाहर खींचें","पार्किंग (स्प्रिंग) ब्रेक लगाने के लिए पीले, हीरे के आकार वाले नॉब को अंदर दबाएँ","ब्रेक पैडल को दबाकर पकड़े रखें, जो स्प्रिंग ब्रेक को यांत्रिक रूप से लॉक कर देता है"],"explanation":"पार्किंग (स्प्रिंग) ब्रेक पीले, हीरे के आकार का नॉब है जिसे लगाने के लिए बाहर खींचा और छोड़ने के लिए अंदर दबाया जाता है।"},"130":{"q":"सुबह सबसे पहले मैं अपने ट्रैक्टर में चढ़ता हूँ, इंजन चालू करता हूँ और चलने के लिए तैयार हूँ। पार्किंग ब्रेक की पीली, हीरे के आकार की नॉब अभी भी बाहर खींची हुई है। पार्किंग ब्रेक छोड़ने के लिए उस नॉब को अंदर दबाने से पहले, मुझे कौन-सी शर्त पूरी होना सुनिश्चित करना चाहिए?","options":["इंजन सामान्य कार्यशील तापमान पर पहुँच गया है और शीतलक गेज ठंडे क्षेत्र से ऊपर आ गया है","हवा का दबाव इतना ऊपर चढ़ गया है कि सिस्टम पूरी तरह चार्ज है और कम हवा दबाव की चेतावनी बंद हो गई है","ईंधन का दबाव स्थिर हो गया है और डीज़ल इंजेक्शन लाइनों में पूरी तरह प्राइम हो गया है","इंजन तेल का दबाव सामान्य बैंड में चढ़ गया है ताकि बेयरिंग ठीक से चिकनाई पा सकें"],"explanation":"स्प्रिंग ब्रेक हवा के दबाव से छूटते हैं, इसलिए पार्किंग ब्रेक छोड़ने से पहले सिस्टम पूरी तरह चार्ज और लो-एयर चेतावनी बंद होनी चाहिए।"},"131":{"q":"यदि गाड़ी चलाते समय एयर सिस्टम में बुरी तरह रिसाव हो, तो अंततः ब्रेक:","options":["पूरी तरह काम करना बंद कर देंगे","अपने आप लग जाएंगे","आपकी गति बढ़ा देंगे","छूटे रहेंगे"],"explanation":"भारी एयर नुकसान से स्प्रिंग ब्रेक अपने आप लग जाते हैं।"},"132":{"q":"यदि गाड़ी चलाते समय आप एयर प्रेशर खो दें, तो आपको चाहिए:","options":["और तेज़ चलते रहना","जब तक संभव हो तब तक रुक जाना","चलते रहने के लिए पंप करना","चेतावनी को नज़रअंदाज़ करना"],"explanation":"जब तक आपके पास ब्रेकिंग है तब तक सुरक्षित रूप से रुक जाएं।"},"133":{"q":"मैं यात्रा-पूर्व एयर ब्रेक जांच कर रहा हूं और गवर्नर का परीक्षण करने के लिए डैश गेज देख रहा हूं। मैं हवा निकालने के लिए ब्रेक को बार-बार दबाता हूं, और कंप्रेसर फिर से चालू होकर हवा का दबाव दोबारा बनाना शुरू कर देता है। लगभग किस गेज रीडिंग पर गवर्नर को CUT IN करना चाहिए (चालू होना चाहिए) और कंप्रेसर को दोबारा पंप करना शुरू करना चाहिए?","options":["लगभग 60 psi, ठीक उसी समय जब लो-एयर चेतावनी आने वाली होती है","लगभग 125 psi, उसी बिंदु पर जहां यह पहले पंप करना बंद हुआ था","लगभग 100 psi, उस बिंदु से कुछ नीचे जहां यह बंद (cut out) हुआ था","लगभग 20 psi, ठीक उसी समय जब स्प्रिंग ब्रेक लगना शुरू होते हैं"],"explanation":"गवर्नर लगभग 100 psi पर पंपिंग फिर से शुरू करने के लिए कट-इन करता है, जो लगभग 125 psi के कट-आउट दबाव से कुछ नीचे है।"},"134":{"q":"ड्यूल एयर ब्रेक प्रणाली वाले एक ट्रैक्टर-ट्रेलर पर अपनी प्री-ट्रिप जांच के दौरान, मैं इंजन को तेज़ आइडल पर ले जाता हूं और डैश गेज को ऊपर चढ़ते हुए देखता हूं। मैं पुष्टि करना चाहता हूं कि हवा के दबाव के बढ़ने की दर मानक के भीतर है। सुई को 85 psi पार करते हुए देखते हुए, बढ़ोतरी को स्वीकार्य माने जाने के लिए किस समय तक इसे 100 psi तक पहुंच जाना चाहिए?","options":["85 psi पार करने के लगभग 3 सेकंड के भीतर","85 psi पार करने के लगभग 30 सेकंड के भीतर","85 psi पार करने के लगभग 60 सेकंड के भीतर","85 psi पार करने के लगभग 45 सेकंड के भीतर"],"explanation":"दोहरे एयर ब्रेक सिस्टम में दबाव लगभग 45 सेकंड के भीतर 85 से 100 psi तक बढ़ना चाहिए, वरना सिस्टम में खराबी है।"},"135":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, एयर कंप्रेसर ने मेरे सप्लाई (वेट) टैंक को चार्ज कर दिया है, लेकिन मुझे अपने सर्विस टैंक के आगे की एक लाइन पर धीमी लीक बनती दिख रही है। टैंकों के बीच एक वन-वे चेक वाल्व लगा है। जैसे-जैसे वह लीक हवा निकालती है, यह चेक वाल्व मेरे लिए मुख्य रूप से क्या काम कर रहा है?","options":["यह ऊपरी टैंक में पहले से जमा हवा को लीक वाले हिस्से से होकर पीछे की ओर बहकर निकलने से रोकता है","यह हवा के दबाव को लीक बिंदु से ऊपर कभी बढ़ने नहीं देता ताकि सिस्टम कभी ओवर-प्रेशर न हो","यह लीक होती हवा को ब्रेक चेंबरों तक पहुँचने से रोकता है ताकि ब्रेक फिर भी लगें","यह लीक के दौरान फँसी हवा को लाइनों के भीतर ठंडा होकर जमने से रोकता है"],"explanation":"एकतरफा चेक वाल्व हवा को केवल एक दिशा में बहने देता है, डाउनस्ट्रीम रिसाव को सील कर देता है ताकि अपस्ट्रीम टैंक में संग्रहीत हवा वापस बाहर न निकले।"},"136":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं अपने एयर टैंकों के ड्रेन वाल्व खोलता हूं और देखता हूं कि एक टैंक विशेष रूप से बाकी सब से कहीं ज्यादा पानी और तेल के गाद से लगातार भरा रहता है। यह जानते हुए कि सिस्टम कंप्रेसर से हवा को कैसे भेजता है, यह सबसे संभावित रूप से कौन सा टैंक है?","options":["ड्राई टैंक, क्योंकि यह प्रवाह में नीचे की ओर होता है और ठंडा होने के बाद नमी अंततः यहीं संघनित होती है","गीला (सप्लाई) टैंक, क्योंकि यह सीधे कंप्रेसर से हवा प्राप्त करता है और अधिकांश पानी पहले यहीं इकट्ठा होता है","ईंधन टैंक, क्योंकि एयर लाइनों से संघनन रातभर वापस इसी में बह जाता है","जो टैंक सबसे नीचे लगा हो, क्योंकि गुरुत्वाकर्षण सारा जमा पानी उसी की ओर खींच लेता है"],"explanation":"गीला (सप्लाई) टैंक कंप्रेसर से सीधे गर्म, नमी से भरी हवा प्राप्त करता है, इसलिए अधिकांश पानी और तेल पहले वहीं संघनित होकर जमा होता है।"},"137":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान मैं समतल जमीन पर वाहन खड़ा करता हूँ, पहियों के नीचे चॉक लगाता हूँ, पीली समचतुर्भुज नॉब को खींचकर पार्किंग ब्रेक लगाता हूँ, फिर चॉक हटाकर कम गियर में ब्रेक के विरुद्ध धीरे-धीरे आगे बढ़ता हूँ। यदि पार्किंग ब्रेक सही काम कर रहा है, तो क्या होना चाहिए?","options":["वाहन को धीरे-धीरे आगे रेंगना चाहिए, यह साबित करते हुए कि स्प्रिंग ब्रेक आंशिक दबाव बनाए रखते हैं","कम हवा की चेतावनी का बजर बजना चाहिए, यह पुष्टि करते हुए कि दबाव समय पर गिरने से स्प्रिंग ब्रेक लग गए","वाहन को अपनी जगह स्थिर रहना चाहिए और हिलना नहीं चाहिए, यह दर्शाते हुए कि पार्किंग ब्रेक वाहन को जगह पर रोके रखता है","वाहन अपनी जगह तभी टिका रहना चाहिए जब मैं सर्विस ब्रेक पेडल को भी मजबूती से दबाकर रखूँ"],"explanation":"सही काम करने वाला स्प्रिंग पार्किंग ब्रेक पूरी ताकत से जकड़ता है और कम गियर में धीरे आगे खींचने पर वाहन को अपनी जगह स्थिर रखना चाहिए।"},"138":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं पार्किंग ब्रेक छोड़ता हूँ, बस को समतल मैदान पर धीरे-धीरे लगभग 5 मील प्रति घंटा की गति तक आगे बढ़ने देता हूँ, और निकलने से पहले यह पुष्टि करना चाहता हूँ कि मेरे सर्विस ब्रेक सही ढंग से काम कर रहे हैं। इस समय मुझे क्या करना चाहिए?","options":["ब्रेक पैडल को कई बार तेज़ी से दबाऊँ और हर बार हवा निकलने की आवाज़ सुनूँ","पैडल को हल्के से दबाए रखूँ और धीरे-धीरे लुढ़कते हुए रुक जाऊँ, यह देखते हुए कि एयर गेज 60 psi से ऊपर बना रहे","पहले लगभग 20 मील प्रति घंटा तक गति बढ़ाऊँ ताकि मुझे ब्रेकों का अधिक यथार्थवादी, हाईवे जैसा अनुभव मिले","ब्रेक पैडल को मजबूती से दबाऊँ और जाँचें कि वाहन किसी एक ओर खिंचे बिना सीधा रुकता है और पैडल मजबूत महसूस होता है"],"explanation":"सही काम करने वाला सर्विस ब्रेक सिस्टम वाहन को बिना किसी ओर खिंचे सीधा रोकता है, और पेडल स्पंजी नहीं बल्कि मजबूत महसूस होता है।"},"139":{"q":"अपनी यात्रा-पूर्व एयर ब्रेक जाँच के दौरान, मैं लगभग 5 मील प्रति घंटे की रफ्तार से आगे बढ़ता हूँ और ब्रेक पेडल दबाता हूँ। ट्रक सीधा रुकता है, लेकिन पेडल मजबूत महसूस होने के बजाय नीचे धँस जाता है और मेरे पैर के नीचे नरम तथा स्पंजी महसूस होता है। पेडल के इस एहसास से मुझे क्या निष्कर्ष निकालना चाहिए?","options":["यह संभवतः ब्रेक सिस्टम में किसी समस्या का संकेत है जिसे गाड़ी चलाने से पहले जाँचना चाहिए","यह सामान्य है क्योंकि एयर ब्रेक हमेशा हाइड्रोलिक ब्रेक की तुलना में अधिक नरम महसूस होते हैं","इसका बस यह मतलब है कि हवा का दबाव 125 psi गवर्नर कट-आउट से ऊपर है","यह दिखाता है कि स्लैक एडजस्टर ने अतिरिक्त खाली जगह को स्वतः समायोजित कर लिया है"],"explanation":"नरम या स्पंजी पेडल जो नीचे तक धंस जाता है, ब्रेक में समस्या का संकेत देता है जैसे लाइनों में हवा, कम दबाव या रिसाव, जिसे चलाने से पहले ठीक करना जरूरी है।"},"140":{"q":"मैं अपनी यात्रा-पूर्व जांच पूरी कर रहा हूं और इंजन चालू करता हूं। डैशबोर्ड पर ABS खराबी की बत्ती पहले जलती है, लेकिन कभी बुझती नहीं — यह आइडल पर और पूरा दबाव बनने के बाद भी जलती रहती है। इसके आधार पर मुझे अपने एंटी-लॉक ब्रेकिंग सिस्टम के बारे में क्या निष्कर्ष निकालना चाहिए?","options":["बत्ती बस यह पुष्टि कर रही है कि ABS की स्व-जांच चली और सिस्टम पूरी तरह काम कर रहा है","ABS शायद ठीक से काम नहीं कर रहा है और गाड़ी चलाने से पहले इसकी जांच करानी चाहिए","बत्ती केवल कम हवा के दबाव का संकेत देती है, इसलिए मुझे बस गवर्नर को और हवा बनाने देना है","बत्ती का मतलब है कि स्प्रिंग ब्रेक लगे हुए हैं, इसलिए पार्किंग नॉब छोड़ते ही यह बुझ जाएगी"],"explanation":"ABS खराबी लैंप स्टार्ट होते समय कुछ देर जलकर बुझ जाना चाहिए; यदि यह जलता रहे तो ABS खराब हो सकता है और चलाने से पहले जांच जरूरी है।"},"141":{"q":"मैं एक भरा हुआ ट्रैक्टर-ट्रेलर चला रहा हूँ, तभी मेरे डैशबोर्ड पर ABS (एंटी-लॉक ब्रेक सिस्टम) की खराबी वाली चेतावनी लाइट जल उठती है। ब्रेक अभी भी सामान्य महसूस हो रहे हैं, लेकिन मुझे चिंता है कि अभी क्या हुआ। निम्नलिखित में से कौन सा कथन इस समय मेरी ब्रेकिंग स्थिति का सबसे सटीक वर्णन करता है?","options":["मैंने ब्रेक लगाने की पूरी क्षमता खो दी है और मुझे केवल इंजन और गियर का उपयोग करके धीमे होकर रुकना होगा","मेरी रुकने की दूरी अब अपने आप कम हो गई है, इसलिए मैं पहले की तुलना में देर से ब्रेक लगा सकता हूँ","मेरे पास अभी भी मेरे सामान्य सर्विस ब्रेक हैं और मैं वाहन को रोक सकता हूँ, लेकिन पहियों को लॉक होने से बचाने के लिए मुझे सावधानी से ब्रेक लगाना होगा","केवल मेरे पार्किंग ब्रेक काम करेंगे, इसलिए रुकने के लिए मुझे पीली नॉब को खींचना होगा"],"explanation":"ABS की खराबी केवल एंटी-लॉक सुविधा को बंद करती है, इसलिए सामान्य सर्विस ब्रेक पूरी तरह काम करते हैं पर पहियों को लॉक होने से बचाने के लिए सावधानी से ब्रेक लगाएं।"},"142":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं एक ब्रेक चैंबर पर अत्यधिक पुशरॉड यात्रा (फ्री प्ले) देखता हूं। मेरे ट्रैक्टर में स्वचालित स्लैक एडजस्टर लगे हैं, जिनके बारे में एक सहकर्मी कहता है कि वे 'रखरखाव-मुक्त' हैं, इसलिए वह कहता है कि अब मुझे उनकी चिंता करने की जरूरत नहीं। कौन सा कथन स्वचालित स्लैक एडजस्टर के साथ सही व्यवहार को दर्शाता है?","options":["चूंकि वे स्वयं समायोजित होते हैं, वे प्री-ट्रिप जांच के दौरान किसी भी निरीक्षण की आवश्यकता को समाप्त कर देते हैं","मुझे गाड़ी चलाते समय उन्हें हाथ से ढीला करना चाहिए जब तक अत्यधिक फ्री प्ले गायब न हो जाए","वे असमायोजित ब्रेक को समाप्त कर देते हैं, इसलिए मेरा सहकर्मी सही है कि उन्हें अनदेखा किया जा सकता है","फिर भी उन्हें नियमित रूप से जांचना चाहिए, क्योंकि असमायोजित ब्रेक उनके होने पर भी एक आम दोष है"],"explanation":"गलत समायोजन वाले ब्रेक एयर ब्रेक की सबसे आम खराबी हैं, इसलिए ऑटोमैटिक स्लैक एडजस्टर भी अचूक नहीं होते और उन्हें नियमित रूप से जांचना जरूरी है।"},"143":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं स्लैक एडजस्टर पर पुशरॉड की अत्यधिक यात्रा देखता हूं, जो बताता है कि ब्रेक एडजस्टमेंट से बाहर हैं। मुझे देर हो रही है और यार्ड के औजार ठीक वहीं रखे हैं। इस वाहन के सड़क पर जाने से पहले वास्तव में ब्रेक एडजस्टमेंट किसे करना चाहिए?","options":["केवल वही व्यक्ति जो ब्रेक एडजस्ट करने के लिए प्रशिक्षित और योग्य हो","कोई भी वर्तमान CDL धारक, क्योंकि लाइसेंस होना ब्रेक की दक्षता साबित करता है","मैं स्वयं, अभी, क्योंकि पुशरॉड यात्रा को यार्ड के औजारों से ठीक करना आसान है","जो भी सबसे पास और उपलब्ध हो, ताकि वाहन और देर न हो"],"explanation":"चूंकि गलत समायोजन वाले ब्रेक सीधे ब्रेकिंग शक्ति घटाते हैं, ब्रेक का समायोजन केवल इस काम के लिए प्रशिक्षित और योग्य व्यक्ति द्वारा ही किया जाना चाहिए।"},"144":{"q":"मैं अपना ट्रैक्टर-ट्रेलर चला रहा हूँ कि तभी कम हवा दबाव चेतावनी बत्ती जल उठती है, और मुझे तुरंत समझ आ जाता है कि मेरा एयर कंप्रेसर हवा पंप करना पूरी तरह बंद कर चुका है। लगभग एक मील आगे सुरक्षित कंधे वाला एक निकास है। यह मानते हुए कि मेरा सिस्टम पूरी तरह चार्ज था, मेरे टैंकों में बचा हुआ आरक्षित हवा मुझे क्या करने देता है?","options":["पूरे दिन भर के सफरों तक सामान्य रूप से गाड़ी चलाते रहना, क्योंकि टैंक एक दिन की हवा का भंडार रखते हैं","दबाव खतरनाक रूप से कम होने से पहले गति धीमी करने और सुरक्षित रूप से किनारे लगाने के लिए कुछ और बार ब्रेक लगाना","असीमित समय तक चलाते रहना, क्योंकि स्प्रिंग ब्रेक मेरे लिए सर्विस टैंकों को फिर से भरते रहेंगे","लगभग कोई उपयोगी ब्रेकिंग न मिलना, इसलिए मुझे ठीक जहाँ हूँ वहीं तुरंत सड़क से उतर जाना चाहिए"],"explanation":"एयर टैंक संपीड़ित हवा का भंडार रखते हैं ताकि कंप्रेसर रुकने के बाद भी आप सुरक्षित रूप से सड़क से हटने के लिए कई बार और ब्रेक लगा सकें।"},"145":{"q":"सर्दियों की एक जमा देने वाली सुबह है और मेरी प्री-ट्रिप जाँच सूची मुझे याद दिला रही है कि हवा की टंकियों को रोज़ाना निकालूँ ताकि पानी और कंप्रेसर का तेल जमा होकर सिस्टम को जमा न दे। मैं ट्रैक्टर के नीचे खड़ा होकर खोलने के लिए सही पुर्ज़े ढूँढ रहा हूँ। हवा की टंकियों में जमा पानी निकालने के लिए मैं असल में कौन-सा उपकरण चलाता हूँ?","options":["सुरक्षा रिलीफ वाल्व, जिसे मैं हाथ से थोड़ा खोलकर सप्लाई (गीली) टंकी से नमी बाहर निकालता हूँ","केबिन में लगा पीला हीरे के आकार का नॉब, जिसे मैं बाहर खींचकर टंकियों से पानी छोड़ता हूँ","ड्रेन वाल्व, जिन्हें पेटकॉक भी कहते हैं, जो हर हवा की टंकी के निचले हिस्से में लगे होते हैं","हवा कंप्रेसर का गवर्नर, जिसे मैं रीसेट करता हूँ ताकि वह फँसे हुए पानी को वापस बाहर धकेल दे"],"explanation":"एयर टैंक को प्रत्येक टैंक के तल पर लगे ड्रेन वाल्व, जिन्हें पेटकॉक भी कहते हैं, से निकाला जाता है ताकि जमा पानी और तेल बाहर निकल सके।"},"146":{"q":"आप टेक्सास के एक ग्रामीण राजमार्ग पर एयर ब्रेक वाला लदा हुआ सीधा ट्रक चला रहे हैं, तभी कम-हवा चेतावनी बत्ती जल उठती है और बज़र बजने लगता है। गेज का काँटा कम दबाव वाली सीमा की ओर गिर रहा है। कौन-सा कदम सही है?","options":["घटी हुई गति पर अगले निकास तक गाड़ी चलाते रहें, क्योंकि स्प्रिंग ब्रेक अभी तक नहीं लगे हैं और आपके पास अब भी कुछ हवा बची है","गाड़ी चलाते रहें पर ब्रेक पेडल को कुछ बार दबाएँ ताकि कंप्रेसर खोया हुआ हवा का दबाव और जल्दी वापस बना सके","अपनी गति बनाए रखें और फिलहाल अलार्म को अनदेखा करें, क्योंकि चेतावनी अक्सर थोड़ी देर के लिए आती है और रेगुलेटर के चालू होते ही खुद बुझ जाती है","जैसे ही सुरक्षित हो वैसे ही रुक जाएँ और सड़क से हट जाएँ, क्योंकि दबाव का लगातार गिरना अचानक और खतरनाक ढंग से ब्रेक खोने का कारण बन सकता है"],"explanation":"जब लो-एयर चेतावनी जले और दबाव गिर रहा हो, तो जैसे ही सुरक्षित हो रुककर सड़क से हट जाएं, क्योंकि लगातार गिरावट से अचानक ब्रेक फेल हो सकते हैं।"},"147":{"q":"मैं अपने ट्रैक्टर-ट्रेलर की प्री-ट्रिप जाँच कर रहा हूँ और एक मैकेनिक बताता है कि मेरी ब्रेक (स्टॉप) लाइटें तभी जलती हैं जब मैं ब्रेक पेडल को वाकई काफी जोर से दबाता हूँ। एयर ब्रेक वाले वाहन में, उस बिजली के स्टॉप-लाइट स्विच को चालू करके ब्रेक लाइटें जलाने वाली चीज़ भौतिक रूप से क्या है?","options":["पेडल दबाने पर ब्रेक लाइनों में बढ़ता हवा का दबाव स्टॉप-लाइट स्विच को बंद (चालू) कर देता है","ब्रेक पेडल की यांत्रिक गति सीधे स्विच को दबाकर बंद कर देती है, ठीक जैसे कार में होता है","जब स्प्रिंग ब्रेक छूटना शुरू होते हैं तब होने वाली हवा के दबाव की गिरावट स्विच को बंद कर देती है","ब्रेक ड्रम पर पैदा हुई गर्मी स्विच को स्टॉप लाइटें जलाने का संकेत देती है"],"explanation":"एयर ब्रेक में स्टॉप-लाइट स्विच बिजली से चलता है और हवा से संचालित होता है; पेडल दबाने पर लाइनों में बढ़ता दबाव इसे बंद कर देता है और ब्रेक लाइट जला देता है।"},"148":{"q":"एक ठंडी सुबह सबसे पहले मैं अपने ट्रैक्टर-ट्रेलर में चढ़ता हूँ, इंजन चालू करता हूँ और स्प्रिंग (पार्किंग) ब्रेक छोड़कर निकलने की तैयारी करता हूँ। स्प्रिंग ब्रेक छोड़ने और चलाने के लिए पीली पार्किंग-ब्रेक नॉब दबाने से पहले, मेरे सिस्टम में हवा के दबाव के बारे में क्या सच होना चाहिए?","options":["कम-हवा चेतावनी लाइट और बजर अभी-अभी बंद हुआ है, इसलिए उस बिंदु से ऊपर का कोई भी दबाव छोड़कर चलाने के लिए पर्याप्त है","दबाव पहले पर्याप्त ऊँचा बनना चाहिए, यानी गवर्नर कट-आउट के पास सामान्य संचालन सीमा तक पहुँचना चाहिए, उसके बाद ही स्प्रिंग ब्रेक छोड़े जाएँ","दबाव को बस उस 20 से 45 psi सीमा से फिर ऊपर चढ़ना है जहाँ स्प्रिंग ब्रेक लगते हैं, फिर मैं छोड़कर चल सकता हूँ","दबाव को जितना हो सके उतना नीचे कर देना चाहिए ताकि स्प्रिंग ब्रेक आसानी से खुल जाएँ, फिर मैं नॉब छोड़ता हूँ"],"explanation":"स्प्रिंग ब्रेक हवा के दबाव से खुले रखे जाते हैं, इसलिए छूटने से पहले दबाव को गवर्नर कट-आउट के पास सामान्य संचालन सीमा तक बढ़ना चाहिए।"},"149":{"q":"मैं एक लदे हुए ट्रेलर को एक लंबी, खड़ी ढलान पर नीचे ले जा रहा हूँ और पूरे रास्ते मैंने ब्रेक पर बहुत ज़ोर डाला है। नीचे के पास मुझे पता चलता है कि ब्रेक ड्रम बहुत ज़्यादा गर्म हो गए हैं। इस अत्यधिक गर्मी का मेरे एयर ब्रेक पर सबसे संभावित प्रभाव क्या होगा?","options":["फैलते हुए ड्रम जूतों (shoes) पर और कसकर दबाव डालते हैं, जिससे मुझे स्पष्ट रूप से अधिक ताकतवर ब्रेकिंग मिलती है","गर्मी लाइनों में मौजूद नमी को सुखा देती है, जिससे ब्रेक तेज़ी से और अधिक मज़बूती से प्रतिक्रिया देते हैं","ब्रेक फेड (fade) हो जाएंगे: कम रोकने की शक्ति पाने के लिए मुझे लगातार ज़्यादा ज़ोर से दबाना पड़ेगा","चलते समय कुछ नहीं बदलता, लेकिन जैसे ही मैं रुककर पार्क करूंगा, गर्म ड्रम चटक जाएंगे"],"explanation":"अधिक गर्म ब्रेक ड्रम गति को ऊष्मा में बदलने की क्षमता खो देते हैं, जिससे ब्रेक फीके पड़ जाते हैं और कम रोक शक्ति के लिए आपको और जोर से दबाना पड़ता है।"},"150":{"q":"मैं राजमार्ग पर ट्रैक्टर-ट्रेलर चला रहा हूँ, तभी अचानक ट्रेलर अलग हो जाता है, उसकी एयर लाइनें टूट जाती हैं और ट्रेलर की ओर की सारी हवा निकल जाती है। कौन-सा उपकरण इसके लिए बनाया गया है कि वह मेरे ट्रैक्टर की हवा की आपूर्ति को बंद करके सुरक्षित रखे, ताकि ट्रैक्टर को नियंत्रित करने और रोकने के लिए मेरे पास पर्याप्त हवा बची रहे?","options":["रिले वाल्व, जो पेडल दबाते ही पिछले ब्रेकों तक हवा भेजकर ब्रेक लगने की गति तेज़ कर देता है","क्विक-रिलीज़ वाल्व, जो फँसी हुई हवा को तेज़ी से बाहर निकाल देता है ताकि पेडल छोड़ते ही ब्रेक तुरंत खुल जाएँ","फुट वाल्व (पेडल वाल्व), जो यह नियंत्रित करता है कि ब्रेक पेडल दबाने पर मैं कितना ब्रेकिंग हवा दबाव भेजता हूँ","ट्रैक्टर प्रोटेक्शन वाल्व, जो ट्रैक्टर की हवा की आपूर्ति को बंद कर देता है ताकि ट्रैक्टर को ब्रेक लगाने और चलाने के लिए पर्याप्त हवा बनी रहे"],"explanation":"यदि ट्रेलर अलग हो जाए या बुरी तरह रिसाव करे, तो ट्रैक्टर प्रोटेक्शन वाल्व अपने आप बंद होकर ट्रैक्टर की हवा सील कर देता है ताकि ब्रेक और स्टीयरिंग के लिए पर्याप्त हवा बची रहे।"},"151":{"q":"आपने अभी-अभी अपने ट्रैक्टर को एक भरे हुए ट्रेलर से जोड़ा है, हवा की लाइनें कनेक्ट की हैं और सिस्टम का दबाव गवर्नर कट-आउट तक बढ़ा लिया है। ट्रेलर को चलाने से पहले आप डैश पर लगे लाल, आठ-भुजाओं वाले नॉब की ओर हाथ बढ़ाते हैं। इस नॉब को अंदर दबाने (PUSH IN) से क्या होता है?","options":["यह ट्रैक्टर से ट्रेलर की ओर हवा भेजकर ट्रेलर के ब्रेक सिस्टम को हवा से भर देता है","यह ट्रेलर के स्प्रिंग (पार्किंग) ब्रेक लगा देता है ताकि ट्रेलर खड़ा रहे","यह केवल ट्रैक्टर के पार्किंग ब्रेक छोड़ता है और ट्रेलर लॉक रहता है","यह कम-हवा चेतावनी बजर का परीक्षण करने के लिए ट्रेलर की हवा की लाइनें खाली कर देता है"],"explanation":"लाल अष्टकोणीय ट्रेलर एयर सप्लाई नॉब को अंदर दबाने से सप्लाई लाइन खुलती है और ट्रैक्टर से हवा भेजकर ट्रेलर का ब्रेक सिस्टम चार्ज होता है।"},"152":{"q":"मैं एक लदा हुआ ट्रेलर खींच रहा हूँ, तभी सप्लाई लाइन में रिसाव से मेरी हवा निकलने लगती है। जैसे-जैसे गेज गिरता रहता है, मैं वह बिंदु जानना चाहता हूँ जहाँ ट्रैक्टर प्रोटेक्शन वाल्व अपने आप बंद होकर ट्रैक्टर की हवा को सील कर देगा और सिस्टम में बची हवा की रक्षा करेगा। यह स्वचालित बंद होना लगभग किस दबाव पर होता है?","options":["लगभग 60 psi पर, ठीक उसी बिंदु पर जहाँ कम हवा दबाव की चेतावनी बत्ती और बजर पहली बार चालू होते हैं","20 से 45 psi की सीमा में, जब चेतावनी कुछ समय से चल रही होती है उसके बाद","लगभग 100 psi पर, उस स्तर पर जहाँ गवर्नर कंप्रेसर को चालू होकर पंपिंग फिर से शुरू करने का संकेत देता है","लगभग 150 psi पर, उस स्तर पर जहाँ सप्लाई टैंक का सुरक्षा रिलीफ वाल्व खुलता है"],"explanation":"ट्रैक्टर प्रोटेक्शन वाल्व तब अपने आप बंद होता है जब हवा का दबाव 20 से 45 psi की सीमा में गिरता है, यानी कम-हवा चेतावनी कुछ देर चलने के बाद।"},"153":{"q":"अपनी प्री-ट्रिप जाँच में, मैं देखता हूँ कि मेरे ट्रेलर के पिछले ब्रेक चैंबर बहुत पीछे लगे हैं, केबिन में लगे फुट ब्रेक वाल्व से एयर लाइन की लंबी दूरी पर। एक प्रशिक्षु पूछता है कि हवा को इतनी अतिरिक्त दूरी तय करनी पड़ती है, फिर भी ब्रेक पेडल दबाने पर ये दूर वाले पिछले ब्रेक अगले ब्रेक की तुलना में ध्यान देने योग्य रूप से देर से क्यों नहीं लगते। सही व्याख्या क्या है?","options":["पिछले ब्रेक दूरी के कारण सचमुच धीरे लगते हैं, इसीलिए एयर ब्रेक में एयर लाइन के लंबे रास्ते की भरपाई के लिए 5 सेकंड का अंतर्निहित ब्रेक लैग इस्तेमाल किया जाता है","अगले और पिछले चैंबर एक बैलेंस वाल्व से जुड़े होते हैं जो जानबूझकर अगले ब्रेक में देरी करता है ताकि दोनों एक्सल बिल्कुल एक ही क्षण में छूटें","पिछले चैंबरों के पास लगा एक रिले वाल्व एक स्थानीय एयर सिग्नल का उपयोग करके इन ब्रेक को तेज़ी से लगाता है, बजाय इसके कि पेडल से हवा आने का इंतज़ार करे","एक स्प्रिंग ब्रेक वाल्व पीछे अतिरिक्त दबाव रोके रखता है ताकि पेडल से हवा वहाँ पहुँचने से बहुत पहले ही वे ब्रेक लग सकें"],"explanation":"पिछले चैंबरों के पास लगा रिले वाल्व स्थानीय हवा संकेत से उन ब्रेकों को लगाता है, जिससे पेडल की हवा का इंतजार किए बिना पिछला ब्रेकिंग तेज हो जाता है।"},"154":{"q":"मैं प्री-ट्रिप निरीक्षण कर रहा हूँ और देखता हूँ कि मेरे एयर-ब्रेक सिस्टम में फ्रंट एक्सल पर, ब्रेक चैंबरों के पास एक क्विक-रिलीज वाल्व (quick-release valve) लगा है। एक मैकेनिक मुझसे पूछता है कि सामान्य संचालन के दौरान यह कलपुर्जा ब्रेक के लिए वास्तव में क्या करता है। कौन-सा कथन इसका उद्देश्य सही ढंग से बताता है?","options":["यह ब्रेक चैंबरों तक हवा पहुँचने की गति को धीमा करता है ताकि ब्रेक अधिक धीरे और सहजता से लगें","यह चैंबरों में बची हुई हवा का दबाव बनाए रखता है ताकि पार्क करने के बाद स्प्रिंग ब्रेक लॉक रहें","यह लाइनों से कंप्रेसर का तेल और पानी निकालता है ताकि फ्रंट ब्रेक जमने न पाएँ","यह हवा को ब्रेक चैंबरों से जल्दी बाहर निकलने देता है, जिससे पेडल छोड़ते ही ब्रेक तेजी से रिलीज (छूट) होते हैं"],"explanation":"क्विक-रिलीज वाल्व पेडल छोड़ते ही ब्रेक चैंबरों के पास से हवा निकाल देता है, जिससे ब्रेक जल्दी छूटते हैं और घिसटते नहीं।"},"155":{"q":"मेरे खड़े ट्रक की एक स्प्रिंग-ब्रेक चैम्बर खराब हो गई है और ट्रक हिल नहीं रहा, लेकिन एक रेकर को इसे हाईवे से थोड़ी दूर खींचकर ले जाना है। ब्रेक को सामान्य तरीके से छोड़ने के लिए हवा उपलब्ध न होने पर, पहियों को मुक्त करने और यूनिट को टो करने योग्य बनाने के लिए कौन-सी कार्रवाई करनी चाहिए?","options":["प्रभावित चैम्बर पर स्प्रिंग ब्रेक को हाथ से केज करें (केजिंग बोल्ट से स्प्रिंग को यांत्रिक रूप से पीछे घुमाएँ)","उन्हें छोड़ने के लिए सिस्टम को गेज पर लगभग 125 psi तक पंप करें","स्प्रिंग छोड़ने के लिए पीले हीरे-आकार वाले पार्किंग नॉब को दबाएँ","हवा की लाइनों को काटकर अलग कर दें ताकि चैम्बर दबाव न रोक सकें"],"explanation":"स्प्रिंग ब्रेक स्प्रिंग से लगते हैं और हवा से खुले रखे जाते हैं, इसलिए चैंबर खराब होने पर टोइंग हेतु उन्हें छोड़ने का एकमात्र तरीका केजिंग बोल्ट से हाथ से केज करना है।"},"156":{"q":"गीले, फिसलन भरे राजमार्ग पर मेरे एयर-ब्रेक ट्रैक्टर में, एक अन्य चालक मुझसे कहता है कि मुझे अपने अगले पहियों के ब्रेक हटा देने या ढीले कर देने चाहिए क्योंकि वे स्टीयरिंग टायरों को फिसलाते हैं और बारिश में ट्रक को नियंत्रित करना कठिन बना देते हैं। टेक्सास CDL हैंडबुक के अनुसार, मुझे अपने अगले पहियों के ब्रेक के साथ कैसा व्यवहार करना चाहिए?","options":["गीली सड़कों पर अगले पहियों के ब्रेक हटा देने चाहिए क्योंकि स्टीयरिंग टायरों को रोकने से अगला हिस्सा फिसलता है और स्टीयरिंग पर नियंत्रण खो जाता है","अगले पहियों के ब्रेक सामान्य रूप से रुकने के लिए महत्वपूर्ण और आवश्यक हैं, और उनके कारण फिसलने का कोई खतरा नहीं है","अगले पहियों के ब्रेक केवल दिखावे के लिए उपयोगी हैं और वास्तविक रोकने की शक्ति बहुत कम जोड़ते हैं, इसलिए उन्हें कमजोर छोड़ना स्वीकार्य है","अगले पहियों के ब्रेक को असमायोजित छोड़ देना सबसे अच्छा है ताकि अधिकांश काम पिछले ब्रेक करें और अगले टायर अधिक समय तक चलें"],"explanation":"अगले पहियों के ब्रेक वास्तविक और आवश्यक रोक शक्ति देते हैं, और यह मानना कि वे स्किड कराते हैं एक मिथक है, इसलिए इन्हें हमेशा ठीक काम करना चाहिए।"},"157":{"q":"मैं एक गीले दो-लेन वाले राजमार्ग पर माल ढो रहा हूँ और रुकते समय देखता हूँ कि मेरे आगे के ब्रेक बहुत जोर लगा रहे हैं। एक अनुभवी चालक ने एक बार मुझसे कहा था कि आगे के ब्रेक हटा दूँ या उनका उपयोग न करूँ क्योंकि वे फिसलन भरी सतह पर वाहन को स्किड करा देते हैं। इस सलाह पर अमल करने से पहले, कौन सा कथन यह दर्शाता है कि टेक्सास CDL हैंडबुक वास्तव में आगे के पहियों की ब्रेकिंग के बारे में क्या कहती है?","options":["वह सही है — आगे के ब्रेक स्किड का प्रमुख कारण हैं, इसलिए जब भी सड़क गीली हो आपको उन्हें हटाए रखना चाहिए।","वह सही है, लेकिन केवल 55 मील प्रति घंटा से ऊपर — उस गति से नीचे आगे के ब्रेक सामान्य रूप से सुरक्षित रूप से उपयोग किए जा सकते हैं।","वह गलत है — यह विचार कि आगे के ब्रेक स्किड का कारण बनते हैं, झूठा है, और सबसे अच्छी ब्रेकिंग तब मिलती है जब सभी ब्रेक एक साथ काम करते हैं।","वह आंशिक रूप से सही है — आगे के ब्रेक सूखी सड़क पर ठीक हैं, लेकिन किसी भी स्थिति में रुकने की शक्ति के लिए उन पर कभी भरोसा नहीं करना चाहिए।"],"explanation":"यह धारणा कि अगले ब्रेक फिसलन पैदा करते हैं, गलत है; सबसे अच्छी और संतुलित रुकने की शक्ति तभी मिलती है जब सभी ब्रेक एक साथ काम करते हैं।"},"158":{"q":"मैं टेक्सास के एक सूखे हाईवे पर 55 मील प्रति घंटा की रफ्तार से माल ढो रहा हूँ, तभी आगे एक रुकी हुई गाड़ी दिखती है और मैं ब्रेक पेडल जोर से दबाता हूँ। मेरे प्रशिक्षक याद दिलाते हैं कि मेरे एयर ब्रेक में वास्तव में पकड़ने से पहले एक अंतर्निहित देरी होती है, इसलिए पहिए धीमे होने से पहले ही उस आधे सेकंड की देरी के दौरान ट्रक अतिरिक्त दूरी तक लुढ़कता रहता है। 55 मील प्रति घंटा पर यह ब्रेक-लैग देरी लगभग कितनी अतिरिक्त रुकने की दूरी जोड़ती है?","options":["लगभग 2 फीट, क्योंकि आधे सेकंड की देरी हाईवे की रफ्तार पर इतनी कम है कि ज्यादा मायने नहीं रखती","लगभग 300 फीट, क्योंकि यही देरी एयर ब्रेक को हाइड्रोलिक ब्रेक से कहीं धीमा रोकती है","लगभग 1 मील, क्योंकि किसी भी ब्रेकिंग के शुरू होने से पहले हवा को लाइनों के पूरे रास्ते से गुजरना पड़ता है","लगभग 32 फीट, वह दूरी जो ट्रक 55 मील प्रति घंटा पर ब्रेक-लैग के आधे सेकंड के दौरान तय करता है"],"explanation":"एयर ब्रेक में लगभग आधे सेकंड की देरी होती है, इसलिए 55 मील/घंटा पर ट्रक ब्रेक पकड़ने से पहले लगभग 32 फीट चलता है।"},"159":{"q":"मैं अपने CDL नोट्स की समीक्षा कर रहा हूँ और एयर ब्रेक की कुल रुकने की दूरी बनाने वाले चार हिस्सों में से तीन को पहले ही गिन चुका हूँ: अनुभव दूरी, प्रतिक्रिया दूरी, और ब्रेक-लैग दूरी। कुल के लिए मुझ में अभी भी कौन सा हिस्सा बाकी है?","options":["प्रभावी ब्रेकिंग दूरी, वह दूरी जो ब्रेक के सचमुच पकड़ने और वाहन को धीमा करने के बाद तय होती है","प्रभावी स्टीयरिंग दूरी, वह अतिरिक्त जगह जो ABS को पहियों को लॉक होने से रोकने के लिए चाहिए","कंप्रेसर बिल्ड-अप दूरी, जो रेगुलेटर द्वारा दबाव वापस कट-आउट तक बढ़ाते समय तय होती है","स्लैक एडजस्टर दूरी, जो ब्रेक लगाने से पहले पुशरॉड के अत्यधिक खाली घुमाव को भरते समय तय होती है"],"explanation":"एयर ब्रेक की कुल रुकने की दूरी धारणा, प्रतिक्रिया, ब्रेक-देरी और प्रभावी ब्रेकिंग दूरी का योग है, जो ब्रेक लगने के बाद तय होती है।"},"160":{"q":"मैं एक लदे हुए संयुक्त ट्रक (कॉम्बिनेशन रिग) को एक लंबी, तीखी पहाड़ी ढलान से नीचे ले जा रहा हूँ और महसूस कर सकता हूँ कि गुरुत्वाकर्षण ट्रक को तेज़ धकेल रहा है। उतराई जितनी लंबी होती जाती है, एयर ब्रेक का तापमान उतना ही बढ़ता जाता है। वाहन को नीचे तक नियंत्रण में रखने के लिए सही ब्रेकिंग तकनीक कौन-सी है?","options":["इंजन को सहज चलाने के लिए ऊँचे गियर में रहें, और गति रोकने के लिए ब्रेक पैडल को ज़ोर से और लगातार दबाए रखें","ढलान शुरू होने से पहले नीचा गियर चुनें और हल्का, स्थिर ब्रेक दबाव लगाएँ; जब गति आपकी सुरक्षित गति से लगभग 5 mph नीचे आ जाए तब ब्रेक छोड़ें और फिर दोबारा लगाएँ","ब्रेक पैडल को तेज़ी से बार-बार दबाएँ और छोड़ें ('फैन' करें) ताकि उपयोगों के बीच ब्रेक ठंडे हो सकें","इंजन बचाने के लिए न्यूट्रल में डाल दें और केवल तब हल्का ब्रेक लगाएँ जब ट्रक काबू से बाहर जाता हुआ महसूस होने लगे"],"explanation":"उतराई से पहले निचला गियर चुनें और हल्की, स्थिर ब्रेकिंग करें, अपनी सुरक्षित गति से लगभग 5 मील/घंटा नीचे आने पर छोड़ें और गति बढ़ने पर फिर लगाएं।"},"161":{"q":"मैं अपने लदे हुए ट्रक के साथ एक लंबी पहाड़ी ढलान से नीचे उतर रहा हूं। मैंने पहले ही निचला गियर लगा लिया है, और प्रशिक्षक मुझे अपनी गति नियंत्रण में रखने के लिए सही 'स्नब' (रुक-रुक कर) ब्रेकिंग का उपयोग करने को कहते हैं। निम्नलिखित में से कौन सा सही बताता है कि मुझे क्या करना चाहिए?","options":["स्थिर गति बनाए रखने के लिए मजबूत, लगातार ब्रेक दबाव डालना और पूरे ढलान भर इसे दबाए रखना","ब्रेक को तेज़ हल्के थपकों में बार-बार दबाना और छोड़ना ताकि हर बार के बीच हवा का दबाव वापस ठीक होने का समय मिल जाए","इतनी जोर से ब्रेक लगाना कि गति मेरी सुरक्षित गति से लगभग 5 mph कम हो जाए, फिर ब्रेक छोड़ देना, और जब गति फिर बढ़ने लगे तब दोबारा ब्रेक लगाना","न्यूट्रल में डालना और ब्रेक को हल्के से दबाते रहना ताकि इंजन मेरी ब्रेकिंग में बाधा न डाले"],"explanation":"स्नब ब्रेकिंग का अर्थ है सुरक्षित गति से लगभग 5 मील/घंटा नीचे लाने के लिए ब्रेक मजबूती से लगाना, पूरी तरह छोड़ना, फिर गति बढ़ने पर दोबारा लगाना।"},"162":{"q":"मैं एक लदा हुआ संयुक्त ट्रक चला रहा हूँ और मुझे आगे एक लंबी, खड़ी पहाड़ी ढलान की चेतावनी देने वाला साइन दिखता है। ढलान पर अपने एयर ब्रेक से सुरक्षित रूप से अपनी गति नियंत्रित करने के लिए, मुझे अपना गियर कब चुनना चाहिए?","options":["लगभग आधी ढलान उतरने के बाद, जब मैं महसूस कर सकूँ कि ढलान वास्तव में कितनी खड़ी है और मैं कितनी तेज़ी से गति पकड़ रहा हूँ","केवल तभी जब इंजन ज़्यादा घूमने लगे या मेरे ब्रेक कमज़ोर पड़ने लगें और मुझे सचमुच नीचे के गियर की ज़रूरत हो","नीचे के पास, जहाँ सड़क समतल हो जाती है और मैं ट्रांसमिशन पर ज़ोर डाले बिना गियर कम कर सकता हूँ","उतरना शुरू करने से पहले, जब मैं अभी भी समतल ज़मीन पर हूँ और गियरबॉक्स पर ज़ोर डाले बिना गियर बदल सकता हूँ"],"explanation":"उतरना शुरू करने से पहले, समतल जमीन पर रहते हुए ही निचला गियर चुनें, क्योंकि खड़ी ढलान पर तेज़ चलते समय गियर कम करना कठिन या असंभव होता है।"},"163":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, मैं एक ट्रैक्टर-ट्रेलर के ब्रेक जांच रहा हूं और देखता हूं कि एक पहिये के ब्रेक लाइनिंग (शू पैड) खतरनाक रूप से पतले घिस गए हैं। वाहन में बाकी सब ठीक है। DPS नियमों के अनुसार, इस वाहन को चलाने की अनुमति मिलने से पहले मुझे क्या करना चाहिए?","options":["घिसे हुए लाइनिंग बदले जाने तक वाहन को सेवा से बाहर (out of service) रखें, क्योंकि खतरनाक रूप से पतले लाइनिंग वाहन को चलाने के लिए असुरक्षित बना देते हैं।","सामान्य रूप से चलाएं लेकिन अतिरिक्त दूरी रखें, क्योंकि पतले लाइनिंग ब्रेकिंग शक्ति को केवल थोड़ा कम करते हैं।","पतले लाइनिंग को बैठाने के लिए ब्रेक पेडल को कुछ बार दबाएं, और यदि पेडल मजबूत महसूस हो तो आगे बढ़ें।","जब तक हवा रिसाव दर 3 psi प्रति मिनट से कम रहे तब तक आगे बढ़ें, क्योंकि लाइनिंग की मोटाई ब्रेक जांच का हिस्सा नहीं है।"],"explanation":"बहुत पतली हो चुकी ब्रेक लाइनिंग स्वतः ही आउट-ऑफ-सर्विस स्थिति है, इसलिए लाइनिंग बदले जाने तक वाहन नहीं चलाना चाहिए।"},"164":{"q":"यात्रा-पूर्व निरीक्षण के दौरान मैं समतल जमीन पर वाहन खड़ा करता हूँ, पहियों के नीचे रोक (चॉक) लगाता हूँ, पार्किंग ब्रेक छोड़ता हूँ और पुशरॉड के अत्यधिक संचलन की जाँच के लिए एक मैनुअल स्लैक एडजस्टर (slack adjuster) पकड़ता हूँ। मैं इसे हाथ से जोर से खींचता हूँ। ब्रेक सही ढंग से समायोजित हैं, यह निष्कर्ष निकालने से पहले इसे कितना हिलना चाहिए?","options":["समायोजन से पहले लगभग एक पूरा इंच का स्वतंत्र संचलन अधिकतम अनुमत सीमा है","हाथ से खींचने पर इसे लगभग एक इंच से कम हिलना चाहिए","लगभग छह इंच का संचलन भी सुरक्षित रूप से समायोजित ब्रेक दर्शाता है","इसे बिल्कुल भी नहीं हिलना चाहिए, क्योंकि कोई भी हलचल असमायोजन का संकेत है"],"explanation":"हाथ से जोर से खींचने पर मैनुअल स्लैक एडजस्टर की रॉड लगभग एक इंच से कम हिलनी चाहिए; अधिक खुलापन दर्शाता है कि ब्रेक एडजस्टमेंट से बाहर हैं।"},"165":{"q":"मैं एयर ब्रेक वाला एक लदा हुआ ट्रैक्टर-ट्रेलर चला रहा हूँ और एक हल्की ढलान के नीचे स्टॉप साइन की ओर बढ़ रहा हूँ। मैं देखता हूँ कि जब मैं ब्रेक पेडल दबाता हूँ, तो मेरी पिकअप के हाइड्रोलिक ब्रेक की तुलना में ब्रेक के वास्तव में पकड़ने से पहले एक छोटी देरी होती है। इस अंतर को सुरक्षित रूप से ध्यान में रखने के लिए, मुझे ब्रेक कब लगाना शुरू करना चाहिए?","options":["हाइड्रोलिक ब्रेक वाले वाहन की तरह उसी बिंदु पर, क्योंकि आधे सेकंड की देरी इतनी छोटी है कि इससे कोई फर्क नहीं पड़ता","सामान्य से थोड़ा बाद में, क्योंकि हवा का दबाव ब्रेक तक पहुँचने पर अतिरिक्त रोकने वाला बल पैदा करता है","सामान्य से थोड़ा पहले, ताकि ब्रेक के पकड़ने से पहले एयर ब्रेक की लगभग आधे सेकंड की देरी की भरपाई हो सके","केवल तब जब ट्रेलर के ब्रेक अपने आप लग जाएँ, फिर रुकने को पूरा करने के लिए पेडल पर दबाव बढ़ाएँ"],"explanation":"एयर ब्रेक की लगभग आधे सेकंड की देरी के कारण, सामान्य से थोड़ा पहले ब्रेक लगाना शुरू करें ताकि यह देरी आपकी रुकने की दूरी में न जुड़े।"},"166":{"q":"मैं एक लदे हुए संयोजन वाहन के साथ एक लंबी, खड़ी पहाड़ी ढलान पर नीचे जा रहा हूँ और निचले गियर का उपयोग करने के बजाय पूरे रास्ते ब्रेक पेडल पर हल्का, लगातार दबाव बनाए रखता हूँ। पूरे उतार के दौरान इस तरह ब्रेक को लगातार दबाए रखने से सबसे अधिक संभावना है कि मेरे ब्रेक:","options":["अधिक ठंडे रहेंगे, क्योंकि लगातार दबाव भार को सभी ड्रमों पर समान रूप से बाँट देता है","ढलान पर जितनी देर दबाए रखूँगा उतना ही बेहतर ट्रक को रोकेंगे","धीमी गति से घिसेंगे क्योंकि लाइनिंग कभी भी ड्रम से पूरी तरह अलग नहीं होती","ज़्यादा गरम होकर फेड हो जाएँगे, और नीचे पहुँचने से पहले ही मुझे ज़रूरी रोकने की शक्ति से वंचित कर देंगे"],"explanation":"लंबी ढलान पर पूरे रास्ते लगातार ब्रेक घसीटने से वे ज़्यादा गर्म होकर फेड हो जाते हैं, जिससे नीचे पहुंचने से पहले ही रुकने की शक्ति खत्म हो जाती है।"},"167":{"q":"मैंने अभी-अभी अपने एयर ब्रेक वाले सीधे ट्रक से एक बाढ़ में डूबे निचले जल-क्रॉसिंग को पार किया, और आगे सूखी सड़क पर मुझे महसूस होता है कि ब्रेक कमजोर हैं और पहली बार रोकने पर असमान रूप से पकड़ रहे हैं। गीले ब्रेक को संभालने का सही तरीका क्या है?","options":["धीमी गति से चलते रहना और हल्का, कोमल ब्रेक दबाव लगाना ताकि घर्षण की गर्मी उन्हें सुखा दे","पीली पार्किंग-ब्रेक नॉब खींचकर स्प्रिंग ब्रेक को एक मिनट तक लगाए रखना ताकि पानी निचुड़ जाए","पूरी ताकत से रेडलाइन तक गति बढ़ाना ताकि पहियों की रफ्तार लाइनिंग से पानी तेजी से उड़ा दे","ब्रेक पेडल को तेजी से कई बार पंप करना ताकि चैंबरों में फंसा पानी बाहर निकल जाए"],"explanation":"गीली ब्रेक लाइनिंग सुखाने के लिए धीमी गति से चलते हुए हल्का और स्थिर ब्रेक दबाव डालें, ताकि घर्षण की गर्मी पानी को सुखा दे और सामान्य ब्रेकिंग बहाल हो।"},"168":{"q":"सड़क बंद होने का इंतज़ार करने के लिए मैंने अपना ट्रक एक तीखी ढलान वाले किनारे पर खड़ा किया है। मैंने पार्किंग ब्रेक लगा दिया है, लेकिन मुझे चिंता है कि इस ढलान पर लंबे समय रुकने पर यह वाहन को रोक नहीं पाएगा। सुरक्षित एयर ब्रेक प्रथाओं के अनुसार, वाहन को लुढ़कने से रोकने के लिए मुझे कौन-सा अतिरिक्त कदम उठाना चाहिए?","options":["इंजन को कम गियर में चालू रखना ताकि ट्रांसमिशन भार को थामने में मदद करे","पहियों को लुढ़कने से यांत्रिक रूप से रोकने के लिए टायरों के सामने चॉक (रोक) लगाना","स्प्रिंग ब्रेक में अतिरिक्त दबाव बनाने के लिए ब्रेक पेडल को कई बार दबाना","ट्रेलर के पहियों को और कसकर बंद करने के लिए लाल अष्टकोणीय ट्रेलर एयर सप्लाई नॉब को खींचना"],"explanation":"ढलान पर पार्किंग ब्रेक धीरे-धीरे हवा खो सकते हैं, इसलिए पहियों को रोकने के लिए टायरों के सामने चॉक लगाएं।"},"169":{"q":"वॉकअराउंड निरीक्षण के दौरान, आप ब्रेक के पास किसके लिए सुनते हैं:","options":["तेज़ संगीत","एयर लीक (रिसाव)","रेडियो","पक्षियों के गीत"],"explanation":"ब्रेक के पास एयर लीक के लिए सुनें।"},"170":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं अपने ट्रैक्टर के एयर-ब्रेक घटकों की जाँच करने के लिए पहियों के पास झुका हुआ हूँ। ब्रेक ड्रम और शू की जाँच करते समय, कौन-सी स्थिति मुझे वाहन चलाने के बजाय उसे सेवा से बाहर कर देनी चाहिए?","options":["ड्रम की सतह पूरे चारों ओर चिकनी, चमकदार धातु की चमक दिखाती है","ब्रेक शू की लाइनिंग में अभी भी पर्याप्त मोटाई बची हुई है","ब्रेक ड्रम की सतह पर दरारें फैली हुई हैं","ड्रम की सतह पर सड़क की धूल और गंदगी की हल्की परत है"],"explanation":"सतह पर दरारों वाला ब्रेक ड्रम एक दोष है जो ब्रेकिंग की गर्मी और बल के कारण टूट सकता है, जिससे वाहन चलाना असुरक्षित हो जाता है।"},"171":{"q":"मैं 2015 में बने एक ट्रैक्टर की प्री-ट्रिप जाँच कर रहा हूँ। ब्रेक लाइनों का पता लगाते समय मुझे एक वाल्व मिलता है जो तेज़ ब्रेकिंग के दौरान किसी एक पहिये को लॉक होने से रोकने के लिए उस पहिये पर सेकंड में सैकड़ों बार अपने आप हवा का दबाव पल्स करके देता और छोड़ता है। एक सहकर्मी ज़ोर देकर कहता है कि यह पुर्ज़ा ट्रक की किसी बिलकुल अलग प्रणाली का हिस्सा है। यह मॉड्यूलेटर वाल्व वास्तव में किस प्रणाली का हिस्सा है?","options":["दोहरी वायु आपूर्ति प्रणाली का, क्योंकि यह प्राथमिक और द्वितीयक टैंकों के बीच हवा के दबाव को चक्रित करता है","पार्किंग ब्रेक प्रणाली का, क्योंकि यह नियंत्रित करता है कि हर पहिये पर स्प्रिंग ब्रेक कैसे लगते और छूटते हैं","सर्विस ब्रेक प्रणाली का, क्योंकि यह सीधे उस हवा को मापता है जो चालक ब्रेक पेडल से भेजता है","ABS (एंटी-लॉक ब्रेकिंग) प्रणाली का, क्योंकि मॉड्यूलेटर वाल्व दबाव को पल्स करके पहियों को लॉक होने से रोकता है ताकि आप तेज़ ब्रेकिंग के दौरान स्टीयर कर सकें"],"explanation":"जो वाल्व कठोर ब्रेकिंग के दौरान पहिये को लॉक होने से रोकने के लिए सेकंड में कई बार हवा छोड़ता है, वह ABS मॉड्युलेटर वाल्व है, जो स्टीयरिंग बनाए रखता है।"},"172":{"q":"मैं अपने ट्रैक्टर को एक ट्रेलर से जोड़ रहा हूं और मुझे दो वायु लाइनें (ग्लैडहैंड) जोड़नी हैं: सर्विस लाइन और सप्लाई/आपातकालीन लाइन। यह सुनिश्चित करने के लिए कि मैं सही सप्लाई लाइन पकड़ूं और कनेक्शन क्रॉस न करूं, मुझे सप्लाई (आपातकालीन) लाइन पर कौन सा रंग ढूंढना चाहिए?","options":["लाल","नीला","पीला","हरा"],"explanation":"ट्रेलर की आपातकालीन (सप्लाई) एयर लाइन लाल होती है, जो कैब में लाल आठ-कोनों वाले ट्रेलर एयर-सप्लाई नॉब से मेल खाती है।"},"173":{"q":"मैं अपने ट्रैक्टर को एक ट्रेलर से जोड़ रहा हूँ और दोनों इकाइयों के बीच चलने वाली दो वायु लाइनों तक पहुँचता हूँ। एक वह संकेत ले जाती है जो ब्रेक पेडल दबाने पर ट्रेलर के ब्रेक लगाती और छोड़ती है (सर्विस/कंट्रोल लाइन), और दूसरी ट्रेलर के भंडार को भरने और आपातकालीन लाइन को नियंत्रित करने के लिए लगातार हवा की आपूर्ति करती है। मुझे सर्विस ग्लैड हैंड से जोड़ने के लिए सही लाइन पकड़नी है। मुझे जिस सर्विस (कंट्रोल) लाइन की तलाश है उसे कौन सा रंग दर्शाता है?","options":["लाल लाइन, क्योंकि लाल रंग उस सर्किट को चिह्नित करता है जो मेरे पेडल से ट्रेलर तक ब्रेकिंग संकेत ले जाता है","नीली लाइन, क्योंकि नीला रंग सर्विस (कंट्रोल) लाइन को चिह्नित करता है जो ट्रेलर के ब्रेक लगाती और छोड़ती है","काली लाइन, क्योंकि अधिकांश संयोजनों में तटस्थ रंग वाली नली ही पैर के ब्रेक से जुड़ी होती है","नारंगी लाइन, क्योंकि अधिक चमकीला रंग उस नली को दर्शाता है जो ब्रेक पेडल पर प्रतिक्रिया करती है"],"explanation":"सर्विस (कंट्रोल) लाइन, जो ट्रेलर के सर्विस ब्रेक लगाने और छोड़ने के लिए ब्रेक-पेडल का संकेत भेजती है, नीली होती है।"},"174":{"q":"मैं हाईवे पर एक लदा हुआ ट्रेलर खींच रहा हूँ, तभी ट्रेलर अचानक मेरे ट्रैक्टर से अलग हो जाता है और हवा सप्लाई लाइन फट जाती है। जब ट्रेलर अपने आप खुलकर लुढ़कता है, तो ट्रेलर के ब्रेक के साथ क्या होना चाहिए?","options":["वे पूरी तरह छूटे रहते हैं, इसलिए ट्रेलर तब तक लुढ़कता रहता है जब तक घर्षण उसे धीमा न कर दे","वे तभी छूटते हैं जब मैं केबिन से लाल ट्रेलर एयर सप्लाई नॉब को खींचता हूँ","वे अपने आप लग जाते हैं क्योंकि हवा सप्लाई के खत्म होने से ट्रेलर के आपातकालीन ब्रेक चालू हो जाते हैं","वे तेज़ी से चालू-बंद होते रहते हैं, ठीक जैसे ABS सिस्टम प्रतिक्रिया करता है"],"explanation":"यदि ट्रेलर अलग हो जाए, तो हवा की आपूर्ति बंद होने से स्प्रिंग वाले आपातकालीन ब्रेक अपने आप लग जाते हैं और भागते ट्रेलर को रोक देते हैं।"},"175":{"q":"आप एक चालू ABS से लैस ट्रैक्टर-ट्रेलर चला रहे हैं, तभी एक कार आपके आगे आकर अचानक रुक जाती है। पीछे से टक्कर रोकने के लिए आप ब्रेक पेडल को पूरी ताकत से दबाते हैं। इस कठोर ब्रेकिंग के दौरान जब ABS अपना काम कर रहा है, तो आप वास्तव में क्या कर पाने की उम्मीद कर सकते हैं?","options":["पेडल को पूरा फर्श तक दबाएँ और भरोसा करें कि ABS आपकी कुल रुकने की दूरी को साफ तौर पर घटा देगा","ब्रेक पेडल को तेज़ी से बार-बार दबाएँ ताकि ABS ज़्यादा बार सक्रिय हो और सड़क पर बेहतर पकड़ बनाए","पेडल दबाए रखें पर स्टीयरिंग बिल्कुल सीधा रखें, क्योंकि कठोर ब्रेकिंग के दौरान मोड़ना ABS को निष्क्रिय कर देगा","पेडल को मज़बूती से दबाए रखते हुए स्टीयरिंग से खतरे के चारों ओर घुमाएँ, क्योंकि पहिए लॉक नहीं होंगे"],"explanation":"ABS के साथ आप ब्रेक पेडल को मजबूती से दबा सकते हैं और फिर भी खतरे से बचने के लिए स्टीयर कर सकते हैं, क्योंकि सिस्टम पहियों को लॉक होने से रोकता है।"},"176":{"q":"मैं बिना ABS वाला एक पुराना ट्रैक्टर-ट्रेलर चला रहा हूँ जब मेरे सामने एक कार अचानक रुक जाती है। मैंने पहले ही ज़ोरदार स्टैब (रुक-रुककर) ब्रेकिंग शुरू कर दी है, लेकिन नियंत्रण खोए बिना रिग को तेज़ी से रोकने के लिए मुझे एक दूसरी तकनीक चाहिए। स्टैब ब्रेकिंग के अलावा, जितनी जल्दी हो सके रुकने के लिए मुझे कौन सी विधि अपनानी चाहिए?","options":["नियंत्रित ब्रेकिंग, पहियों को लॉक हुए बिना ब्रेक को मज़बूती से लगाना","पहिया-लॉक ब्रेकिंग, पैडल को पूरी तरह दबाकर टायरों को स्किड करके रोकना","पहियों पर अधिकतम दबाव बनाए रखने के लिए पूरे रास्ते ब्रेक को तेज़ी से पंप करना","केवल इंजन ब्रेकिंग, गियर कम करके और पैडल छोड़कर ड्राइवट्रेन से धीमा होना"],"explanation":"नियंत्रित ब्रेकिंग का मतलब है पहियों को लॉक किए बिना ब्रेक को जितना हो सके उतना जोर से लगाना, क्योंकि लॉक पहिये स्किडिंग और स्टीयरिंग खोने का कारण बनते हैं।"},"177":{"q":"मैं अपने संयुक्त ट्रक का बाहरी निरीक्षण कर रहा हूँ और हाईवे पर निकलने से पहले यह पक्का करना चाहता हूँ कि ट्रेलर का ABS ठीक से काम कर रहा है। मैं जाँचने के लिए ऊपर चढ़ता हूँ, लेकिन एक सहकर्मी कहता है कि मैं ABS खराबी संकेतक को गलत जगह पर ढूँढ रहा हूँ। ट्रेलर पर मुझे वह ABS चेतावनी लैंप असल में कहाँ ढूँढना चाहिए?","options":["आगे की ओर, किंगपिन के पास, जहाँ ट्रेलर का ABS चालू और तैयार होने पर एक हरी लैंप जलती है","ट्रेलर के बाएँ पिछले हिस्से पर, जहाँ एक पीली खराबी लैंप ABS में समस्या का संकेत देती है","पिछले दरवाज़े पर, जहाँ एक लाल लैंप जलकर दिखाती है कि ट्रेलर का ABS पूरी तरह से फेल हो गया है","ट्रेलर की छत पर ऊपर, जहाँ एक नीली लैंप चालक को शीशों में दिखाई देती है"],"explanation":"ट्रेलर की ABS खराबी ट्रेलर के बाएं पिछले हिस्से पर लगी पीली बत्ती से दिखाई जाती है।"},"178":{"q":"आप I-35 हाईवे पर एक लदे हुए ट्रेलर के साथ चल रहे हैं, तभी अचानक ट्रेलर पर ABS खराबी की बत्ती जल उठती है। जो ट्रैक्टर आप चला रहे हैं वह नया है और उसका अपना ABS अब भी सामान्य रूप से काम कर रहा है। खराबी की बत्ती बताती है कि केवल ट्रेलर का ABS ही बंद हुआ है। इस यात्रा के बाकी हिस्से के लिए आप किस पर भरोसा कर सकते हैं, यह कौन सा कथन सबसे अच्छी तरह बताता है?","options":["चूंकि ट्रेलर का ABS खराब हो गया, आपने ट्रेलर के सर्विस ब्रेक खो दिए हैं और जैकनाइफ से बचने के लिए आपको तुरंत रुकना चाहिए।","चूंकि ट्रेलर का ABS खराब हो गया, अब आपकी रुकने की दूरी चेतावनी बत्ती जलने से पहले की तुलना में कम है।","चूंकि केवल ABS ही खराब हुआ है, आपके पास पूरे रिग पर सामान्य सर्विस ब्रेक अब भी हैं, लेकिन तेज ब्रेक लगाने पर ट्रेलर के पहिए अब लॉक हो सकते हैं।","चूंकि केवल ट्रेलर का ABS खराब हुआ, ट्रैक्टर का चालू ABS अपने आप ट्रेलर के पहियों का ब्रेक नियंत्रण संभाल लेगा।"],"explanation":"ABS की खराबी केवल एंटी-लॉक फंक्शन को बंद करती है, इसलिए आपके सामान्य सर्विस ब्रेक काम करते रहते हैं, पर तेज़ ब्रेकिंग में वे पहिए लॉक हो सकते हैं।"},"179":{"q":"एप्लिकेशन प्रेशर गेज दिखाता है कि आप कितनी एयर:","options":["टैंकों में संग्रहित कर रहे हैं","ब्रेक को भेज रहे हैं","रिसाव में खो रहे हैं","तेल के साथ जोड़ रहे हैं"],"explanation":"यह ब्रेक पर लगाए गए एयर प्रेशर को दिखाता है।"},"180":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान मैं देखता हूँ कि मेरे एयर-ब्रेक डैश पर एक के बजाय दो अलग-अलग दबाव सूइयाँ हैं। जैसे ही मैं इंजन चालू रखता हूँ, दोनों सूइयाँ तब तक चढ़ती हैं जब तक गवर्नर कंप्रेसर को बंद नहीं कर देता, और हर एक अपने अलग रीडिंग पर स्थिर रहती है। इन दो सूइयों की मौजूदगी मुझे इस वाहन के निर्माण के बारे में क्या बताती है?","options":["इसमें दो एयर कंप्रेसर हैं, हर एक स्वतंत्र रूप से एक सूई को हवा देता है","एक सूई सर्विस ब्रेक दिखाती है और दूसरी पार्किंग ब्रेक दिखाती है","इसमें दो गवर्नर हैं, इसलिए हर सिस्टम अलग psi पर बंद होता है","यह दोहरा एयर ब्रेक सिस्टम है: एक प्राइमरी और एक सेकेंडरी एयर सिस्टम"],"explanation":"डैश पर दो सुइयाँ दोहरी एयर ब्रेक प्रणाली दर्शाती हैं, जिसमें एक प्राथमिक और एक द्वितीयक, दो अलग-अलग एयर सिस्टम एक ही नियंत्रण साझा करते हैं।"},"181":{"q":"मैं रुक-रुक कर चलने वाले शहरी ट्रैफिक में एक लदा हुआ ट्रेलर खींच रहा हूँ, और आदतन रुकावटों के बीच तेज़ी से प्रतिक्रिया देने के लिए अपना बायाँ पैर ब्रेक पेडल पर हल्के से टिकाए रखता हूँ। मेरे प्रशिक्षक मुझे कहते हैं कि जब भी मैं वास्तव में ब्रेक नहीं लगा रहा हूँ, अपना पैर पेडल से पूरी तरह हटा लूँ। इसका वे जो मुख्य कारण बताते हैं वह क्या है?","options":["हल्का, लगातार दबाव भी ब्रेक को आंशिक रूप से लगाए रखता है, जिससे वे गरम होते हैं और समय से पहले घिस जाते हैं","पेडल पर पैर रखे रहना हवा का दबाव बहुत गिरने पर स्वचालित स्प्रिंग ब्रेक को सक्रिय होने से रोक देता है","पेडल पर टिके रहना सप्लाई टैंक से धीरे-धीरे हवा निकालता है और कम-हवा चेतावनी को जल्दी चालू कर देता है","हल्का पेडल दबाव गवर्नर को दरकिनार कर देता है और कंप्रेसर को 100 psi पर फिर से चालू होने से रोकता है"],"explanation":"पेडल पर पैर टिकाए रखने से ब्रेक हल्के लगे रहते हैं, जिससे लगातार घर्षण होता है जो लाइनिंग को अधिक गर्म कर समय से पहले घिसा देता है।"},"182":{"q":"एक मैकेनिक ने मेरे ट्रैक्टर पर रिसाव कर रहे ब्रेक चैंबर को अभी बदला है, और मैं पूरी लदी ट्रेलर के साथ वर्कशॉप के यार्ड में खड़ा हूँ और डिलीवरी पहले से देर हो रही है। हवा का गेज लगभग 125 psi दिखा रहा है और कम-हवा चेतावनी बंद है। हाईवे पर निकलने से पहले मुझे सबसे पहले क्या करना चाहिए?","options":["मैकेनिक के काम पर भरोसा करके सीधे हाईवे पर निकल जाना, क्योंकि गेज पहले से लगभग 125 psi दिखा रहा है","गाड़ी चलाने से पहले कम गति पर ब्रेक जाँचना, जिसमें लगभग 5 mph पर धीरे रोककर पुष्टि करना कि ब्रेक पकड़ते हैं और गाड़ी एक ओर नहीं खिंचती","निकल पड़ना और पहले एक मील तक ब्रेक हल्के से दबाए रखना ताकि नया चैंबर ठीक से बैठ जाए","ताज़ा मरम्मत की गई लाइन से हवा निकालने के लिए यार्ड में ब्रेक पेडल को कई बार पंप करना"],"explanation":"किसी भी ब्रेक मरम्मत के बाद आपको स्वयं ब्रेक जाँचने चाहिए, जिसमें लगभग 5 मील/घंटा पर धीमी गति से रोककर पुष्टि करें कि वे पकड़ते हैं और सीधा रुकते हैं।"},"183":{"q":"प्री-ट्रिप निरीक्षण के दौरान, मैं अपने ट्रैक्टर के नीचे रेंगकर जाता हूँ और देखता हूँ कि पिछले एक्सल पर एक स्लैक एडजस्टर में, उसी एक्सल के विपरीत पहिये वाले स्लैक एडजस्टर की तुलना में काफी अधिक फ्री प्ले (पुशरॉड ट्रैवल) है। उस एक्सल पर दोनों स्लैक एडजस्टर को किस तरह सेट किया जाना चाहिए, इसके बारे में निम्नलिखित में से कौन-सा सही है?","options":["ट्रेलर के वजन को संतुलित करने के लिए अधिक भार वाली तरफ का स्लैक एडजस्टर ढीला छोड़ देना चाहिए","दोनों के बीच फ्री प्ले में अंतर सामान्य है और यह कुछ ऐसा नहीं है जिसे मुझे ठीक करने की आवश्यकता हो","एक ही एक्सल पर दोनों स्लैक एडजस्टर एक समान सेट किए जाने चाहिए, इसलिए असमान फ्री प्ले को ठीक किया जाना चाहिए","एक को हटा देना चाहिए ताकि उस एक्सल का बचा हुआ ब्रेक सारा काम समान रूप से करे"],"explanation":"एक ही धुरी पर दोनों स्लैक एडजस्टर का फ्री प्ले समान होना चाहिए, इसलिए असमान फ्री प्ले एक खराबी है जिसे चलाने से पहले ठीक करना ज़रूरी है।"},"184":{"q":"टेक्सास की एक ठंडी सुबह अपने प्री-ट्रिप निरीक्षण के दौरान, मैं देखता हूं कि मेरे एयर ब्रेक सिस्टम में कंप्रेसर और एयर टैंकों के बीच एक एयर ड्रायर लगा है। एक मैकेनिक मुझे चेतावनी देता है कि अगर यह पुर्जा कभी खराब हो जाए, तो सर्दियों में मेरी ब्रेक लाइनों और टैंकों के जमने की संभावना बहुत अधिक होगी। एयर ड्रायर का मुख्य काम क्या है, इसके आधार पर, इसकी खराबी इस जमने की समस्या का कारण क्यों बनेगी?","options":["एयर ड्रायर लाइनों को चिकना करने के लिए थोड़ा तेल मिलाता है, और उस तेल के बिना लाइनें ठंड में जाम होकर जम जाएंगी","एयर ड्रायर संपीड़ित हवा को टैंकों तक पहुंचने से पहले गर्म करता है, इसलिए अगर यह खराब हो जाए तो ठंडी हवा सिस्टम को जमा देती है","एयर ड्रायर हवा को गवर्नर कट-आउट तक दबाव देता है, और पर्याप्त दबाव के बिना बची हुई हवा लाइनों में जम जाती है","एयर ड्रायर हवा से नमी हटाता है, इसलिए अगर यह खराब हो जाए, तो पानी टैंकों और लाइनों में जमा होकर कम तापमान में जम सकता है"],"explanation":"एयर ड्रायर संपीड़ित हवा से नमी हटाता है, इसलिए यदि यह विफल हो जाए तो टैंकों और लाइनों में पानी जमा हो जाता है और ठंड में जम सकता है।"},"185":{"q":"मैंने अभी अपना लदा हुआ ट्रेलर यार्ड में छोड़ा और बिना ट्रेलर जोड़े (बॉबटेल) अपना ट्रैक्टर शहर के दूसरी ओर चला रहा हूँ। जब लदा ट्रेलर जुड़ा था उसकी तुलना में, जब मुझे जोर से ब्रेक लगाना पड़े तो यह वाहन कैसा व्यवहार करेगा, मुझे क्या उम्मीद करनी चाहिए?","options":["इसे रोकना हैरानी की हद तक कठिन हो सकता है, इसलिए मुझे अतिरिक्त सावधानी और ज्यादा दूरी रखनी चाहिए, क्योंकि बिना ट्रेलर वाला ट्रैक्टर ब्रेक लगाने पर अलग व्यवहार करता है","यह स्पष्ट रूप से तेज़ी से और कम दूरी में रुक जाएगा, इसलिए मैं अब पहले की तुलना में दूसरे वाहनों के करीब सुरक्षित रूप से चल सकता हूँ","रुकते समय इसे किसी विशेष ध्यान की ज़रूरत नहीं, क्योंकि ट्रेलर छोड़ने से वजन हट गया और अब ब्रेक का काम आसान है","रुकते समय इसे कम स्टीयरिंग प्रयास और सुधार की ज़रूरत होगी, क्योंकि ट्रैक्टर अब कुल मिलाकर बहुत हल्का है"],"explanation":"बिना ट्रेलर वाले ट्रैक्टर (बॉबटेल) को रोकना कठिन हो सकता है क्योंकि उसके ड्राइव एक्सल पर कम वज़न और पकड़ होती है, इसलिए अतिरिक्त सावधानी और रुकने की दूरी रखें।"},"186":{"q":"ट्रिप से पहले की जाँच के दौरान मैं अपने ट्रैक्टर के नीचे रेंग रहा हूँ और मुझे पता चलता है कि एक माउंटिंग पट्टी ढीली हो जाने से एक एयर रिज़र्वायर (टैंक) अपने ब्रैकेट पर थोड़ा खिसक रहा है। इस रिग को सड़क पर ले जाने से पहले, उस एयर टैंक को माउंट करने का सही तरीका क्या है और यह क्यों मायने रखता है?","options":["लचीली पट्टियों पर ढीला, ताकि सड़क का कंपन और चेसिस का लचीलापन टैंक की वेल्डिंग में दरार न डाल सके","फ्रेम से मज़बूती से, ताकि वह अपनी जगह स्थिर रहे और लाइनों व फिटिंग पर दबाव न पड़े या वे विफल न हों","ड्रेन वाल्व ऊपर की ओर रखते हुए, ताकि जमा पानी और तेल माउंटिंग हार्डवेयर से दूर रहे","फ्रेम रेल पर ऊँचाई पर या केबिन के पीछे, ताकि टैंक आगे की ओर और ब्रेक लाइनों से दूर निकले"],"explanation":"एयर रिज़र्वायर फ्रेम पर मज़बूती से लगे होने चाहिए ताकि वे कंपन में स्थिर रहें और जुड़ी हुई लाइनें व फिटिंग्स पर दबाव या क्षति न हो।"},"187":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान मैं ट्रेलर के एक ड्रम ब्रेक को देख रहा हूँ और मुझे उस पर एक यांत्रिक ब्रेक घिसाव सूचक (wear indicator) दिखाई देता है। जब यह उपकरण अपना संकेत देता है, तो वह ब्रेक लाइनिंग (लाइनर) की स्थिति के बारे में मुझे वास्तव में क्या बता रहा है?","options":["कि लाइनिंग ने नमी सोख ली है और ब्रेक पकड़ने से पहले उन्हें सुखाना जरूरी है","कि स्लैक एडजस्टर अधिकतम अनुमत पुशरॉड ट्रैवल तक पहुँच गए हैं और उन्हें एडजस्ट करने की जरूरत है","कि लाइनिंग इतनी घिस चुकी है कि उन्हें बदलने की जरूरत है","कि लाइनिंग सही ढंग से बैठ गई हैं और ब्रेक इस यात्रा के लिए सुरक्षित हैं"],"explanation":"ब्रेक वियर इंडिकेटर यह दर्शाता है कि ब्रेक लाइनिंग कब इतनी घिस चुकी है कि उसे बदलने की आवश्यकता है।"},"188":{"q":"मैंने अभी-अभी अपने लदे हुए संयोजन वाहन के साथ एक लंबी, खड़ी पहाड़ी ढलान पूरी की है, और मैं एक विश्राम स्थल पर रुककर ब्रेक लेना चाहता हूँ। उतराई से मेरे ब्रेक बहुत गर्म हो गए हैं। निम्नलिखित में से कौन-सा सबसे अच्छा कारण है कि मुझे अभी पार्किंग (स्प्रिंग) ब्रेक नहीं लगाने चाहिए?","options":["ब्रेक गर्म रहते हुए स्प्रिंग ब्रेक लगाने से ट्रेलर की एयर सप्लाई प्रेशर 60 psi से नीचे गिर सकती है और कम-हवा चेतावनी चालू हो सकती है","गर्म ब्रेक पुशरॉड ट्रैवल बढ़ा देते हैं, इसलिए जब तक ब्रेक ठंडे नहीं होते, स्लैक एडजस्टर एडजस्टमेंट से बाहर रहेंगे","स्प्रिंग ब्रेक तभी ठीक से पकड़ते हैं जब एयर प्रेशर 20–45 psi की सीमा में गिर जाता है, जिसे गर्म ब्रेक रोक देते हैं","बहुत गर्म ब्रेक घटकों को स्प्रिंग ब्रेक से जकड़ने पर वे क्षतिग्रस्त हो सकते हैं, इसलिए पार्क करने से पहले मुझे ब्रेक को ठंडा होने देना चाहिए"],"explanation":"बहुत गर्म ब्रेकों पर स्प्रिंग (पार्किंग) ब्रेक लगाने से पुर्ज़े क्षतिग्रस्त हो सकते हैं, इसलिए लंबी ढलान के बाद पार्क करने से पहले ब्रेकों को ठंडा होने दें।"},"189":{"q":"ट्रिप-पूर्व निरीक्षण के दौरान मैंने अपने ट्रैक्टर को एक लदे हुए ट्रेलर से जोड़ा, सिस्टम को लगभग 125 psi तक चार्ज किया, इंजन बंद किया, और रिसाव की जांच के लिए ब्रेक पेडल को दबाकर रखा और डैश गेज को देखता रहा। एक पूरे मिनट में, अधिकतम कितनी हवा-दाब की गिरावट मैं देख सकता हूं और फिर भी इस रिसाव जांच को पास कर सकता हूं?","options":["4 psi","3 psi","2 psi","0 psi"],"explanation":"ब्रेक दबाए रखने पर, संयुक्त वाहन में हवा का रिसाव प्रति मिनट 4 psi से कम रहना चाहिए।"},"190":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं अपने ट्रैक्टर-ट्रेलर संयोजन पर हवा के रिसाव की जांच कर रहा हूं। इंजन बंद है, सिस्टम लगभग 125 psi तक पूरी तरह चार्ज है, और मैंने ब्रेक छोड़े हुए (RELEASED) रखे हैं (पार्किंग वाल्व बाहर खींचे हुए, पैर पेडल से हटा हुआ)। एक मिनट तक अपने गेज को देखते हुए, रिसाव के मानक से बाहर होने से पहले मुझे अधिकतम कितनी हवा की हानि की अनुमति देनी चाहिए?","options":["2 psi प्रति मिनट, क्योंकि ब्रेक छोड़े होने पर यही रिसाव सीमा है","3 psi प्रति मिनट, क्योंकि ब्रेक छोड़े हुए संयोजन वाहन में रिसाव थोड़ा अधिक हो सकता है","4 psi प्रति मिनट, क्योंकि संयोजन वाहन के लिए यही रिसाव सीमा है","जब तक कम-हवा चेतावनी चालू नहीं हुई है, तब तक कोई भी हानि स्वीकार्य है"],"explanation":"ब्रेक छोड़े जाने पर, संयुक्त वाहन प्रति मिनट 3 psi तक रिस सकता है, जो एकल वाहन से थोड़ा अधिक है।"},"191":{"q":"ट्रैक्टर-ट्रेलर पर अपनी यात्रा-पूर्व जांच के दौरान मैं इंजन बंद करता हूँ, ब्रेक छोड़ता हूँ और हवा निकालने के लिए ब्रेक पैडल को बार-बार दबाना शुरू करता हूँ। मैं डैशबोर्ड गेज देखता हूँ, यह पुष्टि करने के लिए कि कम हवा दबाव चेतावनी लाइट और बज़र काम करते हैं। टेक्सास CDL हैंडबुक के अनुसार, मेरे संयुक्त वाहन में हवा का दबाव किस स्तर से नीचे गिरने से पहले चेतावनी को चालू हो जाना चाहिए?","options":["दबाव 45 psi से नीचे गिरने से पहले — वह बिंदु जहां स्प्रिंग ब्रेक लगना शुरू होते हैं","दबाव 100 psi से नीचे गिरने से पहले — वह बिंदु जहां गवर्नर कंप्रेसर को फिर से चालू करता है","दबाव 60 psi से नीचे गिरने से पहले — ब्रेक अपनी प्रभावी रोकने की शक्ति खोने से काफी पहले","दबाव 20 psi से नीचे गिरने से पहले — वह बिंदु जहां आपातकालीन ब्रेक पूरी तरह लग जाते हैं"],"explanation":"कम हवा दबाव की चेतावनी दबाव के 60 psi से नीचे गिरने से पहले आनी चाहिए, ताकि सुरक्षित रूप से रुकने के लिए पर्याप्त हवा रहते जल्दी सचेत किया जा सके।"},"192":{"q":"मैं अपनी प्री-ट्रिप जांच कर रहा हूँ और देख रहा हूँ कि कंप्रेसर हवा पंप करते हुए वायु गेज चढ़ता जा रहा है। लगभग 125 psi पर कंप्रेसर सिस्टम में हवा जोड़ना बंद कर देता है और दबाव को वहीं बनाए रखता है। प्रशिक्षक मुझसे उस गवर्नर सेटिंग का नाम बताने को कहता है जिसने अभी कंप्रेसर का पंप करना रोका। कौन सा शब्द इस सेटिंग का सही नाम है?","options":["कट-इन (cut-in) — लगभग 100 psi पर वह सेटिंग जहाँ कंप्रेसर फिर से हवा पंप करना शुरू करता है","शट-ऑफ (shut-off) — वह सेटिंग जो इंजन फिर से चालू होने तक कंप्रेसर को पूरी तरह बंद कर देती है","स्टैंड-बाय (stand-by) — वह सेटिंग जो पार्किंग ब्रेक लगाने पर कंप्रेसर को निष्क्रिय कर देती है","कट-आउट (cut-out) — लगभग 125 psi पर वह सेटिंग जहाँ गवर्नर कंप्रेसर का हवा पंप करना रोक देता है"],"explanation":"लगभग 125 psi पर कट-आउट सेटिंग वह बिंदु है जहाँ गवर्नर कंप्रेसर को सिस्टम में और हवा पंप करने से रोकता है।"},"193":{"q":"मैं एक भरे हुए संयोजन वाहन के साथ एक लंबी पहाड़ी ढलान से नीचे उतर रहा हूँ। अपनी गति नियंत्रित करने के लिए मैं नीचे का गियर चुनता हूँ ताकि इंजन और ट्रांसमिशन मुझे रोकने का अधिकांश काम करें, और मैं केवल कभी-कभी हल्के से सर्विस ब्रेक दबाता हूँ। पूरी ढलान पर लगातार ब्रेक दबाए रखने की तुलना में, इंजन और नीचे के गियर से गति रोकने का मुख्य लाभ क्या है?","options":["सर्विस ब्रेक ठंडे रहते हैं, इसलिए ढलान के अंत में ज़ोरदार रुकने की ज़रूरत पड़ने पर वे अपनी पूरी रोकने की शक्ति बनाए रखते हैं","सर्विस ब्रेक बस इतने गर्म हो जाते हैं कि ड्रम को बेहतर पकड़ते हैं और रुकने की दूरी कम कर देते हैं","हवा का कंप्रेसर अतिरिक्त दबाव तेज़ी से बनाता है क्योंकि ढलान पर ब्रेक का उपयोग लगभग नहीं होता","स्प्रिंग (पार्किंग) ब्रेक सर्विस ब्रेक के साथ भार बाँट लेते हैं और वाहन को अपने आप धीमा कर देते हैं"],"explanation":"कम गियर इंजन को वाहन की ऊर्जा सोखने देता है, जिससे सर्विस ब्रेक ठंडे रहते हैं और कठोर रुकाव के लिए पूरी रोकने की शक्ति बनी रहती है।"},"194":{"q":"मैं एयर ब्रेक वाले लदे हुए ट्रक में एक लंबी, खड़ी ढलान से उतर रहा हूँ, और गाड़ी मेरी सुरक्षित गति से ऊपर बढ़ने लगती है। सीबी रेडियो पर एक साथी मुझे गति रोके रखने के लिए ब्रेक पेडल को बार-बार दबाने और छोड़ने की सलाह देता है। इस तरह की ढलान पर उस सलाह को मानना खतरनाक क्यों है?","options":["पेडल को बार-बार दबाने से कंप्रेसर ज़्यादा गरम हो जाता है और 150 psi पर सेफ्टी रिलीफ वाल्व खुल जाता है","पेडल को बार-बार दबाने से हवा कंप्रेसर के दोबारा भरने की तुलना में तेज़ी से निकल जाती है, जिससे दबाव गिर सकता है और आप ब्रेकिंग खो सकते हैं","पेडल को बार-बार दबाने से टैंकों से पानी और तेल बाहर निकल जाता है और ब्रेक लाइनें दूषित हो जाती हैं","पेडल को बार-बार दबाने से अतिरिक्त हवा बनती है जो चलते रहने के दौरान ही स्प्रिंग ब्रेक लगा देती है"],"explanation":"लंबी ढलान पर बार-बार ब्रेक दबाने से हवा कंप्रेसर के भरने से तेज़ निकलती है, जिससे दबाव गिरकर ब्रेकिंग खत्म हो सकती है।"},"195":{"q":"मैंने 30 मिनट के ब्रेक के लिए अपने कॉम्बिनेशन रिग को एक विश्राम क्षेत्र में खड़ा किया है। केबिन से दूर रहते हुए यूनिट को अपनी जगह पर रोके रखने के लिए, मैं ट्रेलर हैंड वाल्व तक पहुँचकर उसे लगा देता हूँ। रिग को सुरक्षित करने का यह GALAT तरीका क्यों है?","options":["हैंड वाल्व ट्रेलर के स्प्रिंग ब्रेक चालू कर देता है, जो रिग के खड़े रहने के दौरान ज़्यादा गरम होकर जाम हो सकते हैं","हैंड वाल्व लाल अष्टकोणीय ट्रेलर एयर सप्लाई नॉब को छोड़ देता है, इसलिए ट्रैक्टर अपने आप आगे खिसक जाएगा","हैंड वाल्व ट्रेलर ब्रेक पर केवल सर्विस एयर लगाता है, और वह हवा समय के साथ रिस सकती है जिससे रिग लुढ़क सकता है","हैंड वाल्व केवल स्टीयरिंग एक्सल को हवा भेजता है, इसलिए ड्राइव और ट्रेलर के पहिये पूरी तरह बिना ब्रेक के रह जाते हैं"],"explanation":"ट्रेलर हैंड वाल्व केवल सर्विस हवा लगाता है, जो समय के साथ रिसकर वाहन को लुढ़कने देती है, इसलिए हमेशा स्प्रिंग ब्रेक से पार्क करें।"},"196":{"q":"एकल ट्रैक्टर पर अपनी प्री-ट्रिप जांच के दौरान, मैं हवा प्रणाली को लगभग 125 psi तक चढ़ाता हूँ, फिर इंजन बंद करके ब्रेक छोड़ देता हूँ। मैंने पहियों को पहले ही चॉक कर दिया है और लो-एयर चेतावनी बंद है। इस चरण में इंजन बंद करने का पूरा उद्देश्य क्या है?","options":["ताकि मैं ब्रेक पैडल को कई बार दबाकर यह पुष्टि कर सकूँ कि हवा का दबाव तेजी से वापस बन जाता है","ताकि स्प्रिंग (पार्किंग) ब्रेक स्वतः लग जाएं और मैं पुष्टि कर सकूँ कि वे 20–45 psi की सीमा में सक्रिय होते हैं","ताकि मैं गीले टैंक (वेट टैंक) को इस तरह खाली कर सकूँ कि कंप्रेसर चालू होकर और अधिक तेल और पानी न पहुँचाए","ताकि कंप्रेसर हवा जोड़ना बंद कर दे और मैं दबाव की गिरावट का समय मापकर लीक दर की जांच कर सकूँ"],"explanation":"इंजन बंद करने से कंप्रेसर हवा जोड़ना रोक देता है, जिससे आप दबाव की गिरावट का समय लेकर रिसाव दर सटीक माप सकते हैं।"},"197":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मेरे प्रशिक्षक मुझसे यह समझाने को कहते हैं कि जब मैं ब्रेक पेडल दबाता हूं तो वास्तव में क्या चीज ब्रेक शू को ड्रम के खिलाफ धकेलती है। इंजन चालू है और सिस्टम पूरी तरह चार्ज है। कौन सा उत्तर उस संग्रहीत ऊर्जा के रूप का सही वर्णन करता है जिस पर मेरे ब्रेक यह काम करने के लिए निर्भर रहते हैं?","options":["टैंकों में रखी संपीड़ित हवा, जो ब्रेक लगाने के लिए छोड़ी जाती है","मास्टर सिलेंडर द्वारा दबाव में लाया गया हाइड्रोलिक द्रव, जैसे कार के ब्रेक","बैटरी से प्रत्येक पहिये पर लगे चुंबकों को भेजी गई विद्युत धारा","स्नेहन प्रणाली से ब्रेक की ओर भेजा गया इंजन तेल का दबाव"],"explanation":"एयर ब्रेक सिस्टम ऊर्जा को टैंकों में संपीड़ित हवा के रूप में संग्रहीत करता है, जिसे ब्रेक लगाने के लिए छोड़ा जाता है।"},"198":{"q":"अपने प्री-ट्रिप निरीक्षण के दौरान, मैं इंजन चालू करता हूँ और डैश गेज देखता हूँ। मेरे डुअल एयर सिस्टम को आवश्यक 45 सेकंड में 85 से 100 psi तक पहुँचने में बहुत अधिक समय लग रहा है, और दबाव बहुत धीमे-धीमे ऊपर चढ़ रहा है। निम्नलिखित में से, इस धीमे दबाव-निर्माण का सबसे संभावित कारण क्या है?","options":["कम वायुदाब चेतावनी बजर बहुत जल्दी, 60 psi से नीचे ही बज रहा है","खराब एयर कंप्रेसर या सिस्टम में कहीं वायु रिसाव (लीक)","गवर्नर कट-आउट बहुत ऊँचा सेट है, 150 psi की रिलीफ सेटिंग के पास","स्लैक एडजस्टर में बहुत अधिक पुशरॉड ट्रैवल और फ्री प्ले है"],"explanation":"हवा का दबाव जो 45 सेकंड में 85-100 psi तक पहुँचने के लिए बहुत धीमे बढ़े, वह खराब कंप्रेसर या सिस्टम में रिसाव की ओर इशारा करता है।"},"199":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, जब इंजन चल रहा है और कंप्रेसर हवा बना रहा है, तब मुझे सप्लाई (गीले) टैंक पर लगे सेफ्टी रिलीफ वाल्व से तेज आवाज के साथ हवा निकलने की सीटी सुनाई देती है। निम्न में से, यह वाल्व टैंकों को विशेष रूप से किस स्थिति से बचाने के लिए बनाया गया है?","options":["दबाव 60 psi से नीचे गिरने से पहले कम वायु दबाव चेतावनी का चालू न होना","दबाव लगभग 100 psi तक गिरने पर गवर्नर (रेगुलेटर) द्वारा कंप्रेसर को फिर से चालू न करना","सिस्टम में वायु दबाव बहुत अधिक बढ़ जाना; यह वाल्व लगभग 150 psi पर खुलने के लिए सेट होता है","कंप्रेसर द्वारा 45 सेकंड में दबाव को 85 से 100 psi तक न बढ़ा पाना"],"explanation":"सप्लाई टैंक का सेफ्टी रिलीफ (पॉप-ऑफ) वाल्व सिस्टम को अत्यधिक वायु दबाव से बचाने के लिए लगभग 150 psi पर खुलता है।"},"200":{"q":"मैं अपनी निजी पिकअप, जिसमें हाइड्रॉलिक ब्रेक हैं, से एयर ब्रेक सिस्टम वाले क्लास B ट्रक पर जा रहा हूँ। प्री-ट्रिप जाँच के दौरान, मैं यह समझने की कोशिश कर रहा हूँ कि वास्तविक रोकने वाला बल प्रत्येक पहिये के ब्रेक तक कैसे पहुँचता है, इसमें मूलभूत अंतर क्या है। कौन-सा कथन सही ढंग से बताता है कि मेरे एयर ब्रेक वाहन में ब्रेक लगाने वाले बल को भौतिक रूप से क्या संचारित करता है?","options":["मास्टर सिलेंडर में हाइड्रॉलिक द्रव को और अधिक दबाव में लाया जाता है, फिर शूज़ को दबाने के लिए ब्रेक चैंबरों में भेजा जाता है","इंजन ऑयल का दबाव बढ़ता है और स्लैक एडजस्टरों को ड्रम के विरुद्ध धकेलने के लिए ब्रेक लाइनों से होकर भेजा जाता है","ब्रेक पेडल से एक विद्युत संकेत प्रत्येक पहिये पर लगे चुंबकों को ऊर्जा देता है जो ब्रेक शूज़ को बाहर की ओर खींचते हैं","टैंकों में संग्रहित और पेडल द्वारा छोड़ी गई संपीड़ित हवा, लाइनों से होकर यात्रा करती है और ब्रेक चैंबरों में बल लगाती है"],"explanation":"एयर ब्रेक टैंकों में जमा संपीड़ित हवा का उपयोग करते हैं, जो पेडल दबाने पर लाइनों के जरिए ब्रेक चैंबरों तक जाकर ब्रेकिंग बल लगाती है।"},"201":{"q":"मैं अभी-अभी हाइड्रॉलिक ब्रेक वाली एक पिकअप से एयर ब्रेक वाले ट्रैक्टर-ट्रेलर पर आया हूँ। जब मैं पहली बार ब्रेक पैडल ज़ोर से दबाता हूँ, तो मुझे पता चलता है कि ट्रक मेरा पैर हिलते ही धीमा होना शुरू नहीं करता, जैसा मेरी पुरानी पिकअप करती थी। एयर ब्रेक और हाइड्रॉलिक ब्रेक के बीच इस अंतर को कौन सा कथन सबसे अच्छी तरह समझाता है?","options":["एयर ब्रेक में लगभग आधे सेकंड की अंतर्निहित देरी होती है, क्योंकि ब्रेक लगने से पहले हवा को लाइनों में से होकर यात्रा करनी पड़ती है।","जब तक सिस्टम 125 psi का गवर्नर कट-आउट दबाव नहीं छू लेता, तब तक एयर ब्रेक बिलकुल भी रोकने की शक्ति नहीं देते।","एयर ब्रेक हाइड्रॉलिक की तरह तुरंत प्रतिक्रिया करते हैं, इसलिए मुझे जो देरी महसूस हुई वह केवल घिसे हुए, असमायोजित स्लैक एडजस्टर के कारण थी।","एयर ब्रेक में पैडल फीडबैक नहीं होता, इसलिए धीमा होना वास्तव में तुरंत शुरू हो गया था, चाहे मैं इसे महसूस नहीं कर पाया।"],"explanation":"एयर ब्रेक में लगभग आधे सेकंड की देरी होती है क्योंकि ब्रेक लगने से पहले हवा को लाइनों से होकर गुजरना पड़ता है।"},"202":{"q":"यदि गाड़ी चलाते समय एयर प्रेशर (हवा का दबाव) गिर जाता है, तो आप सबसे पहले क्या देख सकते हैं:","options":["रेडियो बंद हो जाना","लो एयर वार्निंग (कम हवा की चेतावनी)","दरवाज़ा खुल जाना","सीट पीछे खिसक जाना"],"explanation":"लो एयर वार्निंग (कम हवा की चेतावनी) आपको सबसे पहले सचेत करती है।"},"203":{"q":"आप टेक्सास के एक ग्रामीण हाईवे पर माल ढो रहे हैं, तभी कम हवा दबाव की चेतावनी बत्ती जलती है और बज़र बजने लगता है। लगभग 19 किलोमीटर आगे एक ट्रक स्टॉप है जहाँ आप जानते हैं कि एक मैकेनिक ड्यूटी पर है। नीचे दिए गए कार्यों में से एक को छोड़कर बाकी सभी इस चेतावनी के प्रति असुरक्षित प्रतिक्रियाएँ हैं। सही कार्य कौन-सा है?","options":["हाईवे की गति बनाए रखें और 19 किलोमीटर आगे ट्रक स्टॉप तक चलते रहें ताकि मैकेनिक सिस्टम की जाँच कर सके","धीरे-धीरे ब्रेक लगाकर गति घटाएँ और जितनी जल्दी हो सके वाहन को सड़क से हटाकर सुरक्षित रूप से रोक दें","टैंकों में दबाव फिर से बनाने के लिए ब्रेक पेडल को बार-बार दबाएँ और सामान्य रूप से गाड़ी चलाते रहें","चलते रहें लेकिन अभी पार्किंग ब्रेक नॉब खींच लें ताकि स्प्रिंग ब्रेक बाद में रुकने में मदद करें"],"explanation":"लो एयर चेतावनी आने पर धीरे से ब्रेक लगाएं और स्प्रिंग ब्रेक अपने आप लगने से पहले वाहन को सड़क से हटाकर सुरक्षित रूप से रोकें।"},"204":{"q":"आप अपने एयर-ब्रेक वाले सीधे ट्रक में लाल बत्ती पर रुकते हैं। कम हवा की चेतावनी वाली लाइट और बज़र चालू हैं, और डैश गेज दिखाता है कि दबाव सामान्य ऑपरेटिंग सीमा से काफी नीचे गिर गया है। बत्ती हरी हो जाती है और पीछे वाले हॉर्न बजाने लगते हैं। सही कार्रवाई क्या है?","options":["चौराहे से धीरे-धीरे आगे बढ़ें, क्योंकि स्प्रिंग ब्रेक केवल 20 psi पर ही लॉक होते हैं और आप अभी उससे ऊपर हैं","जब तक प␇िए घुमाने लायक हवा बची है, तब तक तेज़ी से लेन बदलकर किनारे की पट्टी पर चले जाएँ","रुके रहें और जब तक हवा का दबाव वापस सामान्य सीमा में न आ जाए, तब तक ट्रक को न चलाएँ","चलने से पहले कंप्रेसर को टैंक तेज़ी से भरने में मदद करने के लिए ब्रेक पेडल को हल्के से कुछ बार दबाएँ"],"explanation":"लो-एयर चेतावनी जलने का मतलब है कि ब्रेकिंग अब भरोसेमंद नहीं है, इसलिए वायु दबाव सामान्य सीमा में लौटने तक रुके रहें।"},"205":{"q":"मैं एक लदा हुआ कॉम्बिनेशन वाहन एक लंबी, तीव्र ढलान पर नीचे की ओर चला रहा हूँ और आधे रास्ते में मुझे लगता है कि ब्रेक पेडल नरम पड़ रहा है और दबाने पर ट्रक मुश्किल से धीमा हो रहा है। मेरे ब्रेक साफ़ तौर पर फेड हो रहे हैं (कमज़ोर पड़ रहे हैं)। निम्नलिखित में से मेरे लिए सबसे अच्छा कदम कौन-सा है?","options":["खोई हुई ब्रेकिंग शक्ति की भरपाई के लिए ब्रेक पेडल को और ज़ोर से दबाना और ढलान के अंत तक लगातार दबाव बनाए रखना","पेडल का एहसास वापस लाने और खोई हुई रोकने की शक्ति बहाल करने के लिए ब्रेक पेडल को तेज़ी से पंप करना","ऊँचे गियर में बदलना ताकि इंजन स्वतंत्र रूप से घूमे और ट्रक ढलान के अंत तक आसानी से लुढ़कता रहे","इंजन ब्रेकिंग के लिए निचले गियर में बदलना और ट्रक को किनारे लगाकर रोकने के लिए निकटतम सुरक्षित जगह ढूँढना"],"explanation":"लंबी ढलान पर एयर ब्रेक कमजोर पड़ने लगें तो इंजन ब्रेकिंग के लिए नीचे के गियर में डालें और रुकने के लिए निकटतम सुरक्षित जगह पर साइड में हट जाएं।"},"206":{"q":"मैंने अपने लदे हुए ट्रैक्टर-ट्रेलर को हल्की ढलान पर खड़ा किया और पीले नॉब से पार्किंग ब्रेक लगा दिया। जब मैं कागजी काम कर रहा हूँ, इंजन बंद है और टैंकों में हवा का दबाव धीरे-धीरे 45 psi से नीचे शून्य की ओर गिर रहा है। मेरे रिग को लुढ़कने से असल में क्या रोक रहा है, और हवा निकल जाने पर भी यह कैसे पकड़ बनाए रखता है?","options":["ब्रेक चैंबरों में शक्तिशाली स्प्रिंग ब्रेक को यांत्रिक रूप से जकड़ लेते हैं, इसलिए हवा निकलने पर भी रोकने वाला बल बना रहता है","ब्रेक चैंबरों के अंदर दबाव में फँसी हवा जूतों को ड्रम से दबाए रखती है","इंजन और ट्रांसमिशन बंद होने के बाद कंप्रेशन के ज़रिए पहियों को थामे रखते हैं","पीला नॉब पेडल बल बनाए रखने के लिए फुट-वाल्व लिंकेज को यांत्रिक रूप से दबाकर लैच कर देता है"],"explanation":"पार्किंग और इमरजेंसी ब्रेक स्प्रिंग ब्रेक चैंबरों में लगे शक्तिशाली स्प्रिंगों द्वारा लगे रहते हैं, इसलिए हवा निकल जाने पर भी वे पकड़े रहते हैं।"},"207":{"q":"मैं हाईवे पर चल रहा हूँ, मेरा एयर सिस्टम सामान्य संचालन दबाव पर पूरी तरह चार्ज है, और मुझे लगता है कि स्प्रिंग ब्रेक न तो घिस रहे हैं और न ही लग रहे हैं। इस स्थिति में होल्ड-ऑफ दबाव की भूमिका को कौन-सा कथन सही ढंग से समझाता है?","options":["होल्ड-ऑफ दबाव स्प्रिंग ब्रेक को आंशिक रूप से दबाए रखता है ताकि पेडल दबाने पर वे तेज़ी से प्रतिक्रिया दें।","होल्ड-ऑफ दबाव मेरे गाड़ी चलाते समय स्प्रिंग ब्रेक को रिलीज़ (छूटा हुआ) रखता है, इसलिए जब तक हवा बहुत कम न हो जाए, वे बंद ही रहते हैं।","होल्ड-ऑफ दबाव स्प्रिंग ब्रेक को हर समय पूरी तरह लगाए रखता है ताकि मेरे सर्विस ब्रेक का बैकअप बने।","होल्ड-ऑफ दबाव चैम्बरों से पूरी तरह हटा दिया गया है, इसी कारण स्प्रिंग ब्रेक बंद महसूस होते हैं।"],"explanation":"होल्ड-ऑफ वायु दबाव स्प्रिंगों को दबाकर गाड़ी चलाते समय स्प्रिंग ब्रेक को रिलीज रखता है, और हवा बहुत कम होने पर ही ये लगते हैं।"},"208":{"q":"अपनी शिफ्ट के अंत में मैं अपना ट्रक पार्क करता हूँ, इंजन बंद करता हूँ, और जैसे ही हवा निकलती है, स्प्रिंग ब्रेक पहियों को जकड़ लेते हैं। एक प्रशिक्षु पूछता है कि ट्रक को रोके रखने के लिए मैंने एयर सिस्टम के किस ब्रेकिंग कार्य पर भरोसा किया। कौन-सा उत्तर सही है?","options":["सर्विस ब्रेकिंग कार्य, क्योंकि इंजन बंद होने पर पार्क किए गए वाहन को फुट पेडल ही रोके रखता है","मॉड्युलेटिंग कार्य, क्योंकि हवा का दबाव 60 psi से नीचे गिरने पर स्प्रिंग ब्रेक धीरे-धीरे लगते हैं","पार्किंग/आपातकालीन कार्य, क्योंकि हवा का दबाव खत्म होने पर स्प्रिंग ब्रेक स्वतः लग जाते हैं और वाहन को रोके रखते हैं","कम-हवा चेतावनी कार्य, क्योंकि बजर और बत्ती ही पहियों को भौतिक रूप से जकड़ते हैं"],"explanation":"वायु दबाव खोने पर स्प्रिंग ब्रेक वाहन को रोके रखने के लिए अपने आप लग जाते हैं, जो पार्किंग/इमरजेंसी फंक्शन है।"},"209":{"q":"निरीक्षण के दौरान सुनाई देने वाले लीक (रिसाव) का मतलब है:","options":["सब कुछ ठीक है","हवा बाहर निकल रही है","अधिक ब्रेकिंग शक्ति","अब बेहतर ब्रेक"],"explanation":"सिसकारी (हिसिंग) वाला लीक का मतलब है कि हवा बाहर निकल रही है।"},"210":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, मैं हुड खोलता हूं और देखता हूं कि मेरा एयर कंप्रेसर इंजन से सीधे जुड़े होने के बजाय एक बेल्ट से चालित है। चूंकि यह बेल्ट-चालित है, मुझे विशेष रूप से किस अतिरिक्त वस्तु का निरीक्षण करना चाहिए जिसे मुझे गियर-चालित कंप्रेसर पर जांचने की आवश्यकता नहीं होगी?","options":["कि गवर्नर कट-आउट दबाव गेज पर लगभग 125 psi दिखाता है","कि एयर टैंकों से पानी और कंप्रेसर तेल निकाल दिया गया है","कि कम वायु दबाव चेतावनी लाइट 60 psi से नीचे गिरने से पहले जल जाती है","कि ड्राइव बेल्ट ठीक से कसा हुआ है और घिसाव के लक्षण नहीं दिखा रहा है"],"explanation":"बेल्ट-चालित कंप्रेसर पर जांचें कि ड्राइव बेल्ट सही तरह से कसी हो और घिसी न हो, क्योंकि गियर-चालित कंप्रेसर में बेल्ट नहीं होती।"},"211":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं देखता हूं कि ट्रेलर के नीचे लगा एक एयर स्टोरेज टैंक अब अपने माउंटिंग ब्रैकेट से कसकर नहीं जुड़ा है और जब मैं उसे धक्का देता हूं तो वह हिलता है। यह ढीला टैंक एक ऐसा दोष क्यों है जिसे मुझे गाड़ी चलाने से पहले ठीक करना चाहिए?","options":["टैंक वाहन के हिस्सों से रगड़ सकता है या ढीला होकर ट्रक से गिर सकता है","टैंक कंप्रेसर से अतिरिक्त हवा खींचेगा और गवर्नर को समय से पहले कट-आउट करने पर मजबूर करेगा","टैंक कम संपीड़ित हवा रोकेगा, इसलिए मेरी कम वायु दबाव चेतावनी जल्दी बजेगी","टैंक पानी और तेल को खुद ही निकाल देगा, जिससे रोज़ निकालने के लिए कुछ नहीं बचेगा"],"explanation":"ढीला एयर टैंक कंपन करके वाहन के पुर्जों से रगड़ सकता है या ढीला होकर ट्रक से गिर सकता है।"},"212":{"q":"आपने अपने एयर-ब्रेक वाले सीधे (स्ट्रेट) ट्रक को फ्यूल आइलैंड पर समतल, पक्की ज़मीन पर खड़ा किया है और इंजन बंद कर दिया है। गेज सिस्टम में पूरा दबाव दिखा रहे हैं और आप ईंधन भरना शुरू करने के लिए केबिन से बाहर निकलने वाले हैं। केबिन छोड़ने से पहले आपको कौन-सा काम अवश्य पूरा करना चाहिए?","options":["ट्रक को सबसे नीची आगे वाली गियर में छोड़ दें और रोके रखने के लिए इंजन कम्प्रेशन पर भरोसा करें","पार्किंग (स्प्रिंग) ब्रेक लगाने के लिए पीले, हीरे के आकार वाले नॉब को बाहर खींचें","सर्विस ब्रेक पैडल पर पैर से लगातार और मज़बूत दबाव बनाए रखकर ट्रक को रोके रखें","ट्रेलर की हवा आपूर्ति लाइन को बंद करने के लिए लाल, अष्टभुज आकार वाले नॉब को बाहर खींचें"],"explanation":"केबिन से निकलने से पहले हमेशा पीली हीरे के आकार वाली नॉब खींचकर पार्किंग (स्प्रिंग) ब्रेक लगाएँ।"},"213":{"q":"मैं एक नया ड्राइवर हूँ और दो पुराने ट्रकों के बीच फैसला कर रहा हूँ: एक भारी ट्रैक्टर-ट्रेलर जो अपने अधिकतम सकल वजन के करीब भार ढो सकता है, और एक हल्की डिलीवरी वैन। एक मैकेनिक मुझे बताता है कि बड़ा ट्रक एयर ब्रेक का उपयोग करता है जबकि वैन हाइड्रोलिक ब्रेक का। मैं समझना चाहता हूँ कि भारी वाणिज्यिक वाहनों को सबसे पहले एयर ब्रेक के साथ क्यों बनाया जाता है। कौन-सा कथन सबसे अच्छी तरह समझाता है कि एयर ब्रेक बड़े, भारी लदे ट्रकों के लिए मानक विकल्प क्यों हैं?","options":["एयर ब्रेक ट्रक की कुल रुकने की दूरी को कम कर देते हैं, इसलिए पूरी तरह लदा हुआ ट्रक हाइड्रोलिक ब्रेक की तुलना में कम जगह में रुक सकता है","एयर ब्रेक मुख्य रूप से इसलिए चुने जाते हैं क्योंकि वे लगाने के लिए सबसे सस्ती ब्रेक प्रणाली हैं और उनके टैंकों को कभी निकालने या रखरखाव की आवश्यकता नहीं होती","एयर ब्रेक एक निश्चित मात्रा के तरल के बजाय संपीड़ित हवा का उपयोग करते हैं, इसलिए वे भारी भार ढोने वाले बड़े वाहनों पर भी प्रभावी ढंग से काम करते रहते हैं","एयर ब्रेक ब्रेक लैग को पूरी तरह समाप्त कर देते हैं, जिससे लदा हुआ ट्रक पेडल दबाते ही उसी क्षण प्रतिक्रिया करता है, लाइनों में कोई देरी नहीं होती"],"explanation":"एयर ब्रेक तरल की निश्चित मात्रा के बजाय लगातार भरी जाने वाली संपीड़ित हवा का उपयोग करते हैं, इसलिए वे भारी, पूरी तरह लदे वाहनों पर भी प्रभावी ढंग से ब्रेक लगाते हैं।"},"214":{"q":"मैं एक ढलान पर खड़ा हूँ और सर्विस ब्रेक पेडल को अब भी ज़ोर से दबाए रखते हुए पीली पार्किंग-ब्रेक नॉब खींचने (स्प्रिंग ब्रेक लगाने) का फैसला करता हूँ। मेरे बगल का एक चालक मुझे चेतावनी देता है कि पहले पेडल छोड़ दूँ। सर्विस ब्रेक और स्प्रिंग ब्रेक को एक साथ ज़ोर से लगाना समस्या क्यों है?","options":["इससे कोई नुकसान नहीं होता और असल में यह मुझे अतिरिक्त पकड़ शक्ति देता है, इसलिए पहले सर्विस पेडल छोड़ने की कोई वजह नहीं है","इससे कम हवा दबाव चेतावनी 60 psi बिंदु से नीचे जल्दी चालू हो जाती है और सप्लाई टैंक तेज़ी से खाली होता है","यह बहुत सारी हवा बचाता है क्योंकि एक साथ लगाने पर दोनों प्रणालियाँ एक ही संग्रहीत दबाव साझा करती हैं","ब्रेकिंग बल आपस में मिलकर जुड़ जाते हैं, और यह संयुक्त बल ब्रेक के पुर्ज़ों पर बहुत अधिक दबाव डालकर उन्हें नुकसान पहुँचा सकता है"],"explanation":"स्प्रिंग ब्रेक लगे होने पर सर्विस ब्रेक जोर से दबाने से दोनों बल मिल जाते हैं, जिससे अत्यधिक दबाव पड़ता है और ब्रेक के पुर्जे क्षतिग्रस्त हो सकते हैं।"},"215":{"q":"मैं अपना ट्रक पार्क कर रहा हूँ और स्प्रिंग (पार्किंग) ब्रेक लगाने के लिए पीली नॉब बाहर खींचता हूँ। आदतवश मेरा पैर अब भी ब्रेक पेडल पर ज़ोर से दबा है, इसलिए उसी समय उन्हीं ब्रेक चैंबरों में हवा का दबाव भी भेजा जा रहा है। मैकेनिक ने चेतावनी दी कि एक खास वाल्व के बिना, दोनों बलों को एक साथ लगाने से वे जुड़कर ब्रेक को नुकसान पहुँचा सकते हैं। इस संयुक्त, 'डबल-अप्लाई' बल से कौन-सा वाल्व बचाता है?","options":["एंटी-कंपाउंडिंग वाल्व, जो स्प्रिंग-ब्रेक बल और हवा-अनुप्रयोग बल को एक ही ब्रेक पर जुड़ने से रोकता है","मॉड्युलेटिंग कंट्रोल वाल्व, जो आपको स्प्रिंग ब्रेक धीरे-धीरे लगाने देता है ताकि दोनों बल कभी न मिलें","सेफ्टी रिलीफ वाल्व, जो लगभग 150 psi पर खुलकर डबल अनुप्रयोग से बने अतिरिक्त दबाव को निकालता है","ट्रेलर एयर सप्लाई वाल्व, लाल अष्टकोणीय नॉब जो दोनों लगने पर पिछले ब्रेक की हवा काट देती है"],"explanation":"एंटी-कंपाउंडिंग वाल्व स्प्रिंग ब्रेक लगे होने पर हवा-अनुप्रयोग दबाव छोड़ देता है ताकि दोनों ब्रेकिंग बल आपस में न जुड़ें।"},"216":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, मैं एक ट्रैक्टर-ट्रेलर पर एयर ब्रेक की जाँच कर रहा हूँ। मैं उस उपकरण की पुष्टि करना चाहता हूँ जिसका मुझे उसी क्षण सचेत करना अनिवार्य है जब सिस्टम का वायु दाब बहुत कम हो जाए (इससे पहले कि वह 60 psi से नीचे गिरे), ताकि मैं तब रुक सकूँ जब मेरे पास अभी भी ब्रेकिंग क्षमता हो। यह चेतावनी देने के लिए सिस्टम को कौन-सी सुविधा का उपयोग करना अनिवार्य है?","options":["वायु दाब गेज जो धीरे-धीरे नीचे गिर रहा हो, जिसे पूरी यात्रा के दौरान मुझसे ध्यान से देखते रहने की अपेक्षा की जाती है","एक चेतावनी बत्ती और/या एक बज़र जो दाब के 60 psi से नीचे गिरने से पहले सक्रिय हो जाती है","स्प्रिंग (पार्किंग) ब्रेक जो मुझे शारीरिक रूप से रुकने के लिए मजबूर करने हेतु स्वतः लग जाते हैं","सुरक्षा रिलीफ वाल्व जो दाब बहुत कम होते ही तेज़ सीटी की आवाज़ के साथ हवा छोड़ता है"],"explanation":"एयर ब्रेक वाहन में कम हवा दबाव की चेतावनी रोशनी, और आमतौर पर एक बजर, होना चाहिए जो दबाव 60 psi से नीचे गिरने से पहले सक्रिय हो जाए।"},"217":{"q":"पूरी चार्जिंग के बाद मैं एक ट्रक स्टॉप पर निष्क्रिय (आइडल) खड़ा होकर अपना एयर प्रेशर गेज देख रहा हूँ। सुई लगातार चक्र लगाती रहती है: यह ऊपर चढ़ती है, गवर्नर कंप्रेसर को बंद कर देता है, सुई धीरे-धीरे थोड़ी नीचे आती है, फिर गवर्नर कंप्रेसर को दोबारा चालू करके दबाव बढ़ा देता है। मैं पुष्टि करना चाहता हूँ कि मेरा एयर कंप्रेसर माँग के साथ बना रहा है। कौन-सा गेज व्यवहार बताता है कि कंप्रेसर अपना काम कर रहा है?","options":["गेज 150 psi से ऊपर चढ़ता रहता है और सेफ्टी रिलीफ वाल्व हवा छोड़ता है, जो साबित करता है कि कंप्रेसर के पास भरपूर अतिरिक्त क्षमता है","गेज धीरे-धीरे पूरी तरह शून्य तक गिर जाता है, फिर कंप्रेसर एक तेज़ झटके में सिस्टम को दोबारा भर देता है","सुई सामान्य कार्यशील सीमा के भीतर रहती है, और जैसे-जैसे दबाव इस्तेमाल होता और फिर से भरता है, यह गवर्नर के कट-इन और कट-आउट के बीच चक्र लगाती रहती है","गेज एक निश्चित psi मान पर बिल्कुल स्थिर रहता है और कभी नहीं हिलता, जो दिखाता है कि गवर्नर ने सिस्टम का दबाव अपनी जगह लॉक कर दिया है"],"explanation":"ठीक काम करने वाला कंप्रेसर दबाव को सामान्य सीमा में रखता है, हवा के उपयोग और पुनःपूर्ति के साथ गवर्नर कट-आउट (लगभग 125 psi) और कट-इन (लगभग 100 psi) के बीच चक्र करता रहता है।"},"218":{"q":"यदि आप ब्रेक दबाते हैं और प्रेशर (दबाव) बहुत गिर जाता है, तो हो सकता है:","options":["अधिक ब्रेकिंग शक्ति","एक लीक (रिसाव)","अब बेहतर पकड़","कोई समस्या नहीं"],"explanation":"प्रेशर (दबाव) में बड़ी गिरावट का मतलब लीक (रिसाव) हो सकता है।"},"219":{"q":"मैं एक अकेले ट्रैक्टर पर अपनी यात्रा-पूर्व जाँच कर रहा हूँ और हवा बनाने के लिए इंजन को निष्क्रिय (आइडल) चलने देता हूँ। निकलने से पहले मैं सिस्टम को पूरी तरह चार्ज करना चाहता हूँ, इसलिए मैं डैश पर लगे गेज को बढ़ते हुए देखता हूँ और कंप्रेसर गवर्नर के कट-आउट होकर हवा पंप करना बंद करने का इंतज़ार करता हूँ। लगभग किस दबाव पर मुझे ऐसा होने की उम्मीद करनी चाहिए?","options":["लगभग 100 psi, वह बिंदु जहाँ गवर्नर कट-इन होकर फिर से हवा पंप करना शुरू करता है","लगभग 60 psi, जहाँ कम हवा दबाव की चेतावनी बत्ती और बज़र बंद हो जाते हैं","लगभग 150 psi, जहाँ अतिरिक्त हवा निकालने के लिए सुरक्षा रिलीफ वाल्व खुलता है","लगभग 125 psi, जहाँ गवर्नर कट-आउट होता है और कंप्रेसर हवा पंप करना बंद कर देता है"],"explanation":"पूरी तरह चार्ज सिस्टम गवर्नर कट-आउट दबाव पर, लगभग 125 psi, रहता है जहाँ कंप्रेसर हवा पंप करना बंद कर देता है।"},"220":{"q":"आप एक संयुक्त वाहन (कॉम्बिनेशन व्हीकल) चला रहे हैं जब अचानक आपका ट्रेलर ट्रैक्टर से अलग हो जाता है और उसकी हवा आपूर्ति लाइन टूट जाती है, जिससे ट्रेलर के ब्रेक सिस्टम की सारी हवा निकल जाती है। बेकाबू ट्रेलर के साथ क्या होगा?","options":["हवा का दबाव गिरते ही उसके स्प्रिंग (आपातकालीन) ब्रेक स्वतः लग जाएंगे, जिससे ट्रेलर धीमा होकर रुक जाएगा","उसके सर्विस ब्रेक केवल तब तक पकड़ रखेंगे जब तक आप ट्रैक्टर में ब्रेक पैडल पर अपना पैर रखेंगे","वह बिना किसी ब्रेक के स्वतंत्र रूप से लुढ़कता रहेगा, क्योंकि हवा निकलने से ट्रेलर के पार्किंग ब्रेक भी छूट जाते हैं","जब तक आप ब्रेक लगाने के लिए लाल ट्रेलर एयर सप्लाई नॉब नहीं खींचते, तब तक उसके साथ कुछ नहीं होगा"],"explanation":"स्प्रिंग ब्रेक हवा दबाव से खुले रहते हैं, इसलिए जब अलग हुआ ट्रेलर हवा खो देता है तो वे अपने आप लग जाते हैं और ट्रेलर को रोक देते हैं।"},"221":{"q":"आप एक एयर ब्रेक प्रणाली वाला अकेला सीधा ट्रक (बिना ट्रेलर) चला रहे हैं, तभी एक बड़ी लाइन खराबी प्रणाली से सारी हवा बाहर निकाल देती है और दबाव गेज शून्य पर गिर जाते हैं। आपने न तो ब्रेक पेडल को छुआ और न ही पार्किंग नियंत्रण को। ट्रक क्या करता है?","options":["यह बिना किसी ब्रेकिंग के स्वतंत्र रूप से लुढ़कता रहता है, क्योंकि हवा खोने से स्प्रिंग ब्रेक भी छूट जाते हैं और आप लुढ़कते रहते हैं।","यह अपने आप रुक जाता है, क्योंकि जैसे ही हवा का दबाव पर्याप्त रूप से नीचे गिरता है, स्प्रिंग ब्रेक अपने आप लग जाते हैं।","यह सामान्य रूप से चलता रहता है और आप केवल अपने सर्विस ब्रेक खो देते हैं, लेकिन स्टीयरिंग और पार्किंग ब्रेक अभी भी काम करते हैं।","यह केवल पावर-सहायता खोता है, इसलिए ब्रेक अभी भी काम करते हैं लेकिन पेडल को दबाना बहुत कठिन हो जाता है।"],"explanation":"स्प्रिंग ब्रेक हवा दबाव से खुले रहते हैं, इसलिए हवा का पूर्ण नुकसान उन्हें अपने आप लगा देता है और वाहन को रोक देता है।"},"222":{"q":"ट्रैक्टर-ट्रेलर पर अपनी यात्रा-पूर्व जाँच के दौरान, मैं देखता हूँ कि एक अगले ब्रेक के स्लैक एडजस्टर में बाकियों की तुलना में ज़्यादा पुशरॉड ट्रैवल है, जिससे वह ब्रेक कम काम करता है और बाकी ज़्यादा। एक साथी कहता है कि इससे ज़्यादा फ़र्क नहीं पड़ता। जब मेरे ब्रेक असमायोजित हों और ब्रेकिंग का काम समान रूप से न बाँटें, तो मैं सबसे महत्वपूर्ण क्या खो देता हूँ?","options":["बेहतर ईंधन किफायत, क्योंकि समान रूप से काम करने वाले ब्रेक इंजन ड्रैग को कम करते हैं","जाँच के दौरान 85 से 100 psi तक हवा का दबाव तेज़ी से बनना","अच्छा ब्रेक संतुलन, ताकि वाहन एक तरफ खिंचे बिना सीधा रुके","लंबी ढलान पर गियर कम करने पर अधिक मजबूत इंजन ब्रेकिंग शक्ति"],"explanation":"जब सभी ब्रेक सही ढंग से समायोजित हों और काम बराबर बाँटें, तो ब्रेक संतुलन वाहन को बिना किसी ओर खिंचे सीधा रोकता है।"},"223":{"q":"मैं अपने ट्रैक्टर-ट्रेलर की प्री-ट्रिप जांच कर रहा हूं। इंजन चल रहा है और टैंकों में हवा का दबाव बढ़ रहा है। पार्किंग ब्रेक छोड़कर यार्ड से बाहर निकलने से पहले, सुरक्षित रूप से चलाने के लिए सिस्टम में कम से कम कितना हवा का दबाव होना चाहिए?","options":["कम से कम लगभग 60 psi, क्योंकि यही वह बिंदु है जहां कम हवा दबाव की चेतावनी बंद हो जाती है","कम से कम लगभग 20 psi, क्योंकि यहीं स्प्रिंग ब्रेक खुलते हैं और रिग लुढ़कने लगती है","कम से कम लगभग 125 psi, क्योंकि जब तक गवर्नर कट-आउट तक नहीं पहुंचता, रिग चलाना सुरक्षित नहीं है","कम से कम लगभग 100 psi, क्योंकि सुरक्षित रूप से ब्रेक लगाने और चलाने के लिए यही न्यूनतम दबाव आवश्यक है"],"explanation":"गाड़ी चलाने से पहले कम से कम लगभग 100 psi बनाना ज़रूरी है, क्योंकि सुरक्षित ब्रेक और ड्राइविंग के लिए यही न्यूनतम वायु दाब है।"},"224":{"q":"मैं एक छोटे 40-मील के डिलीवरी मार्ग पर वही भरोसेमंद ट्रैक्टर-ट्रेलर चलाता हूं, जिसे मैं दिन में कई बार चलाता हूं। इस वाहन ने आज सुबह अपनी पूरी एयर-ब्रेक जांच बिना किसी कमी के पास कर ली, और दोपहर के भोजन के बाद से मैंने इसे छुआ नहीं है। दोपहर की यात्रा शुरू करने के लिए केबिन में दोबारा चढ़ते समय, एयर ब्रेक की जांच के लिए कौन सा तरीका सही है?","options":["इस दोपहर की यात्रा से पहले एयर-ब्रेक जांच फिर से करें, ठीक वैसे ही जैसे किसी भी यात्रा से पहले","इस बार जांच छोड़ दें, क्योंकि इसी वाहन की पूरी जांच आज पहले ही पास हो चुकी है","जांच केवल तभी दोहराएं जब सुबह की यात्रा के दौरान कम हवा के दबाव की चेतावनी बत्ती या बजर चालू हुई हो","रुकें और ब्रेक की दोबारा जांच सप्ताह में एक बार या लगभग हर 1,000 मील चलने के बाद करें"],"explanation":"एयर ब्रेक जाँच हर यात्रा से पहले करनी चाहिए, क्योंकि ब्रेक की स्थिति, हवा का रिसाव और स्लैक समायोजन यात्राओं के बीच बदल सकते हैं।"},"225":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं देखता हूँ कि मेरे ट्रैक्टर के स्लैक एडजस्टर में जितना होना चाहिए उससे ज्यादा फ्री-प्ले है, यानी ब्रेक एडजस्टमेंट से बाहर हैं। अगर मैं इसे ठीक किए बिना फिर भी गाड़ी चलाऊँ, तो सड़क पर मुझे मुख्य रूप से क्या होने की उम्मीद करनी चाहिए?","options":["ब्रेक असल में और मजबूती से पकड़ेंगे और ट्रक को कम दूरी में रोक देंगे","ब्रेक की ताकत कम हो जाएगी और ट्रक उतनी अच्छी तरह नहीं रुकेगा","सिस्टम हवा बचाएगा, इसलिए कंप्रेसर बहुत कम बार चालू होगा","ब्रेक लाइनिंग और ड्रम समय के साथ बहुत धीमी गति से घिसेंगे"],"explanation":"गलत समायोजित स्लैक एडजस्टर से पुशरॉड की अत्यधिक गति ब्रेकिंग शक्ति घटाती है, इसलिए ट्रक अच्छी तरह नहीं रुकता।"},"226":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं देखता हूं कि एक ब्रेक होज़ इस तरह लगाई गई है कि वह फ्रेम के एक नुकीले ब्रैकेट से दब रही है, और जहां वह धातु को छूती है वहां उसकी बाहरी सतह घिसी हुई है। यह बात मेरे एयर ब्रेक सिस्टम के लिए क्यों मायने रखती है?","options":["यह संपर्क समय के साथ फिटिंग को कस देता है, इसलिए यह वास्तव में कनेक्शन के ढीले होने की संभावना को कम कर देता है","घर्षण रबर को सख्त कर देता है, जिससे होज़ बाकी सिस्टम की तुलना में अधिक दबाव झेल सकती है","लगातार रगड़ होज़ को तब तक घिस सकती है जब तक वह फट न जाए और हवा लीक न करने लगे","ब्रेक के लिए कुछ नहीं बदलता, लेकिन रगड़ से केवल उसी जगह पर ठंडक तेज़ हो सकती है"],"explanation":"किसी हिस्से से रगड़ खाने वाली ब्रेक होज़ लगातार घिसाव से तब तक घिसती है जब तक वह कटकर हवा रिसाने न लगे।"},"227":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, मेरा सिंगल ट्रैक्टर लगभग 125 psi तक पूरी तरह चार्ज है। मैं इंजन बंद करता हूं, ब्रेक को छोड़ा हुआ रखता हूं और गेज देखता हूं। दबाव एक मिनट में 2 psi से अधिक गिर जाता है, और मैं एक हल्की फुफकार की आवाज को एक ब्रेक चैंबर तक ढूंढता हूं जहां रबर डायाफ्राम में एक छोटा सा फटाव है। यह फटा हुआ डायाफ्राम मेरे एयर सिस्टम के साथ क्या कर रहा है?","options":["यह पुशरॉड को धकेलने वाले बल को बढ़ा रहा है, जिससे उस पहिये को अतिरिक्त ब्रेकिंग शक्ति मिल रही है","यह केवल तभी मायने रखता है जब ब्रेक लगाए गए हों, इसलिए ब्रेक छोड़े जाने पर इसका कोई वास्तविक प्रभाव नहीं है","यह रुकने के दौरान उस पहिये पर जूतों को ड्रम को और कसकर पकड़ने में मदद कर रहा है","यह संपीड़ित हवा को बाहर निकलने दे रहा है, इसीलिए मेरी रिसाव दर बहुत अधिक है"],"explanation":"ब्रेक चैंबर का फटा डायाफ्राम ब्रेक लगाने के बजाय छेद से संपीड़ित हवा निकलने देता है, जिससे रिसाव दर बढ़ जाती है।"},"228":{"q":"मेरी ट्रैक्टर-ट्रेलर की प्री-ट्रिप जांच के दौरान वायु रिसाव दर परीक्षण में विफल हो रही है—इंजन बंद और ब्रेक छोड़े होने पर भी दबाव सीमा से कहीं तेज़ गिरता है। मुझे ठीक उसी जगह हल्की सी फुफकार सुनाई देती है जहाँ ट्रैक्टर और ट्रेलर की वायु लाइनें आपस में जुड़ती हैं। जो मैं सुन रहा हूँ और जो रिसाव परीक्षण विफल हो रहा है, उसका सबसे संभावित कारण क्या है?","options":["घिसी हुई ग्लैड-हैंड सील (कपलिंग हेड की सील) ट्रैक्टर और ट्रेलर के बीच जुड़ाव वाले जोड़ पर हवा को बाहर निकलने दे रही हैं","एक स्लैक एडजस्टर असमायोजित है, जिससे किसी एक ब्रेक चैंबर में पुशरॉड की अत्यधिक यात्रा हो रही है","चार्जिंग के दौरान टैंक का दबाव 150 psi से ऊपर चढ़ जाने के कारण सुरक्षा रिलीफ वाल्व खुल गया है","गवर्नर कट-आउट तक नहीं पहुँचा, इसलिए कंप्रेसर ने सिस्टम में हवा भरना कभी बंद नहीं किया"],"explanation":"घिसे हुए ग्लैड-हैंड सील ट्रैक्टर और ट्रेलर की एयर लाइनों के जोड़ पर हवा निकलने देते हैं, जिससे सीटी की आवाज़ और अत्यधिक रिसाव होता है।"},"229":{"q":"मैंने अभी-अभी अपने ट्रैक्टर को एक लदे हुए ट्रेलर से जोड़ा है और एयर लाइनें कनेक्ट कर दी हैं। ट्रेलर के एयर टैंक अभी भी खाली हैं, और ब्रेक जांच करने से पहले मुझे उसकी ब्रेक प्रणाली को चार्ज करने के लिए ट्रेलर में वापस हवा भेजनी है। केबिन में बैठे हुए, ट्रेलर में हवा भेजने के लिए मैं कौन-सा कंट्रोल चलाऊं?","options":["ट्रेलर को दबाव देने के लिए मैं पीले, हीरे के आकार वाले नॉब को बाहर खींचता हूं","ट्रेलर में वापस हवा भेजने के लिए मैं लाल, आठ-भुजा वाले नॉब को अंदर दबाता हूं","लाइनों में हवा भेजने के लिए मैं सर्विस ब्रेक पैडल को दबाकर रखता हूं","ट्रेलर की सप्लाई लाइन खोलने के लिए मैं लाल, आठ-भुजा वाले नॉब को बाहर खींचता हूं"],"explanation":"लाल, आठ-कोनों वाली ट्रेलर एयर सप्लाई नॉब को दबाने से ट्रैक्टर से हवा ट्रेलर के ब्रेक सिस्टम को चार्ज करने के लिए जाती है।"},"230":{"q":"मैं एक ट्रैक्टर-ट्रेलर चला रहा हूँ, तभी सिस्टम में रिसाव के कारण मेरा हवा का दबाव उस स्तर से काफी नीचे गिर जाता है जो ट्रेलर एयर सप्लाई वाल्व को खुला रखने के लिए ज़रूरी है। डैश पर बिना कुछ छुए, मुझे लाल, आठ-भुजा वाले ट्रेलर एयर सप्लाई नॉब से क्या होने की उम्मीद करनी चाहिए?","options":["अपनी जगह दबी हुई रहेगी, क्योंकि ट्रेलर के ब्रेक केवल फुट पेडल पर प्रतिक्रिया करते हैं","रोशनी और बज़र बजाएगी, लेकिन तब तक दबी रहेगी जब तक मैं उसे हाथ से न खींचूँ","अपने आप बाहर निकल आएगी और बंद हो जाएगी, ट्रेलर के आपातकालीन ब्रेक अपने आप लगा देगी","ट्रेलर को सील करने और बची हुई हवा का दबाव बनाए रखने के लिए और अंदर की ओर दब जाएगी"],"explanation":"यदि वायु दाब बहुत कम हो जाए, तो लाल आठ-कोनों वाली नॉब खुद बाहर निकल कर बंद हो जाती है और ट्रेलर के आपातकालीन ब्रेक अपने-आप लगा देती है।"},"231":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मेरा मैकेनिक बताता है कि मेरे ट्रक के एक एक्सल पर बाकियों से बड़े ब्रेक चैम्बर लगाए गए हैं, और मेरे साथ बैठा एक नया छात्र पूछता है कि ब्रेक पेडल दबाने पर इससे क्या फर्क पड़ता है। छोटे चैम्बरों की तुलना में, उस एक्सल पर लगा बड़ा ब्रेक चैम्बर वास्तव में क्या उत्पन्न करता है?","options":["यह पेडल का अनुभव नरम कर देता है, क्योंकि बड़ा चैम्बर पुशरॉड के हिलने से पहले अधिक हवा रखता है","यह ब्रेकिंग कम कर देता है, क्योंकि बड़ा चैम्बर स्लैक एडजस्टर से हवा का दबाव बहा देता है","यह ब्रेकिंग में कोई बदलाव नहीं लाता, क्योंकि चैम्बर का आकार केवल यह प्रभावित करता है कि हवा कितनी तेजी से दोबारा भरती है","यह अधिक ब्रेकिंग बल उत्पन्न करता है, क्योंकि बड़ा चैम्बर स्लैक एडजस्टर को अधिक बल से धकेलता है"],"explanation":"बड़ा ब्रेक चैंबर हवा के काम करने के लिए अधिक सतह क्षेत्र देता है, जिससे स्लैक एडजस्टर पर अधिक बल लगता है और अधिक ब्रेकिंग शक्ति मिलती है।"},"232":{"q":"अपनी प्री-ट्रिप जांच के दौरान, मैं ब्रेक पेडल दबाता हूं और ड्राइव एक्सल पर ड्रम ब्रेक के S-कैम (S-cam) को घूमते हुए देखता हूं। जब S-कैम घूमता है, तो पहिए को धीमा करने के लिए वह उस ब्रेक असेंबली के अंदर वास्तव में क्या करता है?","options":["ब्रेक शूज़ को बाहर की ओर धकेलता है ताकि उनकी लाइनिंग ब्रेक ड्रम के अंदरूनी हिस्से से दब जाए","ब्रेक शूज़ को अंदर की ओर, ड्रम से दूर खींचता है, ताकि रिटर्न स्प्रिंग्स उन्हें छोड़ सकें","ब्रेकिंग शुरू होने से पहले पुशरॉड के खाली घुमाव को कम करने के लिए स्लैक एडजस्टर को घुमाता है","ब्रेक चैंबर से हवा निकालता है ताकि स्प्रिंग ब्रेक ड्रम के विरुद्ध लग सकें"],"explanation":"घूमता हुआ S-कैम ब्रेक शूज़ के बीच धंसकर उन्हें बाहर की ओर धकेलता है, जिससे उनके लाइनिंग घूमते ब्रेक ड्रम के अंदरूनी हिस्से पर दबकर पहिया धीमा करते हैं।"},"233":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, मैं एक ट्रैक्टर के फाउंडेशन ब्रेक की जाँच कर रहा हूँ जिसमें अधिक सामान्य ड्रम प्रकार के बजाय एयर डिस्क ब्रेक लगे हैं। पहिये के असेंबली को देखते हुए, मुझे कैलिपर दिखाई देता है जो एक सपाट, घूमते हुए धातु के हिस्से को घेरे हुए है, जिसे कैलिपर पहिये को धीमा करने के लिए दबाता है। अपनी जाँच में इस एयर डिस्क ब्रेक प्रणाली का सही वर्णन करने के लिए, कैलिपर जिस हिस्से को जकड़ता है वह है:","options":["ब्रेक ड्रम जिसके विरुद्ध शूज़ बाहर की ओर दबाते हैं","रोटर (डिस्क) जिसे कैलिपर घर्षण उत्पन्न करने के लिए दबाता है","स्प्रिंग (पार्किंग) ब्रेक चैम्बर जो दबाव लगाता है","स्लैक एडजस्टर जिसके विरुद्ध पुशरॉड चलता है"],"explanation":"एयर डिस्क ब्रेक एक कैलिपर का उपयोग करते हैं जो पहिए के हब पर लगे घूमते रोटर (डिस्क) पर घर्षण पैड दबाता है, जिससे पहिया धीमा करने वाला घर्षण बनता है।"},"234":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, एक मैकेनिक मेरे ट्रक के एक बड़े ब्रेक चैंबर की ओर इशारा करता है और उसे 'मैक्सी' चैंबर कहता है, यह बताते हुए कि यह छोटे चैंबर की तरह पहिए को रोकने के लिए रॉड को बाहर धकेलने हेतु हवा के दबाव का उपयोग नहीं करता। यह घटक वास्तव में कैसे काम करता है, इसके आधार पर 'मैक्सी' चैंबर क्या है?","options":["यह सर्विस ब्रेक है, क्योंकि 'मैक्सी' चैंबर वह हिस्सा है जो सामान्य ड्राइविंग के दौरान हर बार पैर का पेडल दबाने पर ब्रेकिंग बल लगाता है","यह मॉड्युलेटिंग कंट्रोल वाल्व है, क्योंकि 'मैक्सी' चैंबर वह है जो आपात स्थिति में पिछले एक्सल पर धीरे-धीरे दबाव लगाने देता है","यह स्प्रिंग ब्रेक है, क्योंकि 'मैक्सी' चैंबर में एक शक्तिशाली स्प्रिंग होती है जो हवा का दबाव छोड़ने या खोने पर ब्रेक लगाती है","यह ट्रेलर एयर सप्लाई इकाई है, क्योंकि 'मैक्सी' चैंबर वह है जो ड्राइविंग के दौरान ट्रेलर के टैंकों में हवा भेजता और भरता है"],"explanation":"मैक्सी (स्प्रिंग ब्रेक) चैंबर में एक शक्तिशाली दबा हुआ स्प्रिंग होता है जो हवा के दबाव छूटने या खत्म होने पर ब्रेक लगाता है, न कि लागू हवा से रॉड को धकेलता है।"},"235":{"q":"मैं एक लोडिंग डॉक पर खड़ा हूँ और मेरा ट्रक लगभग 125 psi पर पूरी तरह हवा से भरा है और कोई रिसाव नहीं है। हवा का दबाव 20-45 psi की सीमा में गिरने के अलावा, मेरे स्प्रिंग ब्रेक को लगाने का दूसरा तरीका क्या है?","options":["सर्विस ब्रेक पैडल को दबाकर पूरी तरह फर्श तक दबाए रखना","एंटीलॉक ब्रेकिंग सिस्टम (ABS) चेतावनी स्विच को चालू करना","इंजन को तेज़ करके गवर्नर को 125 psi पर कट-आउट तक पहुँचाना","पीली, हीरे के आकार वाली पार्किंग ब्रेक नियंत्रण नॉब को बाहर खींचना"],"explanation":"स्प्रिंग ब्रेक पीले हीरे के आकार वाले पार्किंग ब्रेक नियंत्रण नॉब को खींचकर मैन्युअली लगाए जाते हैं।"},"236":{"q":"पैनहैंडल में जमा देने वाली सर्दियों की सुबह है, और मेरे ट्रैक्टर-ट्रेलर की एयर ब्रेक प्रणाली में एक अल्कोहल इवैपोरेटर लगा हुआ है। जब मैं अपनी प्री-ट्रिप जाँच करके गाड़ी चलाना शुरू करता हूँ, तो इस ठंडे मौसम में यह उपकरण मेरे लिए जो MUKHYA (मुख्य) काम कर रहा है, वह क्या है?","options":["हवा प्रणाली में अल्कोहल मिलाना ताकि बर्फ न जमे और एयर ब्रेक की लाइनें व वाल्व जाम न हों","ब्रेक ड्रम और लाइनिंग को गर्म रखना ताकि सर्विस ब्रेक अपनी रोकने की शक्ति न खोएँ","टैंकों से पानी और कंप्रेसर का तेल निकालना ताकि मुझे उन्हें रोज़ ड्रेन न करना पड़े","गवर्नर का कट-आउट दबाव बढ़ाना ताकि ठंड में कंप्रेसर तेज़ी से हवा बना सके"],"explanation":"अल्कोहल एवापोरेटर हवा प्रणाली में अल्कोहल मिलाता है ताकि नमी का जमने का तापमान घटे और ठंड में बर्फ बनकर ब्रेक लाइनों व वाल्वों को जाम न करे।"},"237":{"q":"एयर प्रेशर (हवा का दबाव) केवल तभी बनता है जब:","options":["रेडियो चालू है","इंजन चल रहा है","दरवाज़े खुले हैं","लाइटें चालू हैं"],"explanation":"प्रेशर (दबाव) केवल तभी बनता है जब इंजन चलता है।"},"238":{"q":"अपनी प्री-ट्रिप जाँच के दौरान मैं इंजन को चालू छोड़कर एयर गेज को ऊपर चढ़ते हुए देखता हूँ। यह लगभग 125 psi तक पहुँचता है और इंजन के चलते रहने के बावजूद सुई का बढ़ना रुक जाता है। गवर्नर अभी-अभी अपने कट-आउट (cut-out) सेटिंग पर पहुँचा है। ठीक इसी क्षण कंप्रेसर स्वयं क्या कर रहा है?","options":["यह इंजन के साथ पूरी तरह बंद हो गया है और तभी दोबारा चालू होगा जब दबाव गिरकर लगभग 60 psi हो जाएगा","यह घूमता तो रहता है पर टैंकों में हवा भरना बंद कर देता है (अनलोड हो गया है) जब तक दबाव गिरकर लगभग 100 psi न हो जाए","यह और जोर से हवा भरता है ताकि दबाव 150 psi वाले सेफ्टी रिलीफ वाल्व सेटिंग तक पहुँच जाए","यह जाम (लॉक) हो जाता है और टैंकों की सुरक्षा के लिए अतिरिक्त हवा को सेफ्टी रिलीफ वाल्व से बाहर निकाल देता है"],"explanation":"गवर्नर कट-आउट बिंदु (लगभग 125 psi) पर कंप्रेसर घूमता रहता है पर अनलोड हो जाता है और टैंकों में हवा भेजना बंद कर देता है, जब तक दबाव कट-इन बिंदु लगभग 100 psi तक न गिरे।"},"239":{"q":"मैंने अभी-अभी अपना ट्रेलर यार्ड में छोड़ा है और बिना ट्रेलर के (बॉबटेल) ट्रैक्टर को टर्मिनल वापस चला रहा हूँ। घर के रास्ते में एक लंबा सपाट हिस्सा है, एक खुला बजरी वाला लॉट है जिससे मैं शॉर्टकट लेता हूँ, कुछ हाईवे ऑन-रैंप हैं, और निकास के पास एक चौड़ा मोड़ है। मुझे सबसे ज़्यादा सावधानी से कहाँ धीमा होना चाहिए, क्योंकि बिना ट्रेलर वाला ट्रैक्टर वहाँ ठीक से नहीं संभलता?","options":["लंबे सपाट हिस्से पर, क्योंकि हल्का वाहन मुझे सामान्य से तेज़ चलने देता है","खुले बजरी वाले लॉट में, क्योंकि ढीली सतह ही एकमात्र जगह है जहाँ बॉबटेल पकड़ खोता है","मोड़ों और ऑन-रैंप पर, जहाँ बिना ट्रेलर वाला ट्रैक्टर (बॉबटेल) ठीक से नहीं संभल सकता","कहीं ख़ास नहीं, क्योंकि बिना ट्रेलर वाला बॉबटेल बेहतर ब्रेक और मोड़ लेता है"],"explanation":"बॉबटेल ट्रैक्टर में ड्राइव एक्सल पर ट्रेलर का वजन नहीं होता और यह खराब चलता है, इसलिए मोड़ों और ऑन-रैंप पर जहाँ बल सबसे अधिक होते हैं, अतिरिक्त धीमा करें।"},"240":{"q":"मैं यार्ड में एक ट्रैक्टर-ट्रेलर पर अपनी यात्रा-पूर्व जाँच पूरी कर रहा हूँ। मैं पहले ही एयर टैंक खाली कर चुका हूँ, पुष्टि कर ली है कि गवर्नर लगभग 125 psi पर कट-आउट करता है, और सत्यापित कर लिया है कि कम हवा दबाव की चेतावनी 60 psi से नीचे गिरने से पहले चालू हो जाती है। सड़क पर निकलने से पहले, अपने वाहन के पिछले हिस्से की लाइटों के संबंध में निम्नलिखित में से मुझे अब भी क्या करना चाहिए?","options":["पुष्टि करें कि पीछे के रिफ्लेक्टर ताज़ा रंगे हुए हैं ताकि अन्य चालक उन्हें रात में देख सकें","पुष्टि करें कि बल्बों को सड़क के मलबे से बचाने के लिए पीछे के लैंप आवरण ढके हुए हैं","पुष्टि करें कि विद्युत भार कम करने के लिए पीछे की मार्कर लाइटें हटा दी गई हैं","पुष्टि करें कि जब मैं ब्रेक पेडल दबाता हूँ तो ब्रेक लाइटें वास्तव में जलती हैं"],"explanation":"यात्रा-पूर्व निरीक्षण में पुष्टि करनी होती है कि ब्रेक पेडल दबाने पर ब्रेक लाइटें वास्तव में जलती हैं, ताकि पीछे आने वाले वाहनों को धीमा होने या रुकने का संकेत मिले।"},"241":{"q":"यात्रा से पहले लगभग 5 मील प्रति घंटे की सर्विस-ब्रेक रुकावट जांच के दौरान, जब मैं ब्रेक पैडल दबाता हूं तो ट्रक तेजी से दाईं ओर झटका खाता है और रुकने से पहले पैडल असमान रूप से पकड़ता है। कौन सा निष्कर्ष सही है?","options":["ब्रेक खराब हैं और वाहन चलाने से पहले उसकी सर्विस करानी जरूरी है","यह सामान्य ब्रेक-लैग व्यवहार है, मैं छोड़कर यात्रा जारी रख सकता हूं","हवा का दबाव बस बहुत ज्यादा है, इसलिए मुझे टैंक खाली करके दोबारा जांचना चाहिए","ABS एक पहिये को पकड़कर अपना काम कर रहा है, इसलिए कोई कार्रवाई जरूरी नहीं है"],"explanation":"5 मील प्रति घंटा ब्रेक परीक्षण में, एक तरफ खींचने या असमान रूप से पकड़ने वाले ब्रेक खराब हैं और वाहन की मरम्मत होने तक उसे नहीं चलाना चाहिए।"},"242":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं प्रत्येक पहिये पर फाउंडेशन ब्रेक (foundation brakes) की जाँच करने के लिए ट्रेलर के नीचे जाता हूँ। मैंने पहले ही पुष्टि कर ली है कि ब्रेक ड्रम और ब्रेक शू अच्छी स्थिति में हैं। फाउंडेशन ब्रेक के घटकों की जाँच पूरी करने के लिए, मुझे आगे किस भाग की जाँच करनी चाहिए?","options":["कैब में पीले, हीरे के आकार वाले पार्किंग ब्रेक नॉब की","प्रत्येक ब्रेक चैंबर के पुशरॉड से जुड़े स्लैक एडजस्टर (slack adjusters) की","गवर्नर की, जो कंप्रेसर के कट-इन और कट-आउट को नियंत्रित करता है","सप्लाई (वेट) टैंक पर लगे सेफ्टी रिलीफ वाल्व की"],"explanation":"स्लैक एडजस्टर प्रत्येक ब्रेक चैंबर पुशरॉड को ब्रेक तंत्र से जोड़ते हैं और पुशरॉड की गति को पहिए पर ब्रेकिंग बल में बदलते हैं।"},"243":{"q":"अपने यात्रा-पूर्व निरीक्षण के दौरान, मैं ट्रैक्टर और ट्रेलर के ग्लैड हैंड (हवा की लाइन के जोड़) जोड़ता हूँ, हवा प्रणाली को लगभग 125 psi तक भरता हूँ, और इंजन बंद कर देता हूँ। जोड़ के पास झुकते ही, मुझे ग्लैड हैंड के किसी एक कनेक्शन से आती हुई एक लगातार सीटी जैसी आवाज़ साफ़ सुनाई देती है। यह आवाज़ उस कनेक्शन के बारे में सबसे अधिक संभावना से क्या बताती है?","options":["सील पूरी तरह वायुरोधी है और कनेक्शन जाँच में पास हो गया","ट्रेलर के ब्रेक को बढ़ावा देने के लिए अतिरिक्त हवा का दबाव भेजा जा रहा है","रिसाव के कारण कनेक्शन से हवा बाहर निकल रही है","सप्लाई लाइन ने अभी-अभी जमा हुआ पानी निकालना पूरा किया है"],"explanation":"ग्लैड हैंड कनेक्शन पर लगातार फुसफुसाहट का मतलब है कि दबाव वाली हवा सील में रिसाव से बाहर निकल रही है।"},"244":{"q":"मैं एक चालू ABS (एंटी-लॉक ब्रेक) प्रणाली से लैस ट्रैक्टर-ट्रेलर चला रहा हूँ, तभी एक कार अचानक मेरी लेन में एकदम रुक जाती है। मुझे वाहन पर नियंत्रण बनाए रखते हुए जितना हो सके उतनी जोर से रुकना है। इस आपातकाल में ब्रेक का सही उपयोग क्या है?","options":["ब्रेक पैडल को तेजी से ऊपर-नीचे पंप करना ताकि ABS को हर बार के बीच प्रतिक्रिया का समय मिल जाए","जोर से दबाएँ, पैडल में कंपन महसूस होते ही छोड़ दें, और छोटे-छोटे झटकों में दोहराएँ","ABS चालू करने के लिए प␘ैडल को एक बार दबाएँ, फिर बिना और ब्रेक लगाए खतरे से बचकर स्टीयर करके निकल जाएँ","पैडल को मजबूती से दबाएँ और लगातार स्थिर दबाव बनाए रखें, ABS को पहियों को जाम होने से रोकने दें ताकि मैं स्टीयर कर सकूँ"],"explanation":"ABS के साथ, ब्रेक पेडल को मजबूती से दबाएं और स्थिर दबाव बनाए रखें ताकि सिस्टम पहियों को लॉक होने से रोके और आप स्टीयरिंग नियंत्रण बनाए रखें।"},"245":{"q":"एक कड़ाके की ठंड वाली सर्दी की सुबह है और मैं एयर ब्रेक वाले ट्रैक्टर-ट्रेलर की यात्रा-पूर्व जाँच कर रहा हूँ। मुझे एहसास होता है कि पिछले कई दिनों से मैं एयर टैंक ड्रेन करना भूल गया, और मुझे ड्रेन वाल्व के आसपास नमी दिखती है। यह ब्रेक सिस्टम के लिए क्यों मायने रखता है?","options":["टैंकों में जमा होने वाला पानी और कंप्रेसर ऑयल ब्रेक सिस्टम को नुकसान पहुँचा सकता है और ठंड में जम सकता है, इसलिए टैंक को रोज़ ड्रेन करना चाहिए","टैंकों में थोड़ी मात्रा में पानी और ऑयल दरअसल ब्रेक वाल्व को चिकना और सील करता है, इसलिए कभी-कभार ड्रेन छोड़ना नुकसानरहित है","पानी और ऑयल ब्रेकिंग को प्रभावित नहीं करते क्योंकि सेफ्टी रिलीफ वाल्व इन्हें लगभग 150 psi पर अपने आप बाहर निकाल देता है","नमी केवल पार्किंग ब्रेक के लिए मायने रखती है, इसलिए जब तक सर्विस ब्रेक पकड़ रहे हैं, मैं टैंक ड्रेन करना वसंत तक सुरक्षित रूप से टाल सकता हूँ"],"explanation":"हवा के टैंक रोज़ निकाले जाने चाहिए क्योंकि उनमें पानी और कंप्रेसर का तेल जमा होता है, जो ब्रेक सिस्टम को नुकसान पहुंचा सकता है या ठंड में जम सकता है।"},"246":{"q":"एक कड़कड़ाती ठंडी सुबह है और प्री-ट्रिप जांच के दौरान आप देखते हैं कि रात भर में सप्लाई (वेट) टैंक में पानी और थोड़ा तैलीय कीचड़ जमा हो गया है। इससे पहले कि यह जम जाए और सिस्टम को नुकसान पहुंचाए, इस संदूषण को बाहर निकालने के लिए आप उस टैंक पर कौन-सा उपकरण चलाते हैं?","options":["सेफ्टी रिलीफ वाल्व, इसे खोलकर टैंक की हवा निकालने के लिए","टैंक के तल पर लगा ड्रेन वाल्व (पेटकॉक)","गवर्नर, इसे कट-आउट करके जमाव को छोड़ने के लिए","लाइन साफ करने के लिए लो-एयर चेतावनी बजर रीसेट"],"explanation":"पानी और तेल को हवा के टैंक के नीचे लगे ड्रेन वाल्व (पेटकॉक) को खोलकर निकाला जाता है।"},"247":{"q":"प्री-ट्रिप निरीक्षण के दौरान, मैं हवा प्रणाली को पूरे दबाव तक भरने देता हूँ। अचानक मुझे सप्लाई (गीले) टैंक पर लगे सुरक्षा रिलीफ वाल्व से हवा निकलने की तेज़ आवाज़ सुनाई देती है। गाड़ी चलाने से पहले, यह मेरी प्रणाली के बारे में सबसे अधिक संभावना से क्या बताता है?","options":["कम हवा दबाव चेतावनी विफल हो गई, इसलिए टैंक का दबाव चुपचाप 60 psi से नीचे गिर गया।","गवर्नर समय से पहले कट-इन हो गया और कंप्रेसर ने टैंकों में हवा भेजना बंद कर दिया।","गवर्नर कट-आउट करने में विफल रहा, इसलिए दबाव लगभग 150 psi से ऊपर चढ़ गया और वाल्व ने उसे बाहर निकाल दिया।","एक धीमी लीक ने दबाव को 20 से 45 psi की सीमा में गिरा दिया और स्प्रिंग ब्रेक चालू कर दिए।"],"explanation":"यदि गवर्नर कंप्रेसर को बंद नहीं कर पाता, तो दबाव लगभग 150 psi से ऊपर चढ़ जाता है और सेफ्टी रिलीफ वाल्व खुलकर अतिरिक्त हवा बाहर निकाल देता है।"},"248":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, वर्कशॉप का मैकेनिक मुझसे कहता है कि ट्रेलर के पार्क रहते हुए जाकर जाँच लूँ कि \"मैक्सी-ब्रेक\" ठीक से पकड़ रहे हैं या नहीं। मैं इस बोलचाल के शब्द से परिचित नहीं हूँ। मेरे एयर-ब्रेक वाहन में वह असल में किस पुर्जे की बात कर रहा है?","options":["सर्विस ब्रेक जिन्हें मैं सामान्य रुकाव के दौरान फुट पेडल से लगाता हूँ","मॉड्युलेटिंग वाल्व जिसे मैं आपात स्थिति में ब्रेक धीरे-धीरे लगाने के लिए उपयोग करता हूँ","स्लैक एडजस्टर जो यह नियंत्रित करते हैं कि पुशरॉड कितनी दूर तक चलता है","स्प्रिंग ब्रेक जो वाहन को रोके रखते हैं और हवा का दबाव खोने पर लग जाते हैं"],"explanation":"मैक्सी-ब्रेक स्प्रिंग ब्रेक का ही दूसरा नाम है, जो खड़े वाहन को रोके रखते हैं और हवा का दबाव खत्म होने पर अपने आप लग जाते हैं।"},"249":{"q":"मैं एक कार से हटकर एयर ब्रेक (वायु ब्रेक) से लैस एक भरे हुए ट्रैक्टर-ट्रेलर पर जा रहा हूँ, और मेरे प्रशिक्षक पूछते हैं कि CDL चालक के लिए एयर ब्रेक प्रणाली में महारत हासिल करना सबसे ज़्यादा क्यों मायने रखता है। एयर ब्रेक सीखने के मुख्य उद्देश्य को कौन-सा उत्तर सबसे अच्छी तरह बताता है?","options":["किसी भारी, भरे हुए वाहन को सुरक्षित और नियंत्रित तरीके से रोकने के लिए","ट्रक को स्वतंत्र रूप से लुढ़कने और अधिक तेज़ क्रूज़िंग गति तक पहुँचने देने के लिए","इंजन के कंप्रेसर को निष्क्रिय रखकर ईंधन की खपत कम करने के लिए","हाइड्रॉलिक ब्रेकों की तुलना में कुल रुकने की दूरी को कम करने के लिए"],"explanation":"एयर ब्रेक सिस्टम का मुख्य उद्देश्य किसी भारी, लदे हुए वाहन को सुरक्षित और नियंत्रित तरीके से रोकना है।"}}};
  Object.keys(REPL).forEach(function(i){ cat.questions[+i]=REPL[i]; });
  APPEND.forEach(function(a){ cat.questions[a.idx]=a.obj; });
  ["ru","tr","es","hi"].forEach(function(L){ var m=TR[L]||{}; Object.keys(m).forEach(function(i){ I.q[L][SUBJ][+i]=m[i]; }); });
})();
